# lets the same server.py run on any Windows box that has Qt 5.14.2 + MinGW
# installed, without code changes.

def _env_path(var: str, default: str) -> Path:
    """Read a filesystem path from `var`, fall back to `default` if unset/empty."""
    val = os.environ.get(var, "").strip()
    return Path(val) if val else Path(default)


