def _in_sandbox(path: Path) -> bool:
    try:
        path.resolve().relative_to(SANDBOX_ROOT)
        return True
    except (ValueError, OSError):
        return False


def _require_sandbox(path: Path, what: str) -> Optional[str]:
    """Return an error message if `path` resolves outside SANDBOX_ROOT, else None."""
    if not _in_sandbox(path):
        return (f"Error: {what} path {path} is outside the allowed sandbox "
                f"{SANDBOX_ROOT}. All MCP inputs/outputs must stay under that root.")
    return None


def _qt_env() -> dict:
    """Build a child-process env with Qt + MinGW first on PATH."""
    env = os.environ.copy()
    # Prepend so qmake's auto-detected g++ wins over any system gcc.
    env["PATH"] = f"{QT_BIN_DIR};{MINGW_BIN_DIR};{env.get('PATH', '')}"
    env["QTDIR"] = str(QT_ROOT)
    return env


def _check_paths() -> Optional[str]:
    for p in (QMAKE, MINGW32_MAKE, WINDEPLOYQT, MINGW_BIN_DIR / "g++.exe"):
        if not p.exists():
            return f"Required Qt tool not found: {p}"
    return None


def _pe_bits(exe: Path) -> int:
    """Return 32 or 64 by reading the PE header `Machine` field. Defaults to 64 on parse error.

    Mirrors the heuristic used by qt_test / qt_run / qt_run_trace so all three tools
    pick the same Qt bin dir for the same .exe.
    """
    import struct
    try:
        with open(exe, "rb") as f:
            dos = f.read(64)
            if len(dos) >= 64 and dos[:2] == b"MZ":
                pe_off = struct.unpack("<I", dos[0x3C:0x40])[0]
                f.seek(pe_off)
                pe = f.read(6)
                if len(pe) >= 6 and pe[:4] == b"PE\x00\x00":
                    machine = struct.unpack("<H", pe[4:6])[0]
                    if machine == 0x14C:  # IMAGE_FILE_MACHINE_I386
                        return 32
                    return 64
    except OSError:
        pass
    return 64


def _clean_artifacts(proj: Path) -> tuple[int, list[str]]:
    """Remove qmake/make build artifacts under `proj`. Returns (count, [relative paths])."""
    removed: list[str] = []
    patterns = [
        "Makefile", "Makefile.*", ".qmake.stash", ".qmake.cache",
        "*.o", "*.obj", "ui_*.h", "moc_*.cpp", "moc_*.obj",
        "qrc_*.cpp", "*.exe", "*.qm",
    ]
    for pat in patterns:
        for p in proj.rglob(pat):
            if p.is_file():
                try:
                    p.unlink()
                    removed.append(str(p.relative_to(proj)))
                except OSError:
                    pass
    for sub in ("debug", "release", "build"):
        target = proj / sub
        if target.is_dir():
            shutil.rmtree(target, ignore_errors=True)
            removed.append(f"{sub}/")
    return len(removed), removed


def _json_footer(obj: dict[str, Any]) -> str:
    """Optional machine-readable trailer appended to every tool response.

    Activated only when QT_MCP_JSON=1 is set in the server's environment.
    Format:

        ...
        <existing human-readable output>

        --- json ---
        {
          "ok": true,
          "data": { ... }
        }

    Failure responses use `{"ok": false, "error": "..."}` instead. Off by
    default so existing e2e string-match contracts (`"Error:" in out`) are
    preserved when the env var is not set.
    """
    if os.environ.get("QT_MCP_JSON", "").strip() != "1":
        return ""
    return "\n\n--- json ---\n" + json.dumps(obj, indent=2, ensure_ascii=False) + "\n"


def main() -> int:
    """Entry point for `python -m server` / pyproject `[project.scripts]`."""
    err = _check_paths()
    if err:
        sys.stderr.write(f"qt-mcp {__version__}: {err}\n")
        sys.stderr.write(
            "Hint: set QT_MCP_QT_ROOT / QT_MCP_MINGW_BIN / QT_MCP_QTCREATOR\n"
            "to point at your Qt + MinGW install. See module docstring.\n"
        )
        return 1
    mcp.run()
    return 0


# --- .pro file parser --------------------------------------------------------
# A pragmatic line-based parser. Handles the common cases (assignment / += / -=
# with line continuations and comments) and round-trips back to a clean file.
# We deliberately do NOT try to support all qmake features (conditionals,
# scopes, functions) — those still require hand-editing.

_PRO_LINE_RE = re.compile(
    r"^\s*(?P<var>[A-Za-z_][A-Za-z0-9_.]*)"
    r"\s*(?P<op>[+\-:]?=)"
    r"(?P<rest>.*)$"
)


def _pro_strip_comments(text: str) -> list[str]:
    """Return raw lines with comment-only fragments removed, preserving structure."""
    out: list[str] = []
    for line in text.splitlines():
        # Drop '#' that isn't inside a quoted value — qmake does not treat '#' as
        # a comment when it follows a quoted token, but we don't emit such lines
        # ourselves and we're permissive on input.
        hash_pos = -1
        in_quote: Optional[str] = None
        i = 0
        while i < len(line):
            c = line[i]
            if in_quote:
                if c == in_quote and (i == 0 or line[i - 1] != "\\"):
                    in_quote = None
            else:
                if c in ("'", '"'):
                    in_quote = c
                elif c == "#":
                    hash_pos = i
                    break
            i += 1
        out.append(line if hash_pos < 0 else line[:hash_pos])
    return out


def _pro_parse(text: str) -> list[dict]:
    """Parse .pro text into a list of {'var','op','value','raw'} entries.

    Continuation lines (start with whitespace and aren't blank) are merged into
    the previous entry's value as space-separated tokens. Trailing backslashes
    on declaration lines (which are the qmake continuation marker) are stripped
    from the value — they belong to the formatting, not the data.
    """
    entries: list[dict] = []
    pending: Optional[dict] = None
    for raw in _pro_strip_comments(text):
        if not raw.strip():
            if pending is None:
                entries.append({"var": "", "op": "", "value": "", "raw": raw})
            else:
                pending["raw"] = pending["raw"] + "\n" + raw
            continue
        if raw[0] in (" ", "\t") and pending is not None:
            cont = raw.rstrip()
            if cont.endswith("\\"):
                cont = cont[:-1].rstrip()
            # If the pending value still ends with a continuation backslash,
            # join with a real newline so the serializer can re-emit the
            # multi-line shape. Otherwise treat this as a space-separated
            # continuation (rare in practice).
            if pending["value"].endswith("\\"):
                pending["value"] = pending["value"] + "\n" + cont
            else:
                pending["value"] = (pending["value"] + " " + cont).strip()
            pending["raw"] = pending["raw"] + "\n" + raw
            continue
        m = _PRO_LINE_RE.match(raw)
        if not m:
            entries.append({"var": "", "op": "", "value": "", "raw": raw})
            pending = None
            continue
        first_value = m.group("rest").lstrip()
        # Note: do NOT strip a trailing backslash here — it's the qmake
        # continuation marker that tells the serializer the line continues.
        # _pro_tokenize drops lone "\" tokens, so callers see clean tokens.
        pending = {
            "var": m.group("var"),
            "op": m.group("op").strip(),
            "value": first_value,
            "raw": raw,
        }
        entries.append(pending)
    return entries


def _pro_format_value(values: list[str]) -> str:
    """Format a list of values for a single .pro line, using '\\' continuations."""
    if not values:
        return ""
    if len(values) == 1:
        return values[0]
    return "\\\n           " + " \\\n           ".join(values)


def _pro_tokenize(value: str) -> list[str]:
    """Split a .pro value into tokens, respecting simple quoting.

    Sufficient for values generated by qt_scaffold and qt_pro_edit itself;
    not a full qmake tokenizer. Stray backslashes left over from the original
    line-continuation markers are dropped.
    """
    tokens: list[str] = []
    cur: list[str] = []
    in_quote: Optional[str] = None
    i = 0
    while i < len(value):
        c = value[i]
        if in_quote:
            cur.append(c)
            if c == in_quote and (i == 0 or value[i - 1] != "\\"):
                in_quote = None
        elif c in ("'", '"'):
            in_quote = c
            cur.append(c)
        elif c.isspace():
            if cur:
                tok = "".join(cur)
                if tok != "\\":
                    tokens.append(tok)
                cur = []
        else:
            cur.append(c)
        i += 1
    if cur:
        tok = "".join(cur)
        if tok != "\\":
            tokens.append(tok)
    return tokens


def _pro_set_variable(entries: list[dict], var: str, op: str, values: list[str]) -> list[dict]:
    """Replace the value of `var` (or add a new entry) in-place. Returns entries."""
    formatted = _pro_format_value(values)
    for e in entries:
        if e["var"] == var:
            e["op"] = op
            e["value"] = formatted
            e["raw"] = f"{var}{op} {formatted}".replace(" \\\n           ", " \\\n           ")
            return entries
    entries.append({
        "var": var,
        "op": op,
        "value": formatted,
        "raw": f"{var}{op} {formatted}",
    })
    return entries


def _pro_to_text(entries: list[dict]) -> str:
    """Serialize entries back to a .pro file. Preserves blank/comment lines."""
    parts: list[str] = []
    for e in entries:
        if e["var"] and e["op"]:
            # Re-emit continuations explicitly.
            head, op, value = e["var"], e["op"], e["value"]
            if "\\\n" in value:
                # Already multi-line.
                first, *rest = value.split("\\\n")
                parts.append(f"{head}{op} {first.strip()} \\")
                for r in rest:
                    parts.append(f"           {r.strip()} \\")
                # Drop trailing backslash on the last item.
                if parts[-1].endswith(" \\"):
                    parts[-1] = parts[-1][:-2]
            else:
                parts.append(f"{head}{op} {value}")
        else:
            parts.append(e.get("raw", ""))
    # Add a trailing newline so file ends cleanly.
    return "\n".join(parts) + "\n"


# --- Subprocess helper --------------------------------------------------------

@dataclass
class CmdResult:
    returncode: int
    stdout: str
    stderr: str
    timed_out: bool = False

    @property
    def ok(self) -> bool:
        return not self.timed_out and self.returncode == 0


async def _run(cmd: list[str], cwd: Path, timeout: float, env: Optional[dict] = None) -> CmdResult:
    """Run a command asynchronously, capturing output and enforcing a timeout.

    `env` overrides the child-process environment. If None (the default), we use
    _qt_env() so Qt and MinGW are first on PATH — that's almost always what you
    want, but qt_test / qt_designer override it to inject a 32-bit Qt bin dir
    when the .exe is 32-bit.
    """
    # Windows cmd / taskkill / windeployqt / etc. emit GBK by default.
    # We force UTF-8 via chcp 65001 first (no-op if cmd is not the launcher),
    # then try GBK → UTF-8 decode as fallback. Unix tools are UTF-8 native.
    if sys.platform == "win32":
        # Wrap native console commands in cmd /c chcp 65001 so the locale
        # switches before taskkill etc. produce output. Non-cmd commands
        # (qmake.exe, mingw32-make.exe, windeployqt.exe, g++.exe) ignore
        # chcp but their output is ASCII so no decoding issues.
        head = cmd[0].lower()
        if head == "taskkill":
            cmd = ["cmd", "/c", "chcp", "65001", ">", "nul", "&&"] + cmd

    def _decode(b: bytes) -> str:
        if sys.platform == "win32":
            for enc in ("utf-8", "gbk"):
                try:
                    return b.decode(enc)
                except UnicodeDecodeError:
                    continue
        return b.decode("utf-8", errors="replace")

    proc = await asyncio.create_subprocess_exec(
        *cmd,
        cwd=str(cwd),
        env=env if env is not None else _qt_env(),
        stdout=asyncio.subprocess.PIPE,
        stderr=asyncio.subprocess.PIPE,
    )
    try:
        stdout_b, stderr_b = await asyncio.wait_for(proc.communicate(), timeout=timeout)
        return CmdResult(
            returncode=proc.returncode or 0,
            stdout=_decode(stdout_b),
            stderr=_decode(stderr_b),
        )
    except asyncio.TimeoutError:
        proc.kill()
        await proc.wait()
        return CmdResult(returncode=-1, stdout="", stderr=f"Timeout after {timeout}s", timed_out=True)


def _tail(text: str, n: int = LOG_TAIL_LINES) -> str:
    lines = text.splitlines()
    if len(lines) <= n:
        return text
    return "\n".join(["... (truncated) ..."] + lines[-n:])


def _is_pid_alive(pid: int) -> bool:
    """Cross-platform liveness check. On Windows uses OpenProcess."""
    if sys.platform == "win32":
        import ctypes
        PROCESS_QUERY_LIMITED_INFORMATION = 0x1000
        STILL_ACTIVE = 259
        kernel32 = ctypes.windll.kernel32
        handle = kernel32.OpenProcess(PROCESS_QUERY_LIMITED_INFORMATION, False, pid)
        if not handle:
            return False
        try:
            code = ctypes.c_ulong()
            ok = kernel32.GetExitCodeProcess(handle, ctypes.byref(code))
            return bool(ok) and code.value == STILL_ACTIVE
        finally:
            kernel32.CloseHandle(handle)
    else:
        try:
            os.kill(pid, 0)
            return True
        except (OSError, ProcessLookupError):
            return False


def _guess_missing_dll(exe: Path) -> Optional[str]:
    """Heuristically identify the DLL Qt5*.dll an exe is missing.

    We can't actually know without launching the loader, but the most common
    failure on Windows is Qt5Core.dll or Qt5Widgets.dll not being on PATH
    (e.g. someone tries to run a freshly built exe from a non-Qt shell).
    Reports the first missing one we detect via the exe's imports list.
    """
    if sys.platform != "win32" or not OBJDUMP.exists() or not exe.is_file():
        return None
    try:
        out = subprocess.check_output(
            [str(OBJDUMP), "-p", str(exe)],
            stderr=subprocess.DEVNULL, timeout=10,
        ).decode("utf-8", errors="replace")
    except Exception:
        return None
    qt_dir = str(QT_BIN_DIR)
    on_path: set[str] = set()
    for d in os.environ.get("PATH", "").split(os.pathsep):
        if not d:
            continue
        try:
            for entry in os.listdir(d):
                if entry.lower().endswith(".dll"):
                    on_path.add(entry.lower())
        except OSError:
            continue
    qt_dir_dlls: set[str] = set()
    try:
        for entry in os.listdir(qt_dir):
            if entry.lower().endswith(".dll"):
                qt_dir_dlls.add(entry.lower())
    except OSError:
        pass

    missing: list[str] = []
    for line in out.splitlines():
        m = re.match(r"\s*DLL Name:\s*(\S+)", line)
        if not m:
            continue
        name = m.group(1)
        if not name.lower().startswith("qt5"):
            continue
        nl = name.lower()
        if nl in on_path or nl in qt_dir_dlls:
            continue
        missing.append(name)
    if not missing:
        return None
    return f"missing Qt DLL(s) on PATH: {', '.join(missing[:5])}" + (
        "" if len(missing) <= 5 else f" (and {len(missing) - 5} more)"
    )


def _categorize_build_error(text: str) -> str:
    """Best-effort classification of mingw32-make / g++ / moc output.

    Returns a short list of root-cause hints the caller can act on, prefixed
    with a category label. Not exhaustive — the underlying tail of the original
    output is always preserved by the caller.
    """
    if not text:
        return "no output captured from the build"
    t = text.lower()
    cats: list[str] = []

    if re.search(r"\bmoc(_|\b).*error|q_object.*not found|no relevant classes|undefined interface", t):
        cats.append("MOC")
    if re.search(r"undefined reference|multiple definition|ld returned|cannot find -l", t):
        cats.append("LINK")
    if re.search(r"no such file or directory #include|file or directory", t):
        cats.append("INCLUDE")
    if re.search(r"expected '|'{|}|\(|;|primary-expression|was not declared|has not been declared", t):
        cats.append("C++-SYNTAX")
    if re.search(r"qmake:.*error|cannot find.*\.pro|project file", t):
        cats.append("QMAKE")

    if not cats:
        return "UNCATEGORIZED — paste the tail into a search engine; the pattern is unusual."

    hints = {
        "MOC": "Run qt_moc_check on the offending header(s) for a precise diagnosis (Q_OBJECT / signal signature / missing #include).",
        "LINK": "Add the missing library to LIBS in the .pro, or implement the missing function. Use qt_deps to see what DLLs the previous .exe imported.",
        "INCLUDE": "Add the missing directory to INCLUDEPATH in the .pro (qt_pro_edit INCLUDEPATH ...).",
        "C++-SYNTAX": "Open the file:line reported above; the source has a typo (missing semicolon, unmatched brace, wrong argument type).",
        "QMAKE": "The .pro file itself is malformed. Re-read it (qt_pro_edit list) and look at the line qmake complained about.",
    }
    out = [f"Category: {'+'.join(cats)}"]
    for c in cats:
        out.append(f"  [{c}] {hints[c]}")
    return "\n".join(out)


# --- Diagnostics parser ------------------------------------------------------
# Structured JSON view over build output, modeled after davecotter/Qt-Creator-
# MCP-Plugin's getBuildDiagnostics. The text-output _categorize_build_error
# above stays as a coarse human hint; this layer is for precise file:line:col.

_ANSI_RE = re.compile(r"\x1b\[[0-9;]*[A-Za-z]")


def _strip_ansi(s: str) -> str:
    return _ANSI_RE.sub("", s)


# g++/clang with column:    main.cpp:10:5: error: 'foo' was not declared
#                           main.cpp:10:5: warning: unused variable [-Wunused-variable]
#                           main.cpp:10:5: note:   in expansion of macro 'X'
_GCC_RE = re.compile(
    r"^(?P<file>[^:][^:]*?):(?P<line>\d+):(?P<col>\d+):\s+"
    r"(?P<severity>fatal error|error|warning|note):\s+"
    r"(?P<message>.+?)(?:\s+\[(?P<code>-W[^\]]+)\])?\s*$"
)
# g++ without column:        main.cpp:10: error: ...
_GCC_NO_COL_RE = re.compile(
    r"^(?P<file>[^:][^:]*?):(?P<line>\d+):\s+"
    r"(?P<severity>fatal error|error|warning|note):\s+"
    r"(?P<message>.+?)(?:\s+\[(?P<code>-W[^\]]+)\])?\s*$"
)
# moc:  moc_xxx.cpp:10:5: Error: ...    or   moc_xxx.cpp:10: Error: ...
_MOC_RE = re.compile(
    r"^moc_(?P<file>[^:]+?)\.cpp:(?P<line>\d+):(?P<col>\d+):\s+Error:\s+(?P<message>.+)$"
)
_MOC_NO_COL_RE = re.compile(
    r"^moc_(?P<file>[^:]+?)\.cpp:(?P<line>\d+):\s+Error:\s+(?P<message>.+)$"
)
# moc 5.14+ newer format:  header.h:6: Error: Not a signal or slot declaration
_MOC_HEADER_RE = re.compile(
    r"^(?P<file>[^:]+?):(?P<line>\d+):\s+Error:\s+(?P<message>.+)$"
)
# moc prefix:                moc: error: ...
_MOC_PREFIX_RE = re.compile(
    r"^moc:\s+(?P<severity>error|warning|note):\s+(?P<message>.+)$"
)
# uic / rcc
_UIC_RE = re.compile(r"^uic:\s+(?P<message>Error.+|error:\s+.+|warning:\s+.+)$", re.IGNORECASE)
_RCC_RE = re.compile(r"^rcc:\s+(?P<message>error:\s+.+|warning:\s+.+)$", re.IGNORECASE)
# qmake:                     "Project ERROR: ..."  /  "qmake: error: ..."
_QMAKE_RE = re.compile(r"^(?P<message>Project ERROR:.+|qmake:.*?error:.+)$", re.IGNORECASE)
# ld (mingw / g++):          undefined reference / multiple definition / cannot find -l
_LD_UNDEF_RE = re.compile(r"^undefined reference to [`'\"](?P<symbol>[^'\"]+)[`'\"]")
_LD_MULTI_RE = re.compile(r"^multiple definition of [`'\"](?P<symbol>[^'\"]+)[`'\"]")
_LD_LIB_RE = re.compile(r"^cannot find -l(?P<lib>\S+)")


def _diagnostic_suggestion(tool: str, message: str, code: Optional[str] = None) -> str:
    """One-line actionable hint for a single diagnostic."""
    m = message.lower()
    if tool == "moc":
        if "no relevant classes" in m:
            return "moc found no Q_OBJECT classes in the header. Add `Q_OBJECT` inside the class declaration."
        if "q_object" in m or "undefined interface" in m:
            return "Missing or misspelled Q_OBJECT macro / signal-slot signature. Run qt_moc_check on the header."
        return "MOC error — run qt_moc_check on the offending header for a precise diagnosis."
    if tool == "ld":
        sym = _LD_UNDEF_RE.match(message)
        if sym:
            return f"Undefined symbol '{sym.group('symbol')}' — add the library to LIBS or implement the function."
        if _LD_MULTI_RE.match(message):
            return "Symbol defined in multiple object files — check for missing `inline` / `static` or duplicate source."
        lib = _LD_LIB_RE.match(message)
        if lib:
            return f"Cannot find -l{lib.group('lib')} — add the library path to LIBS in the .pro (qt_pro_edit LIBS += ...)."
        return "Linker error — check LIBS in the .pro and use qt_deps on the previous .exe to see imports."
    if tool == "uic":
        return "UI file syntax error — open the .ui in Qt Designer or fix the XML manually."
    if tool == "rcc":
        return "Resource (.qrc) file error — check the .qrc file paths and the files they reference exist."
    if tool == "qmake":
        return "The .pro file itself is malformed. Re-read it (qt_pro_edit list) and look at the line qmake complained about."
    if tool in ("gcc", "g++"):
        if "no such file or directory" in m and "include" in m:
            return "Missing header — add the directory to INCLUDEPATH in the .pro (qt_pro_edit INCLUDEPATH ...)."
        if "was not declared" in m or "has not been declared" in m or "undeclared" in m:
            return f"Undeclared identifier — open the file:line reported; typo or missing #include. [{code or 'gcc'}]"
        if "expected" in m:
            return "C++ syntax error — missing token (semicolon, brace, paren, etc.). Open file:line."
        if "unused" in m and code and code.startswith("-W"):
            return f"Warning {code} — fix or silence with a pragma."
        return f"Compiler {code or 'error'} — open the file:line reported."
    return "Inspect the file:line reported in the message."


def _parse_diagnostics(text: str, project_dir: Optional[Path] = None) -> list[dict]:
    """Parse mingw32-make / g++ / moc / uic / rcc / qmake / ld output into JSON-ready dicts.

    Each entry: {severity, file, line, column, tool, code, message, suggestion}.
    Identical lines (e.g. duplicated by parallel make workers) are deduped.
    """
    if not text:
        return []
    out: list[dict] = []
    seen: set[tuple] = set()
    text = _strip_ansi(text)
    for raw in text.splitlines():
        line = raw.rstrip()
        if not line:
            continue
        diag: Optional[dict] = None

        m = _GCC_RE.match(line)
        if m:
            sev = m["severity"]
            diag = {
                "severity": "error" if sev in ("error", "fatal error") else ("warning" if sev == "warning" else "info"),
                "file": m["file"],
                "line": int(m["line"]),
                "column": int(m["col"]),
                "tool": "gcc",
                "code": m["code"],
                "message": m["message"].strip(),
            }
        if diag is None:
            m = _MOC_RE.match(line) or _MOC_NO_COL_RE.match(line)
            if m:
                diag = {
                    "severity": "error",
                    "file": "moc_" + m["file"] + ".cpp",
                    "line": int(m["line"]),
                    "column": int(m["col"]) if m["col"] else None,
                    "tool": "moc",
                    "code": None,
                    "message": m["message"].strip(),
                }
        if diag is None:
            m = _MOC_HEADER_RE.match(line)
            if m and m["file"].endswith((".h", ".hpp", ".hh", ".hxx")):
                diag = {
                    "severity": "error",
                    "file": m["file"],
                    "line": int(m["line"]),
                    "column": None,
                    "tool": "moc",
                    "code": None,
                    "message": m["message"].strip(),
                }
        if diag is None:
            m = _MOC_PREFIX_RE.match(line)
            if m:
                sev = m["severity"]
                diag = {
                    "severity": "error" if sev == "error" else ("warning" if sev == "warning" else "info"),
                    "file": None,
                    "line": None,
                    "column": None,
                    "tool": "moc",
                    "code": None,
                    "message": m["message"].strip(),
                }
        if diag is None:
            m = _UIC_RE.match(line)
            if m:
                diag = {
                    "severity": "error",
                    "file": None,
                    "line": None,
                    "column": None,
                    "tool": "uic",
                    "code": None,
                    "message": m["message"].strip(),
                }
        if diag is None:
            m = _RCC_RE.match(line)
            if m:
                diag = {
                    "severity": "error" if "error" in m["message"].lower() else "warning",
                    "file": None,
                    "line": None,
                    "column": None,
                    "tool": "rcc",
                    "code": None,
                    "message": m["message"].strip(),
                }
        if diag is None:
            m = _QMAKE_RE.match(line)
            if m:
                diag = {
                    "severity": "error",
                    "file": None,
                    "line": None,
                    "column": None,
                    "tool": "qmake",
                    "code": None,
                    "message": m["message"].strip(),
                }
        if diag is None and (
            _LD_UNDEF_RE.match(line) or _LD_MULTI_RE.match(line) or _LD_LIB_RE.match(line)
        ):
            diag = {
                "severity": "error",
                "file": None,
                "line": None,
                "column": None,
                "tool": "ld",
                "code": None,
                "message": line,
            }
        if diag is None:
            continue

        if diag["file"] and project_dir and not Path(diag["file"]).is_absolute():
            try:
                diag["file"] = str((project_dir / diag["file"]).resolve())
            except OSError:
                pass
        diag["suggestion"] = _diagnostic_suggestion(diag["tool"], diag["message"], diag["code"])

        key = (diag["tool"], diag["file"], diag["line"], diag["column"], diag["message"])
        if key in seen:
            continue
        seen.add(key)
        out.append(diag)
    return out


def _diagnostics_log_path(project_dir: Path) -> Path:
    return project_dir / ".qt_mcp_last_build.log"


def _save_build_log(project_dir: Path, qmake: Optional[CmdResult], make: Optional[CmdResult]) -> None:
    """Sidecar log of the most recent build so qt_build_diagnostics can re-parse it."""
    parts: list[str] = []
    if qmake is not None:
        parts.append("=== qmake ===")
        if qmake.stderr:
            parts.append(qmake.stderr)
        if qmake.stdout:
            parts.append(qmake.stdout)
    if make is not None:
        parts.append("\n=== make ===")
        if make.stderr:
            parts.append(make.stderr)
        if make.stdout:
            parts.append(make.stdout)
    try:
        _diagnostics_log_path(project_dir).write_text("\n".join(parts), encoding="utf-8", errors="replace")
    except OSError:
        pass


def _format_diagnostics_block(diagnostics: list[dict]) -> str:
    """Render a `--- diagnostics (JSON) ---` block for inclusion in tool output."""
    if not diagnostics:
        return ""
    body = json.dumps(diagnostics, indent=2, ensure_ascii=False)
    return "\n\n--- diagnostics (JSON) ---\n" + body


