def _pro_file(name: str) -> str:
    return f"""QT       += core gui widgets

CONFIG   += c++17
TARGET   = {name}
TEMPLATE = app

SOURCES += main.cpp \\
           {name}window.cpp

HEADERS += {name}window.h

FORMS   += {name}window.ui

# Default rules for deployment.
qnx: target.path = /tmp/$${{TARGET}}/bin
else: target.path = $$[QT_INSTALL_BINS]/$${{TARGET}}
!isEmpty(target.path): INSTALLS += target
"""


def _main_cpp(name: str, klass: str) -> str:
    return f"""#include <QApplication>
#include "{name}window.h"

int main(int argc, char *argv[]) {{
    QApplication a(argc, argv);
    {klass} w;
    w.show();
    return a.exec();
}}
"""


def _pro_file_console(name: str) -> str:
    return f"""QT       += core

CONFIG   += c++17 console
CONFIG   -= app_bundle
TARGET   = {name}
TEMPLATE = app

SOURCES += main.cpp

# Default rules for deployment.
qnx: target.path = /tmp/$${{TARGET}}/bin
else: target.path = $$[QT_INSTALL_BINS]/$${{TARGET}}

INSTALLS += target
"""


def _main_cpp_console(name: str) -> str:
    return f"""#include <QCoreApplication>
#include <QCommandLineParser>
#include <QCommandLineOption>
#include <QTextStream>
#include <QDebug>

int main(int argc, char *argv[]) {{
    QCoreApplication a(argc, argv);
    QCoreApplication::setApplicationName("{name}");
    QCoreApplication::setApplicationVersion("0.1.0");

    QCommandLineParser parser;
    parser.setApplicationDescription("{name} — Qt console tool skeleton (no GUI).");
    parser.addHelpOption();
    parser.addVersionOption();
    QCommandLineOption verboseOption({{"v", "verbose"}}, "Emit verbose progress on stderr.");
    QCommandLineOption inputOption({{"i", "input"}}, "Input file path.", "path");
    parser.addOption(verboseOption);
    parser.addOption(inputOption);
    parser.process(a);

    QTextStream out(stdout);
    QTextStream err(stderr);
    const bool verbose = parser.isSet(verboseOption);
    const QString input = parser.value(inputOption);

    if (verbose) {{
        err << "[{name}] starting (Qt " << qVersion() << ")" << Qt::endl;
        if (!input.isEmpty()) err << "[{name}] input=" << input << Qt::endl;
    }}
    out << "{name} OK" << Qt::endl;
    return 0;
}}
"""


def _widget_header(name: str, klass: str) -> str:
    return f"""#ifndef {klass.upper()}_H
#define {klass.upper()}_H

#include <QWidget>

QT_BEGIN_NAMESPACE
namespace Ui {{ class {klass}; }}
QT_END_NAMESPACE

class {klass} : public QWidget {{
    Q_OBJECT

public:
    explicit {klass}(QWidget *parent = nullptr);
    ~{klass}();

private:
    Ui::{klass} *ui;
}};

#endif // {klass.upper()}_H
"""


def _widget_source(name: str, klass: str) -> str:
    return f"""#include "{name}window.h"
#include "ui_{name}window.h"

{klass}::{klass}(QWidget *parent)
    : QWidget(parent)
    , ui(new Ui::{klass})
{{
    ui->setupUi(this);
}}

{klass}::~{klass}() {{
    delete ui;
}}
"""


def _widget_ui(klass: str) -> str:
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<ui version="4.0">
 <class>{klass}</class>
 <widget class="QWidget">
  <property name="geometry">
   <rect>
    <x>0</x>
    <y>0</y>
    <width>400</width>
    <height>300</height>
   </rect>
  </property>
  <property name="windowTitle">
   <string>{klass}</string>
  </property>
 </widget>
 <resources/>
 <connections/>
</ui>
"""


def _pro_file_qml(name: str) -> str:
    """A minimal .pro for a Qt Quick app: needs QML/Quick/QuickWidgets modules."""
    return f"""QT       += core gui qml quick quickwidgets

CONFIG   += c++17
TARGET   = {name}
TEMPLATE = app

SOURCES += main.cpp

# Default rules for deployment.
qnx: target.path = /tmp/$${{TARGET}}/bin
else: target.path = $$[QT_INSTALL_BINS]/$${{TARGET}}
!isEmpty(target.path): INSTALLS += target
"""


def _main_cpp_qml(name: str) -> str:
    """A main.cpp that hosts a QML scene via QQuickWidget, loading the .qml from disk so no .qrc round-trip is needed for hot-reload during development."""
    return f"""#include <QApplication>
#include <QQuickWidget>
#include <QFileInfo>

int main(int argc, char *argv[]) {{
    QApplication app(argc, argv);
    app.setApplicationName("{name}");

    QQuickWidget view;
    view.setSource(QUrl::fromLocalFile(QFileInfo("{name}.qml").absoluteFilePath()));
    view.setResizeMode(QQuickWidget::SizeRootObjectToView);
    view.resize(640, 480);
    view.show();

    return app.exec();
}}
"""


def _qml_main_app(name: str) -> str:
    """A starter Qt Quick 2 ApplicationWindow with a label + button, so the project runs out of the box."""
    return f"""import QtQuick 2.14
import QtQuick.Window 2.14
import QtQuick.Controls 2.14

ApplicationWindow {{
    id: root
    width: 640
    height: 480
    visible: true
    title: qsTr("{name}")

    Column {{
        anchors.centerIn: parent
        spacing: 12

        Label {{
            id: helloLabel
            text: qsTr("Hello from {name}!")
            font.pixelSize: 24
            horizontalAlignment: Text.AlignHCenter
        }}

        Button {{
            id: greetButton
            text: qsTr("Greet")
            onClicked: helloLabel.text = qsTr("Greetings, friend.")
        }}
    }}
}}
"""


def _pro_file_game(name: str, extra_sources: list[str], extra_headers: list[str], extra_forms: list[str]) -> str:
    """A .pro that pulls in everything under ./game and ./view plus the root window.

    Empty lists skip the corresponding variable entirely, so qmake never sees
    a trailing backslash on an empty line.
    """
    sections: list[str] = [
        f"TARGET   = {name}",
        "TEMPLATE = app",
    ]

    def block(var: str, items: list[str]) -> str:
        if not items:
            return ""
        body = " \\\n".join(f"           {x}" for x in items)
        return f"{var} += \\\n{body}"

    sections.append(block("SOURCES", ["main.cpp", f"{name}window.cpp", *extra_sources]))
    sections.append(block("HEADERS", [f"{name}window.h", *extra_headers]))
    forms = [f"{name}window.ui", *extra_forms]
    if forms:
        sections.append(block("FORMS", forms))

    sections.append("")
    sections.append("# Default rules for deployment.")
    sections.append("qnx: target.path = /tmp/$${TARGET}/bin")
    sections.append("else: target.path = $$[QT_INSTALL_BINS]/$${TARGET}")
    sections.append("!isEmpty(target.path): INSTALLS += target")

    return "QT       += core gui widgets\nCONFIG   += c++17\n\n" + "\n".join(sections) + "\n"


def _card_class_h() -> str:
    return """#ifndef CARD_H
#define CARD_H

#include <QString>

class Card {
public:
    enum Suit { Spade, Heart, Diamond, Club };
    enum Rank { Ace = 1, Two, Three, Four, Five, Six, Seven, Eight, Nine, Ten, Jack, Queen, King };

    Card(Suit s, Rank r) : m_suit(s), m_rank(r) {}
    Suit suit() const { return m_suit; }
    Rank rank() const { return m_rank; }
    bool faceUp() const { return m_faceUp; }
    void setFaceUp(bool f) { m_faceUp = f; }

    int value() const { return static_cast<int>(m_rank); }                 // 1..13
    bool isRed() const { return m_suit == Heart || m_suit == Diamond; }

    QString suitSymbol() const {
        switch (m_suit) {
            case Spade:   return QStringLiteral("\\u2660");   // ♠
            case Heart:   return QStringLiteral("\\u2665");   // ♥
            case Diamond: return QStringLiteral("\\u2666");   // ♦
            case Club:    return QStringLiteral("\\u2663");   // ♣
        }
        return QStringLiteral("?");
    }

    QString rankLabel() const {
        switch (m_rank) {
            case Ace:   return QStringLiteral("A");
            case Jack:  return QStringLiteral("J");
            case Queen: return QStringLiteral("Q");
            case King:  return QStringLiteral("K");
            default:    return QString::number(static_cast<int>(m_rank));
        }
    }

    bool operator<(const Card& other) const {
        if (m_suit != other.m_suit) return m_suit < other.m_suit;
        return m_rank < other.m_rank;
    }

private:
    Suit m_suit;
    Rank m_rank;
    bool m_faceUp = true;
};

#endif // CARD_H
"""


