def _game_controller_h() -> str:
    return """#ifndef GAMECONTROLLER_H
#define GAMECONTROLLER_H

#include <QObject>
#include <QVector>
#include "player.h"
#include "card.h"

// GameController is the model: owns game state, knows the rules.
// It emits signals; the View (GameView) listens and redraws.
class GameController : public QObject {
    Q_OBJECT

public:
    explicit GameController(QObject* parent = nullptr);
    ~GameController() override;

    // Lifecycle hooks you implement for your specific game.
    virtual void startNewGame();           // shuffle, deal, set first player
    virtual void onCardPlayed(int playerIdx, const Card& card);
    virtual bool isGameOver() const;
    virtual int  winnerIndex() const;      // -1 if not over

    QVector<Player>& players() { return m_players; }
    const QVector<Player>& players() const { return m_players; }

    int  currentPlayerIndex() const { return m_currentPlayer; }
    int  deckSize() const { return int(m_deck.size()); }

signals:
    void stateChanged();                   // view repaints on this
    void gameOver(int winnerIdx);

protected:
    QVector<Player> m_players;
    QVector<Card>   m_deck;
    int             m_currentPlayer = 0;
};

#endif // GAMECONTROLLER_H
"""


def _game_controller_cpp() -> str:
    return """#include "gamecontroller.h"

#include <algorithm>
#include <random>

GameController::GameController(QObject* parent) : QObject(parent) {
    m_players.append(Player(QStringLiteral("Player 1")));
    m_players.append(Player(QStringLiteral("Player 2")));
}

GameController::~GameController() = default;

void GameController::startNewGame() {
    m_deck.clear();
    for (int s = 0; s < 4; ++s) {
        for (int r = 1; r <= 13; ++r) {
            m_deck.append(Card(static_cast<Card::Suit>(s), static_cast<Card::Rank>(r)));
        }
    }
    std::random_device rd;
    std::mt19937 rng(rd());
    std::shuffle(m_deck.begin(), m_deck.end(), rng);
    m_currentPlayer = 0;
    emit stateChanged();
}

void GameController::onCardPlayed(int playerIdx, const Card& /*card*/) {
    if (playerIdx >= 0 && playerIdx < int(m_players.size())) {
        m_currentPlayer = (playerIdx + 1) % m_players.size();
    }
    emit stateChanged();
    if (isGameOver()) {
        emit gameOver(winnerIndex());
    }
}

bool GameController::isGameOver() const {
    return m_deck.isEmpty();
}

int GameController::winnerIndex() const {
    int best = 0;
    for (int i = 1; i < m_players.size(); ++i) {
        if (m_players[i].score() > m_players[best].score()) best = i;
    }
    return m_deck.isEmpty() ? best : -1;
}
"""


def _card_widget_h() -> str:
    return """#ifndef CARDWIDGET_H
#define CARDWIDGET_H

#include <QWidget>
#include "card.h"

// A single on-screen card. Pure QPainter drawing; no image assets required.
class CardWidget : public QWidget {
    Q_OBJECT
    Q_PROPERTY(Card card READ card WRITE setCard NOTIFY cardChanged)
    Q_PROPERTY(bool selected READ isSelected WRITE setSelected NOTIFY selectionChanged)

public:
    explicit CardWidget(QWidget* parent = nullptr);
    ~CardWidget() override;

    Card card() const { return m_card; }
    void setCard(const Card& c);

    bool isSelected() const { return m_selected; }
    void setSelected(bool s);

    QSize sizeHint() const override { return QSize(80, 120); }
    QSize minimumSizeHint() const override { return QSize(60, 90); }

signals:
    void cardChanged();
    void selectionChanged();
    void clicked();

protected:
    void paintEvent(QPaintEvent* event) override;
    void mousePressEvent(QMouseEvent* event) override;

private:
    Card m_card{Card::Spade, Card::Ace};
    bool m_selected = false;
};

#endif // CARDWIDGET_H
"""


def _card_widget_cpp() -> str:
    return """#include "cardwidget.h"

#include <QPainter>
#include <QPaintEvent>
#include <QMouseEvent>

CardWidget::CardWidget(QWidget* parent) : QWidget(parent) {
    setAttribute(Qt::WA_StyledBackground, false);
}

CardWidget::~CardWidget() = default;

void CardWidget::setCard(const Card& c) {
    m_card = c;
    update();
    emit cardChanged();
}

void CardWidget::setSelected(bool s) {
    if (m_selected == s) return;
    m_selected = s;
    update();
    emit selectionChanged();
}

void CardWidget::paintEvent(QPaintEvent* /*event*/) {
    QPainter p(this);
    p.setRenderHint(QPainter::Antialiasing);

    const QRectF r = rect().adjusted(2, 2, -2, -2);
    const qreal radius = 8.0;

    // Card body
    p.setPen(m_selected ? QPen(Qt::yellow, 3) : QPen(Qt::black, 1));
    p.setBrush(m_card.faceUp() ? QColor(Qt::white) : QColor(60, 80, 160));
    p.drawRoundedRect(r, radius, radius);

    if (!m_card.faceUp()) {
        // Simple pattern on the back
        p.setPen(Qt::NoPen);
        p.setBrush(QColor(80, 100, 180));
        p.drawRoundedRect(r.adjusted(8, 8, -8, -8), radius, radius);
        return;
    }

    // Suit color
    const QColor textColor = m_card.isRed() ? Qt::red : Qt::black;
    p.setPen(textColor);

    // Top-left rank + suit
    QFont f = p.font();
    f.setPointSizeF(11);
    f.setBold(true);
    p.setFont(f);
    p.drawText(r.adjusted(6, 4, 0, 0), Qt::AlignTop | Qt::AlignLeft,
               m_card.rankLabel());
    p.drawText(r.adjusted(6, 22, 0, 0), Qt::AlignTop | Qt::AlignLeft,
               m_card.suitSymbol());

    // Centered large suit
    f.setPointSizeF(36);
    p.setFont(f);
    p.drawText(r, Qt::AlignCenter, m_card.suitSymbol());

    // Bottom-right rank + suit (rotated 180)
    p.save();
    p.translate(r.bottomRight());
    p.rotate(180);
    p.drawText(QRectF(QPointF(0, 0), r.size()).adjusted(6, 4, 0, 0),
               Qt::AlignTop | Qt::AlignLeft, m_card.rankLabel());
    p.drawText(QRectF(QPointF(0, 0), r.size()).adjusted(6, 22, 0, 0),
               Qt::AlignTop | Qt::AlignLeft, m_card.suitSymbol());
    p.restore();
}

void CardWidget::mousePressEvent(QMouseEvent* /*event*/) {
    setSelected(!m_selected);
    emit clicked();
}
"""


