def _write_scaffold(out_dir: Path, name: str, tpl: ScaffoldTemplate) -> None:
    klass = name[0].upper() + name[1:] if name else "MainWindow"
    if tpl in (ScaffoldTemplate.MAIN_WINDOW, ScaffoldTemplate.CARDS_GAME, ScaffoldTemplate.CHESS_GAME, ScaffoldTemplate.GENERIC_GAME):
        klass = "MainWindow"

    if tpl in (ScaffoldTemplate.WIDGET, ScaffoldTemplate.MAIN_WINDOW, ScaffoldTemplate.DIALOG):
        (out_dir / f"{name}.pro").write_text(_pro_file(name), encoding="utf-8")
        (out_dir / "main.cpp").write_text(_main_cpp(name, klass), encoding="utf-8")
        (out_dir / f"{name}window.h").write_text(_widget_header(name, klass), encoding="utf-8")
        (out_dir / f"{name}window.cpp").write_text(_widget_source(name, klass), encoding="utf-8")
        (out_dir / f"{name}window.ui").write_text(_widget_ui(klass), encoding="utf-8")
        return

    if tpl == ScaffoldTemplate.QML_APP:
        (out_dir / f"{name}.pro").write_text(_pro_file_qml(name), encoding="utf-8")
        (out_dir / "main.cpp").write_text(_main_cpp_qml(name), encoding="utf-8")
        (out_dir / f"{name}.qml").write_text(_qml_main_app(name), encoding="utf-8")
        return

    if tpl == ScaffoldTemplate.CONSOLE_APP:
        (out_dir / f"{name}.pro").write_text(_pro_file_console(name), encoding="utf-8")
        (out_dir / "main.cpp").write_text(_main_cpp_console(name), encoding="utf-8")
        return

    # ---- Game templates ----
    game_dir = out_dir / "game"
    view_dir = out_dir / "view"
    res_dir = out_dir / "resources"
    game_dir.mkdir(parents=True, exist_ok=True)
    view_dir.mkdir(parents=True, exist_ok=True)
    res_dir.mkdir(parents=True, exist_ok=True)

    extra_sources = ["game/gamecontroller.cpp", "view/gameview.cpp"]
    extra_headers = ["game/card.h", "game/player.h", "game/gamecontroller.h",
                     "view/gameview.h"]
    extra_forms: list[str] = []

    if tpl == ScaffoldTemplate.CARDS_GAME:
        extra_sources += ["game/card.cpp", "game/player.cpp", "view/cardwidget.cpp"]
        extra_headers += ["view/cardwidget.h"]
        (game_dir / "card.cpp").write_text(
            "// Card is a plain data class with no Qt dependencies — defined entirely in card.h\n",
            encoding="utf-8")
        (game_dir / "player.cpp").write_text(
            "// Player is a plain data class with no Qt dependencies — defined entirely in player.h\n",
            encoding="utf-8")
        (view_dir / "cardwidget.h").write_text(_card_widget_h(), encoding="utf-8")
        (view_dir / "cardwidget.cpp").write_text(_card_widget_cpp(), encoding="utf-8")

    (out_dir / f"{name}.pro").write_text(
        _pro_file_game(name, extra_sources, extra_headers, extra_forms), encoding="utf-8")
    (out_dir / "main.cpp").write_text(_main_cpp(name, klass), encoding="utf-8")
    (out_dir / f"{name}window.h").write_text(_widget_header(name, klass), encoding="utf-8")
    (out_dir / f"{name}window.cpp").write_text(_widget_source(name, klass), encoding="utf-8")
    (out_dir / f"{name}window.ui").write_text(_widget_ui(klass), encoding="utf-8")

    (game_dir / "card.h").write_text(_card_class_h(), encoding="utf-8")
    (game_dir / "player.h").write_text(_player_class_h(), encoding="utf-8")
    (game_dir / "gamecontroller.h").write_text(_game_controller_h(), encoding="utf-8")
    (game_dir / "gamecontroller.cpp").write_text(_game_controller_cpp(), encoding="utf-8")
    (view_dir / "gameview.h").write_text(_game_view_h(), encoding="utf-8")
    (view_dir / "gameview.cpp").write_text(
        _game_view_cpp(has_cardwidget=(tpl == ScaffoldTemplate.CARDS_GAME)),
        encoding="utf-8",
    )

    (res_dir / "README.txt").write_text(
        "Drop your card / icon assets here, then call qt_gen_qrc to wire them into the build.\n",
        encoding="utf-8")

    if tpl == ScaffoldTemplate.TICTACTOE_GAME:
        _write_tictactoe_game(out_dir, name)
        return
    if tpl == ScaffoldTemplate.BREAKOUT_GAME:
        _write_breakout_game(out_dir, name)
        return
    if tpl == ScaffoldTemplate.TASKLIST:
        _write_tasklist(out_dir, name)
        return
    if tpl == ScaffoldTemplate.MUSIC_PLAYER:
        _write_music_player(out_dir, name)
        return
    if tpl == ScaffoldTemplate.GAME_FRAMEWORK:
        _write_game_framework(out_dir, name)


# --- v0.3.8: SCU 16 项目库 实战模板 -----------------------------------------


def _write_tictactoe_game(out_dir: Path, name: str) -> None:
    """井字棋教学模板 (SCU 项目库 13). 3x3 QGridLayout + 9 QPushButton + X/O 切换 + 胜利检测."""
    main_h = f"""#ifndef {name.upper()}_H
#define {name.upper()}_H

#include <QMainWindow>
#include <QPushButton>
#include <QLabel>
#include <QGridLayout>

class {name.capitalize()}Window : public QMainWindow {{
    Q_OBJECT
public:
    explicit {name.capitalize()}Window(QWidget *parent = nullptr);
    ~{name.capitalize()}Window() override;

private slots:
    void onCellClicked();
    void onResetClicked();

private:
    QPushButton *m_cells[3][3];
    QLabel *m_statusLabel;
    char m_currentPlayer;
    int m_moveCount;

    bool checkWinner() const;
    void updateStatus();
    void resetBoard();
}};

#endif // {name.upper()}_H
"""

    main_cpp = f"""#include "{name}window.h"

{name.capitalize()}Window::{name.capitalize()}Window(QWidget *parent)
    : QMainWindow(parent), m_currentPlayer('X'), m_moveCount(0) {{
    setWindowTitle(tr("Tic Tac Toe - SCU Project Library #13"));
    resize(400, 450);

    auto *central = new QWidget(this);
    auto *layout = new QVBoxLayout(central);

    m_statusLabel = new QLabel(tr("Player X's turn"), this);
    m_statusLabel->setAlignment(Qt::AlignCenter);
    layout->addWidget(m_statusLabel);

    auto *grid = new QGridLayout;
    for (int r = 0; r < 3; ++r) {{
        for (int c = 0; c < 3; ++c) {{
            m_cells[r][c] = new QPushButton("", this);
            m_cells[r][c]->setFixedSize(100, 100);
            m_cells[r][c]->setFont(QFont("Arial", 24, QFont::Bold));
            grid->addWidget(m_cells[r][c], r, c);
            connect(m_cells[r][c], &QPushButton::clicked, this, &{name.capitalize()}Window::onCellClicked);
        }}
    }}
    layout->addLayout(grid);

    auto *resetBtn = new QPushButton(tr("Reset"), this);
    connect(resetBtn, &QPushButton::clicked, this, &{name.capitalize()}Window::onResetClicked);
    layout->addWidget(resetBtn);

    setCentralWidget(central);
    statusBar()->showMessage(tr("Tic Tac Toe - SCU project library #13"));
}}

{name.capitalize()}Window::~{name.capitalize()}Window() {{}}

void {name.capitalize()}Window::onCellClicked() {{
    auto *btn = qobject_cast<QPushButton*>(sender());
    if (!btn || !btn->text().isEmpty()) return;

    btn->setText(QString(m_currentPlayer));
    m_moveCount++;

    if (checkWinner()) {{
        m_statusLabel->setText(tr("Player %1 wins!").arg(m_currentPlayer));
        for (int r = 0; r < 3; ++r) for (int c = 0; c < 3; ++c) m_cells[r][c]->setEnabled(false);
        return;
    }}
    if (m_moveCount >= 9) {{
        m_statusLabel->setText(tr("Draw!"));
        return;
    }}
    m_currentPlayer = (m_currentPlayer == 'X') ? 'O' : 'X';
    updateStatus();
}}

void {name.capitalize()}Window::onResetClicked() {{
    resetBoard();
}}

bool {name.capitalize()}Window::checkWinner() const {{
    for (int i = 0; i < 3; ++i) {{
        if (!m_cells[i][0]->text().isEmpty() && m_cells[i][0]->text() == m_cells[i][1]->text() && m_cells[i][1]->text() == m_cells[i][2]->text()) return true;
        if (!m_cells[0][i]->text().isEmpty() && m_cells[0][i]->text() == m_cells[1][i]->text() && m_cells[1][i]->text() == m_cells[2][i]->text()) return true;
    }}
    if (!m_cells[0][0]->text().isEmpty() && m_cells[0][0]->text() == m_cells[1][1]->text() && m_cells[1][1]->text() == m_cells[2][2]->text()) return true;
    if (!m_cells[0][2]->text().isEmpty() && m_cells[0][2]->text() == m_cells[1][1]->text() && m_cells[1][1]->text() == m_cells[2][0]->text()) return true;
    return false;
}}

void {name.capitalize()}Window::updateStatus() {{
    m_statusLabel->setText(tr("Player %1's turn").arg(m_currentPlayer));
}}

void {name.capitalize()}Window::resetBoard() {{
    m_currentPlayer = 'X';
    m_moveCount = 0;
    for (int r = 0; r < 3; ++r) {{
        for (int c = 0; c < 3; ++c) {{
            m_cells[r][c]->setText("");
            m_cells[r][c]->setEnabled(true);
        }}
    }}
    updateStatus();
}}
"""
    pro = f"""QT       += core gui widgets
CONFIG   += c++17
TARGET   = {name}
TEMPLATE = app
SOURCES += main.cpp \\
           {name}window.cpp
HEADERS += {name}window.h
"""
    main_cpp_simple = f"""#include <QApplication>
#include "{name}window.h"

int main(int argc, char *argv[]) {{
    QApplication app(argc, argv);
    {name.capitalize()}Window w;
    w.show();
    return app.exec();
}}
"""
    (out_dir / f"{name}.pro").write_text(pro, encoding="utf-8")
    (out_dir / "main.cpp").write_text(main_cpp_simple, encoding="utf-8")
    (out_dir / f"{name}window.h").write_text(main_h, encoding="utf-8")
    (out_dir / f"{name}window.cpp").write_text(main_cpp, encoding="utf-8")


def _write_breakout_game(out_dir: Path, name: str) -> None:
    """打砖块教学模板 (SCU 项目库 14). QTimer 动画 + keyPressEvent 控制 paddle + 碰撞检测."""
    main_h = f"""#ifndef {name.upper()}_H
#define {name.upper()}_H

#include <QMainWindow>
#include <QWidget>
#include <QTimer>
#include <QKeyEvent>
#include <QVector>
#include <QRect>

class {name.capitalize()}Window : public QMainWindow {{
    Q_OBJECT
public:
    explicit {name.capitalize()}Window(QWidget *parent = nullptr);
    ~{name.capitalize()}Window() override;

protected:
    void keyPressEvent(QKeyEvent *event) override;
    void paintEvent(QPaintEvent *event) override;

private:
    QTimer *m_timer;
    QRect m_paddle;
    QRect m_ball;
    QVector<QRect> m_bricks;
    int m_dx, m_dy;
    int m_score;

    void moveBall();
    void buildBricks();
    void drawGame(QPainter &p);
}};

#endif // {name.upper()}_H
"""

    main_cpp = f"""#include "{name}window.h"
#include <QPainter>

constexpr int GAME_WIDTH = 480;
constexpr int GAME_HEIGHT = 600;
constexpr int PADDLE_W = 80;
constexpr int PADDLE_H = 12;
constexpr int BALL_SIZE = 12;

{name.capitalize()}Window::{name.capitalize()}Window(QWidget *parent)
    : QMainWindow(parent), m_dx(3), m_dy(-3), m_score(0) {{
    setWindowTitle(tr("Breakout - SCU Project Library #14"));
    setFixedSize(GAME_WIDTH, GAME_HEIGHT);
    m_paddle = QRect(GAME_WIDTH/2 - PADDLE_W/2, GAME_HEIGHT - 40, PADDLE_W, PADDLE_H);
    m_ball = QRect(GAME_WIDTH/2, GAME_HEIGHT/2, BALL_SIZE, BALL_SIZE);
    buildBricks();

    m_timer = new QTimer(this);
    connect(m_timer, &QTimer::timeout, this, &{name.capitalize()}Window::moveBall);
    m_timer->start(20);
    setFocus();
    statusBar()->showMessage(tr("Use Left/Right arrow keys to move the paddle"));
}}

{name.capitalize()}Window::~{name.capitalize()}Window() {{}}

void {name.capitalize()}Window::buildBricks() {{
    m_bricks.clear();
    for (int r = 0; r < 5; ++r) {{
        for (int c = 0; c < 8; ++c) {{
            m_bricks.append(QRect(c * 60 + 5, r * 25 + 40, 50, 20));
        }}
    }}
}}

void {name.capitalize()}Window::keyPressEvent(QKeyEvent *event) {{
    if (event->key() == Qt::Key_Left && m_paddle.left() > 0)
        m_paddle.translate(-20, 0);
    else if (event->key() == Qt::Key_Right && m_paddle.right() < GAME_WIDTH)
        m_paddle.translate(20, 0);
    update();
}}

void {name.capitalize()}Window::paintEvent(QPaintEvent * /*event*/) {{
    QPainter p(this);
    drawGame(p);
}}

void {name.capitalize()}Window::drawGame(QPainter &p) {{
    p.fillRect(rect(), Qt::black);
    p.setBrush(Qt::white);
    p.drawRect(m_paddle);
    p.setBrush(Qt::yellow);
    p.drawEllipse(m_ball);
    p.setBrush(Qt::red);
    for (const auto &b : m_bricks) p.drawRect(b);
    p.setPen(Qt::white);
    p.setFont(QFont("Arial", 16, QFont::Bold));
    p.drawText(10, 25, tr("Score: %1").arg(m_score));
}}

void {name.capitalize()}Window::moveBall() {{
    m_ball.translate(m_dx, m_dy);
    if (m_ball.left() <= 0 || m_ball.right() >= GAME_WIDTH) m_dx = -m_dx;
    if (m_ball.top() <= 0) m_dy = -m_dy;
    if (m_ball.intersects(m_paddle)) {{
        m_dy = -qAbs(m_dy);
        m_ball.moveTo(m_ball.x(), m_paddle.top() - BALL_SIZE);
    }}
    for (int i = 0; i < m_bricks.size(); ++i) {{
        if (m_ball.intersects(m_bricks[i])) {{
            m_bricks.removeAt(i);
            m_dy = -m_dy;
            m_score += 10;
            break;
        }}
    }}
    if (m_ball.bottom() >= GAME_HEIGHT) {{
        m_timer->stop();
        statusBar()->showMessage(tr("Game Over - Final Score: %1").arg(m_score));
    }}
    update();
}}
"""
    pro = f"""QT       += core gui widgets
CONFIG   += c++17
TARGET   = {name}
TEMPLATE = app
SOURCES += main.cpp \\
           {name}window.cpp
HEADERS += {name}window.h
"""
    main_cpp_simple = f"""#include <QApplication>
#include "{name}window.h"

int main(int argc, char *argv[]) {{
    QApplication app(argc, argv);
    {name.capitalize()}Window w;
    w.show();
    return app.exec();
}}
"""
    (out_dir / f"{name}.pro").write_text(pro, encoding="utf-8")
    (out_dir / "main.cpp").write_text(main_cpp_simple, encoding="utf-8")
    (out_dir / f"{name}window.h").write_text(main_h, encoding="utf-8")
    (out_dir / f"{name}window.cpp").write_text(main_cpp, encoding="utf-8")


def _write_tasklist(out_dir: Path, name: str) -> None:
    """任务清单教学模板 (SCU 项目库 15). QListView + QStringListModel + add/remove."""
    main_h = f"""#ifndef {name.upper()}_H
#define {name.upper()}_H

#include <QMainWindow>
#include <QListView>
#include <QLineEdit>
#include <QPushButton>
#include <QStringListModel>
#include <QLabel>

class {name.capitalize()}Window : public QMainWindow {{
    Q_OBJECT
public:
    explicit {name.capitalize()}Window(QWidget *parent = nullptr);
    ~{name.capitalize()}Window() override;

private slots:
    void onAddClicked();
    void onRemoveClicked();
    void onClearClicked();

private:
    QListView *m_listView;
    QLineEdit *m_inputEdit;
    QPushButton *m_addBtn;
    QPushButton *m_removeBtn;
    QPushButton *m_clearBtn;
    QLabel *m_countLabel;
    QStringListModel *m_model;
    QStringList m_tasks;
}};

#endif // {name.upper()}_H
"""

    main_cpp = f"""#include "{name}window.h"

{name.capitalize()}Window::{name.capitalize()}Window(QWidget *parent)
    : QMainWindow(parent) {{
    setWindowTitle(tr("Task List - SCU Project Library #15"));
    resize(500, 400);

    auto *central = new QWidget(this);
    auto *layout = new QVBoxLayout(central);

    auto *inputLayout = new QHBoxLayout;
    m_inputEdit = new QLineEdit(this);
    m_inputEdit->setPlaceholderText(tr("Enter a new task..."));
    inputLayout->addWidget(m_inputEdit);

    m_addBtn = new QPushButton(tr("Add"), this);
    connect(m_addBtn, &QPushButton::clicked, this, &{name.capitalize()}Window::onAddClicked);
    inputLayout->addWidget(m_addBtn);

    layout->addLayout(inputLayout);

    m_listView = new QListView(this);
    m_model = new QStringListModel(this);
    m_listView->setModel(m_model);
    layout->addWidget(m_listView);

    auto *btnLayout = new QHBoxLayout;
    m_removeBtn = new QPushButton(tr("Remove Selected"), this);
    connect(m_removeBtn, &QPushButton::clicked, this, &{name.capitalize()}Window::onRemoveClicked);
    btnLayout->addWidget(m_removeBtn);

    m_clearBtn = new QPushButton(tr("Clear All"), this);
    connect(m_clearBtn, &QPushButton::clicked, this, &{name.capitalize()}Window::onClearClicked);
    btnLayout->addWidget(m_clearBtn);

    layout->addLayout(btnLayout);

    m_countLabel = new QLabel(tr("Total: 0 tasks"), this);
    layout->addWidget(m_countLabel);

    setCentralWidget(central);
    statusBar()->showMessage(tr("Task List - SCU project library #15"));
}}

{name.capitalize()}Window::~{name.capitalize()}Window() {{}}

void {name.capitalize()}Window::onAddClicked() {{
    QString text = m_inputEdit->text().trimmed();
    if (text.isEmpty()) return;
    m_tasks.append(text);
    m_model->setStringList(m_tasks);
    m_inputEdit->clear();
    m_countLabel->setText(tr("Total: %1 tasks").arg(m_tasks.size()));
}}

void {name.capitalize()}Window::onRemoveClicked() {{
    QModelIndex idx = m_listView->currentIndex();
    if (!idx.isValid()) return;
    m_tasks.removeAt(idx.row());
    m_model->setStringList(m_tasks);
    m_countLabel->setText(tr("Total: %1 tasks").arg(m_tasks.size()));
}}

void {name.capitalize()}Window::onClearClicked() {{
    m_tasks.clear();
    m_model->setStringList(m_tasks);
    m_countLabel->setText(tr("Total: 0 tasks"));
}}
"""
    pro = f"""QT       += core gui widgets
CONFIG   += c++17
TARGET   = {name}
TEMPLATE = app
SOURCES += main.cpp \\
           {name}window.cpp
HEADERS += {name}window.h
"""
    main_cpp_simple = f"""#include <QApplication>
#include "{name}window.h"

int main(int argc, char *argv[]) {{
    QApplication app(argc, argv);
    {name.capitalize()}Window w;
    w.show();
    return app.exec();
}}
"""
    (out_dir / f"{name}.pro").write_text(pro, encoding="utf-8")
    (out_dir / "main.cpp").write_text(main_cpp_simple, encoding="utf-8")
    (out_dir / f"{name}window.h").write_text(main_h, encoding="utf-8")
