def _write_music_player(out_dir: Path, name: str) -> None:
    """音乐播放器教学模板 (SCU 项目库 4). QMediaPlayer + 播放控制 + 进度条 + 文件对话框."""
    main_h = f"""#ifndef {name.upper()}_H
#define {name.upper()}_H

#include <QMainWindow>
#include <QMediaPlayer>
#include <QPushButton>
#include <QSlider>
#include <QLabel>
#include <QFileDialog>

class {name.capitalize()}Window : public QMainWindow {{
    Q_OBJECT
public:
    explicit {name.capitalize()}Window(QWidget *parent = nullptr);
    ~{name.capitalize()}Window() override;

private slots:
    void onOpenClicked();
    void onPlayClicked();
    void onPauseClicked();
    void onStopClicked();
    void onPositionChanged(qint64 position);
    void onDurationChanged(qint64 duration);
    void onMediaStatusChanged(QMediaPlayer::MediaStatus status);

private:
    QMediaPlayer *m_player;
    QPushButton *m_openBtn;
    QPushButton *m_playBtn;
    QPushButton *m_pauseBtn;
    QPushButton *m_stopBtn;
    QSlider *m_positionSlider;
    QLabel *m_statusLabel;
    QLabel *m_fileLabel;
}};

#endif // {name.upper()}_H
"""

    main_cpp = f"""#include "{name}window.h"

{name.capitalize()}Window::{name.capitalize()}Window(QWidget *parent)
    : QMainWindow(parent) {{
    setWindowTitle(tr("Music Player - SCU Project Library #4"));
    resize(600, 200);

    m_player = new QMediaPlayer(this);
    connect(m_player, &QMediaPlayer::positionChanged, this, &{name.capitalize()}Window::onPositionChanged);
    connect(m_player, &QMediaPlayer::durationChanged, this, &{name.capitalize()}Window::onDurationChanged);
    connect(m_player, &QMediaPlayer::mediaStatusChanged, this, &{name.capitalize()}Window::onMediaStatusChanged);

    auto *central = new QWidget(this);
    auto *layout = new QVBoxLayout(central);

    m_fileLabel = new QLabel(tr("No file loaded"), this);
    layout->addWidget(m_fileLabel);

    auto *ctrlLayout = new QHBoxLayout;
    m_openBtn = new QPushButton(tr("Open..."), this);
    connect(m_openBtn, &QPushButton::clicked, this, &{name.capitalize()}Window::onOpenClicked);
    ctrlLayout->addWidget(m_openBtn);

    m_playBtn = new QPushButton(tr("Play"), this);
    connect(m_playBtn, &QPushButton::clicked, this, &{name.capitalize()}Window::onPlayClicked);
    ctrlLayout->addWidget(m_playBtn);

    m_pauseBtn = new QPushButton(tr("Pause"), this);
    connect(m_pauseBtn, &QPushButton::clicked, this, &{name.capitalize()}Window::onPauseClicked);
    ctrlLayout->addWidget(m_pauseBtn);

    m_stopBtn = new QPushButton(tr("Stop"), this);
    connect(m_stopBtn, &QPushButton::clicked, this, &{name.capitalize()}Window::onStopClicked);
    ctrlLayout->addWidget(m_stopBtn);

    layout->addLayout(ctrlLayout);

    m_positionSlider = new QSlider(Qt::Horizontal, this);
    layout->addWidget(m_positionSlider);

    m_statusLabel = new QLabel(tr("Ready"), this);
    layout->addWidget(m_statusLabel);

    setCentralWidget(central);
    statusBar()->showMessage(tr("Music Player - SCU project library #4 (requires QtMultimedia)"));
}}

{name.capitalize()}Window::~{name.capitalize()}Window() {{}}

void {name.capitalize()}Window::onOpenClicked() {{
    QString file = QFileDialog::getOpenFileName(this, tr("Open Audio File"),
        "", tr("Audio Files (*.mp3 *.wav *.ogg *.flac);;All Files (*)"));
    if (file.isEmpty()) return;
    m_player->setMedia(QUrl::fromLocalFile(file));
    m_fileLabel->setText(file);
    m_statusLabel->setText(tr("Loaded: %1").arg(file));
}}

void {name.capitalize()}Window::onPlayClicked() {{ m_player->play(); }}
void {name.capitalize()}Window::onPauseClicked() {{ m_player->pause(); }}
void {name.capitalize()}Window::onStopClicked() {{ m_player->stop(); }}

void {name.capitalize()}Window::onPositionChanged(qint64 position) {{
    if (!m_positionSlider->isSliderDown()) m_positionSlider->setValue(static_cast<int>(position));
}}

void {name.capitalize()}Window::onDurationChanged(qint64 duration) {{
    m_positionSlider->setRange(0, static_cast<int>(duration));
}}

void {name.capitalize()}Window::onMediaStatusChanged(QMediaPlayer::MediaStatus status) {{
    if (status == QMediaPlayer::EndOfMedia) {{
        m_statusLabel->setText(tr("End of file"));
    }}
}}
"""
    pro = f"""QT       += core gui widgets multimedia
CONFIG   += c++17
TARGET   = {name}
TEMPLATE = app
SOURCES += main.cpp \\
           {name}window.cpp
HEADERS += {name}window.h
"""
    main_cpp_simple = f"""#include <QApplication>
#include "{name}window.h"

int main(int argc, char *argv[]) {{
    QApplication app(argc, argv);
    {name.capitalize()}Window w;
    w.show();
    return app.exec();
}}
"""
    (out_dir / f"{name}.pro").write_text(pro, encoding="utf-8")
    (out_dir / "main.cpp").write_text(main_cpp_simple, encoding="utf-8")
    (out_dir / f"{name}window.h").write_text(main_h, encoding="utf-8")
    (out_dir / f"{name}window.cpp").write_text(main_cpp, encoding="utf-8")


def _write_game_framework(out_dir: Path, name: str) -> None:
    """Emit the full generic game framework scaffold.

    Replaces the simple gamecontroller.cpp/gameview.cpp stubs produced by the
    generic_game branch above with a more complete M/V split that includes
    serializable GameState / GameAction base classes, pluggable AI, two
    worked-example games (Higher or Lower, Guess the Number), and a real
    MainWindow with sidebar / log / status bar.
    """
    game_dir = out_dir / "game"
    games_dir = game_dir / "games"
    view_dir = out_dir / "view"
    games_dir.mkdir(parents=True, exist_ok=True)

    # game/*
    (game_dir / "gamestate.h").write_text(gf_tpl.gamestate_h(), encoding="utf-8")
    (game_dir / "gameaction.h").write_text(gf_tpl.gameaction_h(), encoding="utf-8")
    (game_dir / "player.h").write_text(gf_tpl.player_h(), encoding="utf-8")
    (game_dir / "aiplayer.h").write_text(gf_tpl.aiplayer_h(), encoding="utf-8")
    (game_dir / "aiplayer.cpp").write_text(gf_tpl.aiplayer_cpp(), encoding="utf-8")
    (game_dir / "gamecontroller.h").write_text(gf_tpl.gamecontroller_h(), encoding="utf-8")
    (game_dir / "gamecontroller.cpp").write_text(gf_tpl.gamecontroller_cpp(), encoding="utf-8")

    # game/games/* — two reference implementations
    (games_dir / "higherlower.h").write_text(gf_tpl.higherlower_h(), encoding="utf-8")
    (games_dir / "higherlower.cpp").write_text(gf_tpl.higherlower_cpp(), encoding="utf-8")
    (games_dir / "guessnumber.h").write_text(gf_tpl.guessnumber_h(), encoding="utf-8")
    (games_dir / "guessnumber.cpp").write_text(gf_tpl.guessnumber_cpp(), encoding="utf-8")

    # view/*
    (view_dir / "gridwidget.h").write_text(gf_tpl.gridwidget_h(), encoding="utf-8")
    (view_dir / "gridwidget.cpp").write_text(gf_tpl.gridwidget_cpp(), encoding="utf-8")
    (view_dir / "cardwidget.h").write_text(gf_tpl.cardwidget_h(), encoding="utf-8")
    (view_dir / "cardwidget.cpp").write_text(gf_tpl.cardwidget_cpp(), encoding="utf-8")
    (view_dir / "gameview.h").write_text(gf_tpl.gameview_h(), encoding="utf-8")
    (view_dir / "gameview.cpp").write_text(gf_tpl.gameview_cpp(), encoding="utf-8")

    # Overwrite the .pro with the full framework version (game/games/* included).
    (out_dir / f"{name}.pro").write_text(gf_tpl.pro_file(), encoding="utf-8")

    # Overwrite the main window + main.cpp + .ui with the full-layout versions.
    (out_dir / "main.cpp").write_text(gf_tpl.main_cpp(), encoding="utf-8")
    (out_dir / f"{name}window.h").write_text(gf_tpl.mainwindow_h(), encoding="utf-8")
    (out_dir / f"{name}window.cpp").write_text(gf_tpl.mainwindow_cpp(), encoding="utf-8")
    (out_dir / f"{name}window.ui").write_text(gf_tpl.mainwindow_ui(), encoding="utf-8")

    (out_dir / "README.md").write_text(gf_tpl.readme_md(), encoding="utf-8")


