# --- Tool input models -------------------------------------------------------

class QtScaffoldInput(BaseModel):
    model_config = ConfigDict(str_strip_whitespace=True, extra="forbid")

    name: str = Field(..., description="Project name (lowercase, becomes .exe name)", min_length=1, max_length=40)
    template: ScaffoldTemplate = Field(default=ScaffoldTemplate.MAIN_WINDOW, description="UI scaffold type")
    output_dir: str = Field(..., description="Absolute path of directory to create files in (will be created if missing)")


class QtBuildInput(BaseModel):
    model_config = ConfigDict(extra="forbid")

    project_dir: str = Field(..., description="Absolute path to directory containing the .pro file")
    build_type: str = Field(default="debug", description="'debug' or 'release'")
    jobs: int = Field(default=4, description="Parallel make jobs", ge=1, le=32)
    clean_first: bool = Field(default=False, description="Run 'mingw32-make distclean' before building")
    timeout: int = Field(default=300, description="Build timeout in seconds", ge=10, le=3600)


class QtRunInput(BaseModel):
    model_config = ConfigDict(extra="forbid")

    executable: str = Field(..., description="Absolute path to the .exe (or .bat/.cmd) to run")
