    cwd: Optional[str] = Field(default=None, description="Working directory (defaults to exe's parent)")
    detach: bool = Field(default=False, description="True: launch GUI in background and return immediately (recommended for GUI apps)")
    env_vars: Optional[dict[str, str]] = Field(default=None, description="Extra environment variables to merge into the child's env (e.g. {'QT_LOGGING_RULES': '*.debug=true'} for signal/slot tracing, 'QT_DEBUG_PLUGINS': '1' for plugin loading diagnostics).")


