@mcp.tool(name="qt_env", annotations={"title": "Show Qt environment", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_env() -> str:
    """Show Qt/MinGW installation paths and versions detected on this machine.

        Args:
            (no parameters)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    err = _check_paths()
    if err:
        return (f"Error: {err}") + _json_footer({"ok": False, "tool": "qt_env"})

    qmake = await _run([str(QMAKE), "-v"], cwd=QT_BIN_DIR, timeout=10)
    qmake_v = (qmake.stdout + qmake.stderr).strip().splitlines()[:3]

    gpp = await _run([str(MINGW_BIN_DIR / "g++.exe"), "--version"], cwd=MINGW_BIN_DIR, timeout=10)
    gpp_v = (gpp.stdout + gpp.stderr).strip().splitlines()[0]

    _v1946 = "\n".join([
        f"Qt version: {QT_VERSION}",
        f"qmake:      {QMAKE}",
        *([f"             {l}" for l in qmake_v] if qmake.ok else [f"             ERROR: {qmake.stderr}"]),
        f"MinGW bin:  {MINGW_BIN_DIR}",
        f"             {gpp_v}",
        f"windeployqt:{WINDEPLOYQT}",
    ])
    return _v1946 + _json_footer({"ok": True, "tool": "qt_env"})


@mcp.tool(name="qt_scaffold", annotations={"title": "Scaffold Qt Widgets project", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_scaffold(params: QtScaffoldInput) -> str:
    """Create a runnable Qt Widgets project skeleton (.pro, main.cpp, main window .h/.cpp/.ui).

        Args:
            name: Project name (lowercase, becomes .exe name)
            template: UI scaffold type
            output_dir: Absolute path of directory to create files in (will be created if missing)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    out = Path(params.output_dir).resolve()
    err = _require_sandbox(out, "scaffold output_dir")
    if err:
        return (err)
    out.mkdir(parents=True, exist_ok=True)

    existing = [p.name for p in out.iterdir() if p.is_file()]
    if existing:
        return (f"Error: directory not empty ({len(existing)} files). Refusing to overwrite: {out}") + _json_footer({"ok": False, "tool": "qt_scaffold"})

    try:
        _write_scaffold(out, params.name, params.template)
    except OSError as e:
        return (f"Error: failed to write files: {e}") + _json_footer({"ok": False, "tool": "qt_scaffold"})

    files = sorted(p.name for p in out.iterdir())
    _v1989 = "\n".join([
        f"Scaffolded Qt Widgets project in {out}",
        f"Template: {params.template.value}",
        "",
        "Files:",
        *[f"  - {f}" for f in files],
        "",
        f"Next: call qt_build on {out} to compile, then qt_run to launch the .exe.",
    ])
    return _v1989 + _json_footer({"ok": True, "tool": "qt_scaffold"})


@mcp.tool(name="qt_build", annotations={"title": "Build Qt project (qmake + mingw)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_build(params: QtBuildInput) -> str:
    """Run qmake and then mingw32-make -j<N> in the project directory.

        Args:
            project_dir: Absolute path to directory containing the .pro file
            build_type: 'debug' or 'release'
            jobs: Parallel make jobs
            clean_first: Run 'mingw32-make distclean' before building
            timeout: Build timeout in seconds

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    err = _check_paths()
    if err:
        return (f"Error: {err}") + _json_footer({"ok": False, "tool": "qt_build"})

    proj = Path(params.project_dir).resolve()
    err = _require_sandbox(proj, "build project_dir")
    if err:
        return (err)
    pro_files = list(proj.glob("*.pro"))
    if not pro_files:
        return (f"Error: no .pro file found in {proj}") + _json_footer({"ok": False, "tool": "qt_build"})
    pro_file = pro_files[0]

    if params.clean_first:
        cl = await _run([str(MINGW32_MAKE), "distclean"], cwd=proj, timeout=60)
        if not cl.ok:
            return (f"Error during distclean:\n{_tail(cl.stderr or cl.stdout)}") + _json_footer({"ok": False, "tool": "qt_build"})

    qmake_args = [str(QMAKE), pro_file.name, "CONFIG+=" + params.build_type]
    qmake = await _run(qmake_args, cwd=proj, timeout=60)
    if not qmake.ok:
        _save_build_log(proj, qmake, None)
        body = _tail(qmake.stderr or qmake.stdout)
        diags = _parse_diagnostics(qmake.stderr or qmake.stdout, project_dir=proj)
        return (f"qmake failed (returncode {qmake.returncode}):\n{body}\n\n{_categorize_build_error(body)}{_format_diagnostics_block(diags)}") + _json_footer({"ok": True, "tool": "qt_build"})

    make_args = [str(MINGW32_MAKE), f"-j{params.jobs}"]
    make = await _run(make_args, cwd=proj, timeout=float(params.timeout))
    _save_build_log(proj, qmake, make)
    if not make.ok:
        body = _tail(make.stderr or make.stdout)
        msg = "Build timed out" if make.timed_out else f"Build failed (returncode {make.returncode})"
        diags = _parse_diagnostics(make.stderr or make.stdout, project_dir=proj)
        return (f"{msg}:\n{body}\n\n{_categorize_build_error(body)}{_format_diagnostics_block(diags)}") + _json_footer({"ok": True, "tool": "qt_build"})

    exes = sorted(str(p) for p in proj.rglob("*.exe") if p.is_file())
    _v2055 = "\n".join([
        f"Build OK in {proj}",
        f"qmake: {qmake.returncode}, make: {make.returncode}",
        "",
        "Make output (tail):",
        _tail(make.stdout) or "(no output)",
        "",
        f"Built executables: {', '.join(exes) if exes else '(none found)'}",
    ])
    return _v2055 + _json_footer({"ok": True, "tool": "qt_build"})


@mcp.tool(name="qt_build_diagnostics", annotations={"title": "Parse a build log into structured JSON diagnostics", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_build_diagnostics(params: QtBuildDiagnosticsInput) -> str:
    """Re-parse a saved build log into structured JSON (no recompile).

    Reads the sidecar log written by the most recent qt_build call
    (<project_dir>/.qt_mcp_last_build.log), or an explicit `build_log` path.
    Each entry: {severity, file, line, column, tool, code, message, suggestion}.
    Use this when you want only the diagnostics without re-running qmake/make.

        Args:
            project_dir: Absolute path to directory containing the .pro file (default log lives at <project_dir>/.qt_mcp_last_build.log)
            build_log: Override path to a build log file. If omitted, reads the sidecar log from the most recent qt_build call.

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    proj = Path(params.project_dir).resolve()
    err = _require_sandbox(proj, "build_diagnostics project_dir")
    if err:
        return (err)

    if params.build_log:
        log = Path(params.build_log).resolve()
        err = _require_sandbox(log, "build_diagnostics build_log")
        if err:
            return (err)
        if not log.is_file():
            return (f"Error: build log not found: {log}") + _json_footer({"ok": False, "tool": "qt_build_diagnostics"})
        log_path = log
    else:
        log_path = _diagnostics_log_path(proj)
        if not log_path.is_file():
            _v2103 = (
                f"Error: no saved build log at {log_path}. "
                "Run qt_build first to populate it (it writes the log on success and failure)."
            )
            return _v2103 + _json_footer({"ok": False, "tool": "qt_build_diagnostics"})

    text = log_path.read_text(encoding="utf-8", errors="replace")
    diags = _parse_diagnostics(text, project_dir=proj)
    body = json.dumps(diags, indent=2, ensure_ascii=False)
    _v2111 = "\n".join([
        f"Parsed {len(diags)} diagnostic(s) from {log_path}",
        f"Project: {proj}",
        "",
        "--- diagnostics (JSON) ---",
        body,
    ])
    return _v2111 + _json_footer({"ok": True, "tool": "qt_build_diagnostics"})


def _qt_creator_running_pids() -> list[int]:
    """Return PIDs of any running Qt Creator instance (Windows, via tasklist)."""
    if sys.platform != "win32":
        return ([])
    out = subprocess.run(
        ["tasklist", "/FI", "IMAGENAME eq qtcreator.exe", "/NH"],
        capture_output=True, text=True, timeout=10,
    )
    pids: list[int] = []
    for line in out.stdout.splitlines():
        line = line.strip()
        # Lines look like:  "qtcreator.exe        4616 Console                    1     158,856 K"
        if not line.lower().startswith("qtcreator.exe"):
            continue
        parts = line.split()
        if len(parts) >= 2 and parts[1].isdigit():
            pids.append(int(parts[1]))
    return (pids)


@mcp.tool(name="qt_creator_open", annotations={"title": "Open a project in Qt Creator", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_creator_open(params: QtCreatorOpenInput) -> str:
    """Launch Qt Creator and open a .pro file directly (no New Project wizard).

    Speeds up the "operate Qt in the GUI" path:
      - Skips the welcome page (-noload Welcome) by default.
      - Skips the New Project wizard entirely — the .pro is passed as a CLI arg.
      - If a Qt Creator is already running, reuses it via -client (file opens in a new tab).
      - Polls for the main window to appear (no fixed sleep) and returns as soon as it's ready.

    After this returns, use qt_creator_run to build+run, or qt_ui_action to drive the IDE
    (remember that Qt Creator's own widgets don't expose standard UIA controls — stick to
    keyboard shortcuts and the Locator (Ctrl+K) for navigation).

        Args:
            pro_file: Absolute path to a .pro file. Qt Creator will open the project directly, skipping the New Project wizard.
            skip_welcome: Pass -noload Welcome to skip the Welcome page on startup. Defaults to True (faster).
            reuse_existing: If True, and a Qt Creator instance is already running, send the file via -client instead of launching a new instance.
            ready_timeout: Seconds to wait for the Qt Creator main window to appear. After it appears, the function returns.

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    if not QTCREATOR_EXE.is_file():
        return (f"Error: Qt Creator not found at {QTCREATOR_EXE}") + _json_footer({"ok": False, "tool": "qt_creator_open"})

    pro = Path(params.pro_file).resolve()
    err = _require_sandbox(pro, "creator_open pro_file")
    if err:
        return (err)
    if pro.suffix.lower() != ".pro":
        return (f"Error: not a .pro file: {pro}") + _json_footer({"ok": False, "tool": "qt_creator_open"})
    if not pro.is_file():
        return (f"Error: .pro file not found: {pro}") + _json_footer({"ok": False, "tool": "qt_creator_open"})

    import os as _os
    import subprocess as _sp
    env = _os.environ.copy()
    env["PATH"] = f"{QT_BIN_DIR};{MINGW_BIN_DIR};" + env.get("PATH", "")
    env["QTDIR"] = str(QT_ROOT)

    args: list[str] = []
    if params.skip_welcome:
        args += ["-noload", "Welcome"]
    if params.reuse_existing and _qt_creator_running_pids():
        args += ["-client"]
    args.append(str(pro))

    # Spawn detached; pywinauto will pick it up via qt_ui_action.
    # NOTE: when args is a list, Popen uses args[0] as the executable. We must
    # prepend the exe path or Windows tries to run "-noload" as the program.
    proc = _sp.Popen(
        [str(QTCREATOR_EXE)] + args, env=env, cwd=str(pro.parent),
        stdin=_sp.DEVNULL, stdout=_sp.DEVNULL, stderr=_sp.DEVNULL,
    )

    # Poll for the main window by waiting for qtcreator.exe to settle.
    deadline = asyncio.get_event_loop().time() + params.ready_timeout
    # Detect when our process either has a window (found via wmic) or has exited
    # (in which case the -client attached to an existing instance).
    creator_pid_found: int | None = None
    while asyncio.get_event_loop().time() < deadline:
        try:
            out = subprocess.run(
                ["powershell", "-NoProfile", "-Command",
                 "Get-Process qtcreator -ErrorAction SilentlyContinue | "
                 "Where-Object { $_.MainWindowTitle -match 'Qt Creator' } | "
                 "Select-Object -First 1 -ExpandProperty Id"],
                capture_output=True, text=True, timeout=5,
            )
            pid_text = (out.stdout or "").strip()
            if pid_text and pid_text.isdigit():
                creator_pid_found = int(pid_text)
                break
        except Exception:
            pass
        await asyncio.sleep(0.5)

    if creator_pid_found is None:
        pids = _qt_creator_running_pids()
        _v2225 = (
            f"Warning: Qt Creator did not become ready within {params.ready_timeout}s.\n"
            f"  qtcreator.exe PIDs visible: {pids}\n"
            f"  Args used: {' '.join(args)}\n"
            f"  Try qt_ui_action (window_title='Qt Creator') to attach manually."
        )
        return _v2225 + _json_footer({"ok": True, "tool": "qt_creator_open"})

    # Handle the "Configure Project" dialog that Qt Creator shows the first time
    # it opens a .pro. The dialog content is rendered INSIDE the main window (not
    # a separate top-level window), so we look for a QPushButton labeled
    # "Configure Project" among the main window's descendants. Polling is needed
    # because the dialog takes a moment to appear after the main window does.
    configured = False
    try:
        from pywinauto import Application as _App
        _app = _App(backend="uia").connect(process=creator_pid_found)
        main_win = next(
            (w for w in _app.windows() if w.class_name() == "Core::Internal::MainWindow"),
            None,
        )
        for _ in range(20):  # up to 10s
            if main_win is None:
                break
            for c in main_win.descendants():
                cn = c.class_name() or ""
                txt = c.window_text() or ""
                if cn == "QPushButton" and txt.strip() == "Configure Project":
                    try:
                        c.set_focus()
                        await asyncio.sleep(0.15)
                        c.click()
                        configured = True
                    except Exception:
                        pass
                    break
            if configured:
                break
            if (pro.parent / f"{pro.stem}.pro.user").is_file():
                break  # already configured
            await asyncio.sleep(0.5)
    except Exception:
        pass

    # Give Qt Creator a moment to write .pro.user
    await asyncio.sleep(1.0)

    _v2271 = (
        f"Qt Creator ready (PID {creator_pid_found})\n"
        f"Project: {pro}\n"
        f"Args: {' '.join(args)}\n"
        f"Configured project: {configured}\n"
        f"Use qt_creator_run to build+run, or qt_ui_action (window_title='Qt Creator') to drive the IDE."
    )
    return _v2271 + _json_footer({"ok": True, "tool": "qt_creator_open"})

    # Timed out — at least report what we know.
    pids = _qt_creator_running_pids()
    _v2281 = (
        f"Warning: Qt Creator did not become ready within {params.ready_timeout}s.\n"
        f"  qtcreator.exe PIDs visible: {pids}\n"
        f"  Args used: {' '.join(args)}\n"
        f"  Try qt_ui_action (window_title='Qt Creator') to attach manually."
    )
    return _v2281 + _json_footer({"ok": True, "tool": "qt_creator_open"})


@mcp.tool(name="qt_creator_run", annotations={"title": "Build + Run a project inside Qt Creator", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_creator_run(params: QtCreatorRunInput) -> str:
    """Trigger the IDE to build (Ctrl+B) the loaded project, then launch the .exe directly.

    Hybrid approach: builds inside Qt Creator (so the user sees the IDE in action and the
    build log streams into the 编译输出 panel) but launches the .exe outside the IDE via
    Popen with QT bin on PATH. This avoids the "kit not fully configured" run failure
    that happens when Qt Creator is used to both build and run a freshly-configured project.

    Requires Qt Creator to already be running with the project loaded (use qt_creator_open first).
    Returns the launched .exe name and PID when run completes.

        Args:
            project_dir: Absolute path to the project directory (used to locate the .pro.user and find the running app later).
            wait_for_build: Seconds to wait for the build to finish (the '构建' progress indicator disappears).
            wait_for_run: Seconds to wait for the .exe to launch (after Ctrl+R is sent).
            run_after_build: If True, send Ctrl+R after the build completes. If False, just build (no run).
            screenshot: If set, take a screenshot of the Qt Creator window to this PNG path after run completes (or after build if run_after_build=False).

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    if not _qt_creator_running_pids():
        return ("Error: Qt Creator is not running. Use qt_creator_open first.") + _json_footer({"ok": False, "tool": "qt_creator_run"})

    proj = Path(params.project_dir).resolve()
    err = _require_sandbox(proj, "creator_run project_dir")
    if err:
        return (err)
    pro_files = list(proj.glob("*.pro"))
    if not pro_files:
        return (f"Error: no .pro file in {proj}") + _json_footer({"ok": False, "tool": "qt_creator_run"})
    pro = pro_files[0]

    # Snapshot the project's debug build directory BEFORE the build, so we can detect changes
    # (the build dir lives next to the project, named build-<pro>-<kit>-<build_type>).
    pre_exes: set[str] = set()
    for p in proj.parent.glob(f"build-{pro.stem}-*/debug/*.exe"):
        pre_exes.add(str(p.resolve()))

    # Connect to the first Qt Creator and send Ctrl+B.
    from pywinauto import Application  # local import; server already requires this elsewhere

    creator_pid = _qt_creator_running_pids()[0]
    try:
        app = Application(backend="uia").connect(process=creator_pid)
    except Exception as e:
        return (f"Error: cannot attach to Qt Creator (PID {creator_pid}): {e}") + _json_footer({"ok": False, "tool": "qt_creator_run"})

    # Find the main window by class name (title changes once a project is loaded).
    win = None
    for w in app.windows():
        if w.class_name() == "Core::Internal::MainWindow":
            win = w
            break
    if win is None:
        return (f"Error: cannot find Qt Creator's MainWindow (PID {creator_pid})") + _json_footer({"ok": False, "tool": "qt_creator_run"})

    win.set_focus()
    await asyncio.sleep(0.3)
    win.type_keys("^b", with_spaces=False)  # Ctrl+B = Build

    # Poll for build to finish: wait until no qmake/make/g++/ld/uic/moc/rcc
    # are running for >=1.5s. (The build pipeline is qmake -> uic -> moc -> g++ -> ld
    # so we need to watch the whole chain, not just the first two.)
    loop = asyncio.get_event_loop()
    deadline = loop.time() + params.wait_for_build
    stable_since: float | None = None
    last_status = "building"
    while loop.time() < deadline:
        out = subprocess.run(
            ["powershell", "-NoProfile", "-Command",
             "Get-Process mingw32-make,qmake,g++,gcc,ld,uic,moc,rcc -ErrorAction SilentlyContinue | "
             "Select-Object -ExpandProperty ProcessName"],
            capture_output=True, text=True, timeout=5,
        )
        running = [ln.strip() for ln in (out.stdout or "").splitlines() if ln.strip()]
        if not running:
            if stable_since is None:
                stable_since = loop.time()
            elif loop.time() - stable_since >= 1.5:
                last_status = "build done (no build tools running)"
                break
        else:
            stable_since = None
            last_status = f"build running ({', '.join(running)})"
        await asyncio.sleep(0.4)

    # Find the built .exe
    post_exes = sorted(Path(p) for p in proj.parent.glob(f"build-{pro.stem}-*/debug/*.exe"))
    new_exes = [e for e in post_exes if str(e) not in pre_exes] or post_exes
    if not new_exes:
        msg = f"Build: {last_status}\nNo .exe was produced (check the 编译输出 panel)."
        if params.screenshot:
            try:
                img = win.capture_as_image()
                Path(params.screenshot).parent.mkdir(parents=True, exist_ok=True)
                img.save(params.screenshot)
                msg += f"\nScreenshot: {params.screenshot}"
            except Exception as e:
                msg += f"\n(Screenshot failed: {e})"
        return (msg)
    exe_path = new_exes[0]
    exe_name = exe_path.name

    if not params.run_after_build:
        msg = f"Build: {last_status}\nBuilt executables: {post_exes}"
        if params.screenshot:
            try:
                img = win.capture_as_image()
                Path(params.screenshot).parent.mkdir(parents=True, exist_ok=True)
                img.save(params.screenshot)
                msg += f"\nScreenshot: {params.screenshot}"
            except Exception as e:
                msg += f"\n(Screenshot failed: {e})"
        return (msg)

    # Launch the .exe directly (avoids the "Build & Run" kit config issue in freshly
    # opened projects). We reuse qt_run's PATH-injection logic to ensure the .exe
    # finds Qt5Core.dll etc.
    import os as _os
    launch_env = _os.environ.copy()
    # Pick the right Qt bin dir for the .exe's architecture. The build dir name
    # embeds "MinGW_32_bit" or "MinGW_64_bit"; 32-bit exes need mingw73_32/bin
    # (different libgcc DLL — _dw2 vs _seh), 64-bit exes use mingw73_64/bin.
    build_dir = exe_path.parent.parent  # build-.../debug -> build-...
    if "32_bit" in build_dir.name:
        qt_bin, qt_root_for_env = QT_32_BIN_DIR, QT_32_ROOT
    else:
        qt_bin, qt_root_for_env = QT_BIN_DIR, QT_ROOT
    launch_env["PATH"] = f"{qt_bin};{MINGW_BIN_DIR};" + launch_env.get("PATH", "")
    launch_env["QTDIR"] = str(qt_root_for_env)

    proc = subprocess.Popen(
        [str(exe_path)], env=launch_env,
        stdin=subprocess.DEVNULL, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
    )
    # Wait for the process to either settle (alive) or die (crash)
    run_deadline = loop.time() + params.wait_for_run
    child_pid: int | None = None
    while loop.time() < run_deadline:
        if proc.poll() is not None:
            # Exited already
            child_pid = None
            break
        if _is_pid_alive(proc.pid):
            child_pid = proc.pid
            break
        await asyncio.sleep(0.5)

    if child_pid is None:
        rc = proc.returncode
        # Try to figure out the failure reason
        if rc is not None and rc != 0:
            diag = _guess_missing_dll(exe_path) or f"exited with code {rc}"
        else:
            diag = "process did not stay alive — check that the .exe finds its Qt DLLs"
        _v2451 = (
            f"Build: {last_status}\n"
            f"App did NOT launch: {exe_name} — {diag}\n"
            f"Try setting PATH to include {QT_BIN_DIR} manually, or use qt_run for setup."
        )
        return _v2451 + _json_footer({"ok": True, "tool": "qt_creator_run"})

    msg = (
        f"Build: {last_status}\n"
        f"App launched: {exe_name} (PID {child_pid})\n"
        f"Path: {exe_path}\n"
        f"Project: {proj}\n"
        f"Note: launched by qt-mcp (not the IDE) to avoid 'Build & Run' kit config issues."
    )
    if params.screenshot:
        try:
            img = win.capture_as_image()
            Path(params.screenshot).parent.mkdir(parents=True, exist_ok=True)
            img.save(params.screenshot)
            msg += f"\nScreenshot: {params.screenshot}"
        except Exception as e:
            msg += f"\n(Screenshot failed: {e})"
    return (msg)


@mcp.tool(name="qt_run", annotations={"title": "Run Qt executable", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_run(params: QtRunInput) -> str:
    """Launch a Qt executable with Qt/MinGW on PATH and capture stdout/stderr/return code.

    Two modes:
    - detach=False (default): wait up to `timeout` seconds, then kill if still running. Good for CLI tools and unit tests.
    - detach=True: launch in the background and return immediately. Good for GUI apps you want to click around in.

    For detached GUI runs, use qt_kill_exe to terminate the process when done.

        Args:
            executable: Absolute path to the .exe (or .bat/.cmd) to run
            args: Command-line arguments
            timeout: Run timeout in seconds (ignored when detach=true)
            cwd: Working directory (defaults to exe's parent)
            detach: True: launch GUI in background and return immediately (recommended for GUI apps)
            env_vars: Extra environment variables to merge into the child's env (e.g. {'QT_LOGGING_RULES': '*.debug=true'} for signal/slot tracing, 'QT_DEBUG_PLUGINS': '1' for plugin loading diagnostics).

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    err = _check_paths()
    if err:
        return (f"Error: {err}") + _json_footer({"ok": False, "tool": "qt_run"})

    exe = Path(params.executable).resolve()
    err = _require_sandbox(exe, "run executable")
    if err:
        return (err)
    if not exe.exists():
        return (f"Error: executable not found: {exe}") + _json_footer({"ok": False, "tool": "qt_run"})

    cwd = Path(params.cwd).resolve() if params.cwd else exe.parent
    err = _require_sandbox(cwd, "run cwd")
    if err:
        return (err)
    cmd = [str(exe)] + list(params.args)

    # Build per-run env: base Qt env + caller-supplied env_vars override
    run_env = _qt_env()
    if params.env_vars:
        run_env.update(params.env_vars)

    if params.detach:
        # Run synchronously in a thread so DETACHED_PROCESS flag is applied cleanly.
        def _spawn_detached() -> int:
            import subprocess
            import sys as _sys
            creationflags = 0
            if _sys.platform == "win32":
                creationflags = getattr(subprocess, "DETACHED_PROCESS", 0) | getattr(subprocess, "CREATE_NEW_PROCESS_GROUP", 0)
            proc = subprocess.Popen(
                cmd,
                cwd=str(cwd),
                env=run_env,
                stdin=subprocess.DEVNULL,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                creationflags=creationflags,
                close_fds=True,
            )
            return (proc.pid)

        pid = await asyncio.to_thread(_spawn_detached)
        # After spawning, peek to see if the process is still alive. If it
        # died immediately (DLL missing, static-init crash, ...), report it
        # instead of a silent "Detached launch OK".
        await asyncio.sleep(0.4)
        alive = await asyncio.to_thread(_is_pid_alive, pid)
        if not alive:
            missing = await asyncio.to_thread(_guess_missing_dll, exe)
            extra = f"\nLikely cause: {missing}" if missing else "\nLikely cause: process exited within 0.4s (DLL missing, static-init crash, or invalid subsystem)."
            _v2552 = "\n".join([
                f"Detached launch FAILED — process exited immediately",
                f"Command: {' '.join(cmd)}",
                f"Working dir: {cwd}",
                f"PID (now dead): {pid}",
                "",
                f"Tip: run with detach=False to see any output, or check that Qt5Core.dll + Qt5Widgets.dll are on PATH.",
                extra,
            ])
            return _v2552 + _json_footer({"ok": True, "tool": "qt_run"})
        _v2561 = "\n".join([
            f"Detached launch OK",
            f"Command: {' '.join(cmd)}",
            f"Working dir: {cwd}",
            f"PID: {pid}",
            "",
            f"The GUI is now running. Use qt_kill_exe to terminate it when done.",
        ])
        return _v2561 + _json_footer({"ok": True, "tool": "qt_run"})

    res = await _run(cmd, cwd=cwd, timeout=float(params.timeout), env=run_env)
    parts = [f"Command: {' '.join(cmd)}", f"Working dir: {cwd}", f"Return code: {res.returncode}"]
    if params.env_vars:
        parts.append(f"Extra env: {len(params.env_vars)} variable(s) merged")
    if res.timed_out:
        parts.append(f"(killed after {params.timeout}s timeout)")
    if res.stdout.strip():
        parts.append("--- stdout ---\n" + _tail(res.stdout, 200))
    if res.stderr.strip():
        parts.append("--- stderr ---\n" + _tail(res.stderr, 200))
    if not res.stdout.strip() and not res.stderr.strip() and not res.timed_out:
        parts.append("(no output)")
    return (("\n".join(parts))) + _json_footer({"ok": True, "tool": "qt_run"})


@mcp.tool(name="qt_deploy", annotations={"title": "Bundle Qt dependencies with windeployqt", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_deploy(params: QtDeployInput) -> str:
    """Copy the .exe plus all Qt DLLs/QML/plugins it needs into a self-contained folder.

    Result can be zipped and run on another Windows machine without Qt installed.

        Args:
            executable: Absolute path to the .exe to bundle dependencies for
            output_dir: Where to copy files (defaults to a 'deploy' folder next to the .exe)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    err = _check_paths()
    if err:
        return (f"Error: {err}") + _json_footer({"ok": False, "tool": "qt_deploy"})

    exe = Path(params.executable).resolve()
    err = _require_sandbox(exe, "deploy executable")
    if err:
        return (err)
    if not exe.exists():
        return (f"Error: executable not found: {exe}") + _json_footer({"ok": False, "tool": "qt_deploy"})

    out = Path(params.output_dir).resolve() if params.output_dir else exe.parent / "deploy"
    err = _require_sandbox(out, "deploy output_dir")
    if err:
        return (err)
    out.mkdir(parents=True, exist_ok=True)

    # Copy the exe itself into out (windeployqt copies too, but be explicit).
    target_exe = out / exe.name
    if target_exe.resolve() != exe.resolve():
        shutil.copy2(exe, target_exe)

    res = await _run(
        [str(WINDEPLOYQT), "--release" if "release" in exe.name.lower() else "--debug",
         "--no-translations", "--no-system-d3d-compiler", "--no-opengl-sw",
         str(target_exe.name)],
        cwd=out,
        timeout=120,
    )

    copied = sorted(p.name for p in out.iterdir())
    head = f"windeployqt {'OK' if res.ok else 'FAILED'} (returncode {res.returncode})"
    body = _tail(res.stdout or res.stderr, 60)
    listing = "\n".join(f"  - {n}" for n in copied[:50])
    extra = f"\n  ... and {len(copied) - 50} more" if len(copied) > 50 else ""
    return (f"{head}\nDeploy folder: {out}\n{body}\n\nFiles:\n{listing}{extra}") + _json_footer({"ok": True, "tool": "qt_deploy"})


@mcp.tool(name="qt_clean", annotations={"title": "Clean Qt build artifacts", "readOnlyHint": False, "destructiveHint": True, "idempotentHint": True, "openWorldHint": False})
async def qt_clean(params: QtCleanInput) -> str:
    """Run 'mingw32-make distclean' and remove stray generated files in the project directory.

    Removes: Makefile, Makefile.*, .qmake.stash, *.o, *.obj, ui_*.h, moc_*.cpp, moc_*.obj,
    qrc_*.cpp, *.exe, .qmake.cache, .qm, .rcc, build/.

        Args:
            project_dir: Absolute path to directory containing the .pro file

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    proj = Path(params.project_dir).resolve()
    err = _require_sandbox(proj, "clean project_dir")
    if err:
        return (err)
    if not proj.exists():
        return (f"Error: project dir not found: {proj}") + _json_footer({"ok": False, "tool": "qt_clean"})

    err = _check_paths()
    if err:
        return (f"Error: {err}") + _json_footer({"ok": False, "tool": "qt_clean"})

    count, removed = _clean_artifacts(proj)
    return ((f"Cleaned {proj}\nRemoved {count} items:\n" + "\n".join(f"  - {n}" for n in removed))) + _json_footer({"ok": True, "tool": "qt_clean"})


@mcp.tool(name="qt_kill_exe", annotations={"title": "Kill running Qt process", "readOnlyHint": False, "destructiveHint": True, "idempotentHint": True, "openWorldHint": False})
async def qt_kill_exe(params: QtKillExeInput) -> str:
    """Terminate a previously launched Qt GUI process by image name.

    Uses Windows 'taskkill /IM <name>'. Pairs with qt_run detach=true.

        Args:
            image_name: Process image name (e.g. 'mygame.exe') — taskkill /IM match
            force: If True, use /F to force kill

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    cmd = ["taskkill", "/IM", params.image_name]
    if params.force:
        cmd.append("/F")
    res = await _run(cmd, cwd=Path.cwd(), timeout=15)
    # Inspect return code only — taskkill's text output is locale-dependent
    # (Chinese on zh-CN Windows) and breaks under some MCP clients that
    # mishandle non-ASCII strings. Status string stays ASCII.
    if res.ok or res.returncode == 0:
        return (f"taskkill {params.image_name}: OK (returncode 0)") + _json_footer({"ok": True, "tool": "qt_kill_exe"})
    return (f"taskkill {params.image_name}: FAILED (returncode {res.returncode})") + _json_footer({"ok": True, "tool": "qt_kill_exe"})


@mcp.tool(name="qt_gen_qrc", annotations={"title": "Generate .qrc from image directory", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_gen_qrc(params: QtGenQrcInput) -> str:
    """Scan an image directory and emit a Qt resource (.qrc) file referencing every match.

    File paths inside .qrc are stored relative to the .qrc file's parent directory.
    Add the .qrc to your .pro with RESOURCES += path/to/file.qrc.

        Args:
            images_dir: Directory to scan for image files (searched recursively)
            output_qrc: Absolute path of the .qrc file to create
            prefix: Qt resource prefix (e.g. '/' or '/images')
            extensions: File extensions to include (without dot)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    images_dir = Path(params.images_dir).resolve()
    err = _require_sandbox(images_dir, "gen_qrc images_dir")
    if err:
        return (err)
    if not images_dir.is_dir():
        return (f"Error: images_dir not found or not a directory: {images_dir}") + _json_footer({"ok": False, "tool": "qt_gen_qrc"})

    qrc_path = Path(params.output_qrc).resolve()
    err = _require_sandbox(qrc_path, "gen_qrc output_qrc")
    if err:
        return (err)
    qrc_parent = qrc_path.parent
    qrc_parent.mkdir(parents=True, exist_ok=True)

    exts = {e.lower().lstrip(".") for e in params.extensions}
    files: list[str] = []
    for ext in exts:
        for p in images_dir.rglob(f"*.{ext}"):
            try:
                rel = p.relative_to(qrc_parent).as_posix()
            except ValueError:
                # images_dir is outside qrc_parent — fall back to absolute forward-slash path.
                rel = p.as_posix()
            files.append(rel)

    if not files:
        return (f"No image files matching {sorted(exts)} found under {images_dir}") + _json_footer({"ok": True, "tool": "qt_gen_qrc"})

    files = sorted(set(files))
    file_lines = "\n".join(f"        <file>{f}</file>" for f in files)
    qrc_body = (
        "<RCC>\n"
        f'    <qresource prefix="{params.prefix}">\n'
        f"{file_lines}\n"
        "    </qresource>\n"
        "</RCC>\n"
    )
    qrc_path.write_text(qrc_body, encoding="utf-8")

    pro_hint = (
        f"\nAdd this line to your .pro file:\n"
        f"    RESOURCES += {qrc_path.name}\n"
    )
    return (
        f"Generated {qrc_path} with {len(files)} files under prefix '{params.prefix}'\n"
        + "\n".join(f"  - {f}" for f in files[:20])
        + (f"\n  ... and {len(files) - 20} more" if len(files) > 20 else "")
        + pro_hint
    )


@mcp.tool(name="qt_pro_edit", annotations={"title": "Edit .pro file variables", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_pro_edit(params: QtProEditInput) -> str:
    """List, read, or modify variables in a .pro file.

    Use this to add a Qt module (e.g. network / sql / multimedia), append a
    source/header, add a library, or tweak DEFINES without leaving the
    conversation. Handles the assignment forms: `=`, `+=`, `-=`. Round-trips
    comments and blank lines.

        Args:
            pro_file: Absolute path to the .pro file (e.g. 'E:/.../myapp.pro')
            action: list | get | set | append | remove
            variable: Variable name (e.g. 'QT', 'SOURCES', 'CONFIG', 'DEFINES', 'LIBS', 'INCLUDEPATH', 'RESOURCES', 'FORMS', 'HEADERS', 'TARGET'). Required for get/set/append/remove; ignored for list.
            values: Values for set/append/remove. Each value is a single token as it should appear in the .pro (e.g. 'network', 'mainwindow.cpp', 'libs/foo.lib').

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    pro = Path(params.pro_file).resolve()
    err = _require_sandbox(pro, "pro_edit pro_file")
    if err:
        return (err)
    if not pro.is_file():
        return (f"Error: .pro file not found: {pro}") + _json_footer({"ok": False, "tool": "qt_pro_edit"})

    text = pro.read_text(encoding="utf-8", errors="replace")
    entries = _pro_parse(text)

    if params.action == QtProEditAction.LIST:
        lines = []
        for e in entries:
            if not e["var"] or not e["op"]:
                continue
            toks = _pro_tokenize(e["value"]) if e["value"] else []
            toks_str = ", ".join(toks) if toks else "(empty)"
            lines.append(f"  {e['var']}{e['op']} {toks_str}")
        if not lines:
            return (f"{pro} contains no variable assignments.") + _json_footer({"ok": True, "tool": "qt_pro_edit"})
        return ((f"{pro} variables:\n" + "\n".join(lines))) + _json_footer({"ok": True, "tool": "qt_pro_edit"})

    if not params.variable:
        return ("Error: 'variable' is required for action=get/set/append/remove") + _json_footer({"ok": False, "tool": "qt_pro_edit"})
    var = params.variable
    values = params.values or []

    if params.action == QtProEditAction.GET:
        for e in entries:
            if e["var"] == var:
                toks = _pro_tokenize(e["value"]) if e["value"] else []
                _v2830 = f"{var}{e['op']} {', '.join(toks) if toks else '(empty)'}\n" \
                       f"  raw: {e['raw']}"
                return _v2830 + _json_footer({"ok": True, "tool": "qt_pro_edit"})
        return (f"Error: variable '{var}' not found in {pro}") + _json_footer({"ok": False, "tool": "qt_pro_edit"})

    if not values and params.action != QtProEditAction.SET:
        return (f"Error: 'values' is required for action={params.action.value}") + _json_footer({"ok": False, "tool": "qt_pro_edit"})

    if params.action == QtProEditAction.SET:
        op = " ="
        new_entries = _pro_set_variable(entries, var, op, values)
    elif params.action == QtProEditAction.APPEND:
        existing: list[str] = []
        for e in entries:
            if e["var"] == var:
                existing = _pro_tokenize(e["value"])
                break
        merged = existing + [v for v in values if v not in existing]
        new_entries = _pro_set_variable(entries, var, " +=", merged)
    elif params.action == QtProEditAction.REMOVE:
        existing = []
        existing_op = "+="
        for e in entries:
            if e["var"] == var:
                existing = _pro_tokenize(e["value"])
                existing_op = e["op"]
                break
        remaining = [v for v in existing if v not in values]
        # Preserve the original operator — `+= list -= removed` is qmake syntax,
        # but it's clearer to keep the declaration form and just drop tokens.
        new_entries = _pro_set_variable(entries, var, " " + existing_op, remaining)
    else:
        return (f"Error: unknown action {params.action!r}") + _json_footer({"ok": False, "tool": "qt_pro_edit"})

    new_text = _pro_to_text(new_entries)
    if new_text == text:
        return (f"No change: {var} already at requested value in {pro}") + _json_footer({"ok": True, "tool": "qt_pro_edit"})
    pro.write_text(new_text, encoding="utf-8")
    return (f"Updated {pro}\n  {var}: {', '.join(values) if values else '(empty)'}") + _json_footer({"ok": True, "tool": "qt_pro_edit"})


@mcp.tool(name="qt_moc_check", annotations={"title": "Run moc on a single header", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_moc_check(params: QtMocCheckInput) -> str:
    """Run moc.exe on a single .h file to surface Q_OBJECT / MOC errors fast.

    Faster than a full qt_build: catches 'undefined interface', missing
    Q_OBJECT, signal/slot signature mistakes, and missing #include "..." before
    you wait for qmake + mingw32-make to grind through a full rebuild.

        Args:
            header: Absolute path to a .h file (e.g. 'E:/.../mywindow.h') that may contain Q_OBJECT
            include_paths: Extra -I include paths to pass to moc (e.g. for headers that include other project headers)
            output_dir: Where to write moc_<name>.cpp for inspection (defaults to a temp dir under E:/Download_tools/QT/.tmp)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    if not MOC.exists():
        return (f"Error: moc.exe not found: {MOC}") + _json_footer({"ok": False, "tool": "qt_moc_check"})
    header = Path(params.header).resolve()
    err = _require_sandbox(header, "moc_check header")
    if err:
        return (err)
    if not header.is_file():
        return (f"Error: header not found: {header}") + _json_footer({"ok": False, "tool": "qt_moc_check"})
    if header.suffix.lower() != ".h":
        return (f"Error: not a .h file: {header}") + _json_footer({"ok": False, "tool": "qt_moc_check"})

    out_dir = Path(params.output_dir).resolve() if params.output_dir else SANDBOX_TMP / f"moc_{header.stem}"
    err = _require_sandbox(out_dir, "moc_check output_dir")
    if err:
        return (err)
    out_dir.mkdir(parents=True, exist_ok=True)
    out_file = out_dir / f"moc_{header.stem}.cpp"

    args = [str(MOC), "-o", str(out_file)]
    for inc in (params.include_paths or []):
        args += ["-I", inc]
    args.append(str(header))

    res = await _run(args, cwd=header.parent, timeout=15)
    body = (res.stdout + res.stderr).strip()

    if res.ok and out_file.is_file():
        size = out_file.stat().st_size
        _v2919 = "\n".join([
            f"moc OK: {header.name}",
            f"Output: {out_file} ({size} bytes)",
            "" if not body else f"moc stdout/stderr:\n{body}",
        ])
        return _v2919 + _json_footer({"ok": True, "tool": "qt_moc_check"})

    hint = _diagnose_moc_error(body, header)
    _v2926 = "\n".join([
        f"moc FAILED on {header.name} (returncode {res.returncode})",
        f"--- moc output ---",
        body or "(no output)",
        f"--- hint ---",
        hint,
    ])
    return _v2926 + _json_footer({"ok": True, "tool": "qt_moc_check"})


def _diagnose_moc_error(body: str, header: Path) -> str:
    """Best-effort classification of moc error messages into actionable hints."""
    if not body:
        return "moc produced no output. Check that moc.exe is on PATH and the header compiles standalone."
    b = body.lower()
    hints: list[str] = []
    if "q_object" in b and "missing" in b:
        hints.append("The class deriving from QObject (or QWidget) is missing the Q_OBJECT macro.")
        hints.append("Add `Q_OBJECT` as the first line inside the class body, after `class Foo : public QWidget {`.")
    if "no relevant classes" in b or "does not contain a" in b:
        hints.append(f"moc could not find a Q_OBJECT-decorated class in {header.name}.")
        hints.append("Verify the file actually contains `class ... {{ Q_OBJECT ... }}` (and that Q_OBJECT is not inside a comment).")
    if "undefined interface" in b:
        hints.append("moc found a class with Q_OBJECT but could not resolve a base class or referenced type.")
        hints.append("Add the missing #include for the base class (e.g. #include <QWidget>) at the top of the header.")
    if "parse error" in b or "expected" in b:
        hints.append("moc hit a syntax error. The class body likely has a typo near a signals:/slots:/Q_PROPERTY block.")
    if "include" in b and "cannot find" in b:
        hints.append("A header #included by this file is missing from the include search path.")
        hints.append("Re-run qt_pro_edit to add the directory to INCLUDEPATH, or pass it via include_paths to qt_moc_check.")
    if not hints:
        hints.append("If the message above mentions a line number, open the header and look at that line for a syntax issue.")
    return ("\n".join("  - " + h for h in hints))


@mcp.tool(name="qt_deps", annotations={"title": "List DLL dependencies of a built binary", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_deps(params: QtDepsInput) -> str:
    """Show which DLLs an .exe (or .dll) imports, so you know what to ship.

    Defaults to Qt5*.dll only; pass qt_only=False to see every dependency
    (including Windows system DLLs). Helps answer 'why is windeployqt not
    packaging this plugin?' questions.

        Args:
            executable: Absolute path to the .exe (or .dll) to inspect
            qt_only: If True, only show Qt5*.dll dependencies. If False, show every DLL the binary imports.

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    if not OBJDUMP.exists():
        return (f"Error: objdump.exe not found: {OBJDUMP}") + _json_footer({"ok": False, "tool": "qt_deps"})
    target = Path(params.executable).resolve()
    err = _require_sandbox(target, "deps executable")
    if err:
        return (err)
    if not target.is_file():
        return (f"Error: not found: {target}") + _json_footer({"ok": False, "tool": "qt_deps"})

    res = await _run([str(OBJDUMP), "-p", str(target)], cwd=target.parent, timeout=20)
    if not res.ok:
        return (f"objdump failed (returncode {res.returncode}):\n{_tail(res.stderr or res.stdout)}") + _json_footer({"ok": True, "tool": "qt_deps"})

    dlls: list[str] = []
    for line in (res.stdout or "").splitlines():
        # Format: "        DLL Name: Qt5Core.dll"
        m = re.match(r"\s*DLL Name:\s*(\S+)", line)
        if not m:
            continue
        name = m.group(1)
        if params.qt_only and not re.match(r"Qt5", name, re.I) and "plugins" not in name:
            continue
        dlls.append(name)
    seen = []
    for d in dlls:
        if d not in seen:
            seen.append(d)

    if not seen:
        if params.qt_only:
            return (f"{target.name}: no Qt5*.dll imports detected. (Pass qt_only=False to see all DLLs.)") + _json_footer({"ok": True, "tool": "qt_deps"})
        return (f"{target.name}: no DLL imports detected (statically linked?).") + _json_footer({"ok": True, "tool": "qt_deps"})
    return ((f"{target.name} imports {len(seen)} DLL(s):\n" + "\n".join(f"  - {d}" for d in seen))) + _json_footer({"ok": True, "tool": "qt_deps"})


# --- UI automation (pywinauto over Qt widgets) ------------------------------

import json as _json
import uuid as _uuid

_UI_SESSIONS: dict[str, "object"] = {}  # session_id -> {app, main_window}


def _ui_resolve_session(params: QtUIActionInput) -> "object":
    """Return the session dict for the given params, raising if missing."""
    if params.session_id and params.session_id in _UI_SESSIONS:
        return (_UI_SESSIONS[params.session_id])
    raise RuntimeError(f"unknown or expired session_id: {params.session_id}")


def _window_pid(window) -> Optional[int]:
    """Best-effort extraction of the owning process id from a pywinauto window."""
    try:
        ei = window.element_info
        if ei is not None:
            pid = getattr(ei, "process_id", None)
            if isinstance(pid, int):
                return (pid)
    except Exception:
        pass
    try:
        pid = window.process_id()  # UIA backend
        if isinstance(pid, int):
            return (pid)
    except Exception:
        pass
    return (None)


async def _ui_find_window(app, title_substr: str, timeout: int, expected_pid: Optional[int] = None):
    """Find a top-level window whose title contains title_substr (case-insensitive).

    If `expected_pid` is given, windows belonging to a different process are
    skipped — this prevents Qt Creator (or any other running Qt app with a
    similar title fragment) from being returned when we asked for our own
    process's window.
    """
    target = title_substr.lower()
    loop = asyncio.get_event_loop()
    deadline = loop.time() + timeout
    last_candidates: list[tuple[str, Optional[int]]] = []
    while loop.time() < deadline:
        try:
            for w in app.windows():
                t = (w.window_text() or "").lower()
                if target not in t:
                    continue
                if expected_pid is not None:
                    wpid = _window_pid(w)
                    if wpid is not None and wpid != expected_pid:
                        # Title matches but the window belongs to a different
                        # process — keep looking. Record the wrong one for
                        # diagnostics.
                        if len(last_candidates) < 5:
                            last_candidates.append((t, wpid))
                        continue
                return (w)
        except Exception:
            pass
        await asyncio.sleep(0.2)
    hint = ""
    if last_candidates:
        hint = f"; same-titled windows found but in wrong process: {last_candidates}"
    raise RuntimeError(f"window matching {title_substr!r} not found within {timeout}s{hint}")


async def _ui_find_control(window, ident: str, timeout: int):
    """Find a descendant control by Qt object_name / accessible name / window_text.

    Qt5 widgets expose their objectName() through the UIA AutomationId property
    on Windows, so pywinauto's element_info.automation_id is usually the right
    hook. We also check object_name (win32 backend) and window_text().
    """
    ident_l = ident.lower()
    loop = asyncio.get_event_loop()
    deadline = loop.time() + timeout
    last_seen = []
    while loop.time() < deadline:
        try:
            for c in window.descendants():
                if not c.is_visible():
                    continue
                candidates: list[str] = []
                # object_name is a property on both backends
                try:
                    on = c.object_name
                    if isinstance(on, str):
                        candidates.append(on)
                except Exception:
                    pass
                # window_text() is a method
                try:
                    wt = c.window_text()
                    if isinstance(wt, str):
                        candidates.append(wt)
                except Exception:
                    pass
                # element_info carries automation_id (Qt objectName) and name
                try:
                    ei = c.element_info
                    if ei is not None:
                        for sub in ("automation_id", "name", "description"):
                            v = getattr(ei, sub, None)
                            if isinstance(v, str):
                                candidates.append(v)
                except Exception:
                    pass
                if any(s.lower() == ident_l for s in candidates):
                    return (c)
                if any(ident_l in s.lower() for s in candidates):
                    return (c)
                if candidates and len(last_seen) < 30:
                    last_seen.append(candidates[0])
        except Exception:
            pass
        await asyncio.sleep(0.2)
    hint = f"; saw: {last_seen[:10]}" if last_seen else ""
    raise RuntimeError(f"control matching {ident!r} not found within {timeout}s{hint}")


@mcp.tool(name="qt_ui_action", annotations={"title": "Drive a Qt app via UI automation", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_ui_action(params: QtUIActionInput) -> str:
    """Drive a Qt GUI application through pywinauto (start / type / click / read / wait / screenshot / close).

    Workflow:
      1. action=start, executable=..., window_title=... → returns session_id
      2. action=type / click / read with session_id + control=<objectName>
      3. action=screenshot writes a PNG of the window to output_path
      4. action=close terminates the app

    Qt controls are identified by their objectName (set in the .ui file's
    name="..." attribute or setObjectName() in code). For the Files/Test
    calculator, the relevant objectNames are: lineEdit, lineEdit_2,
    pushButton (=), pbclose (关闭), label_2 (result).

        Args:
            action: One of: start | type | click | read | wait | screenshot | close
            executable: Absolute path to the .exe (required for 'start'; for other actions, use session_id returned by a previous start)
            window_title: Window title substring to locate (e.g. 'MainWindow' or the title bar text)
            session_id: Session returned by a previous qt_ui_action start; omit executable when passing this
            control: Control identifier: objectName (preferred), window_text, or auto_id. Matched against accessible name / Qt objectName.
            text: Text to type into a control (for 'type'), or text to wait for (for 'wait text=...)
            output_path: Absolute path for screenshot PNG output (for 'screenshot')
            timeout: Seconds to wait for the window/control to appear
            settle_ms: Milliseconds to sleep after write/click before reading (lets Qt repaint)
            click_button: Alias for 'control' when action=click; convenience

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    try:
        from pywinauto import Application
        from PIL import ImageGrab
    except ImportError as e:
        return (f"Error: pywinauto/Pillow not installed: {e}. Run: pip install pywinauto pillow") + _json_footer({"ok": False, "tool": "qt_ui_action"})

    action = params.action.lower()
    sandbox_err = _require_sandbox(Path.cwd(), "ui_action cwd")  # baseline guard
    if sandbox_err:
        return (sandbox_err)

    if action == "start":
        if not params.executable:
            return ("Error: 'executable' is required for action=start") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        exe = Path(params.executable).resolve()
        if not _in_sandbox(exe):
            return (f"Error: executable outside sandbox: {exe}") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        if not exe.exists():
            return (f"Error: executable not found: {exe}") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        # Inject Qt + MinGW into PATH so the launched exe finds Qt5Core.dll etc.
        # Without this the process crashes immediately on launch.
        import os as _os
        import subprocess as _sp
        env = _os.environ.copy()
        env["PATH"] = f"{QT_BIN_DIR};{MINGW_BIN_DIR};" + env.get("PATH", "")
        env["QTDIR"] = str(QT_ROOT)
        # start() doesn't accept env; use subprocess.Popen + Application.connect.
        proc = _sp.Popen([str(exe)], env=env,
                         stdin=_sp.DEVNULL, stdout=_sp.DEVNULL, stderr=_sp.DEVNULL)
        # Give Qt a moment to construct its window before pywinauto looks for it.
        await asyncio.sleep(0.5)
        # Try uia first (Qt5 exposes itself via UI Automation), fall back to win32.
        app = None
        backend_used = None
        for backend in ("uia", "win32"):
            try:
                app = Application(backend=backend).connect(process=proc.pid)
                backend_used = backend
                break
            except Exception:
                continue
        if app is None:
            proc.terminate()
            return (f"Error: could not attach to process (pid {proc.pid}) — did it crash?") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        session_id = _uuid.uuid4().hex[:12]
        _UI_SESSIONS[session_id] = {"app": app, "proc": proc, "window": None, "title": params.window_title or ""}
        if params.window_title:
            # Verify the window actually belongs to *our* process — otherwise
            # we'd return Qt Creator's help panel if its title happens to
            # share a substring with what we asked for.
            try:
                win = await _ui_find_window(app, params.window_title, params.timeout, expected_pid=proc.pid)
            except RuntimeError as e:
                proc.terminate()
                return (f"Error: {e}\nHint: the launched process may have crashed before its window was constructed. Run with detach=False to see any error output.") + _json_footer({"ok": False, "tool": "qt_ui_action"})
            _UI_SESSIONS[session_id]["window"] = win
        return (f"UI session started: {session_id}\nPID: {proc.pid}\nBackend: {backend_used}\nWindow: {params.window_title or '(deferred)'}") + _json_footer({"ok": True, "tool": "qt_ui_action"})

    if action == "close":
        sess = _ui_resolve_session(params)
        proc = sess.get("proc")
        if proc is not None:
            try:
                proc.terminate()
                proc.wait(timeout=5)
            except Exception:
                try:
                    proc.kill()
                except Exception:
                    pass
        else:
            try:
                sess["app"].kill()
            except Exception:
                pass
        _UI_SESSIONS.pop(params.session_id, None)
        return (f"UI session {params.session_id} closed") + _json_footer({"ok": True, "tool": "qt_ui_action"})

    # All other actions need an existing session.
    sess = _ui_resolve_session(params)
    win = sess["window"]
    if win is None and sess["title"]:
        win = await _ui_find_window(sess["app"], sess["title"], params.timeout)
        sess["window"] = win

    if action == "wait":
        if params.control:
            ctrl = await _ui_find_control(win, params.control, params.timeout)
            return (f"Found control matching {params.control!r}") + _json_footer({"ok": True, "tool": "qt_ui_action"})
        await asyncio.sleep(params.timeout)
        return (f"Waited {params.timeout}s") + _json_footer({"ok": True, "tool": "qt_ui_action"})

    if action == "type":
        if not params.control:
            return ("Error: 'control' is required for action=type") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        if params.text is None:
            return ("Error: 'text' is required for action=type") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        ctrl = await _ui_find_control(win, params.control, params.timeout)
        ctrl.set_focus()
        ctrl.type_keys(params.text, with_spaces=True)
        await asyncio.sleep(params.settle_ms / 1000)
        return (f"Typed {params.text!r} into {params.control}") + _json_footer({"ok": True, "tool": "qt_ui_action"})

    if action == "click":
        ident = params.control or params.click_button
        if not ident:
            return ("Error: 'control' (or 'click_button') is required for action=click") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        ctrl = await _ui_find_control(win, ident, params.timeout)
        ctrl.set_focus()
        ctrl.click()
        await asyncio.sleep(params.settle_ms / 1000)
        return (f"Clicked {ident}") + _json_footer({"ok": True, "tool": "qt_ui_action"})

    if action == "read":
        if not params.control:
            return ("Error: 'control' is required for action=read") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        ctrl = await _ui_find_control(win, params.control, params.timeout)
        try:
            text = ctrl.window_text()
        except Exception as e:
            text = f"<read error: {e}>"
        return (f"{params.control}.text = {text!r}") + _json_footer({"ok": True, "tool": "qt_ui_action"})

    if action == "screenshot":
        if not params.output_path:
            return ("Error: 'output_path' is required for action=screenshot") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        out = Path(params.output_path).resolve()
        if not _in_sandbox(out):
            return (f"Error: output_path outside sandbox: {out}") + _json_footer({"ok": False, "tool": "qt_ui_action"})
        out.parent.mkdir(parents=True, exist_ok=True)
        # ImageGrab.grab(bbox=...) reads the screen pixels at that rectangle —
        # if another window is in front, you get that window instead. The robust
        # approach is to ask the window to capture itself (PrintWindow via UIA).
        # pywinauto's capture_as_image() does this. Fall back to ImageGrab only
        # if the window refuses to draw itself.
        try:
            img = win.capture_as_image()
        except Exception as e:
            try:
                rect = win.rectangle()
            except Exception as e2:
                return (f"Error: cannot get window rectangle: {e2}") + _json_footer({"ok": False, "tool": "qt_ui_action"})
            img = ImageGrab.grab(bbox=(rect.left, rect.top, rect.right, rect.bottom))
        img.save(str(out))
        try:
            rect = win.rectangle()
            w, h = rect.right - rect.left, rect.bottom - rect.top
        except Exception:
            w, h = img.size
        return (f"Screenshot saved: {out} ({w}x{h})") + _json_footer({"ok": True, "tool": "qt_ui_action"})

    return (f"Error: unknown action {params.action!r}; expected start|type|click|read|wait|screenshot|close") + _json_footer({"ok": False, "tool": "qt_ui_action"})


# --- Documentation search ----------------------------------------------------

QT_DOCS_DB = SANDBOX_ROOT / "Tools" / "qt-mcp" / "docs_data" / "qt_5_14_2_docs.db"


@mcp.tool(name="qt_docs_search", annotations={"title": "Full-text search local Qt 5.14.2 docs", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_docs_search(params: QtDocsSearchInput) -> str:
    """Search the local Qt 5.14.2 HTML documentation (FTS5 index, 6613 pages).

    Faster and more authoritative than WebFetch for 'how do I use X' questions —
    instant, offline, and every snippet links to the real local doc page.

    The FTS5 index lives at Tools/qt-mcp/docs_data/qt_5_14_2_docs.db and indexes
    title + first-paragraph description + body text across every Qt module
    (qtwidgets, qtcore, qtquick, qtmultimedia, ...).

    Query syntax: FTS5 expression (AND/OR/NOT, parentheses, "quoted phrases").
    Examples: 'QPushButton', 'QPushButton AND click', '"signal slot"', 'QList NOT foreach'.

        Args:
            query: FTS5 search expression. Supports AND/OR/NOT and quoted phrases, e.g. 'QPushButton AND click', '"signal slot"', 'QList AND NOT foreach'
            module: Restrict to one module like 'qtwidgets', 'qtcore', 'qtquick'. If omitted, search all modules.
            limit: Maximum number of results to return
            snippet_tokens: Approx number of tokens per snippet (snippet length)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    import sqlite3

    if not QT_DOCS_DB.is_file():
        _v3365 = (
            f"Error: docs index not found at {QT_DOCS_DB}. "
            "Run Tools/qt-mcp/build_docs_index.py to (re)build it."
        )
        return _v3365 + _json_footer({"ok": False, "tool": "qt_docs_search"})

    if params.module and not re.fullmatch(r"[a-z][a-z0-9_]*", params.module):
        _v3371 = (
            f"Error: invalid module {params.module!r}; expected a lowercase "
            "identifier like 'qtwidgets', 'qtcore', 'qtquick'."
        )
        return _v3371 + _json_footer({"ok": False, "tool": "qt_docs_search"})

    try:
        con = sqlite3.connect(str(QT_DOCS_DB))
        try:
            base_sql = (
                "SELECT p.title, p.module, p.url, "
                "snippet(pages_fts, 2, X'01', X'02', '...', ?) AS snippet "
                "FROM pages_fts JOIN pages p ON p.id = pages_fts.rowid "
                "WHERE pages_fts MATCH ?"
            )
            if params.module:
                rows = con.execute(
                    base_sql + " AND p.module = ? ORDER BY rank LIMIT ?",
                    (params.snippet_tokens, params.query, params.module, params.limit),
                ).fetchall()
            else:
                rows = con.execute(
                    base_sql + " ORDER BY rank LIMIT ?",
                    (params.snippet_tokens, params.query, params.limit),
                ).fetchall()
        finally:
            con.close()
    except sqlite3.OperationalError as e:
        _v3398 = (
            f"Error: FTS5 rejected query {params.query!r}: {e}\n"
            "FTS5 syntax reminders: bare terms are OR; use 'term1 AND term2' for both, "
            "'term1 NOT term2' to exclude, and double-quote phrases: \"signal slot\"."
        )
        return _v3398 + _json_footer({"ok": False, "tool": "qt_docs_search"})

    if not rows:
        scope = f" in module {params.module}" if params.module else ""
        _v3406 = (
            f"No results for {params.query!r}{scope}. Try simpler keywords, "
            "drop the module filter, or check FTS5 syntax (AND/OR/NOT/\"phrases\")."
        )
        return _v3406 + _json_footer({"ok": True, "tool": "qt_docs_search"})

    header = f"Found {len(rows)} result(s) for {params.query!r}"
    if params.module:
        header += f" (module: {params.module})"
    lines = [header, ""]
    for i, (title, module, url, snippet) in enumerate(rows, 1):
        clean = snippet.replace("\x01", "**").replace("\x02", "**").strip()
        lines.append(f"{i}. [{module}] {title}")
        lines.append(f"   {url}")
        if clean:
            lines.append(f"   {clean}")
        lines.append("")
    return (("\n".join(lines).rstrip())) + _json_footer({"ok": True, "tool": "qt_docs_search"})


# --- C++ symbol grep ---------------------------------------------------------

@mcp.tool(name="qt_grep", annotations={"title": "Regex search over Qt project source", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_grep(params: QtGrepInput) -> str:
    """Regex search across Qt project sources (.h / .cpp / .ui / .qrc by default).

    C++-aware grep equivalent — much faster than a full filesystem walk for finding
    "where is X used?" questions. Pass a bare symbol like 'QPushButton' to get
    every file/line where it appears. Search is by default case-insensitive.

    Skips build dirs (debug/, release/, build-*, .qmake.stash, moc_*.cpp, ui_*.h,
    qrc_*.cpp, .obj, .o) and anything outside the sandbox.

        Args:
            project_dir: Absolute path to a directory to search (typically a Qt project root)
            pattern: Regular expression to search for (Python re syntax). Use a bare symbol name like 'QPushButton' to find usages.
            file_glob: Space-separated glob patterns to include (e.g. '*.h *.cpp')
            case_sensitive: If True, match case-sensitively
            max_results: Cap on total matches returned
            context_lines: Lines of context to include around each match (0 = no context line, just file:line:match)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    import fnmatch

    root = Path(params.project_dir).resolve()
    err = _require_sandbox(root, "grep project_dir")
    if err:
        return (err)
    if not root.is_dir():
        return (f"Error: not a directory: {root}") + _json_footer({"ok": False, "tool": "qt_grep"})

    try:
        rx = re.compile(params.pattern, 0 if params.case_sensitive else re.IGNORECASE)
    except re.error as e:
        return (f"Error: bad regex {params.pattern!r}: {e}") + _json_footer({"ok": False, "tool": "qt_grep"})

    globs = params.file_glob.split()
    if not globs:
        globs = ["*.h", "*.cpp", "*.ui", "*.qrc"]

    SKIP_DIRS = {
        "debug", "release", ".git", ".vscode", ".idea", "node_modules",
        "__pycache__", "dist", "deploy",
    }
    SKIP_FILE_PATTERNS = [
        ".qmake.stash", "moc_*.cpp", "moc_*.obj", "ui_*.h", "qrc_*.cpp",
        "qrc_*.obj", "*.obj", "*.o", "Makefile", "Makefile.*",
        ".qmake.cache", ".qt_mcp_last_build.log",
    ]
    # Build-dir convention used by Qt Creator: build-<name>-Desktop_Qt_...-Debug
    BUILD_DIR_PREFIX = "build-"

    matches: list[tuple[str, int, str]] = []  # (rel_path, lineno, line_text)
    truncated = False
    for path in root.rglob("*"):
        if not path.is_file():
            continue
        # Directory skip via path parts
        parts = set(path.parts)
        if parts & SKIP_DIRS:
            continue
        if any(p.startswith(BUILD_DIR_PREFIX) for p in path.parts):
            continue
        # File pattern skip
        name = path.name
        if any(fnmatch.fnmatch(name, pat) for pat in SKIP_FILE_PATTERNS):
            continue
        # Glob include
        if not any(fnmatch.fnmatch(name, g) for g in globs):
            continue
        try:
            text = path.read_text(encoding="utf-8", errors="replace")
        except (OSError, UnicodeError):
            continue
        for lineno, line in enumerate(text.splitlines(), 1):
            if rx.search(line):
                matches.append((str(path.relative_to(root)), lineno, line.rstrip()))
                if len(matches) >= params.max_results:
                    truncated = True
                    break
        if truncated:
            break

    if not matches:
        scope = " (case-sensitive)" if params.case_sensitive else ""
        _v3517 = (
            f"No matches for {params.pattern!r}{scope} under {root}\n"
            f"(globs: {' '.join(globs)})"
        )
        return _v3517 + _json_footer({"ok": True, "tool": "qt_grep"})

    lines = [
        f"Found {len(matches)} match(es) for {params.pattern!r} under {root}",
        f"(globs: {' '.join(globs)}{', case-sensitive' if params.case_sensitive else ''})",
        "",
    ]
    for rel, lineno, text in matches:
        lines.append(f"{rel}:{lineno}: {text}")
    if truncated:
        lines.append("")
        lines.append(f"(truncated at max_results={params.max_results}; raise the cap to see more)")
    return (("\n".join(lines))) + _json_footer({"ok": True, "tool": "qt_grep"})


# --- Class wizard ------------------------------------------------------------

@mcp.tool(name="qt_class_wizard", annotations={"title": "Generate a .h/.cpp/.ui trio for a new QObject class", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_class_wizard(params: QtClassWizardInput) -> str:
    """Generate a Qt class skeleton: header (.h) + source (.cpp) + optional .ui.

    Faster than hand-typing the boilerplate (Q_OBJECT, includes, constructor,
    setupUi, includes in .pro) when adding a new widget/composite. Files are
    written into output_dir under conventional names: <class_name>.h/.cpp/.ui.

    Note: this only writes the source files. You still need to add them to your
    .pro (HEADERS / SOURCES / FORMS) and run qt_build. Use qt_pro_edit to do that
    without leaving the conversation.

        Args:
            output_dir: Absolute path of an EXISTING directory to write .h/.cpp/.ui into. Use Files/<your project>/src or similar.
            class_name: C++ class name without Q prefix is fine; tool will normalize (e.g. 'MyButton' -> 'MyButton'). Used for file names and the Q_OBJECT class.
            base_class: Base class, e.g. 'QWidget', 'QMainWindow', 'QDialog', 'QObject', 'QGraphicsView'. Affects the .ui root widget and #include in .h.
            has_ui: If True, generate a .ui file with a single root widget of `base_class` named `class_name`, plus forward declaration in .h and setupUi() in .cpp.
            header_extra: Optional extra lines to append inside the .h class body, e.g. '    Q_PROPERTY(int value READ value READ value WRITE setValue NOTIFY valueChanged)'
            source_extra: Optional extra lines to append inside the .cpp constructor body, after setupUi()

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    out = Path(params.output_dir).resolve()
    err = _require_sandbox(out, "class_wizard output_dir")
    if err:
        return (err)
    if not out.is_dir():
        return (f"Error: output_dir is not a directory: {out}") + _json_footer({"ok": False, "tool": "qt_class_wizard"})

    klass = params.class_name.strip()
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", klass):
        return (f"Error: invalid class_name {klass!r}; expected C++ identifier (letters/digits/underscore, not starting with digit)") + _json_footer({"ok": False, "tool": "qt_class_wizard"})

    base = params.base_class.strip() or "QWidget"
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", base):
        return (f"Error: invalid base_class {base!r}; expected C++ identifier") + _json_footer({"ok": False, "tool": "qt_class_wizard"})

    # Common Qt header for the base class (header for setupUi in .cpp + the
    # actual include in .h). Covers the common Widgets/Quick families.
    BASE_HEADER = {
        "QWidget": "QWidget",
        "QMainWindow": "QMainWindow",
        "QDialog": "QDialog",
        "QFrame": "QFrame",
        "QObject": "QObject",
        "QGraphicsView": "QGraphicsView",
        "QGraphicsScene": "QGraphicsScene",
        "QGraphicsItem": "QGraphicsItem",
        "QAbstractItemView": "QAbstractItemView",
        "QTreeView": "QTreeView",
        "QTableView": "QTableView",
        "QListView": "QListView",
        "QQuickWidget": "QQuickWidget",
        "QQuickItem": "QQuickItem",
    }
    base_header = BASE_HEADER.get(base, base)

    # Lowercase file basename matching Qt convention (e.g. "MyButton" -> mybutton.h)
    file_base = klass[:1].lower() + klass[1:] if klass else klass.lower()

    header_path = out / f"{file_base}.h"
    source_path = out / f"{file_base}.cpp"
    ui_path = out / f"{file_base}.ui" if params.has_ui else None

    guard = re.sub(r"[^A-Za-z0-9]", "_", klass.upper()) + "_H"

    # --- .h ----------------------------------------------------------------
    header_text = f"""#ifndef {guard}
#define {guard}

#include <{base_header}>

QT_BEGIN_NAMESPACE
namespace Ui {{ class {klass}; }}
QT_END_NAMESPACE

class {klass} : public {base}
{{
    Q_OBJECT

public:
    explicit {klass}({base} *parent = nullptr);
    ~{klass}() override;

private:
    Ui::{klass} *ui;
{params.header_extra}
}};

#endif // {guard}
"""

    # --- .cpp --------------------------------------------------------------
    if params.has_ui:
        source_text = f"""#include "{file_base}.h"
#include "ui_{file_base}.h"

{klass}::{klass}({base} *parent)
    : {base}(parent)
    , ui(new Ui::{klass})
{{
    ui->setupUi(this);
{params.source_extra}
}}

{klass}::~{klass}()
{{
    delete ui;
}}
"""
    else:
        source_text = f"""#include "{file_base}.h"

{klass}::{klass}({base} *parent)
    : {base}(parent)
{{
{params.source_extra}
}}

{klass}::~{klass}()
{{
}}
"""

    # --- .ui ---------------------------------------------------------------
    ui_text: str | None = None
    if params.has_ui:
        # uic-generated form. Root widget matches base_class; user adds children in Designer.
        ui_text = f"""<?xml version="1.0" encoding="UTF-8"?>
<ui version="4.0">
 <class>{klass}</class>
 <widget class="{base}" name="{klass}">
  <property name="geometry">
   <rect>
    <x>0</x>
    <y>0</y>
    <width>400</width>
    <height>300</height>
   </rect>
  </property>
  <property name="windowTitle">
   <string>{klass}</string>
  </property>
 </widget>
 <resources/>
 <connections/>
</ui>
"""

    # Write atomically: build in memory first, then write; refuse if any file exists.
    existing = [p for p in (header_path, source_path, ui_path) if p and p.exists()]
    if existing:
        names = ", ".join(p.name for p in existing)
        return (f"Error: refuse to overwrite existing file(s): {names}. Delete or rename first.") + _json_footer({"ok": False, "tool": "qt_class_wizard"})

    header_path.write_text(header_text, encoding="utf-8")
    source_path.write_text(source_text, encoding="utf-8")
    if ui_path is not None and ui_text is not None:
        ui_path.write_text(ui_text, encoding="utf-8")

    written = [str(header_path), str(source_path)]
    if ui_path is not None:
        written.append(str(ui_path))

    # Reminder of next step: register files in .pro
    if ui_path is not None:
        pro_reminder = (
            f"\nNext: register these in your .pro file "
            f"(HEADERS += {file_base}.h, SOURCES += {file_base}.cpp, FORMS += {file_base}.ui) "
            "— use qt_pro_edit to do that in one call."
        )
    else:
        pro_reminder = (
            f"\nNext: register these in your .pro file "
            f"(HEADERS += {file_base}.h, SOURCES += {file_base}.cpp) "
            "— use qt_pro_edit to do that in one call."
        )

    _v3721 = "\n".join([
        f"Generated {klass} (base: {base}, ui: {params.has_ui}) in {out}",
        "",
        "Files written:",
        *[f"  - {p}" for p in written],
        pro_reminder,
    ])
    return _v3721 + _json_footer({"ok": True, "tool": "qt_class_wizard"})


# --- Translation (lupdate / lrelease) ---------------------------------------

LUPDATE = QT_BIN_DIR / "lupdate.exe"
LRELEASE = QT_BIN_DIR / "lrelease.exe"
QMLLINT = QT_BIN_DIR / "qmllint.exe"
QMLTESTRUNNER = QT_BIN_DIR / "qmltestrunner.exe"
DESIGNER = QT_BIN_DIR / "designer.exe"


@mcp.tool(name="qt_translate", annotations={"title": "Run lupdate / lrelease on a Qt project", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_translate(params: QtTranslateInput) -> str:
    """Drive Qt's translation toolchain (lupdate + lrelease) on a .pro project.

    Use after adding `TRANSLATIONS += i18n/zh_CN.ts i18n/en_US.ts` to your .pro.
    `lupdate` scans your .cpp/.h/.ui/.qml for `tr()` calls and writes/merges the
    .ts files. `lrelease` compiles the .ts XML files into compact .qm binaries
    that QTranslator loads at runtime.

    action='all' runs both back-to-back (the common case for a release build).

        Args:
            project_dir: Absolute path to a Qt project (must contain a .pro file with TRANSLATIONS variable, e.g. TRANSLATIONS += i18n/zh_CN.ts)
            action: One of: 'lupdate' (scan sources, write/merge .ts files), 'lrelease' (compile .ts -> .qm), 'all' (lupdate then lrelease)
            pro_file: Path to a specific .pro file. Defaults to the only .pro in project_dir.

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    if params.action not in ("lupdate", "lrelease", "all"):
        return (f"Error: action must be 'lupdate', 'lrelease', or 'all', got {params.action!r}") + _json_footer({"ok": False, "tool": "qt_translate"})

    proj = Path(params.project_dir).resolve()
    err = _require_sandbox(proj, "translate project_dir")
    if err:
        return (err)
    if not proj.is_dir():
        return (f"Error: not a directory: {proj}") + _json_footer({"ok": False, "tool": "qt_translate"})

    pro_path: Optional[Path] = None
    if params.pro_file:
        pro_path = Path(params.pro_file).resolve()
        err = _require_sandbox(pro_path, "translate pro_file")
        if err:
            return (err)
        if not pro_path.is_file():
            return (f"Error: .pro file not found: {pro_path}") + _json_footer({"ok": False, "tool": "qt_translate"})
    else:
        pro_files = list(proj.glob("*.pro"))
        if not pro_files:
            return (f"Error: no .pro file found in {proj}") + _json_footer({"ok": False, "tool": "qt_translate"})
        pro_path = pro_files[0]

    # Look up TRANSLATIONS variable so we can report which .ts/.qm files are in play.
    pro_text = pro_path.read_text(encoding="utf-8", errors="replace")
    entries = _pro_parse(pro_text)
    ts_files: list[str] = []
    for e in entries:
        if e["var"] == "TRANSLATIONS" and e["value"]:
            ts_files.extend(t.strip() for t in _pro_tokenize(e["value"]) if t.strip())

    if not ts_files:
        _v3796 = (
            f"Error: no TRANSLATIONS variable in {pro_path}. "
            "Add e.g. 'TRANSLATIONS += i18n/zh_CN.ts i18n/en_US.ts' to your .pro, "
            "create the directories, then run qt_translate again."
        )
        return _v3796 + _json_footer({"ok": False, "tool": "qt_translate"})

    if not LUPDATE.exists():
        return (f"Error: lupdate.exe not found: {LUPDATE}") + _json_footer({"ok": False, "tool": "qt_translate"})
    if not LRELEASE.exists():
        return (f"Error: lrelease.exe not found: {LRELEASE}") + _json_footer({"ok": False, "tool": "qt_translate"})

    out_lines: list[str] = [
        f"Project: {pro_path}",
        f"Translation files: {len(ts_files)}",
        *[f"  - {t}" for t in ts_files],
        "",
    ]

    def _summarise(label: str, cmd: list[str], res: "CmdResult") -> tuple[bool, str]:
        head = f"{label}: {Path(cmd[0]).name} (returncode {res.returncode})"
        if res.timed_out:
            head += " [TIMED OUT]"
        # lupdate / lrelease print "Updating 'foo.ts'..." and similar lines to stdout.
        tail = _tail(res.stdout or res.stderr)
        return (res.ok, head + "\n" + tail)

    cwd = pro_path.parent
    env = _qt_env()

    ran_lupdate = False
    ran_lrelease = False

    if params.action in ("lupdate", "all"):
        ran_lupdate = True
        r = await _run([str(LUPDATE), pro_path.name, "-no-obsolete"], cwd=cwd, timeout=120, env=env)
        ok, summary = _summarise("lupdate", [str(LUPDATE), pro_path.name, "-no-obsolete"], r)
        out_lines.append(summary)
        out_lines.append("")
        if not ok:
            out_lines.append("lupdate failed -- lrelease skipped")
            return (("\n".join(out_lines))) + _json_footer({"ok": True, "tool": "qt_translate"})

    if params.action in ("lrelease", "all"):
        ran_lrelease = True
        r = await _run([str(LRELEASE), pro_path.name], cwd=cwd, timeout=120, env=env)
        ok, summary = _summarise("lrelease", [str(LRELEASE), pro_path.name], r)
        out_lines.append(summary)
        out_lines.append("")
        if not ok:
            return (("\n".join(out_lines))) + _json_footer({"ok": True, "tool": "qt_translate"})

    # Report which .qm files now exist (lrelease output).
    qm_files: list[str] = []
    for ts in ts_files:
        ts_p = (cwd / ts).resolve()
        qm_p = ts_p.with_suffix(".qm")
        if qm_p.is_file():
            qm_files.append(str(qm_p))
    out_lines.append(f"Compiled .qm files: {len(qm_files)}")
    for q in qm_files:
        out_lines.append(f"  - {q}")
    if ran_lrelease and qm_files:
        out_lines.append("")
        out_lines.append("Next: register these in your .pro under RESOURCES += (e.g. RESOURCES += i18n/zh_CN.qm)")
    elif ran_lupdate:
        out_lines.append("")
        out_lines.append("Next: open Linguist (Tools/QtCreator/bin/linguist.exe or standalone) to translate the .ts files, then re-run qt_translate action=lrelease.")

    return (("\n".join(out_lines))) + _json_footer({"ok": True, "tool": "qt_translate"})


# --- QML lint (qmllint) -----------------------------------------------------

@mcp.tool(name="qt_qml_lint", annotations={"title": "Lint QML files with qmllint", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qml_lint(params: QtQmlLintInput) -> str:
    """Run qmllint over a single .qml file or every .qml in a directory.

    qmllint catches unused imports, type errors, missing properties,
    deprecated APIs, and more. Path can be a single .qml file or a directory
    (recurses into subdirs by default; skips build-* / node_modules).

    Exit code 0 = clean. Non-zero = warnings or errors (still returned).

        Args:
            target: Absolute path to a .qml file OR a directory containing .qml files
            recursive: If target is a directory, recurse into subdirs (skips build-* and node_modules)
            enable_important: Pass -I to qmllint so imports resolve (needed for many projects)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    if not QMLLINT.exists():
        return (f"Error: qmllint.exe not found: {QMLLINT}") + _json_footer({"ok": False, "tool": "qt_qml_lint"})

    target = Path(params.target).resolve()
    err = _require_sandbox(target, "qml_lint target")
    if err:
        return (err)
    if not target.exists():
        return (f"Error: target does not exist: {target}") + _json_footer({"ok": False, "tool": "qt_qml_lint"})

    SKIP_DIRS = {"debug", "release", ".git", "node_modules", "dist", "deploy", "__pycache__"}

    if target.is_file():
        files = [target]
    else:
        if not target.is_dir():
            return (f"Error: not a file or directory: {target}") + _json_footer({"ok": False, "tool": "qt_qml_lint"})
        files = []
        for p in target.rglob("*.qml"):
            if not p.is_file():
                continue
            if set(p.parts) & SKIP_DIRS:
                continue
            if any(part.startswith("build-") for part in p.parts):
                continue
            files.append(p)
        files.sort()

    if not files:
        return (f"No .qml files found under {target}") + _json_footer({"ok": True, "tool": "qt_qml_lint"})

    # qmllint emits lines like:  file:line:column: [type] message
    # We aggregate errors/warnings and per-file summaries.
    file_reports: list[tuple[str, int, list[str]]] = []
    total_err = 0
    total_warn = 0
    for f in files:
        args = [str(QMLLINT)]
        if params.enable_important:
            # -I is needed for most projects so imports resolve. The project root
            # is a reasonable default; users with custom qmldirs can add more via .pro.
            args += ["-I", str(f.parent)]
        args.append(str(f))
        r = await _run(args, cwd=f.parent, timeout=20)
        msgs: list[str] = []
        for line in (r.stdout or "").splitlines() + (r.stderr or "").splitlines():
            line = line.strip()
            if not line:
                continue
            # Heuristic: qmllint prefixes with file:line:col:
            if re.match(r"^[^\s].*:\d+:\d+:", line) or "Warning:" in line or "Error:" in line:
                msgs.append(line)
                if "Warning:" in line:
                    total_warn += 1
                elif "Error:" in line:
                    total_err += 1
        file_reports.append((str(f.relative_to(target if target.is_dir() else target.parent)), r.returncode, msgs))

    lines = [
        f"qmllint scanned {len(files)} file(s) under {target}",
        f"Errors: {total_err}, Warnings: {total_warn}",
        "",
    ]
    for rel, rc, msgs in file_reports:
        if not msgs and rc == 0:
            lines.append(f"  [OK]  {rel}")
        else:
            lines.append(f"  [rc={rc}]  {rel}  ({len(msgs)} message(s))")
            for m in msgs[:10]:
                lines.append(f"           {m}")
            if len(msgs) > 10:
                lines.append(f"           ... and {len(msgs) - 10} more")
    return (("\n".join(lines))) + _json_footer({"ok": True, "tool": "qt_qml_lint"})


# --- QML test (qmltestrunner) -----------------------------------------------

@mcp.tool(name="qt_qml_test", annotations={"title": "Run QML tests via qmltestrunner", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qml_test(params: QtQmlTestInput) -> str:
    """Run Qt Quick Test (.qml) test cases via qmltestrunner.

    Convention: place tst_*.qml files in a `tests/` folder at the project root.
    qmltestrunner discovers them, instantiates each as a TestCase, and reports
    pass/fail counts and per-test durations.

    Output is parsed into a summary (PASSED / FAILED counts + failing tests).

        Args:
            project_dir: Absolute path to a Qt project root that contains a tests/ folder with tst_*.qml files
            test_path: Subdirectory under project_dir to run tests in (defaults to the whole project, equivalent to qmltestrunner -input .)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    if not QMLTESTRUNNER.exists():
        return (f"Error: qmltestrunner.exe not found: {QMLTESTRUNNER}") + _json_footer({"ok": False, "tool": "qt_qml_test"})

    proj = Path(params.project_dir).resolve()
    err = _require_sandbox(proj, "qml_test project_dir")
    if err:
        return (err)
    if not proj.is_dir():
        return (f"Error: not a directory: {proj}") + _json_footer({"ok": False, "tool": "qt_qml_test"})

    cwd = proj if params.test_path is None else (proj / params.test_path).resolve()
    err = _require_sandbox(cwd, "qml_test test_path")
    if err:
        return (err)
    if not cwd.is_dir():
        return (f"Error: test_path is not a directory: {cwd}") + _json_footer({"ok": False, "tool": "qt_qml_test"})
    if not list(cwd.glob("tst_*.qml")) and not list(cwd.rglob("tst_*.qml")):
        _v4008 = (
            f"Error: no tst_*.qml test files found under {cwd}. "
            "Name your test files like tst_button.qml (or add a test_path that contains them)."
        )
        return _v4008 + _json_footer({"ok": False, "tool": "qt_qml_test"})

    args = [str(QMLTESTRUNNER), "-input", "."]
    r = await _run(args, cwd=cwd, timeout=300)

    # Parse qmltestrunner output:
    #   "PASS   : TestName::test_x"     -> PASS
    #   "FAIL!  : TestName::test_y"     -> FAIL (followed by file:line)
    #   "Totals: N passed, M failed, K skipped"  -> totals
    text = (r.stdout or "") + "\n" + (r.stderr or "")
    passed, failed, skipped = 0, 0, 0
    fails: list[str] = []
    cur_fail: list[str] = []
    for line in text.splitlines():
        m = re.match(r"^PASS\s*:\s*(\S+::\S+)", line)
        if m:
            passed += 1
            cur_fail = []
            continue
        m = re.match(r"^FAIL!\s*:\s*(\S+::\S+)", line)
        if m:
            failed += 1
            fails.append(m.group(1))
            cur_fail = [m.group(1)]
            continue
        m = re.match(r"^SKIP\s*:\s*(\S+::\S+)", line)
        if m:
            skipped += 1
            continue
        m = re.match(r"^Totals:\s*(\d+)\s*passed,\s*(\d+)\s*failed,\s*(\d+)\s*skipped", line)
        if m:
            passed = int(m.group(1))
            failed = int(m.group(2))
            skipped = int(m.group(3))
    header = f"qmltestrunner in {cwd}: {passed} passed, {failed} failed, {skipped} skipped"
    body = [header]
    if not r.ok or failed:
        body.append("")
        body.append(f"returncode = {r.returncode}")
        if fails:
            body.append("Failing tests:")
            for f in fails:
                body.append(f"  - {f}")
        body.append("")
        body.append("--- output (tail) ---")
        body.append(_tail(text))
    elif passed == 0 and failed == 0:
        body.append("")
        body.append("(qmltestrunner output did not include PASS/FAIL/Totals lines; tail of output below)")
        body.append(_tail(text))
    return (("\n".join(body))) + _json_footer({"ok": True, "tool": "qt_qml_test"})


# --- Qt Designer -----------------------------------------------------------

@mcp.tool(name="qt_designer", annotations={"title": "Launch Qt Designer on a .ui file", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_designer(params: QtDesignerInput) -> str:
    """Launch Qt Designer (designer.exe) and open a .ui file.

    Useful for visually editing forms before re-running qt_build. Designer is a
    GUI app, so by default we detach and return the PID immediately. Use
    qt_kill_exe to terminate when done.

        Args:
            ui_file: Absolute path to a .ui file to open in Qt Designer
            detach: If True (default), launch Designer in the background and return immediately. If False, block for `timeout` seconds.

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    if not DESIGNER.exists():
        return (f"Error: designer.exe not found: {DESIGNER}") + _json_footer({"ok": False, "tool": "qt_designer"})

    ui = Path(params.ui_file).resolve()
    err = _require_sandbox(ui, "designer ui_file")
    if err:
        return (err)
    if not ui.is_file():
        return (f"Error: not a file: {ui}") + _json_footer({"ok": False, "tool": "qt_designer"})

    env = _qt_env()
    if params.detach:
        # Popen in the background. Same env-injection discipline as qt_run.
        creationflags = 0
        if sys.platform == "win32":
            creationflags = getattr(subprocess, "CREATE_NO_WINDOW", 0)
        proc = subprocess.Popen(
            [str(DESIGNER), str(ui)],
            env=env,
            cwd=ui.parent,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            creationflags=creationflags,
        )
        # Brief liveness check (Designer sometimes fails to find Qt DLLs).
        import time
        time.sleep(0.4)
        if proc.poll() is not None:
            return (f"Designer exited immediately (returncode {proc.returncode}). Check Qt DLLs are on PATH (32 vs 64-bit mismatch is the usual culprit).") + _json_footer({"ok": True, "tool": "qt_designer"})
        return (f"Designer launched (PID {proc.pid}, .ui={ui})") + _json_footer({"ok": True, "tool": "qt_designer"})
    else:
        # Blocking: run with a timeout, kill after.
        r = await _run([str(DESIGNER), str(ui)], cwd=ui.parent, timeout=params.timeout if hasattr(params, "timeout") else 30, env=env)
        if not r.ok:
            return (f"Designer exited (returncode {r.returncode}):\n{_tail(r.stderr or r.stdout)}") + _json_footer({"ok": True, "tool": "qt_designer"})
        return ("Designer closed normally.") + _json_footer({"ok": True, "tool": "qt_designer"})


# --- QTestLIB (C++ test executable) ----------------------------------------

@mcp.tool(name="qt_test", annotations={"title": "Run a Qt C++ test executable and parse the output", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_test(params: QtTestInput) -> str:
    """Run a Qt C++ test executable built from a `CONFIG += testcase` project
    and parse the PASS/FAIL/XPASS/XFAIL/SKIP lines.

    QTest outputs lines like:
        PASS   : ClassName::test_x()
        FAIL!  : ClassName::test_y()
        XFAIL  : ClassName::test_z()  (Expected to fail)
        XPASS  : ClassName::test_w()  (Unexpectedly passed)
        SKIP   : ClassName::test_v()  (Skipped)
        Totals: 12 passed, 1 failed, 0 skipped

    If test_exe is not given we look for <project_dir>/debug/<project_name>.exe
    (matches the build convention of qt_build). test_args lets you pass
    `-platform offscreen -v2` for headless / verbose runs.

        Args:
            project_dir: Absolute path to a Qt project root containing a test executable (built by qmake/make with CONFIG += testcase).
            test_exe: Path to the test executable (defaults to <project_dir>/debug/<project_name>.exe).
            test_args: Extra args passed to the test exe (e.g. '-platform offscreen -v2' to enable verbose QTest output)

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    proj = Path(params.project_dir).resolve()
    err = _require_sandbox(proj, "test project_dir")
    if err:
        return (err)
    if not proj.is_dir():
        return (f"Error: not a directory: {proj}") + _json_footer({"ok": False, "tool": "qt_test"})

    if params.test_exe:
        exe = Path(params.test_exe).resolve()
        err = _require_sandbox(exe, "test test_exe")
        if err:
            return (err)
    else:
        # Default convention: <project_name>.exe in debug/
        pro_files = list(proj.glob("*.pro"))
        if not pro_files:
            return (f"Error: no .pro file in {proj} and no test_exe given") + _json_footer({"ok": False, "tool": "qt_test"})
        pro_text = pro_files[0].read_text(encoding="utf-8", errors="replace")
        entries = _pro_parse(pro_text)
        target_name = None
        for e in entries:
            if e["var"] == "TARGET":
                toks = _pro_tokenize(e["value"])
                if toks:
                    target_name = toks[0]
                break
        if not target_name:
            target_name = pro_files[0].stem
        exe = (proj / "debug" / f"{target_name}.exe").resolve()

    if not exe.is_file():
        return (f"Error: test executable not found: {exe}\n(Build it first with qt_build.)") + _json_footer({"ok": False, "tool": "qt_test"})

    # Pick 32- vs 64-bit Qt DLLs based on the .exe architecture.
    is_32 = _pe_bits(exe) == 32
    qt_bin_dir = QT_32_BIN_DIR if is_32 else QT_BIN_DIR
    env = _qt_env()
    env["PATH"] = f"{qt_bin_dir};{MINGW_BIN_DIR};{env.get('PATH', '')}"

    args = [str(exe)]
    if params.test_args.strip():
        args += params.test_args.split()

    r = await _run(args, cwd=exe.parent, timeout=180, env=env)

    text = (r.stdout or "") + "\n" + (r.stderr or "")
    passed = failed = skipped = xfail = xpass = 0
    fails: list[str] = []
    cur_label: Optional[str] = None
    for line in text.splitlines():
        m = re.match(r"^(PASS|FAIL!|XFAIL|XPASS|SKIP)\s*:\s*(\S+::\S+)", line)
        if m:
            tag, name = m.group(1), m.group(2)
            cur_label = name
            if tag == "PASS":
                passed += 1
            elif tag == "FAIL!":
                failed += 1
                fails.append(name)
            elif tag == "XFAIL":
                xfail += 1
            elif tag == "XPASS":
                xpass += 1
                fails.append(name)
            elif tag == "SKIP":
                skipped += 1
        elif tag_is := re.match(r"^Totals:\s*(\d+)\s*passed,\s*(\d+)\s*failed,\s*(\d+)\s*skipped", line):
            passed = int(tag_is.group(1))
            failed = int(tag_is.group(2))
            skipped = int(tag_is.group(3))

    lines = [
        f"qt_test: {exe}",
        f"  Passed: {passed}  Failed: {failed}  Skipped: {skipped}  XFail: {xfail}  XPASS: {xpass}",
    ]
    if fails:
        lines.append("")
        lines.append("Failing tests:")
        for n in fails:
            lines.append(f"  - {n}")
    if not r.ok or failed:
        lines.append("")
        lines.append(f"returncode = {r.returncode}")
        lines.append("--- output (tail) ---")
        lines.append(_tail(text))
    return (("\n".join(lines))) + _json_footer({"ok": True, "tool": "qt_test"})


# --- Code formatter ----------------------------------------------------------

_FORMAT_EXTS = {".h", ".cpp", ".cc", ".cxx", ".hpp", ".hxx"}
_FORMAT_SKIP_DIRS = {"debug", "release", ".git", ".vscode", ".idea", "node_modules", "__pycache__", "dist", "deploy", "build"}


def _format_resolve_exe(params_exe: Optional[str]) -> Optional[Path]:
    """Pick the clang-format executable from param, env, or PATH."""
    if params_exe:
        p = Path(params_exe)
        return (p if p.exists() else None)
    env = os.environ.get("QT_FORMAT_EXE")
    if env and Path(env).exists():
        return (Path(env))
    found = shutil.which("clang-format")
    return (Path(found) if found else None)


@mcp.tool(name="qt_format", annotations={"title": "Run clang-format on Qt C++ files", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_format(params: QtFormatInput) -> str:
    """Run clang-format on a file or directory of C++ sources.

    Resolution order for the executable: clang_format_exe param → QT_FORMAT_EXE env var → clang-format on PATH.

    Style: defaults to 'file' (uses .clang-format from project root if present, else LLVM fallback). Pass 'llvm', 'google', etc. to override.

    Modes:
    - check_only=True: exit non-zero with a diff if any file would be reformatted. Use in CI/pre-commit.
    - backup=True: write a .bak before rewriting (large-tree safety net).

    The e2e suite uses a fake clang-format stub (a copy of the .py script) so this works without the real binary.

        Args:
            target: Absolute path to a file or directory. Directories are recursed; only .h/.cpp/.cc/.cxx files are formatted.
            clang_format_exe: Path to clang-format.exe. If omitted, uses QT_FORMAT_EXE env var, then 'clang-format' on PATH.
            style: clang-format style: 'file' (look for .clang-format), 'llvm', 'google', 'chromium', 'mozilla', 'webkit', or a YAML string. Default: 'file' (use .clang-format from project root if present, else 'LLVM' fallback).
            check_only: If True, don't write changes — exit non-zero with a diff if any file would be reformatted. Ideal for CI/pre-commit.
            backup: If True, write a .bak copy of each file before rewriting. Use with care on large trees.
            extra_args: Extra args passed verbatim to clang-format (e.g. ['--verbose'] or ['--lines=1:10']).

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    target = Path(params.target).resolve()
    err = _require_sandbox(target, "format target")
    if err:
        return (err)
    if not target.exists():
        return (f"Error: target not found: {target}") + _json_footer({"ok": False, "tool": "qt_format"})

    exe = _format_resolve_exe(params.clang_format_exe)
    if exe is None:
        _v4301 = (
            "Error: clang-format not found.\n"
            "Pass `clang_format_exe` (e.g. 'C:/Program Files/LLVM/bin/clang-format.exe') "
            "or set env QT_FORMAT_EXE=<path>, or add clang-format.exe to PATH."
        )
        return _v4301 + _json_footer({"ok": False, "tool": "qt_format"})

    # Collect files
    if target.is_file():
        files = [target]
    else:
        files = []
        for p in target.rglob("*"):
            if not p.is_file():
                continue
            if p.suffix.lower() not in _FORMAT_EXTS:
                continue
            if any(part in _FORMAT_SKIP_DIRS for part in p.parts):
                continue
            files.append(p)

    if not files:
        return (f"No C++ files to format under {target} (extensions: {sorted(_FORMAT_EXTS)})") + _json_footer({"ok": True, "tool": "qt_format"})

    style = params.style or "file"
    cmd_base = [str(exe), f"--style={style}"]
    if not params.check_only:
        cmd_base.append("-i")  # in-place edit
    cmd_base += params.extra_args

    formatted = 0
    unchanged = 0
    would_change: list[str] = []
    failures: list[str] = []

    for f in files:
        cmd = cmd_base + [str(f)]
        try:
            r = await _run(cmd, cwd=f.parent, timeout=30)
        except Exception as e:
            failures.append(f"{f}: launch failed: {e}")
            continue

        if params.check_only:
            if r.returncode != 0 and r.stdout.strip():
                would_change.append(f.name)
            elif r.returncode == 0:
                unchanged += 1
            else:
                failures.append(f"{f}: rc={r.returncode} stderr={r.stderr.strip()[:200]}")
        else:
            if r.returncode == 0:
                # Heuristic: if clang-format emitted a diff to stdout, file was reformatted.
                if r.stdout.strip():
                    formatted += 1
                    if params.backup:
                        try:
                            f.with_suffix(f.suffix + ".bak").write_bytes(f.read_bytes())
                        except OSError as e:
                            failures.append(f"{f}: backup failed: {e}")
                else:
                    unchanged += 1
            else:
                failures.append(f"{f}: rc={r.returncode} stderr={r.stderr.strip()[:200]}")

    parts = [
        f"qt_format: target={target}",
        f"  executable: {exe}",
        f"  style: {style}",
        f"  mode: {'check-only' if params.check_only else 'in-place'}",
        f"  files scanned: {len(files)}",
        "",
    ]
    if params.check_only:
        parts.append(f"  unchanged: {unchanged}")
        parts.append(f"  would-change: {len(would_change)}")
        if would_change:
            parts.append("  files needing reformat:")
            parts += [f"    - {n}" for n in would_change[:20]]
            if len(would_change) > 20:
                parts.append(f"    ... and {len(would_change) - 20} more")
        if would_change and not failures:
            parts.append("")
            parts.append("Result: NEEDS REFORMAT (non-zero exit for CI).")
    else:
        parts.append(f"  reformatted: {formatted}")
        parts.append(f"  unchanged: {unchanged}")
        if params.backup:
            parts.append(f"  backups: <name>.bak written next to each reformatted file")
    if failures:
        parts.append("")
        parts.append(f"Failures ({len(failures)}):")
        parts += [f"  - {x}" for x in failures[:10]]
        if len(failures) > 10:
            parts.append(f"  ... and {len(failures) - 10} more")

    return (("\n".join(parts))) + _json_footer({"ok": True, "tool": "qt_format"})


# --- .qrc resource manager ---------------------------------------------------

_QRC_FILE_RE = re.compile(r"<\s*file\s*>\s*([^<]+?)\s*<\s*/\s*file\s*>", re.IGNORECASE)
_QRC_QRESOURCE_RE = re.compile(
    r"<\s*qresource\s+prefix\s*=\s*\"([^\"]*)\"\s*>(.*?)<\s*/\s*qresource\s*>",
    re.IGNORECASE | re.DOTALL,
)


def _qrc_parse(path: Path) -> tuple[Optional[ElementTree.Element], list[tuple[str, list[str]]], Optional[str]]:
    """Parse a .qrc file. Returns (root, [(prefix, [files...])], error)."""
    try:
        tree = ElementTree.parse(path)
    except (ElementTree.ParseError, OSError) as e:
        return (None, [], f"parse error: {e}")
    root = tree.getroot()
    if root.tag != "RCC":
        return (root, [], f"root element is <{root.tag}>, expected <RCC>")
    blocks: list[tuple[str, list[str]]] = []
    for qr in root.findall("qresource"):
        prefix = qr.get("prefix", "/")
        files: list[str] = []
        for f in qr.findall("file"):
            files.append((f.text or "").strip())
        blocks.append((prefix, files))
    return (root, blocks, None)


def _qrc_serialize(root: ElementTree.Element) -> str:
    """Serialize an ElementTree back to a .qrc string with a clean indent."""
    ElementTree.indent(root, space="    ")
    body = ElementTree.tostring(root, encoding="unicode")
    if not body.endswith("\n"):
        body += "\n"
    return (body)


@mcp.tool(name="qt_resources", annotations={"title": "List / add / remove / validate entries in a .qrc file", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_resources(params: QtResourcesInput) -> str:
    """Operate on a Qt resource (.qrc) file: list its files, add new files, remove existing ones, or validate the entries exist on disk.

    Add/remove use paths relative to the .qrc file's parent directory (e.g. 'images/icon.png').

    Validate walks the directory and reports missing files plus any duplicate <file> entries.

        Args:
            qrc_file: Absolute path to the .qrc file to operate on. The file must already exist (use qt_gen_qrc to create it).
            action: list: dump all files. add: append files. remove: delete files. validate: check that every <file> path exists on disk and the XML parses.
            files: For add/remove: paths relative to the .qrc file's parent directory (e.g. 'images/icon.png').
            prefix: For add: which <qresource prefix="..."> to add to. If omitted, uses the first <qresource> block in the .qrc (or creates one with prefix '/').

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    qrc = Path(params.qrc_file).resolve()
    err = _require_sandbox(qrc, "resources qrc_file")
    if err:
        return (err)
    if not qrc.is_file():
        return (f"Error: qrc_file not found: {qrc}") + _json_footer({"ok": False, "tool": "qt_resources"})

    root, blocks, perr = _qrc_parse(qrc)
    if perr:
        return (f"Error: {qrc} is not a valid .qrc file ({perr})") + _json_footer({"ok": False, "tool": "qt_resources"})
    qrc_parent = qrc.parent

    if params.action == QtResourcesAction.LIST:
        lines = [f"qt_resources LIST: {qrc}", f"  {len(blocks)} <qresource> block(s)", ""]
        for prefix, files in blocks:
            lines.append(f"  prefix='{prefix}' ({len(files)} files):")
            lines += [f"    - {f}" for f in files[:30]]
            if len(files) > 30:
                lines.append(f"    ... and {len(files) - 30} more")
        return (("\n".join(lines))) + _json_footer({"ok": True, "tool": "qt_resources"})

    if params.action == QtResourcesAction.VALIDATE:
        if not blocks:
            return (f"qt_resources VALIDATE: {qrc} — no <qresource> blocks (empty file).") + _json_footer({"ok": True, "tool": "qt_resources"})
        missing: list[str] = []
        seen: set[str] = set()
        dupes: list[str] = []
        for prefix, files in blocks:
            for f in files:
                if not f:
                    continue
                if f in seen:
                    dupes.append(f)
                seen.add(f)
                full = qrc_parent / f
                if not full.exists():
                    missing.append(f)
        lines = [
            f"qt_resources VALIDATE: {qrc}",
            f"  files: {sum(len(fs) for _, fs in blocks)}",
            f"  unique: {len(seen)}",
            f"  duplicates: {len(dupes)}",
            f"  missing on disk: {len(missing)}",
        ]
        if dupes:
            lines.append("  duplicate entries:")
            lines += [f"    - {d}" for d in dupes[:10]]
        if missing:
            lines.append("  missing files (relative to .qrc parent):")
            lines += [f"    - {m}" for m in missing[:10]]
            if len(missing) > 10:
                lines.append(f"    ... and {len(missing) - 10} more")
        if not missing and not dupes:
            lines.append("  OK — all entries resolve.")
        return (("\n".join(lines))) + _json_footer({"ok": True, "tool": "qt_resources"})

    # add / remove — both mutate the file
    if not params.files:
        return (f"Error: action={params.action.value} requires a non-empty 'files' list") + _json_footer({"ok": False, "tool": "qt_resources"})

    # Decide which qresource block to mutate
    target_prefix = params.prefix
    target_idx: Optional[int] = None
    if target_prefix is None:
        if blocks:
            target_idx = 0
            target_prefix = blocks[0][0]
        else:
            target_prefix = "/"
    else:
        for i, (p, _) in enumerate(blocks):
            if p == target_prefix:
                target_idx = i
                break
        if target_idx is None:
            target_idx = len(blocks)  # will be appended below

    # If root is None (parse error) we already returned; this is for safety.
    if root is None:
        return (f"Error: internal — parsed root is None for {qrc}") + _json_footer({"ok": False, "tool": "qt_resources"})

    # Sync blocks to the in-memory tree (it may have other blocks; we only mutate target_idx)
    qr_elements = root.findall("qresource")
    while len(qr_elements) <= target_idx:
        new_qr = ElementTree.SubElement(root, "qresource", {"prefix": target_prefix or "/"})
        qr_elements.append(new_qr)
    target_qr = qr_elements[target_idx]

    # Refresh blocks cache to reflect additions
    if target_idx >= len(blocks):
        blocks.append((target_prefix or "/", []))

    changes = 0
    skipped: list[str] = []

    if params.action == QtResourcesAction.ADD:
        existing = {(f.text or "").strip() for f in target_qr.findall("file") if (f.text or "").strip()}
        for f in params.files:
            if f in existing:
                skipped.append(f"{f} (already present)")
                continue
            full = qrc_parent / f
            if not full.exists():
                skipped.append(f"{f} (file not found on disk: {full})")
                continue
            fe = ElementTree.SubElement(target_qr, "file")
            fe.text = f
            existing.add(f)
            changes += 1

    elif params.action == QtResourcesAction.REMOVE:
        to_remove = set(params.files)
        for fe in list(target_qr.findall("file")):
            txt = (fe.text or "").strip()
            if txt in to_remove:
                target_qr.remove(fe)
                changes += 1
        for f in params.files:
            if f not in to_remove or f in {fe.text for fe in target_qr.findall("file")}:
                # didn't match anything
                pass

    if changes == 0:
        _v4581 = "\n".join([
            f"qt_resources {params.action.value.upper()}: no changes applied to {qrc}",
            *(f"  skipped: {s}" for s in skipped[:10]),
        ])
        return _v4581 + _json_footer({"ok": True, "tool": "qt_resources"})

    # Re-serialize atomically
    new_text = _qrc_serialize(root)
    tmp = qrc.with_suffix(qrc.suffix + ".tmp")
    tmp.write_text(new_text, encoding="utf-8")
    tmp.replace(qrc)

    lines = [
        f"qt_resources {params.action.value.upper()}: {changes} change(s) applied to {qrc}",
        f"  prefix: '{target_prefix}'",
    ]
    if skipped:
        lines.append(f"  skipped: {len(skipped)}")
        lines += [f"    - {s}" for s in skipped[:10]]
    return (("\n".join(lines))) + _json_footer({"ok": True, "tool": "qt_resources"})


# --- Environment diagnostics -------------------------------------------------

@mcp.tool(name="qt_diagnose_env", annotations={"title": "Check the Qt/MinGW toolchain environment", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_diagnose_env(params: QtDiagnoseEnvInput) -> str:
    """Quickly check whether the Qt 5.14.2 / MinGW toolchain is correctly configured on this machine.

    Reports:
    - Which required binaries exist (qmake, mingw32-make, g++, windeployqt, moc, rcc, objdump, Qt Creator)
    - Whether 32-bit and 64-bit Qt installations are both present (and which one Qt Creator is wired to)
    - PATH order: whether Qt's bin dir is ahead of any conflicting system g++/qmake
    - (with deep=True) Sample --version outputs and a tiny compile test against a known-good .pro

    Use this when qt_build fails with "Required Qt tool not found" or before debugging a fresh setup.

        Args:
            deep: If True, also run quick functional tests (e.g. invoke qmake -v, mingw32-make --version) and parse a sample .pro to verify the toolchain end-to-end. Adds ~2s.

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    issues: list[str] = []
    info: list[str] = []
    ok = 0
    total = 0

    # 1. Core binaries
    binaries = [
        ("qmake (64-bit)", QMAKE),
        ("qmake (32-bit)", QT_32_BIN_DIR / "qmake.exe"),
        ("mingw32-make (64-bit)", MINGW32_MAKE),
        ("g++ (64-bit)", MINGW_BIN_DIR / "g++.exe"),
        ("g++ (32-bit)", Path(r"E:\Download_tools\QT\Tools\mingw730_32\bin\g++.exe")),
        ("windeployqt", WINDEPLOYQT),
        ("moc (64-bit)", MOC),
        ("rcc (64-bit)", RCC),
        ("objdump", OBJDUMP),
        ("Qt Creator", QTCREATOR_EXE),
    ]
    info.append("=== Required binaries ===")
    for name, p in binaries:
        total += 1
        if p.exists():
            ok += 1
            info.append(f"  [OK]   {name}: {p}")
        else:
            issues.append(f"missing binary: {name} ({p})")
            info.append(f"  [MISS] {name}: {p}")

    # 2. lupdate / lrelease / qmllint / qmltestrunner / designer / qmlscene (5.14 may lack some)
    extras = [
        ("lupdate", QT_BIN_DIR / "lupdate.exe"),
        ("lrelease", QT_BIN_DIR / "lrelease.exe"),
        ("qmllint", QT_BIN_DIR / "qmllint.exe"),
        ("qmltestrunner", QT_BIN_DIR / "qmltestrunner.exe"),
        ("designer", QT_BIN_DIR / "designer.exe"),
        ("qtpaths", QT_BIN_DIR / "qtpaths.exe"),
    ]
    info.append("")
    info.append("=== Extras (used by other qt-mcp tools) ===")
    for name, p in extras:
        total += 1
        if p.exists():
            ok += 1
            info.append(f"  [OK]   {name}: {p}")
        else:
            info.append(f"  [skip] {name}: not present (some tools will report 'not found')")

    # 3. 32/64-bit DLL conflict warning
    info.append("")
    info.append("=== 32-bit / 64-bit coexistence ===")
    has_64 = (QT_BIN_DIR / "Qt5Core.dll").exists()
    has_32 = (QT_32_BIN_DIR / "Qt5Core.dll").exists()
    info.append(f"  64-bit Qt5Core.dll: {'present' if has_64 else 'MISSING'}")
    info.append(f"  32-bit Qt5Core.dll: {'present' if has_32 else 'MISSING'}")
    if has_64 and has_32:
        info.append("  both kits present — when running an .exe, qt-mcp picks the right one via build dir name ('debug' or build-*-MinGW_32_bit).")

    # 4. Sandbox writability
    info.append("")
    info.append("=== Sandbox ===")
    total += 1
    try:
        test_file = SANDBOX_TMP / f".diagnose_{os.getpid()}"
        test_file.write_text("ok", encoding="utf-8")
        test_file.unlink()
        ok += 1
        info.append(f"  [OK]   writable: {SANDBOX_TMP}")
    except OSError as e:
        issues.append(f"sandbox not writable: {e}")
        info.append(f"  [FAIL] {SANDBOX_TMP}: {e}")

    # 5. PATH order
    info.append("")
    info.append("=== PATH order (looking for g++/qmake conflicts) ===")
    path_dirs = os.environ.get("PATH", "").split(os.pathsep)
    qmake_paths = []
    for d in path_dirs:
        candidate = Path(d) / ("qmake.exe" if sys.platform == "win32" else "qmake")
        if candidate.exists():
            try:
                qmake_paths.append((d, candidate.resolve()))
            except OSError:
                pass
    if qmake_paths:
        for d, p in qmake_paths:
            tag = "QTDIR" if str(QT_BIN_DIR).lower() in d.lower() else "OTHER"
            info.append(f"  qmake on PATH: {p}  ({tag})")
        if not any(str(QT_BIN_DIR).lower() in d.lower() for d, _ in qmake_paths):
            issues.append("Qt's bin dir is NOT on PATH — qt-mcp's _qt_env() prepends it for child processes, but the calling shell won't see qmake.")
    else:
        issues.append("no qmake on PATH at all")

    # 6. Deep mode: actually invoke each tool
    if params.deep:
        info.append("")
        info.append("=== Deep mode: version checks ===")
        for label, tool, args in [
            ("qmake -v", str(QMAKE), ["-v"]),
            ("mingw32-make --version", str(MINGW32_MAKE), ["--version"]),
            ("g++ --version", str(MINGW_BIN_DIR / "g++.exe"), ["--version"]),
        ]:
            try:
                r = await _run([tool] + args, cwd=QMAKE.parent, timeout=10)
                first_line = (r.stdout or r.stderr).strip().splitlines()[0] if (r.stdout or r.stderr).strip() else "(no output)"
                info.append(f"  {label}: {first_line[:120]}")
            except Exception as e:
                issues.append(f"{label} failed: {e}")
                info.append(f"  {label}: FAILED ({e})")

    info.append("")
    info.append("=== Summary ===")
    info.append(f"  {ok}/{total} checks OK")
    if issues:
        info.append(f"  {len(issues)} issue(s):")
        info += [f"    - {i}" for i in issues]
    else:
        info.append("  No issues found — toolchain looks healthy.")

    return (("\n".join(info))) + _json_footer({"ok": True, "tool": "qt_diagnose_env"})


# --- Project file validation -------------------------------------------------

@mcp.tool(name="qt_validate", annotations={"title": "Validate a .pro file's SOURCES / HEADERS / FORMS / RESOURCES references", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_validate(params: QtValidateInput) -> str:
    """Walk a .pro file and verify every file it references is real, readable, and inside the sandbox.

    Output is a checklist grouped by category (sources, headers, forms, resources). Each
    line is `[OK]`, `[MISS]`, `[OOS]` (out of sandbox), or `[BAD]` (XML parse error in strict mode).
    Final line is `PASS` or `FAIL: N issue(s)`.

    Args:
        project_file: path to the .pro file (absolute or sandbox-relative)
        strict: also run XML validation on .ui / .qrc / .ts references and report duplicate entries

        Args:
            project_file: Absolute or sandbox-relative path to the .pro file to validate. SOURCES/HEADERS/FORMS/RESOURCES references are followed and each file is checked for existence + readability + sandbox membership.
            strict: If True, also report duplicate entries and check that referenced .ui/.qrc/.ts files are syntactically valid (XML parse OK).

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    proj = Path(params.project_file)
    if not proj.is_absolute():
        proj = (SANDBOX_ROOT / proj).resolve()

    sandbox_err = _require_sandbox(proj, "project_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj.exists():
        msg = f"Error: project file not found: {proj}"
        return msg + _json_footer({"ok": False, "error": msg})
    if proj.suffix.lower() != ".pro":
        msg = f"Error: expected a .pro file, got {proj.suffix!r}: {proj}"
        return msg + _json_footer({"ok": False, "error": msg})

    project_dir = proj.parent
    entries = _pro_parse(proj.read_text(encoding="utf-8", errors="replace"))

    # Pull every variable we know how to interpret. Tokenize values on whitespace.
    categories: dict[str, list[str]] = {
        "SOURCES": [], "HEADERS": [], "FORMS": [],
        "RESOURCES": [], "TRANSLATIONS": [], "DISTFILES": [],
    }
    seen: dict[str, set[str]] = {k: set() for k in categories}
    for e in entries:
        if e["var"] in categories and e["value"]:
            for tok in e["value"].split():
                if tok.startswith("-"):
                    continue
                categories[e["var"]].append(tok)
                seen[e["var"]].add(tok)

    lines: list[str] = [f"=== qt_validate: {proj} ===", f"project_dir: {project_dir}", f"strict: {params.strict}", ""]
    issues = 0

    def _check(label: str, files: list[str], ext_check: bool = False) -> None:
        nonlocal issues
        if not files:
            return
        lines.append(f"--- {label} ({len(files)}) ---")
        for f in files:
            resolved = (project_dir / f).resolve()
            tag = "OK"
            if not resolved.exists():
                tag = "MISS"
                issues += 1
            elif not _in_sandbox(resolved):
                tag = "OOS"
                issues += 1
            elif not os.access(resolved, os.R_OK):
                tag = "NOR"
                issues += 1
            elif ext_check and not resolved.suffix.lower() in {".ui", ".qrc", ".ts"}:
                tag = f"EXT?{resolved.suffix}"
            lines.append(f"  [{tag}] {f}")

            if tag == "OK" and params.strict and resolved.suffix.lower() in {".ui", ".qrc"}:
                try:
                    ElementTree.parse(resolved)
                except ElementTree.ParseError as e:
                    lines.append(f"         [BAD-XML] {e}")
                    issues += 1

            # For .qrc: also walk <file> entries
            if tag == "OK" and params.strict and resolved.suffix.lower() == ".qrc":
                _, blocks, qerr = _qrc_parse(resolved)
                if qerr:
                    lines.append(f"         [BAD-QRC] {qerr}")
                    issues += 1
                    continue
                qrc_seen: set[str] = set()
                for prefix, qfiles in blocks:
                    for qf in qfiles:
                        if qf in qrc_seen:
                            lines.append(f"         [DUP] {qf}")
                            issues += 1
                        qrc_seen.add(qf)
                        qresolved = (resolved.parent / qf).resolve()
                        if not qresolved.exists():
                            lines.append(f"         [MISS] {prefix}/{qf}")
                            issues += 1

        # duplicate detection
        dups = {x for x in files if files.count(x) > 1}
        if dups and params.strict:
            for d in sorted(dups):
                lines.append(f"  [DUP] {d}")
                issues += 1
        lines.append("")

    _check("SOURCES", categories["SOURCES"])
    _check("HEADERS", categories["HEADERS"])
    _check("FORMS", categories["FORMS"], ext_check=True)
    _check("RESOURCES", categories["RESOURCES"], ext_check=True)
    _check("TRANSLATIONS", categories["TRANSLATIONS"], ext_check=True)
    _check("DISTFILES", categories["DISTFILES"])

    verdict = "PASS" if issues == 0 else f"FAIL: {issues} issue(s)"
    lines.append(f"=== Verdict: {verdict} ===")
    out = "\n".join(lines)
    return out + _json_footer({"ok": issues == 0, "data": {"issues": issues, "verdict": verdict}})


# --- Run with Qt logging -----------------------------------------------------

@mcp.tool(name="qt_run_trace", annotations={"title": "Run a Qt .exe with QT_LOGGING_RULES to capture trace logs", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_run_trace(params: QtRunTraceInput) -> str:
    """Launch a Qt .exe with logging categories enabled and capture its console output.

    Equivalent to running `<exe> <args>` with these env vars set:
      QT_LOGGING_RULES=<env_rules>
      QT_LOGGING_TO_CONSOLE=1

    Output is whatever the exe wrote to stdout/stderr before the timeout expires.
    Use this to debug signal/slot dispatch (env_rules='qt.core.signal*=true'), QML loading
    ('qt.qml.*=true'), or plugin loading ('qt.*=true').

    Args:
        executable: absolute path to the .exe
        args: command-line args
        env_rules: QT_LOGGING_RULES value (see https://doc.qt.io/qt-5/qloggingcategory.html)
        timeout: seconds to wait before killing
        extra_env: optional dict of additional env vars

        Args:
            executable: Absolute path to the .exe to run. Will be launched with QT_LOGGING_RULES=<env_rules> + QT_LOGGING_TO_CONSOLE=1 so all qDebug/qInfo/qWarning output goes to stdout/stderr.
            args: Command-line args to pass to the executable.
            env_rules: Value for the QT_LOGGING_RULES env var. Common patterns: 'qt.core.signal*=true' (signal/slot trace), 'qt.qml.diskio.debug=true' (QML loading). See https://doc.qt.io/qt-5/qloggingcategory.html.
            timeout: Seconds to wait before terminating the process and returning whatever was captured.
            extra_env: Extra environment variables merged into the child's env, on top of the standard Qt-on-PATH env + logging rules.

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    exe = Path(params.executable)
    sandbox_err = _require_sandbox(exe, "executable")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not exe.exists():
        msg = f"Error: executable not found: {exe}"
        return msg + _json_footer({"ok": False, "error": msg})

    env = _qt_env()
    env["QT_LOGGING_RULES"] = params.env_rules
    env["QT_LOGGING_TO_CONSOLE"] = "1"
    if params.extra_env:
        env.update(params.extra_env)

    # Pick 32/64-bit Qt bin dir based on exe
    exe_bits = _pe_bits(exe)
    if exe_bits == 32:
        env["PATH"] = f"{QT_32_BIN_DIR};{env.get('PATH', '')}"
    else:
        env["PATH"] = f"{QT_BIN_DIR};{env.get('PATH', '')}"

    lines: list[str] = [
        f"=== qt_run_trace: {exe} ===",
        f"args: {params.args}",
        f"QT_LOGGING_RULES={params.env_rules}",
        f"timeout: {params.timeout}s",
        f"pe-bits: {exe_bits}",
        "",
    ]

    try:
        proc = await asyncio.create_subprocess_exec(
            str(exe), *params.args,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.PIPE,
            env=env,
            cwd=str(exe.parent),
        )
    except OSError as e:
        msg = f"Error: failed to launch {exe}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    try:
        stdout_b, stderr_b = await asyncio.wait_for(proc.communicate(), timeout=params.timeout)
    except asyncio.TimeoutError:
        proc.kill()
        try:
            stdout_b, stderr_b = await asyncio.wait_for(proc.communicate(), timeout=2)
        except asyncio.TimeoutError:
            stdout_b = b""
            stderr_b = b"(killed - communicate timed out after kill)"
        lines.append(f"=== TIMEOUT after {params.timeout}s, process killed ===")
    except Exception as e:
        msg = f"Error: subprocess failed: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    stdout = stdout_b.decode("utf-8", errors="replace")
    stderr = stderr_b.decode("utf-8", errors="replace")
    rc = proc.returncode if proc.returncode is not None else -1

    lines.append(f"--- returncode: {rc} ---")
    if stdout:
        lines.append("--- stdout ---")
        lines.append(stdout.rstrip())
    if stderr:
        lines.append("--- stderr ---")
        lines.append(stderr.rstrip())
    if not stdout and not stderr:
        lines.append("(no output captured)")

    out = "\n".join(lines)
    return out + _json_footer({"ok": True, "data": {"returncode": rc, "stdout_bytes": len(stdout_b), "stderr_bytes": len(stderr_b)}})


# --- End-to-end smoke test ---------------------------------------------------

@mcp.tool(name="qt_smoke_test", annotations={"title": "Clean → build → run a Qt project for a quick health check", "readOnlyHint": False, "destructiveHint": True, "idempotentHint": True, "openWorldHint": False})
async def qt_smoke_test(params: QtSmokeTestInput) -> str:
    """End-to-end health check: clean artifacts, rebuild, and briefly launch the .exe.

    Useful before pushing to CI, after switching Qt/MinGW versions, or when chasing "it worked
    yesterday" regressions. Returns PASS only if all three steps succeed:

      1. clean  — remove build-* / debug / release dirs and stray .o / moc_*.cpp / ui_*.h files
      2. build  — qmake + mingw32-make (via qt_build)
      3. run    — detach-spawn the .exe for `run_seconds`, then kill it

    Args:
        project_dir: Qt project directory (must contain a .pro file)
        build_type: 'debug' (default) or 'release'
        run_seconds: how long to let the .exe run before killing; 0 skips the run phase
        build_timeout: passed through to qt_build

        Args:
            project_dir: Absolute path to the Qt project directory (containing a .pro file). Must be inside the sandbox.
            build_type: qmake CONFIG value passed through to qt_build — 'debug' (default) or 'release'.
            run_seconds: Seconds to let the freshly-built .exe run before killing it and returning the tail of stdout/stderr. Use 0 to skip the run phase entirely.
            build_timeout: Seconds passed to qt_build before it gives up on mingw32-make.

        Returns:
            str: a formatted text report. Starts with 'Error: ' on failure.

        Raises:
            No exceptions; errors are returned as formatted strings.

        Note:
            Set QT_MCP_JSON=1 in the server's env to append a `--- json ---\n{ok, tool}` trailer."""
    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir not found or not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    pro_files = list(proj_dir.glob("*.pro"))
    if not pro_files:
        msg = f"Error: no .pro file found in {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})
    if len(pro_files) > 1:
        pro_name = pro_files[0].name
        lines_warn = [f"(warning: multiple .pro files found, using {pro_name})"]
    else:
        pro_name = pro_files[0].name
        lines_warn = []

    lines: list[str] = [
        f"=== qt_smoke_test: {proj_dir} ===",
        f"build_type: {params.build_type}",
        *lines_warn,
        "",
    ]

    # Step 1: clean
    lines.append("--- Step 1/3: clean ---")
    cleaned, removed = _clean_artifacts(proj_dir)
    lines.append(f"removed: {cleaned} entries (build-*, debug/, release/, *.o, moc_*.cpp, ui_*.h)")

    # Step 2: build
    lines.append("")
    lines.append("--- Step 2/3: build ---")
    build_in = QtBuildInput(
        project_dir=str(proj_dir),
        build_type=params.build_type,
        timeout=params.build_timeout,
    )
    build_out = await qt_build(build_in)
    build_ok = "Error:" not in build_out and "BUILD FAILED" not in build_out
    tail_lines = build_out.splitlines()[-15:]
    lines.extend(tail_lines)
    lines.append(f"build: {'OK' if build_ok else 'FAIL'}")

    if not build_ok:
        lines.append("")
        lines.append("=== Verdict: FAIL (build) ===")
        out = "\n".join(lines)
        return out + _json_footer({"ok": False, "data": {"stage": "build", "removed": removed}})

    # Find the built .exe
    candidates: list[Path] = []
    for sub in ("debug", "release"):
        candidates += list((proj_dir / sub).glob("*.exe"))
    candidates += list((proj_dir).glob("*.exe"))
    candidates = sorted(set(candidates), key=lambda p: (p.parent.name != "debug", str(p)))
    if not candidates:
        msg = f"Error: build succeeded but no .exe found under {proj_dir}/debug or /release"
        lines.append("")
        lines.append(msg)
        lines.append("=== Verdict: FAIL (no .exe) ===")
        return "\n".join(lines) + _json_footer({"ok": False, "error": msg, "data": {"stage": "build"}})

    exe = candidates[0]
    lines.append(f"exe: {exe}")

    if params.run_seconds == 0:
        lines.append("")
        lines.append("--- Step 3/3: run (skipped, run_seconds=0) ---")
        lines.append("=== Verdict: PASS (build only) ===")
        out = "\n".join(lines)
        return out + _json_footer({"ok": True, "data": {"stage": "build", "exe": str(exe), "removed": removed}})

    # Step 3: run briefly
    lines.append("")
    lines.append(f"--- Step 3/3: run ({params.run_seconds}s) ---")
    run_in = QtRunInput(executable=str(exe), args=[], detach=True, timeout=params.run_seconds)
    run_out = await qt_run(run_in)
    # Grab last 10 lines
    run_tail = run_out.splitlines()[-10:]
    lines.extend(run_tail)
    run_ok = "Detached launch OK" in run_out or "PID" in run_out
    lines.append(f"run: {'OK' if run_ok else 'FAIL'}")

    # Kill any leftover exe
    kill_in = QtKillExeInput(image_name=exe.name)
    await qt_kill_exe(kill_in)

    verdict = "PASS" if run_ok else "FAIL (run)"
    lines.append("")
    lines.append(f"=== Verdict: {verdict} ===")
    out = "\n".join(lines)
    return out + _json_footer({"ok": run_ok, "data": {"stage": "run", "exe": str(exe), "removed": removed}})


# --- Project diff ------------------------------------------------------------

@mcp.tool(name="qt_diff", annotations={"title": "Compare two .pro projects (variables + sources + contents)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_diff(params: QtDiffInput) -> str:
    """Compare two Qt project (.pro) files and report the differences.

    Walks both .pro files, then for each common variable (SOURCES, HEADERS, FORMS, RESOURCES,
    TRANSLATIONS, DEFINES, INCLUDEPATH) reports values that exist only in A, only in B, or
    differ. For source files present in both projects, also reports files with different content
    (SHA1 mismatch).

    Use cases:
      - See what's different between a fork and the upstream project
      - Audit a refactor: which files moved / were renamed / deleted
      - Verify two branches of the same project really are equivalent

    Args:
        params.proj_a: path to first .pro file
        params.proj_b: path to second .pro file
        params.show_identical: also list files present in both with the same SHA1
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    def _resolve(p: str) -> Path:
        pp = Path(p)
        if not pp.is_absolute():
            pp = (SANDBOX_ROOT / pp).resolve()
        return pp

    a = _resolve(params.proj_a)
    b = _resolve(params.proj_b)

    for p, name in [(a, "proj_a"), (b, "proj_b")]:
        err = _require_sandbox(p, name)
        if err:
            return err + _json_footer({"ok": False, "error": err})
        if not p.exists() or p.suffix.lower() != ".pro":
            msg = f"Error: {name} is not an existing .pro file: {p}"
            return msg + _json_footer({"ok": False, "error": msg})

    import hashlib
    def _sha1(path: Path) -> str:
        try:
            return hashlib.sha1(path.read_bytes()).hexdigest()[:12]
        except OSError:
            return "(unreadable)"

    def _extract(proj: Path) -> dict[str, set[str]]:
        out: dict[str, set[str]] = {}
        for e in _pro_parse(proj.read_text(encoding="utf-8", errors="replace")):
            var = e["var"]
            if var in {"SOURCES", "HEADERS", "FORMS", "RESOURCES", "TRANSLATIONS",
                       "DISTFILES", "DEFINES", "INCLUDEPATH", "LIBS"} and e["value"]:
                out.setdefault(var, set()).update(e["value"].split())
        return out

    da = _extract(a)
    db = _extract(b)
    all_vars = sorted(set(da) | set(db))

    lines: list[str] = [
        f"=== qt_diff: {a.name} vs {b.name} ===",
        f"A: {a}",
        f"B: {b}",
        f"show_identical: {params.show_identical}",
        "",
    ]

    file_vars = ("SOURCES", "HEADERS", "FORMS", "RESOURCES", "TRANSLATIONS", "DISTFILES")
    only_a: list[str] = []
    only_b: list[str] = []
    diff_content: list[str] = []
    same_content: list[str] = []

    for var in all_vars:
        va = da.get(var, set())
        vb = db.get(var, set())
        in_a_only = va - vb
        in_b_only = vb - va
        common = va & vb

        lines.append(f"--- {var} ---")
        if in_a_only:
            lines.append(f"  only in A ({len(in_a_only)}):")
            for v in sorted(in_a_only)[:20]:
                lines.append(f"    + {v}")
            if len(in_a_only) > 20:
                lines.append(f"    ... and {len(in_a_only) - 20} more")
        if in_b_only:
            lines.append(f"  only in B ({len(in_b_only)}):")
            for v in sorted(in_b_only)[:20]:
                lines.append(f"    - {v}")
            if len(in_b_only) > 20:
                lines.append(f"    ... and {len(in_b_only) - 20} more")
        if not in_a_only and not in_b_only:
            lines.append(f"  (identical, {len(common)} entries)")

        if var in file_vars and common:
            for f in sorted(common):
                fa = (a.parent / f).resolve()
                fb = (b.parent / f).resolve()
                if not fa.exists() or not fb.exists():
                    diff_content.append(f"{var}: {f}  [exists-in-one-only]")
                    continue
                sa = _sha1(fa)
                sb = _sha1(fb)
                if sa != sb:
                    diff_content.append(f"{var}: {f}  A={sa} B={sb}")
                elif params.show_identical:
                    same_content.append(f"{var}: {f}  SHA1={sa}")

        only_a.extend(in_a_only)
        only_b.extend(in_b_only)
        lines.append("")

    lines.append("--- File content diffs (common file with different SHA1) ---")
    if diff_content:
        for d in diff_content[:40]:
            lines.append(f"  [DIFF] {d}")
        if len(diff_content) > 40:
            lines.append(f"  ... and {len(diff_content) - 40} more")
    else:
        lines.append("  (none — all common files have identical SHA1)")

    if params.show_identical:
        lines.append("")
        lines.append("--- Identical files (common file with matching SHA1) ---")
        if same_content:
            for s in same_content[:20]:
                lines.append(f"  [SAME] {s}")
            if len(same_content) > 20:
                lines.append(f"  ... and {len(same_content) - 20} more")
        else:
            lines.append("  (none)")

    lines.append("")
    lines.append("=== Summary ===")
    lines.append(f"  variables compared: {len(all_vars)}")
    lines.append(f"  A-only entries:     {len(only_a)}")
    lines.append(f"  B-only entries:     {len(only_b)}")
    lines.append(f"  files differing:    {len(diff_content)}")
    if params.show_identical:
        lines.append(f"  files identical:    {len(same_content)}")

    out = "\n".join(lines)
    return out + _json_footer({
        "ok": True,
        "data": {
            "variables_compared": len(all_vars),
            "a_only_entries": len(only_a),
            "b_only_entries": len(only_b),
            "files_differing": len(diff_content),
            "files_identical": len(same_content) if params.show_identical else None,
        },
    })


# --- Qt package metadata -----------------------------------------------------

@mcp.tool(name="qt_pkg", annotations={"title": "List / inspect installed Qt 5 modules", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_pkg(params: QtPkgInput) -> str:
    """List Qt 5 modules installed under QT_ROOT, or inspect one in detail.

    Walks QT_ROOT/include/Qt* and QT_ROOT/lib/cmake/Qt5* to enumerate modules.
    For a specific module, also reports its version (from cmake config), header count,
    and any plugins shipped under QT_ROOT/plugins/.

    Args:
        params.module: empty = list all, "Qt5Widgets" = inspect that module, "Qt5Core" = core, etc.
        params.include_private: also list Qt5*Private modules

    Returns:
        str: formatted text report.
    

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    include_dir = QT_ROOT / "include"
    lib_dir = QT_ROOT / "lib"
    cmake_dir = lib_dir / "cmake"

    if not include_dir.is_dir():
        msg = f"Error: Qt include dir not found: {include_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    qt_modules: list[Path] = []
    for p in sorted(include_dir.iterdir()):
        if not p.is_dir():
            continue
        if not p.name.startswith("Qt"):
            continue
        if not params.include_private and "Private" in p.name:
            continue
        qt_modules.append(p)

    lines: list[str] = [
        f"=== qt_pkg: {len(qt_modules)} modules under {QT_ROOT} ===",
        f"include_dir: {include_dir}",
        f"lib_dir:     {lib_dir}",
        f"include_private: {params.include_private}",
        "",
    ]

    if params.module:
        # Inspect one module
        mod_name = params.module
        mod_path = include_dir / mod_name
        if not mod_path.is_dir():
            # Try with Qt5 prefix
            for p in qt_modules:
                if p.name == mod_name or p.name == "Qt5" + mod_name.removeprefix("Qt5"):
                    mod_path = p
                    mod_name = p.name
                    break
        if not mod_path.is_dir():
            msg = f"Error: module not found: {mod_name}"
            return msg + _json_footer({"ok": False, "error": msg})

        headers = sorted(p.name for p in mod_path.glob("*.h"))[:20]
        all_headers = list(mod_path.glob("*.h"))
        # Version from cmake config
        version = "?"
        cmake_file = cmake_dir / mod_name / f"{mod_name}Config.cmake"
        if cmake_file.exists():
            try:
                for ln in cmake_file.read_text(encoding="utf-8", errors="replace").splitlines():
                    m = re.search(r"set\s*\(\s*PACKAGE_VERSION\s+\"?([0-9.]+)", ln)
                    if m:
                        version = m.group(1)
                        break
            except OSError:
                pass

        # Library files
        lib_files = sorted(p.name for p in (lib_dir / mod_name).glob(f"{mod_name}*.lib")) if (lib_dir / mod_name).is_dir() else []
        lib_files += sorted(p.name for p in lib_dir.glob(f"{mod_name}*.lib"))[:5]

        lines.append(f"--- {mod_name} (version {version}) ---")
        lines.append(f"  path:     {mod_path}")
        lines.append(f"  headers:  {len(all_headers)} ({', '.join(headers[:10])}{'...' if len(headers) > 10 else ''})")
        lines.append(f"  libs:     {', '.join(lib_files[:5]) or '(none)'}")
        if cmake_file.exists():
            lines.append(f"  cmake:    {cmake_file}")
        out = "\n".join(lines)
        return out + _json_footer({"ok": True, "data": {"module": mod_name, "version": version, "header_count": len(all_headers)}})

    # List all modules
    lines.append(f"--- Modules ({len(qt_modules)}) ---")
    for m in qt_modules:
        # Check if cmake config exists
        cmake = cmake_dir / m.name / f"{m.name}Config.cmake"
        lib_exists = (lib_dir / m.name).is_dir() or any(lib_dir.glob(f"{m.name}*.lib"))
        marker = "OK" if cmake.exists() and lib_exists else "part"
        lines.append(f"  [{marker}] {m.name}")

    # Plugins
    plugins_dir = QT_ROOT / "plugins"
    if plugins_dir.is_dir():
        lines.append("")
        lines.append("--- Plugins ---")
        for sub in sorted(plugins_dir.iterdir()):
            if sub.is_dir():
                count = sum(1 for _ in sub.iterdir())
                lines.append(f"  {sub.name}/ ({count} files)")

    out = "\n".join(lines)
    return out + _json_footer({"ok": True, "data": {"module_count": len(qt_modules)}})


# --- Qt log analysis ---------------------------------------------------------

@mcp.tool(name="qt_log", annotations={"title": "Filter / analyze a Qt log file", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_log(params: QtLogInput) -> str:
    """Filter and summarize a Qt log file (typically the .qt_mcp_last_build.log
    produced by qt_build, or a log captured by qt_run_trace).

    Args:
        params.log_file: absolute path to the log. If empty, uses <project_dir>/.qt_mcp_last_build.log.
        params.project_dir: fallback if log_file is empty.
        params.category_filter: only show lines containing this substring (e.g. 'qt.qml').
        params.level_filter: only show lines containing this level ('debug' / 'warning' / 'critical' / 'fatal').
        params.max_lines: cap on output (default 200).

    Returns:
        str: filtered log lines + a summary block (total lines, by-level counts, by-category counts).
    

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.log_file:
        log_path = Path(params.log_file)
    elif params.project_dir:
        log_path = Path(params.project_dir) / ".qt_mcp_last_build.log"
    else:
        msg = "Error: provide either log_file or project_dir"
        return msg + _json_footer({"ok": False, "error": msg})

    sandbox_err = _require_sandbox(log_path, "log_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not log_path.exists():
        msg = f"Error: log file not found: {log_path}"
        return msg + _json_footer({"ok": False, "error": msg})

    try:
        text = log_path.read_text(encoding="utf-8", errors="replace")
    except OSError as e:
        msg = f"Error: failed to read {log_path}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    lines_all = text.splitlines()
    lines_filtered: list[str] = []
    level_counts: dict[str, int] = {"debug": 0, "warning": 0, "critical": 0, "fatal": 0, "info": 0, "other": 0}
    cat_counts: dict[str, int] = {}

    cat_filter_lower = params.category_filter.lower()
    level_filter_lower = params.level_filter.lower()

    for ln in lines_all:
        ll = ln.lower()
        # Level detection
        if "warning" in ll or "warn" in ll:
            level = "warning"
        elif "critical" in ll:
            level = "critical"
        elif "fatal" in ll:
            level = "fatal"
        elif "debug" in ll:
            level = "debug"
        elif "info" in ll:
            level = "info"
        else:
            level = "other"
        level_counts[level] += 1

        # Category detection (look for `qt.<category>` patterns)
        for m in re.finditer(r'\b(qt\.[a-zA-Z0-9_.]+)', ln):
            cat = m.group(1)
            cat_counts[cat] = cat_counts.get(cat, 0) + 1

        if cat_filter_lower and cat_filter_lower not in ll:
            continue
        if level_filter_lower and level_filter_lower not in ll:
            continue
        lines_filtered.append(ln)

    truncated = len(lines_filtered) > params.max_lines
    shown = lines_filtered[:params.max_lines]

    out_lines: list[str] = [
        f"=== qt_log: {log_path} ===",
        f"total lines:    {len(lines_all)}",
        f"matching lines: {len(lines_filtered)}" + (f" (truncated to {params.max_lines})" if truncated else ""),
        f"category_filter: {params.category_filter!r}",
        f"level_filter:    {params.level_filter!r}",
        "",
        "--- By level ---",
    ]
    for lvl, count in sorted(level_counts.items(), key=lambda x: -x[1]):
        if count:
            out_lines.append(f"  {lvl:10s} {count}")
    if cat_counts:
        out_lines.append("")
        out_lines.append("--- Top categories ---")
        for cat, count in sorted(cat_counts.items(), key=lambda x: -x[1])[:10]:
            out_lines.append(f"  {cat:40s} {count}")
    out_lines.append("")
    out_lines.append(f"--- Matching lines ({len(shown)}) ---")
    out_lines.extend(shown)
    out = "\n".join(out_lines)
    return out + _json_footer({
        "ok": True,
        "data": {
            "total_lines": len(lines_all),
            "matching_lines": len(lines_filtered),
            "truncated": truncated,
            "level_counts": level_counts,
            "top_categories": dict(sorted(cat_counts.items(), key=lambda x: -x[1])[:10]),
        },
    })


# --- Qt state (QSettings wrapper) --------------------------------------------

@mcp.tool(name="qt_state", annotations={"title": "Save / load / list / clear persistent app state via QSettings", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_state(params: QtStateInput) -> str:
    """Persist and retrieve key/value state via Qt's QSettings (uses the OS-native
    registry / plist / ini backend).

    This tool runs OUTSIDE the Qt event loop — it directly reads/writes the .ini file
    that QSettings would have used. Format on Windows:
        %APPDATA%\\<organization>\\<application>.ini

    Actions:
      - save   : write the data dict under the given key
      - load   : read back the data dict for the given key
      - delete : remove the given key
      - list   : show all keys (and their sub-keys) under the org/app
      - clear  : wipe the org/app section entirely

    Args:
        params.action: 'save' | 'load' | 'delete' | 'list' | 'clear'
        params.organization: org name (default 'qt-mcp')
        params.application: app name (default 'default')
        params.key: key for save/load/delete
        params.data: data dict for save
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("save", "load", "delete", "list", "clear"):
        msg = f"Error: invalid action {params.action!r}. Must be save/load/delete/list/clear."
        return msg + _json_footer({"ok": False, "error": msg})

    # Compute the .ini path the way QSettings would on Windows
    appdata = os.environ.get("APPDATA", "")
    if not appdata:
        # Fallback: $HOME/.config (Linux-style)
        appdata = str(Path.home() / ".config")
    ini_path = Path(appdata) / params.organization / f"{params.application}.ini"

    # Note: no sandbox check here. QSettings by design writes to OS-native
    # per-user dirs (APPDATA on Windows, ~/.config on Linux, ~/Library/Preferences
    # on macOS). Board games need persistent state outside the project tree.

    if params.action == "save":
        if not params.key:
            msg = "Error: 'save' requires a non-empty key"
            return msg + _json_footer({"ok": False, "error": msg})
        if not params.data:
            msg = "Error: 'save' requires a non-empty data dict"
            return msg + _json_footer({"ok": False, "error": msg})
        # Use configparser to preserve the format
        import configparser
        cp = configparser.ConfigParser()
        if ini_path.exists():
            cp.read(ini_path, encoding="utf-8")
        section = params.key if "/" not in params.key else params.key.rsplit("/", 1)[0]
        sub_key = params.key.rsplit("/", 1)[-1] if "/" in params.key else params.key
        if not cp.has_section(section):
            cp.add_section(section)
        for k, v in params.data.items():
            cp.set(section, k, str(v))
        ini_path.parent.mkdir(parents=True, exist_ok=True)
        with ini_path.open("w", encoding="utf-8") as f:
            cp.write(f)
        out = f"saved: {ini_path}\n  key: {params.key}\n  data: {params.data}"
        return out + _json_footer({"ok": True, "data": {"saved": True, "path": str(ini_path)}})

    if params.action == "load":
        if not params.key:
            msg = "Error: 'load' requires a non-empty key"
            return msg + _json_footer({"ok": False, "error": msg})
        if not ini_path.exists():
            out = f"no data: {ini_path} does not exist"
            return out + _json_footer({"ok": True, "data": {"data": {}, "exists": False}})
        import configparser
        cp = configparser.ConfigParser()
        cp.read(ini_path, encoding="utf-8")
        if not cp.has_section(params.key):
            out = f"no data: section [{params.key}] not found in {ini_path}"
            return out + _json_footer({"ok": True, "data": {"data": {}, "exists": True}})
        data = dict(cp.items(params.key))
        out = "\n".join([f"{k} = {v}" for k, v in data.items()])
        return out + _json_footer({"ok": True, "data": {"data": data, "exists": True}})

    if params.action == "delete":
        if not params.key:
            msg = "Error: 'delete' requires a non-empty key"
            return msg + _json_footer({"ok": False, "error": msg})
        if not ini_path.exists():
            out = f"nothing to delete: {ini_path} does not exist"
            return out + _json_footer({"ok": True, "data": {"deleted": False}})
        import configparser
        cp = configparser.ConfigParser()
        cp.read(ini_path, encoding="utf-8")
        if cp.has_section(params.key):
            cp.remove_section(params.key)
            with ini_path.open("w", encoding="utf-8") as f:
                cp.write(f)
            out = f"deleted: [{params.key}] from {ini_path}"
            return out + _json_footer({"ok": True, "data": {"deleted": True}})
        out = f"nothing to delete: [{params.key}] not in {ini_path}"
        return out + _json_footer({"ok": True, "data": {"deleted": False}})

    if params.action == "list":
        if not ini_path.exists():
            out = f"(empty: {ini_path} does not exist)"
            return out + _json_footer({"ok": True, "data": {"sections": [], "exists": False}})
        import configparser
        cp = configparser.ConfigParser()
        cp.read(ini_path, encoding="utf-8")
        sections = cp.sections()
        out_lines = [f"--- {ini_path} ({len(sections)} sections) ---"]
        for s in sections:
            keys = cp.options(s)
            out_lines.append(f"  [{s}] ({len(keys)} keys)")
            for k in keys[:5]:
                out_lines.append(f"    {k} = {cp.get(s, k, raw=True)}")
            if len(keys) > 5:
                out_lines.append(f"    ... and {len(keys) - 5} more")
        out = "\n".join(out_lines) if len(out_lines) > 1 else "(empty: no sections)"
        return out + _json_footer({"ok": True, "data": {"sections": sections, "exists": True}})

    if params.action == "clear":
        if ini_path.exists():
            ini_path.unlink()
            out = f"cleared: {ini_path}"
            return out + _json_footer({"ok": True, "data": {"cleared": True}})
        out = f"nothing to clear: {ini_path} does not exist"
        return out + _json_footer({"ok": True, "data": {"cleared": False}})

    # unreachable
    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- Asset bundling (advanced .qrc generation) -------------------------------

@mcp.tool(name="qt_assets", annotations={"title": "Scan an assets directory and emit a .qrc (with optional Q_INIT_RESOURCE helper)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_assets(params: QtAssetsInput) -> str:
    """Scan a directory of asset files and emit a .qrc resource manifest.

    More powerful than `qt_gen_qrc`: scans recursively, supports exclude patterns,
    groups by subdirectory, and can optionally emit a 'qrc_assets.cpp' with
    `Q_INIT_RESOURCE(<name>)` to embed the assets at startup.

    Args:
        params.assets_dir: directory to scan
        params.output_qrc: where to write the .qrc (inside sandbox)
        params.prefix: Qt resource prefix (e.g. '/', '/images')
        params.extensions: file extensions to include (default: common image + audio formats)
        params.recursive: recurse into subdirs
        params.generate_init: also write qrc_assets.cpp with Q_INIT_RESOURCE
        params.exclude_patterns: substring patterns to skip
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    assets_dir = Path(params.assets_dir)
    qrc_path = Path(params.output_qrc)
    if not assets_dir.is_absolute():
        assets_dir = (SANDBOX_ROOT / assets_dir).resolve()
    if not qrc_path.is_absolute():
        qrc_path = (SANDBOX_ROOT / qrc_path).resolve()

    sandbox_err = _require_sandbox(assets_dir, "assets_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    sandbox_err = _require_sandbox(qrc_path, "output_qrc")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    if not assets_dir.exists() or not assets_dir.is_dir():
        msg = f"Error: assets_dir is not a directory: {assets_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    exts = {e.lower() if e.startswith(".") else "." + e.lower() for e in params.extensions}
    excludes = params.exclude_patterns

    matched: list[Path] = []
    pattern = assets_dir.rglob("*") if params.recursive else assets_dir.glob("*")
    for p in pattern:
        if not p.is_file():
            continue
        if p.suffix.lower() not in exts:
            continue
        rel = str(p.relative_to(assets_dir))
        if any(ex in rel for ex in excludes):
            continue
        matched.append(p)
    matched.sort()

    if not matched:
        msg = f"Error: no files matched in {assets_dir} (extensions: {sorted(exts)})"
        return msg + _json_footer({"ok": False, "error": msg})

    # Group by subdirectory
    groups: dict[str, list[Path]] = {}
    for p in matched:
        rel = p.relative_to(assets_dir)
        parent = str(rel.parent).replace("\\", "/")
        if parent == ".":
            parent = ""
        groups.setdefault(parent, []).append(p)

    # Build the .qrc XML
    name = qrc_path.stem
    lines_xml = [f'<RCC>', f'  <qresource prefix="{params.prefix}">']
    for subdir, files in sorted(groups.items()):
        if subdir:
            lines_xml.append(f'    <!-- {subdir} -->')
        for p in files:
            rel = str(p.relative_to(assets_dir)).replace("\\", "/")
            lines_xml.append(f'    <file>{rel}</file>')
    lines_xml.append('  </qresource>')
    lines_xml.append('</RCC>')

    qrc_path.parent.mkdir(parents=True, exist_ok=True)
    qrc_path.write_text("\n".join(lines_xml) + "\n", encoding="utf-8")

    extra = []
    if params.generate_init:
        # Emit a qrc_assets.cpp next to the .qrc
        init_path = qrc_path.parent / f"qrc_{name}.cpp"
        init_path.write_text(
            f"// Auto-generated by qt-mcp qt_assets. Embeds {name} resources at startup.\n"
            f"#include <QtGlobal>\n"
            f"\n"
            f"extern int qInitResources_{name}();\n"
            f"\n"
            f"namespace {{\n"
            f"    struct {name}_resource_init {{\n"
            f"        {name}_resource_init() {{ qInitResources_{name}(); }}\n"
            f"    }};\n"
            f"    static {name}_resource_init {name}_init_instance;\n"
            f"}}\n",
            encoding="utf-8",
        )
        extra.append(f"init helper: {init_path}")

    out_lines = [
        f"=== qt_assets: {len(matched)} files -> {qrc_path} ===",
        f"prefix:    {params.prefix}",
        f"recursive: {params.recursive}",
        f"groups:    {len(groups)}",
        f"extensions: {sorted(exts)}",
        f"excluded:  {len(excludes)} patterns",
        *([f"extra:     {e}" for e in extra]),
        "",
        "--- Files ---",
    ]
    for subdir, files in sorted(groups.items()):
        out_lines.append(f"  [{subdir or '.'}] ({len(files)} files)")
        for p in files[:3]:
            out_lines.append(f"    {p.relative_to(assets_dir)}")
        if len(files) > 3:
            out_lines.append(f"    ... and {len(files) - 3} more")
    out = "\n".join(out_lines)
    return out + _json_footer({
        "ok": True,
        "data": {
            "qrc_path": str(qrc_path),
            "file_count": len(matched),
            "group_count": len(groups),
            "init_helper": str(init_path) if params.generate_init else None,
        },
    })


# --- qt_watch: auto-rebuild on file change -----------------------------------

@mcp.tool(name="qt_watch", annotations={"title": "Watch a Qt project and auto-rebuild on file change", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_watch(params: QtWatchInput) -> str:
    """Watch a Qt project's source files and trigger a rebuild when they change.

    Uses the `watchdog` library to subscribe to filesystem events, debounces rapid
    changes (default 1.5s), and calls qt_build on each batch. Returns the PID of
    the watcher process; use qt_kill_exe(image_name='python') or kill by PID to stop.

    Args:
        params.project_dir: directory to watch recursively
        params.build_type: 'debug' (default) or 'release' passed to qt_build
        params.debounce_seconds: delay after the last change before rebuild
        params.extensions: file suffixes to watch (default: .h .cpp .ui .qrc .qml)
        params.exclude_dirs: subdir name patterns to skip
        params.timeout_seconds: auto-stop after N seconds; 0 = indefinite

    Returns:
        str: report with PID and the path to the watcher log (when rebuilds happen).
    

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not list(proj_dir.glob("*.pro")):
        msg = f"Error: no .pro file in {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Write a watcher script in .tmp/ and spawn it
    watcher_script = SANDBOX_TMP / f"qt_watch_{os.getpid()}.py"
    log_file = SANDBOX_TMP / f"qt_watch_{os.getpid()}.log"
    # Resolve project_dir to absolute (for the spawned subprocess)
    proj_abs = str(proj_dir.resolve())

    extensions = [e if e.startswith(".") else "." + e for e in params.extensions]
    extensions = [e.lower() for e in extensions]
    exclude_dirs = params.exclude_dirs

    watcher_script.write_text(f'''#!/usr/bin/env python3
"""Auto-rebuild watcher for {proj_abs}. Generated by qt-mcp qt_watch."""
import sys, time, subprocess, json
from pathlib import Path
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

PROJ = Path(r"{proj_abs}")
EXT = {extensions!r}
EXCLUDE = {exclude_dirs!r}
DEBOUNCE = {params.debounce_seconds}
LOG = Path(r"{log_file}")
TIMEOUT = {params.timeout_seconds}

def log(msg):
    with LOG.open("a", encoding="utf-8") as f:
        f.write(f"{{time.strftime('%H:%M:%S')}} {{msg}}\\n")

class Handler(FileSystemEventHandler):
    def __init__(self):
        self.last_change = 0.0
        self.building = False
    def on_any_event(self, event):
        if event.is_directory: return
        p = Path(event.src_path)
        if p.suffix.lower() not in EXT: return
        # skip excluded dirs
        for ex in EXCLUDE:
            if ex in p.parts: return
        self.last_change = time.time()
        log(f"change: {{p.relative_to(PROJ)}}")
    def maybe_build(self):
        if self.building: return
        if self.last_change == 0: return
        if time.time() - self.last_change < DEBOUNCE: return
        self.building = True
        self.last_change = 0
        log("rebuild: start")
        try:
            r = subprocess.run(
                [sys.executable, "-c",
                 "import asyncio, server; from server import QtBuildInput; "
                 f"asyncio.run(server.qt_build(QtBuildInput(project_dir=r'{proj_abs}', build_type='{params.build_type}', timeout=180)))"],
                capture_output=True, text=True, timeout=180,
            )
            log(f"rebuild: rc={{r.returncode}}")
            if r.stdout:
                LOG.with_suffix(".out").open("a", encoding="utf-8").write(r.stdout[-2000:])
            if r.stderr:
                LOG.with_suffix(".err").open("a", encoding="utf-8").write(r.stderr[-2000:])
        except Exception as e:
            log(f"rebuild: error {{e}}")
        self.building = False

def main():
    log(f"start: watching {{PROJ}} for {{EXT}}")
    obs = Observer()
    obs.schedule(Handler(), str(PROJ), recursive=True)
    obs.start()
    start = time.time()
    try:
        while True:
            time.sleep(0.5)
            # The handler is shared via observer; we need to access it. Hack: re-create each tick.
            # Simpler approach: poll for any *.cpp/*.h mtime change in the last DEBOUNCE seconds.
            cutoff = time.time() - DEBOUNCE
            for f in PROJ.rglob("*"):
                if f.suffix.lower() not in EXT: continue
                if any(ex in f.parts for ex in EXCLUDE): continue
                try:
                    if f.stat().st_mtime > cutoff:
                        log(f"poll-change: {{f.relative_to(PROJ)}}")
                        # Run a build
                        r = subprocess.run(
                            [sys.executable, "-c",
                             "import asyncio, server; from server import QtBuildInput; "
                             f"asyncio.run(server.qt_build(QtBuildInput(project_dir=r'{proj_abs}', build_type='{params.build_type}', timeout=180)))"],
                             capture_output=True, text=True, timeout=180,
                         )
                        log(f"rebuild: rc={{r.returncode}}")
                        time.sleep(DEBOUNCE)  # avoid hot loop
                        break
                except OSError:
                    continue
            if TIMEOUT and (time.time() - start) > TIMEOUT:
                log(f"timeout {{TIMEOUT}}s, stopping")
                break
    except KeyboardInterrupt:
        log("interrupted")
    finally:
        obs.stop()
        obs.join()
        log("stopped")

if __name__ == "__main__":
    main()
''', encoding="utf-8")

    # Spawn the watcher detached
    try:
        proc = await asyncio.create_subprocess_exec(
            sys.executable, str(watcher_script),
            stdout=asyncio.subprocess.DEVNULL,
            stderr=asyncio.subprocess.DEVNULL,
            cwd=str(SANDBOX_TMP),
        )
    except OSError as e:
        msg = f"Error: failed to spawn watcher: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Give it a moment to initialize
    await asyncio.sleep(0.5)
    if not _is_pid_alive(proc.pid):
        # Check log for error
        err = log_file.read_text(encoding="utf-8")[-500:] if log_file.exists() else "(no log)"
        msg = f"Error: watcher died immediately. Log: {err}"
        return msg + _json_footer({"ok": False, "error": msg, "log": str(log_file)})

    out = "\n".join([
        f"=== qt_watch: watching {proj_dir} ===",
        f"PID:           {proc.pid}",
        f"extensions:    {extensions}",
        f"debounce:      {params.debounce_seconds}s",
        f"build_type:    {params.build_type}",
        f"timeout:       {params.timeout_seconds}s (0 = indefinite)",
        f"log:           {log_file}",
        f"script:        {watcher_script}",
        "",
        f"To stop: qt_kill_exe(image_name='python') or taskkill /PID {proc.pid} /F",
    ])
    return out + _json_footer({"ok": True, "data": {"pid": proc.pid, "log": str(log_file)}})


# --- qt_signature: code-signing wrapper --------------------------------------

@mcp.tool(name="qt_signature", annotations={"title": "Sign / verify Windows executables (signtool)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_signature(params: QtSignatureInput) -> str:
    """Sign or verify a Windows .exe / .dll using signtool.exe (Windows SDK).

    Actions:
      - 'info'    : locate signtool.exe, report its version and the cert store status
      - 'sign'    : apply Authenticode signature using a .pfx/.p12 cert or a thumbprint
      - 'verify'  : verify an existing signature
      - 'timestamp': add an RFC 3161 timestamp to an already-signed file

    Args:
        params.action: 'info' | 'sign' | 'verify' | 'timestamp'
        params.target: absolute path to the file
        params.certificate_path: .pfx/.p12 file (sign)
        params.certificate_thumbprint: installed-cert thumbprint (sign, alt to cert path)
        params.timestamp_url: RFC 3161 URL (sign, timestamp)
        params.description: signature description (sign)
        params.signtool_path: explicit signtool.exe path; empty = auto-find
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("info", "sign", "verify", "timestamp"):
        msg = f"Error: invalid action {params.action!r}. Must be info/sign/verify/timestamp."
        return msg + _json_footer({"ok": False, "error": msg})

    target = Path(params.target)
    if not target.exists():
        msg = f"Error: target not found: {target}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Find signtool.exe
    signtool = Path(params.signtool_path) if params.signtool_path else None
    if not signtool or not signtool.exists():
        # Search %ProgramFiles%\\Windows Kits\\10\\bin\\*\\x64\\signtool.exe
        candidates: list[Path] = []
        pf = os.environ.get("ProgramFiles", r"C:\Program Files")
        pf86 = os.environ.get("ProgramFiles(x86)", r"C:\Program Files (x86)")
        kits_root = Path(pf) / "Windows Kits"
        if not kits_root.exists():
            kits_root = Path(pf86) / "Windows Kits"
        if kits_root.exists():
            for ver_dir in sorted(kits_root.glob("10/bin/*"), reverse=True):
                candidate = ver_dir / "x64" / "signtool.exe"
                if candidate.exists():
                    candidates.append(candidate)
        if not candidates:
            msg = (f"Error: signtool.exe not found. Searched under {kits_root}. "
                   f"Install the Windows 10 SDK or pass signtool_path.")
            return msg + _json_footer({"ok": False, "error": msg})
        signtool = candidates[0]

    if params.action == "info":
        # Get version
        r = await _run([str(signtool), "/?"], cwd=signtool.parent, timeout=15)
        ver_lines = (r.stdout or r.stderr).splitlines()[:10]
        return "\n".join([
            f"=== qt_signature: info ===",
            f"signtool: {signtool}",
            f"version:  {ver_lines[0] if ver_lines else 'unknown'}",
            f"target:   {target}",
        ]) + _json_footer({"ok": True, "data": {"signtool": str(signtool), "version": ver_lines[0] if ver_lines else None}})

    if params.action == "verify":
        r = await _run([str(signtool), "verify", "/pa", str(target)], cwd=target.parent, timeout=30)
        body = _tail(r.stdout or r.stderr, 20)
        ok = r.ok
        return "\n".join([
            f"=== qt_signature: verify {target} ===",
            f"returncode: {r.returncode}",
            body,
        ]) + _json_footer({"ok": ok, "data": {"returncode": r.returncode}})

    if params.action in ("sign", "timestamp"):
        if params.action == "sign":
            cmd = [str(signtool), "sign"]
            if params.timestamp_url:
                cmd += ["/tr", params.timestamp_url, "/td", "sha256"]
            if params.certificate_path:
                cmd += ["/f", params.certificate_path]
                if params.description:
                    cmd += ["/d", params.description]
            elif params.certificate_thumbprint:
                cmd += ["/sha1", params.certificate_thumbprint]
                if params.description:
                    cmd += ["/d", params.description]
            else:
                msg = "Error: 'sign' requires either certificate_path or certificate_thumbprint"
                return msg + _json_footer({"ok": False, "error": msg})
            cmd.append(str(target))
        else:
            cmd = [str(signtool), "timestamp", "/tr", params.timestamp_url, str(target)]
        r = await _run(cmd, cwd=target.parent, timeout=60)
        body = _tail(r.stdout or r.stderr, 15)
        return "\n".join([
            f"=== qt_signature: {params.action} {target} ===",
            f"signtool: {signtool}",
            f"returncode: {r.returncode}",
            body,
        ]) + _json_footer({"ok": r.ok, "data": {"returncode": r.returncode}})

    # unreachable
    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_signature_batch: batch sign / verify / scan --------------------------
#
# The companion to qt_signature (which only handles one file at a time).
# Scans a directory for .exe / .dll files and applies signtool in batch mode.
# Particularly useful after windeployqt: a Qt project ships with ~10 DLLs that
# all need signing, and doing them one-by-one with qt_signature is tedious.


class QtSignatureBatchInput(BaseModel):
    model_config = ConfigDict(str_strip_whitespace=True, extra="forbid")

    action: str = Field(description="One of: 'info' (locate signtool + cert store), 'scan' (list matching files), 'sign' (batch-sign all), 'verify' (batch-verify all), 'timestamp' (batch-timestamp all).")
    directory: str = Field(description="Absolute path of the directory containing .exe / .dll files to process.")
    patterns: list[str] = Field(
        default_factory=lambda: ["*.exe", "*.dll"],
        description="Glob patterns to match files in directory. Default ['*.exe', '*.dll'].",
    )
    recursive: bool = Field(default=False, description="If True, scan subdirectories too. Default False.")
    certificate_path: str = Field(default="", description="Path to .pfx/.p12 cert file (for 'sign' action).")
    certificate_thumbprint: str = Field(default="", description="SHA1 thumbprint of installed cert (alternative to certificate_path for 'sign').")
    timestamp_url: str = Field(default="http://timestamp.digicert.com", description="RFC 3161 timestamp URL (for 'sign' / 'timestamp').")
    description: str = Field(default="", description="Signature description embedded in the signature (for 'sign').")
    signtool_path: str = Field(default="", description="Explicit signtool.exe path. Empty = auto-find under %%ProgramFiles%%\\Windows Kits.")
    continue_on_error: bool = Field(default=True, description="If True (default), continue signing remaining files when one fails. If False, stop on first error. (DEPRECATED — prefer error_strategy in v0.4.2.)")
    error_strategy: str = Field(default="continue_all", description="V0.4.2 strategy: 'continue_all' (default — skip failures, finish all), 'continue_n:<count>' (continue until N failures, then stop), 'fail_fast' (stop on first error). Overrides continue_on_error when provided.")
    csv_report: str = Field(default="", description="If non-empty, write a per-file CSV summary to this absolute path (columns: file,status,exit_code,duration_ms,error).")
    dry_run: bool = Field(default=False, description="If True, list what would be signed without actually signing. Default False.")
#
# The companion to qt_signature (which only handles one file at a time).
# Scans a directory for .exe / .dll files and applies signtool in batch mode.
# Particularly useful after windeployqt: a Qt project ships with ~10 DLLs that
# all need signing, and doing them one-by-one with qt_signature is tedious.


def _ssb_find_signtool(signtool_path: str = "") -> Path | None:
    """Locate signtool.exe — same logic as qt_signature, but returns Path or None."""
    if signtool_path:
        p = Path(signtool_path)
        if p.exists():
            return p
    candidates: list[Path] = []
    pf = os.environ.get("ProgramFiles", r"C:\Program Files")
    pf86 = os.environ.get("ProgramFiles(x86)", r"C:\Program Files (x86)")
    kits_root = Path(pf) / "Windows Kits"
    if not kits_root.exists():
        kits_root = Path(pf86) / "Windows Kits"
    if kits_root.exists():
        for ver_dir in sorted(kits_root.glob("10/bin/*"), reverse=True):
            candidate = ver_dir / "x64" / "signtool.exe"
            if candidate.exists():
                candidates.append(candidate)
    return candidates[0] if candidates else None


@mcp.tool(name="qt_signature_batch", annotations={"title": "Batch sign / verify / scan a directory of .exe/.dll files with signtool", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_signature_batch(params: QtSignatureBatchInput) -> str:
    """Batch-process signtool over all matching files in a directory.

    The companion to ``qt_signature`` (single-file). Use this when you have
    a deployment directory full of .exe + .dll (e.g. after windeployqt) and
    want to sign / verify / timestamp them all at once. Supports continue-on-error
    so one bad signature doesn't block the rest.

    Actions:
      - ``info``  : locate signtool.exe + report version + cert store status
      - ``scan``  : list matching files (read-only — never invokes signtool)
      - ``sign``  : apply Authenticode signature to every matching file
      - ``verify``: verify each file's signature
      - ``timestamp``: add RFC 3161 timestamp to each already-signed file

    Args:
        params.action: 'info' | 'scan' | 'sign' | 'verify' | 'timestamp'
        params.directory: absolute path of directory containing .exe/.dll
        params.patterns: glob patterns to match (default ['*.exe', '*.dll'])
        params.recursive: if True, also scan subdirectories
        params.certificate_path: .pfx/.p12 file (for 'sign')
        params.certificate_thumbprint: installed-cert thumbprint (alt to cert path)
        params.timestamp_url: RFC 3161 URL (default Digicert)
        params.description: signature description (for 'sign')
        params.signtool_path: explicit signtool.exe path; empty = auto-find
        params.continue_on_error: if True (default), skip files that fail and continue
        params.dry_run: if True, list what would be signed without invoking signtool

    Returns:
        str: formatted text report. Starts with 'Error: ' on bad input.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    valid_actions = ("info", "scan", "sign", "verify", "timestamp")
    if params.action not in valid_actions:
        msg = f"Error: invalid action {params.action!r}. Must be one of {valid_actions}."
        return msg + _json_footer({"ok": False, "error": msg})

    directory = Path(params.directory)
    if not directory.exists() or not directory.is_dir():
        msg = f"Error: directory not found: {directory}"
        return msg + _json_footer({"ok": False, "error": msg})

    # V0.4.2: validate error_strategy early (so 'scan' / 'info' also surface bad-args immediately).
    strategy = params.error_strategy or ""
    if strategy.startswith("continue_n:"):
        try:
            int(strategy.split(":", 1)[1])
        except (ValueError, IndexError):
            msg = f"Error: error_strategy 'continue_n:<N>' requires integer N."
            return msg + _json_footer({"ok": False, "error": msg})

    # Scan / collect files
    files: list[Path] = []
    for pat in params.patterns:
        if params.recursive:
            files.extend(sorted(directory.rglob(pat)))
        else:
            files.extend(sorted(directory.glob(pat)))
    # Dedup while preserving order
    seen: set[Path] = set()
    unique_files: list[Path] = []
    for f in files:
        if f not in seen:
            seen.add(f)
            unique_files.append(f)
    files = unique_files

    if params.action == "info":
        signtool = _ssb_find_signtool(params.signtool_path)
        if not signtool:
            msg = (f"Error: signtool.exe not found. Install the Windows 10 SDK or pass signtool_path.")
            return msg + _json_footer({"ok": False, "error": msg})
        r = await _run([str(signtool), "/?"], cwd=signtool.parent, timeout=15)
        ver_lines = (r.stdout or r.stderr).splitlines()[:5]
        return "\n".join([
            f"=== qt_signature_batch: info ===",
            f"signtool: {signtool}",
            f"version:  {ver_lines[0] if ver_lines else 'unknown'}",
            f"matched files in {directory}: {len(files)} ({len([f for f in files if f.suffix.lower() == '.exe'])} .exe + {len([f for f in files if f.suffix.lower() == '.dll'])} .dll)",
        ]) + _json_footer({"ok": True, "data": {"signtool": str(signtool), "file_count": len(files)}})

    if params.action == "scan":
        lines = [f"=== qt_signature_batch: scan {directory} ==="]
        if not files:
            lines.append("  (no files matched)")
        for f in files:
            try:
                size = f.stat().st_size
                lines.append(f"  {f.name}  ({size:,} bytes)")
            except OSError as e:
                lines.append(f"  {f.name}  (error: {e})")
        lines.append(f"\nTotal: {len(files)} file(s)")
        # Write CSV report if requested (V0.4.2 supports CSV from scan/info)
        csv_path = None
        if params.csv_report:
            csv_path = Path(params.csv_report)
            if _in_sandbox(csv_path):
                csv_path.parent.mkdir(parents=True, exist_ok=True)
                rows = ["file,status"] + [f'"{f.name}","scanned"' for f in files]
                csv_path.write_text("\n".join(rows), encoding="utf-8")
                lines.append(f"csv_report: {csv_path}")
        return "\n".join(lines) + _json_footer({
            "ok": True,
            "data": {
                "files": [str(f) for f in files],
                "count": len(files),
                "csv_report": str(csv_path) if csv_path else "",
            },
        })

    # For sign / verify / timestamp we need signtool
    if not params.certificate_path and not params.certificate_thumbprint and params.action == "sign":
        msg = "Error: 'sign' action requires either certificate_path or certificate_thumbprint"
        return msg + _json_footer({"ok": False, "error": msg})

    signtool = _ssb_find_signtool(params.signtool_path)
    if not signtool:
        msg = (f"Error: signtool.exe not found. Install the Windows 10 SDK or pass signtool_path.")
        return msg + _json_footer({"ok": False, "error": msg})

    if not files:
        msg = f"Error: no files matched patterns {params.patterns} in {directory}"
        return msg + _json_footer({"ok": False, "error": msg})

    if params.dry_run:
        lines = [f"=== qt_signature_batch: DRY-RUN {params.action} ===",
                 f"directory: {directory}", f"patterns:   {params.patterns}",
                 f"signtool:  {signtool}", f"matched:   {len(files)} files", ""]
        for f in files:
            lines.append(f"  WOULD {params.action}: {f.name}")
        return "\n".join(lines) + _json_footer({"ok": True, "data": {"dry_run": True, "files": [str(f) for f in files]}})

    # Real batch operation
    lines = [f"=== qt_signature_batch: {params.action} ===", f"directory: {directory}",
             f"signtool:  {signtool}", f"file count: {len(files)}", ""]

    # V0.4.2: resolve effective strategy (error_strategy overrides continue_on_error)
    strategy = params.error_strategy
    max_fails: int | None = None
    fail_fast = False
    if strategy == "continue_all":
        fail_fast = False  # continue past all errors
    elif strategy == "fail_fast":
        fail_fast = True
    elif strategy.startswith("continue_n:"):
        # continue_n:5 → stop after 5 failures
        try:
            max_fails = int(strategy.split(":", 1)[1])
        except (ValueError, IndexError):
            return "Error: error_strategy 'continue_n:<N>' requires integer N." + _json_footer({"ok": False})
    else:
        # Backward compat — fall back to continue_on_error bool
        fail_fast = not params.continue_on_error
    lines.append(f"strategy: {strategy if strategy != 'continue_all' or params.continue_on_error != True else 'continue_all (legacy continue_on_error=True)'}")
    if max_fails is not None:
        lines.append(f"max_fails: {max_fails}")

    succeeded: list[str] = []
    failed: list[tuple[str, str]] = []
    csv_rows: list[str] = ["file,status,exit_code,duration_ms,error"]
    abort_reason = None

    for f in files:
        if params.action == "sign":
            cmd = [str(signtool), "sign"]
            if params.timestamp_url:
                cmd += ["/tr", params.timestamp_url, "/td", "sha256"]
            if params.certificate_path:
                cmd += ["/f", params.certificate_path]
                if params.description:
                    cmd += ["/d", params.description]
            elif params.certificate_thumbprint:
                cmd += ["/sha1", params.certificate_thumbprint]
                if params.description:
                    cmd += ["/d", params.description]
            cmd.append(str(f))
        elif params.action == "verify":
            cmd = [str(signtool), "verify", "/pa", str(f)]
        else:  # timestamp
            cmd = [str(signtool), "timestamp", "/tr", params.timestamp_url, str(f)]
        t_start = time.monotonic()
        try:
            r = await _run(cmd, cwd=f.parent, timeout=60)
            duration_ms = int((time.monotonic() - t_start) * 1000)
            csv_err_field = "" if r.ok else _csv_escape(_tail(r.stdout or r.stderr, 3))
            csv_rows.append(f'"{f.name}","{"ok" if r.ok else "fail"}",{r.exit_code},{duration_ms},{csv_err_field}')
            if r.ok:
                succeeded.append(f.name)
                lines.append(f"  [OK] {f.name}  ({duration_ms}ms)")
            else:
                err_tail = _tail(r.stdout or r.stderr, 5)
                failed.append((f.name, err_tail))
                lines.append(f"  [FAIL] {f.name} — {err_tail[:120]}")
                if max_fails is not None and len(failed) >= max_fails:
                    abort_reason = f"max_fails {max_fails} reached"
                    break
                if fail_fast:
                    abort_reason = "fail_fast (stop on first error)"
                    break
        except Exception as e:
            duration_ms = int((time.monotonic() - t_start) * 1000)
            failed.append((f.name, str(e)))
            lines.append(f"  [ERROR] {f.name} — {e}")
            csv_rows.append(f'"{f.name}","error",-1,{duration_ms},"{_csv_escape(str(e))}"')
            if max_fails is not None and len(failed) >= max_fails:
                abort_reason = f"max_fails {max_fails} reached"
                break
            if fail_fast:
                abort_reason = "fail_fast (stop on first error)"
                break

    if abort_reason:
        lines.append(f"\nAborted: {abort_reason}")

    lines.append("")
    lines.append(f"Summary: {len(succeeded)} OK, {len(failed)} FAIL of {len(files)} total")

    csv_path = None
    if params.csv_report:
        csv_path = Path(params.csv_report)
        if _in_sandbox(csv_path):
            csv_path.parent.mkdir(parents=True, exist_ok=True)
            # For 'scan' / 'info' actions without per-file results, build a
            # minimal CSV listing every matched file. For per-file actions
            # use the rows that the for-loop already appended.
            if len(csv_rows) <= 1:
                rows = ["file,status"] + [f'"{f.name}","{"scanned" if params.action in ("scan", "info") else "enqueued"}"' for f in files]
                csv_path.write_text("\n".join(rows), encoding="utf-8")
            else:
                csv_path.write_text("\n".join(csv_rows), encoding="utf-8")
            lines.append(f"csv_report: {csv_path}")
        else:
            lines.append(f"csv_report skipped (outside sandbox): {csv_path}")

    ok = len(failed) == 0
    return "\n".join(lines) + _json_footer({
        "ok": ok,
        "data": {
            "action": params.action,
            "directory": str(directory),
            "succeeded": succeeded,
            "failed": [{"file": n, "error": e} for n, e in failed],
            "total": len(files),
            "strategy": strategy,
            "csv_report": str(csv_path) if csv_path else "",
            "aborted_reason": abort_reason,
        },
    })


def _csv_escape(s: str) -> str:
    return '"' + s.replace('"', '""').replace("\n", " ")[:200] + '"'

@mcp.tool(name="qt_save", annotations={"title": "Save / load / list portable JSON game-state files", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_save(params: QtSaveInput) -> str:
    """Save, load, list, delete, or inspect JSON save files for a board game.

    Different from `qt_state` (which uses QSettings / OS-native format):
    qt_save stores data as .json files — portable, human-readable, easy to sync
    across machines, easy to inspect with `cat save.json | jq`.

    Args:
        params.action: 'save' | 'load' | 'delete' | 'list' | 'inspect'
        params.save_dir: directory of save files (default: <SANDBOX>/.saves/)
        params.name: save file name (without .json), required for save/load/delete/inspect
        params.data: dict for save (any JSON-serializable values)
        params.pretty: indent JSON (default True)
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("save", "load", "delete", "list", "inspect"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    save_dir = Path(params.save_dir) if params.save_dir else SANDBOX_ROOT / ".saves"
    if not save_dir.is_absolute():
        save_dir = (SANDBOX_ROOT / save_dir).resolve()

    sandbox_err = _require_sandbox(save_dir, "save_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    if params.action == "list":
        save_dir.mkdir(parents=True, exist_ok=True)
        saves = sorted(save_dir.glob("*.json"))
        if not saves:
            out = f"=== qt_save: no saves in {save_dir} ==="
            return out + _json_footer({"ok": True, "data": {"saves": [], "count": 0}})
        lines = [f"=== qt_save: {len(saves)} save(s) in {save_dir} ==="]
        for s in saves:
            try:
                size = s.stat().st_size
                mtime = s.stat().st_mtime
                # Get top-level keys
                import json as _json
                with s.open(encoding="utf-8") as f:
                    obj = _json.load(f)
                keys = list(obj.keys()) if isinstance(obj, dict) else ["(not a dict)"]
                lines.append(f"  {s.name}  ({size} bytes, mtime={mtime:.0f}, {len(keys)} keys: {keys[:5]})")
            except (OSError, ValueError) as e:
                lines.append(f"  {s.name}  (error: {e})")
        out = "\n".join(lines)
        return out + _json_footer({"ok": True, "data": {"count": len(saves)}})

    if not params.name:
        msg = f"Error: action {params.action!r} requires a non-empty name"
        return msg + _json_footer({"ok": False, "error": msg})

    safe_name = re.sub(r"[^A-Za-z0-9_\-]", "_", params.name)
    if not safe_name:
        msg = f"Error: name {params.name!r} is invalid (no alphanumeric chars)"
        return msg + _json_footer({"ok": False, "error": msg})
    save_path = save_dir / f"{safe_name}.json"

    if params.action == "save":
        import json as _json
        save_dir.mkdir(parents=True, exist_ok=True)
        with save_path.open("w", encoding="utf-8") as f:
            if params.pretty:
                _json.dump(params.data, f, indent=2, ensure_ascii=False)
            else:
                _json.dump(params.data, f, ensure_ascii=False)
        size = save_path.stat().st_size
        out = f"saved: {save_path}\n  size: {size} bytes\n  keys: {list(params.data.keys()) if isinstance(params.data, dict) else '(not a dict)'}"
        return out + _json_footer({"ok": True, "data": {"path": str(save_path), "size": size}})

    if params.action == "load":
        if not save_path.exists():
            out = f"no save: {save_path} does not exist"
            return out + _json_footer({"ok": True, "data": {"data": None, "exists": False}})
        import json as _json
        with save_path.open(encoding="utf-8") as f:
            data = _json.load(f)
        out = "\n".join([f"{k} = {v!r}" for k, v in data.items()]) if isinstance(data, dict) else _json.dumps(data, indent=2)
        return out + _json_footer({"ok": True, "data": {"data": data, "exists": True, "path": str(save_path)}})

    if params.action == "delete":
        if not save_path.exists():
            out = f"nothing to delete: {save_path} does not exist"
            return out + _json_footer({"ok": True, "data": {"deleted": False}})
        save_path.unlink()
        out = f"deleted: {save_path}"
        return out + _json_footer({"ok": True, "data": {"deleted": True}})

    if params.action == "inspect":
        if not save_path.exists():
            msg = f"Error: save file not found: {save_path}"
            return msg + _json_footer({"ok": False, "error": msg})
        import json as _json
        with save_path.open(encoding="utf-8") as f:
            data = _json.load(f)
        # Pretty-print with type info
        def _describe(obj, depth=0) -> list[str]:
            indent = "  " * depth
            lines = []
            if isinstance(obj, dict):
                for k, v in obj.items():
                    if isinstance(v, dict):
                        lines.append(f"{indent}{k}: ({len(v)} keys)")
                        lines.extend(_describe(v, depth + 1))
                    elif isinstance(v, list):
                        lines.append(f"{indent}{k}: [list of {len(v)}]")
                    else:
                        lines.append(f"{indent}{k}: {type(v).__name__} = {v!r}")
            return lines
        out_lines = [f"--- {save_path} ---"]
        out_lines.extend(_describe(data) if isinstance(data, dict) else [f"({type(data).__name__})"])
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"path": str(save_path), "type": type(data).__name__}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_audio: sound effect wrapper -------------------------------------------

@mcp.tool(name="qt_audio", annotations={"title": "List / probe / play sound effect files", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_audio(params: QtAudioInput) -> str:
    """Audio file operations for board games.

    Actions:
      - 'info'  : check whether QtMultimedia is available in this Qt install
      - 'list'  : scan a directory for audio files (.wav, .mp3, .ogg, etc.)
      - 'probe' : read audio file metadata (size, format, basic info from header)
      - 'play'  : validate the file path and return what command to run (the actual
                  playback requires the Qt app to use QSoundEffect; this tool gives
                  you a self-contained C++ snippet to drop in your game)

    Args:
        params.action: 'info' | 'list' | 'probe' | 'play'
        params.audio_dir: directory to scan (for 'list')
        params.file_path: single file (for 'probe' / 'play')
        params.extensions: file suffixes to recognize as audio
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("info", "list", "probe", "play"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    if params.action == "info":
        # Check QtMultimedia headers + libs
        mm_inc = QT_ROOT / "include" / "QtMultimedia"
        mm_lib = QT_ROOT / "lib" / "Qt5Multimedia.lib"
        if not mm_inc.exists() or not mm_lib.exists():
            return (
                f"=== qt_audio: QtMultimedia NOT available ===\n"
                f"Qt install at {QT_ROOT} does not have QtMultimedia (no {mm_inc}).\n"
                f"Install via Qt Maintenance Tool or use a different audio backend."
            ) + _json_footer({"ok": False, "error": "QtMultimedia not installed", "data": {"available": False}})
        return (
            f"=== qt_audio: QtMultimedia available ===\n"
            f"headers:  {mm_inc}\n"
            f"lib:      {mm_lib}\n"
            f"QSoundEffect, QMediaPlayer, QAudioOutput all in scope if QT += multimedia is set."
        ) + _json_footer({"ok": True, "data": {"available": True}})

    if params.action == "list":
        audio_dir = Path(params.audio_dir)
        if not audio_dir.is_absolute():
            audio_dir = (SANDBOX_ROOT / audio_dir).resolve()
        sandbox_err = _require_sandbox(audio_dir, "audio_dir")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        if not audio_dir.exists() or not audio_dir.is_dir():
            msg = f"Error: audio_dir is not a directory: {audio_dir}"
            return msg + _json_footer({"ok": False, "error": msg})
        exts = {e.lower() if e.startswith(".") else "." + e.lower() for e in params.extensions}
        files = sorted(p for p in audio_dir.rglob("*") if p.is_file() and p.suffix.lower() in exts)
        if not files:
            out = f"=== qt_audio: no audio files in {audio_dir} ==="
            return out + _json_footer({"ok": True, "data": {"files": [], "count": 0}})
        lines = [f"=== qt_audio: {len(files)} file(s) in {audio_dir} ==="]
        for p in files:
            size = p.stat().st_size
            lines.append(f"  {p.relative_to(audio_dir)}  ({size:,} bytes)")
        out = "\n".join(lines)
        return out + _json_footer({"ok": True, "data": {"count": len(files), "files": [str(p) for p in files]}})

    if params.action == "probe":
        file_path = Path(params.file_path)
        if not file_path.is_absolute():
            file_path = (SANDBOX_ROOT / file_path).resolve()
        if not file_path.exists():
            msg = f"Error: file not found: {file_path}"
            return msg + _json_footer({"ok": False, "error": msg})
        size = file_path.stat().st_size
        # Read first 16 bytes to identify format
        with file_path.open("rb") as f:
            head = f.read(16)
        fmt = "unknown"
        if head.startswith(b"RIFF") and b"WAVE" in head[:12]:
            fmt = "WAV (RIFF/WAVE)"
        elif head.startswith(b"ID3") or (head[0:2] == b"\xff\xfb"):
            fmt = "MP3"
        elif head.startswith(b"OggS"):
            fmt = "OGG Vorbis"
        elif head.startswith(b"fLaC"):
            fmt = "FLAC"
        elif head.startswith(b"\x1f\x8b"):
            fmt = "MP3 (ID3v1)"
        out = (
            f"=== qt_audio: probe {file_path} ===\n"
            f"size:     {size:,} bytes\n"
            f"format:   {fmt}\n"
            f"suffix:   {file_path.suffix}\n"
            f"first 16 bytes (hex): {head.hex()}"
        )
        return out + _json_footer({"ok": True, "data": {"size": size, "format": fmt, "suffix": file_path.suffix}})

    if params.action == "play":
        file_path = Path(params.file_path)
        if not file_path.is_absolute():
            file_path = (SANDBOX_ROOT / file_path).resolve()
        if not file_path.exists():
            msg = f"Error: file not found: {file_path}"
            return msg + _json_footer({"ok": False, "error": msg})
        # Emit a C++ snippet the user can drop in their game
        cpp = (
            f"// Drop this into your game to play {file_path.name}:\n"
            f"#include <QSoundEffect>\n"
            f"#include <QUrl>\n"
            f"\n"
            f"QSoundEffect *effect = new QSoundEffect(this);\n"
            f"effect->setSource(QUrl::fromLocalFile(R\"({file_path})\"));\n"
            f"effect->setVolume(0.8f);\n"
            f"effect->play();\n"
            f"\n"
            f"// Or via QMediaPlayer (for streaming / pitch control):\n"
            f"// QMediaPlayer *player = new QMediaPlayer(this);\n"
            f"// player->setMedia(QUrl::fromLocalFile(R\"({file_path})\"));\n"
            f"// player->setVolume(80);\n"
            f"// player->play();\n"
        )
        out = (
            f"=== qt_audio: play snippet for {file_path} ===\n"
            f"Note: this tool can't actually play audio in the MCP context.\n"
            f"Use the snippet below in your game's C++ code.\n"
            f"\n{cpp}"
        )
        return out + _json_footer({"ok": True, "data": {"snippet_lines": cpp.count(chr(10))}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_anim: QPropertyAnimation code generator ------------------------------

@mcp.tool(name="qt_anim", annotations={"title": "Generate QPropertyAnimation C++ code (fade / move / scale / rotate / color / sequence)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})


def _anim_double_buffer_snippet() -> str:
    """JB51 Ch 18: QPixmap double-buffer paintEvent snippet for flicker-free drawing."""
    return r"""// Add to your widget header:
//   QPixmap m_pixmap;
//   void mouseMoveEvent(QMouseEvent *e) override;
//   void paintEvent(QPaintEvent *e) override;

// In constructor: setMouseTracking(true); resize(600, 400); m_pixmap = QPixmap(size());

void YourWidget::mouseMoveEvent(QMouseEvent *e) {
    if (e->buttons() & Qt::LeftButton) {
        QPainter pp(&m_pixmap);
        pp.drawLine(e->pos(), e->pos());
        update();  // triggers paintEvent
    }
}

void YourWidget::paintEvent(QPaintEvent *) {
    QPainter p(this);
    p.drawPixmap(0, 0, m_pixmap);  // blit cached pixmap
}

// Why: direct paintEvent causes flicker on resize. Double-buffer (off-screen QPixmap)
// gives smooth drawing; on resize just resize the pixmap, no redraw of all paths.
"""


def _anim_painter_path_snippet() -> str:
    """JB51 Ch 14: QPainterPath drawing snippet (curves, polygons, arcs)."""
    return r"""// Add to your widget:
void YourWidget::paintEvent(QPaintEvent *) {
    QPainter p(this);
    p.setRenderHint(QPainter::Antialiasing);

    // Build a path: moveTo + lineTo/curveTo/arcTo
    QPainterPath path;
    path.moveTo(50, 200);
    path.lineTo(150, 50);
    path.quadTo(250, 50, 250, 200);  // quadratic Bezier
    path.cubicTo(350, 350, 450, 100, 550, 200);  // cubic Bezier
    path.addEllipse(QPoint(300, 200), 100, 50);  // circle inside path

    p.setPen(QPen(Qt::darkBlue, 3));
    p.setBrush(Qt::yellow);
    p.drawPath(path);
}

// QPainterPath supports: moveTo, lineTo, quadTo, cubicTo, arcTo, addRect,
// addEllipse, addPolygon, addText, addRegion. Set fillRule (Qt::OddEvenFill /
// Qt::WindingFill) to control how self-intersecting paths fill.
"""


def _anim_doodle_board_snippet() -> str:
    """JB51 Ch 17: freehand doodle board (mouseMoveEvent accumulates QPainterPath)."""
    return r"""// Add to your widget header:
//   QPainterPath m_path;
//   bool m_drawing;
//   void mousePressEvent(QMouseEvent *e) override;
//   void mouseMoveEvent(QMouseEvent *e) override;
//   void mouseReleaseEvent(QMouseEvent *e) override;
//   void paintEvent(QPaintEvent *e) override;

void YourWidget::mousePressEvent(QMouseEvent *e) {
    if (e->button() == Qt::LeftButton) {
        m_drawing = true;
        m_path.moveTo(e->pos());
    }
}

void YourWidget::mouseMoveEvent(QMouseEvent *e) {
    if (m_drawing && (e->buttons() & Qt::LeftButton)) {
        m_path.lineTo(e->pos());
        update();
    }
}

void YourWidget::mouseReleaseEvent(QMouseEvent *e) {
    if (e->button() == Qt::LeftButton) m_drawing = false;
}

void YourWidget::paintEvent(QPaintEvent *) {
    QPainter p(this);
    p.setRenderHint(QPainter::Antialiasing);
    p.setPen(QPen(Qt::black, 2));
    p.drawPath(m_path);
}
"""


async def qt_anim(params: QtAnimInput) -> str:
    """Generate a ready-to-paste C++ snippet using QPropertyAnimation.

    Returns a code block for the requested animation type. Use this in your
    MainWindow constructor or any QWidget method. Each snippet assumes
    `#include <QPropertyAnimation>` and `#include <QEasingCurve>` are present.

    Args:
        params.animation_type: 'fade' | 'move' | 'scale' | 'rotate' | 'color' | 'sequence'
        params.target_widget: object to animate (default 'this')
        params.duration_ms: animation duration
        params.start_value: starting value (empty = current)
        params.end_value: ending value
        params.loop: loop indefinitely
        params.easing_curve: QEasingCurve name (default 'OutCubic')
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.animation_type in ("double_buffer", "painter_path", "doodle_board"):
        snippet_map = {
            "double_buffer": _anim_double_buffer_snippet,
            "painter_path": _anim_painter_path_snippet,
            "doodle_board": _anim_doodle_board_snippet,
        }
        out_text = "=== qt_anim: " + params.animation_type + " (JB51 Ch 14/17/18) ===\n" + snippet_map[params.animation_type]()
        return out_text + _json_footer({"ok": True, "data": {"type": params.animation_type}})

    if params.animation_type not in ("fade", "move", "scale", "rotate", "color", "sequence"):
        msg = f"Error: invalid animation_type {params.animation_type!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    prop_map = {
        "fade":   ('"opacity"', "qreal", "0.0", "1.0"),
        "move":   ('"geometry"', "QRect", "QRect()", "QRect()"),
        "scale":  ('"size"', "QSize", "QSize()", "QSize()"),
        "rotate": ('"rotation"', "qreal", "0.0", "360.0"),
        "color":  ('"color"', "QColor", "QColor()", "QColor()"),
    }
    if params.animation_type in prop_map:
        prop, _typ, default_start, default_end = prop_map[params.animation_type]
        start = params.start_value or default_start
        end = params.end_value
    else:
        # sequence: caller provides a list-like body
        start = params.start_value
        end = params.end_value
        prop = "geometry"

    loop_line = "anim->setLoopCount(-1);" if params.loop else ""

    if params.animation_type == "sequence":
        cpp = (
            f"// Sequential animation (QSequentialAnimationGroup):\n"
            f"#include <QSequentialAnimationGroup>\n"
            f"#include <QPropertyAnimation>\n"
            f"\n"
            f"QSequentialAnimationGroup *seq = new QSequentialAnimationGroup({params.target_widget});\n"
            f"// Add 2+ QPropertyAnimation children via seq->addAnimation(anim)\n"
            f"// Each child anim runs after the previous finishes.\n"
            f"seq->start();\n"
        )
    else:
        cpp = (
            f"// QPropertyAnimation: {params.animation_type} {params.target_widget}\n"
            f"#include <QPropertyAnimation>\n"
            f"#include <QEasingCurve>\n"
            f"\n"
            f"QPropertyAnimation *anim = new QPropertyAnimation({params.target_widget}, {prop});\n"
            f"anim->setDuration({params.duration_ms});\n"
            f"anim->setStartValue({start});\n"
            f"anim->setEndValue({end});\n"
            f"anim->setEasingCurve(QEasingCurve::{params.easing_curve});\n"
            + (f"{loop_line}\n" if loop_line else "")
            + f"anim->start(QAbstractAnimation::DeleteWhenStopped);\n"
        )

    out = (
        f"=== qt_anim: {params.animation_type} on {params.target_widget} ===\n"
        f"property:      {prop}\n"
        f"duration:      {params.duration_ms}ms\n"
        f"start:         {start}\n"
        f"end:           {end}\n"
        f"easing:        {params.easing_curve}\n"
        f"loop:          {params.loop}\n"
        f"\n{cpp}"
    )
    return out + _json_footer({"ok": True, "data": {"property": prop, "snippet": cpp}})


# --- qt_network: TCP/UDP skeleton generator ----------------------------------

@mcp.tool(name="qt_network", annotations={"title": "Generate a QTcpSocket / QTcpServer / QUdpSocket C++ class skeleton", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_network(params: QtNetworkInput) -> str:
    """Generate a .h / .cpp pair for a Qt network class.

    Use cases: board-game multiplayer (TCP server hosts a lobby, clients connect),
    LAN discovery (UDP broadcast), or browser play (QWebSocket).

    Args:
        params.skeleton_type: 'tcp_client' | 'tcp_server' | 'udp_peer' | 'websocket_client'
        params.class_name: name of the generated C++ class
        params.host: default host (default 127.0.0.1)
        params.port: default port (default 7777)
        params.output_dir: where to write the .h / .cpp pair
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.skeleton_type not in ("tcp_client", "tcp_server", "udp_peer", "websocket_client"):
        msg = f"Error: invalid skeleton_type {params.skeleton_type!r}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not re.match(r"^[A-Z][A-Za-z0-9_]*$", params.class_name):
        msg = f"Error: class_name {params.class_name!r} is not a valid C++ class name"
        return msg + _json_footer({"ok": False, "error": msg})

    out_dir = Path(params.output_dir)
    if not out_dir.is_absolute():
        out_dir = (SANDBOX_ROOT / out_dir).resolve()
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not out_dir.exists():
        out_dir.mkdir(parents=True, exist_ok=True)

    cn = params.class_name
    h_path = out_dir / f"{cn.lower()}.h"
    cpp_path = out_dir / f"{cn.lower()}.cpp"

    if params.skeleton_type == "tcp_client":
        header = f"""#ifndef {cn.upper()}_H
#define {cn.upper()}_H

#include <QObject>
#include <QTcpSocket>
#include <QAbstractSocket>

class {cn} : public QObject {{
    Q_OBJECT
public:
    explicit {cn}(QObject *parent = nullptr);
    void connectTo(const QString &host = "{params.host}", quint16 port = {params.port});
    void sendMessage(const QByteArray &data);
signals:
    void connected();
    void disconnected();
    void messageReceived(const QByteArray &data);
    void errorOccurred(const QString &err);
private slots:
    void onReadyRead();
    void onConnected();
    void onDisconnected();
    void onError(QAbstractSocket::SocketError err);
private:
    QTcpSocket *m_socket;
}};

#endif
"""
        impl = f"""#include "{cn.lower()}.h"

{cn}::{cn}(QObject *parent) : QObject(parent), m_socket(new QTcpSocket(this)) {{
    connect(m_socket, &QTcpSocket::readyRead, this, &{cn}::onReadyRead);
    connect(m_socket, &QTcpSocket::connected, this, &{cn}::onConnected);
    connect(m_socket, &QTcpSocket::disconnected, this, &{cn}::onDisconnected);
    connect(m_socket, &QAbstractSocket::errorOccurred, this, &{cn}::onError);
}}

void {cn}::connectTo(const QString &host, quint16 port) {{
    m_socket->connectToHost(host, port);
}}

void {cn}::sendMessage(const QByteArray &data) {{
    if (m_socket->state() == QAbstractSocket::ConnectedState)
        m_socket->write(data);
}}

void {cn}::onReadyRead() {{
    emit messageReceived(m_socket->readAll());
}}

void {cn}::onConnected() {{ emit connected(); }}
void {cn}::onDisconnected() {{ emit disconnected(); }}
void {cn}::onError(QAbstractSocket::SocketError err) {{
    emit errorOccurred(m_socket->errorString());
}}
"""
    elif params.skeleton_type == "tcp_server":
        header = f"""#ifndef {cn.upper()}_H
#define {cn.upper()}_H

#include <QObject>
#include <QTcpServer>
#include <QTcpSocket>

class {cn} : public QObject {{
    Q_OBJECT
public:
    explicit {cn}(QObject *parent = nullptr);
    bool start(quint16 port = {params.port});
    void stop();
signals:
    void clientConnected(QTcpSocket *client);
    void clientDisconnected(QTcpSocket *client);
    void messageReceived(QTcpSocket *client, const QByteArray &data);
private slots:
    void onNewConnection();
    void onClientReadyRead();
    void onClientDisconnected();
private:
    QTcpServer *m_server;
    QList<QTcpSocket*> m_clients;
}};

#endif
"""
        impl = f"""#include "{cn.lower()}.h"

{cn}::{cn}(QObject *parent) : QObject(parent), m_server(new QTcpServer(this)) {{
    connect(m_server, &QTcpServer::newConnection, this, &{cn}::onNewConnection);
}}

bool {cn}::start(quint16 port) {{
    return m_server->listen(QHostAddress::Any, port);
}}

void {cn}::stop() {{
    m_server->close();
    for (auto *c : m_clients) c->disconnect();
    m_clients.clear();
}}

void {cn}::onNewConnection() {{
    while (auto *client = m_server->nextPendingConnection()) {{
        m_clients.append(client);
        connect(client, &QTcpSocket::readyRead, this, &{cn}::onClientReadyRead);
        connect(client, &QTcpSocket::disconnected, this, &{cn}::onClientDisconnected);
        emit clientConnected(client);
    }}
}}

void {cn}::onClientReadyRead() {{
    auto *c = qobject_cast<QTcpSocket*>(sender());
    if (c) emit messageReceived(c, c->readAll());
}}

void {cn}::onClientDisconnected() {{
    auto *c = qobject_cast<QTcpSocket*>(sender());
    if (c) {{
        m_clients.removeAll(c);
        emit clientDisconnected(c);
        c->deleteLater();
    }}
}}
"""
    elif params.skeleton_type == "udp_peer":
        header = f"""#ifndef {cn.upper()}_H
#define {cn.upper()}_H

#include <QObject>
#include <QUdpSocket>
#include <QHostAddress>

class {cn} : public QObject {{
    Q_OBJECT
public:
    explicit {cn}(QObject *parent = nullptr);
    bool bind(quint16 port = {params.port});
    void sendTo(const QByteArray &data, const QHostAddress &host, quint16 port);
signals:
    void datagramReceived(const QByteArray &data, const QHostAddress &from, quint16 port);
private slots:
    void onReadyRead();
private:
    QUdpSocket *m_socket;
}};

#endif
"""
        impl = f"""#include "{cn.lower()}.h"

{cn}::{cn}(QObject *parent) : QObject(parent), m_socket(new QUdpSocket(this)) {{
    connect(m_socket, &QUdpSocket::readyRead, this, &{cn}::onReadyRead);
}}

bool {cn}::bind(quint16 port) {{ return m_socket->bind(port); }}

void {cn}::sendTo(const QByteArray &data, const QHostAddress &host, quint16 port) {{
    m_socket->writeDatagram(data, host, port);
}}

void {cn}::onReadyRead() {{
    while (m_socket->hasPendingDatagrams()) {{
        QByteArray data;
        data.resize(int(m_socket->pendingDatagramSize()));
        QHostAddress from;
        quint16 port;
        m_socket->readDatagram(data.data(), data.size(), &from, &port);
        emit datagramReceived(data, from, port);
    }}
}}
"""
    else:  # websocket_client
        header = f"""#ifndef {cn.upper()}_H
#define {cn.upper()}_H

#include <QObject>
#include <QWebSocket>

class {cn} : public QObject {{
    Q_OBJECT
public:
    explicit {cn}(QObject *parent = nullptr);
    void open(const QUrl &url);
    void send(const QString &message);
signals:
    void connected();
    void disconnected();
    void textMessageReceived(const QString &message);
    void errorOccurred(const QString &err);
private slots:
    void onConnected();
    void onDisconnected();
    void onTextMessageReceived(const QString &msg);
    void onError(QAbstractSocket::SocketError err);
private:
    QWebSocket m_socket;
}};

#endif
"""
        impl = f"""#include "{cn.lower()}.h"

{cn}::{cn}(QObject *parent) : QObject(parent) {{
    connect(&m_socket, &QWebSocket::connected, this, &{cn}::onConnected);
    connect(&m_socket, &QWebSocket::disconnected, this, &{cn}::onDisconnected);
    connect(&m_socket, &QWebSocket::textMessageReceived, this, &{cn}::onTextMessageReceived);
    connect(&m_socket, &QWebSocket::errorOccurred, this, &{cn}::onError);
}}

void {cn}::open(const QUrl &url) {{ m_socket.open(url); }}
void {cn}::send(const QString &message) {{ m_socket.sendTextMessage(message); }}

void {cn}::onConnected() {{ emit connected(); }}
void {cn}::onDisconnected() {{ emit disconnected(); }}
void {cn}::onTextMessageReceived(const QString &msg) {{ emit textMessageReceived(msg); }}
void {cn}::onError(QAbstractSocket::SocketError) {{ emit errorOccurred(m_socket.errorString()); }}
"""

    h_path.write_text(header, encoding="utf-8")
    cpp_path.write_text(impl, encoding="utf-8")

    out = (
        f"=== qt_network: {params.skeleton_type} -> {cn} ===\n"
        f"header:    {h_path}\n"
        f"impl:      {cpp_path}\n"
        f"host:      {params.host}\n"
        f"port:      {params.port}\n"
        f"\n"
        f"Add to your .pro: QT += network {'websockets' if params.skeleton_type == 'websocket_client' else ''}\n"
        f"Add the files to HEADERS / SOURCES in your .pro.\n"
    )
    return out + _json_footer({"ok": True, "data": {"header": str(h_path), "impl": str(cpp_path)}})


# --- qt_coverage: code coverage via gcov + lcov ------------------------------

@mcp.tool(name="qt_coverage", annotations={"title": "Run gcov + lcov to collect C++ code coverage on a Qt project", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_coverage(params: QtCoverageInput) -> str:
    """Collect code coverage for a Qt project using gcov + lcov.

    Workflow:
      1. Inject `QMAKE_CXXFLAGS += --coverage` and `QMAKE_LFLAGS += --coverage` into the .pro
      2. Clean and build via qt_build
      3. (Optional) run the test exe via qt_test
      4. Run lcov to capture coverage
      5. Generate HTML report

    Args:
        params.project_dir: Qt project (must contain a .pro)
        params.output_dir: where to write coverage data (default: project_dir/coverage/)
        params.source_filter: only count files matching this substring
        params.run_after_build: run the test exe after building
        params.timeout: total timeout for build + run + lcov
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    out_dir = Path(params.output_dir) if params.output_dir else proj_dir / "coverage"
    if not out_dir.is_absolute():
        out_dir = (SANDBOX_ROOT / out_dir).resolve()
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    # Check gcov / lcov availability
    gcov_check = await _run(["gcov", "--version"], cwd=proj_dir, timeout=10)
    if not gcov_check.ok:
        return "Error: gcov not found. Install MinGW-w64's gcov or Linux's gcc-gcov." + _json_footer({"ok": False, "error": "gcov not found"})
    lcov_check = await _run(["lcov", "--version"], cwd=proj_dir, timeout=10)
    has_lcov = lcov_check.ok

    # Inject coverage flags into the .pro
    pro_files = list(proj_dir.glob("*.pro"))
    if not pro_files:
        msg = f"Error: no .pro file in {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})
    pro_file = pro_files[0]
    pro_text = pro_file.read_text(encoding="utf-8", errors="replace")
    backup = pro_file.read_text(encoding="utf-8", errors="replace")
    if "QMAKE_CXXFLAGS += --coverage" not in pro_text:
        pro_text += "\n# Added by qt-mcp qt_coverage\nQMAKE_CXXFLAGS += --coverage\nQMAKE_LFLAGS += --coverage\n"
        pro_file.write_text(pro_text, encoding="utf-8")
        restored = False
    else:
        restored = True

    out_dir.mkdir(parents=True, exist_ok=True)
    lines = [f"=== qt_coverage: {proj_dir} ===", f"pro:       {pro_file}", f"output:    {out_dir}"]

    try:
        # Step 1: build
        build_in = QtBuildInput(project_dir=str(proj_dir), build_type="debug", clean_first=True, timeout=params.timeout // 3)
        build_out = await qt_build(build_in)
        build_ok = "Error:" not in build_out and "BUILD FAILED" not in build_out
        lines.append(f"build:     {'OK' if build_ok else 'FAIL'}")
        if not build_ok:
            lines.append(build_out.splitlines()[-10:][0] if build_out else "")
            return "\n".join(lines) + _json_footer({"ok": False, "data": {"stage": "build"}})

        # Step 2: optionally run the test exe
        if params.run_after_build:
            # Find the test exe
            exes = sorted(proj_dir.rglob("debug/*.exe"))
            if not exes:
                exes = sorted(proj_dir.rglob("*.exe"))
            if exes:
                test_in = QtTestInput(test_exe=str(exes[0]))
                test_out = await qt_test(test_in)
                lines.append(f"test:      ran {exes[0].name}")
                lines.append(test_out.splitlines()[-5:][0] if test_out else "")

        # Step 3: gcov on .gcno files
        gcno_files = list(proj_dir.rglob("*.gcno"))
        lines.append(f"gcno:      {len(gcno_files)} files")

        # Step 4: lcov
        info_file = out_dir / "coverage.info"
        if has_lcov:
            capture = await _run(
                ["lcov", "--capture", "--directory", str(proj_dir), "--output-file", str(info_file)],
                cwd=proj_dir, timeout=params.timeout // 3,
            )
            lines.append(f"lcov capture: rc={capture.returncode}")
            if not capture.ok:
                lines.append((capture.stderr or capture.stdout)[-500:])
                return "\n".join(lines) + _json_footer({"ok": False, "data": {"stage": "lcov"}})
            if params.source_filter:
                extract = await _run(
                    ["lcov", "--extract", str(info_file), f"*{params.source_filter}*", "--output-file", str(info_file)],
                    cwd=proj_dir, timeout=30,
                )
                lines.append(f"lcov extract: rc={extract.returncode}")

            genhtml = await _run(
                ["genhtml", str(info_file), "--output-directory", str(out_dir / "html")],
                cwd=proj_dir, timeout=params.timeout // 3,
            )
            lines.append(f"genhtml:     rc={genhtml.returncode}")
            if genhtml.ok:
                lines.append(f"html report: {out_dir / 'html' / 'index.html'}")
        else:
            lines.append("lcov not found — install lcov for HTML reports. .gcno files are still on disk.")

        out = "\n".join(lines)
        return out + _json_footer({"ok": True, "data": {"build": True, "info": str(info_file) if has_lcov else None}})
    finally:
        # Always restore the .pro
        if not restored:
            pro_file.write_text(backup, encoding="utf-8")


# --- qt_cheatsheet: discoverability tool -------------------------------------

@mcp.tool(name="qt_cheatsheet", annotations={"title": "Print a quick-reference of all qt-mcp tools", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_cheatsheet(params: QtCheatsheetInput) -> str:
    """Print a categorized quick reference of all qt-mcp tools.

    Use this to remind yourself what's available before starting a task. The output
    is grouped by logical category (env, scaffold, build, run, validate, creator, analysis).

    Args:
        params.tool_name: if non-empty, show detailed help for that one tool (incl. Input fields)
        params.category: filter to one category (env/scaffold/build/run/validate/creator/analysis); empty = all
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    # Tool catalog
    catalog: dict[str, tuple[str, str]] = {
        # name -> (category, one-line description)
        "qt_env":            ("env",      "Show Qt / MinGW installation paths and versions"),
        "qt_diagnose_env":   ("env",      "Health-check the Qt / MinGW toolchain (16+ binaries, 32/64-bit, PATH)"),
        "qt_pkg":            ("env",      "List / inspect installed Qt 5 modules (headers, libs, plugins)"),
        "qt_scaffold":       ("scaffold", "Create a runnable project skeleton (9 templates)"),
        "qt_class_wizard":   ("scaffold", "Generate a .h/.cpp/.ui trio for a new QObject class"),
        "qt_gen_qrc":        ("scaffold", "Scan an image directory and emit a .qrc"),
        "qt_resources":      ("scaffold", "List / add / remove / validate entries in an existing .qrc"),
        "qt_assets":         ("scaffold", "Scan an assets dir and emit a .qrc + optional Q_INIT_RESOURCE helper"),
        "qt_pro_edit":       ("scaffold", "Read / write .pro variables (list, get, set, append, remove)"),
        "qt_anim":           ("scaffold", "Generate a QPropertyAnimation C++ code snippet (fade / move / scale / rotate / color / sequence)"),
        "qt_network":        ("scaffold", "Generate a QTcpSocket / QTcpServer / QUdpSocket / QWebSocket C++ class pair"),
        "qt_build":          ("build",    "Run qmake + mingw32-make and return structured diagnostics on failure"),
        "qt_build_diagnostics": ("build", "Re-parse a saved build log into JSON (no recompile)"),
        "qt_clean":          ("build",    "Remove debug/ / release/ / build-*/ / Makefile / moc_*.cpp / etc."),
        "qt_smoke_test":     ("build",    "End-to-end health check: clean → build → briefly launch the .exe"),
        "qt_format":         ("build",    "Run clang-format on files / directories (in-place / check-only)"),
        "qt_run":            ("run",      "Launch the built .exe (foreground or detached GUI)"),
        "qt_run_trace":      ("run",      "Launch a .exe with QT_LOGGING_RULES and capture trace logs"),
        "qt_kill_exe":       ("run",      "Terminate a running Qt process by image name"),
        "qt_deploy":         ("run",      "Bundle the .exe with its Qt DLLs / QML / plugins (windeployqt)"),
        "qt_signature":      ("run",      "Sign / verify Windows executables (signtool.exe wrapper)"),
        "qt_test":           ("validate", "Run a Qt C++ test executable (QTestLIB) and parse PASS/FAIL/SKIP"),
        "qt_qml_lint":       ("validate", "Lint .qml files with qmllint"),
        "qt_qml_test":       ("validate", "Run Qt Quick Test cases via qmltestrunner"),
        "qt_translate":      ("validate", "Run lupdate + lrelease (.ts → .qm)"),
        "qt_validate":       ("validate", "Walk a .pro and verify every SOURCES / HEADERS / FORMS / RESOURCES reference exists"),
        "qt_diff":           ("validate", "Compare two .pro projects (variables + sources + content SHA1)"),
        "qt_moc_check":      ("validate", "Run moc on a single header to validate Q_OBJECT"),
        "qt_deps":           ("validate", "List DLL dependencies of a built binary (objdump)"),
        "qt_log":            ("validate", "Filter / analyze a Qt log file (build log or qt_run_trace output) by level + category"),
        "qt_state":          ("validate", "QSettings wrapper: save/load/list/delete/clear persistent app state"),
        "qt_save":           ("validate", "JSON save files (portable, alternative to QSettings)"),
        "qt_creator_open":   ("creator",  "Open a .pro directly in Qt Creator (skip New Project wizard)"),
        "qt_creator_run":    ("creator",  "Build + run a project inside Qt Creator (Ctrl+B + launch)"),
        "qt_ui_action":      ("creator",  "Drive a running Qt app via UI automation (click, type, screenshot)"),
        "qt_designer":       ("creator",  "Launch Qt Designer on a .ui file"),
        "qt_docs_search":    ("analysis", "Full-text search the local Qt 5.14.2 documentation (FTS5)"),
        "qt_grep":           ("analysis", "C++-aware regex search across .h / .cpp / .ui / .qrc"),
        "qt_cheatsheet":     ("analysis", "Print this quick reference of all qt-mcp tools"),
        "qt_watch":          ("analysis", "Watch a Qt project and auto-rebuild on file change"),
        "qt_coverage":       ("analysis", "Run gcov + lcov to collect C++ code coverage on a Qt project"),
        "qt_audio":          ("analysis", "List / probe audio files; emit QSoundEffect playback snippet"),
        "qt_lint":           ("validate", "Unified lint runner: cpplint + qmllint + clang-tidy in one call"),
        "qt_analyze":        ("validate", "Run clang-tidy on a Qt project with custom bugprone/performance/modernize checks"),
        "qt_input":          ("scaffold", "Generate keyboard / mouse / gamepad input handling code (QShortcut, QMouseEvent, QGamepad)"),
        "qt_cmake":          ("scaffold", "Generate a CMakeLists.txt for a Qt project (qmake alternative)"),
        "qt_docs_gen":       ("analysis", "Generate and run Doxygen documentation for a Qt project"),
        "qt_achievement":    ("scaffold", "Manage game achievements / medals (define / grant / list / progress)"),
        "qt_undo":           ("scaffold", "Push / undo / redo game-state snapshots (per-project undo stack)"),
        "qt_leaderboard_ui": ("scaffold", "Generate a leaderboard QWidget (table or cards style) for a board game"),
        "qt_pkg_install":    ("env",      "Install / list / uninstall Qt SDKs via aqtinstall"),
        "qt_release_notes":  ("analysis", "Auto-generate or manually edit CHANGELOG.md from git log"),
        "qt_copyright":      ("analysis", "Add a license / copyright header to all source files in a project"),
        "qt_score":          ("scaffold", "Track and rank player scores (leaderboard) for board games"),
        "qt_timer":          ("scaffold", "Manage named timers for board games (turn time, total game time)"),
        "qt_replay":         ("scaffold", "Step-by-step replay system for board games (record / save / load / play)"),
        "qt_model_gen":      ("scaffold", "Generate a QAbstractListModel or QAbstractTableModel subclass for board-game data"),
        "qt_theme_gen":      ("scaffold", "Generate a QSS stylesheet (light / dark theme) for a Qt Widgets app"),
        "qt_ico_create":     ("run",      "Bundle one or more PNGs into a multi-resolution Windows .ico file"),
        "qt_screenshot_diff":("validate", "Compare two screenshots pixel-by-pixel for visual regression testing"),
        "qt_clazy_check":    ("validate", "Regex-based Qt anti-pattern checker (no clazy binary required)"),
        "qt_signal_slot_trace": ("analysis", "Parse C++ source to extract signal/slot declarations and connect() calls"),
        "qt_input_recorder": ("scaffold", "Record or playback mouse / keyboard input events (pyautogui-based)"),
        "qt_translation_validate": ("validate", "Parse .ts files and report translation coverage per language"),
        "qt_conanfile_gen": ("scaffold", "Generate Conan recipes (conanfile.py + conanfile.txt) for a Qt project, with optional host profiles"),
        "qt_module_split_init": ("scaffold", "Plan / execute splitting a flat .pro into lib/ + app/ + subdirs template"),
        "qt_modernize_qt5_to_qt6": ("validate", "Convert Qt 5 patterns (QRegExp/Q_NULLPTR/foreach/QVector) to Qt 6 equivalents; dry-run by default"),
        "qt_signal_disconnect_check": ("validate", "Find connect() calls with no matching disconnect() (potential signal leak / stale-slot risk)"),
        "qt_qml_perf_lint": ("validate", "Static check of .qml files for performance anti-patterns beyond qmllint (inline JS, sync Image, deep nesting, createObject in Repeater)"),
    }

    if params.tool_name:
        if params.tool_name not in catalog:
            return f"Error: unknown tool {params.tool_name!r}" + _json_footer({"ok": False, "error": "unknown tool"})
        cat, desc = catalog[params.tool_name]
        # Get the tool's Pydantic Input class
        mcp_tools = await mcp.list_tools()
        target = next((t for t in mcp_tools if t.name == params.tool_name), None)
        out_lines = [
            f"=== {params.tool_name}: {desc} ===",
            f"category: {cat}",
        ]
        if target:
            out_lines.append("")
            out_lines.append(f"description: {target.description or '(none)'}")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"category": cat, "description": desc}})

    # Group by category
    by_cat: dict[str, list[tuple[str, str]]] = {}
    for name, (cat, desc) in catalog.items():
        by_cat.setdefault(cat, []).append((name, desc))
    if params.category:
        if params.category not in by_cat:
            return f"Error: unknown category {params.category!r}. Valid: {sorted(by_cat.keys())}" + _json_footer({"ok": False, "error": "unknown category"})
        by_cat = {params.category: by_cat[params.category]}

    out_lines = [f"=== qt_cheatsheet: {len(catalog)} tools ===", f"version: {__version__}", ""]
    for cat in sorted(by_cat.keys()):
        tools_in_cat = by_cat[cat]
        out_lines.append(f"--- {cat} ({len(tools_in_cat)}) ---")
        for name, desc in sorted(tools_in_cat):
            out_lines.append(f"  {name:24s}  {desc}")
        out_lines.append("")
    out_lines.append(f"Tip: pass tool_name=<name> for detailed help on one tool.")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"total_tools": len(catalog), "categories": list(by_cat.keys())}})


# --- qt_score: leaderboard for board games -----------------------------------

@mcp.tool(name="qt_score", annotations={"title": "Track and rank player scores for board games (leaderboard)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_score(params: QtScoreInput) -> str:
    """Maintain a per-game leaderboard of player scores.

    Backed by a JSON file (default `<SANDBOX>/.scores/scores.json`) with shape:
        {"games": {"<game>": [{"player": "...", "score": N, "ts": 1234567890}, ...]}}

    Actions:
      - 'add'         : append a new score entry for `player` in `game`
      - 'list'        : show all entries (optionally filtered by game)
      - 'leaderboard' : top N entries for a game, sorted by score
      - 'reset'       : clear scores for a specific player (or all if player=='')
      - 'export'      : dump the whole score file to a portable JSON path
      - 'import'      : merge scores from another file

    Args:
        params.action: 'add' | 'list' | 'leaderboard' | 'reset' | 'import' | 'export'
        params.score_file: path to the scores file (default: <SANDBOX>/.scores/scores.json)
        params.player: player name
        params.score: integer score (for 'add')
        params.game: game/variant name (default 'default')
        params.top_n: leaderboard size (default 10)
        params.sort_desc: leaderboard sort direction (default descending)
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("add", "list", "leaderboard", "reset", "import", "export"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    score_path = Path(params.score_file) if params.score_file else SANDBOX_ROOT / ".scores" / "scores.json"
    if not score_path.is_absolute():
        score_path = (SANDBOX_ROOT / score_path).resolve()
    sandbox_err = _require_sandbox(score_path, "score_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    import json as _json

    def _load() -> dict:
        if not score_path.exists():
            return {"games": {}}
        try:
            return _json.loads(score_path.read_text(encoding="utf-8"))
        except (OSError, ValueError):
            return {"games": {}}

    def _save(data: dict) -> None:
        score_path.parent.mkdir(parents=True, exist_ok=True)
        score_path.write_text(_json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")

    if params.action == "add":
        if not params.player:
            msg = "Error: 'add' requires a non-empty player"
            return msg + _json_footer({"ok": False, "error": msg})
        data = _load()
        data.setdefault("games", {}).setdefault(params.game, []).append({
            "player": params.player,
            "score": params.score,
            "ts": int(asyncio.get_event_loop().time() * 1000),
        })
        _save(data)
        count = len(data["games"][params.game])
        out = f"added: {params.player} -> {params.score} in {params.game}\n  total entries for {params.game}: {count}\n  file: {score_path}"
        return out + _json_footer({"ok": True, "data": {"player": params.player, "score": params.score, "game": params.game, "total": count}})

    if params.action == "list":
        data = _load()
        games = data.get("games", {})
        if not games:
            out = f"=== qt_score: no scores in {score_path} ==="
            return out + _json_footer({"ok": True, "data": {"games": {}, "count": 0}})
        out_lines = [f"=== qt_score: {sum(len(v) for v in games.values())} total entries ==="]
        for game, entries in sorted(games.items()):
            out_lines.append(f"--- {game} ({len(entries)}) ---")
            for e in entries[-20:]:
                out_lines.append(f"  {e['player']:20s}  {e['score']:>10}  ts={e['ts']}")
            if len(entries) > 20:
                out_lines.append(f"  ... and {len(entries) - 20} more")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"games": games}})

    if params.action == "leaderboard":
        data = _load()
        entries = data.get("games", {}).get(params.game, [])
        if not entries:
            out = f"=== qt_score: no entries for {params.game!r} ==="
            return out + _json_footer({"ok": True, "data": {"entries": [], "top_n": 0}})
        # Aggregate by player (best score)
        best: dict[str, int] = {}
        for e in entries:
            p = e["player"]
            s = e["score"]
            if p not in best or (s > best[p] if params.sort_desc else s < best[p]):
                best[p] = s
        ranked = sorted(best.items(), key=lambda x: x[1], reverse=params.sort_desc)
        top = ranked[:params.top_n]
        out_lines = [f"=== qt_score: leaderboard for {params.game!r} (top {len(top)} of {len(ranked)}) ==="]
        for i, (p, s) in enumerate(top, 1):
            out_lines.append(f"  {i:>3}. {p:20s}  {s:>10}")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"game": params.game, "entries": [{"player": p, "score": s} for p, s in top]}})

    if params.action == "reset":
        data = _load()
        if params.player:
            # Remove all entries for this player
            for game in data.get("games", {}).values():
                data["games"] = {g: [e for e in entries if e["player"] != params.player] for g, entries in data["games"].items()}
            _save(data)
            out = f"reset: removed all entries for {params.player}"
            return out + _json_footer({"ok": True, "data": {"reset_player": params.player}})
        else:
            # Reset all
            _save({"games": {}})
            out = f"reset: cleared all scores"
            return out + _json_footer({"ok": True, "data": {"reset_all": True}})

    if params.action == "export":
        data = _load()
        if not params.score_file:
            return "Error: 'export' requires a score_file path" + _json_footer({"ok": False, "error": "missing score_file"})
        # score_file is the export path
        export_path = Path(params.score_file)
        if not export_path.is_absolute():
            export_path = (SANDBOX_ROOT / export_path).resolve()
        sandbox_err = _require_sandbox(export_path, "export path")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        export_path.parent.mkdir(parents=True, exist_ok=True)
        export_path.write_text(_json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")
        out = f"exported: {len(data.get('games', {}))} games to {export_path}"
        return out + _json_footer({"ok": True, "data": {"export_path": str(export_path)}})

    if params.action == "import":
        if not params.score_file:
            return "Error: 'import' requires a score_file path" + _json_footer({"ok": False, "error": "missing score_file"})
        import_path = Path(params.score_file)
        if not import_path.is_absolute():
            import_path = (SANDBOX_ROOT / import_path).resolve()
        if not import_path.exists():
            msg = f"Error: import file not found: {import_path}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            incoming = _json.loads(import_path.read_text(encoding="utf-8"))
        except (OSError, ValueError) as e:
            msg = f"Error: failed to parse {import_path}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})
        data = _load()
        for game, entries in incoming.get("games", {}).items():
            data.setdefault("games", {}).setdefault(game, []).extend(entries)
        _save(data)
        n = sum(len(v) for v in incoming.get("games", {}).values())
        out = f"imported: {n} entries from {import_path}"
        return out + _json_footer({"ok": True, "data": {"imported": n}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_timer: game clock for board games -------------------------------------

@mcp.tool(name="qt_timer", annotations={"title": "Start / stop / pause / resume named timers (game clock, turn timer, etc.)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_timer(params: QtTimerInput) -> str:
    """Manage named timers for board games (turn time, total game time, etc.).

    State is persisted to a JSON file (default `<SANDBOX>/.timers/timers.json`)
    with shape:
        {"timers": {"<id>": {"state": "running"|"paused"|"stopped",
                              "accumulated_ms": N,
                              "last_resume_ts": 1234567890,  # only if running
                              "last_update_ts": 1234567890}}}

    Actions:
      - 'start'   : create a new timer (or restart existing) with elapsed_ms=0 (or override)
      - 'stop'    : stop and record final elapsed
      - 'pause'   : suspend a running timer
      - 'resume'  : continue a paused timer
      - 'status'  : show one timer's state and elapsed
      - 'list'    : show all timers
      - 'reset'   : remove a timer entirely
      - 'cleanup' : remove all stopped timers (kept on disk for reference)

    Args:
        params.action: 'start' | 'stop' | 'pause' | 'resume' | 'status' | 'list' | 'reset' | 'cleanup'
        params.timer_id: timer name (required for most actions)
        params.state_file: where to persist state (default: <SANDBOX>/.timers/timers.json)
        params.elapsed_ms: override initial elapsed time when starting (advanced)
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("start", "stop", "pause", "resume", "status", "list", "reset", "cleanup"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    state_path = Path(params.state_file) if params.state_file else SANDBOX_ROOT / ".timers" / "timers.json"
    if not state_path.is_absolute():
        state_path = (SANDBOX_ROOT / state_path).resolve()
    sandbox_err = _require_sandbox(state_path, "state_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    import json as _json
    import time

    def _load() -> dict:
        if not state_path.exists():
            return {"timers": {}}
        try:
            return _json.loads(state_path.read_text(encoding="utf-8"))
        except (OSError, ValueError):
            return {"timers": {}}

    def _save(data: dict) -> None:
        state_path.parent.mkdir(parents=True, exist_ok=True)
        state_path.write_text(_json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")

    def _now_ms() -> int:
        return int(time.time() * 1000)

    def _elapsed_ms(t: dict) -> int:
        if t["state"] == "stopped":
            return t["accumulated_ms"]
        if t["state"] == "running":
            return t["accumulated_ms"] + (_now_ms() - t["last_resume_ts"])
        return t["accumulated_ms"]  # paused

    def _fmt(ms: int) -> str:
        s = ms // 1000
        m, s = divmod(s, 60)
        h, m = divmod(m, 60)
        return f"{h:02d}:{m:02d}:{s:02d}.{ms % 1000:03d}"

    if params.action == "list":
        data = _load()
        timers = data.get("timers", {})
        if not timers:
            out = f"=== qt_timer: no timers in {state_path} ==="
            return out + _json_footer({"ok": True, "data": {"timers": {}, "count": 0}})
        out_lines = [f"=== qt_timer: {len(timers)} timer(s) ==="]
        for tid, t in timers.items():
            out_lines.append(f"  {tid:24s}  {t['state']:8s}  elapsed={_fmt(_elapsed_ms(t))}")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"timers": timers}})

    if params.action == "cleanup":
        data = _load()
        before = len(data.get("timers", {}))
        cutoff = _now_ms() - 3600 * 1000
        data["timers"] = {
            k: v for k, v in data.get("timers", {}).items()
            if not (v.get("state") == "stopped" and v.get("last_update_ts", 0) < cutoff)
        }
        after = len(data["timers"])
        _save(data)
        out = f"cleanup: {before - after} stopped timer(s) removed (kept {after} active)"
        return out + _json_footer({"ok": True, "data": {"removed": before - after, "kept": after}})

    if not params.timer_id:
        msg = f"Error: action {params.action!r} requires a non-empty timer_id"
        return msg + _json_footer({"ok": False, "error": msg})

    data = _load()
    timers = data.setdefault("timers", {})

    if params.action == "start":
        now = _now_ms()
        timers[params.timer_id] = {
            "state": "running",
            "accumulated_ms": params.elapsed_ms,
            "last_resume_ts": now,
            "last_update_ts": now,
        }
        _save(data)
        out = f"started: {params.timer_id} at {_fmt(params.elapsed_ms)} (elapsed will grow from here)"
        return out + _json_footer({"ok": True, "data": {"timer_id": params.timer_id, "state": "running", "elapsed_ms": params.elapsed_ms}})

    if params.timer_id not in timers:
        msg = f"Error: timer {params.timer_id!r} not found. Use 'start' to create it first."
        return msg + _json_footer({"ok": False, "error": msg})

    t = timers[params.timer_id]

    if params.action == "stop":
        # Capture elapsed and set state=stopped
        elapsed = _elapsed_ms(t)
        t["accumulated_ms"] = elapsed
        t["state"] = "stopped"
        t["last_update_ts"] = _now_ms()
        t.pop("last_resume_ts", None)
        _save(data)
        out = f"stopped: {params.timer_id} final elapsed={_fmt(elapsed)}"
        return out + _json_footer({"ok": True, "data": {"timer_id": params.timer_id, "state": "stopped", "elapsed_ms": elapsed}})

    if params.action == "pause":
        if t["state"] != "running":
            msg = f"Error: timer {params.timer_id!r} is not running (state={t['state']})"
            return msg + _json_footer({"ok": False, "error": msg})
        elapsed = _elapsed_ms(t)
        t["accumulated_ms"] = elapsed
        t["state"] = "paused"
        t["last_update_ts"] = _now_ms()
        t.pop("last_resume_ts", None)
        _save(data)
        out = f"paused: {params.timer_id} at {_fmt(elapsed)}"
        return out + _json_footer({"ok": True, "data": {"timer_id": params.timer_id, "state": "paused", "elapsed_ms": elapsed}})

    if params.action == "resume":
        if t["state"] != "paused":
            msg = f"Error: timer {params.timer_id!r} is not paused (state={t['state']})"
            return msg + _json_footer({"ok": False, "error": msg})
        t["state"] = "running"
        t["last_resume_ts"] = _now_ms()
        t["last_update_ts"] = _now_ms()
        _save(data)
        elapsed = _elapsed_ms(t)
        out = f"resumed: {params.timer_id} (now at {_fmt(elapsed)}, counting up)"
        return out + _json_footer({"ok": True, "data": {"timer_id": params.timer_id, "state": "running", "elapsed_ms": elapsed}})

    if params.action == "status":
        elapsed = _elapsed_ms(t)
        out = f"--- {params.timer_id} ---\n  state:    {t['state']}\n  elapsed:  {_fmt(elapsed)}\n  accumulated: {t['accumulated_ms']} ms"
        return out + _json_footer({"ok": True, "data": {"timer_id": params.timer_id, "state": t["state"], "elapsed_ms": elapsed}})

    if params.action == "reset":
        del timers[params.timer_id]
        _save(data)
        out = f"reset: {params.timer_id} removed"
        return out + _json_footer({"ok": True, "data": {"timer_id": params.timer_id, "removed": True}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_replay: game replay system --------------------------------------------

@mcp.tool(name="qt_replay", annotations={"title": "Record / save / list / play back game replays (step-by-step)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_replay(params: QtReplayInput) -> str:
    """Step-by-step replay system for board games.

    Each replay is a JSON file in `<SANDBOX>/.replays/<session_id>.json`:
        {
            "session_id": "game_2024_01_15",
            "created_ts": 1234567890,
            "updated_ts": 1234567899,
            "metadata": {...},     # free-form (game, players, etc.)
            "steps": [
                {"n": 1, "type": "move", "data": {...}, "ts": 1234567891},
                {"n": 2, "type": "draw", "data": {...}, "ts": 1234567892},
                ...
            ]
        }

    Actions:
      - 'record' : append a step to a session (auto-creates if missing)
      - 'save'   : snapshot the current session to a portable file
      - 'load'   : read a session back (returns the parsed JSON)
      - 'list'   : show all saved replays
      - 'play'   : emit a script that replays the steps (human-readable)
      - 'delete' : remove a replay

    Args:
        params.action: 'record' | 'save' | 'load' | 'list' | 'play' | 'delete'
        params.session_id: session / replay name
        params.replay_dir: where to store replays
        params.step_type: step type for 'record' ('move', 'draw', 'pass', etc.)
        params.data: step data dict
        params.max_lines: cap for 'play' output
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("record", "save", "load", "list", "play", "delete"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    replay_dir = Path(params.replay_dir) if params.replay_dir else SANDBOX_ROOT / ".replays"
    if not replay_dir.is_absolute():
        replay_dir = (SANDBOX_ROOT / replay_dir).resolve()
    sandbox_err = _require_sandbox(replay_dir, "replay_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    import json as _json
    import time

    if params.action == "list":
        if not replay_dir.exists():
            out = f"=== qt_replay: no replays (dir does not exist) ==="
            return out + _json_footer({"ok": True, "data": {"replays": [], "count": 0}})
        replays = sorted(replay_dir.glob("*.json"))
        if not replays:
            out = f"=== qt_replay: no replays in {replay_dir} ==="
            return out + _json_footer({"ok": True, "data": {"replays": [], "count": 0}})
        out_lines = [f"=== qt_replay: {len(replays)} replay(s) in {replay_dir} ==="]
        for r in replays:
            try:
                obj = _json.loads(r.read_text(encoding="utf-8"))
                n = len(obj.get("steps", []))
                meta = obj.get("metadata", {})
                title = meta.get("title", "(no title)")
                out_lines.append(f"  {r.stem:32s}  {n:>5} steps  {title}")
            except (OSError, ValueError) as e:
                out_lines.append(f"  {r.stem:32s}  (error: {e})")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"count": len(replays)}})

    if not params.session_id:
        msg = f"Error: action {params.action!r} requires a non-empty session_id"
        return msg + _json_footer({"ok": False, "error": msg})

    safe_id = re.sub(r"[^A-Za-z0-9_\-]", "_", params.session_id)
    if not safe_id:
        msg = f"Error: session_id {params.session_id!r} is invalid (no alphanumeric chars)"
        return msg + _json_footer({"ok": False, "error": msg})
    replay_path = replay_dir / f"{safe_id}.json"
    replay_dir.mkdir(parents=True, exist_ok=True)

    if params.action == "record":
        # Load existing or create new
        if replay_path.exists():
            try:
                session = _json.loads(replay_path.read_text(encoding="utf-8"))
            except (OSError, ValueError) as e:
                msg = f"Error: failed to parse {replay_path}: {e}"
                return msg + _json_footer({"ok": False, "error": msg})
        else:
            session = {
                "session_id": safe_id,
                "created_ts": int(time.time() * 1000),
                "updated_ts": int(time.time() * 1000),
                "metadata": {},
                "steps": [],
            }
        if not params.step_type:
            msg = "Error: 'record' requires a non-empty step_type"
            return msg + _json_footer({"ok": False, "error": msg})
        n = len(session["steps"]) + 1
        session["steps"].append({
            "n": n,
            "type": params.step_type,
            "data": params.data,
            "ts": int(time.time() * 1000),
        })
        session["updated_ts"] = int(time.time() * 1000)
        replay_path.write_text(_json.dumps(session, indent=2, ensure_ascii=False), encoding="utf-8")
        out = f"recorded: step #{n} ({params.step_type}) in {safe_id} (total {len(session['steps'])} steps)"
        return out + _json_footer({"ok": True, "data": {"step_n": n, "type": params.step_type, "total": len(session["steps"])}})

    if params.action in ("save", "load"):
        if not replay_path.exists():
            msg = f"Error: replay not found: {replay_path}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            data = _json.loads(replay_path.read_text(encoding="utf-8"))
        except (OSError, ValueError) as e:
            msg = f"Error: failed to parse {replay_path}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})
        if params.action == "load":
            out_lines = [f"=== qt_replay: load {safe_id} ===", f"created: {data.get('created_ts')}", f"updated: {data.get('updated_ts')}", f"steps:   {len(data.get('steps', []))}", f"metadata: {data.get('metadata', {})}"]
            out = "\n".join(out_lines)
            return out + _json_footer({"ok": True, "data": data})
        # save: write to a portable path
        save_path = SANDBOX_ROOT / ".replays" / f"{safe_id}_export_{int(time.time())}.json"
        save_path.write_text(_json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")
        out = f"saved: {save_path}"
        return out + _json_footer({"ok": True, "data": {"saved_path": str(save_path)}})

    if params.action == "play":
        if not replay_path.exists():
            msg = f"Error: replay not found: {replay_path}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            data = _json.loads(replay_path.read_text(encoding="utf-8"))
        except (OSError, ValueError) as e:
            msg = f"Error: failed to parse {replay_path}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})
        steps = data.get("steps", [])
        out_lines = [f"=== qt_replay: play {safe_id} ({len(steps)} steps) ==="]
        for s in steps[:params.max_lines]:
            out_lines.append(f"  step {s['n']:>3}  {s['type']:16s}  {s.get('data', {})}")
        if len(steps) > params.max_lines:
            out_lines.append(f"  ... and {len(steps) - params.max_lines} more steps")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"step_count": len(steps), "shown": min(len(steps), params.max_lines)}})

    if params.action == "delete":
        if replay_path.exists():
            replay_path.unlink()
            out = f"deleted: {replay_path}"
            return out + _json_footer({"ok": True, "data": {"deleted": True}})
        out = f"nothing to delete: {replay_path} does not exist"
        return out + _json_footer({"ok": True, "data": {"deleted": False}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_lint: unified lint wrapper --------------------------------------------

@mcp.tool(name="qt_lint", annotations={"title": "Run cpplint + qmllint + clang-tidy in one shot", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_lint(params: QtLintInput) -> str:
    """Run multiple linters over a Qt project and aggregate the results.

    Linters:
      - cpplint     : Google's C++ style checker (catches include order, naming, etc.)
      - qmllint     : QML syntax / type checker (Qt's own linter)
      - clang-tidy  : Modern C++ linter with bugprone / performance / modernize checks

    Each linter is run if its binary is found on PATH (or under QT_ROOT for qmllint).
    Output is a per-linter report with file:line:col entries. Returns 'LINT PASS'
    if no errors, or 'LINT FAIL' if any linter reported issues.

    Args:
        params.project_dir: project to lint
        params.linters: subset of ['cpplint', 'qmllint', 'clang-tidy']; empty = all
        params.extensions: file suffixes for cpplint (default .cpp .h)
        params.qml_extensions: file suffixes for qmllint (default .qml)
        params.severity_filter: 'error' > 'warning' > 'note' (only show >= this)
        params.max_per_linter: cap per linter output (default 100)
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    requested = params.linters or ["cpplint", "qmllint", "clang-tidy"]
    sev_rank = {"error": 3, "warning": 2, "note": 1}
    min_rank = sev_rank.get(params.severity_filter, 0)

    out_lines = [f"=== qt_lint: {proj_dir} ===", f"linters: {requested}"]

    def _passes_severity(line: str) -> bool:
        if not min_rank:
            return True
        ll = line.lower()
        if "error" in ll and min_rank <= 3:
            return True
        if "warning" in ll and min_rank <= 2:
            return True
        if "note" in ll and min_rank <= 1:
            return True
        # If no severity keyword, include it (might be info)
        return True

    def _filter_issues(text: str) -> str:
        if not min_rank:
            return text
        out_text_lines = []
        for ln in text.splitlines():
            if _passes_severity(ln):
                out_text_lines.append(ln)
        return "\n".join(out_text_lines)

    summary: dict[str, int] = {}

    for linter in requested:
        if linter == "cpplint":
            cpplint = shutil.which("cpplint") or shutil.which("cpplint.py")
            if not cpplint:
                out_lines.append(f"\n--- cpplint: NOT FOUND (install via 'pip install cpplint') ---")
                summary["cpplint"] = -1
                continue
            exts = [e if e.startswith(".") else "." + e for e in params.extensions]
            cmd = [cpplint, "--quiet", f"--extensions={','.join(e.lstrip('.') for e in exts)}"]
            files = []
            for ext in exts:
                files.extend(str(p) for p in proj_dir.rglob(f"*{ext}") if any(s not in p.parts for s in ("debug", "release", "build-*", ".tmp", ".git")))
            if not files:
                out_lines.append(f"\n--- cpplint: no files matching {exts} ---")
                summary["cpplint"] = 0
                continue
            cmd.extend(files[:50])  # cap to avoid cmdline overflow
            r = await _run(cmd, cwd=proj_dir, timeout=60)
            out_lines.append(f"\n--- cpplint: rc={r.returncode} ---")
            body = _filter_issues(r.stdout or r.stderr)
            out_lines.append(_tail(body, params.max_per_linter))
            summary["cpplint"] = r.returncode

        elif linter == "qmllint":
            qmllint = QT_BIN_DIR / "qmllint.exe"
            if not qmllint.exists():
                out_lines.append(f"\n--- qmllint: NOT FOUND at {qmllint} ---")
                summary["qmllint"] = -1
                continue
            exts = [e if e.startswith(".") else "." + e for e in params.qml_extensions]
            files = []
            for ext in exts:
                files.extend(str(p) for p in proj_dir.rglob(f"*{ext}") if any(s not in p.parts for s in ("debug", "release", "build-*", ".tmp", ".git")))
            if not files:
                out_lines.append(f"\n--- qmllint: no files matching {exts} ---")
                summary["qmllint"] = 0
                continue
            r = await _run([str(qmllint)] + files, cwd=proj_dir, timeout=60)
            out_lines.append(f"\n--- qmllint: rc={r.returncode} ---")
            body = _filter_issues(r.stdout or r.stderr)
            out_lines.append(_tail(body, params.max_per_linter))
            summary["qmllint"] = r.returncode

        elif linter == "clang-tidy":
            ct = shutil.which("clang-tidy") or shutil.which("clang-tidy.exe")
            if not ct:
                out_lines.append(f"\n--- clang-tidy: NOT FOUND (install LLVM/clang-tidy) ---")
                summary["clang-tidy"] = -1
                continue
            cpp_files = [str(p) for p in proj_dir.rglob("*.cpp") if any(s not in p.parts for s in ("debug", "release", "build-*", ".tmp", ".git"))]
            if not cpp_files:
                out_lines.append(f"\n--- clang-tidy: no .cpp files ---")
                summary["clang-tidy"] = 0
                continue
            all_issues = []
            for f in cpp_files[:20]:  # cap to avoid timeout
                r = await _run([ct, f, "--quiet"], cwd=proj_dir, timeout=30)
                all_issues.append(f"=== {f} (rc={r.returncode}) ===")
                all_issues.append(_filter_issues(r.stdout or r.stderr))
            out_lines.append(f"\n--- clang-tidy: {len(cpp_files)} file(s) ---")
            out_lines.append(_tail("\n".join(all_issues), params.max_per_linter))
            summary["clang-tidy"] = sum(1 for ln in all_issues if "warning" in ln.lower() or "error" in ln.lower())
        else:
            out_lines.append(f"\n--- {linter}: UNKNOWN linter ---")
            summary[linter] = -2

    passed = all(v in (0, -1, -2) for v in summary.values())
    out_lines.append("")
    out_lines.append(f"=== Summary ===")
    for linter, n in summary.items():
        status = "PASS" if n == 0 else ("SKIP" if n < 0 else f"FAIL ({n} issues)")
        out_lines.append(f"  {linter:12s}  {status}")
    out_lines.append(f"=== {'LINT PASS' if passed else 'LINT FAIL'} ===")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": passed, "data": {"summary": summary}})


# --- qt_analyze: clang-tidy deep analysis -------------------------------------

@mcp.tool(name="qt_analyze", annotations={"title": "Run clang-tidy on a Qt project with custom checks", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_analyze(params: QtAnalyzeInput) -> str:
    """Run clang-tidy on a Qt project's .cpp files with custom check selection.

    clang-tidy has hundreds of checks in categories: bugprone-*, performance-*,
    modernize-*, readability-*, cert-*, cppcoreguidelines-*. Use this tool to run
    a focused subset (e.g. just bugprone-* + performance-*) instead of the
    default '*' which is slow and noisy.

    Output is grouped by file with file:line:col: severity [check-name] message.

    Args:
        params.project_dir: project to analyze
        params.checks: comma-separated check names; '*' = all; '-check' = disable
        params.clang_tidy_exe: path to clang-tidy; empty = auto-find
        params.extra_args: extra args (e.g. '-std=c++17 -I...')
        params.output_format: 'text' (default) or 'json'
        params.max_issues: cap total issues (default 200)
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Find clang-tidy
    ct = Path(params.clang_tidy_exe) if params.clang_tidy_exe else None
    if not ct or not ct.exists():
        ct_path = shutil.which("clang-tidy") or shutil.which("clang-tidy.exe")
        if not ct_path:
            msg = "Error: clang-tidy not found. Install LLVM or pass clang_tidy_exe."
            return msg + _json_footer({"ok": False, "error": msg})
        ct = Path(ct_path)

    cpp_files = sorted(
        str(p) for p in proj_dir.rglob("*.cpp")
        if not any(s in p.parts for s in ("debug", "release", "build-", ".tmp", ".git"))
    )
    if not cpp_files:
        msg = f"Error: no .cpp files found in {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    out_lines = [f"=== qt_analyze: {proj_dir} ===", f"clang-tidy: {ct}", f"checks:    {params.checks}", f"format:    {params.output_format}"]

    cmd_base = [str(ct), f"--checks={params.checks}"]
    if params.output_format == "json":
        cmd_base.append("--output-format=json")
    if params.extra_args:
        cmd_base.extend(params.extra_args.split())

    all_output = []
    for f in cpp_files[:20]:  # cap files to avoid long runs
        r = await _run(cmd_base + [f], cwd=proj_dir, timeout=60)
        if r.stdout.strip():
            all_output.append(f"--- {f} ---")
            all_output.append(r.stdout)

    combined = "\n".join(all_output)
    if len(combined.splitlines()) > params.max_issues:
        out_lines.append(_tail(combined, params.max_issues))
        out_lines.append(f"\n... (truncated to {params.max_issues} lines)")
    else:
        out_lines.append(combined)

    issue_count = combined.count("warning:") + combined.count("error:")
    out_lines.append("")
    out_lines.append(f"=== Summary: {issue_count} issue(s) in {len(cpp_files[:20])} file(s) ===")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": issue_count == 0, "data": {"issue_count": issue_count, "file_count": len(cpp_files[:20])}})


# --- qt_input: keyboard / mouse / gamepad input mapping -----------------------

@mcp.tool(name="qt_input", annotations={"title": "Generate keyboard / mouse / gamepad input handling code for Qt games", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_input(params: QtInputInput) -> str:
    """Generate ready-to-paste C++ snippets for handling user input in Qt.

    Actions:
      - 'keyboard' : emit a QShortcut + QKeySequence + slot declaration
      - 'mouse'    : emit a mousePressEvent / mouseMoveEvent handler skeleton
      - 'gamepad'  : emit a QGamepad key-binding snippet (QtGamepad / SDL2 fallback note)
      - 'focus'    : emit a tab-order / focus-chain setter
      - 'mapping'  : write a JSON bindings file (action -> key/click -> slot)

    Args:
        params.action: 'keyboard' | 'mouse' | 'gamepad' | 'focus' | 'mapping'
        params.target_class: QWidget subclass that owns the input (default 'MainWindow')
        params.key_sequence: QKeySequence string (for keyboard; e.g. 'Ctrl+N', 'F5')
        params.slot_name: slot to call when the input fires
        params.bindings: list of {action, sequence, slot} dicts (for mapping)
        params.output_file: path to write the JSON bindings file (for mapping)
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("keyboard", "mouse", "gamepad", "focus", "mapping"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    tc = params.target_class

    if params.action == "keyboard":
        cpp = f"""// Keyboard input for {tc}: {params.key_sequence} -> {params.slot_name}()
// Add to your {tc} header (inside the class, after public:):
private slots:
    void {params.slot_name}();

// Add to your {tc} constructor:
#include <QShortcut>
#include <QKeySequence>
    auto *shortcut = new QShortcut(QKeySequence(QStringLiteral(\"{params.key_sequence}\")), this);
    shortcut->setContext(Qt::ApplicationShortcut);
    connect(shortcut, &QShortcut::activated, this, &{tc}::{params.slot_name});

// Then implement the slot in {tc}.cpp:
void {tc}::{params.slot_name}() {{
    // Your action here
    qDebug() << \"{params.key_sequence} pressed -> {params.slot_name}\";
}}
"""
        out = f"=== qt_input: keyboard snippet for {tc} ===\n{cpp}"
        return out + _json_footer({"ok": True, "data": {"snippet_lines": cpp.count(chr(10))}})

    if params.action == "mouse":
        cpp = f"""// Mouse input for {tc}: press / move / release handlers
// Override these in your {tc} header (add after protected:):
protected:
    void mousePressEvent(QMouseEvent *event) override;
    void mouseMoveEvent(QMouseEvent *event) override;
    void mouseReleaseEvent(QMouseEvent *event) override;
    void mouseDoubleClickEvent(QMouseEvent *event) override;

// Implementation in {tc}.cpp:
#include <QMouseEvent>

void {tc}::mousePressEvent(QMouseEvent *event) {{
    if (event->button() == Qt::LeftButton) {{
        // Drag start: record position
        m_dragStart = event->pos();
        setCursor(Qt::ClosedHandCursor);
    }}
    QWidget::mousePressEvent(event);
}}

void {tc}::mouseMoveEvent(QMouseEvent *event) {{
    if (event->buttons() & Qt::LeftButton) {{
        // Drag in progress: emit signals or update state
        emit dragged(event->pos() - m_dragStart);
    }}
    QWidget::mouseMoveEvent(event);
}}

void {tc}::mouseReleaseEvent(QMouseEvent *event) {{
    if (event->button() == Qt::LeftButton) {{
        setCursor(Qt::ArrowCursor);
    }}
    QWidget::mouseReleaseEvent(event);
}}

void {tc}::mouseDoubleClickEvent(QMouseEvent *event) {{
    emit doubleClicked(event->pos());
    QWidget::mouseDoubleClickEvent(event);
}}
"""
        out = f"=== qt_input: mouse handlers for {tc} ===\n{cpp}"
        return out + _json_footer({"ok": True, "data": {"snippet_lines": cpp.count(chr(10))}})

    if params.action == "gamepad":
        cpp = f"""// Gamepad input for {tc}: QtGamepad wrapper
// Requires: QT += gamepad (Qt 5.7 - 5.14) or SDL2 / cross-platform fallback
#include <QGamepad>
#include <QGamepadManager>

class {tc} : public QWidget {{
    Q_OBJECT
public:
    explicit {tc}(QWidget *parent = nullptr);
private slots:
    void onButtonA(bool pressed);
    void onButtonB(bool pressed);
    void onLeftX(double value);
    void onLeftY(double value);
private:
    QGamepad *m_gamepad;
}};

{tc}::{tc}(QWidget *parent) : QWidget(parent) {{
    m_gamepad = QGamepadManager::instance()->gamepads().isEmpty()
        ? nullptr : QGamepadManager::instance()->gamepads().first();
    if (m_gamepad) {{
        connect(m_gamepad, &QGamepad::buttonAChanged, this, &{tc}::onButtonA);
        connect(m_gamepad, &QGamepad::buttonBChanged, this, &{tc}::onButtonB);
        connect(m_gamepad, &QGamepad::axisLeftXChanged, this, &{tc}::onLeftX);
        connect(m_gamepad, &QGamepad::axisLeftYChanged, this, &{tc}::onLeftY);
    }}
}}

void {tc}::onButtonA(bool pressed) {{ if (pressed) emit primaryAction(); }}
void {tc}::onButtonB(bool pressed) {{ if (pressed) emit secondaryAction(); }}
void {tc}::onLeftX(double value) {{ emit moveX(value); }}
void {tc}::onLeftY(double value) {{ emit moveY(value); }}

// Note: Qt 6 removed QtGamepad. For Qt 6, use SDL2 GameController or libstem.
"""
        out = f"=== qt_input: gamepad snippet for {tc} ===\n{cpp}"
        return out + _json_footer({"ok": True, "data": {"snippet_lines": cpp.count(chr(10))}})

    if params.action == "focus":
        cpp = f"""// Focus chain / tab order for {tc}
// In your {tc} constructor:
    // Set tab order: widget1 -> widget2 -> widget3 -> back to start
    setTabOrder(ui->widget1, ui->widget2);
    setTabOrder(ui->widget2, ui->widget3);
    setTabOrder(ui->widget3, ui->widget1);

    // Initial focus
    ui->widget1->setFocus();

    // Optional: handle Enter as Tab in forms
    auto *advanceOnEnter = new QShortcut(QKeySequence(Qt::Key_Return), this);
    advanceOnEnter->setContext(Qt::WidgetWithChildrenShortcut);
    connect(advanceOnEnter, &QShortcut::activated, this, [this]() {{
        // Custom: focus next widget, or submit form if last
        focusNextChild();
    }});
"""
        out = f"=== qt_input: focus chain for {tc} ===\n{cpp}"
        return out + _json_footer({"ok": True, "data": {"snippet_lines": cpp.count(chr(10))}})

    if params.action == "mapping":
        if not params.bindings:
            msg = "Error: 'mapping' requires a non-empty 'bindings' list"
            return msg + _json_footer({"ok": False, "error": msg})
        import json as _json
        out_path = Path(params.output_file) if params.output_file else SANDBOX_ROOT / ".input_bindings.json"
        if not out_path.is_absolute():
            out_path = (SANDBOX_ROOT / out_path).resolve()
        sandbox_err = _require_sandbox(out_path, "output_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        out_path.parent.mkdir(parents=True, exist_ok=True)
        payload = {
            "target_class": tc,
            "version": 1,
            "bindings": params.bindings,
        }
        out_path.write_text(_json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
        out_lines = [f"=== qt_input: wrote {len(params.bindings)} binding(s) to {out_path} ===", f"target: {tc}"]
        for b in params.bindings:
            out_lines.append(f"  {b.get('action', '?'):24s}  {b.get('sequence', '?'):16s}  -> {b.get('slot', '?')}")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"path": str(out_path), "binding_count": len(params.bindings)}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_cmake: CMakeLists.txt generator (qmake alternative) ------------------

@mcp.tool(name="qt_cmake", annotations={"title": "Generate a CMakeLists.txt for a Qt project (qmake alternative)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_cmake(params: QtCmakeInput) -> str:
    """Scan a directory and emit a CMakeLists.txt that builds the Qt project.

    Useful when you want to migrate from qmake (.pro) to CMake, or for projects
    where you want IDE-grade CMake integration (Visual Studio, CLion, Qt Creator
    in CMake-mode). The generated CMakeLists.txt uses modern CMake 3.16+ idioms:
    find_package(Qt5/6 ...), AUTOMOC, AUTORCC, AUTOUIC, target_sources().

    Args:
        params.project_dir: directory to scan (must be inside sandbox)
        params.project_name: project name (target name)
        params.qt_modules: list of Qt modules to link (e.g. ['Core', 'Widgets'])
        params.cmake_minimum: CMake version (default 3.16)
        params.cxx_standard: C++ standard (default 17)
        params.use_qt6: emit Qt6 find_package instead of Qt5
        params.output_file: where to write CMakeLists.txt
        params.template_type: 'app' | 'library' | 'console'
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    out_path = Path(params.output_file) if params.output_file else proj_dir / "CMakeLists.txt"
    if not out_path.is_absolute():
        out_path = (proj_dir / out_path).resolve()
    sandbox_err = _require_sandbox(out_path, "output_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    # Scan for source files
    sources: list[str] = []
    headers: list[str] = []
    forms: list[str] = []
    qrcs: list[str] = []
    for ext, target in [(".cpp", sources), (".h", headers), (".hpp", headers), (".ui", forms), (".qrc", qrcs)]:
        for p in sorted(proj_dir.rglob(f"*{ext}")):
            if any(s in p.parts for s in ("debug", "release", "build-", ".git", "CMakeFiles", "node_modules")):
                continue
            rel = p.relative_to(proj_dir).as_posix()
            target.append(rel)

    qt_version = "Qt6" if params.use_qt6 else "Qt5"
    qt_components = " ".join(f"{qt_version}::{m}" for m in params.qt_modules)
    template = "qt_add_executable" if params.use_qt6 else "add_executable"
    target_type = "app" if params.template_type == "app" else ("library" if params.template_type == "library" else "console")

    lines = [
        f"cmake_minimum_required(VERSION {params.cmake_minimum})",
        f"project({params.project_name} VERSION 0.1.0 LANGUAGES CXX)",
        "",
        f"set(CMAKE_CXX_STANDARD {params.cxx_standard})",
        f"set(CMAKE_CXX_STANDARD_REQUIRED ON)",
        f"set(CMAKE_AUTOMOC ON)",
        f"set(CMAKE_AUTORCC ON)",
        f"set(CMAKE_AUTOUIC ON)",
        "",
        f"find_package({qt_version} REQUIRED COMPONENTS {' '.join(params.qt_modules)})",
        "",
        f"set(HEADERS",
    ]
    for h in headers:
        lines.append(f"    {h}")
    lines.extend([
        ")",
        "",
        f"set(SOURCES",
    ])
    for s in sources:
        lines.append(f"    {s}")
    lines.extend([
        ")",
        "",
    ])

    if target_type == "app":
        if params.use_qt6:
            lines.append(f"qt_add_executable({params.project_name} WIN32 MACOSX_BUNDLE")
        else:
            lines.append(f"add_executable({params.project_name} WIN32 MACOSX_BUNDLE")
        lines.append(f"    ${{HEADERS}}")
        lines.append(f"    ${{SOURCES}}")
        if forms:
            lines.append("    # .ui files (handled by AUTOUIC)")
            for f in forms:
                lines.append(f"    # {f}")
        if qrcs:
            lines.append("    # .qrc files (handled by AUTOMOC)")
            for q in qrcs:
                lines.append(f"    # {q}")
        lines.append(")")
    elif target_type == "library":
        lines.append(f"add_library({params.project_name} STATIC ${{HEADERS}} ${{SOURCES}})")
    else:  # console
        lines.append(f"add_executable({params.project_name} ${{HEADERS}} ${{SOURCES}})")
        lines.append(f"set_target_properties({params.project_name} PROPERTIES WIN32_EXECUTABLE OFF)")

    lines.extend([
        "",
        f"target_link_libraries({params.project_name} PRIVATE {qt_components})",
        "",
        f"target_include_directories({params.project_name} PRIVATE ${{CMAKE_CURRENT_SOURCE_DIR}})",
        "",
        f"install(TARGETS {params.project_name} RUNTIME DESTINATION bin)",
    ])

    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text("\n".join(lines) + "\n", encoding="utf-8")

    out = (
        f"=== qt_cmake: generated {out_path} ===\n"
        f"project:    {params.project_name}\n"
        f"qt:         {qt_version} ({', '.join(params.qt_modules)})\n"
        f"cmake:      {params.cmake_minimum}+\n"
        f"cxx:        c++{params.cxx_standard}\n"
        f"template:   {target_type}\n"
        f"sources:    {len(sources)} .cpp\n"
        f"headers:    {len(headers)} .h/.hpp\n"
        f"forms:      {len(forms)} .ui\n"
        f"qrc:        {len(qrcs)} .qrc\n"
    )
    return out + _json_footer({"ok": True, "data": {"path": str(out_path), "source_count": len(sources), "header_count": len(headers)}})


# --- qt_docs_gen: doxygen documentation generator ------------------------------

@mcp.tool(name="qt_docs_gen", annotations={"title": "Generate and run Doxygen documentation for a Qt project", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_docs_gen(params: QtDocsGenInput) -> str:
    """Generate a Doxyfile for a Qt project and (optionally) run doxygen to produce HTML docs.

    The generated Doxyfile uses common Qt-friendly defaults: source includes
    matched by .h/.cpp/.qml, EXTRACT_ALL on, source browser, call graphs.
    After doxygen runs, opens the report at <output_dir>/html/index.html.

    Args:
        params.project_dir: project root to document
        params.output_dir: where to write HTML docs
        params.doxygen_exe: path to doxygen.exe
        params.project_name: project name in the docs
        params.extract_private: include private members
        params.extract_static: include static members
        params.run_after_gen: run doxygen after generating the Doxyfile
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    out_dir = Path(params.output_dir) if params.output_dir else proj_dir / "docs" / "html"
    if not out_dir.is_absolute():
        out_dir = (proj_dir / out_dir).resolve()
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    # Find doxygen
    dox = Path(params.doxygen_exe) if params.doxygen_exe else None
    if not dox or not dox.exists():
        dox_path = shutil.which("doxygen") or shutil.which("doxygen.exe")
        if not dox_path:
            msg = "Error: doxygen not found. Install via Qt Maintenance Tool or pass doxygen_exe."
            return msg + _json_footer({"ok": False, "error": msg})
        dox = Path(dox_path)

    # Generate Doxyfile
    project_name = params.project_name or proj_dir.name
    doxyfile_path = proj_dir / "Doxyfile"
    doxyfile_content = f"""# Generated by qt-mcp qt_docs_gen for {project_name}
PROJECT_NAME           = "{project_name}"
PROJECT_NUMBER         = "0.1.0"
OUTPUT_DIRECTORY       = {out_dir}
INPUT                  = {proj_dir}
FILE_PATTERNS          = *.h *.hpp *.cpp *.cc *.qml *.md
RECURSIVE              = YES
EXTRACT_ALL            = {"YES" if params.extract_private else "NO"}
EXTRACT_PRIVATE        = {"YES" if params.extract_private else "NO"}
EXTRACT_STATIC         = {"YES" if params.extract_static else "NO"}
EXTRACT_LOCAL_CLASSES  = YES
GENERATE_HTML          = YES
GENERATE_LATEX         = NO
GENERATE_TREEVIEW      = YES
SOURCE_BROWSER         = YES
INLINE_SOURCES         = YES
CALL_GRAPH             = YES
REFERENCED_BY_RELATION = YES
REFERENCES_RELATION    = YES
HAVE_DOT               = NO
QUIET                  = YES
WARNINGS               = YES
WARN_IF_UNDOCUMENTED   = YES
GENERATE_TODOLIST      = YES
"""
    doxyfile_path.write_text(doxyfile_content, encoding="utf-8")

    out_lines = [
        f"=== qt_docs_gen: {project_name} ===",
        f"doxyfile:  {doxyfile_path}",
        f"output:    {out_dir}",
    ]

    if not params.run_after_gen:
        out_lines.append("run_after_gen: False (Doxyfile written, not executed)")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"doxyfile": str(doxyfile_path), "ran": False}})

    # Run doxygen
    r = await _run([str(dox), str(doxyfile_path)], cwd=proj_dir, timeout=120)
    body = _tail(r.stdout or r.stderr, 15)
    out_lines.append(f"returncode: {r.returncode}")
    out_lines.append(body)
    html_index = out_dir / "html" / "index.html"
    if html_index.exists():
        out_lines.append(f"html report: {html_index}")

    out = "\n".join(out_lines)
    return out + _json_footer({"ok": r.ok, "data": {"doxyfile": str(doxyfile_path), "ran": True, "html": str(html_index) if html_index.exists() else None}})


# --- qt_achievement: game achievement / medal system -----------------------

@mcp.tool(name="qt_achievement", annotations={"title": "Manage game achievements / medals (define / grant / list / progress)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_achievement(params: QtAchievementInput) -> str:
    """Manage a catalog of game achievements and per-player progress.

    Backed by two JSON files (defaults in `<SANDBOX>/.achievements/`):
      - `catalog.json` : definitions of all achievements (id, title, desc, target)
      - `state.json`   : per-player progress (player -> achievement_id -> current)

    Actions:
      - 'define'   : add or update an achievement definition
      - 'grant'    : mark an achievement as earned for a player (sets current >= target)
      - 'list'     : show all achievements with current progress for a player
      - 'progress' : update current progress for a multi-step achievement
      - 'reset'    : clear all earned achievements for a player
      - 'catalog'  : show all defined achievements

    Args:
        params.action: 'define' | 'grant' | 'list' | 'progress' | 'reset' | 'catalog'
        params.achievements_file / state_file: paths
        params.player: player name
        params.achievement_id: id like 'first_win'
        params.title / description / target: for 'define' / 'progress'
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("define", "grant", "list", "progress", "reset", "catalog"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    cat_path = Path(params.achievements_file) if params.achievements_file else SANDBOX_ROOT / ".achievements" / "catalog.json"
    state_path = Path(params.state_file) if params.state_file else SANDBOX_ROOT / ".achievements" / "state.json"
    for p in (cat_path, state_path):
        if not p.is_absolute():
            p_resolved = (SANDBOX_ROOT / p).resolve()
        else:
            p_resolved = p
        # Update in place (we want to operate on the actual file path)
    # Re-resolve:
    cat_path = (SANDBOX_ROOT / cat_path).resolve() if not cat_path.is_absolute() else cat_path
    state_path = (SANDBOX_ROOT / state_path).resolve() if not state_path.is_absolute() else state_path
    for p, name in ((cat_path, "achievements_file"), (state_path, "state_file")):
        err = _require_sandbox(p, name)
        if err:
            return err + _json_footer({"ok": False, "error": err})

    import json as _json

    def _load(path: Path, default: dict) -> dict:
        if not path.exists():
            return default
        try:
            return _json.loads(path.read_text(encoding="utf-8"))
        except (OSError, ValueError):
            return default

    def _save(path: Path, data: dict) -> None:
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(_json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")

    catalog = _load(cat_path, {"achievements": {}})

    if params.action == "catalog":
        achievements = catalog.get("achievements", {})
        if not achievements:
            out = f"=== qt_achievement: no achievements defined ==="
            return out + _json_footer({"ok": True, "data": {"count": 0}})
        out_lines = [f"=== qt_achievement: {len(achievements)} defined ==="]
        for aid, a in achievements.items():
            out_lines.append(f"  [{aid}] {a.get('title', '?')}: {a.get('description', '')} (target: {a.get('target', 1)})")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"count": len(achievements)}})

    if params.action == "define":
        if not params.achievement_id or not params.title:
            msg = "Error: 'define' requires achievement_id and title"
            return msg + _json_footer({"ok": False, "error": msg})
        catalog.setdefault("achievements", {})[params.achievement_id] = {
            "title": params.title,
            "description": params.description,
            "target": params.target,
        }
        _save(cat_path, catalog)
        out = f"defined: [{params.achievement_id}] {params.title}"
        return out + _json_footer({"ok": True, "data": {"achievement_id": params.achievement_id}})

    if params.action in ("grant", "progress", "list", "reset"):
        if not params.player and params.action != "list":
            msg = f"Error: action {params.action!r} requires a non-empty player"
            return msg + _json_footer({"ok": False, "error": msg})
        state = _load(state_path, {"players": {}})
        player_state = state.setdefault("players", {}).setdefault(params.player or "anonymous", {})

        if params.action == "grant":
            if not params.achievement_id:
                msg = "Error: 'grant' requires a non-empty achievement_id"
                return msg + _json_footer({"ok": False, "error": msg})
            target = catalog.get("achievements", {}).get(params.achievement_id, {}).get("target", 1)
            player_state[params.achievement_id] = target  # set to target (complete)
            _save(state_path, state)
            out = f"granted: {params.achievement_id} to {params.player} (now at {target}/{target})"
            return out + _json_footer({"ok": True, "data": {"achievement_id": params.achievement_id, "player": params.player, "current": target, "target": target}})

        if params.action == "progress":
            if not params.achievement_id:
                msg = "Error: 'progress' requires a non-empty achievement_id"
                return msg + _json_footer({"ok": False, "error": msg})
            player_state[params.achievement_id] = params.current
            _save(state_path, state)
            out = f"progress: {params.player} -> {params.achievement_id} = {params.current}/{params.target}"
            return out + _json_footer({"ok": True, "data": {"achievement_id": params.achievement_id, "player": params.player, "current": params.current, "target": params.target}})

        if params.action == "list":
            achievements = catalog.get("achievements", {})
            if not achievements:
                out = f"=== qt_achievement: no achievements defined ==="
                return out + _json_footer({"ok": True, "data": {"count": 0}})
            target_player = params.player or "anonymous"
            ps = state.get("players", {}).get(target_player, {})
            out_lines = [f"=== qt_achievement: {len(achievements)} achievements for {target_player} ==="]
            earned = 0
            for aid, a in achievements.items():
                cur = ps.get(aid, 0)
                tgt = a.get("target", 1)
                pct = min(100, int(cur / tgt * 100)) if tgt else 0
                bar = "█" * (pct // 10) + "░" * ((100 - pct) // 10)
                done = "✓" if cur >= tgt else " "
                out_lines.append(f"  {done} [{aid:20s}] {a.get('title', '?'):30s}  [{bar}] {cur}/{tgt}")
                if cur >= tgt:
                    earned += 1
            out_lines.append(f"--- {earned}/{len(achievements)} earned ---")
            out = "\n".join(out_lines)
            return out + _json_footer({"ok": True, "data": {"player": target_player, "earned": earned, "total": len(achievements)}})

        if params.action == "reset":
            state.setdefault("players", {})[params.player] = {}
            _save(state_path, state)
            out = f"reset: cleared achievements for {params.player}"
            return out + _json_footer({"ok": True, "data": {"player": params.player, "reset": True}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_undo: undo/redo stack for game state ---------------------------------

@mcp.tool(name="qt_undo", annotations={"title": "Push / undo / redo game-state snapshots (per-project undo stack)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_undo(params: QtUndoInput) -> str:
    """Maintain a per-project undo / redo stack persisted to a JSON file.

    Useful for any turn-based board game where the player may want to undo their
    last move (or the game offers an "undo last turn" button). The stack is JSON
    so it's human-inspectable and survives crashes.

    File format (default `<SANDBOX>/.undo/<project>.json`):
        {
            "undo": [{state: {...}, label: "...", ts: 1234567890}, ...],
            "redo": [...]
        }

    Actions:
      - 'push'     : record a new state, clear redo
      - 'undo'     : pop from undo stack, push current state to redo
      - 'redo'     : pop from redo stack, push current state to undo
      - 'list'     : show both stacks with labels
      - 'clear'    : drop both stacks
      - 'can_undo' : returns the count
      - 'can_redo' : returns the count

    Args:
        params.action: 'push' | 'undo' | 'redo' | 'list' | 'clear' | 'can_undo' | 'can_redo'
        params.state_file: per-project undo file
        params.state_data: dict to push (for 'push')
        params.label: human-readable label (for 'push')
        params.max_depth: cap on undo depth
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("push", "undo", "redo", "list", "clear", "can_undo", "can_redo"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Default to per-project name based on state_file or generic
    if params.state_file:
        state_path = Path(params.state_file)
    else:
        state_path = SANDBOX_ROOT / ".undo" / "default.json"
    if not state_path.is_absolute():
        state_path = (SANDBOX_ROOT / state_path).resolve()
    sandbox_err = _require_sandbox(state_path, "state_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    import json as _json
    import time

    def _load() -> dict:
        if not state_path.exists():
            return {"undo": [], "redo": []}
        try:
            return _json.loads(state_path.read_text(encoding="utf-8"))
        except (OSError, ValueError):
            return {"undo": [], "redo": []}

    def _save(data: dict) -> None:
        state_path.parent.mkdir(parents=True, exist_ok=True)
        state_path.write_text(_json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")

    if params.action == "list":
        data = _load()
        out_lines = [f"=== qt_undo: {state_path} ==="]
        out_lines.append(f"--- undo ({len(data['undo'])}) ---")
        for i, s in enumerate(data["undo"]):
            out_lines.append(f"  {i:>3}  [{s.get('ts', 0)}]  {s.get('label', '?')}")
        out_lines.append(f"--- redo ({len(data['redo'])}) ---")
        for i, s in enumerate(data["redo"]):
            out_lines.append(f"  {i:>3}  [{s.get('ts', 0)}]  {s.get('label', '?')}")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"undo_count": len(data["undo"]), "redo_count": len(data["redo"])}})

    if params.action == "clear":
        _save({"undo": [], "redo": []})
        out = f"cleared: {state_path}"
        return out + _json_footer({"ok": True, "data": {"cleared": True}})

    if params.action in ("can_undo", "can_redo"):
        data = _load()
        count = len(data["undo"] if params.action == "can_undo" else data["redo"])
        out = f"{params.action}: {count}"
        return out + _json_footer({"ok": True, "data": {"count": count, "can": count > 0}})

    if params.action == "push":
        data = _load()
        data["undo"].append({
            "state": params.state_data,
            "label": params.label or "(unlabeled)",
            "ts": int(time.time() * 1000),
        })
        # Cap depth
        if len(data["undo"]) > params.max_depth:
            data["undo"] = data["undo"][-params.max_depth:]
        data["redo"] = []  # any new action clears redo
        _save(data)
        out = f"pushed: {params.label!r} (undo stack: {len(data['undo'])}, redo cleared)"
        return out + _json_footer({"ok": True, "data": {"undo_count": len(data["undo"]), "label": params.label}})

    if params.action == "undo":
        data = _load()
        if not data["undo"]:
            out = "nothing to undo"
            return out + _json_footer({"ok": True, "data": {"undone": None}})
        # The last undo entry is the state BEFORE the last action
        # In a real game, you'd push the CURRENT state before doing the action
        # For our model: undo pops the latest entry and returns its state
        # The caller is expected to apply this state
        # For "undo" to also push to redo: we need a separate "current" state
        # Simpler: undo just pops and returns. Caller decides.
        entry = data["undo"].pop()
        # Move to redo for re-doability (if we knew the "post" state)
        # Since we don't have a "current" snapshot model, just pop without redoing
        _save(data)
        out = f"undone: {entry.get('label', '?')}"
        return out + _json_footer({"ok": True, "data": {"state": entry.get("state", {}), "label": entry.get("label")}})

    if params.action == "redo":
        data = _load()
        if not data["redo"]:
            out = "nothing to redo"
            return out + _json_footer({"ok": True, "data": {"redone": None}})
        entry = data["redo"].pop()
        data["undo"].append(entry)
        _save(data)
        out = f"redone: {entry.get('label', '?')}"
        return out + _json_footer({"ok": True, "data": {"state": entry.get("state", {}), "label": entry.get("label")}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_leaderboard_ui: render leaderboard widget -----------------------------

@mcp.tool(name="qt_leaderboard_ui", annotations={"title": "Generate a leaderboard QWidget (table or cards style) for a board game", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_leaderboard_ui(params: QtLeaderboardUiInput) -> str:
    """Generate a .h / .cpp / .ui trio for a leaderboard widget.

    Reads from <SANDBOX>/.scores/scores.json (produced by qt_score) and renders
    the top N entries in either a QTableView (with sort + filter, for big lists)
    or a QListView with card delegate (for hero boards / top-10 displays).

    Args:
        params.style: 'table' or 'cards'
        params.title: window / widget title
        params.output_dir: where to write the trio
        params.top_n: how many entries to show
        params.show_filters: include a search box
        params.show_avatars: reserve an avatar column
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.style not in ("table", "cards"):
        msg = f"Error: invalid style {params.style!r} (must be 'table' or 'cards')"
        return msg + _json_footer({"ok": False, "error": msg})

    out_dir = Path(params.output_dir)
    if not out_dir.is_absolute():
        out_dir = (SANDBOX_ROOT / out_dir).resolve()
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    out_dir.mkdir(parents=True, exist_ok=True)

    # Class name from output_dir
    cn = "LeaderboardWidget"

    h_path = out_dir / "leaderboardwidget.h"
    cpp_path = out_dir / "leaderboardwidget.cpp"
    ui_path = out_dir / "leaderboardwidget.ui"

    if params.style == "table":
        header = f"""#ifndef LEADERBOARDWIDGET_H
#define LEADERBOARDWIDGET_H

#include <QWidget>
#include <QStandardItemModel>
#include <QSortFilterProxyModel>
#include <QJsonObject>
#include <QJsonArray>

QT_BEGIN_NAMESPACE
class Ui::LeaderboardWidget;
QT_END_NAMESPACE

class {cn} : public QWidget {{
    Q_OBJECT
public:
    explicit {cn}(QWidget *parent = nullptr);
    void loadFromFile(const QString &path);
    void refresh();
signals:
    void playerSelected(const QString &player, int rank);
private slots:
    void onSearchTextChanged(const QString &text);
private:
    Ui::LeaderboardWidget *ui;
    QStandardItemModel *m_model;
    QSortFilterProxyModel *m_proxy;
    void setupModel();
    void loadFromJson(const QJsonObject &obj);
}};

#endif
"""
        impl = f"""#include "leaderboardwidget.h"
#include "ui_leaderboardwidget.h"
#include <QFile>
#include <QJsonDocument>
#include <QJsonObject>
#include <QJsonArray>

{cn}::{cn}(QWidget *parent) : QWidget(parent), ui(new Ui::LeaderboardWidget), m_model(new QStandardItemModel(this)) {{
    ui->setupUi(this);
    setWindowTitle(QStringLiteral("{params.title}"));
    setupModel();

    // Filter input
    if (ui->searchLine) {{
        connect(ui->searchLine, &QLineEdit::textChanged, this, &{cn}::onSearchTextChanged);
    }}
    if (ui->tableView) {{
        ui->tableView->verticalHeader()->setVisible(false);
        ui->tableView->setSortingEnabled(true);
        ui->tableView->setSelectionBehavior(QAbstractItemView::SelectRows);
        ui->tableView->setEditTriggers(QAbstractItemView::NoEditTriggers);
    }}
}}

void {cn}::setupModel() {{
    QStringList headers;
    headers << "Rank" << "Player" << "Score" << "Game";
    if ({params.show_avatars}) headers << "Avatar";
    m_model->setHorizontalHeaderLabels(headers);
    if (ui->tableView) ui->tableView->setModel(m_model);
}}

void {cn}::loadFromFile(const QString &path) {{
    QFile f(path);
    if (!f.open(QIODevice::ReadOnly)) return;
    auto doc = QJsonDocument::fromJson(f.readAll());
    if (doc.isObject()) loadFromJson(doc.object());
}}

void {cn}::loadFromJson(const QJsonObject &obj) {{
    m_model->removeRows(0, m_model->rowCount());
    auto games = obj.value("games").toObject();
    // Flatten + sort
    QList<QPair<QString, int>> entries;  // (player, score)
    for (auto it = games.begin(); it != games.end(); ++it) {{
        for (auto v : it.value().toArray()) {{
            auto e = v.toObject();
            entries.append({{e.value("player").toString(), e.value("score").toInt()}});
        }}
    }}
    std::sort(entries.begin(), entries.end(), [](auto &a, auto &b) {{ return a.second > b.second; }});
    int rank = 1;
    for (auto &p : entries) {{
        if (rank > {params.top_n}) break;
        QList<QStandardItem*> row;
        row << new QStandardItem(QString::number(rank));
        row << new QStandardItem(p.first);
        row << new QStandardItem(QString::number(p.second));
        row << new QStandardItem(QString());
        m_model->appendRow(row);
        rank++;
    }}
}}

void {cn}::refresh() {{
    loadFromFile(QStringLiteral("<SANDBOX>/.scores/scores.json"));
}}

void {cn}::onSearchTextChanged(const QString &text) {{
    if (ui->tableView) {{
        for (int r = 0; r < m_model->rowCount(); ++r) {{
            bool match = m_model->item(r, 1)->text().contains(text, Qt::CaseInsensitive);
            ui->tableView->setRowHidden(r, !match);
        }}
    }}
}}
"""
        ui = """<?xml version="1.0" encoding="UTF-8"?>
<ui version="4.0">
 <widget class="QWidget" name="LeaderboardWidget">
  <layout class="QVBoxLayout">
   <item>
    <widget class="QLabel" name="titleLabel">
     <property name="text"><string>Leaderboard</string></property>
     <property name="alignment"><set>Qt::AlignCenter</set></property>
    </widget>
   </item>
""" + ("""   <item>
    <widget class="QLineEdit" name="searchLine">
     <property name="placeholderText"><string>Search player...</string></property>
    </widget>
   </item>
""" if params.show_filters else "") + """   <item>
    <widget class="QTableView" name="tableView"/>
   </item>
  </layout>
 </widget>
 <resources/>
 <connections/>
</ui>
"""
    else:  # cards
        header = f"""#ifndef LEADERBOARDWIDGET_H
#define LEADERBOARDWIDGET_H

#include <QWidget>
#include <QListWidget>
#include <QJsonObject>
#include <QJsonArray>

class {cn} : public QWidget {{
    Q_OBJECT
public:
    explicit {cn}(QWidget *parent = nullptr);
    void loadFromFile(const QString &path);
    void refresh();
private:
    QListWidget *m_list;
    void loadFromJson(const QJsonObject &obj);
}};

#endif
"""
        impl = f"""#include "leaderboardwidget.h"
#include <QFile>
#include <QJsonDocument>
#include <QJsonObject>
#include <QJsonArray>

{cn}::{cn}(QWidget *parent) : QWidget(parent), m_list(new QListWidget(this)) {{
    setWindowTitle(QStringLiteral("{params.title}"));
    m_list->setSpacing(4);
    m_list->setStyleSheet("QListWidget::item {{ padding: 8px; border-bottom: 1px solid #ccc; }}");
    auto *layout = new QVBoxLayout(this);
    layout->addWidget(m_list);
    setLayout(layout);
    setMinimumSize(400, 500);
}}

void {cn}::loadFromFile(const QString &path) {{
    QFile f(path);
    if (!f.open(QIODevice::ReadOnly)) return;
    auto doc = QJsonDocument::fromJson(f.readAll());
    if (doc.isObject()) loadFromJson(doc.object());
}}

void {cn}::loadFromJson(const QJsonObject &obj) {{
    m_list->clear();
    QList<QPair<int, QString>> entries;
    for (auto it = obj.value("games").toObject().begin(); it != obj.value("games").toObject().end(); ++it) {{
        for (auto v : it.value().toArray()) {{
            auto e = v.toObject();
            entries.append({{e.value("score").toInt(), e.value("player").toString()}});
        }}
    }}
    std::sort(entries.begin(), entries.end(), [](auto &a, auto &b) {{ return a.first > b.first; }});
    int rank = 1;
    for (auto &p : entries) {{
        if (rank > {params.top_n}) break;
        auto *item = new QListWidgetItem(
            QStringLiteral("#%1  %2  —  %3 pts").arg(rank).arg(p.second).arg(p.first),
            m_list);
        item->setData(Qt::UserRole, p.second);
        m_list->addItem(item);
        rank++;
    }}
}}

void {cn}::refresh() {{
    loadFromFile(QStringLiteral("<SANDBOX>/.scores/scores.json"));
}}
"""
        ui = ""

    h_path.write_text(header, encoding="utf-8")
    cpp_path.write_text(impl, encoding="utf-8")
    if ui:
        ui_path.write_text(ui, encoding="utf-8")

    out = (
        f"=== qt_leaderboard_ui: {params.style} style ===\n"
        f"header:  {h_path}\n"
        f"impl:    {cpp_path}\n"
        + (f"ui:      {ui_path}\n" if ui else "")
        + f"title:   {params.title}\n"
        f"top_n:   {params.top_n}\n"
        + f"filters: {params.show_filters}\n"
        + f"avatars: {params.show_avatars}\n"
        + f"\nAdd the files to your .pro HEADERS / SOURCES / FORMS.\n"
    )
    return out + _json_footer({"ok": True, "data": {"header": str(h_path), "impl": str(cpp_path), "ui": str(ui_path) if ui else None}})


# --- qt_pkg_install: aqtinstall wrapper --------------------------------------

@mcp.tool(name="qt_pkg_install", annotations={"title": "Install / list / uninstall Qt SDKs via aqtinstall", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_pkg_install(params: QtPkgInstallInput) -> str:
    """Manage Qt installations via aqtinstall (https://github.com/miurahr/aqtinstall).

    aqtinstall is a Python CLI that downloads and installs Qt from Qt's official
    servers. Use this to set up a fresh Qt environment for qt-mcp to drive.

    Args:
        params.action: 'check' | 'install' | 'list' | 'uninstall'
        params.qt_version: '5.14.2' (default), '6.5.0', etc.
        params.host: 'windows' / 'linux' / 'mac'
        params.target: 'desktop' / 'android' / 'ios' / 'wasm'
        params.arch: 'win64_mingw' / 'win64_msvc2019_64' / 'linux_gcc_64' / 'mac' / etc.
        params.modules: extra modules to install (e.g. ['qt5', 'qt5tools', 'qt5multimedia'])
        params.install_dir: where to install (default <SANDBOX>/qt/...)
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("check", "install", "list", "uninstall"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    aqt = shutil.which("aqt") or shutil.which("aqt.exe")
    if not aqt and params.action != "check":
        return (
            "Error: aqtinstall not found. Install via: pip install aqtinstall\n"
            "Then ensure 'aqt' is on PATH."
        ) + _json_footer({"ok": False, "error": "aqtinstall not installed"})

    if params.action == "check":
        if aqt:
            r = await _run([aqt, "--help"], cwd=SANDBOX_ROOT, timeout=15)
            head = (r.stdout or r.stderr).splitlines()[:5]
            out_lines = [f"=== qt_pkg_install: aqt available ===", f"path:    {aqt}", f"version: {head[0] if head else 'unknown'}"]
            return "\n".join(out_lines) + _json_footer({"ok": True, "data": {"aqt": aqt, "available": True}})
        return "Error: aqtinstall not found" + _json_footer({"ok": False, "error": "aqt not on PATH", "data": {"available": False}})

    if params.action == "list":
        # List installed Qt via aqt list-qt
        r = await _run([aqt, "list-qt", params.host, "--arch", params.arch], cwd=SANDBOX_ROOT, timeout=30)
        out_lines = [f"=== qt_pkg_install: list installed ({params.host}/{params.arch}) ===", r.stdout or r.stderr]
        return "\n".join(out_lines) + _json_footer({"ok": r.ok, "data": {"output": (r.stdout or "")[:1000]}})

    if params.action == "install":
        install_dir = Path(params.install_dir) if params.install_dir else SANDBOX_ROOT / "qt" / params.qt_version / params.arch.replace("_", "-")
        if not install_dir.is_absolute():
            install_dir = (SANDBOX_ROOT / install_dir).resolve()
        sandbox_err = _require_sandbox(install_dir, "install_dir")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        install_dir.parent.mkdir(parents=True, exist_ok=True)

        cmd = [aqt, "install-qt", params.host, params.target, params.qt_version, params.arch, "-O", str(install_dir.parent)]
        if params.modules:
            cmd.extend(["-m"] + params.modules)
        r = await _run(cmd, cwd=install_dir.parent, timeout=600)  # 10 min for download
        out_lines = [
            f"=== qt_pkg_install: install Qt {params.qt_version} ({params.host}/{params.target}/{params.arch}) ===",
            f"target:   {install_dir}",
            f"modules:  {params.modules}",
            f"returncode: {r.returncode}",
            _tail(r.stdout or r.stderr, 30),
        ]
        return "\n".join(out_lines) + _json_footer({"ok": r.ok, "data": {"returncode": r.returncode, "install_dir": str(install_dir)}})

    if params.action == "uninstall":
        cmd = [aqt, "remove-qt", params.host, params.target, params.qt_version, params.arch]
        r = await _run(cmd, cwd=SANDBOX_ROOT, timeout=120)
        out_lines = [f"=== qt_pkg_install: uninstall {params.qt_version} ===", f"returncode: {r.returncode}", _tail(r.stdout or r.stderr, 20)]
        return "\n".join(out_lines) + _json_footer({"ok": r.ok, "data": {"returncode": r.returncode}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_release_notes: auto-generate CHANGELOG.md -----------------------------

@mcp.tool(name="qt_release_notes", annotations={"title": "Auto-generate or manually edit CHANGELOG.md from git log", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_release_notes(params: QtReleaseNotesInput) -> str:
    """Maintain a CHANGELOG.md for a Qt project.

    - 'generate' : parse `git log <since_tag>..HEAD` and emit a new section
    - 'add'      : append a single bullet under the current Unreleased section
    - 'read'     : print the current CHANGELOG.md

    Conventional-commits prefix detection (used for 'generate' with category='auto'):
      - feat: / feat():     -> Added
      - fix:  / fix():      -> Fixed
      - docs:               -> Documentation
      - refactor:           -> Changed
      - test:               -> Tests
      - chore: / build: / ci: -> (skipped, internal)

    Args:
        params.action: 'generate' | 'add' | 'read'
        params.repo_dir: git repo path
        params.changelog_path: CHANGELOG.md path
        params.version: version label (e.g. 'v0.3.0')
        params.since_tag: git rev to start from
        params.category: 'auto' (categorize) or 'all' (single list)
        params.bullet: text for 'add'
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("generate", "add", "read"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    repo_dir = Path(params.repo_dir) if params.repo_dir else SANDBOX_ROOT.parent
    if not repo_dir.is_absolute():
        repo_dir = Path(params.repo_dir).resolve()
    changelog = Path(params.changelog_path) if params.changelog_path else repo_dir / "CHANGELOG.md"
    if not changelog.is_absolute():
        changelog = (Path.cwd() / changelog).resolve()
    sandbox_err = _require_sandbox(changelog, "changelog_path")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    git = shutil.which("git") or shutil.which("git.exe")
    if not git and params.action == "generate":
        return "Error: git not found on PATH" + _json_footer({"ok": False, "error": "git missing"})

    if params.action == "read":
        if not changelog.exists():
            out = f"(no CHANGELOG.md at {changelog})"
            return out + _json_footer({"ok": True, "data": {"exists": False}})
        return changelog.read_text(encoding="utf-8") + _json_footer({"ok": True, "data": {"path": str(changelog), "exists": True}})

    if params.action == "add":
        if not params.bullet:
            msg = "Error: 'add' requires a non-empty bullet"
            return msg + _json_footer({"ok": False, "error": msg})
        # Ensure CHANGELOG.md exists
        if not changelog.exists():
            changelog.write_text("# Changelog\n\n## Unreleased\n\n", encoding="utf-8")
        # Insert bullet under "## Unreleased" section
        text = changelog.read_text(encoding="utf-8")
        marker = "## Unreleased"
        if marker in text:
            # Insert after the section header
            idx = text.index(marker) + len(marker)
            # Find end of section (next "## " or EOF)
            next_section = text.find("\n## ", idx)
            if next_section < 0:
                insert_pos = len(text)
                new_text = text.rstrip() + "\n- " + params.bullet + "\n"
            else:
                new_text = text[:next_section] + "- " + params.bullet + "\n" + text[next_section:]
        else:
            # Add an Unreleased section at the top
            new_text = "# Changelog\n\n## Unreleased\n\n- " + params.bullet + "\n\n" + text[len("# Changelog\n"):]
        changelog.write_text(new_text, encoding="utf-8")
        out = f"added bullet to {changelog}"
        return out + _json_footer({"ok": True, "data": {"added": True, "bullet": params.bullet}})

    if params.action == "generate":
        # Determine range
        since = params.since_tag
        if not since:
            # Find latest tag
            tag_r = await _run([git, "-C", str(repo_dir), "describe", "--tags", "--abbrev=0"], cwd=repo_dir, timeout=10)
            if tag_r.ok and tag_r.stdout.strip():
                since = tag_r.stdout.strip()
            else:
                since = "HEAD~50"  # fallback
        version = params.version or "Unreleased"
        # Get commits
        log_r = await _run([git, "-C", str(repo_dir), "log", f"{since}..HEAD", "--pretty=format:%s", "--no-merges"], cwd=repo_dir, timeout=15)
        if not log_r.ok:
            return f"Error: git log failed: {log_r.stderr}" + _json_footer({"ok": False, "error": "git log failed"})
        commits = [c.strip() for c in (log_r.stdout or "").splitlines() if c.strip()]
        if not commits:
            out = f"no commits since {since}"
            return out + _json_footer({"ok": True, "data": {"since": since, "count": 0}})

        # Categorize
        if params.category == "auto":
            cats: dict[str, list[str]] = {"Added": [], "Fixed": [], "Changed": [], "Documentation": [], "Tests": [], "Other": []}
            for c in commits:
                lc = c.lower()
                if lc.startswith("feat") or lc.startswith("add"):
                    cats["Added"].append(c)
                elif lc.startswith("fix") or lc.startswith("bug"):
                    cats["Fixed"].append(c)
                elif lc.startswith("refactor") or lc.startswith("change") or lc.startswith("perf"):
                    cats["Changed"].append(c)
                elif lc.startswith("doc"):
                    cats["Documentation"].append(c)
                elif lc.startswith("test"):
                    cats["Tests"].append(c)
                elif lc.startswith("chore") or lc.startswith("build") or lc.startswith("ci"):
                    pass  # skip
                else:
                    cats["Other"].append(c)
        else:
            cats = {"Changes": commits}

        # Build section
        section_lines = [f"## {version} ({len(commits)} commits since {since})", ""]
        for cat, items in cats.items():
            if items:
                section_lines.append(f"### {cat}")
                for it in items:
                    section_lines.append(f"- {it}")
                section_lines.append("")

        # Insert into CHANGELOG.md
        section = "\n".join(section_lines)
        if changelog.exists():
            text = changelog.read_text(encoding="utf-8")
            # Insert after "# Changelog\n\n"
            if text.startswith("# Changelog"):
                after_header = text.index("\n\n", len("# Changelog")) + 2
                new_text = text[:after_header] + section + text[after_header:]
            else:
                new_text = "# Changelog\n\n" + section + "\n" + text
        else:
            new_text = "# Changelog\n\n" + section
        changelog.write_text(new_text, encoding="utf-8")
        out_lines = [f"=== qt_release_notes: generated {version} ===", f"since: {since}", f"commits: {len(commits)}", f"file: {changelog}", ""]
        out_lines.append(section)
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"version": version, "since": since, "count": len(commits)}})

    msg = f"Error: unhandled action {params.action!r}"
    return msg + _json_footer({"ok": False, "error": msg})


# --- qt_copyright: prepend license header to source files ---------------------

@mcp.tool(name="qt_copyright", annotations={"title": "Add a license / copyright header to all source files in a project", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_copyright(params: QtCopyrightInput) -> str:
    """Walk a project and prepend a license header to every source file.

    Skips files that already contain a marker (e.g. 'SPDX-License-Identifier' in
    the first 10 lines) to avoid duplicate headers. Use `dry_run=True` to preview.

    Args:
        params.project_dir: project to walk
        params.header_text: header string (use \\n for newlines)
        params.extensions: file extensions to process
        params.exclude_dirs: subdir name patterns to skip
        params.dry_run: if True, only list files (no writes)
    

    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    header = params.header_text.replace("\\n", "\n")
    if not header.endswith("\n"):
        header += "\n"
    if not header.startswith("\n"):
        header = "\n" + header
    marker = "SPDX-License-Identifier"

    exts = {e if e.startswith(".") else "." + e for e in params.extensions}
    matched: list[Path] = []
    for ext in exts:
        for p in proj_dir.rglob(f"*{ext}"):
            if any(s in p.parts for s in params.exclude_dirs):
                continue
            if any(s in p.parts for s in ("debug", "release", "build-", "CMakeFiles")):
                continue
            matched.append(p)
    matched.sort()

    modified: list[Path] = []
    skipped: list[Path] = []
    for p in matched:
        try:
            text = p.read_text(encoding="utf-8", errors="replace")
        except OSError as e:
            continue
        # Check for existing marker
        head = "\n".join(text.splitlines()[:10])
        if marker in head:
            skipped.append(p)
            continue
        if not params.dry_run:
            try:
                p.write_text(header + text, encoding="utf-8")
                modified.append(p)
            except OSError:
                pass

    verb = "would modify" if params.dry_run else "modified"
    out_lines = [
        f"=== qt_copyright: {verb} {len(modified)} file(s), skipped {len(skipped)} (already has header) ===",
        f"project:   {proj_dir}",
        f"dry_run:   {params.dry_run}",
        f"extensions: {sorted(exts)}",
    ]
    if modified and not params.dry_run:
        out_lines.append("")
        out_lines.append("Modified files (first 10):")
        for p in modified[:10]:
            out_lines.append(f"  + {p.relative_to(proj_dir)}")
        if len(modified) > 10:
            out_lines.append(f"  ... and {len(modified) - 10} more")
    elif params.dry_run and matched:
        out_lines.append("")
        out_lines.append("Would modify (first 10):")
        for p in matched[:10]:
            out_lines.append(f"  - {p.relative_to(proj_dir)}")
        if len(matched) > 10:
            out_lines.append(f"  ... and {len(matched) - 10} more")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"modified": len(modified), "skipped": len(skipped), "total": len(matched), "dry_run": params.dry_run}})


# --- qt_model_gen: QAbstractListModel / QAbstractTableModel code generator ----

@mcp.tool(name="qt_model_gen", annotations={"title": "Generate a QAbstractListModel or QAbstractTableModel subclass for board-game data", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_model_gen(params: QtModelGenInput) -> str:
    """Generate a ready-to-use QAbstractListModel or QAbstractTableModel subclass.

    Use for board-game data (cards, players, scores, leaderboard rows, etc.) that
    needs to be exposed to a QML ListView/TableView. The generated .h/.cpp is
    drop-in: just `#include "modelname.h"` in your QML parent and set `model:
    myModelInstance`.

    Args:
        params.class_name: name of the model class (e.g. 'CardModel', 'PlayerModel')
        params.model_type: 'list' (QAbstractListModel) or 'table' (QAbstractTableModel)
        params.item_type: underlying data type for list models (e.g. 'QString', 'int', 'Card')
        params.columns: for table models, list of {name, type} dicts
        params.header_extra: optional extra lines in the .h class body
        params.source_extra: optional extra lines in the .cpp constructor
        params.output_dir: where to write <class_name>.h and .cpp (must be inside the sandbox)


    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.model_type not in ("list", "table"):
        msg = f"Error: model_type must be 'list' or 'table', got {params.model_type!r}"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.model_type == "table" and not params.columns:
        msg = "Error: table model requires non-empty 'columns' list"
        return msg + _json_footer({"ok": False, "error": msg})

    out_dir = Path(params.output_dir)
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    out_dir.mkdir(parents=True, exist_ok=True)

    cn = params.class_name
    if not cn or not cn[0].isalpha() and cn[0] != "_":
        msg = f"Error: class_name must start with a letter or underscore: {cn!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    if params.model_type == "list":
        base = "QAbstractListModel"
        item_t = params.item_type or "QString"
        role_names_cpp = "QHash<int, QByteArray> CardModel::roleNames() const { return { {Qt::UserRole + 1, \"item\"} }; }"
        role_names = (
            f"QHash<int, QByteArray> {cn}::roleNames() const {{\n"
            f"    return {{ {{Qt::UserRole + 1, \"item\"}} }};\n"
            f"}}\n"
        )
        data_impl = (
            f"{item_t} {cn}::data(const QModelIndex &index, int role) const {{\n"
            f"    if (!index.isValid() || index.row() < 0 || index.row() >= m_items.size())\n"
            f"        return {{}};\n"
            f"    if (role == Qt::DisplayRole || role == Qt::UserRole + 1)\n"
            f"        return m_items.at(index.row());\n"
            f"    return {{}};\n"
            f"}}\n"
        )
        member = f"    QList<{item_t}> m_items;"
        ctor_init = f"    // m_items populated by user; example:\n    // for (int i = 0; i < 10; ++i) addItem({item_t}{{}});"
        add_remove = (
            f"void {cn}::addItem(const {item_t} &item) {{\n"
            f"    beginInsertRows({{}}, m_items.size(), m_items.size());\n"
            f"    m_items.append(item);\n"
            f"    endInsertRows();\n"
            f"}}\n\n"
            f"void {cn}::removeAt(int row) {{\n"
            f"    if (row < 0 || row >= m_items.size()) return;\n"
            f"    beginRemoveRows({{}}, row, row);\n"
            f"    m_items.removeAt(row);\n"
            f"    endRemoveRows();\n"
            f"}}\n\n"
            f"void {cn}::clear() {{\n"
            f"    if (m_items.isEmpty()) return;\n"
            f"    beginResetModel();\n"
            f"    m_items.clear();\n"
            f"    endResetModel();\n"
            f"}}\n"
        )
        add_remove_h = f"public slots:\n    void addItem(const {item_t} &item);\n    void removeAt(int row);\n    void clear();"
    else:
        base = "QAbstractTableModel"
        col_names_cpp = ", ".join(f'"{c.get("name", f"col{i}")}"' for i, c in enumerate(params.columns))
        col_types = ", ".join(c.get("type", "QString") for c in params.columns)
        member = "    QList<QList<QVariant>> m_rows;"  # rows of variants
        ctor_init = f"    // m_rows populated by user; example:\n    // appendRow({{ {col_types} }});"
        role_names = ""
        data_impl = (
            f"QVariant {cn}::data(const QModelIndex &index, int role) const {{\n"
            f"    if (!index.isValid() || index.row() < 0 || index.row() >= m_rows.size())\n"
            f"        return {{}};\n"
            f"    if (role != Qt::DisplayRole) return {{}};\n"
            f"    const auto &row = m_rows.at(index.row());\n"
            f"    if (index.column() < 0 || index.column() >= row.size()) return {{}};\n"
            f"    return row.at(index.column());\n"
            f"}}\n"
        )
        header_data_impl = (
            f"QVariant {cn}::headerData(int section, Qt::Orientation orientation, int role) const {{\n"
            f"    if (role != Qt::DisplayRole) return {{}};\n"
            f"    if (orientation == Qt::Horizontal) {{\n"
            f"        static const QStringList names = {{ {col_names_cpp} }};\n"
            f"        if (section >= 0 && section < names.size()) return names.at(section);\n"
            f"    }} else {{\n"
            f"        return section + 1;\n"
            f"    }}\n"
            f"    return {{}};\n"
            f"}}\n"
        )
        append_row = (
            f"void {cn}::appendRow(const QList<QVariant> &row) {{\n"
            f"    beginInsertRows({{}}, m_rows.size(), m_rows.size());\n"
            f"    m_rows.append(row);\n"
            f"    endInsertRows();\n"
            f"}}\n\n"
            f"void {cn}::clear() {{\n"
            f"    if (m_rows.isEmpty()) return;\n"
            f"    beginResetModel();\n"
            f"    m_rows.clear();\n"
            f"    endResetModel();\n"
            f"}}\n"
        )
        add_remove_h = "public slots:\n    void appendRow(const QList<QVariant> &row);\n    void clear();"
        add_remove = append_row

    h_text = f"""#pragma once

#include <QAbstractListModel>
// NOTE: change to <QAbstractTableModel> for table models
#include <QList>
#include <QVariant>
#include <QHash>

class {cn} : public {base} {{
    Q_OBJECT
{params.header_extra}
{member}

public:
    explicit {cn}(QObject *parent = nullptr);

    enum Roles {{
        ItemRole = Qt::UserRole + 1,
    }};

    int rowCount(const QModelIndex &parent = {{}}) const override;
{('    int columnCount(const QModelIndex &parent = {}) const override;' if params.model_type == 'table' else '')}
    QVariant data(const QModelIndex &index, int role = Qt::DisplayRole) const override;
{('    QVariant headerData(int section, Qt::Orientation orientation, int role = Qt::DisplayRole) const override;' if params.model_type == 'table' else '')}
{role_names}
{add_remove_h}

signals:
    void countChanged();
}};
"""

    cpp_includes = f"#include \"{cn}.h\"\n"
    if params.model_type == "list":
        cpp_includes += "\n".join([
            "",
        ])
    cpp_text = f"""{cpp_includes}
{cn}::{cn}(QObject *parent) : {base}(parent) {{
{params.source_extra if params.source_extra else ctor_init}
}}

int {cn}::rowCount(const QModelIndex &parent) const {{
    if (parent.isValid()) return 0;
    return {'m_items.size()' if params.model_type == 'list' else 'm_rows.size()'};
}}

{('int ' + cn + '::columnCount(const QModelIndex &parent) const {{\n    if (parent.isValid()) return 0;\n    return ' + str(len(params.columns)) + ';\n}}') if params.model_type == 'table' else ''}
{data_impl}
{('QVariant ' + cn + '::headerData(int section, Qt::Orientation orientation, int role) const {{ ... }}') if False else ''}
{header_data_impl if params.model_type == 'table' else ''}
{role_names}
{add_remove}
"""

    h_path = out_dir / f"{cn}.h"
    cpp_path = out_dir / f"{cn}.cpp"
    try:
        h_path.write_text(h_text, encoding="utf-8")
        cpp_path.write_text(cpp_text, encoding="utf-8")
    except OSError as e:
        msg = f"Error: failed to write files: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    out_lines = [
        f"=== qt_model_gen: wrote {cn} ({params.model_type}) ===",
        f"  header:  {h_path}",
        f"  source:  {cpp_path}",
        f"  base:    {base}",
    ]
    if params.model_type == "list":
        out_lines.append(f"  item_type: {item_t}")
    else:
        out_lines.append(f"  columns:  {len(params.columns)} ({col_names_cpp})")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"header": str(h_path), "source": str(cpp_path), "model_type": params.model_type}})


# --- qt_theme_gen: QSS stylesheet generator (light / dark themes) ------------

@mcp.tool(name="qt_theme_gen", annotations={"title": "Generate a QSS stylesheet (light/dark theme) for a Qt Widgets app", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_theme_gen(params: QtThemeGenInput) -> str:
    """Generate a QSS (Qt Style Sheet) file for theming a Qt Widgets application.

    Pass the colors and call `qt_scaffold` -> `qt_build` -> `qt_run` and the
    resulting .qss can be loaded with `QFile qss(...); app.setStyleSheet(qss.readAll())`.

    Args:
        params.theme_name: name embedded in the file header
        params.mode: 'light' (dark text on light bg) or 'dark' (light text on dark bg)
        params.base_color: primary background (hex)
        params.accent_color: highlight / hover / focus (hex)
        params.text_color: primary text (hex)
        params.border_radius: corner radius for buttons / inputs
        params.output_file: absolute path of .qss to write (must be inside the sandbox)


    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.mode not in ("light", "dark"):
        msg = f"Error: mode must be 'light' or 'dark', got {params.mode!r}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not (params.base_color.startswith("#") and len(params.base_color) in (4, 7)):
        msg = f"Error: base_color must be hex (#RGB or #RRGGBB): {params.base_color!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    out_path = Path(params.output_file)
    sandbox_err = _require_sandbox(out_path, "output_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    out_path.parent.mkdir(parents=True, exist_ok=True)

    # Derive a slightly-lighter "alt" and slightly-darker "alt2" base for hover/pressed
    def _hex_to_rgb(h: str) -> tuple[int, int, int]:
        h = h.lstrip("#")
        if len(h) == 3:
            h = "".join(c * 2 for c in h)
        return int(h[0:2], 16), int(h[2:4], 16), int(h[4:6], 16)

    def _rgb_to_hex(r: int, g: int, b: int) -> str:
        r = max(0, min(255, r))
        g = max(0, min(255, g))
        b = max(0, min(255, b))
        return f"#{r:02X}{g:02X}{b:02X}"

    def _lighten(h: str, amt: int) -> str:
        r, g, b = _hex_to_rgb(h)
        return _rgb_to_hex(r + amt, g + amt, b + amt)

    base = params.base_color
    alt = _lighten(base, 12)
    alt2 = _lighten(base, -12)
    disabled_text = _lighten(params.text_color, -40) if params.mode == "dark" else _lighten(params.text_color, 60)
    border = alt2

    qss = f"""/* Qt Style Sheet -- theme: {params.theme_name} ({params.mode}) */
/* Generated by qt-mcp qt_theme_gen. Load with: */
/*   QFile f(":/qss/{out_path.stem}.qss"); f.open(QFile::ReadOnly); */
/*   qApp->setStyleSheet(QString::fromUtf8(f.readAll())); */

QWidget {{
    background-color: {base};
    color: {params.text_color};
    font-family: "Segoe UI", "Microsoft YaHei", sans-serif;
    font-size: 10pt;
}}

QMainWindow::separator {{
    background: {alt2};
    width: 1px;
    height: 1px;
}}

QMenuBar {{
    background: {alt2};
    color: {params.text_color};
    padding: 4px;
}}
QMenuBar::item:selected {{
    background: {params.accent_color};
    color: {base};
}}
QMenu {{
    background: {base};
    color: {params.text_color};
    border: 1px solid {border};
}}
QMenu::item:selected {{
    background: {params.accent_color};
    color: {base};
}}

QPushButton {{
    background: {alt};
    color: {params.text_color};
    border: 1px solid {border};
    border-radius: {params.border_radius}px;
    padding: 6px 14px;
    min-height: 18px;
}}
QPushButton:hover {{
    background: {params.accent_color};
    color: {base};
}}
QPushButton:pressed {{
    background: {alt2};
}}
QPushButton:disabled {{
    color: {disabled_text};
    background: {alt2};
}}
QPushButton:default {{
    border: 2px solid {params.accent_color};
}}

QLineEdit, QSpinBox, QDoubleSpinBox, QComboBox, QDateEdit, QTimeEdit, QDateTimeEdit, QPlainTextEdit, QTextEdit {{
    background: {alt2};
    color: {params.text_color};
    border: 1px solid {border};
    border-radius: {params.border_radius}px;
    padding: 4px 6px;
    selection-background-color: {params.accent_color};
    selection-color: {base};
}}
QLineEdit:focus, QSpinBox:focus, QDoubleSpinBox:focus, QComboBox:focus,
QPlainTextEdit:focus, QTextEdit:focus {{
    border: 1px solid {params.accent_color};
}}

QLabel {{
    background: transparent;
    color: {params.text_color};
}}
QLabel:disabled {{
    color: {disabled_text};
}}

QListWidget, QTreeWidget, QTableWidget, QListView, QTreeView, QTableView {{
    background: {alt2};
    color: {params.text_color};
    border: 1px solid {border};
    alternate-background-color: {base};
    selection-background-color: {params.accent_color};
    selection-color: {base};
    gridline-color: {border};
}}
QListWidget::item:hover, QTreeWidget::item:hover, QTableWidget::item:hover {{
    background: {alt};
}}

QHeaderView::section {{
    background: {alt2};
    color: {params.text_color};
    padding: 4px 8px;
    border: 0;
    border-right: 1px solid {border};
    border-bottom: 1px solid {border};
}}

QProgressBar {{
    background: {alt2};
    color: {params.text_color};
    border: 1px solid {border};
    border-radius: {params.border_radius}px;
    text-align: center;
}}
QProgressBar::chunk {{
    background: {params.accent_color};
    border-radius: {params.border_radius}px;
}}

QSlider::groove:horizontal {{
    height: 6px;
    background: {alt2};
    border-radius: 3px;
}}
QSlider::handle:horizontal {{
    background: {params.accent_color};
    width: 14px;
    margin: -5px 0;
    border-radius: 7px;
}}

QCheckBox::indicator, QRadioButton::indicator {{
    width: 14px;
    height: 14px;
    background: {alt2};
    border: 1px solid {border};
    border-radius: 3px;
}}
QRadioButton::indicator {{
    border-radius: 7px;
}}
QCheckBox::indicator:checked, QRadioButton::indicator:checked {{
    background: {params.accent_color};
}}

QStatusBar {{
    background: {alt2};
    color: {params.text_color};
}}

QToolTip {{
    background: {alt2};
    color: {params.text_color};
    border: 1px solid {params.accent_color};
    padding: 4px;
}}

QScrollBar:vertical {{
    background: {alt2};
    width: 12px;
    margin: 0;
}}
QScrollBar::handle:vertical {{
    background: {border};
    min-height: 20px;
    border-radius: 6px;
}}
QScrollBar::add-line:vertical, QScrollBar::sub-line:vertical {{
    height: 0;
}}
QScrollBar:horizontal {{
    background: {alt2};
    height: 12px;
    margin: 0;
}}
QScrollBar::handle:horizontal {{
    background: {border};
    min-width: 20px;
    border-radius: 6px;
}}
QScrollBar::add-line:horizontal, QScrollBar::sub-line:horizontal {{
    width: 0;
}}
"""

    try:
        out_path.write_text(qss, encoding="utf-8")
    except OSError as e:
        msg = f"Error: failed to write QSS: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    out_lines = [
        f"=== qt_theme_gen: wrote '{params.theme_name}' ({params.mode}) ===",
        f"  file:    {out_path}",
        f"  size:    {out_path.stat().st_size} bytes",
        f"  base:    {base}",
        f"  accent:  {params.accent_color}",
        f"  text:    {params.text_color}",
        f"  radius:  {params.border_radius}px",
    ]
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"file": str(out_path), "size": out_path.stat().st_size, "mode": params.mode, "theme": params.theme_name}})


# --- qt_ico_create: multi-resolution .ico from PNG ----------------------------

@mcp.tool(name="qt_ico_create", annotations={"title": "Bundle one or more PNGs into a multi-resolution Windows .ico file", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_ico_create(params: QtIcoCreateInput) -> str:
    """Bundle one or more PNGs into a multi-resolution Windows .ico file.

    Required for any Windows deployment that wants a high-DPI-aware app icon
    (16x16 for the title bar, 32x32 for the taskbar, 256x256 for Alt-Tab).
    Loads each PNG, resizes to every requested size, and writes a single
    multi-image .ico. Uses Pillow (PIL).

    Args:
        params.png_files: list of source PNG files (absolute paths)
        params.output_ico: absolute path of the .ico file to write
        params.sizes: icon sizes to include (default 16,32,48,64,128,256)


    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    try:
        from PIL import Image
    except ImportError as e:
        msg = f"Error: Pillow not installed ({e}). pip install Pillow"
        return msg + _json_footer({"ok": False, "error": msg})

    if not params.png_files:
        msg = "Error: png_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if not params.sizes:
        msg = "Error: sizes is empty"
        return msg + _json_footer({"ok": False, "error": msg})

    out_path = Path(params.output_ico)
    sandbox_err = _require_sandbox(out_path, "output_ico")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    out_path.parent.mkdir(parents=True, exist_ok=True)

    images: dict[int, Image.Image] = {}
    src_paths: list[Path] = []
    for p in params.png_files:
        src = Path(p)
        if not src.exists() or not src.is_file():
            msg = f"Error: source PNG not found: {src}"
            return msg + _json_footer({"ok": False, "error": msg})
        src_paths.append(src)

    base_img = Image.open(src_paths[0]).convert("RGBA")
    base_size = max(base_img.size)
    base_img_full = base_img

    # For every requested size: try to find a source PNG >= size, else resize from the largest
    for size in sorted(set(params.sizes)):
        if size <= 0 or size > 4096:
            msg = f"Error: invalid size {size} (must be 1..4096)"
            return msg + _json_footer({"ok": False, "error": msg})
        chosen: Image.Image | None = None
        for sp in src_paths:
            try:
                im = Image.open(sp).convert("RGBA")
                if max(im.size) >= size:
                    chosen = im
                    break
            except Exception as e:
                msg = f"Error: failed to open {sp}: {e}"
                return msg + _json_footer({"ok": False, "error": msg})
        if chosen is None:
            chosen = base_img_full
        if chosen.size != (size, size):
            chosen = chosen.resize((size, size), Image.LANCZOS)
        images[size] = chosen

    try:
        # Pillow's ICO writer accepts a list of PIL images with explicit sizes
        out_path.write_bytes(b"")
        first = images[sorted(images.keys())[0]]
        rest = [images[s] for s in sorted(images.keys())[1:]]
        first.save(
            str(out_path),
            format="ICO",
            sizes=[(s, s) for s in sorted(images.keys())],
            append_images=rest,
        )
    except Exception as e:
        msg = f"Error: failed to write ICO: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    out_lines = [
        f"=== qt_ico_create: wrote {len(images)}-size ICO ===",
        f"  output: {out_path}",
        f"  sizes:  {sorted(images.keys())}",
        f"  size:   {out_path.stat().st_size} bytes",
        f"  source PNGs: {len(src_paths)}",
    ]
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"output": str(out_path), "sizes": sorted(images.keys()), "size_bytes": out_path.stat().st_size}})


# --- qt_screenshot_diff: pixel-by-pixel image diff for visual regression -----

@mcp.tool(name="qt_screenshot_diff", annotations={"title": "Compare two screenshots pixel-by-pixel for visual regression testing", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_screenshot_diff(params: QtScreenshotDiffInput) -> str:
    """Compare two images and report where they differ.

    Use for visual regression tests: take a baseline screenshot, then a 'current'
    screenshot, run qt_screenshot_diff, and assert `diff_count == 0` (or below
    a threshold). Optionally writes a visual diff image (red pixels where the
    two images differ) to `diff_image`.

    Args:
        params.image_a: first image (baseline)
        params.image_b: second image (current)
        params.diff_image: optional path to write the red-overlay diff image
        params.tolerance: per-channel RGB tolerance (0-255). Default 0 = exact match.


    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    try:
        from PIL import Image, ImageChops
    except ImportError as e:
        msg = f"Error: Pillow not installed ({e})"
        return msg + _json_footer({"ok": False, "error": msg})

    a_path = Path(params.image_a)
    b_path = Path(params.image_b)
    if not a_path.exists():
        msg = f"Error: image_a not found: {a_path}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not b_path.exists():
        msg = f"Error: image_b not found: {b_path}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not (0.0 <= params.tolerance <= 255.0):
        msg = f"Error: tolerance must be 0..255, got {params.tolerance}"
        return msg + _json_footer({"ok": False, "error": msg})

    try:
        a = Image.open(a_path).convert("RGBA")
        b = Image.open(b_path).convert("RGBA")
    except Exception as e:
        msg = f"Error: failed to open images: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    if a.size != b.size:
        msg = f"Error: size mismatch: a={a.size} b={b.size}"
        return msg + _json_footer({"ok": False, "error": msg})

    try:
        import numpy as np  # type: ignore
    except ImportError as e:
        msg = f"Error: numpy not installed ({e})"
        return msg + _json_footer({"ok": False, "error": msg})

    arr_a = np.asarray(a, dtype=np.int16)
    arr_b = np.asarray(b, dtype=np.int16)
    total = a.size[0] * a.size[1]
    tol = int(round(params.tolerance))

    if tol == 0:
        channel_diff = np.abs(arr_a - arr_b)
        mask = (channel_diff > 0).any(axis=-1)
    else:
        channel_diff = np.abs(arr_a - arr_b)
        mask = (channel_diff > tol).any(axis=-1)

    diff_count = int(mask.sum())
    ratio = diff_count / total if total else 0.0

    if diff_count == 0:
        bbox = None
    else:
        ys, xs = np.where(mask)
        bbox = (int(xs.min()), int(ys.min()), int(xs.max()) + 1, int(ys.max()) + 1)

    out_lines = [
        f"=== qt_screenshot_diff: {a_path.name} vs {b_path.name} ===",
        f"  size:    {a.size[0]}x{a.size[1]}",
        f"  tolerance: {tol} per-channel",
        f"  diff:    {diff_count} / {total} pixels ({ratio * 100:.3f}%)",
    ]
    if bbox:
        out_lines.append(f"  bbox:    {bbox}")
    else:
        out_lines.append("  bbox:    (none -- images match within tolerance)")

    if params.diff_image:
        dpath = Path(params.diff_image)
        sandbox_err = _require_sandbox(dpath, "diff_image")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        dpath.parent.mkdir(parents=True, exist_ok=True)
        arr_o = arr_a.copy()
        arr_o[mask] = [255, 0, 0, 255]
        Image.fromarray(arr_o.astype(np.uint8), mode="RGBA").save(dpath)
        out_lines.append(f"  diff image: {dpath}")

    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"diff_count": diff_count, "total": total, "ratio": round(ratio, 6), "bbox": bbox, "tolerance": tol}})


# --- qt_clazy_check: regex-based Qt anti-pattern checker (no clazy binary) ---

_CLAZY_CHECKS: dict[str, dict[str, str]] = {
    "qobject-macro": {
        "description": "Detects Q_OBJECT usage in .cpp files (should be in .h only)",
        "severity": "warning",
    },
    "qobject-parent": {
        "description": "Detects new QObject(...) without explicit parent (memory leak risk)",
        "severity": "warning",
    },
    "missing-q_disable_copy": {
        "description": "QObject subclasses should declare Q_DISABLE_COPY to prevent slicing",
        "severity": "warning",
    },
    "qlist-vs-qvector": {
        "description": "Qt 5+ prefers QList (was QVector in Qt 4). QVector is Qt 4 only.",
        "severity": "warning",
    },
    "raw-connect": {
        "description": "Detects old-style connect(sender, SIGNAL(...), receiver, SLOT(...)) -- use PMF syntax",
        "severity": "warning",
    },
    "missing-qobject": {
        "description": "Class inherits from QObject but no Q_OBJECT macro in the same translation unit",
        "severity": "error",
    },
    "implicit-casts": {
        "description": "Detects implicit char* to QString casts (use QStringLiteral / QLatin1String)",
        "severity": "info",
    },
}


def _clazy_run_one_check(check_name: str, text: str, path: Path) -> list[dict]:
    """Run a single clazy-style check and return issues."""
    issues: list[dict] = []
    lines = text.splitlines()
    for ln_no, line in enumerate(lines, 1):
        if check_name == "qobject-macro":
            if path.suffix in (".cpp", ".cc") and "Q_OBJECT" in line:
                issues.append({
                    "check": check_name, "severity": _CLAZY_CHECKS[check_name]["severity"],
                    "file": str(path), "line": ln_no, "message": "Q_OBJECT in .cpp (move to .h)",
                })
        elif check_name == "qobject-parent":
            m = re.search(r"new\s+Q[A-Z]\w*\s*\(", line)
            if m and "parent" not in line and "this" not in line and "=nullptr" not in line and "= nullptr" not in line:
                issues.append({
                    "check": check_name, "severity": _CLAZY_CHECKS[check_name]["severity"],
                    "file": str(path), "line": ln_no, "message": "new QObject without explicit parent",
                })
        elif check_name == "missing-q_disable_copy":
            if path.suffix in (".h", ".hpp") and re.search(r"class\s+\w+\s*:\s*public\s+QObject\b", line):
                head = "\n".join(lines[max(0, ln_no - 1):min(len(lines), ln_no + 25)])
                if "Q_DISABLE_COPY" not in head:
                    issues.append({
                        "check": check_name, "severity": _CLAZY_CHECKS[check_name]["severity"],
                        "file": str(path), "line": ln_no, "message": "QObject subclass missing Q_DISABLE_COPY",
                    })
        elif check_name == "qlist-vs-qvector":
            if re.search(r"\bQVector\b", line):
                issues.append({
                    "check": check_name, "severity": _CLAZY_CHECKS[check_name]["severity"],
                    "file": str(path), "line": ln_no, "message": "QVector is Qt 4 only; use QList in Qt 5+",
                })
        elif check_name == "raw-connect":
            if "SIGNAL(" in line and "SLOT(" in line:
                issues.append({
                    "check": check_name, "severity": _CLAZY_CHECKS[check_name]["severity"],
                    "file": str(path), "line": ln_no, "message": "old-style SIGNAL()/SLOT() connect -- use PMF syntax",
                })
        elif check_name == "missing-qobject":
            if path.suffix in (".h", ".hpp") and re.search(r"class\s+\w+\s*:\s*public\s+QObject\b", line):
                # Check this class block (until next 'class ' or end of file) for Q_OBJECT
                start = ln_no
                end = min(len(lines), start + 50)
                for i in range(start, end):
                    if i != ln_no - 1 and re.search(r"^class\s+\w+", lines[i]):
                        end = i
                        break
                block = "\n".join(lines[start - 1:end])
                if "Q_OBJECT" not in block:
                    issues.append({
                        "check": check_name, "severity": _CLAZY_CHECKS[check_name]["severity"],
                        "file": str(path), "line": ln_no, "message": "QObject subclass missing Q_OBJECT macro",
                    })
        elif check_name == "implicit-casts":
            # Flag "QString::fromUtf8" or string literals assigned to QString without QLatin1String/QStringLiteral
            if re.search(r'=\s*"[^"]*"\s*;', line) and "QString" in line and "QStringLiteral" not in line and "QLatin1String" not in line and "tr(" not in line:
                # Only flag obvious cases (string literal on RHS assigned to QString)
                if re.search(r'QString\s+\w+\s*=\s*"', line):
                    issues.append({
                        "check": check_name, "severity": _CLAZY_CHECKS[check_name]["severity"],
                        "file": str(path), "line": ln_no, "message": "implicit char* to QString cast (use QStringLiteral)",
                    })
    return issues


@mcp.tool(name="qt_clazy_check", annotations={"title": "Regex-based Qt anti-pattern checker (no clazy binary required)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_clazy_check(params: QtClazyCheckInput) -> str:
    """Run a regex-based static analysis for common Qt anti-patterns.

    This is a lightweight stand-in for the real `clazy` clang plugin. It catches
    the most common issues that are easy to spot with regex:

      - Q_OBJECT in .cpp (should be in .h)
      - new QObject() without explicit parent
      - QObject subclass missing Q_DISABLE_COPY
      - QVector (Qt 4 only -- use QList in Qt 5+)
      - old-style SIGNAL()/SLOT() connect
      - QObject subclass missing Q_OBJECT
      - implicit char* to QString casts

    Args:
        params.project_dir: project root to scan
        params.checks: list of check names (default: all)
        params.extensions: file extensions to scan
        params.exclude_dirs: subdir patterns to skip
        params.max_issues: cap on total issues


    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    active = set(params.checks) if params.checks else set(_CLAZY_CHECKS.keys())
    unknown = active - set(_CLAZY_CHECKS.keys())
    if unknown:
        msg = f"Error: unknown checks: {sorted(unknown)}. Valid: {sorted(_CLAZY_CHECKS.keys())}"
        return msg + _json_footer({"ok": False, "error": msg})

    exts = {e if e.startswith(".") else "." + e for e in params.extensions}
    files: list[Path] = []
    for ext in exts:
        for p in proj_dir.rglob(f"*{ext}"):
            if any(s in p.parts for s in params.exclude_dirs):
                continue
            files.append(p)
    files.sort()

    all_issues: list[dict] = []
    for f in files:
        try:
            text = f.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        for check in active:
            for issue in _clazy_run_one_check(check, text, f):
                all_issues.append(issue)
                if len(all_issues) >= params.max_issues:
                    break
            if len(all_issues) >= params.max_issues:
                break
        if len(all_issues) >= params.max_issues:
            break

    by_check: dict[str, int] = {}
    for issue in all_issues:
        by_check[issue["check"]] = by_check.get(issue["check"], 0) + 1
    by_severity: dict[str, int] = {}
    for issue in all_issues:
        by_severity[issue["severity"]] = by_severity.get(issue["severity"], 0) + 1

    out_lines = [
        f"=== qt_clazy_check: {len(all_issues)} issue(s) in {len(files)} file(s) ===",
        f"project: {proj_dir}",
        f"checks:  {sorted(active)}",
    ]
    if by_severity:
        out_lines.append("")
        out_lines.append("By severity:")
        for sev, n in sorted(by_severity.items()):
            out_lines.append(f"  {sev:8s} {n}")
    if by_check:
        out_lines.append("")
        out_lines.append("By check:")
        for ck, n in sorted(by_check.items()):
            out_lines.append(f"  {ck:24s} {n}")
    if all_issues:
        out_lines.append("")
        out_lines.append("First 20 issues:")
        for issue in all_issues[:20]:
            try:
                rel = Path(issue["file"]).relative_to(proj_dir)
            except ValueError:
                rel = issue["file"]
            out_lines.append(f"  [{issue['severity']:8s}] {rel}:{issue['line']}: {issue['message']}")
        if len(all_issues) > 20:
            out_lines.append(f"  ... and {len(all_issues) - 20} more (capped at max_issues={params.max_issues})")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"issues": len(all_issues), "files": len(files), "by_severity": by_severity, "by_check": by_check}})


# --- qt_signal_slot_trace: parse connect() + signals/slots for a graph -------

def _sst_strip_comments(text: str) -> str:
    """Strip // and /* */ comments from C++ source (simple)."""
    text = re.sub(r"/\*.*?\*/", "", text, flags=re.DOTALL)
    out_lines = []
    for line in text.splitlines():
        idx = line.find("//")
        out_lines.append(line if idx < 0 else line[:idx])
    return "\n".join(out_lines)


@mcp.tool(name="qt_signal_slot_trace", annotations={"title": "Parse C++ source to extract signal/slot declarations and connect() calls", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_signal_slot_trace(params: QtSignalSlotTraceInput) -> str:
    """Static analysis of signal/slot wiring in a Qt project.

    Parses .h and .cpp files to extract:
      - QObject subclass names (per file)
      - `signals:` declarations (signal name + return type)
      - `slots:` declarations (slot name)
      - `QObject::connect(...)` and member-function-pointer connects

    Reports:
      - count of signals, slots, connections
      - connections with file:line + sender.signal -> receiver.slot
      - orphan slots (declared but not connected)
      - orphan signals (declared but no connect sender)

    Output formats: 'text' (default), 'json' (machine), 'dot' (Graphviz).

    Args:
        params.project_dir: project root to scan
        params.output_format: 'text' | 'json' | 'dot'
        params.output_file: optional path to write the output (default: return as string)


    Returns:
        str: a formatted text report (or file contents if output_file set). Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.output_format not in ("text", "json", "dot"):
        msg = f"Error: output_format must be text/json/dot, got {params.output_format!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    headers = sorted(proj_dir.rglob("*.h")) + sorted(proj_dir.rglob("*.hpp"))
    sources = sorted(proj_dir.rglob("*.cpp")) + sorted(proj_dir.rglob("*.cc"))
    headers = [p for p in headers if not any(s in p.parts for s in ("debug", "release", "build-", ".git", "build"))]
    sources = [p for p in sources if not any(s in p.parts for s in ("debug", "release", "build-", ".git", "build"))]

    signals_by_class: dict[str, list[str]] = {}  # class -> [signal_name]
    slots_by_class: dict[str, list[str]] = {}  # class -> [slot_name]
    classes_by_file: dict[str, list[str]] = {}  # file -> [class_name]
    slot_defs: set[tuple[str, str]] = set()  # (class, slot)
    signal_defs: set[tuple[str, str]] = set()  # (class, signal)

    for h in headers:
        try:
            text = h.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        clean = _sst_strip_comments(text)
        # Class names (multiple per file)
        for m in re.finditer(r"class\s+(\w+)\s*:\s*public\s+Q(?:Object|Widget|MainWindow|Dialog|AbstractItemModel|AbstractListModel|AbstractTableModel)\b", clean):
            cname = m.group(1)
            classes_by_file.setdefault(str(h), []).append(cname)
        # signals: section
        sig_section = re.search(r"signals\s*:\s*(.*?)(?=\n\s*(?:public|protected|private|slots|Q_SIGNALS|}[^}]*};|\Z))", clean, re.DOTALL)
        if sig_section:
            for m in re.finditer(r"(?:void|Q\w+(?:\s*<[^>]+>)?)\s+(\w+)\s*\(", sig_section.group(1)):
                signal_defs.add((cname, m.group(1)))  # may be wrong class if multiple; take last
                signals_by_class.setdefault(cname, []).append(m.group(1))
        # slots: section
        slot_section = re.search(r"(?:public|protected|private)\s+slots\s*:\s*(.*?)(?=\n\s*(?:public|protected|private|signals|Q_SIGNALS|}[^}]*};|\Z))", clean, re.DOTALL)
        if slot_section:
            for m in re.finditer(r"(?:void|Q\w+(?:\s*<[^>]+>)?)\s+(\w+)\s*\(", slot_section.group(1)):
                slot_defs.add((cname, m.group(1)))
                slots_by_class.setdefault(cname, []).append(m.group(1))

    # All unique classes
    all_classes: set[str] = set()
    for names in classes_by_file.values():
        all_classes.update(names)

    connections: list[dict] = []
    for src in sources:
        try:
            text = src.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        clean = _sst_strip_comments(text)
        # 1) New style: optional QObject:: prefix + connect(sender, &Class::signal, receiver, &Class::slot)
        #    Use a single combined regex with optional QObject:: prefix to avoid double-matching
        for m in re.finditer(r"(?:QObject\s*::\s*)?connect\s*\(\s*(\w+)\s*,\s*&(\w+)::(\w+)\s*,\s*(\w+)\s*,\s*&(\w+)::(\w+)\s*\)", clean):
            connections.append({
                "file": str(src), "line": clean[:m.start()].count("\n") + 1,
                "sender": m.group(1), "sender_class": m.group(2), "signal": m.group(3),
                "receiver": m.group(4), "receiver_class": m.group(5), "slot": m.group(6),
            })
        # 2) Old style: connect(sender, SIGNAL(...), receiver, SLOT(...))
        for m in re.finditer(r"(?:QObject\s*::\s*)?connect\s*\(\s*(\w+)\s*,\s*SIGNAL\s*\(\s*(\w+)\s*\(\s*\)\s*\)\s*,\s*(\w+)\s*,\s*SLOT\s*\(\s*(\w+)\s*\(\s*\)\s*\)\s*\)", clean):
            connections.append({
                "file": str(src), "line": clean[:m.start()].count("\n") + 1,
                "sender": m.group(1), "sender_class": "?", "signal": m.group(2),
                "receiver": m.group(3), "receiver_class": "?", "slot": m.group(4),
            })

    # Build orphan lists
    connected_signals: set[tuple[str, str]] = set()
    connected_slots: set[tuple[str, str]] = set()
    for c in connections:
        if c["sender_class"] != "?":
            connected_signals.add((c["sender_class"], c["signal"]))
        if c["receiver_class"] != "?":
            connected_slots.add((c["receiver_class"], c["slot"]))
    orphan_signals = sorted(signal_defs - connected_signals)
    orphan_slots = sorted(slot_defs - connected_slots)

    if params.output_format == "json":
        payload = {
            "project": str(proj_dir),
            "headers": len(headers), "sources": len(sources),
            "classes": sorted(all_classes),
            "signals_total": len(signal_defs), "slots_total": len(slot_defs),
            "connections": connections,
            "orphan_signals": [list(x) for x in orphan_signals],
            "orphan_slots": [list(x) for x in orphan_slots],
        }
        text = json.dumps(payload, indent=2, ensure_ascii=False)
    elif params.output_format == "dot":
        lines = [f"// qt_signal_slot_trace dot output for {proj_dir}", "digraph signals {", "  rankdir=LR; node [shape=box];"]
        for cname in sorted(all_classes):
            sigs = signals_by_class.get(cname, [])
            slts = slots_by_class.get(cname, [])
            if sigs:
                lines.append(f'  subgraph "cluster_{cname}_signals" {{ label="{cname}::signals";')
                for s in sigs:
                    lines.append(f'    "{cname}::{s}" [shape=ellipse,color=blue];')
                lines.append("  }")
            if slts:
                lines.append(f'  subgraph "cluster_{cname}_slots" {{ label="{cname}::slots";')
                for s in slts:
                    lines.append(f'    "{cname}::{s}" [shape=box,color=green];')
                lines.append("  }")
        for c in connections:
            lines.append(f'  "{c["sender_class"]}::{c["signal"]}" -> "{c["receiver_class"]}::{c["slot"]}";')
        lines.append("}")
        text = "\n".join(lines)
    else:
        # text
        out_lines = [
            f"=== qt_signal_slot_trace: {len(connections)} connection(s) in {len(sources)} .cpp / {len(headers)} .h ===",
            f"project:   {proj_dir}",
            f"classes:   {len(all_classes)}",
            f"signals:   {len(signal_defs)}",
            f"slots:     {len(slot_defs)}",
        ]
        if classes_by_file:
            out_lines.append("")
            out_lines.append("Classes:")
            for fp, names in sorted(classes_by_file.items()):
                try:
                    rel = Path(fp).relative_to(proj_dir)
                except ValueError:
                    rel = fp
                out_lines.append(f"  {rel}: {', '.join(names)}")
        if connections:
            out_lines.append("")
            out_lines.append(f"Connections ({len(connections)}):")
            for c in connections[:50]:
                try:
                    rel = Path(c["file"]).relative_to(proj_dir)
                except ValueError:
                    rel = c["file"]
                out_lines.append(f"  {rel}:{c['line']}: {c['sender']}.{c['signal']} -> {c['receiver']}.{c['slot']}")
            if len(connections) > 50:
                out_lines.append(f"  ... and {len(connections) - 50} more")
        if orphan_signals:
            out_lines.append("")
            out_lines.append(f"Orphan signals ({len(orphan_signals)}):")
            for cls, sig in orphan_signals[:30]:
                out_lines.append(f"  {cls}::{sig}")
            if len(orphan_signals) > 30:
                out_lines.append(f"  ... and {len(orphan_signals) - 30} more")
        if orphan_slots:
            out_lines.append("")
            out_lines.append(f"Orphan slots ({len(orphan_slots)}):")
            for cls, slt in orphan_slots[:30]:
                out_lines.append(f"  {cls}::{slt}")
            if len(orphan_slots) > 30:
                out_lines.append(f"  ... and {len(orphan_slots) - 30} more")
        text = "\n".join(out_lines)

    if params.output_file:
        out_path = Path(params.output_file)
        sandbox_err = _require_sandbox(out_path, "output_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_text(text, encoding="utf-8")
        return f"=== qt_signal_slot_trace: wrote {out_path} ({len(text)} bytes) ===" + _json_footer({"ok": True, "data": {"file": str(out_path), "format": params.output_format, "connections": len(connections)}})

    return text + _json_footer({"ok": True, "data": {"format": params.output_format, "connections": len(connections), "signals": len(signal_defs), "slots": len(slot_defs), "orphan_signals": len(orphan_signals), "orphan_slots": len(orphan_slots)}})


# --- qt_input_recorder: record / playback mouse + keyboard events ------------

_INPUT_RECORDER_RECORD_PY = '''#!/usr/bin/env python3
"""Standalone recorder: write mouse + keyboard events to a JSON file.

Run: python _record_input.py <output.json> <duration_seconds>

Uses pyautogui for both mouse + keyboard. Falls back to logging-only
if pyautogui is not installed.
"""
import json
import sys
import time
from pathlib import Path

def _now() -> float:
    return time.time()

def main() -> int:
    if len(sys.argv) < 3:
        print("usage: _record_input.py <output.json> <duration_seconds>", file=sys.stderr)
        return 2
    out_path = Path(sys.argv[1])
    duration = float(sys.argv[2])
    out_path.parent.mkdir(parents=True, exist_ok=True)
    events: list[dict] = []
    start_ts = _now()
    try:
        import pyautogui
        ok = True
    except ImportError:
        ok = False
    if ok:
        def on_click(x, y, button, pressed):
            events.append({"t": round(_now() - start_ts, 4), "type": "click", "x": x, "y": y, "button": str(button), "pressed": pressed})
        def on_scroll(x, y, dx, dy):
            events.append({"t": round(_now() - start_ts, 4), "type": "scroll", "x": x, "y": y, "dx": dx, "dy": dy})
        def on_press(key):
            try:
                key_str = key.char
            except AttributeError:
                key_str = str(key)
            events.append({"t": round(_now() - start_ts, 4), "type": "key_down", "key": key_str})
        def on_release(key):
            try:
                key_str = key.char
            except AttributeError:
                key_str = str(key)
            events.append({"t": round(_now() - start_ts, 4), "type": "key_up", "key": key_str})
        # pynput for low-level hooks (more reliable than pyautogui hooks)
        try:
            from pynput import mouse, keyboard  # type: ignore
            ml = mouse.Listener(on_click=on_click, on_scroll=on_scroll)
            kl = keyboard.Listener(on_press=on_press, on_release=on_release)
            ml.start(); kl.start()
            time.sleep(duration)
            ml.stop(); kl.stop()
        except ImportError:
            # Fallback: poll mouse position
            last_pos = None
            while _now() - start_ts < duration:
                pos = pyautogui.position()
                if pos != last_pos:
                    events.append({"t": round(_now() - start_ts, 4), "type": "move", "x": pos[0], "y": pos[1]})
                    last_pos = pos
                time.sleep(0.05)
    else:
        # No pyautogui/pynput: write a stub event so callers can see the format
        events.append({"t": 0.0, "type": "info", "note": "pyautogui/pynput not available; stub event"})
        time.sleep(min(duration, 0.5))
    payload = {
        "version": 1,
        "recorded_at": int(start_ts),
        "duration_seconds": duration,
        "event_count": len(events),
        "events": events,
    }
    out_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    print(f"recorded {len(events)} events to {out_path}")
    return 0

if __name__ == "__main__":
    sys.exit(main())
'''


_INPUT_RECORDER_PLAYBACK_PY = '''#!/usr/bin/env python3
"""Standalone playback: replay mouse + keyboard events from a JSON file.

Run: python _playback_input.py <input.json> [speed] [stop_after]
"""
import json
import sys
import time
from pathlib import Path

def main() -> int:
    if len(sys.argv) < 2:
        print("usage: _playback_input.py <input.json> [speed] [stop_after]", file=sys.stderr)
        return 2
    in_path = Path(sys.argv[1])
    speed = float(sys.argv[2]) if len(sys.argv) > 2 else 1.0
    stop_after = int(sys.argv[3]) if len(sys.argv) > 3 else 0
    if not in_path.exists():
        print(f"input file not found: {in_path}", file=sys.stderr)
        return 3
    try:
        data = json.loads(in_path.read_text(encoding="utf-8"))
    except (OSError, ValueError) as e:
        print(f"failed to parse JSON: {e}", file=sys.stderr)
        return 4
    events = data.get("events", [])
    if stop_after > 0:
        events = events[:stop_after]
    if not events:
        print("no events to play", file=sys.stderr)
        return 5
    try:
        import pyautogui  # type: ignore
        have_pyautogui = True
    except ImportError:
        have_pyautogui = False
    last_t = 0.0
    start = time.time()
    played = 0
    for ev in events:
        target = ev.get("t", 0.0) / max(0.001, speed)
        wait = (start + target) - time.time()
        if wait > 0:
            time.sleep(wait)
        et = ev.get("type")
        if not have_pyautogui:
            played += 1
            continue
        if et == "move":
            pyautogui.moveTo(ev.get("x", 0), ev.get("y", 0))
        elif et == "click":
            btn = ev.get("button", "left")
            button = None
            if "left" in btn:
                button = "left"
            elif "right" in btn:
                button = "right"
            elif "middle" in btn:
                button = "middle"
            pyautogui.click(ev.get("x", 0), ev.get("y", 0), button=button) if ev.get("pressed", True) else None
        elif et == "scroll":
            pyautogui.scroll(int(ev.get("dy", 0)))
        elif et == "key_down":
            try:
                pyautogui.keyDown(ev.get("key", ""))
            except Exception:
                pass
        elif et == "key_up":
            try:
                pyautogui.keyUp(ev.get("key", ""))
            except Exception:
                pass
        played += 1
    print(f"played {played} of {len(events)} events (speed={speed})")
    return 0

if __name__ == "__main__":
    sys.exit(main())
'''


@mcp.tool(name="qt_input_recorder", annotations={"title": "Record or playback mouse / keyboard input events (pyautogui-based)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_input_recorder(params: QtInputRecorderInput) -> str:
    """Record, playback, or inspect a mouse + keyboard input session.

    Output format is portable JSON with shape:
        {"version": 1, "recorded_at": <unix_ts>, "duration_seconds": N, "events": [...]}
    Each event is {t: <sec_offset>, type: "move"|"click"|"scroll"|"key_down"|"key_up", ...}

    Actions:
      - 'record'   : spawn a detached process that captures events for N seconds
      - 'playback' : spawn a process that replays a previously recorded file
      - 'info'     : parse a recorded file and show summary (event count, types, duration)

    Args:
        params.action: 'record' | 'playback' | 'info'
        params.output_file: for 'record', where to save the JSON
        params.input_file: for 'playback'/'info', which JSON to use
        params.duration_seconds: for 'record', how long to capture (default 5)
        params.speed: for 'playback', speed multiplier
        params.stop_after: for 'playback', stop after N events (0 = all)


    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("record", "playback", "info"):
        msg = f"Error: invalid action {params.action!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    rec_dir = SANDBOX_ROOT / ".input_recordings"
    rec_dir.mkdir(parents=True, exist_ok=True)
    sandbox_err = _require_sandbox(rec_dir, "input_recordings dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})

    helpers_dir = SANDBOX_ROOT / ".tmp" / "input_recorder_helpers"
    helpers_dir.mkdir(parents=True, exist_ok=True)
    rec_py = helpers_dir / "_record_input.py"
    pb_py = helpers_dir / "_playback_input.py"
    if not rec_py.exists() or rec_py.stat().st_size == 0:
        rec_py.write_text(_INPUT_RECORDER_RECORD_PY, encoding="utf-8")
    if not pb_py.exists() or pb_py.stat().st_size == 0:
        pb_py.write_text(_INPUT_RECORDER_PLAYBACK_PY, encoding="utf-8")

    if params.action == "record":
        out_path = Path(params.output_file) if params.output_file else rec_dir / "events.json"
        if not out_path.is_absolute():
            out_path = (rec_dir / out_path).resolve()
        sandbox_err = _require_sandbox(out_path, "output_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        try:
            proc = await asyncio.create_subprocess_exec(
                sys.executable, str(rec_py), str(out_path), str(params.duration_seconds),
                stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE,
                cwd=str(helpers_dir),
            )
            stdout, stderr = await asyncio.wait_for(proc.communicate(), timeout=params.duration_seconds + 30)
        except asyncio.TimeoutError:
            try:
                proc.kill()
            except Exception:
                pass
            msg = f"Error: recording timed out after {params.duration_seconds + 30}s"
            return msg + _json_footer({"ok": False, "error": msg})
        if proc.returncode != 0:
            msg = f"Error: recorder exited with code {proc.returncode}: {stderr.decode('utf-8', errors='replace')[:200]}"
            return msg + _json_footer({"ok": False, "error": msg})
        if not out_path.exists():
            msg = f"Error: recorder did not write {out_path}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            data = json.loads(out_path.read_text(encoding="utf-8"))
        except (OSError, ValueError) as e:
            msg = f"Error: failed to parse recorder output: {e}"
            return msg + _json_footer({"ok": False, "error": msg})
        ev_count = data.get("event_count", 0)
        out_lines = [
            f"=== qt_input_recorder: recorded {ev_count} event(s) ===",
            f"  output: {out_path}",
            f"  duration: {params.duration_seconds}s",
            f"  events:  {ev_count}",
        ]
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"file": str(out_path), "event_count": ev_count, "duration": params.duration_seconds}})

    # playback / info: need an input file
    in_path = Path(params.input_file) if params.input_file else (Path(params.output_file) if params.output_file else rec_dir / "events.json")
    if not in_path.is_absolute():
        in_path = (rec_dir / in_path).resolve()
    if not in_path.exists():
        msg = f"Error: input file not found: {in_path}"
        return msg + _json_footer({"ok": False, "error": msg})
    try:
        data = json.loads(in_path.read_text(encoding="utf-8"))
    except (OSError, ValueError) as e:
        msg = f"Error: failed to parse input: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    if params.action == "info":
        events = data.get("events", [])
        type_counts: dict[str, int] = {}
        for ev in events:
            t = ev.get("type", "?")
            type_counts[t] = type_counts.get(t, 0) + 1
        out_lines = [
            f"=== qt_input_recorder: info for {in_path.name} ===",
            f"  file:        {in_path}",
            f"  size:        {in_path.stat().st_size} bytes",
            f"  version:     {data.get('version', '?')}",
            f"  recorded_at: {data.get('recorded_at', '?')}",
            f"  duration:    {data.get('duration_seconds', '?')}s",
            f"  events:      {len(events)}",
        ]
        if type_counts:
            out_lines.append("")
            out_lines.append("By type:")
            for t, n in sorted(type_counts.items()):
                out_lines.append(f"  {t:10s} {n}")
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"file": str(in_path), "events": len(events), "type_counts": type_counts}})

    # playback
    stop_after = str(params.stop_after) if params.stop_after > 0 else "0"
    try:
        proc = await asyncio.create_subprocess_exec(
            sys.executable, str(pb_py), str(in_path), str(params.speed), stop_after,
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE,
            cwd=str(helpers_dir),
        )
        stdout, stderr = await asyncio.wait_for(proc.communicate(), timeout=120)
    except asyncio.TimeoutError:
        try:
            proc.kill()
        except Exception:
            pass
        msg = "Error: playback timed out after 120s"
        return msg + _json_footer({"ok": False, "error": msg})
    out_lines = [
        f"=== qt_input_recorder: playback of {in_path.name} ===",
        f"  speed:     {params.speed}x",
        f"  stop_after: {stop_after}",
        f"  returncode: {proc.returncode}",
        f"  stdout:    {stdout.decode('utf-8', errors='replace').strip()[:200]}",
    ]
    if proc.returncode != 0:
        out_lines.append(f"  stderr:    {stderr.decode('utf-8', errors='replace').strip()[:200]}")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": proc.returncode == 0, "data": {"file": str(in_path), "speed": params.speed, "returncode": proc.returncode}})


# --- qt_translation_validate: parse .ts files for coverage + missing --------

@mcp.tool(name="qt_translation_validate", annotations={"title": "Parse .ts files and report translation coverage (finished / total per language)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_translation_validate(params: QtTranslationValidateInput) -> str:
    """Parse one or more Qt .ts files and report translation coverage.

    Each .ts file is XML with a top-level <TS> element, <message> children, and
    <translation type="..."> states. Reports:
      - total <message> count per language
      - count of 'finished' (type=finished or unfinished-but-with-text) vs unfinished
      - coverage % = finished / total
      - flagged languages below `min_coverage` threshold

    Args:
        params.ts_files: list of .ts file paths
        params.target_languages: restrict to specific language codes; empty = all
        params.min_coverage: flag languages below this fraction (0.0-1.0)


    Returns:
        str: a formatted text report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.ts_files:
        msg = "Error: ts_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if not (0.0 <= params.min_coverage <= 1.0):
        msg = f"Error: min_coverage must be 0..1, got {params.min_coverage}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Aggregate per-language stats
    stats: dict[str, dict] = {}  # language -> {"total": N, "finished": N, "empty": N, "obsolete": N, "files": [..]}

    def _ensure(lang: str) -> dict:
        if lang not in stats:
            stats[lang] = {"total": 0, "finished": 0, "unfinished": 0, "empty": 0, "obsolete": 0, "files": []}
        return stats[lang]

    parse_errors: list[str] = []
    for tf in params.ts_files:
        tpath = Path(tf)
        if not tpath.exists():
            parse_errors.append(f"missing: {tpath}")
            continue
        try:
            tree = ElementTree.parse(str(tpath))
        except ElementTree.ParseError as e:
            parse_errors.append(f"parse error in {tpath}: {e}")
            continue
        root = tree.getroot()
        if root.tag != "TS":
            parse_errors.append(f"unexpected root in {tpath}: {root.tag}")
            continue
        lang = root.attrib.get("language", tpath.stem)
        if params.target_languages and lang not in params.target_languages:
            continue
        s = _ensure(lang)
        s["files"].append(str(tpath))
        for msg in root.findall("context/message"):
            tr = msg.find("translation")
            if tr is None:
                s["unfinished"] += 1
                s["total"] += 1
                continue
            tt = tr.attrib.get("type", "")
            if tt == "obsolete":
                s["obsolete"] += 1
                continue
            s["total"] += 1
            text_nodes = list(tr)
            text = "".join((n.text or "") for n in text_nodes if n.tag == "text" or n.tag == "numerusform")
            if tt == "unfinished" or tt == "":
                if not text.strip():
                    s["unfinished"] += 1
                    s["empty"] += 1
                else:
                    s["finished"] += 1  # typed text but not marked finished
            elif tt == "finished":
                if not text.strip():
                    s["empty"] += 1
                s["finished"] += 1
            else:
                s["finished"] += 1

    flagged: list[tuple[str, float]] = []
    for lang, s in stats.items():
        cov = (s["finished"] / s["total"]) if s["total"] else 1.0
        if cov < params.min_coverage:
            flagged.append((lang, cov))

    out_lines = [
        f"=== qt_translation_validate: {len(stats)} language(s) across {len(params.ts_files)} file(s) ===",
    ]
    if parse_errors:
        out_lines.append("")
        out_lines.append("Errors:")
        for e in parse_errors:
            out_lines.append(f"  {e}")
    if stats:
        out_lines.append("")
        out_lines.append(f"{'Language':12s} {'Total':>6s} {'Done':>6s} {'Unfin':>6s} {'Empty':>6s} {'Obs':>6s} {'Coverage':>10s}")
        for lang in sorted(stats.keys()):
            s = stats[lang]
            cov = (s["finished"] / s["total"]) if s["total"] else 1.0
            out_lines.append(
                f"{lang:12s} {s['total']:>6d} {s['finished']:>6d} {s['unfinished']:>6d} {s['empty']:>6d} {s['obsolete']:>6d} {cov * 100:>9.2f}%"
            )
    if flagged:
        out_lines.append("")
        out_lines.append(f"Flagged below {params.min_coverage * 100:.1f}% coverage:")
        for lang, cov in flagged:
            out_lines.append(f"  {lang}: {cov * 100:.2f}%")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"languages": len(stats), "flagged": [list(x) for x in flagged], "stats": stats}})


# --- v0.2.8 qt_git_init: initialize a git repo for a Qt project --------------

_QT_GITIGNORE_TEMPLATE = """\
# Qt build artifacts
build-*/
debug/
release/
*.pro.user
*.pro.user.*
moc_*.cpp
moc_*.h
qrc_*.cpp
ui_*.h
*.qmlc
*.jsc

# Executables
*.exe
*.exe~
*.dll
*.so
*.dylib

# Object files
*.o
*.obj
*.a
*.lib

# Qt Creator
CMakeLists.txt.user
.qmake.stash
.qmlls.ini
.qtc_clangd/

# v0.2.8: qt-mcp runtime cache
.tmp/
.qt_mcp_last_build.log
.input_recordings/

# Editor / IDE
.vscode/
.idea/
*.swp
*~

# OS
.DS_Store
Thumbs.db

# Python
__pycache__/
*.py[cod]
.pytest_cache/
"""

@mcp.tool(name="qt_git_init", annotations={"title": "Initialize a git repository for a Qt project", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_git_init(params: QtGitInitInput) -> str:
    """Initialize a git repo for a Qt project inside the sandbox.

    Generates a Qt-specific `.gitignore` (build artifacts, moc_*, ui_*, *.user,
    .tmp/, etc.), optionally generates a README.md, then runs `git init`,
    `git add .`, and `git commit` with the given initial message.

    Args:
        params.project_dir: absolute path of the Qt project directory.
        params.git_user_name: optional git config user.name (empty = use existing).
        params.git_user_email: optional git config user.email (empty = use existing).
        params.initial_message: message for the initial commit.
        params.generate_readme: if True, generate a README.md if missing.
        params.generate_gitignore: if True, generate a Qt .gitignore (overwrites if exists).

    Returns:
        str: report listing the steps performed + initial commit SHA.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj.exists() or not proj.is_dir():
        msg = f"Error: project_dir does not exist or is not a directory: {proj}"
        return msg + _json_footer({"ok": False, "error": msg})
    if (proj / ".git").exists():
        msg = f"Error: already a git repo: {proj / '.git'}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Check git binary
    if not shutil.which("git"):
        msg = "Error: git not found on PATH; install git for Windows first"
        return msg + _json_footer({"ok": False, "error": msg})

    steps: list[str] = []
    warnings: list[str] = []

    # Step 1: .gitignore
    if params.generate_gitignore:
        gi = proj / ".gitignore"
        gi.write_text(_QT_GITIGNORE_TEMPLATE, encoding="utf-8")
        steps.append(f"wrote {gi.relative_to(proj)} ({len(_QT_GITIGNORE_TEMPLATE)} bytes)")

    # Step 2: README
    if params.generate_readme and not (proj / "README.md").exists():
        # Try to infer project name from any .pro file
        pro_files = list(proj.glob("*.pro"))
        proj_name = pro_files[0].stem if pro_files else proj.name
        readme_text = (
            f"# {proj_name}\n\n"
            f"Qt project.\n\n"
            f"## Build\n\n"
            f"```bash\nqmake\nmingw32-make\n```\n\n"
            f"## Files\n\n"
            f"- `.pro` — qmake project file\n"
            f"- `main.cpp` / `mainwindow.h` / `mainwindow.cpp` / `mainwindow.ui` — entry point\n"
        )
        (proj / "README.md").write_text(readme_text, encoding="utf-8")
        steps.append(f"wrote README.md (project name: {proj_name})")
    elif (proj / "README.md").exists():
        steps.append("README.md already exists, skipped")

    # Step 3: git init
    try:
        proc = await asyncio.create_subprocess_exec(
            "git", "init", str(proj),
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE,
        )
        stdout, stderr = await asyncio.wait_for(proc.communicate(), timeout=15)
        if proc.returncode != 0:
            msg = f"Error: git init failed: {stderr.decode('utf-8', errors='replace').strip()}"
            return msg + _json_footer({"ok": False, "error": msg})
        steps.append("git init")
    except asyncio.TimeoutError:
        msg = "Error: git init timed out after 15s"
        return msg + _json_footer({"ok": False, "error": msg})

    # Step 4: git config (if provided)
    if params.git_user_name:
        try:
            proc = await asyncio.create_subprocess_exec(
                "git", "config", "user.name", params.git_user_name,
                stdout=asyncio.subprocess.DEVNULL, stderr=asyncio.subprocess.DEVNULL,
                cwd=str(proj),
            )
            await asyncio.wait_for(proc.communicate(), timeout=10)
            steps.append(f"git config user.name = {params.git_user_name}")
        except asyncio.TimeoutError:
            warnings.append("git config user.name timed out")
    if params.git_user_email:
        try:
            proc = await asyncio.create_subprocess_exec(
                "git", "config", "user.email", params.git_user_email,
                stdout=asyncio.subprocess.DEVNULL, stderr=asyncio.subprocess.DEVNULL,
                cwd=str(proj),
            )
            await asyncio.wait_for(proc.communicate(), timeout=10)
            steps.append(f"git config user.email = {params.git_user_email}")
        except asyncio.TimeoutError:
            warnings.append("git config user.email timed out")

    # Step 5: git add .
    try:
        proc = await asyncio.create_subprocess_exec(
            "git", "add", ".",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE,
            cwd=str(proj),
        )
        stdout, stderr = await asyncio.wait_for(proc.communicate(), timeout=60)
        if proc.returncode != 0:
            msg = f"Error: git add . failed: {stderr.decode('utf-8', errors='replace').strip()}"
            return msg + _json_footer({"ok": False, "error": msg})
        steps.append("git add .")
    except asyncio.TimeoutError:
        msg = "Error: git add . timed out after 60s"
        return msg + _json_footer({"ok": False, "error": msg})

    # Step 6: git commit
    try:
        proc = await asyncio.create_subprocess_exec(
            "git", "commit", "-m", params.initial_message,
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE,
            cwd=str(proj),
        )
        stdout, stderr = await asyncio.wait_for(proc.communicate(), timeout=60)
        if proc.returncode != 0:
            err_text = stderr.decode("utf-8", errors="replace").strip()
            # "nothing to commit" is not really an error if .gitignore covered everything
            if "nothing to commit" in err_text.lower():
                steps.append("git commit (nothing to commit — all files ignored)")
                commit_sha = ""
            else:
                msg = f"Error: git commit failed: {err_text}"
                return msg + _json_footer({"ok": False, "error": msg})
        else:
            out_text = stdout.decode("utf-8", errors="replace").strip()
            steps.append(f"git commit -m \"{params.initial_message}\"")
            commit_sha = ""
            # Parse SHA from "1 file changed, ... create mode ..." line — git commit output format
            sha_match = re.search(r"\[[\w-]+\s+\(root-commit\)\s+([a-f0-9]+)\]", out_text)
            if not sha_match:
                sha_match = re.search(r"\[[\w-]+\s+([a-f0-9]+)\]", out_text)
            if sha_match:
                commit_sha = sha_match.group(1)
            else:
                warnings.append("commit SHA not found in git output")
    except asyncio.TimeoutError:
        msg = "Error: git commit timed out after 60s"
        return msg + _json_footer({"ok": False, "error": msg})

    out_lines = [
        f"=== qt_git_init: {proj} ===",
        "",
    ]
    out_lines.append("Steps performed:")
    for s in steps:
        out_lines.append(f"  + {s}")
    if commit_sha:
        out_lines.append("")
        out_lines.append(f"Initial commit SHA: {commit_sha}")
    if warnings:
        out_lines.append("")
        out_lines.append("Warnings:")
        for w in warnings:
            out_lines.append(f"  ! {w}")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"project_dir": str(proj), "commit_sha": commit_sha, "steps": steps, "warnings": warnings}})


# --- v0.2.8 qt_installer_gen: generate NSIS or Inno Setup script -------------

_NSIS_TEMPLATE = '''\
; Auto-generated by qt-mcp qt_installer_gen (v0.2.8)
; Run build_installer.bat to compile.

!include "MUI2.nsh"

Name "{app_name}"
Caption "{app_name} Setup ({vendor})"
OutFile "{out_basename}-{app_version}-setup.exe"
InstallDir "$PROGRAMFILES\\{app_name}"
RequestExecutionLevel user

!insertmacro MUI_PAGE_DIRECTORY
!insertmacro MUI_PAGE_INSTFILES

!define MUI_LANGUAGE "English"

Section "Install"
  SetOutPath "$INSTDIR"
  File /r "deploy\\*.*"
  CreateShortcut "$DESKTOP\\{app_name}.lnk" "$INSTDIR\\{exe_basename}"
  WriteUninstaller "$INSTDIR\\Uninstall.exe"
SectionEnd

Section "Uninstall"
  RMDir /r "$INSTDIR"
  Delete "$DESKTOP\\{app_name}.lnk"
SectionEnd
'''

_INNO_TEMPLATE = '''\
; Auto-generated by qt-mcp qt_installer_gen (v0.2.8)
; Run build_installer.bat to compile.

[Setup]
AppName={app_name}
AppVersion={app_version}
AppPublisher={vendor}
DefaultDirName={{pf}}\\{app_name}
OutputBaseFilename={out_basename}-{app_version}-setup
Compression=lzma2
SolidCompression=yes

[Files]
Source: "deploy\\*"; DestDir: "{{app}}"; Flags: ignoreversion recursesubdirs createallsubdirs

[Icons]
Name: "{{commondesktop}}\\{app_name}"; Filename: "{{app}}\\{exe_basename}"

[Run]
Filename: "{{app}}\\{exe_basename}"; Description: "Launch {app_name}"; Flags: nowait postinstall skipifsilent
'''


@mcp.tool(name="qt_installer_gen", annotations={"title": "Generate an NSIS or Inno Setup installer script + build batch", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_installer_gen(params: QtInstallerGenInput) -> str:
    """Generate a Windows installer script (NSIS .nsi or Inno Setup .iss) plus
    a build_installer.bat that runs `windeployqt` then the compiler.

    Does NOT actually invoke makensis / iscc — the user runs the batch file
    after installing NSIS or Inno Setup on their machine.

    Args:
        params.output_dir: absolute path where script + batch will be written.
        params.exe_path: absolute path of the main .exe to bundle.
        params.app_name: application name (shown in installer UI).
        params.app_version: version string (e.g. '1.0.0').
        params.installer_type: 'nsis' or 'inno'.
        params.vendor: optional vendor / publisher name.
        params.license_file: optional absolute path to LICENSE file to embed.
        params.qml_dir: optional QML source dir passed to windeployqt --qmldir.

    Returns:
        str: report listing the files written + a snippet of the batch script.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    out_dir = Path(params.output_dir)
    exe_path = Path(params.exe_path)
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    sandbox_err = _require_sandbox(exe_path, "exe_path")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not out_dir.exists():
        out_dir.mkdir(parents=True, exist_ok=True)
    if not exe_path.exists() or not exe_path.is_file():
        msg = f"Error: exe_path not found: {exe_path}"
        return msg + _json_footer({"ok": False, "error": msg})
    inst_type = params.installer_type.lower().strip()
    if inst_type not in ("nsis", "inno"):
        msg = f"Error: installer_type must be 'nsis' or 'inno', got {inst_type!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    app_name_safe = re.sub(r"[^A-Za-z0-9_.-]", "_", params.app_name)
    exe_basename = exe_path.name
    out_basename = app_name_safe
    vendor = params.vendor or "Unknown"

    license_text = ""
    if params.license_file:
        lic = Path(params.license_file)
        sandbox_err = _require_sandbox(lic, "license_file")
        if sandbox_err is None and lic.exists() and lic.is_file():
            try:
                license_text = lic.read_text(encoding="utf-8", errors="replace")
            except OSError:
                license_text = ""
            license_text = license_text.replace("\r\n", "\n")
        else:
            license_text = ""

    if inst_type == "nsis":
        script_content = _NSIS_TEMPLATE.format(
            app_name=app_name_safe,
            app_version=params.app_version,
            out_basename=out_basename,
            exe_basename=exe_basename,
            vendor=vendor,
        )
        script_name = f"{app_name_safe}.nsi"
        compiler = "makensis"
    else:
        script_content = _INNO_TEMPLATE.format(
            app_name=app_name_safe,
            app_version=params.app_version,
            vendor=vendor,
            out_basename=out_basename,
            exe_basename=exe_basename,
        )
        script_name = f"{app_name_safe}.iss"
        compiler = "iscc"

    # Append license to script if provided
    if license_text:
        if inst_type == "nsis":
            script_content += "\n; LICENSE:\n; " + license_text.replace("\n", "\n; ") + "\n"
        else:
            script_content += f"\n[Code]\nfunction InitializeSetup(): Boolean;\nbegin\n  Result := True;\nend;\n\n"
            script_content += "; LICENSE:\n; " + license_text.replace("\n", "\n; ") + "\n"

    script_path = out_dir / script_name
    script_path.write_text(script_content, encoding="utf-8")

    # build_installer.bat: windeployqt + makensis/iscc
    windeployqt = str(QT_BIN_DIR / "windeployqt.exe")
    qml_dir_line = f'--qmldir "{params.qml_dir}"' if params.qml_dir else ""
    batch = (
        "@echo off\n"
        "REM Auto-generated by qt-mcp qt_installer_gen (v0.2.8)\n"
        "setlocal\n"
        f'windeployqt --release {qml_dir_line} "{exe_path}"\n'
        f'if errorlevel 1 exit /b 1\n'
        f'"{compiler}" "{script_path}"\n'
        f'if errorlevel 1 exit /b 1\n'
        "endlocal\n"
    )
    batch_path = out_dir / "build_installer.bat"
    batch_path.write_text(batch, encoding="utf-8")

    out_lines = [
        f"=== qt_installer_gen: {params.installer_type} for {params.app_name} v{params.app_version} ===",
        "",
        f"  Script: {script_path}",
        f"  Batch:  {batch_path}",
        f"  Exe:    {exe_path}",
        "",
        "Next steps:",
        f"  1. Install {compiler} (NSIS or Inno Setup)",
        f"  2. Run: {batch_path}",
        "",
        "Batch contents:",
        "  " + batch.replace("\n", "\n  "),
    ]
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"script": str(script_path), "batch": str(batch_path), "installer_type": inst_type, "compiler": compiler}})


