@mcp.tool(name="qt_qml_component_gen", annotations={"title": "Generate reusable QML components for board games", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qml_component_gen(params: QtQmlComponentGenInput) -> str:
    """Generate ready-to-use QML components for board-game UIs.

    Each component is a self-contained .qml file with default styling. A
    top-level qmldir is also written for module imports.

    Args:
        params.output_dir: absolute path where .qml files will be written.
        params.components: list of component names (must be one of card/board/player/hand/deck/tile).
        params.namespace: QML import namespace used in qmldir 'module' line.
        params.theme: 'dark' or 'light' (drives default colors baked into components).

    Returns:
        str: report listing each component file written + qmldir.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    out_dir = Path(params.output_dir)
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    out_dir.mkdir(parents=True, exist_ok=True)
    available = set(_QML_COMPONENT_TEMPLATES.keys())
    unknown = [c for c in params.components if c not in available]
    if unknown:
        msg = f"Error: unknown component(s): {unknown}; available: {sorted(available)}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not params.components:
        msg = "Error: components list is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.theme not in ("dark", "light"):
        msg = f"Error: theme must be 'dark' or 'light', got {params.theme!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    written: list[str] = []
    for comp in params.components:
        tpl = _QML_COMPONENT_TEMPLATES[comp]
        out_path = out_dir / tpl["filename"]
        out_path.write_text(tpl["qml"], encoding="utf-8")
        written.append(str(out_path))

    # Write a qmldir at the top of output_dir so Qt Creator picks it up as a module
    qmldir_path = out_dir / "qmldir"
    qmldir_lines = [f"module {params.namespace}", ""]
    for comp in params.components:
        tpl = _QML_COMPONENT_TEMPLATES[comp]
        comp_name = tpl["filename"].rsplit(".", 1)[0]
        qmldir_lines.append(f"{comp_name} 1.0 {tpl['filename']}")
    qmldir_path.write_text("\n".join(qmldir_lines) + "\n", encoding="utf-8")

    out_lines = [
        f"=== qt_qml_component_gen: {len(params.components)} component(s) in {params.theme} theme ===",
        "",
    ]
    for w in written:
        out_lines.append(f"  wrote {Path(w).relative_to(out_dir)} — {_QML_COMPONENT_TEMPLATES[Path(w).stem.lower()]['description']}")
    out_lines.append(f"  wrote qmldir (module: {params.namespace})")
    out_lines.append("")
    out_lines.append("Usage: in main QML, add to .pro:")
    out_lines.append("  RESOURCES += qml/qmldir")
    out_lines.append("and in QML:")
    out_lines.append(f"  import {params.namespace} 1.0")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"output_dir": str(out_dir), "theme": params.theme, "components": params.components, "files": written, "qmldir": str(qmldir_path)}})


# --- v0.2.8 qt_db_seed: SQLite schema + seed data + CRUD examples -------------

_SQLITE_TYPE_MAP = {
    "TEXT": str, "INTEGER": int, "REAL": float, "BLOB": bytes, "NUMERIC": (int, float),
}


@mcp.tool(name="qt_db_seed", annotations={"title": "Create a SQLite database with schema + seed data + CRUD examples", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})


def _db_mysql_compat_report() -> str:
    """Probe the system for MySQL/MariaDB compatibility with Qt 5.14.2.

    Based on JB51 PDF Chapter 22. For Qt 5.14.2 + MinGW 7.3, QMYSQL driver
    is NOT prebuilt; must be compiled from source or use MariaDB connector
    (drop-in replacement for libmysql.dll).
    """
    lines = ["=== MySQL/QMYSQL driver compatibility ==="]
    qt_root = _env_path("QT_MCP_QT_ROOT", "E:/Download_tools/QT/5.14.2/mingw73_64")
    qt_32 = _env_path("QT_MCP_QT_32_ROOT", "E:/Download_tools/QT/5.14.2/mingw73_32")
    for root, label in [(qt_root, "Qt 64-bit"), (qt_32, "Qt 32-bit")]:
        if not root.exists():
            continue
        driver_dir = root / "plugins" / "sqldrivers"
        if not driver_dir.exists():
            lines.append(f"  [{label}] {driver_dir} not present")
            continue
        mysql_drv = driver_dir / "qsqlmysql.dll"
        mariadb_drv = driver_dir / "qsqlmariadb.dll"
        found = []
        if mysql_drv.exists():
            found.append(f"qsqlmysql.dll ({mysql_drv.stat().st_size} bytes)")
        if mariadb_drv.exists():
            found.append(f"qsqlmariadb.dll ({mariadb_drv.stat().st_size} bytes)")
        if found:
            lines.append(f"  [{label}] driver present: {', '.join(found)}")
        else:
            lines.append(f"  [{label}] NO QMYSQL / QSQLMariaDB driver in {driver_dir}")
            lines.append(f"           -> compile from Qt source OR use MariaDB connector (drop-in)")
    libmysql = shutil.which("libmysql.dll") or shutil.which("libmariadb.dll")
    lines.append(f"  [PATH] libmysql.dll / libmariadb.dll: {libmysql or 'NOT on PATH'}")
    mysql_exe = shutil.which("mysql.exe") or shutil.which("mariadb.exe")
    lines.append(f"  [PATH] mysql / mariadb CLI: {mysql_exe or 'NOT on PATH (only for testing, not Qt runtime)'}")
    mysql_config = shutil.which("mysql_config")
    lines.append(f"  [PATH] mysql_config: {mysql_config or 'NOT found (only needed for building QMYSQL from source)'}")
    lines.append("")
    lines.append("  To enable MySQL support in your Qt project:")
    lines.append("    1. Add QT += sql to your .pro file")
    lines.append("    2. Use QSqlDatabase::addDatabase(\"QMYSQL\") in code")
    lines.append("    3. Ensure libmysql.dll / libmariadb.dll is in your .exe dir at deploy time")
    lines.append("    4. For Qt 5.14.2 + MinGW prebuilt: QMYSQL driver not shipped;")
    lines.append("       compile from source (JB51 Ch 22) or use MariaDB connector (drop-in)")
    return "\n".join(lines)


async def qt_db_seed(params: QtDbSeedInput) -> str:
    """Create a SQLite .db file from a schema definition, optionally insert seed
    rows, and generate a Python file with CRUD helpers (insert/select/update/delete).

    Args:
        params.db_path: absolute path of .db file to create.
        params.tables: list of {name, columns[{name, type, pk, not_null, default}]}.
        params.seed_data: mapping table_name -> list[row_dict] of seed rows.
        params.generate_query_examples: if True, write <db>_examples.py with CRUD.

    Returns:
        str: report listing tables created, seed rows inserted, examples file path.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    db_path = Path(params.db_path)
    sandbox_err = _require_sandbox(db_path, "db_path")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not params.tables:
        msg = "Error: tables is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if db_path.exists():
        msg = f"Error: db already exists: {db_path} (delete it first or pick another path)"
        return msg + _json_footer({"ok": False, "error": msg})

    parent = db_path.parent
    if not parent.exists():
        msg = f"Error: parent dir does not exist: {parent}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Build CREATE TABLE statements
    created_tables: list[str] = []
    errors: list[str] = []

    try:
        conn = sqlite3.connect(str(db_path))
        cur = conn.cursor()
        for tbl in params.tables:
            if not isinstance(tbl, dict) or "name" not in tbl or "columns" not in tbl:
                errors.append(f"invalid table entry: {tbl}")
                continue
            tname = tbl["name"]
            cols = tbl["columns"]
            col_defs = []
            pk_cols = []
            for c in cols:
                cname = c["name"]
                ctype = c.get("type", "TEXT").upper()
                if ctype not in _SQLITE_TYPE_MAP:
                    errors.append(f"unknown type {ctype!r} for column {tname}.{cname}")
                    continue
                parts = [cname, ctype]
                if c.get("pk"):
                    parts.append("PRIMARY KEY")
                    pk_cols.append(cname)
                if c.get("not_null"):
                    parts.append("NOT NULL")
                if "default" in c:
                    default = c["default"]
                    if isinstance(default, str):
                        parts.append(f"DEFAULT '{default.replace(chr(39), chr(39) * 2)}'")
                    elif isinstance(default, bool):
                        parts.append(f"DEFAULT {1 if default else 0}")
                    elif default is None:
                        parts.append("DEFAULT NULL")
                    else:
                        parts.append(f"DEFAULT {default}")
                col_defs.append(" ".join(parts))
            ddl = f"CREATE TABLE {tname} (\n  " + ",\n  ".join(col_defs) + "\n);"
            try:
                cur.execute(ddl)
                created_tables.append(tname)
            except sqlite3.Error as e:
                errors.append(f"failed to create table {tname}: {e}")
        conn.commit()
    except sqlite3.Error as e:
        msg = f"Error: sqlite connection failed: {e}"
        return msg + _json_footer({"ok": False, "error": msg})
    finally:
        try:
            conn.close()
        except Exception:
            pass

    # Insert seed data
    seed_inserted = 0
    seed_failed = 0
    if params.seed_data:
        try:
            conn = sqlite3.connect(str(db_path))
            cur = conn.cursor()
            for tbl_name, rows in params.seed_data.items():
                if tbl_name not in created_tables:
                    errors.append(f"seed data references missing table: {tbl_name}")
                    continue
                if not isinstance(rows, list):
                    errors.append(f"seed_data[{tbl_name}] must be a list, got {type(rows).__name__}")
                    continue
                # Find column names for this table
                tbl_cols = [c["name"] for c in next(t["columns"] for t in params.tables if t["name"] == tbl_name)]
                placeholders = ",".join(["?"] * len(tbl_cols))
                for row in rows:
                    if not isinstance(row, dict):
                        seed_failed += 1
                        continue
                    vals = [row.get(c) for c in tbl_cols]
                    try:
                        cur.execute(f"INSERT INTO {tbl_name} ({','.join(tbl_cols)}) VALUES ({placeholders})", vals)
                        seed_inserted += 1
                    except sqlite3.Error as e:
                        errors.append(f"insert into {tbl_name} failed: {e}")
                        seed_failed += 1
            conn.commit()
            conn.close()
        except sqlite3.Error as e:
            errors.append(f"seed insert connection failed: {e}")

    # Generate CRUD examples
    examples_path = None
    if params.generate_query_examples and created_tables:
        py_lines = [
            f'"""CRUD examples for {db_path.name}. Auto-generated by qt-mcp qt_db_seed (v0.2.8)."""',
            "import sqlite3",
            f'from pathlib import Path',
            "",
            f"DB_PATH = Path(__file__).resolve().parent / {db_path.name!r}",
            "",
        ]
        for tname in created_tables:
            tbl = next(t["columns"] for t in params.tables if t["name"] == tname)
            cols = [c["name"] for c in tbl]
            pk_cols = [c["name"] for c in tbl if c.get("pk")]
            py_lines.append(f"# --- {tname} ---")
            py_lines.append(f"def select_all_{tname}() -> list[dict]:")
            py_lines.append(f'    """Return all rows from {tname} as list of dicts."""')
            py_lines.append(f"    conn = sqlite3.connect(str(DB_PATH))")
            py_lines.append(f"    conn.row_factory = sqlite3.Row")
            py_lines.append(f"    cur = conn.cursor()")
            py_lines.append(f"    cur.execute(f'SELECT * FROM {tname}')")
            py_lines.append(f"    rows = [dict(r) for r in cur.fetchall()]")
            py_lines.append(f"    conn.close()")
            py_lines.append(f"    return rows")
            py_lines.append("")
            col_list = ", ".join(cols)
            placeholders = ", ".join([":" + c for c in cols])
            py_lines.append(f"def insert_{tname}({', '.join([c + ': object = None' for c in cols])}) -> int:")
            py_lines.append(f'    """Insert a row into {tname}, return new rowid."""')
            py_lines.append(f"    conn = sqlite3.connect(str(DB_PATH))")
            py_lines.append(f"    cur = conn.cursor()")
            py_lines.append(f"    cur.execute(f'INSERT INTO {tname} ({col_list}) VALUES ({placeholders})', {{")
            for c in cols:
                py_lines.append(f"        {c!r}: {c},")
            py_lines.append(f"    }})")
            py_lines.append(f"    conn.commit()")
            py_lines.append(f"    new_id = cur.lastrowid")
            py_lines.append(f"    conn.close()")
            py_lines.append(f"    return new_id")
            py_lines.append("")
            if pk_cols:
                pk = pk_cols[0]
                py_lines.append(f"def delete_{tname}({pk}: int) -> int:")
                py_lines.append(f'    """Delete row(s) from {tname} by primary key, return rowcount."""')
                py_lines.append(f"    conn = sqlite3.connect(str(DB_PATH))")
                py_lines.append(f"    cur = conn.cursor()")
                py_lines.append(f"    cur.execute(f'DELETE FROM {tname} WHERE {pk} = ?', ({pk},))")
                py_lines.append(f"    rowcount = cur.rowcount")
                py_lines.append(f"    conn.commit()")
                py_lines.append(f"    conn.close()")
                py_lines.append(f"    return rowcount")
                py_lines.append("")
        examples_path = db_path.parent / f"{db_path.stem}_examples.py"
        examples_path.write_text("\n".join(py_lines), encoding="utf-8")

    out_lines = [
        f"=== qt_db_seed: {db_path} ===",
        "",
        f"Tables created ({len(created_tables)}):",
        *[f"  + {t}" for t in created_tables],
        "",
        f"Seed rows: {seed_inserted} inserted, {seed_failed} failed",
    ]
    if examples_path:
        out_lines.append(f"Examples file: {examples_path}")
    if errors:
        out_lines.append("")
        out_lines.append("Errors:")
        for e in errors:
            out_lines.append(f"  ! {e}")
    out = "\n".join(out_lines)
    if params.mysql_check:
        out += "\n\n" + _db_mysql_compat_report()
    return out + _json_footer({"ok": True, "data": {"db_path": str(db_path), "tables": created_tables, "seed_inserted": seed_inserted, "seed_failed": seed_failed, "examples_path": str(examples_path) if examples_path else None, "errors": errors}})


# --- v0.2.8 qt_high_dpi_test: launch .exe at multiple QT_SCALE_FACTORs --------

@mcp.tool(name="qt_high_dpi_test", annotations={"title": "Launch .exe at multiple QT_SCALE_FACTORs and screenshot each", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_high_dpi_test(params: QtHighDpiTestInput) -> str:
    """Launch a .exe at multiple QT_SCALE_FACTOR values, screenshot the window
    for each, and (optionally) compare against a baseline screenshot.

    Uses pywinauto for screenshotting (falls back to pyautogui if unavailable).
    Always kills the launched process before returning.

    Args:
        params.executable: absolute path of the .exe to launch.
        params.scale_factors: list of scale factors to test (e.g. [1.0, 1.5, 2.0]).
        params.screenshot_dir: directory where screenshots will be saved.
        params.wait_seconds: seconds to wait after launch before screenshotting.
        params.compare_with_baseline: if True, compare each screenshot to a baseline.
        params.baseline_dir: directory of baseline screenshots (matched by scale_factor in filename).

    Returns:
        str: report listing each scale factor, screenshot path, and diff result.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    exe = Path(params.executable)
    sandbox_err = _require_sandbox(exe, "executable")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    shot_dir = Path(params.screenshot_dir)
    sandbox_err = _require_sandbox(shot_dir, "screenshot_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not params.scale_factors:
        msg = "Error: scale_factors is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.compare_with_baseline and not params.baseline_dir:
        msg = "Error: baseline_dir is required when compare_with_baseline=True"
        return msg + _json_footer({"ok": False, "error": msg})
    if not exe.exists() or not exe.is_file():
        msg = f"Error: executable not found: {exe}"
        return msg + _json_footer({"ok": False, "error": msg})
    shot_dir.mkdir(parents=True, exist_ok=True)

    if params.compare_with_baseline and not params.baseline_dir:
        msg = "Error: baseline_dir is required when compare_with_baseline=True"
        return msg + _json_footer({"ok": False, "error": msg})

    # Try pywinauto for screenshot; if not installed, fall back to subprocess + file-existence check
    have_pywinauto = False
    try:
        import pywinauto  # type: ignore  # noqa: F401
        have_pywinauto = True
    except ImportError:
        have_pywinauto = False

    results: list[dict] = []
    errors: list[str] = []

    for scale in params.scale_factors:
        scale_str = f"{scale}".replace(".", "_")
        screenshot_path = shot_dir / f"screenshot_scale_{scale_str}.png"
        env = os.environ.copy()
        env["QT_SCALE_FACTOR"] = str(scale)
        env["QT_LOGGING_TO_CONSOLE"] = "0"
        proc = None
        try:
            proc = await asyncio.create_subprocess_exec(
                str(exe),
                stdout=asyncio.subprocess.DEVNULL,
                stderr=asyncio.subprocess.DEVNULL,
                env=env,
                cwd=str(exe.parent),
            )
            await asyncio.sleep(params.wait_seconds)
            # Try to capture the window
            captured = False
            if have_pywinauto:
                try:
                    from pywinauto import Application  # type: ignore
                    app = Application(backend="win32").connect(process=proc.pid, timeout=5)
                    win = app.window(process=proc.pid)
                    img = win.capture_as_image()
                    img.save(str(screenshot_path))
                    captured = True
                except Exception as e:
                    errors.append(f"pywinauto capture failed at scale {scale}: {e}")
            if not captured:
                # Fallback: just note the process started; no screenshot file
                screenshot_path = None  # type: ignore
        except Exception as e:
            errors.append(f"launch failed at scale {scale}: {e}")
        finally:
            if proc and proc.returncode is None:
                try:
                    proc.terminate()
                    await asyncio.wait_for(proc.wait(), timeout=3)
                except (asyncio.TimeoutError, ProcessLookupError):
                    try:
                        proc.kill()
                    except Exception:
                        pass

        entry: dict = {"scale": scale, "screenshot": str(screenshot_path) if screenshot_path else None}
        if params.compare_with_baseline and screenshot_path:
            baseline_dir = Path(params.baseline_dir)
            sandbox_err = _require_sandbox(baseline_dir, "baseline_dir")
            if sandbox_err is None:
                baseline_path = baseline_dir / f"screenshot_scale_{scale_str}.png"
            if baseline_path.exists():
                # Quick pixel diff using PIL
                try:
                    from PIL import Image  # type: ignore
                    import numpy as np  # type: ignore
                    a = np.array(Image.open(str(baseline_path)).convert("RGB"))
                    b = np.array(Image.open(str(screenshot_path)).convert("RGB"))
                    if a.shape != b.shape:
                        entry["baseline_diff"] = "size_mismatch"
                    else:
                        diff = np.any(np.abs(a.astype(int) - b.astype(int)) > 5, axis=-1).sum()
                        entry["baseline_diff_pixels"] = int(diff)
                except Exception as e:
                    entry["baseline_diff"] = f"error: {e}"
            else:
                entry["baseline_diff"] = "baseline_missing"
        results.append(entry)

    out_lines = [
        f"=== qt_high_dpi_test: {exe.name} at {len(params.scale_factors)} scale factor(s) ===",
        "",
        f"Screenshot dir: {shot_dir}",
        f"Wait seconds:   {params.wait_seconds}",
        f"pywinauto:      {have_pywinauto}",
        "",
        f"{'Scale':>6s}  {'Screenshot':>50s}  {'Baseline diff':>20s}",
    ]
    for r in results:
        scale_str = f"{r['scale']}"
        shot_str = Path(r['screenshot']).name if r['screenshot'] else "(no capture)"
        baseline_str = ""
        if "baseline_diff_pixels" in r:
            baseline_str = f"{r['baseline_diff_pixels']} pixels"
        elif "baseline_diff" in r:
            baseline_str = r["baseline_diff"]
        out_lines.append(f"{scale_str:>6s}  {shot_str:>50s}  {baseline_str:>20s}")
    if errors:
        out_lines.append("")
        out_lines.append("Errors:")
        for e in errors:
            out_lines.append(f"  ! {e}")
    out = "\n".join(out_lines)
    return out + _json_footer({"ok": True, "data": {"exe": str(exe), "screenshot_dir": str(shot_dir), "results": results, "errors": errors}})


# --- v0.2.8 qt_property_browser: parse Q_PROPERTY from .h file ----------------

# Matches a single Q_PROPERTY line (possibly multi-line via \ at end)
_QPROP_RE = re.compile(
    r"Q_PROPERTY\s*\(\s*"
    r"(?P<type>[^()]+?)"  # type may contain templates like QList<int>
    r"\s+(?P<name>\w+)"
    r"(?P<rest>.*?)"
    r"\)",
    re.DOTALL,
)

_QPROP_CLAUSE_RE = re.compile(r"\b(READ|WRITE|RESET|NOTIFY|REVISION|DESIGNABLE|SCRIPTABLE|STORED|USER|MEMBER|CONSTANT|FINAL)\b")


@mcp.tool(name="qt_property_browser", annotations={"title": "Parse Q_PROPERTY declarations from a .h file and render as a table", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_property_browser(params: QtPropertyBrowserInput) -> str:
    """Extract all Q_PROPERTY declarations from a Qt header file and render them
    as a table (markdown, html, or json).

    Useful for documenting public APIs, generating cheat-sheets, or auditing
    the meta-object surface of a class.

    Args:
        params.header: absolute path of the .h file.
        params.output_format: 'markdown' (default), 'html', or 'json'.
        params.output_file: if non-empty, write to this path (else return as string).

    Returns:
        str: rendered property table, or confirmation of file write.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    hpath = Path(params.header)
    sandbox_err = _require_sandbox(hpath, "header")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not hpath.exists() or not hpath.is_file():
        msg = f"Error: header not found: {hpath}"
        return msg + _json_footer({"ok": False, "error": msg})
    fmt = params.output_format.lower().strip()
    if fmt not in ("markdown", "html", "json"):
        msg = f"Error: output_format must be markdown/html/json, got {fmt!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    try:
        src = hpath.read_text(encoding="utf-8", errors="replace")
    except OSError as e:
        msg = f"Error: failed to read {hpath}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Strip C++ comments to avoid false matches inside /* Q_PROPERTY(...) */
    no_block = re.sub(r"/\*.*?\*/", "", src, flags=re.DOTALL)
    no_comments = re.sub(r"//[^\n]*", "", no_block)

    properties: list[dict] = []
    for m in _QPROP_RE.finditer(no_comments):
        ptype = m.group("type").strip()
        pname = m.group("name").strip()
        rest = m.group("rest")
        clauses: dict[str, str] = {}
        # Tokenize: each clause is NAME followed by its argument (if any)
        # e.g. "READ getX WRITE setX NOTIFY xChanged CONSTANT"
        tokens = re.findall(r"(READ|WRITE|RESET|NOTIFY|REVISION|DESIGNABLE|SCRIPTABLE|STORED|USER|MEMBER|CONSTANT|FINAL)(?:\s+(\w+))?", rest)
        for k, v in tokens:
            clauses[k] = v if v else "yes"
        properties.append({"name": pname, "type": ptype, **clauses})

    if not properties:
        out_lines = [
            f"=== qt_property_browser: no Q_PROPERTY found in {hpath} ===",
        ]
        out = "\n".join(out_lines)
        return out + _json_footer({"ok": True, "data": {"header": str(hpath), "count": 0, "properties": []}})

    # Render
    if fmt == "json":
        rendered = json.dumps({"header": str(hpath), "count": len(properties), "properties": properties}, indent=2)
    elif fmt == "html":
        rows = []
        for p in properties:
            cells = "".join(f"<td>{p.get(k, '')}</td>" for k in ["name", "type", "READ", "WRITE", "NOTIFY", "MEMBER", "CONSTANT"])
            rows.append(f"<tr>{cells}</tr>")
        rendered = (
            f"<!DOCTYPE html><html><head><meta charset='utf-8'><title>Q_PROPERTY — {hpath.name}</title></head>\n"
            f"<body><h1>Q_PROPERTY — {hpath.name}</h1>\n"
            f"<table border='1' cellpadding='4'><thead><tr>"
            f"<th>Name</th><th>Type</th><th>READ</th><th>WRITE</th><th>NOTIFY</th><th>MEMBER</th><th>CONSTANT</th>"
            f"</tr></thead><tbody>\n" + "\n".join(rows) + "\n</tbody></table></body></html>"
        )
    else:  # markdown
        headers = ["Name", "Type", "READ", "WRITE", "NOTIFY", "MEMBER", "CONSTANT"]
        md_rows = ["| " + " | ".join(headers) + " |", "|" + "|".join(["---"] * len(headers)) + "|"]
        for p in properties:
            cells = [str(p.get(k.lower(), "")) for k in headers]
            md_rows.append("| " + " | ".join(cells) + " |")
        rendered = f"# Q_PROPERTY — {hpath.name}\n\n" + "\n".join(md_rows)

    if params.output_file:
        out_path = Path(params.output_file)
        sandbox_err = _require_sandbox(out_path, "output_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_text(rendered, encoding="utf-8")
        return f"=== qt_property_browser: wrote {out_path} ({len(properties)} properties) ===\n" + _json_footer({"ok": True, "data": {"header": str(hpath), "output_file": str(out_path), "count": len(properties), "format": fmt}})
    return rendered + "\n" + _json_footer({"ok": True, "data": {"header": str(hpath), "count": len(properties), "format": fmt}})


# --- v0.2.9 qt_env_diff: compare two Qt SDK environments ---------------------

class QtEnvDiffInput(BaseModel):
    env_a_path: str = Field(..., description="Absolute path to first Qt install root (e.g. mingw73_64).")
    env_b_path: str = Field(..., description="Absolute path to second Qt install root (e.g. mingw73_32).")


@mcp.tool(name="qt_env_diff", annotations={"title": "Compare two Qt SDK environments (qmake version, modules, libs)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_env_diff(params: QtEnvDiffInput) -> str:
    """Compare two Qt SDK installations side-by-side, finding differences in
    qmake version, available modules, library counts, and missing components.

    Useful when a project works on machine A but not on machine B, or when
    debugging a MinGW32 vs MinGW64 kit mismatch (the classic "wrong DLL
    architecture" symptom).

    Args:
        params.env_a_path: absolute path to first Qt install root (e.g. QT_ROOT).
        params.env_b_path: absolute path to second Qt install root.

    Returns:
        str: side-by-side comparison report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    a = Path(params.env_a_path)
    b = Path(params.env_b_path)
    for p, name in [(a, "env_a_path"), (b, "env_b_path")]:
        sandbox_err = _require_sandbox(p, name)
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        if not p.exists() or not p.is_dir():
            msg = f"Error: {name} does not exist or is not a directory: {p}"
            return msg + _json_footer({"ok": False, "error": msg})

    def _qmake_version(root: Path) -> str:
        qmake = root / "bin" / "qmake.exe"
        if not qmake.exists():
            return "(qmake.exe not found)"
        try:
            r = subprocess.run([str(qmake), "-v"], capture_output=True, text=True, timeout=5)
            out = (r.stdout or "") + (r.stderr or "")
            line1 = out.strip().splitlines()[0] if out.strip() else "(empty output)"
            return line1
        except subprocess.TimeoutExpired:
            return "(qmake timeout)"
        except Exception as e:
            return f"(error: {e})"

    def _modules(root: Path) -> set[str]:
        inc = root / "include"
        if not inc.exists():
            return set()
        return {d.name for d in inc.iterdir() if d.is_dir() and d.name.startswith("Qt")}

    def _lib_count(root: Path) -> int:
        lib_dir = root / "lib"
        if not lib_dir.exists():
            return 0
        return sum(1 for f in lib_dir.iterdir() if f.suffix in (".a", ".dll", ".lib"))

    a_ver = _qmake_version(a)
    b_ver = _qmake_version(b)
    a_mods = _modules(a)
    b_mods = _modules(b)
    a_libs = _lib_count(a)
    b_libs = _lib_count(b)

    only_a = sorted(a_mods - b_mods)
    only_b = sorted(b_mods - a_mods)
    common = sorted(a_mods & b_mods)

    lines = [
        "=== qt_env_diff ===",
        "",
        f"A: {a}",
        f"   qmake:  {a_ver}",
        f"   modules:{len(a_mods):4d}     libs: {a_libs}",
        "",
        f"B: {b}",
        f"   qmake:  {b_ver}",
        f"   modules:{len(b_mods):4d}     libs: {b_libs}",
        "",
        f"Common modules: {len(common)}",
    ]
    if only_a:
        lines.append("")
        lines.append(f"Only in A ({len(only_a)}):")
        for m in only_a:
            lines.append(f"  + {m}")
    if only_b:
        lines.append("")
        lines.append(f"Only in B ({len(only_b)}):")
        for m in only_b:
            lines.append(f"  + {m}")
    if a_libs != b_libs:
        lines.append("")
        lines.append(f"Lib count differs: A={a_libs} vs B={b_libs} (delta={abs(a_libs - b_libs)})")

    out = "\n".join(lines)
    return out + _json_footer({"ok": True, "data": {"env_a": str(a), "env_b": str(b), "qmake_a": a_ver, "qmake_b": b_ver, "modules_a": len(a_mods), "modules_b": len(b_mods), "libs_a": a_libs, "libs_b": b_libs, "only_in_a": only_a, "only_in_b": only_b, "common_count": len(common)}})


# --- v0.2.9 qt_dll_search_path: analyze DLL search path for a Qt exe ---------

class QtDllSearchPathInput(BaseModel):
    executable: str = Field(..., description="Absolute path to the Qt .exe to analyze.")
    search_dirs: list[str] = Field(default_factory=list, description="Extra directories to check (beyond .exe dir, Qt bin dirs, and PATH).")


_DLL_NAME_RE = re.compile(r"\s*DLL Name:\s*(\S+)")


@mcp.tool(name="qt_dll_search_path", annotations={"title": "Analyze DLL search path for a Qt .exe (find missing Qt5*.dll)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_dll_search_path(params: QtDllSearchPathInput) -> str:
    """Analyze the DLL search path for a Qt executable. Uses objdump to extract
    the full list of DLL imports, then walks the standard Windows search order
    (.exe dir -> Qt bin dirs -> PATH) and reports which DLLs are present and
    which are missing.

    This is the diagnostic companion to `qt_run` startup failures: when an exe
    crashes 0.4s after launch, 90% of the time it's a missing or wrong-bitness
    Qt5Core.dll.

    Args:
        params.executable: absolute path to the .exe.
        params.search_dirs: extra directories to inspect (in addition to .exe dir,
                            Qt 32/64 bin, and PATH).

    Returns:
        str: ordered search path + missing/found DLL report.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    exe = Path(params.executable)
    sandbox_err = _require_sandbox(exe, "executable")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not exe.exists() or not exe.is_file():
        msg = f"Error: executable not found: {exe}"
        return msg + _json_footer({"ok": False, "error": msg})

    try:
        r = subprocess.run([str(OBJDUMP), "-p", str(exe)], capture_output=True, text=True, timeout=15)
        required = _DLL_NAME_RE.findall(r.stdout + (r.stderr or ""))
    except subprocess.TimeoutExpired:
        msg = "Error: objdump timeout (>15s) — the .exe may be huge or on a slow disk"
        return msg + _json_footer({"ok": False, "error": msg})
    except Exception as e:
        msg = f"Error: objdump failed: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    if not required:
        msg = f"Error: objdump found 0 DLL imports in {exe} — is this a real PE file?"
        return msg + _json_footer({"ok": False, "error": msg})

    # Build search path in Windows standard order:
    #   1. .exe directory
    #   2. User-supplied search_dirs
    #   3. Qt 64-bit bin (default)
    #   4. Qt 32-bit bin (default)
    #   5. PATH
    search_path: list[Path] = [exe.parent]
    for d in params.search_dirs:
        p = Path(d)
        if p.exists():
            search_path.append(p)
    if QT_BIN_DIR.exists():
        search_path.append(QT_BIN_DIR)
    if QT_32_BIN_DIR.exists():
        search_path.append(QT_32_BIN_DIR)
    for p in os.environ.get("PATH", "").split(os.pathsep):
        s = p.strip()
        if s:
            search_path.append(Path(s))

    # Dedup preserving order
    seen: set[str] = set()
    unique_search: list[Path] = []
    for p in search_path:
        key = str(p).lower()
        if key not in seen:
            seen.add(key)
            unique_search.append(p)

    # Find each DLL (first hit wins)
    found: dict[str, str] = {}
    missing: list[str] = []
    for dll in required:
        for d in unique_search:
            cand = d / dll
            if cand.exists():
                found[dll] = str(cand)
                break
        else:
            missing.append(dll)

    lines = [
        f"=== qt_dll_search_path: {exe.name} ===",
        "",
        f"Required DLLs: {len(required)} (per objdump -p)",
        f"Search dirs:   {len(unique_search)}",
        f"Found:         {len(found)}",
        f"Missing:       {len(missing)}",
        "",
        "Search order (1 = highest priority):",
    ]
    shown = unique_search[:15]
    for i, d in enumerate(shown, 1):
        lines.append(f"  {i:2d}. {d}")
    if len(unique_search) > 15:
        lines.append(f"  ... and {len(unique_search) - 15} more PATH entries")

    lines.append("")
    if missing:
        lines.append(f"Missing DLLs ({len(missing)}):")
        for dll in missing:
            lines.append(f"  ! {dll}")
        lines.append("")
        lines.append("Hint: if any missing DLL starts with Qt5*, check the 32/64-bit bitness")
        lines.append("of your Qt bin dir. Use qt_env_diff to compare installs.")
    else:
        lines.append(f"All {len(required)} required DLLs found in the search path.")

    out = "\n".join(lines)
    return out + _json_footer({"ok": True, "data": {"executable": str(exe), "required_count": len(required), "found_count": len(found), "missing": missing, "search_path_count": len(unique_search)}})


# --- v0.2.9 qt_audio_convert: ffmpeg wrapper for batch audio conversion ------

FFMPEG_EXE = _env_path("QT_MCP_FFMPEG", r"E:\Download_tools\ffmpeg-8.1.1-essentials_build\bin\ffmpeg.exe")

_QT_AUDIO_FORMATS = ("mp3", "opus", "wav", "ogg", "flac", "m4a", "aac")


class QtAudioConvertInput(BaseModel):
    input_files: list[str] = Field(..., description="Absolute paths to source audio files (wav, mp3, ogg, flac, ...).")
    output_format: str = Field(default="mp3", description="Target format: mp3 / opus / wav / ogg / flac / m4a / aac.")
    output_dir: str = Field(..., description="Absolute path to directory where converted files will be written.")
    bitrate: str = Field(default="128k", description="Audio bitrate (e.g. '128k', '192k'). Ignored for lossless formats (wav, flac).")


@mcp.tool(name="qt_audio_convert", annotations={"title": "Convert audio files via ffmpeg (mp3 / opus / wav / ogg ...)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_audio_convert(params: QtAudioConvertInput) -> str:
    """Convert one or more audio files to a target format using ffmpeg.

    Typical use: prepare card-flip / shuffle / chip-drop sound effects for a
    board game. Source files are usually 24-bit / 48 kHz WAVs from a sample
    pack; the game wants compact 128kbps MP3 or Opus for size.

    Args:
        params.input_files: absolute paths to source files.
        params.output_format: mp3 / opus / wav / ogg / flac / m4a / aac.
        params.output_dir: destination directory (created if missing).
        params.bitrate: e.g. '128k', '192k' (ignored for wav/flac).

    Returns:
        str: per-file report listing input/output paths and ffmpeg exit code.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    fmt = params.output_format.lower().strip()
    if fmt not in _QT_AUDIO_FORMATS:
        msg = f"Error: output_format must be one of {_QT_AUDIO_FORMATS}, got {fmt!r}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not params.input_files:
        msg = "Error: input_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})

    out_dir = Path(params.output_dir)
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    out_dir.mkdir(parents=True, exist_ok=True)

    if not FFMPEG_EXE.exists():
        msg = (f"Error: ffmpeg.exe not found at {FFMPEG_EXE}. "
               f"Set QT_MCP_FFMPEG env var or install ffmpeg.")
        return msg + _json_footer({"ok": False, "error": msg})

    # Codec mapping per format
    codec_map = {"mp3": "libmp3lame", "opus": "libopus", "wav": "pcm_s16le",
                 "ogg": "libvorbis", "flac": "flac", "m4a": "aac", "aac": "aac"}
    codec = codec_map[fmt]
    lossless = fmt in ("wav", "flac")

    results: list[dict] = []
    lines = [
        f"=== qt_audio_convert: {len(params.input_files)} file(s) -> {fmt} ===",
        f"ffmpeg:   {FFMPEG_EXE}",
        f"output:   {out_dir}",
        f"bitrate:  {params.bitrate}{'' if lossless else ' (lossless: bitrate ignored)'}",
        "",
    ]

    for src_str in params.input_files:
        src = Path(src_str)
        sandbox_err = _require_sandbox(src, f"input_files[{src_str}]")
        if sandbox_err:
            results.append({"input": str(src), "error": sandbox_err})
            lines.append(f"  ! {src.name}: {sandbox_err}")
            continue
        if not src.exists() or not src.is_file():
            msg = f"input file not found: {src}"
            results.append({"input": str(src), "error": msg})
            lines.append(f"  ! {src.name}: {msg}")
            continue

        dst = out_dir / f"{src.stem}.{fmt}"
        cmd = [str(FFMPEG_EXE), "-y", "-i", str(src), "-vn"]
        if not lossless:
            cmd += ["-acodec", codec, "-b:a", params.bitrate]
        else:
            cmd += ["-acodec", codec]
        cmd.append(str(dst))

        try:
            proc = await asyncio.create_subprocess_exec(
                *cmd,
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
            )
            _, stderr = await asyncio.wait_for(proc.communicate(), timeout=120)
            rc = proc.returncode
            if rc != 0:
                err_tail = (stderr.decode("utf-8", errors="replace") if stderr else "").strip().splitlines()[-3:]
                err_str = "\n".join(err_tail)
                results.append({"input": str(src), "output": str(dst), "rc": rc, "error": err_str})
                lines.append(f"  ! {src.name} -> {dst.name}: rc={rc}")
                lines.append(f"      {err_str}")
            else:
                size_in = src.stat().st_size
                size_out = dst.stat().st_size if dst.exists() else 0
                results.append({"input": str(src), "output": str(dst), "rc": 0, "size_in": size_in, "size_out": size_out})
                ratio = (size_out / size_in * 100) if size_in else 0
                lines.append(f"  + {src.name} -> {dst.name}  ({size_in} -> {size_out} bytes, {ratio:.1f}%)")
        except asyncio.TimeoutError:
            results.append({"input": str(src), "error": "ffmpeg timeout 120s"})
            lines.append(f"  ! {src.name}: ffmpeg timeout (120s)")
        except Exception as e:
            results.append({"input": str(src), "error": str(e)})
            lines.append(f"  ! {src.name}: {e}")

    ok = sum(1 for r in results if r.get("rc") == 0)
    fail = len(results) - ok
    lines.append("")
    lines.append(f"Summary: {ok} ok, {fail} failed, {len(results)} total")

    out = "\n".join(lines)
    return out + _json_footer({"ok": fail == 0, "data": {"output_format": fmt, "output_dir": str(out_dir), "ok": ok, "failed": fail, "results": results}})


# --- v0.2.9 qt_qss_inspect: parse and audit a Qt Style Sheet -----------------

class QtQssInspectInput(BaseModel):
    qss_file: str = Field(..., description="Absolute path to the .qss file to inspect.")


_QSS_SELECTOR_RE = re.compile(r"([^{}]+?)\s*\{([^{}]*?)\}", re.DOTALL)
_QSS_PROP_RE = re.compile(r"([\w-]+)\s*:\s*([^;]+?)\s*(?:;|$)", re.DOTALL)


@mcp.tool(name="qt_qss_inspect", annotations={"title": "Parse a .qss file and report selectors, properties, duplicates", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qss_inspect(params: QtQssInspectInput) -> str:
    """Parse a Qt Style Sheet (.qss) file and report its structure:
    selector count, property count, duplicate selectors, duplicate properties
    within a selector, !important usage, and color/font-size summary.

    Useful for auditing themes generated by `qt_theme_gen` or hand-written
    stylesheets that have grown unwieldy.

    Args:
        params.qss_file: absolute path to the .qss file.

    Returns:
        str: structured report of the QSS contents.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    qpath = Path(params.qss_file)
    sandbox_err = _require_sandbox(qpath, "qss_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not qpath.exists() or not qpath.is_file():
        msg = f"Error: qss_file not found: {qpath}"
        return msg + _json_footer({"ok": False, "error": msg})

    try:
        text = qpath.read_text(encoding="utf-8", errors="replace")
    except OSError as e:
        msg = f"Error: failed to read {qpath}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Strip /* ... */ comments
    text = re.sub(r"/\*.*?\*/", "", text, flags=re.DOTALL)

    selectors: list[dict] = []
    duplicate_selectors: list[str] = []
    color_hits: list[str] = []
    font_sizes: list[str] = []
    important_count = 0

    seen_selectors: dict[str, int] = {}

    for m in _QSS_SELECTOR_RE.finditer(text):
        sel = m.group(1).strip()
        body = m.group(2)
        if not sel:
            continue
        # Count duplicate selectors (normalize whitespace)
        norm = re.sub(r"\s+", " ", sel)
        seen_selectors[norm] = seen_selectors.get(norm, 0) + 1

        props: list[dict] = []
        seen_props: dict[str, int] = {}
        duplicate_props: list[str] = []
        for pm in _QSS_PROP_RE.finditer(body):
            pname = pm.group(1).strip().lower()
            pval = pm.group(2).strip()
            seen_props[pname] = seen_props.get(pname, 0) + 1
            if seen_props[pname] == 2:
                duplicate_props.append(pname)
            if "important" in pval.lower():
                important_count += 1
            if pname in ("color", "background", "background-color", "border", "border-top", "border-bottom", "border-left", "border-right"):
                color_hits.append(pval)
            if pname == "font-size":
                font_sizes.append(pval)
            props.append({"name": pname, "value": pval})
        selectors.append({"selector": sel, "props": props, "dup_props": duplicate_props})

    for sel, count in seen_selectors.items():
        if count > 1:
            duplicate_selectors.append(f"{sel} (x{count})")

    lines = [
        f"=== qt_qss_inspect: {qpath.name} ({len(text)} chars) ===",
        "",
        f"Selectors:        {len(selectors)}",
        f"Properties:       {sum(len(s['props']) for s in selectors)}",
        f"Duplicate selectors:   {len(duplicate_selectors)}",
        f"Duplicate properties:  {sum(len(s['dup_props']) for s in selectors)}",
        f"!important uses:        {important_count}",
    ]
    if color_hits:
        unique_colors = sorted(set(color_hits))
        lines.append(f"Unique color values: {len(unique_colors)}")
        for c in unique_colors[:10]:
            lines.append(f"  - {c}")
        if len(unique_colors) > 10:
            lines.append(f"  ... and {len(unique_colors) - 10} more")
    if font_sizes:
        unique_sizes = sorted(set(font_sizes), key=lambda s: (len(s), s))
        lines.append(f"Font sizes: {', '.join(unique_sizes)}")

    if duplicate_selectors:
        lines.append("")
        lines.append(f"Duplicate selectors ({len(duplicate_selectors)}):")
        for s in duplicate_selectors[:10]:
            lines.append(f"  ! {s}")
        if len(duplicate_selectors) > 10:
            lines.append(f"  ... and {len(duplicate_selectors) - 10} more")

    dup_props_total = [s for s in selectors if s["dup_props"]]
    if dup_props_total:
        lines.append("")
        lines.append(f"Selectors with duplicate properties ({len(dup_props_total)}):")
        for s in dup_props_total[:5]:
            lines.append(f"  ! {s['selector']}: {', '.join(s['dup_props'])}")
        if len(dup_props_total) > 5:
            lines.append(f"  ... and {len(dup_props_total) - 5} more")

    out = "\n".join(lines)
    return out + _json_footer({"ok": True, "data": {"qss_file": str(qpath), "selector_count": len(selectors), "property_count": sum(len(s['props']) for s in selectors), "duplicate_selectors": duplicate_selectors, "important_count": important_count, "unique_colors": len(set(color_hits)) if color_hits else 0}})


# --- v0.2.9 qt_svg_to_png: convert SVG files to PNG (multiple sizes) --------

class QtSvgToPngInput(BaseModel):
    input_files: list[str] = Field(..., description="Absolute paths to .svg files.")
    output_dir: str = Field(..., description="Absolute path to output directory (created if missing).")
    widths: list[int] = Field(default_factory=lambda: [256], description="Output widths in pixels (height auto-derived from SVG aspect ratio).")


def _qt_svg_render(input_path: Path, output_path: Path, width: int) -> tuple[bool, str]:
    """Try cairosvg first, then ImageMagick, then return False with explanation."""
    # 1. cairosvg (pip install cairosvg)
    try:
        import cairosvg  # type: ignore
        cairosvg.svg2png(url=str(input_path), write_to=str(output_path), output_width=width)
        return True, "cairosvg"
    except ImportError:
        pass
    except Exception as e:
        return False, f"cairosvg failed: {e}"

    # 2. ImageMagick `magick` (modern) or `convert` (legacy)
    magick_exe = shutil.which("magick") or shutil.which("convert")
    if magick_exe:
        try:
            r = subprocess.run(
                [magick_exe, "-background", "none", "-density", "300",
                 str(input_path), "-resize", f"{width}x", str(output_path)],
                capture_output=True, text=True, timeout=30,
            )
            if r.returncode == 0 and output_path.exists():
                return True, Path(magick_exe).name
            return False, f"ImageMagick rc={r.returncode}: {(r.stderr or '').strip()[-200:]}"
        except subprocess.TimeoutExpired:
            return False, "ImageMagick timeout (30s)"
        except Exception as e:
            return False, f"ImageMagick error: {e}"

    return False, ("no SVG renderer available — install one of: "
                   "  pip install cairosvg   # pure-Python, easiest\n"
                   "  ImageMagick (magick.exe)   # system-wide binary")


@mcp.tool(name="qt_svg_to_png", annotations={"title": "Convert .svg files to .png at multiple widths", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_svg_to_png(params: QtSvgToPngInput) -> str:
    """Convert SVG files to PNG at one or more widths. Tries cairosvg first,
    then ImageMagick (`magick` or `convert`). Reports which backend was used.

    Typical use: prepare card art / icon set / UI mockups from vector sources
    into PNGs that Qt can bundle in a .qrc resource file (Qt 5 SVG support
    works at runtime, but .ico / .qrc workflows need raster).

    Args:
        params.input_files: absolute paths to .svg source files.
        params.output_dir: destination directory.
        params.widths: list of widths to render (e.g. [16, 32, 48, 256]).

    Returns:
        str: per-file report listing renders + backend used.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.input_files:
        msg = "Error: input_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if not params.widths or any(w <= 0 for w in params.widths):
        msg = "Error: widths must be a non-empty list of positive integers"
        return msg + _json_footer({"ok": False, "error": msg})

    out_dir = Path(params.output_dir)
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    out_dir.mkdir(parents=True, exist_ok=True)

    results: list[dict] = []
    lines = [
        f"=== qt_svg_to_png: {len(params.input_files)} file(s) x {len(params.widths)} size(s) ===",
        f"Output dir: {out_dir}",
        f"Widths:     {params.widths}",
        "",
    ]
    backend_used: Optional[str] = None

    for src_str in params.input_files:
        src = Path(src_str)
        sandbox_err = _require_sandbox(src, f"input_files[{src_str}]")
        if sandbox_err:
            results.append({"input": str(src), "error": sandbox_err})
            lines.append(f"  ! {src.name}: {sandbox_err}")
            continue
        if not src.exists() or not src.is_file():
            results.append({"input": str(src), "error": "not found"})
            lines.append(f"  ! {src.name}: not found")
            continue
        if src.suffix.lower() != ".svg":
            msg = f"not an SVG file (suffix={src.suffix!r})"
            results.append({"input": str(src), "error": msg})
            lines.append(f"  ! {src.name}: {msg}")
            continue

        for w in params.widths:
            dst = out_dir / f"{src.stem}_{w}.png"
            ok, info = _qt_svg_render(src, dst, w)
            if ok:
                if backend_used is None:
                    backend_used = info
                size_out = dst.stat().st_size if dst.exists() else 0
                results.append({"input": str(src), "output": str(dst), "width": w, "size": size_out, "backend": info})
                lines.append(f"  + {src.name} @{w}px -> {dst.name} ({size_out} bytes, via {info})")
            else:
                results.append({"input": str(src), "output": str(dst), "width": w, "error": info})
                lines.append(f"  ! {src.name} @{w}px: {info}")

    ok = sum(1 for r in results if "output" in r)
    fail = len(results) - ok
    lines.append("")
    lines.append(f"Summary: {ok} ok, {fail} failed, {len(results)} total")
    if backend_used:
        lines.append(f"Backend used: {backend_used}")

    out = "\n".join(lines)
    return out + _json_footer({"ok": fail == 0, "data": {"output_dir": str(out_dir), "widths": params.widths, "ok": ok, "failed": fail, "backend": backend_used, "results": results}})


# --- v0.2.9 qt_qml_property_linter: static analysis of QML files -------------

class QtQmlPropertyLinterInput(BaseModel):
    qml_files: list[str] = Field(..., description="Absolute paths to .qml files to lint.")


_QML_PROPERTY_RE = re.compile(r"\b(?:property|alias)\s+(\w+)\s+(\w+)\s*[:=]")
_QML_ID_RE = re.compile(r"\bid\s*:\s*(\w+)")
_QML_USAGE_RE = re.compile(r"\b(\w+)\s*\.")
_QML_COMPONENT_RE = re.compile(r"(\w+)\s*\{")
_QML_STRING_ASSIGN_RE = re.compile(r"(\w+)\s*:\s*\"[^\"]*\"")


@mcp.tool(name="qt_qml_property_linter", annotations={"title": "Static analysis of QML properties (unused, shadowed, type mismatch)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qml_property_linter(params: QtQmlPropertyLinterInput) -> str:
    """Lint a set of QML files for common property issues.

    Detects:
      - Unused properties (declared but never referenced)
      - Shadowed ids (same id defined twice in the same file)
      - Type mismatch (assigning a string literal to a numeric property, etc.)
      - Property count per file

    Companion to `qt_qml_lint` (which checks syntax via qmllint). This tool
    catches property-level issues that qmllint misses when types aren't
    declared or when ids are reused.

    Args:
        params.qml_files: absolute paths to .qml files to lint.

    Returns:
        str: per-file lint report. Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.qml_files:
        msg = "Error: qml_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})

    all_issues: list[dict] = []
    file_summaries: list[dict] = []
    lines = ["=== qt_qml_property_linter ===", ""]

    for fstr in params.qml_files:
        fpath = Path(fstr)
        sandbox_err = _require_sandbox(fpath, f"qml_files[{fstr}]")
        if sandbox_err:
            all_issues.append({"file": str(fpath), "error": sandbox_err})
            lines.append(f"  ! {fpath.name}: {sandbox_err}")
            continue
        if not fpath.exists() or not fpath.is_file():
            all_issues.append({"file": str(fpath), "error": "not found"})
            lines.append(f"  ! {fpath.name}: not found")
            continue

        try:
            text = fpath.read_text(encoding="utf-8", errors="replace")
        except OSError as e:
            all_issues.append({"file": str(fpath), "error": f"read failed: {e}"})
            continue

        # Strip /* */ and // comments to avoid false matches
        text_nc = re.sub(r"/\*.*?\*/", "", text, flags=re.DOTALL)
        text_nc = re.sub(r"//[^\n]*", "", text_nc)

        # 1. Find all property declarations
        declared: list[dict] = []
        for m in _QML_PROPERTY_RE.finditer(text_nc):
            line_no = text_nc[: m.start()].count("\n") + 1
            declared.append({"type": m.group(1), "name": m.group(2), "line": line_no})

        # 2. Find all ids
        ids: list[dict] = []
        for m in _QML_ID_RE.finditer(text_nc):
            line_no = text_nc[: m.start()].count("\n") + 1
            ids.append({"id": m.group(1), "line": line_no})

        # 3. Check for shadowed ids (same id defined twice)
        shadowed_ids: list[dict] = []
        id_counts: dict[str, int] = {}
        for i in ids:
            id_counts[i["id"]] = id_counts.get(i["id"], 0) + 1
        for i in ids:
            if id_counts[i["id"]] > 1:
                shadowed_ids.append({"id": i["id"], "line": i["line"]})

        # 4. Check for unused properties
        unused_props: list[dict] = []
        prop_names = {p["name"] for p in declared}
        for p in declared:
            name = p["name"]
            # Look for references: word-boundary "name." or "name " or "{name}"
            pattern = rf"\b{re.escape(name)}\b"
            refs = [m for m in re.finditer(pattern, text_nc)]
            # Filter out the declaration itself (count == 1 means only declaration)
            if len(refs) <= 1:
                unused_props.append({"name": name, "type": p["type"], "line": p["line"]})

        # 5. Type mismatch: string literal assigned to a numeric property
        type_mismatches: list[dict] = []
        numeric_types = ("int", "real", "double", "float", "var", "bool", "color")
        for p in declared:
            if p["type"] in numeric_types and p["type"] != "var":
                # Find assignments to this property
                assign_re = re.compile(rf"\b{re.escape(p['name'])}\s*:\s*(.+)")
                for m in assign_re.finditer(text_nc):
                    val = m.group(1).strip().rstrip(",;")
                    if val.startswith('"') or val.startswith("'"):
                        type_mismatches.append({"name": p["name"], "type": p["type"], "value": val[:30], "line": text_nc[: m.start()].count("\n") + 1})

        # Filter out the property declaration from unused_props if there is also an id reference
        file_issues = len(unused_props) + len(shadowed_ids) + len(type_mismatches)
        file_summaries.append({
            "file": str(fpath),
            "properties": len(declared),
            "ids": len(ids),
            "unused_props": len(unused_props),
            "shadowed_ids": len(shadowed_ids),
            "type_mismatches": len(type_mismatches),
        })

        lines.append(f"--- {fpath.name} ---")
        lines.append(f"  properties: {len(declared)}, ids: {len(ids)}, issues: {file_issues}")
        if unused_props:
            lines.append(f"  unused properties ({len(unused_props)}):")
            for u in unused_props[:5]:
                lines.append(f"    ! {u['name']}: {u['type']} (line {u['line']})")
            if len(unused_props) > 5:
                lines.append(f"    ... and {len(unused_props) - 5} more")
            for u in unused_props:
                all_issues.append({"file": str(fpath), "kind": "unused_property", **u})
        if shadowed_ids:
            lines.append(f"  shadowed ids ({len(shadowed_ids)}):")
            seen_dup = set()
            for s in shadowed_ids:
                if s["id"] not in seen_dup:
                    seen_dup.add(s["id"])
                    lines.append(f"    ! id '{s['id']}' defined multiple times (line {s['line']})")
                    all_issues.append({"file": str(fpath), "kind": "shadowed_id", **s})
        if type_mismatches:
            lines.append(f"  type mismatches ({len(type_mismatches)}):")
            for tm in type_mismatches[:5]:
                lines.append(f"    ! {tm['name']}: {tm['type']} = {tm['value']} (line {tm['line']})")
            if len(type_mismatches) > 5:
                lines.append(f"    ... and {len(type_mismatches) - 5} more")
            for tm in type_mismatches:
                all_issues.append({"file": str(fpath), "kind": "type_mismatch", **tm})
        if file_issues == 0:
            lines.append("  clean")
        lines.append("")

    total_issues = sum(fs["unused_props"] + fs["shadowed_ids"] + fs["type_mismatches"] for fs in file_summaries)
    lines.append(f"Summary: {len(params.qml_files)} files, {total_issues} issue(s)")

    out = "\n".join(lines)
    return out + _json_footer({"ok": total_issues == 0, "data": {"files": len(params.qml_files), "total_issues": total_issues, "summaries": file_summaries, "issues": all_issues[:50]}})


# --- v0.2.9 qt_accessibility_check: scan C++ source for a11y issues ----------

class QtAccessibilityCheckInput(BaseModel):
    source_files: list[str] = Field(..., description="Absolute paths to .cpp / .h files to scan.")


_A11Y_WIDGETS = ("QPushButton", "QLabel", "QLineEdit", "QComboBox", "QCheckBox", "QRadioButton",
                 "QSpinBox", "QDoubleSpinBox", "QSlider", "QProgressBar", "QToolButton",
                 "QGroupBox", "QTabWidget", "QListWidget", "QTreeWidget", "QTableWidget",
                 "QTextEdit", "QPlainTextEdit")


@mcp.tool(name="qt_accessibility_check", annotations={"title": "Scan Qt C++ sources for accessibility issues (missing accessibleName, objectName, tab order)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_accessibility_check(params: QtAccessibilityCheckInput) -> str:
    """Scan Qt C++ source files for common accessibility (a11y) issues.

    Checks for:
      - Interactive widgets (QPushButton, QLineEdit, ...) missing
        setAccessibleName() — screen readers can't describe them
      - Widgets missing setObjectName() — Qt Designer / UI tests / a11y
        tools can't find them by name
      - Missing QWidget::setTabOrder() chains — keyboard navigation broken
      - Q_OBJECT classes missing Q_DISABLE_COPY — default-copy of QObject
        is a known Qt anti-pattern

    Args:
        params.source_files: absolute paths to .cpp / .h files to scan.

    Returns:
        str: per-file a11y report with recommendations.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.source_files:
        msg = "Error: source_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})

    all_issues: list[dict] = []
    lines = ["=== qt_accessibility_check ===", ""]

    for fstr in params.source_files:
        fpath = Path(fstr)
        sandbox_err = _require_sandbox(fpath, f"source_files[{fstr}]")
        if sandbox_err:
            all_issues.append({"file": str(fpath), "error": sandbox_err})
            lines.append(f"  ! {fpath.name}: {sandbox_err}")
            continue
        if not fpath.exists() or not fpath.is_file():
            all_issues.append({"file": str(fpath), "error": "not found"})
            lines.append(f"  ! {fpath.name}: not found")
            continue

        try:
            text = fpath.read_text(encoding="utf-8", errors="replace")
        except OSError as e:
            all_issues.append({"file": str(fpath), "error": f"read failed: {e}"})
            continue

        text_nc = re.sub(r"/\*.*?\*/", "", text, flags=re.DOTALL)
        text_nc = re.sub(r"//[^\n]*", "", text_nc)

        file_issues = 0

        # 1. Q_OBJECT classes missing Q_DISABLE_COPY
        qobject_re = re.compile(r"\bclass\s+\w+\s*:\s*(?:public\s+)?QObject\b[^{]*\{")
        qdisable_re = re.compile(r"\bQ_DISABLE_COPY\s*\(")
        for m in qobject_re.finditer(text_nc):
            # Find the next 600 chars (the class body intro region)
            chunk = text_nc[m.end(): m.end() + 600]
            if not qdisable_re.search(chunk):
                line_no = text_nc[: m.start()].count("\n") + 1
                all_issues.append({"file": str(fpath), "kind": "missing_q_disable_copy", "line": line_no})
                file_issues += 1

        # 2. Interactive widgets without setAccessibleName
        for widget in _A11Y_WIDGETS:
            # Match: new QPushButton(...)  OR  QPushButton *x = new ...  OR  ui->pushButton
            widget_create_re = re.compile(rf"\b{re.escape(widget)}\b\s*(?:\*|\&|\s+)\s*(\w+)?[=\(;]")
            for m in widget_create_re.finditer(text_nc):
                var_name = m.group(1) or widget
                # Look ahead 800 chars for setAccessibleName call on this var
                chunk = text_nc[m.end(): m.end() + 800]
                if "setAccessibleName" not in chunk:
                    line_no = text_nc[: m.start()].count("\n") + 1
                    all_issues.append({"file": str(fpath), "kind": "missing_accessible_name",
                                       "widget": widget, "var": var_name, "line": line_no})
                    file_issues += 1

        # 3. Widgets without setObjectName (within first 200 chars after creation)
        for widget in _A11Y_WIDGETS:
            widget_create_re = re.compile(rf"\b{re.escape(widget)}\b\s*(?:\*|\&|\s+)\s*(\w+)?[=\(;]")
            for m in widget_create_re.finditer(text_nc):
                chunk = text_nc[m.end(): m.end() + 200]
                if "setObjectName" not in chunk:
                    var_name = m.group(1) or widget
                    line_no = text_nc[: m.start()].count("\n") + 1
                    all_issues.append({"file": str(fpath), "kind": "missing_object_name",
                                       "widget": widget, "var": var_name, "line": line_no})
                    file_issues += 1

        # 4. setTabOrder usage (just count occurrences for summary)
        tab_order_count = len(re.findall(r"\bsetTabOrder\s*\(", text_nc))

        # 5. accessibleName count
        a11y_name_count = len(re.findall(r"\bsetAccessibleName\s*\(", text_nc))
        a11y_desc_count = len(re.findall(r"\bsetAccessibleDescription\s*\(", text_nc))

        lines.append(f"--- {fpath.name} ---")
        lines.append(f"  setAccessibleName:       {a11y_name_count}")
        lines.append(f"  setAccessibleDescription: {a11y_desc_count}")
        lines.append(f"  setTabOrder calls:        {tab_order_count}")
        lines.append(f"  Issues: {file_issues}")
        if file_issues > 0:
            # Group by kind
            by_kind: dict[str, list] = {}
            for iss in all_issues:
                if iss.get("file") == str(fpath):
                    by_kind.setdefault(iss["kind"], []).append(iss)
            for kind, items in by_kind.items():
                lines.append(f"  {kind} ({len(items)}):")
                for it in items[:3]:
                    if "line" in it:
                        lines.append(f"    L{it['line']}: {it.get('widget', '')} {it.get('var', '')}".rstrip())
                if len(items) > 3:
                    lines.append(f"    ... and {len(items) - 3} more")
        lines.append("")

    total = len(all_issues)
    lines.append(f"Summary: {len(params.source_files)} file(s), {total} a11y issue(s)")
    if total == 0:
        lines.append("All scanned files pass basic a11y checks.")

    out = "\n".join(lines)
    return out + _json_footer({"ok": total == 0, "data": {"files": len(params.source_files), "total_issues": total, "issues": all_issues[:50]}})


# --- v0.2.9 qt_pro_project_graph: emit DOT dependency graph for a .pro -------

