# --- v0.3.1 LLM helpers (used by auto_fill tools, NOT registered as tools) ---


def _llm_check_config(provider: str = "", model: str = "") -> dict:
    """Resolve LLM provider / model + API key. Returns dict with keys:
        ok (bool), provider, model, api_key_set, error.
    Does NOT raise; tools call this and return Error: string on ok=False.
    """
    p = provider or os.environ.get("QT_MCP_LLM_PROVIDER", "anthropic")
    m = model or os.environ.get("QT_MCP_LLM_MODEL", "")
    if p == "anthropic":
        api_key = os.environ.get("ANTHROPIC_API_KEY", "")
        default_model = "claude-3-5-sonnet-20241022"
    elif p == "openai":
        api_key = os.environ.get("OPENAI_API_KEY", "")
        default_model = "gpt-4o-mini"
    else:
        return {"ok": False, "provider": p, "model": m, "api_key_set": False, "error": f"unknown provider: {p}"}
    if not m:
        m = default_model
    return {
        "ok": bool(api_key),
        "provider": p,
        "model": m,
        "api_key_set": bool(api_key),
        "error": "" if api_key else f"missing API key for provider '{p}' (set {('ANTHROPIC' if p == 'anthropic' else 'OPENAI')}_API_KEY env var)",
    }


async def _llm_call(provider: str, model: str, system_prompt: str, user_prompt: str, timeout: float = 30.0) -> dict:
    """Make a single LLM call. Returns dict: ok, text, error.
    Uses urllib.request (no extra dependency beyond stdlib).
    Raises nothing — errors are returned in the dict.
    """
    cfg = _llm_check_config(provider, model)
    if not cfg["ok"]:
        return {"ok": False, "text": "", "error": cfg["error"]}
    api_key = os.environ.get("ANTHROPIC_API_KEY" if cfg["provider"] == "anthropic" else "OPENAI_API_KEY", "")

    try:
        if cfg["provider"] == "anthropic":
            url = "https://api.anthropic.com/v1/messages"
            payload = {
                "model": cfg["model"],
                "max_tokens": 2048,
                "system": system_prompt,
                "messages": [{"role": "user", "content": user_prompt}],
            }
            req = urllib.request.Request(url, data=json.dumps(payload).encode("utf-8"), method="POST")
            req.add_header("content-type", "application/json")
            req.add_header("x-api-key", api_key)
            req.add_header("anthropic-version", "2023-06-01")
        else:  # openai
            url = "https://api.openai.com/v1/chat/completions"
            payload = {
                "model": cfg["model"],
                "max_tokens": 2048,
                "messages": [
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": user_prompt},
                ],
            }
            req = urllib.request.Request(url, data=json.dumps(payload).encode("utf-8"), method="POST")
            req.add_header("content-type", "application/json")
            req.add_header("Authorization", f"Bearer {api_key}")

        loop = asyncio.get_event_loop()
        resp_text = await asyncio.wait_for(
            loop.run_in_executor(None, lambda: urllib.request.urlopen(req, timeout=timeout).read().decode("utf-8")),
            timeout=timeout,
        )
        resp = json.loads(resp_text)
        if cfg["provider"] == "anthropic":
            text = resp.get("content", [{}])[0].get("text", "")
        else:
            text = resp.get("choices", [{}])[0].get("message", {}).get("content", "")
        return {"ok": True, "text": text, "error": ""}
    except asyncio.TimeoutError:
        return {"ok": False, "text": "", "error": f"LLM call timed out after {timeout}s"}
    except Exception as e:
        return {"ok": False, "text": "", "error": f"{type(e).__name__}: {e}"}


def _make_unified_diff(path: str, original: str, modified: str) -> str:
    """Generate a minimal unified-diff preview between original and modified text."""
    import difflib
    diff = difflib.unified_diff(
        original.splitlines(keepends=True),
        modified.splitlines(keepends=True),
        fromfile=f"a/{Path(path).name}",
        tofile=f"b/{Path(path).name}",
        n=2,
    )
    return "".join(diff)


@mcp.tool(name="qt_pro_project_graph", annotations={"title": "Emit a DOT dependency graph for a .pro project (sources, headers, forms, resources)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_pro_project_graph(params: QtProProjectGraphInput) -> str:
    """Walk a .pro file's SOURCES / HEADERS / FORMS / RESOURCES lists, then
    scan each file's content for #include directives to build a dependency
    graph. Emit it as Graphviz DOT (for `dot -Tpng foo.dot -o foo.png`).

    Useful for visualizing large projects and spotting include cycles.

    Args:
        params.pro_file: absolute path to the .pro file.
        params.output_dot: if non-empty, write DOT to this path.
        params.show_cycles: if True, run a DFS to detect include cycles.

    Returns:
        str: DOT graph (or confirmation of file write). Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    pro = Path(params.pro_file)
    sandbox_err = _require_sandbox(pro, "pro_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not pro.exists() or not pro.is_file():
        msg = f"Error: pro_file not found: {pro}"
        return msg + _json_footer({"ok": False, "error": msg})

    try:
        text = pro.read_text(encoding="utf-8", errors="replace")
    except OSError as e:
        msg = f"Error: failed to read {pro}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Parse .pro entries via the existing helper
    entries = _pro_parse(text)

    # Collect files by category
    buckets: dict[str, list[str]] = {"SOURCES": [], "HEADERS": [], "FORMS": [], "RESOURCES": []}
    for e in entries:
        var = e.get("var", "")
        if var in buckets:
            value = e.get("value", "")
            if value:
                buckets[var].extend(value.split())

    # For each .h / .cpp, parse #include "..."
    include_re = re.compile(r'^\s*#include\s+"([^"]+)"', re.MULTILINE)
    nodes: dict[str, str] = {}  # relpath -> kind
    edges: list[tuple[str, str]] = []  # (from, to)
    pro_dir = pro.parent

    for kind, files in buckets.items():
        for rel in files:
            p = pro_dir / rel
            try:
                norm = str(p.resolve()).lower()
            except OSError:
                continue
            nodes[norm] = kind
            if not p.exists():
                continue
            try:
                src = p.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            for m in include_re.finditer(src):
                inc_rel = m.group(1)
                inc_abs = (p.parent / inc_rel).resolve()
                try:
                    inc_norm = str(inc_abs).lower()
                except OSError:
                    continue
                if inc_norm not in nodes:
                    nodes[inc_norm] = "header" if inc_norm.endswith(".h") else "unknown"
                edges.append((norm, inc_norm))

    # Detect cycles (Tarjan / DFS)
    cycles: list[list[str]] = []
    if params.show_cycles and edges:
        adj: dict[str, list[str]] = {}
        for a, b in edges:
            adj.setdefault(a, []).append(b)
        visited: set[str] = set()
        stack: list[str] = []
        on_stack: set[str] = set()

        def _dfs(node: str) -> None:
            visited.add(node)
            stack.append(node)
            on_stack.add(node)
            for nxt in adj.get(node, []):
                if nxt not in visited:
                    _dfs(nxt)
                elif nxt in on_stack:
                    try:
                        idx = stack.index(nxt)
                        cycle = stack[idx:] + [nxt]
                        cycles.append(cycle)
                    except ValueError:
                        pass
            stack.pop()
            on_stack.discard(node)

        for n in list(nodes.keys()):
            if n not in visited:
                _dfs(n)
        # Deduplicate cycles (cycle normalized)
        seen_cycles: set[tuple] = set()
        unique_cycles = []
        for c in cycles:
            key = tuple(sorted(set(c)))
            if key not in seen_cycles:
                seen_cycles.add(key)
                unique_cycles.append(c)
        cycles = unique_cycles[:10]  # cap

    # Emit DOT
    dot_lines = [
        f'digraph "{pro.stem}" {{',
        '  rankdir=LR;',
        '  node [shape=box, style="filled,rounded", fontname="Helvetica"];',
        '',
        '  // Categories',
        '  subgraph cluster_sources { label="SOURCES (.cpp)"; style=dashed; color="#888888";',
    ]
    sources = [n for n, k in nodes.items() if k == "SOURCES"]
    headers = [n for n, k in nodes.items() if k == "HEADERS"]
    forms = [n for n, k in nodes.items() if k == "FORMS"]
    resources = [n for n, k in nodes.items() if k == "RESOURCES"]
    others = [n for n, k in nodes.items() if k not in ("SOURCES", "HEADERS", "FORMS", "RESOURCES")]

    for n in sources:
        dot_lines.append(f'    "{n}" [fillcolor="#cce5ff"];')
    dot_lines.append('  }')
    dot_lines.append('  subgraph cluster_headers { label="HEADERS (.h)"; style=dashed; color="#888888";')
    for n in headers:
        dot_lines.append(f'    "{n}" [fillcolor="#ccffcc"];')
    dot_lines.append('  }')
    if forms:
        dot_lines.append('  subgraph cluster_forms { label="FORMS (.ui)"; style=dashed; color="#888888";')
        for n in forms:
            dot_lines.append(f'    "{n}" [fillcolor="#ffe5cc"];')
        dot_lines.append('  }')
    if resources:
        dot_lines.append('  subgraph cluster_resources { label="RESOURCES (.qrc)"; style=dashed; color="#888888";')
        for n in resources:
            dot_lines.append(f'    "{n}" [fillcolor="#ffccff"];')
        dot_lines.append('  }')
    dot_lines.append('')
    dot_lines.append('  // Edges (includes)')
    for a, b in edges:
        dot_lines.append(f'  "{a}" -> "{b}";')
    dot_lines.append('}')

    dot_text = "\n".join(dot_lines)

    if params.output_dot:
        out_path = Path(params.output_dot)
        sandbox_err = _require_sandbox(out_path, "output_dot")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_text(dot_text, encoding="utf-8")
        report = (
            f"=== qt_pro_project_graph: wrote {out_path} ===\n"
            f"Nodes: {len(nodes)} (sources={len(sources)}, headers={len(headers)}, forms={len(forms)}, resources={len(resources)})\n"
            f"Edges: {len(edges)}\n"
            f"Cycles detected: {len(cycles)}\n"
        )
        if cycles:
            report += "\nCycles:\n"
            for c in cycles[:5]:
                names = [Path(p).name for p in c[:-1]]
                report += f"  ! {' -> '.join(names)} ({len(c)-1} nodes)\n"
        return report + _json_footer({"ok": True, "data": {"pro_file": str(pro), "output_dot": str(out_path), "node_count": len(nodes), "edge_count": len(edges), "cycles": [list(c) for c in cycles]}})

    # Inline DOT (cap at reasonable size)
    if len(dot_text) > 50_000:
        dot_text = dot_text[:50_000] + "\n... [truncated]\n}"
    return dot_text + _json_footer({"ok": True, "data": {"pro_file": str(pro), "node_count": len(nodes), "edge_count": len(edges), "cycles_count": len(cycles)}})


# --- v0.3.0 tools ------------------------------------------------------------

@mcp.tool(name="qt_build_cache", annotations={"title": "Detect / inject ccache (or sccache) compiler launcher to accelerate Qt incremental builds", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_build_cache(params: QtBuildCacheInput) -> str:
    """Detect which compiler cache is available (ccache / sccache), report hit
    stats from the cache directory, and (optionally) inject a launcher line
    into the .pro file so the next ``qt_build`` invocation re-uses cached
    object files.

    Why ccache:
      ``qt_build`` runs ``mingw32-make`` which forks ``g++`` once per
      translation unit. On a typical board-game project (200-400 .cpp files)
      a clean rebuild is 30-60 s. With ccache, the second incremental build
      drops to 2-6 s because unchanged files are served from cache instead of
      recompiled. The compiler never knows — ccache is a wrapper that hashes
      the preprocessed source and either returns the cached .o or invokes
      g++ and stores the result.

    What it writes:
      - Adds ``QMAKE_CXX = ccache g++`` (or sccache equivalent) at the top of
        the .pro, so qmake's generated Makefile routes every compile through
        the cache.
      - Sets ``CCACHE_DIR`` / ``SCCACHE_DIR`` env var hint in a sidecar
        ``.qt_ccache_env`` so subsequent ``qt_build`` calls pick it up.
      - If ``report_only=True``, prints the recommendation but does not
        modify any file.

    Args:
        params.project_dir: absolute path to the Qt project directory.
        params.enable_ccache: if True, inject ccache launcher; if False, only report.
        params.cache_dir: explicit cache directory (empty = default).
        params.report_only: dry-run mode — do not modify any file.

    Returns:
        str: multi-line report (backend detected, cache size, hit rate, .pro
        snippet added). Starts with 'Error: ' on failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    project_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(project_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not project_dir.exists() or not project_dir.is_dir():
        msg = f"Error: project_dir not found: {project_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    pro_files = list(project_dir.glob("*.pro"))
    if not pro_files:
        msg = f"Error: no .pro file in {project_dir}"
        return msg + _json_footer({"ok": False, "error": msg})
    pro = pro_files[0]

    # Detect backend
    backend: str = ""
    backend_path: str = ""
    for name in ("ccache", "sccache"):
        try:
            r = await _run([name, "--version"], cwd=project_dir, timeout=5)
            if r.returncode == 0:
                backend = name
                backend_path = name  # on PATH
                break
        except (FileNotFoundError, OSError):
            continue

    # Determine cache directory
    cache_dir = Path(params.cache_dir) if params.cache_dir else Path.home() / ".ccache"
    if backend == "sccache" and not params.cache_dir:
        cache_dir = Path.home() / ".cache" / "sccache"

    # Read cache stats (ccache only)
    cache_stats: dict[str, str] = {}
    if backend == "ccache" and cache_dir.exists():
        stats_file = cache_dir / "0" / "stats"
        if not stats_file.exists():
            stats_file = cache_dir / "stats"  # older ccache layout
        if stats_file.exists():
            try:
                for line in stats_file.read_text(encoding="utf-8", errors="replace").splitlines():
                    if "=" in line:
                        k, v = line.split("=", 1)
                        cache_stats[k.strip()] = v.strip()
            except OSError:
                pass

    # Recommend .pro snippet
    if backend:
        if backend == "ccache":
            pro_snippet = (
                "# qt_build_cache: route every compile through ccache\n"
                "QMAKE_CXX = ccache g++\n"
                "QMAKE_CC = ccache gcc\n"
            )
            env_hint = "CCACHE_DIR"
        else:
            pro_snippet = (
                "# qt_build_cache: route every compile through sccache\n"
                "QMAKE_CXX = sccache g++\n"
                "QMAKE_CC = sccache gcc\n"
            )
            env_hint = "SCCACHE_DIR"
    else:
        pro_snippet = (
            "# qt_build_cache: NO cache backend detected. Install ccache (https://ccache.dev)\n"
            "# then re-run qt_build_cache to enable caching.\n"
        )
        env_hint = "CCACHE_DIR"

    report_lines = [
        f"=== qt_build_cache: {pro.name} ===",
        f"Backend detected: {backend if backend else '(none — ccache / sccache not on PATH)'}",
        f"Cache directory: {cache_dir}",
        f"Exists: {cache_dir.exists()}",
    ]
    if cache_stats:
        hits = cache_stats.get("cache_hit", cache_stats.get("cache hits", "0"))
        misses = cache_stats.get("cache_miss", cache_stats.get("cache misses", "0"))
        report_lines.append(f"Stats (raw): {dict(list(cache_stats.items())[:8])}")
        try:
            h, m = int(hits), int(misses)
            total = h + m
            rate = (h / total * 100.0) if total else 0.0
            report_lines.append(f"Hit rate: {h}/{total} ({rate:.1f}%)")
        except ValueError:
            pass
    else:
        report_lines.append("Stats: (no stats file yet — run a build to populate)")

    if params.report_only or not backend or not params.enable_ccache:
        report_lines.append("\n--- recommended .pro snippet (NOT written) ---")
        report_lines.append(pro_snippet)
        report_lines.append(f"\nEnv var hint: set {env_hint}={cache_dir} before qt_build")
        if params.report_only:
            return "\n".join(report_lines) + _json_footer({"ok": True, "data": {"backend": backend, "cache_dir": str(cache_dir), "report_only": True, "hit_rate": cache_stats}})
        if not backend:
            msg = "Error: no ccache / sccache on PATH; cannot enable caching"
            return msg + _json_footer({"ok": False, "error": msg})
        # enable_ccache=False but backend exists → still report only
        return "\n".join(report_lines) + _json_footer({"ok": True, "data": {"backend": backend, "cache_dir": str(cache_dir), "enable_ccache": False}})

    # Real write: prepend snippet + write sidecar env file
    try:
        original = pro.read_text(encoding="utf-8", errors="replace")
    except OSError as e:
        msg = f"Error: failed to read {pro}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Idempotent: skip if snippet already present
    marker = "# qt_build_cache:"
    if marker in original:
        report_lines.append(f"\n.marker already present in {pro.name}; not duplicating.")
    else:
        new_text = pro_snippet + original
        try:
            pro.write_text(new_text, encoding="utf-8")
            report_lines.append(f"\nPatched {pro.name}: prepended ccache launcher lines.")
        except OSError as e:
            msg = f"Error: failed to write {pro}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})

    env_file = project_dir / ".qt_ccache_env"
    try:
        env_file.write_text(f"{env_hint}={cache_dir}\n", encoding="utf-8")
        report_lines.append(f"Wrote {env_file.name}: {env_hint}={cache_dir}")
    except OSError as e:
        report_lines.append(f"Warning: failed to write {env_file}: {e}")

    report_lines.append("\nNext qt_build will route every g++ call through ccache.")
    return "\n".join(report_lines) + _json_footer({"ok": True, "data": {"backend": backend, "cache_dir": str(cache_dir), "pro_file": str(pro), "env_file": str(env_file), "hit_rate": cache_stats}})


@mcp.tool(name="qt_steamworks_init", annotations={"title": "Generate Steamworks SDK integration snippets for a Qt project (SteamAPI_Init, callbacks, achievements)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_steamworks_init(params: QtSteamworksInitInput) -> str:
    """Generate a drop-in Steamworks SDK integration for a Qt project:
      - ``steamworks_integration.h`` / ``.cpp`` — wraps ``SteamAPI_Init`` /
        ``Shutdown`` / ``SteamAPI_RunCallbacks``, exposes a Qt signal that
        fires whenever Steam callbacks are dispatched.
      - ``steam_achievements.h`` / ``.cpp`` — QObject helper with
        ``grantAchievement(QString apiName)`` that calls
        ``SteamUserStats()->SetAchievement``.
      - ``steam_appid.txt`` — placed next to the .pro so SteamAPI works in
        dev mode without launching through the Steam client.
      - A ``STEAMWORKS.md`` with step-by-step Steam partner setup notes.

    The snippet assumes the Steamworks SDK headers (``steam_api.h``) are on
    the include path. If ``sdk_path`` is provided, the snippet writes a
    ``STEAMWORKS_SDK_PATH`` hint into a ``.pro.user``-style sidecar so the
    user can point MSVC / CMake at the right include + lib dirs.

    Args:
        params.project_dir: absolute path to the Qt project directory.
        params.app_id: Steam app ID (480 = Spacewar test app).
        params.sdk_path: absolute path to the Steamworks SDK root (empty = skip SDK path generation).
        params.write_steam_appid_txt: if True, also write steam_appid.txt.

    Returns:
        str: multi-line report listing every file written plus a 'Next steps' checklist.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    project_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(project_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not project_dir.exists() or not project_dir.is_dir():
        msg = f"Error: project_dir not found: {project_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    pro_files = list(project_dir.glob("*.pro"))
    if not pro_files:
        msg = f"Error: no .pro file in {project_dir}"
        return msg + _json_footer({"ok": False, "error": msg})
    pro = pro_files[0]
    stem = pro.stem

    header_text = (
        f"// steamworks_integration.h — auto-generated by qt_steamworks_init\n"
        f"// Wraps the C-style Steamworks SDK into a Qt-friendly QObject.\n"
        f"#ifndef STEAMWORKS_INTEGRATION_H\n"
        f"#define STEAMWORKS_INTEGRATION_H\n"
        f"\n"
        f"#include <QObject>\n"
        f"#include <QTimer>\n"
        f"\n"
        f"class SteamworksIntegration : public QObject {{\n"
        f"    Q_OBJECT\n"
        f"public:\n"
        f"    explicit SteamworksIntegration(QObject *parent = nullptr);\n"
        f"    ~SteamworksIntegration() override;\n"
        f"\n"
        f"    bool init();   // calls SteamAPI_Init(); returns true on success\n"
        f"    void shutdown();\n"
        f"\n"
        f"signals:\n"
        f"    void steamCallbacksDispatched();  // fired ~10x/sec from SteamAPI_RunCallbacks\n"
        f"\n"
        f"private slots:\n"
        f"    void onPollTimerTimeout();\n"
        f"\n"
        f"private:\n"
        f"    QTimer m_pollTimer;\n"
        f"    bool m_initialized = false;\n"
        f"}};\n"
        f"\n"
        f"#endif // STEAMWORKS_INTEGRATION_H\n"
    )

    cpp_text = (
        f"// steamworks_integration.cpp — auto-generated by qt_steamworks_init\n"
        f"#include \"steamworks_integration.h\"\n"
        f"#include \"steam_api.h\"   // from Steamworks SDK\n"
        f"\n"
        f"SteamworksIntegration::SteamworksIntegration(QObject *parent) : QObject(parent) {{\n"
        f"    connect(&m_pollTimer, &QTimer::timeout, this, &SteamworksIntegration::onPollTimerTimeout);\n"
        f"    m_pollTimer.setInterval(100);  // 10 Hz — Steam callbacks are cheap to dispatch\n"
        f"}}\n"
        f"\n"
        f"SteamworksIntegration::~SteamworksIntegration() {{\n"
        f"    shutdown();\n"
        f"}}\n"
        f"\n"
        f"bool SteamworksIntegration::init() {{\n"
        f"    if (m_initialized) return true;\n"
        f"    m_initialized = SteamAPI_Init();\n"
        f"    if (m_initialized) {{\n"
        f"        m_pollTimer.start();\n"
        f"    }}\n"
        f"    return m_initialized;\n"
        f"}}\n"
        f"\n"
        f"void SteamworksIntegration::shutdown() {{\n"
        f"    if (m_initialized) {{\n"
        f"        m_pollTimer.stop();\n"
        f"        SteamAPI_Shutdown();\n"
        f"        m_initialized = false;\n"
        f"    }}\n"
        f"}}\n"
        f"\n"
        f"void SteamworksIntegration::onPollTimerTimeout() {{\n"
        f"    SteamAPI_RunCallbacks();\n"
        f"    emit steamCallbacksDispatched();\n"
        f"}}\n"
    )

    achievements_header = (
        f"// steam_achievements.h — auto-generated by qt_steamworks_init\n"
        f"#ifndef STEAM_ACHIEVEMENTS_H\n"
        f"#define STEAM_ACHIEVEMENTS_H\n"
        f"\n"
        f"#include <QObject>\n"
        f"#include <QString>\n"
        f"\n"
        f"class SteamAchievements : public QObject {{\n"
        f"    Q_OBJECT\n"
        f"public:\n"
        f"    explicit SteamAchievements(QObject *parent = nullptr);\n"
        f"\n"
        f"    // apiName = the achievement API name configured in the Steamworks partner site\n"
        f"    bool grant(const QString &apiName);\n"
        f"    bool isUnlocked(const QString &apiName) const;\n"
        f"\n"
        f"    bool storeStats();  // call after granting to push to Steam servers\n"
        f"\n"
        f"signals:\n"
        f"    void achievementUnlocked(const QString &apiName);\n"
        f"}};\n"
        f"\n"
        f"#endif // STEAM_ACHIEVEMENTS_H\n"
    )

    achievements_cpp = (
        f"// steam_achievements.cpp — auto-generated by qt_steamworks_init\n"
        f"#include \"steam_achievements.h\"\n"
        f"#include \"steam_api.h\"\n"
        f"\n"
        f"SteamAchievements::SteamAchievements(QObject *parent) : QObject(parent) {{}}\n"
        f"\n"
        f"bool SteamAchievements::grant(const QString &apiName) {{\n"
        f"    ISteamUserStats *stats = SteamUserStats();\n"
        f"    if (!stats) return false;\n"
        f"    bool achieved = false;\n"
        f"    if (stats->GetAchievement(apiName.toUtf8().constData(), &achieved) && !achieved) {{\n"
        f"        stats->SetAchievement(apiName.toUtf8().constData());\n"
        f"        stats->StoreStats();\n"
        f"        emit achievementUnlocked(apiName);\n"
        f"        return true;\n"
        f"    }}\n"
        f"    return false;\n"
        f"}}\n"
        f"\n"
        f"bool SteamAchievements::isUnlocked(const QString &apiName) const {{\n"
        f"    ISteamUserStats *stats = SteamUserStats();\n"
        f"    if (!stats) return false;\n"
        f"    bool achieved = false;\n"
        f"    stats->GetAchievement(apiName.toUtf8().constData(), &achieved);\n"
        f"    return achieved;\n"
        f"}}\n"
        f"\n"
        f"bool SteamAchievements::storeStats() {{\n"
        f"    ISteamUserStats *stats = SteamUserStats();\n"
        f"    if (!stats) return false;\n"
        f"    return stats->StoreStats();\n"
        f"}}\n"
    )

    files_written: list[str] = []
    for fname, content in [
        ("steamworks_integration.h", header_text),
        ("steamworks_integration.cpp", cpp_text),
        ("steam_achievements.h", achievements_header),
        ("steam_achievements.cpp", achievements_cpp),
    ]:
        out = project_dir / fname
        try:
            out.write_text(content, encoding="utf-8")
            files_written.append(str(out))
        except OSError as e:
            msg = f"Error: failed to write {out}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})

    # .pro snippet (the user still needs to add it to SOURCES / HEADERS manually)
    pro_hint = (
        f"\n# qt_steamworks_init: add these to {stem}.pro (or use qt_pro_edit to merge):\n"
        f"# HEADERS += steamworks_integration.h steam_achievements.h\n"
        f"# SOURCES += steamworks_integration.cpp steam_achievements.cpp\n"
    )
    if params.sdk_path:
        sdk_path = Path(params.sdk_path)
        if sdk_path.exists():
            pro_hint += (
                f"# INCLUDEPATH += {sdk_path / 'public'}\n"
                f"# LIBS += -L{sdk_path / 'redistributable_bin' / 'win64'} -lsteam_api\n"
            )

    if params.write_steam_appid_txt:
        appid_file = project_dir / "steam_appid.txt"
        try:
            appid_file.write_text(f"{params.app_id}\n", encoding="utf-8")
            files_written.append(str(appid_file))
        except OSError as e:
            msg = f"Error: failed to write {appid_file}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})

    readme = (
        f"# Steamworks integration — generated by qt_steamworks_init\n"
        f"\n"
        f"App ID: {params.app_id}\n"
        f"\n"
        f"## Next steps\n"
        f"\n"
        f"1. Download the Steamworks SDK from https://partner.steamgames.com (redistributable).\n"
        f"2. Unzip into ``steamworks_sdk/`` next to this project.\n"
        f"3. Add the .h / .cpp files to your .pro (see hint at the bottom of qt_steamworks_init output).\n"
        f"4. In your main.cpp / mainwindow.cpp, construct a SteamworksIntegration and call ``init()``:\n"
        f"\n"
        f"```cpp\n"
        f"SteamworksIntegration steam;\n"
        f"if (!steam.init()) {{\n"
        f"    qWarning() << \"SteamAPI_Init failed; running in offline mode.\";\n"
        f"}}\n"
        f"SteamAchievements achievements;\n"
        f"achievements.grant(\"ACH_WIN_FIRST_GAME\");\n"
        f"```\n"
        f"\n"
        f"5. Configure achievements on the Steamworks partner site (https://partner.steamgames.com)\n"
        f"   with API names matching those you pass to ``SteamAchievements::grant``.\n"
        f"\n"
        f"## Common pitfalls\n"
        f"\n"
        f"- ``steam_appid.txt`` must sit alongside the .exe in the deploy dir, NOT just the source dir.\n"
        f"  Add a copy step to your .pro: ``win32: {{ QMAKE_POST_LINK += $$quote(cmd /c copy /Y $$PWD\\\\steam_appid.txt $$OUT_PWD) }}``\n"
        f"- SteamAPI_Init returns false if steam_appid.txt is missing or the Steam client isn't running.\n"
        f"- Use ``SteamAPI_RunCallbacks()`` regularly — the included 100 ms QTimer handles this.\n"
    )
    md_file = project_dir / "STEAMWORKS.md"
    try:
        md_file.write_text(readme, encoding="utf-8")
        files_written.append(str(md_file))
    except OSError as e:
        msg = f"Error: failed to write {md_file}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    report = (
        f"=== qt_steamworks_init: {stem}.pro (app_id={params.app_id}) ===\n"
        f"Files written ({len(files_written)}):\n"
        + "\n".join(f"  + {f}" for f in files_written)
        + "\n\n--- .pro hint (paste into your .pro) ---\n"
        + pro_hint
        + "\nSee STEAMWORKS.md for the full step-by-step checklist.\n"
    )
    return report + _json_footer({"ok": True, "data": {"project_dir": str(project_dir), "app_id": params.app_id, "files_written": files_written, "sdk_path": params.sdk_path}})


@mcp.tool(name="qt_itch_butler", annotations={"title": "Generate an itch.io .itch.toml + push scripts for distributing a Qt game via butler", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_itch_butler(params: QtItchButlerInput) -> str:
    """Generate the configuration and push scripts needed to publish a Qt
    game on itch.io via the official ``butler`` CLI.

    Outputs:
      - ``.itch.toml`` — channel manifest (windows/macos/linux/html5) with
        the per-channel artefact pattern. butler reads this on push.
      - ``push_windows.bat`` / ``push_macos.sh`` / ``push_linux.sh`` /
        ``push_html5.bat`` — wrapper scripts that call
        ``butler push <artifact_dir> <user>/<game>:<channel>``.
      - ``BUTLER_README.md`` — setup instructions (install butler, log in
        via ``butler login``, set up the itch.io project page).

    All scripts are dry-run by default (``dry_run=True``); they echo the
    command they would invoke but do not actually push. Set
    ``dry_run=False`` to remove the ``echo`` prefix.

    Args:
        params.project_dir: absolute path to the Qt project directory.
        params.butler_exe: path to butler binary (or just 'butler' on PATH).
        params.itch_user: itch.io username.
        params.itch_game: itch.io game slug.
        params.channels: list of channel names to declare.
        params.artifact_dir: subdirectory under project_dir containing built artefacts.
        params.dry_run: if True, scripts echo the push command but do not invoke butler.

    Returns:
        str: multi-line report listing every file written + a 'First time setup' checklist.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    project_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(project_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not project_dir.exists() or not project_dir.is_dir():
        msg = f"Error: project_dir not found: {project_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    if not params.itch_user or not params.itch_game:
        msg = "Error: itch_user and itch_game are required"
        return msg + _json_footer({"ok": False, "error": msg})

    artifact_rel = params.artifact_dir if params.artifact_dir else "."

    # .itch.toml manifest
    channels_block_lines = []
    for ch in params.channels:
        if ch == "windows":
            pattern = f"{artifact_rel}/windows/*.zip"
        elif ch == "macos":
            pattern = f"{artifact_rel}/macos/*.zip"
        elif ch == "linux":
            pattern = f"{artifact_rel}/linux/*.zip"
        elif ch == "html5":
            pattern = f"{artifact_rel}/html5/*.zip"
        elif ch == "android":
            pattern = f"{artifact_rel}/android/*.apk"
        else:
            pattern = f"{artifact_rel}/{ch}/*"
        channels_block_lines.append(f"[[channels]]\nname = \"{ch}\"\npattern = \"{pattern}\"")
    channels_block = "\n".join(channels_block_lines)

    toml_text = (
        f"# .itch.toml — auto-generated by qt_itch_butler\n"
        f"# butler reads this on `butler push`.\n"
        f"\n"
        f"{channels_block}\n"
    )

    files_written: list[str] = []
    toml_path = project_dir / ".itch.toml"
    try:
        toml_path.write_text(toml_text, encoding="utf-8")
        files_written.append(str(toml_path))
    except OSError as e:
        msg = f"Error: failed to write {toml_path}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Per-channel push scripts
    target = f"{params.itch_user}/{params.itch_game}"

    def _push_cmd(channel: str, ext: str = "bat") -> str:
        # .bat uses %~dp0 for script-relative path; .sh uses $(dirname "$0")
        script_rel = "%~dp0" if ext == "bat" else "$(dirname \"$0\")"
        prefix = "echo [dry-run] " if params.dry_run else ""
        butler = params.butler_exe if params.butler_exe else "butler"
        return f"{prefix}\"{butler}\" push \"{script_rel}{artifact_rel}\" {target}:{channel}"

    for ch in params.channels:
        if ch in ("windows", "html5", "android"):
            script = project_dir / f"push_{ch}.bat"
            content = (
                f"@echo off\n"
                f"REM push_{ch}.bat — auto-generated by qt_itch_butler\n"
                f"REM target: {target}:{ch}\n"
                f"\n"
                f"{_push_cmd(ch, 'bat')}\n"
            )
        else:  # macos / linux / unknown
            script = project_dir / f"push_{ch}.sh"
            content = (
                f"#!/usr/bin/env bash\n"
                f"# push_{ch}.sh — auto-generated by qt_itch_butler\n"
                f"# target: {target}:{ch}\n"
                f"set -euo pipefail\n"
                f"{_push_cmd(ch, 'sh')}\n"
            )
        try:
            script.write_text(content, encoding="utf-8")
            files_written.append(str(script))
        except OSError as e:
            msg = f"Error: failed to write {script}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})

    readme = (
        f"# itch.io publishing — generated by qt_itch_butler\n"
        f"\n"
        f"Target: **{target}**\n"
        f"Channels: {', '.join(params.channels)}\n"
        f"Artifact dir: `{artifact_rel}`\n"
        f"\n"
        f"## First-time setup (one-time)\n"
        f"\n"
        f"1. Download butler from https://itch.io/docs/butler/ (single-binary CLI).\n"
        f"2. Place ``butler.exe`` on PATH or note its absolute path.\n"
        f"3. Run ``butler login`` in a terminal; it opens a browser to authorize.\n"
        f"4. Create the project page on https://itch.io/dashboard → New project.\n"
        f"   Slug must match ``itch_game`` = ``{params.itch_game}``.\n"
        f"\n"
        f"## Pushing a build\n"
        f"\n"
        f"1. Build and zip your artefact into the right subdir:\n"
        f"   - Windows: ``{artifact_rel}/windows/my-game-windows-v1.0.zip``\n"
        f"   - macOS:   ``{artifact_rel}/macos/my-game-macos-v1.0.zip``\n"
        f"   - Linux:   ``{artifact_rel}/linux/my-game-linux-v1.0.zip``\n"
        f"\n"
        f"2. Run the matching push script: ``push_windows.bat``, etc.\n"
        f"\n"
        f"## Going live\n"
        f"\n"
        f"After the first successful push, visit https://itch.io/dashboard to\n"
        f"set the project's 'Kind of project' (HTML5 vs downloadable), enable\n"
        f"payments, and configure the page. butler handles uploads; the page\n"
        f"setup is on the itch.io web UI.\n"
        f"\n"
        f"## Versioning tip\n"
        f"\n"
        f"butler tracks channels independently — you can have ``windows:v1.0.3``\n"
        f"live while still iterating on ``windows:dev``. Push to ``windows:dev``\n"
        f"during development, then promote to the default channel with\n"
        f"``butler promote {target}:windows:dev {target}:windows``.\n"
    )
    md_path = project_dir / "BUTLER_README.md"
    try:
        md_path.write_text(readme, encoding="utf-8")
        files_written.append(str(md_path))
    except OSError as e:
        msg = f"Error: failed to write {md_path}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    report = (
        f"=== qt_itch_butler: {target} ===\n"
        f"Channels: {', '.join(params.channels)}\n"
        f"Artifact dir: {artifact_rel}\n"
        f"Dry run: {params.dry_run}\n"
        f"Files written ({len(files_written)}):\n"
        + "\n".join(f"  + {f}" for f in files_written)
        + f"\n\nNext: read BUTLER_README.md, run `butler login`, then `push_windows.bat`.\n"
    )
    return report + _json_footer({"ok": True, "data": {"project_dir": str(project_dir), "target": target, "channels": params.channels, "files_written": files_written, "dry_run": params.dry_run}})


@mcp.tool(name="qt_documentation_lint", annotations={"title": "Check doxygen comment coverage on .h / .cpp / .qml files (reports missing @brief / @param / @return)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_documentation_lint(params: QtDocumentationLintInput) -> str:
    """Static analysis of doxygen comment completeness.

    For every public function found in the given .h / .cpp files, check:
      - has a doxygen-style block comment immediately above (either
        ``///`` repeated, or ``/** ... */``, or ``/*! ... */``).
      - the comment contains ``@brief`` (or a single-line ``/// summary``).
      - function declarations with parameters have a ``@param`` tag for
        each parameter.
      - non-void functions have a ``@return`` tag.

    Companion to ``qt_docs_gen`` (which *generates* Doxyfile + runs doxygen).
    This tool *checks* that the source is documented to begin with.

    Args:
        params.source_files: list of absolute paths to .h / .cpp / .qml files.
        params.min_brief_chars: minimum summary length to count as documented.
        params.output_format: 'text' or 'json'.
        params.fail_threshold: coverage fraction below which the tool returns Error.

    Returns:
        str: report. Starts with 'Error: ' on file read failure or below-threshold coverage.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.source_files:
        msg = "Error: source_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.output_format not in ("text", "json"):
        msg = f"Error: invalid output_format: {params.output_format} (must be text or json)"
        return msg + _json_footer({"ok": False, "error": msg})

    # Regex patterns
    # Function-like decl: capture name + params
    func_re = re.compile(
        r"^[ \t]*(?:virtual\s+|static\s+|inline\s+|explicit\s+|constexpr\s+|Q_INVOKABLE\s+|signals?:\s+|public\s+slots?:\s+)?"
        r"(?:[A-Za-z_][\w:&<>\s\*]+?\s+)?"
        r"([A-Za-z_]\w*)"
        r"\s*\(([^)]*)\)"
        r"\s*(?:const)?\s*;",
        re.MULTILINE,
    )
    # Doxygen block: /// text OR /** ... */ OR /*! ... */
    dox_block_re = re.compile(
        r"(?:(?:\/\/\/[^\n]*\n)+)|(?:\/\*\*.*?\*\/)|(?:\/\*![^\*]*\*\/)",
        re.DOTALL,
    )
    brief_re = re.compile(r"@brief\s+(\S.*?)(?:\n|$|@)", re.IGNORECASE)
    param_re = re.compile(r"@param\s+(\w+)", re.IGNORECASE)
    return_re = re.compile(r"@return\b", re.IGNORECASE)
    void_re = re.compile(r"\bvoid\b")

    all_findings: list[dict] = []
    summary = {"files": 0, "functions": 0, "documented": 0, "missing_brief": 0, "missing_params": 0, "missing_return": 0}

    for path_str in params.source_files:
        p = Path(path_str)
        if not p.exists():
            all_findings.append({"file": str(p), "error": "file not found"})
            continue
        sandbox_err = _require_sandbox(p, "source_file")
        if sandbox_err:
            all_findings.append({"file": str(p), "error": sandbox_err})
            continue
        try:
            text = p.read_text(encoding="utf-8", errors="replace")
        except OSError as e:
            all_findings.append({"file": str(p), "error": f"read failed: {e}"})
            continue

        summary["files"] += 1
        # For each function, find the preceding doxygen block (within 600 chars back)
        for m in func_re.finditer(text):
            name = m.group(1)
            params_str = m.group(2)
            # skip if it looks like a control statement (if/while/for/switch/catch)
            if name in ("if", "while", "for", "switch", "catch", "return", "sizeof"):
                continue
            # Skip macros / known Qt non-functions
            if name.startswith("Q_") or name.isupper():
                continue

            # Find preceding non-empty text
            start = max(0, m.start() - 600)
            preceding = text[start:m.start()]
            dox_match = None
            for d in dox_block_re.finditer(preceding):
                dox_match = d
            if not dox_match:
                all_findings.append({"file": str(p), "line": text[:m.start()].count("\n") + 1, "function": name, "issue": "no doxygen comment"})
                summary["functions"] += 1
                summary["missing_brief"] += 1
                continue

            block = dox_match.group(0)
            summary["functions"] += 1
            issues: list[str] = []

            # @brief check
            brief_match = brief_re.search(block)
            if brief_match:
                brief_text = brief_match.group(1).strip()
                if len(brief_text) < params.min_brief_chars:
                    issues.append(f"@brief too short ({len(brief_text)} < {params.min_brief_chars})")
                    summary["missing_brief"] += 1
                else:
                    summary["documented"] += 1
            else:
                # Fall back: first line of /// comment
                first_line = ""
                for line in block.splitlines():
                    line = line.strip().lstrip("/").lstrip("*!").strip()
                    if line:
                        first_line = line
                        break
                if len(first_line) >= params.min_brief_chars:
                    summary["documented"] += 1
                else:
                    issues.append("missing @brief")
                    summary["missing_brief"] += 1

            # @param check
            declared_params = [s.strip() for s in params_str.split(",") if s.strip() and s.strip() != "void"]
            declared_params = [p for p in declared_params if not p.startswith("//")]  # skip comments
            if declared_params:
                doc_params = set(param_re.findall(block))
                missing = []
                for dp in declared_params:
                    # extract just the param name (last token of "int x" or "const QString &name")
                    tokens = dp.replace("&", " ").replace("*", " ").split()
                    pname = tokens[-1] if tokens else ""
                    if pname and pname not in doc_params:
                        missing.append(pname)
                if missing:
                    issues.append(f"missing @param: {', '.join(missing)}")
                    summary["missing_params"] += 1

            # @return check
            is_void = bool(void_re.search(m.group(0))) or "void " in m.group(0).split("(")[0]
            if not is_void and not return_re.search(block):
                # const-ref return types count too
                issues.append("missing @return")
                summary["missing_return"] += 1

            if issues:
                all_findings.append({"file": str(p), "line": text[:m.start()].count("\n") + 1, "function": name, "issues": issues})

    coverage = (summary["documented"] / summary["functions"]) if summary["functions"] else 1.0

    if params.output_format == "json":
        import json
        payload = {
            "summary": {**summary, "coverage": round(coverage, 3)},
            "findings": all_findings,
        }
        text = json.dumps(payload, indent=2, ensure_ascii=False)
    else:
        lines = [
            "=== qt_documentation_lint ===",
            f"Files scanned: {summary['files']}",
            f"Functions found: {summary['functions']}",
            f"Documented (have @brief or summary >= {params.min_brief_chars} chars): {summary['documented']}",
            f"Coverage: {coverage*100:.1f}%",
            f"Missing @brief: {summary['missing_brief']}",
            f"Missing @param (total): {summary['missing_params']}",
            f"Missing @return: {summary['missing_return']}",
        ]
        if all_findings:
            lines.append("\nFindings:")
            for f in all_findings[:50]:
                if "error" in f:
                    lines.append(f"  ! {f['file']}: {f['error']}")
                else:
                    issues_str = ", ".join(f.get("issues", [f.get("issue", "")]))
                    lines.append(f"  {f['file']}:{f.get('line', '?')}  {f['function']}() — {issues_str}")
            if len(all_findings) > 50:
                lines.append(f"  ... and {len(all_findings) - 50} more")
        text = "\n".join(lines)

    if coverage < params.fail_threshold:
        msg = f"Error: coverage {coverage*100:.1f}% below threshold {params.fail_threshold*100:.1f}%"
        return msg + "\n" + text + _json_footer({"ok": False, "error": msg, "coverage": coverage})

    return text + _json_footer({"ok": True, "data": {"summary": summary, "coverage": coverage, "findings_count": len(all_findings)}})


# --- v0.3.1 tools ------------------------------------------------------------

@mcp.tool(name="qt_documentation_auto_fill", annotations={"title": "Use an LLM to auto-fill missing doxygen comments on public functions (companion to qt_documentation_lint)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_documentation_auto_fill(params: QtDocumentationAutoFillInput) -> str:
    """Find every public function in the given .h / .cpp files that is missing
    a doxygen comment (per the rules used by ``qt_documentation_lint``), and
    generate an LLM-completed doxygen block for each one.

    Companion to ``qt_documentation_lint``: the lint tool *reports* missing
    docs; this tool *fills them in*.

    Default behaviour (``apply=False``):
      - Calls the LLM once per file with all the missing-function signatures
        in a single prompt (cheaper than per-function calls).
      - Returns a unified-diff preview of every change.
      - Does NOT modify the source files.

    Set ``apply=True`` to write the changes back. The tool backs up each
    modified file to ``<name>.bak`` unless ``backup=False`` (this option
    exists for parity with ``qt_signal_lint_fix`` and is always on here).

    Requires an LLM API key:
      - Anthropic: set ``ANTHROPIC_API_KEY`` env var (model
        ``claude-3-5-sonnet-20241022`` by default).
      - OpenAI:    set ``OPENAI_API_KEY`` env var (model ``gpt-4o-mini`` by
        default).

    If no key is set, returns ``Error: missing API key for provider ...``
    rather than raising.

    Args:
        params.source_files: absolute paths to .h / .cpp / .qml files.
        params.target_style: comment style (currently only 'doxygen').
        params.language_hint: language for the generated summaries (e.g. 'en', 'zh_CN').
        params.llm_provider: 'anthropic' or 'openai' (empty = auto-detect).
        params.llm_model: model name (empty = provider default).
        params.apply: if True, write changes back; else show diff preview.

    Returns:
        str: multi-line report (per-file diff or write confirmation).

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.source_files:
        msg = "Error: source_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})

    cfg = _llm_check_config(params.llm_provider, params.llm_model)
    if not cfg["ok"]:
        return f"Error: {cfg['error']}" + _json_footer({"ok": False, "error": cfg["error"], "hint": f"set {('ANTHROPIC' if cfg['provider']=='anthropic' else 'OPENAI')}_API_KEY env var"})

    func_re = re.compile(
        r"^[ \t]*(?:virtual\s+|static\s+|inline\s+|explicit\s+|constexpr\s+|Q_INVOKABLE\s+|signals?:\s+|public\s+slots?:\s+)?"
        r"(?:[A-Za-z_][\w:&<>\s\*]+?\s+)?"
        r"([A-Za-z_]\w*)"
        r"\s*\(([^)]*)\)"
        r"\s*(?:const)?\s*;",
        re.MULTILINE,
    )
    dox_block_re = re.compile(r"(?:(?:\/\/\/[^\n]*\n)+)|(?:\/\*\*.*?\*\/)|(?:\/\*![^\*]*\*\/)", re.DOTALL)
    brief_re = re.compile(r"@brief\s+(\S.*?)(?:\n|$|@)", re.IGNORECASE)
    param_re = re.compile(r"@param\s+(\w+)", re.IGNORECASE)
    return_re = re.compile(r"@return\b", re.IGNORECASE)
    void_re = re.compile(r"\bvoid\b")

    all_diffs: list[str] = []
    total_undocumented = 0
    files_written: list[str] = []

    for path_str in params.source_files:
        p = Path(path_str)
        sandbox_err = _require_sandbox(p, "source_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        if not p.exists():
            msg = f"Error: file not found: {p}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            original = p.read_text(encoding="utf-8", errors="replace")
        except OSError as e:
            msg = f"Error: failed to read {p}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})

        # Collect undocumented functions in this file
        missing: list[dict] = []
        for m in func_re.finditer(original):
            name = m.group(1)
            if name in ("if", "while", "for", "switch", "catch", "return", "sizeof") or name.startswith("Q_") or name.isupper():
                continue
            start = max(0, m.start() - 600)
            preceding = original[start:m.start()]
            dox_match = None
            for d in dox_block_re.finditer(preceding):
                dox_match = d
            block = dox_match.group(0) if dox_match else ""

            needs_brief = True
            if block:
                bm = brief_re.search(block)
                if bm and len(bm.group(1).strip()) >= 10:
                    needs_brief = False
                elif not bm:
                    first_line = ""
                    for line in block.splitlines():
                        line = line.strip().lstrip("/").lstrip("*!").strip()
                        if line:
                            first_line = line
                            break
                    if len(first_line) >= 10:
                        needs_brief = False
            if not needs_brief:
                continue

            # Compute parameter names + return type
            params_str = m.group(2)
            declared_params = [s.strip() for s in params_str.split(",") if s.strip() and s.strip() != "void"]
            declared_params = [pp for pp in declared_params if not pp.startswith("//")]
            param_names: list[str] = []
            for dp in declared_params:
                tokens = dp.replace("&", " ").replace("*", " ").split()
                if tokens:
                    param_names.append(tokens[-1])
            sig = m.group(0).strip()
            is_void = bool(void_re.search(m.group(0))) or "void " in m.group(0).split("(")[0]
            missing.append({"name": name, "sig": sig, "params": param_names, "is_void": is_void})

        if not missing:
            continue
        total_undocumented += len(missing)

        # Build LLM prompt
        system_prompt = (
            "You are a doxygen comment generator. For each C++ function signature below, "
            "emit a single doxygen comment block (C++ style, ///) placed BEFORE the function. "
            f"Write all @brief summaries in {params.language_hint}. "
            "Use @brief for the one-line summary, @param <name> for each parameter, and @return for non-void returns. "
            "Be concise (one short sentence per @brief). Output ONLY the doxygen blocks separated by blank lines, "
            "in the same order as the input list. Do NOT output the function signatures themselves."
        )
        user_prompt = "Generate doxygen comments for these undocumented public functions:\n\n"
        for i, fn in enumerate(missing, 1):
            user_prompt += f"[{i}] {fn['sig']}\n"
            if fn["params"]:
                user_prompt += f"    params: {', '.join(fn['params'])}\n"
            user_prompt += f"    returns_void: {fn['is_void']}\n\n"

        llm_resp = await _llm_call(cfg["provider"], cfg["model"], system_prompt, user_prompt)
        if not llm_resp["ok"]:
            return f"Error: LLM call failed: {llm_resp['error']}" + _json_footer({"ok": False, "error": llm_resp["error"], "file": str(p)})

        # Parse the LLM output: split on blank lines into N blocks (where N = len(missing))
        blocks = [b.strip() for b in re.split(r"\n\s*\n", llm_resp["text"]) if b.strip()]
        if len(blocks) != len(missing):
            # best-effort: use what we have, pad/truncate to match
            if len(blocks) < len(missing):
                blocks.extend(["/// @brief TODO\n"] * (len(missing) - len(blocks)))
            else:
                blocks = blocks[: len(missing)]

        # Apply blocks by inserting before each function's match position
        modified = original
        # Walk in reverse so earlier insertions don't shift later positions
        for fn, block in reversed(list(zip(missing, blocks))):
            block_text = block if block.endswith("\n") else block + "\n"
            # Find the function position again (positions in 'modified' are same as 'original' since we walk in reverse and insert before each match)
            mm = re.search(re.escape(fn["sig"]), modified)
            if mm:
                modified = modified[: mm.start()] + block_text + modified[mm.start():]

        # Build diff
        diff = _make_unified_diff(str(p), original, modified)
        all_diffs.append(f"--- {p} ({len(missing)} functions) ---\n{diff}")

        if params.apply:
            try:
                bak = p.with_suffix(p.suffix + ".bak")
                bak.write_text(original, encoding="utf-8")
                p.write_text(modified, encoding="utf-8")
                files_written.append(str(p))
            except OSError as e:
                msg = f"Error: failed to write {p}: {e}"
                return msg + _json_footer({"ok": False, "error": msg})

    report_lines = [
        f"=== qt_documentation_auto_fill ({cfg['provider']} / {cfg['model']}) ===",
        f"Files scanned: {len(params.source_files)}",
        f"Total undocumented functions: {total_undocumented}",
        f"Apply: {params.apply}",
    ]
    if all_diffs:
        report_lines.append("\n--- Diff preview ---")
        report_lines.extend(all_diffs[:50])
    if files_written:
        report_lines.append(f"\nFiles written ({len(files_written)}):")
        report_lines.extend(f"  + {f}" for f in files_written)
    if not all_diffs:
        report_lines.append("\n(no undocumented functions found — your code is fully documented!)")
    return "\n".join(report_lines) + _json_footer({
        "ok": True,
        "data": {
            "provider": cfg["provider"], "model": cfg["model"], "files_scanned": len(params.source_files),
            "undocumented_count": total_undocumented, "apply": params.apply, "files_written": files_written,
        },
    })


@mcp.tool(name="qt_translation_auto_fill", annotations={"title": "Use an LLM to fill unfinished entries in Qt .ts translation files (companion to qt_translation_validate)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_translation_auto_fill(params: QtTranslationAutoFillInput) -> str:
    """Find every ``<message>`` with an empty ``<translation>`` (or one marked
    ``type=\"unfinished\"``) in the given .ts files, ask an LLM to translate
    the ``<source>`` text, and return a diff preview (or write back when
    ``apply=True``).

    Companion to ``qt_translation_validate``: validate reports coverage;
    this tool fills the gaps.

    Behaviour:
      - Default ``apply=False`` returns a unified diff per .ts file showing
        the new ``<translation>`` entries inserted.
      - ``apply=True`` writes the modified .ts back (with a ``.bak`` copy).
      - Batches ``batch_size`` unfinished messages per LLM call (default 20)
        to balance speed vs reliability.
      - Preserves the .ts XML structure (DOCTYPE, contexts, messages order).

    Requires the same LLM API key as ``qt_documentation_auto_fill``.

    Args:
        params.ts_files: absolute paths to .ts files.
        params.target_language: restrict to one language code (empty = all).
        params.llm_provider: 'anthropic' or 'openai'.
        params.llm_model: model name (empty = provider default).
        params.batch_size: messages per LLM call.
        params.apply: if True, write changes back; else show diff preview.

    Returns:
        str: multi-line report (per-file diff or write confirmation).

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.ts_files:
        msg = "Error: ts_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})

    cfg = _llm_check_config(params.llm_provider, params.llm_model)
    if not cfg["ok"]:
        return f"Error: {cfg['error']}" + _json_footer({"ok": False, "error": cfg["error"]})

    files_written: list[str] = []
    all_diffs: list[str] = []
    total_filled = 0

    for ts_path_str in params.ts_files:
        p = Path(ts_path_str)
        sandbox_err = _require_sandbox(p, "ts_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        if not p.exists():
            msg = f"Error: ts file not found: {p}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            original = p.read_text(encoding="utf-8")
        except OSError as e:
            msg = f"Error: failed to read {p}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})

        # Detect language from XML attribute
        lang_match = re.search(r'<TS[^>]*language="([^"]+)"', original)
        lang = lang_match.group(1) if lang_match else ""
        if params.target_language and lang != params.target_language:
            continue

        # Find unfinished <message> blocks via regex (XML parsing optional; this is robust enough)
        # Pattern: <message>...<source>X</source>...<translation type="unfinished"></message>
        msg_re = re.compile(
            r"(<message>\s*"
            r"<location[^>]*/>\s*"
            r"<source>(.*?)</source>\s*"
            r")(<translation[^>]*>.*?</translation>)\s*"
            r"(</message>)",
            re.DOTALL,
        )
        unfinished: list[dict] = []
        for mm in msg_re.finditer(original):
            trans_tag = mm.group(3)
            if 'type="unfinished"' in trans_tag or "<translation></translation>" in trans_tag or "<translation/>" in trans_tag:
                unfinished.append({
                    "start": mm.start(),
                    "header": mm.group(1),
                    "source": mm.group(2),
                    "old_trans": mm.group(3),
                    "footer": mm.group(4),
                })

        if not unfinished:
            continue
        total_filled += len(unfinished)

        # Batch LLM calls
        translated_map: dict[str, str] = {}  # source text -> translation
        for batch_start in range(0, len(unfinished), params.batch_size):
            batch = unfinished[batch_start: batch_start + params.batch_size]
            numbered_sources = "\n".join(f"[{i+1}] {b['source']}" for i, b in enumerate(batch))
            system_prompt = (
                f"You are a translator into {lang or 'the target language'}. "
                "For each numbered source string, output ONLY the translation on a single line, "
                "in the same order, prefixed with the same number in square brackets. "
                "Preserve Qt format markers like %1, %2, %n, ellipsis (…) and HTML/XML tags. "
                "Do NOT add commentary, explanations, or extra punctuation."
            )
            user_prompt = f"Translate these {len(batch)} source strings:\n\n{numbered_sources}"
            llm_resp = await _llm_call(cfg["provider"], cfg["model"], system_prompt, user_prompt)
            if not llm_resp["ok"]:
                return f"Error: LLM call failed: {llm_resp['error']}" + _json_footer({"ok": False, "error": llm_resp["error"]})

            # Parse "[N] translation" lines
            for line in llm_resp["text"].splitlines():
                lm = re.match(r"^\s*\[(\d+)\]\s*(.+?)\s*$", line)
                if lm:
                    idx = int(lm.group(1)) - 1
                    if 0 <= idx < len(batch):
                        # HTML-escape the translation (basic)
                        trans = lm.group(2).replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
                        translated_map[batch[idx]["source"]] = trans

        # Build modified XML (regex sub per entry to avoid splice offset bugs)
        modified = original
        for entry in unfinished:
            trans = translated_map.get(entry["source"])
            if not trans:
                # fallback: keep unfinished if LLM missed it
                continue
            new_trans = f"<translation>{trans}</translation>"
            old_block = entry["header"] + entry["old_trans"] + entry["footer"]
            new_block = entry["header"] + new_trans + entry["footer"]
            modified = modified.replace(old_block, new_block, 1)

        diff = _make_unified_diff(str(p), original, modified)
        all_diffs.append(f"--- {p} (lang={lang}, {len(unfinished)} entries) ---\n{diff}")

        if params.apply:
            try:
                bak = p.with_suffix(p.suffix + ".bak")
                bak.write_text(original, encoding="utf-8")
                p.write_text(modified, encoding="utf-8")
                files_written.append(str(p))
            except OSError as e:
                msg = f"Error: failed to write {p}: {e}"
                return msg + _json_footer({"ok": False, "error": msg})

    report_lines = [
        f"=== qt_translation_auto_fill ({cfg['provider']} / {cfg['model']}) ===",
        f"Files scanned: {len(params.ts_files)}",
        f"Total unfinished entries: {total_filled}",
        f"Apply: {params.apply}",
    ]
    if all_diffs:
        report_lines.append("\n--- Diff preview (truncated to 50 .ts files / first 100 lines each) ---")
        for d in all_diffs[:50]:
            truncated = "\n".join(d.splitlines()[:100])
            report_lines.append(truncated)
    if files_written:
        report_lines.append(f"\nFiles written ({len(files_written)}):")
        report_lines.extend(f"  + {f}" for f in files_written)
    if not all_diffs:
        report_lines.append("\n(no unfinished entries found — all translations complete!)")
    return "\n".join(report_lines) + _json_footer({
        "ok": True,
        "data": {
            "provider": cfg["provider"], "model": cfg["model"], "files_scanned": len(params.ts_files),
            "unfinished_count": total_filled, "apply": params.apply, "files_written": files_written,
        },
    })


@mcp.tool(name="qt_signal_lint_fix", annotations={"title": "Auto-fix common signal/slot anti-patterns in .cpp files (companion to qt_signal_slot_trace)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_signal_lint_fix(params: QtSignalLintFixInput) -> str:
    """Auto-fix four categories of fixable signal/slot anti-patterns in the
    given .cpp files. Companion to ``qt_signal_slot_trace``: trace *reports*
    the connections, this tool *fixes* them.

    Rules (each can be individually disabled via ``rules``):

    1. **orphan_slot_stub** — for every ``slots:`` declaration in the file
       that is NOT connected anywhere, insert a stub implementation that logs
       a warning. This prevents silent no-op behaviour when an event fires.
       Detection: parse the class for ``slots:`` / ``public slots:`` blocks,
       collect declared slot names, scan for ``connect(this, SIGNAL(...),
       this, SLOT(<name>))`` patterns, and stub the ones with no incoming
       connection.

    2. **unique_connection** — for ``connect(...)`` calls WITHOUT
       ``Qt::UniqueConnection``, append it. Idempotent (skips if already
       present). Safe because it only affects duplicate-connection prevention.

    3. **queued_connection** — for ``connect(sender, SIGNAL(...), receiver,
       SLOT(...))`` where ``sender`` and ``receiver`` live in different
       threads (heuristic: comment marker ``// @thread:main`` on the sender
       class), insert ``Qt::QueuedConnection``. Conservative — only acts
       when the comment marker is present, so it never guesses wrong.

    4. **functor_to_pointer** — convert Qt 5-style string-based
       ``connect(...)`` (SIGNAL/SLOT macros) to Qt 6-style PMF
       (``&Sender::signal``, ``&Receiver::slot``) only when the conversion
       is unambiguous (only one class named the same in the file).
       Conservative: leaves string-based connects alone when the conversion
       is risky (multiple classes with the same name).

    Default ``apply=False`` shows a unified diff. Set ``apply=True`` to write
    back (a ``.bak`` copy is made by default).

    Args:
        params.source_files: absolute paths to .cpp files.
        params.rules: subset of rule names; empty = all four.
        params.apply: if True, write changes back.
        params.backup: if True and apply=True, write .bak before modifying.

    Returns:
        str: multi-line report (per-file diff or write confirmation).

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.source_files:
        msg = "Error: source_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})

    enabled_rules = set(params.rules) if params.rules else {"orphan_slot_stub", "unique_connection", "queued_connection", "functor_to_pointer"}
    valid_rules = {"orphan_slot_stub", "unique_connection", "queued_connection", "functor_to_pointer"}
    invalid = enabled_rules - valid_rules
    if invalid:
        msg = f"Error: unknown rule(s): {', '.join(sorted(invalid))} (valid: {', '.join(sorted(valid_rules))})"
        return msg + _json_footer({"ok": False, "error": msg})

    all_diffs: list[str] = []
    total_fixes = 0
    files_written: list[str] = []

    for path_str in params.source_files:
        p = Path(path_str)
        sandbox_err = _require_sandbox(p, "source_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        if not p.exists():
            msg = f"Error: file not found: {p}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            original = p.read_text(encoding="utf-8", errors="replace")
        except OSError as e:
            msg = f"Error: failed to read {p}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})

        modified = original
        file_fixes: list[str] = []

        # Rule 2: unique_connection (regex, idempotent)
        # Matches 5-arg connect(...) calls that already have an explicit Qt::Xxx type
        # (4-arg calls leave the type unspecified — adding UniqueConnection there
        # would change semantics; we skip them).
        if "unique_connection" in enabled_rules:
            pat = re.compile(
                r"(connect\s*\([^;]+?,\s*(?:Qt::AutoConnection|Qt::DirectConnection|Qt::QueuedConnection))(\s*)\)",
                re.DOTALL,
            )
            def _add_unique(m: re.Match) -> str:
                # If already has UniqueConnection, leave alone
                if "Qt::UniqueConnection" in m.group(0):
                    return m.group(0)
                return m.group(1) + " | Qt::UniqueConnection" + m.group(2) + ")"
            new_modified, n = pat.subn(_add_unique, modified)
            if n and new_modified != modified:
                added = new_modified.count("| Qt::UniqueConnection") - modified.count("| Qt::UniqueConnection")
                modified = new_modified
                file_fixes.append(f"unique_connection: +{added}")

        # Rule 3: queued_connection (only if // @thread:main marker on sender class)
        if "queued_connection" in enabled_rules:
            pat = re.compile(
                r"connect\s*\(\s*(\w+)\s*,\s*SIGNAL\s*\(.*?\)\s*,\s*(\w+)\s*,\s*SLOT\s*\(.*?\)\s*\)",
            )
            def _add_queued(m: re.Match) -> str:
                sender, _receiver = m.group(1), m.group(2)
                # Heuristic: search for "// @thread:main" within 1500 chars before the connect call
                search_start = max(0, m.start() - 1500)
                window = modified[search_start: m.start()]
                if f"@thread:main" in window or f"@thread: ui" in window:
                    return m.group(0)[:-1] + ", Qt::QueuedConnection)"
                return m.group(0)
            new_modified, n = pat.subn(_add_queued, modified)
            if n and new_modified != modified:
                # subn count = match count, not replace count; check actual delta
                added = new_modified.count(", Qt::QueuedConnection)") - modified.count(", Qt::QueuedConnection)")
                modified = new_modified
                file_fixes.append(f"queued_connection: +{added}")

        # Rule 4: functor_to_pointer (Qt 5 SIGNAL/SLOT macros → Qt 6 PMF)
        if "functor_to_pointer" in enabled_rules:
            # Pattern: connect(sender, SIGNAL(className::sig()), receiver, SLOT(className::slot()))
            pat = re.compile(
                r"connect\s*\(\s*(\w+)\s*,\s*SIGNAL\s*\(\s*(\w+)::(\w+)\s*\(\s*\)\s*\)\s*,\s*(\w+)\s*,\s*SLOT\s*\(\s*(\w+)::(\w+)\s*\(\s*\)\s*\)\s*\)",
            )
            def _to_pmf(m: re.Match) -> str:
                sender, sclass, ssignal, receiver, rclass, rslot = m.groups()
                return f"connect({sender}, &{sclass}::{ssignal}, {receiver}, &{rclass}::{rslot})"
            new_modified, n = pat.subn(_to_pmf, modified)
            if n and new_modified != modified:
                added = new_modified.count("&") - modified.count("&")  # heuristic: each PMF adds one & per signal+slot = 2
                modified = new_modified
                file_fixes.append(f"functor_to_pointer: +{added // 2}")

        # Rule 1: orphan_slot_stub — append stub implementations at end of file
        if "orphan_slot_stub" in enabled_rules and "connect(" in original:
            # Find class name and slots
            class_match = re.search(r"class\s+(\w+)\s*:\s*public\s+Q\w+", modified)
            class_name = class_match.group(1) if class_match else ""
            if class_name:
                slots = re.findall(r"void\s+(\w+)\s*\([^)]*\)\s*;", modified)
                # Find connected slot names via connect() scan
                connected = set()
                for cm in re.finditer(r"SLOT\s*\(\s*\w+::(\w+)\s*\(", modified):
                    connected.add(cm.group(1))
                orphans = [s for s in slots if s not in connected]
                if orphans:
                    stub_block = "\n\n// --- qt_signal_lint_fix: orphan slot stubs ---\n"
                    for sname in orphans:
                        stub_block += f"void {class_name}::{sname}() {{\n"
                        stub_block += f'    qWarning() << "[qt_signal_lint_fix] orphan slot {class_name}::{sname} called but never connected";\n'
                        stub_block += "}\n"
                    modified = modified + stub_block
                    file_fixes.append(f"orphan_slot_stub: +{len(orphans)}")

        total_fixes += len(file_fixes)
        if file_fixes:
            diff = _make_unified_diff(str(p), original, modified)
            all_diffs.append(f"--- {p} ({', '.join(file_fixes)}) ---\n{diff}")
            if params.apply:
                try:
                    if params.backup:
                        bak = p.with_suffix(p.suffix + ".bak")
                        bak.write_text(original, encoding="utf-8")
                    p.write_text(modified, encoding="utf-8")
                    files_written.append(str(p))
                except OSError as e:
                    msg = f"Error: failed to write {p}: {e}"
                    return msg + _json_footer({"ok": False, "error": msg})

    report_lines = [
        "=== qt_signal_lint_fix ===",
        f"Rules enabled: {', '.join(sorted(enabled_rules))}",
        f"Files scanned: {len(params.source_files)}",
        f"Files modified: {len([d for d in all_diffs])}",
        f"Total rule applications: {total_fixes}",
        f"Apply: {params.apply}",
    ]
    if all_diffs:
        report_lines.append("\n--- Diff preview ---")
        report_lines.extend(all_diffs[:50])
    if files_written:
        report_lines.append(f"\nFiles written ({len(files_written)}):")
        report_lines.extend(f"  + {f}" for f in files_written)
    if not all_diffs:
        report_lines.append("\n(no fixable signal/slot issues found)")
    return "\n".join(report_lines) + _json_footer({
        "ok": True,
        "data": {
            "rules": sorted(enabled_rules), "files_scanned": len(params.source_files),
            "files_written": files_written, "rule_applications": total_fixes, "apply": params.apply,
        },
    })


# === v0.3.2: qt_translation_sync ===========================================

class QtTranslationSyncInput(BaseModel):
    project_dir: str = Field(description="Absolute path to the project root (must contain .pro and the .ts file referenced inside).")
    ts_file: str = Field(description="Absolute path to the target .ts file (XML Qt translation source).")
    source_extensions: list[str] = Field(default_factory=lambda: [".cpp", ".h", ".hpp", ".cc", ".qml"], description="File extensions to scan for tr() calls.")
    apply: bool = Field(default=False, description="If True, append <message> stubs for missing source strings to the .ts (with a .bak first). If False (default), return a diff preview.")


@mcp.tool(name="qt_translation_sync", annotations={"title": "Synchronize .ts file with tr() calls in source code (find missing and orphan translations)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_translation_sync(params: QtTranslationSyncInput) -> str:
    """Find divergences between the source code's ``tr()`` calls and a .ts
    translation file. Companion to ``qt_translation_validate`` (which reports
    coverage on the .ts side) and ``qt_translation_auto_fill`` (which LLM-fills
    unfinished entries). This tool handles the *source* side: which strings
    are referenced in the code but not declared in the .ts, and which .ts
    entries are no longer referenced anywhere in the code.

    Workflow:
      1. Walk the project_dir for files matching ``source_extensions``.
      2. Regex-extract every ``tr("...")`` literal source string.
      3. Parse the .ts XML, collect every existing ``<source>...</source>``.
      4. Diff: missing = in source but not in .ts; orphan = in .ts but not in source.
      5. With ``apply=True`` (default False), insert ``<message>`` stubs for
         missing strings into the .ts (with a .bak backup), then return the
         updated coverage percentage.

    Note: the scan is regex-based (handles ``tr("hello")`` and
    ``tr("hello", "ctx")`` forms; does not handle ``QT_TR_NOOP`` or
    ``tr(someVar)`` dynamic strings). False positives are possible in
    comments or string literals that happen to match ``tr("...")``.

    Args:
        params.project_dir: project root to scan for tr() calls.
        params.ts_file: target .ts file (XML, lupdate-compatible).
        params.source_extensions: file suffixes to include in the scan.
        params.apply: if True, write missing strings to the .ts (with .bak).

    Returns:
        str: report. Starts with 'Error: ' on file/sandbox failure.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj.exists() or not proj.is_dir():
        msg = f"Error: project_dir not found or not a dir: {proj}"
        return msg + _json_footer({"ok": False, "error": msg})

    ts = Path(params.ts_file)
    sandbox_err2 = _require_sandbox(ts, "ts_file")
    if sandbox_err2:
        return sandbox_err2 + _json_footer({"ok": False, "error": sandbox_err2})
    if not ts.exists() or not ts.is_file():
        msg = f"Error: ts_file not found: {ts}"
        return msg + _json_footer({"ok": False, "error": msg})

    # 1) Collect tr() sources from code
    tr_re = re.compile(r"""\btr\s*\(\s*"((?:[^"\\]|\\.)*)"(?:\s*,\s*"[^"]*")?\s*\)""")
    source_strings: dict[str, int] = {}  # string -> first occurrence file
    scanned = 0
    for ext in params.source_extensions:
        for p in proj.rglob("*" + ext):
            try:
                txt = p.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            scanned += 1
            for m in tr_re.finditer(txt):
                s = m.group(1)
                # Unescape basic Qt tr() forms: \" \\ \n \t \\
                s = s.replace(r'\"', '"').replace(r'\\', '\\').replace(r'\n', '\n').replace(r'\t', '\t')
                if s not in source_strings:
                    source_strings[s] = 1  # presence marker; value unused
    src_set = set(source_strings.keys())

    # 2) Parse .ts to collect existing <source>
    try:
        ts_text = ts.read_text(encoding="utf-8", errors="replace")
    except OSError as e:
        msg = f"Error: failed to read {ts}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})
    try:
        root = ElementTree.fromstring(ts_text)
    except ElementTree.ParseError as e:
        msg = f"Error: failed to parse {ts} as XML: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    ts_sources: list[str] = []
    for msg in root.iter("message"):
        src_el = msg.find("source")
        if src_el is not None and src_el.text:
            ts_sources.append(src_el.text)
    ts_set = set(ts_sources)

    missing = sorted(src_set - ts_set)  # in source but not in .ts
    orphan = sorted(ts_set - src_set)   # in .ts but not in source

    # 3) Optionally append <message> stubs for missing strings
    inserted: list[str] = []
    new_text = ts_text
    if params.apply and missing:
        # Insert before </TS>; keep doctype untouched
        # Find insertion point: just before </TS>
        end_marker = "</TS>"
        idx = ts_text.rfind(end_marker)
        if idx == -1:
            # Try lowercase
            idx = ts_text.rfind("</ts>")
            end_marker = "</ts>" if idx != -1 else ""
        if idx == -1:
            msg = f"Error: cannot find </TS> close tag in {ts}; refusing to write"
            return msg + _json_footer({"ok": False, "error": msg})
        block = "\n"
        for s in missing:
            esc = s.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
            block += f'    <message>\n        <source>{esc}</source>\n        <translation type="unfinished"></translation>\n    </message>\n'
        new_text = ts_text[:idx] + block + ts_text[idx:]
        try:
            bak = ts.with_suffix(ts.suffix + ".bak")
            bak.write_text(ts_text, encoding="utf-8")
            ts.write_text(new_text, encoding="utf-8")
            inserted = missing
        except OSError as e:
            msg = f"Error: failed to write {ts}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})

    # 4) Build report
    coverage_after = 100.0 * len(src_set & ts_set) / max(1, len(src_set))
    if params.apply and inserted:
        coverage_after = 100.0 * len(src_set) / max(1, len(src_set))  # all in .ts after apply

    lines = [
        "=== qt_translation_sync ===",
        f"Project: {proj}",
        f"TS file: {ts}",
        f"Files scanned: {scanned}",
        f"Source tr() strings: {len(src_set)}",
        f"TS <message> entries: {len(ts_set)}",
        f"Missing (in source, not in .ts): {len(missing)}",
        f"Orphan (in .ts, not in source): {len(orphan)}",
        f"Coverage (source → ts): {coverage_after:.1f}%",
        f"Apply: {params.apply}",
    ]
    if missing:
        lines.append("\n--- Missing strings (first 30) ---")
        for s in missing[:30]:
            lines.append(f"  + {s!r}")
        if len(missing) > 30:
            lines.append(f"  ... +{len(missing) - 30} more")
    if orphan:
        lines.append("\n--- Orphan strings (first 30) ---")
        for s in orphan[:30]:
            lines.append(f"  - {s!r}")
        if len(orphan) > 30:
            lines.append(f"  ... +{len(orphan) - 30} more")
    if inserted:
        lines.append(f"\nInserted {len(inserted)} <message> stubs into {ts}")
        lines.append(f"Backup at: {ts.with_suffix(ts.suffix + '.bak')}")
    if not missing and not orphan:
        lines.append("\n(no divergences — source and .ts are in sync)")
    return "\n".join(lines) + _json_footer({
        "ok": True,
        "data": {
            "files_scanned": scanned,
            "source_strings": len(src_set),
            "ts_entries": len(ts_set),
            "missing": missing,
            "orphan": orphan,
            "inserted": inserted,
            "coverage_after": coverage_after,
            "apply": params.apply,
        },
    })


# === v0.3.2: qt_async_await_lint ============================================

# Rules for qt_async_await_lint. Each rule: id, severity, regex, description.
# severity: 'warning' (likely bug) or 'info' (style/perf).
# Regexes are intentionally line-anchored; the tool reports file:line for each match.
_ASYNC_LINT_RULES: list[dict] = [
    {
        "id": "qtconcurrent_blocking_in_main",
        "severity": "warning",
        "pattern": r"\bQtConcurrent::(run|map|filter|blockingMapped|blockingMappedReduced|blockingFiltered|blockingFilteredReduced|mapReduced|filterReduced)\s*\(",
        "description": "QtConcurrent::run/map/filter is non-blocking; use the returned QFuture. blockingMapped/... freeze the calling thread — call them only from a worker thread, never the GUI thread.",
    },
    {
        "id": "qfuture_waitforfinished",
        "severity": "warning",
        "pattern": r"\.waitForFinished\s*\(",
        "description": "QFuture::waitForFinished() blocks the calling thread. Prefer QFutureWatcher with finished() signal so the UI stays responsive.",
    },
    {
        "id": "qthreadpool_direct_start",
        "severity": "info",
        "pattern": r"\bQThreadPool::(globalInstance\(\)\s*->)?start\s*\(\s*new\s+Q(?:Thread|Runnable)\b",
        "description": "Direct QThreadPool::start with a new QThread leaks unless the thread is wired to deleteLater() on finish. Prefer QThreadPool::start with a QRunnable that manages its own lifetime, or use QtConcurrent::run.",
    },
    {
        "id": "qfuturewatcher_unwired",
        "severity": "warning",
        "pattern": r"\bQFutureWatcher<[^>]*>\s+\w+\s*(?:\([^)]*\))?\s*;",
        "description": "QFutureWatcher declared but the regex does not show it being wired to setFuture() + a slot. If you create one, you must call setFuture(future) and connect at least finished() — otherwise it never fires.",
    },
    {
        "id": "qthread_no_eventloop",
        "severity": "warning",
        "pattern": r"class\s+\w+\s*:\s*public\s+QThread\b",
        "description": "Subclassing QThread without overriding run() that calls exec() leaves the thread with no event loop — signals/slots won't dispatch. Prefer QObject + moveToThread() pattern.",
    },
    {
        "id": "movetothread_after_connect",
        "severity": "info",
        "pattern": r"\bmoveToThread\s*\(",
        "description": "moveToThread() must be called BEFORE the QObject has any signal/slot connections from outside, otherwise the connections lock to the old thread. Verify connection order around any moveToThread() call.",
    },
    {
        "id": "qrunnable_no_autodelete",
        "severity": "warning",
        "pattern": r"class\s+\w+\s*:\s*public\s+QRunnable\b",
        "description": "QRunnable subclass without setAutoDelete(false) is auto-deleted by the thread pool. If you keep a pointer to it past QThreadPool::start(), set autoDelete=false and manage lifetime yourself.",
    },
]


class QtAsyncAwaitLintInput(BaseModel):
    source_files: list[str] = Field(description="Absolute paths to .cpp / .h files to scan for async anti-patterns.")
    output_format: str = Field(default="text", description="'text' (human-readable) or 'json' (machine-readable).")
    min_severity: str = Field(default="info", description="Lowest severity to report: 'info' < 'warning'. Errors are not used (this tool warns only).")


@mcp.tool(name="qt_async_await_lint", annotations={"title": "Static lint of Qt async patterns (QtConcurrent / QFuture / QThreadPool / moveToThread)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_async_await_lint(params: QtAsyncAwaitLintInput) -> str:
    """Scan Qt C++ source files for common async / concurrency anti-patterns.

    The companion to ``qt_clazy_check`` (general Qt anti-patterns). This tool
    focuses specifically on async primitives: QtConcurrent, QFuture, QThread,
    QThreadPool, QRunnable, moveToThread, and QFutureWatcher.

    Rules detected (see ``_ASYNC_LINT_RULES``):
      - ``qtconcurrent_blocking_in_main`` — QtConcurrent::run is fine; blockingMapped/... on the GUI thread freezes the UI
      - ``qfuture_waitforfinished`` — QFuture::waitForFinished() blocks
      - ``qthreadpool_direct_start`` — new QThread leaked into QThreadPool::start
      - ``qfuturewatcher_unwired`` — QFutureWatcher declared but no setFuture()
      - ``qthread_no_eventloop`` — QThread subclass without exec() in run()
      - ``movetothread_after_connect`` — moveToThread() called after connect() (common bug)
      - ``qrunnable_no_autodelete`` — QRunnable subclass without explicit autoDelete policy

    Args:
        params.source_files: absolute paths to .cpp / .h files.
        params.output_format: 'text' or 'json'.
        params.min_severity: 'info' or 'warning'.

    Returns:
        str: report grouped by file. Starts with 'Error: ' on bad input.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.source_files:
        msg = "Error: source_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.output_format not in ("text", "json"):
        msg = f"Error: invalid output_format: {params.output_format} (must be text or json)"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.min_severity not in ("info", "warning"):
        msg = f"Error: invalid min_severity: {params.min_severity}"
        return msg + _json_footer({"ok": False, "error": msg})

    sev_rank = {"info": 0, "warning": 1}
    min_rank = sev_rank[params.min_severity]

    all_findings: list[dict] = []
    files_scanned = 0
    files_with_issues = 0

    for path_str in params.source_files:
        p = Path(path_str)
        sandbox_err = _require_sandbox(p, "source_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        if not p.exists() or not p.is_file():
            msg = f"Error: file not found: {p}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            text = p.read_text(encoding="utf-8", errors="replace")
        except OSError as e:
            msg = f"Error: failed to read {p}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})
        files_scanned += 1
        file_findings: list[dict] = []

        for rule in _ASYNC_LINT_RULES:
            if sev_rank[rule["severity"]] < min_rank:
                continue
            pat = re.compile(rule["pattern"], re.MULTILINE)
            for m in pat.finditer(text):
                line_no = text.count("\n", 0, m.start()) + 1
                file_findings.append({
                    "rule": rule["id"],
                    "severity": rule["severity"],
                    "line": line_no,
                    "snippet": m.group(0).strip()[:120],
                    "description": rule["description"],
                })

        if file_findings:
            files_with_issues += 1
        all_findings.extend({"file": str(p), **f} for f in file_findings)

    summary = {
        "files_scanned": files_scanned,
        "files_with_issues": files_with_issues,
        "total_findings": len(all_findings),
        "by_severity": {
            "info": sum(1 for f in all_findings if f["severity"] == "info"),
            "warning": sum(1 for f in all_findings if f["severity"] == "warning"),
        },
    }

    if params.output_format == "json":
        return json.dumps({"summary": summary, "findings": all_findings}, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": summary})

    lines = [
        "=== qt_async_await_lint ===",
        f"Files scanned: {summary['files_scanned']}",
        f"Files with issues: {summary['files_with_issues']}",
        f"Total findings: {summary['total_findings']}",
        f"  info:    {summary['by_severity']['info']}",
        f"  warning: {summary['by_severity']['warning']}",
    ]
    if all_findings:
        lines.append("\n--- Findings ---")
        by_file: dict[str, list[dict]] = {}
        for f in all_findings:
            by_file.setdefault(f["file"], []).append(f)
        for fpath, finds in by_file.items():
            lines.append(f"\n{fpath}")
            for f in finds:
                lines.append(f"  [{f['severity']}] {f['line']}:{0}  {f['rule']}  -- {f['snippet']}")
                lines.append(f"      {f['description']}")
    else:
        lines.append("\n(no async anti-patterns detected)")
    return "\n".join(lines) + _json_footer({"ok": True, "data": summary})


# === v0.3.2: qt_hotreload_check ============================================

# Q_PROPERTY pattern: find the Q_PROPERTY(... ) body, then tokenize.
# (Renamed to _HR_QPROP_RE to avoid clobbering qt_property_browser's _QPROP_RE.)
_HR_QPROP_RE = re.compile(
    r"Q_PROPERTY\s*\(\s*(?P<body>[^)]*)\)",
    re.DOTALL,
)
# Allowed attribute keywords (those that take a value: READ, WRITE, NOTIFY, MEMBER, RESET, DESIGNABLE, SCRIPTABLE, STORED, USER, REVISION)
_HR_QPROP_TAKE_VALUE = re.compile(r"\b(READ|WRITE|NOTIFY|MEMBER|RESET|DESIGNABLE|SCRIPTABLE|STORED|USER|REVISION)\s+(\w+)")
# Boolean keywords (no value)
_HR_QPROP_BOOL_KW = re.compile(r"\b(CONSTANT|FINAL)\b")


def _qprop_check_parse(text: str) -> list[dict]:
    """Parse a .h file and return a list of Q_PROPERTY entries with their attributes."""
    entries: list[dict] = []
    for m in _HR_QPROP_RE.finditer(text):
        body = m.group("body")
        # Find the boundary between type/name and the first keyword.
        # Keywords we split on: READ|WRITE|NOTIFY|MEMBER|CONSTANT|FINAL|RESET|SCRIPTABLE|DESIGNABLE|STORED|USER|REVISION
        kw_re = re.compile(r"\b(?:READ|WRITE|NOTIFY|MEMBER|CONSTANT|FINAL|RESET|SCRIPTABLE|DESIGNABLE|STORED|USER|REVISION)\b")
        kw_match = kw_re.search(body)
        if not kw_match:
            continue  # malformed Q_PROPERTY with no keyword
        prefix = body[:kw_match.start()].strip()
        attrs = body[kw_match.start():]
        # prefix is "type name" — last word is name, rest is type
        prefix_tokens = prefix.rsplit(None, 1)
        if len(prefix_tokens) != 2:
            continue
        type_name, prop_name = prefix_tokens
        type_name = type_name.strip()
        prop_name = prop_name.strip()
        tokens = {k: v for k, v in _HR_QPROP_TAKE_VALUE.findall(attrs)}
        line = text.count("\n", 0, m.start()) + 1
        entries.append({
            "type": type_name,
            "name": prop_name,
            "read": tokens.get("READ", ""),
            "write": tokens.get("WRITE", ""),
            "notify": tokens.get("NOTIFY", ""),
            "member": tokens.get("MEMBER", ""),
            "constant": bool(_HR_QPROP_BOOL_KW.search(attrs)),
            "line": line,
        })
    return entries


class QtHotreloadCheckInput(BaseModel):
    header_files: list[str] = Field(description="Absolute paths to .h files containing Q_PROPERTY declarations. The tool also reads the matching .cpp (same basename) to verify signal implementations exist.")
    output_format: str = Field(default="text", description="'text' (human-readable) or 'json' (machine-readable).")


@mcp.tool(name="qt_hotreload_check", annotations={"title": "Verify Q_PROPERTY completeness: NOTIFY required, signal signatures match, MEMBER/CONSTANT consistency", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_hotreload_check(params: QtHotreloadCheckInput) -> str:
    """Check Q_PROPERTY declarations in Qt .h files for completeness.

    Companion to ``qt_property_browser`` (which *renders* Q_PROPERTY as a
    table for documentation). This tool *validates* them for runtime safety:

      - **missing_notify** — any Q_PROPERTY with READ but no NOTIFY violates
        the Qt convention. QML/bindings cannot react to changes without a
        NOTIFY signal. Warning.
      - **missing_read** — Q_PROPERTY without READ is malformed (Qt requires
        it; MEMBER is an alternative but excludes QML access). Error.
      - **constant_with_write** — CONSTANT + WRITE is contradictory.
        CONSTANT means "set once at construction"; WRITE means "mutable".
        Error.
      - **member_with_read** — MEMBER + READ is redundant; pick one.
        Info.
      - **notify_signal_not_found** — NOTIFY references a signal that does
        not exist in the .h signals: block. Error.
      - **member_variable_not_found** — MEMBER references a member that is
        not declared in the .h. Error.
      - **write_setter_not_found** — WRITE references a setter function
        that is not declared in the .h. Error.

    Args:
        params.header_files: absolute paths to .h files to check.
        params.output_format: 'text' or 'json'.

    Returns:
        str: report. Starts with 'Error: ' on bad input.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.header_files:
        msg = "Error: header_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.output_format not in ("text", "json"):
        msg = f"Error: invalid output_format: {params.output_format} (must be text or json)"
        return msg + _json_footer({"ok": False, "error": msg})

    all_findings: list[dict] = []
    files_scanned = 0
    total_props = 0

    for path_str in params.header_files:
        p = Path(path_str)
        sandbox_err = _require_sandbox(p, "header_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        if not p.exists() or not p.is_file():
            msg = f"Error: file not found: {p}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            text = p.read_text(encoding="utf-8", errors="replace")
        except OSError as e:
            msg = f"Error: failed to read {p}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})
        files_scanned += 1

        entries = _qprop_check_parse(text)
        total_props += len(entries)

        # Collect signals: and member variables from the same .h.
        # Match every signal declaration under any `signals:` block.
        signal_re = re.compile(r"signals\s*:\s*(.+?)(?:public\s+slots|protected\s+slots|private\s+slots|public\s*:|protected\s*:|private\s*:|^\}|\Z)", re.DOTALL | re.MULTILINE)
        signals: set[str] = set()
        for blk in signal_re.finditer(text):
            body = blk.group(1)
            for m in re.finditer(r"(?:[\w:]+\s+)?(\w+)\s*\([^)]*\)\s*;", body):
                signals.add(m.group(1))
        # void on_<name>(...) slots (so we can also catch onXxx auto-slot form, but treat only declared signals as authoritative)
        # member variables: "Type name;" or "Type name = ...;" inside class body
        members = set(re.findall(r"^\s*(?:static\s+)?(?:const\s+)?(?:[A-Za-z_][\w:<>&\s\*]+?)\s+(\w+)\s*(?:=\s*[^;]+)?\s*;", text, re.MULTILINE))
        # method declarations (readers, writers) — match both `;`-ended declarations and `{`-bodied inline definitions
        methods = set(re.findall(r"^\s*(?:virtual\s+|static\s+)?(?:[\w:&<>\s\*]+?)\s+(\w+)\s*\([^)]*\)\s*(?:const)?\s*(?:;|\{)", text, re.MULTILINE))

        for e in entries:
            line = e["line"]
            pname = e["name"]
            # missing_read
            if not e["read"] and not e["member"]:
                all_findings.append({"file": str(p), "line": line, "property": pname, "rule": "missing_read", "severity": "error", "message": f"Q_PROPERTY {pname} has no READ accessor (or MEMBER fallback)."})
            # missing_notify
            if (e["read"] or e["member"]) and not e["notify"] and not e["constant"]:
                all_findings.append({"file": str(p), "line": line, "property": pname, "rule": "missing_notify", "severity": "warning", "message": f"Q_PROPERTY {pname} has no NOTIFY signal — QML/bindings cannot react to changes."})
            # constant_with_write
            if e["constant"] and e["write"]:
                all_findings.append({"file": str(p), "line": line, "property": pname, "rule": "constant_with_write", "severity": "error", "message": f"Q_PROPERTY {pname} is CONSTANT but also has WRITE — contradictory."})
            # member_with_read
            if e["member"] and e["read"]:
                all_findings.append({"file": str(p), "line": line, "property": pname, "rule": "member_with_read", "severity": "info", "message": f"Q_PROPERTY {pname} has both MEMBER and READ — pick one (MEMBER hides READ from QML)."})
            # notify_signal_not_found
            if e["notify"] and e["notify"] not in signals:
                all_findings.append({"file": str(p), "line": line, "property": pname, "rule": "notify_signal_not_found", "severity": "error", "message": f"Q_PROPERTY {pname} NOTIFY signal '{e['notify']}' is not declared in signals: block."})
            # member_variable_not_found
            if e["member"] and e["member"] not in members:
                all_findings.append({"file": str(p), "line": line, "property": pname, "rule": "member_variable_not_found", "severity": "error", "message": f"Q_PROPERTY {pname} MEMBER '{e['member']}' is not declared as a class member."})
            # write_setter_not_found
            if e["write"] and e["write"] not in methods:
                all_findings.append({"file": str(p), "line": line, "property": pname, "rule": "write_setter_not_found", "severity": "error", "message": f"Q_PROPERTY {pname} WRITE setter '{e['write']}' is not declared in the class."})

    summary = {
        "files_scanned": files_scanned,
        "total_properties": total_props,
        "total_findings": len(all_findings),
        "by_severity": {
            "info": sum(1 for f in all_findings if f["severity"] == "info"),
            "warning": sum(1 for f in all_findings if f["severity"] == "warning"),
            "error": sum(1 for f in all_findings if f["severity"] == "error"),
        },
    }

    if params.output_format == "json":
        return json.dumps({"summary": summary, "findings": all_findings}, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": summary})

    lines = [
        "=== qt_hotreload_check ===",
        f"Files scanned: {summary['files_scanned']}",
        f"Total Q_PROPERTY: {summary['total_properties']}",
        f"Total findings: {summary['total_findings']}",
        f"  info:    {summary['by_severity']['info']}",
        f"  warning: {summary['by_severity']['warning']}",
        f"  error:   {summary['by_severity']['error']}",
    ]
    if all_findings:
        lines.append("\n--- Findings ---")
        by_file: dict[str, list[dict]] = {}
        for f in all_findings:
            by_file.setdefault(f["file"], []).append(f)
        for fpath, finds in by_file.items():
            lines.append(f"\n{fpath}")
            for f in finds:
                lines.append(f"  [{f['severity']}] {f['line']}:0  {f['rule']} (property '{f['property']}')")
                lines.append(f"      {f['message']}")
    else:
        lines.append("\n(no Q_PROPERTY issues found)")
    return "\n".join(lines) + _json_footer({"ok": True, "data": summary})


# === v0.3.2: qt_perf_budget ================================================

class QtPerfBudgetInput(BaseModel):
    executable: str = Field(description="Absolute path to the .exe to time.")
    budget_ms: int = Field(default=2000, description="Allowed startup budget in milliseconds. Default 2000 (2s).")
    max_wait_ms: int = Field(default=10000, description="Hard upper bound on how long to wait for the window to appear. Default 10000 (10s).")
    args: list[str] = Field(default_factory=list, description="Command-line arguments for the .exe.")


def _perf_find_window_for_pid(pid: int) -> tuple[bool, float]:
    """Return (found, elapsed_since_epoch). Uses pywinauto to find a top-level
    window owned by the given pid. Returns elapsed=0 if not found within
    one polling iteration (caller should loop)."""
    import time
    try:
        from pywinauto import findwindows  # type: ignore
    except ImportError:
        return (False, time.monotonic())
    try:
        wins = findwindows.find_windows(process=pid)
    except Exception:
        wins = []
    return (bool(wins), time.monotonic())


def _perf_first_cpu_active(pid: int) -> tuple[bool, float]:
    """Return (saw_cpu, elapsed_since_epoch). Checks if psutil sees non-zero
    user+system CPU time for the pid. Returns elapsed=0 if not yet."""
    import time
    try:
        import psutil  # type: ignore
    except ImportError:
        return (False, time.monotonic())
    try:
        p = psutil.Process(pid)
        ct = p.cpu_times()
        if (ct.user + ct.system) > 0.001:
            return (True, time.monotonic())
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        pass
    return (False, time.monotonic())


@mcp.tool(name="qt_perf_budget", annotations={"title": "Measure .exe startup latency against a budget (first CPU + first window), then kill", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_perf_budget(params: QtPerfBudgetInput) -> str:
    """Launch a Qt .exe, measure the time from spawn to "first CPU activity"
    (proxy for entering the event loop) and to "first top-level window"
    (proxy for the GUI being visible), compare against a budget, then
    always kill the launched process.

    Use this as a CI gate: pass ``budget_ms=2000`` to enforce a 2-second
    cold-start budget, fail the build if a release regresses by more than
    200ms vs the baseline. The companion to ``qt_smoke_test`` (which only
    checks "does it run"); this tool checks "does it run FAST enough".

    Args:
        params.executable: absolute path to the .exe to time.
        params.budget_ms: allowed startup budget in ms (default 2000).
        params.max_wait_ms: hard upper bound on wait for window (default 10000).
        params.args: command-line arguments.

    Returns:
        str: report with measured times + budget pass/fail. The process is
        always killed before returning.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    err = _check_paths()
    if err:
        return f"Error: {err}" + _json_footer({"ok": False, "error": err})

    exe = Path(params.executable).resolve()
    sandbox_err = _require_sandbox(exe, "executable")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not exe.exists() or not exe.is_file():
        msg = f"Error: executable not found: {exe}"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.budget_ms <= 0 or params.max_wait_ms <= 0:
        msg = "Error: budget_ms and max_wait_ms must be positive"
        return msg + _json_footer({"ok": False, "error": msg})

    cmd = [str(exe)] + list(params.args)
    run_env = _qt_env()

    import time as _t
    import subprocess as _sp
    t0 = _t.monotonic()
    try:
        proc = _sp.Popen(cmd, cwd=str(exe.parent), env=run_env, stdin=_sp.DEVNULL, stdout=_sp.DEVNULL, stderr=_sp.DEVNULL, close_fds=True)
    except OSError as e:
        msg = f"Error: failed to spawn {exe}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})
    pid = proc.pid

    first_cpu_ms: float | None = None
    first_window_ms: float | None = None
    alive_at_400ms = False
    poll_interval = 0.05  # 50 ms
    elapsed_ms = 0.0

    try:
        while elapsed_ms < params.max_wait_ms:
            await asyncio.sleep(poll_interval)
            elapsed_ms = (_t.monotonic() - t0) * 1000.0

            # First, check the process is still alive (we expect it to be)
            try:
                alive_at_400ms = (proc.poll() is None) and (elapsed_ms >= 400)
            except Exception:
                pass

            if first_cpu_ms is None:
                saw, _ = await asyncio.to_thread(_perf_first_cpu_active, pid)
                if saw:
                    first_cpu_ms = elapsed_ms
            if first_window_ms is None:
                found, _ = await asyncio.to_thread(_perf_find_window_for_pid, pid)
                if found:
                    first_window_ms = elapsed_ms
                    break  # window appeared; no need to keep polling
        else:
            pass  # timed out without window
    finally:
        # Always kill the launched process
        try:
            proc.kill()
            try:
                proc.wait(timeout=2)
            except _sp.TimeoutExpired:
                pass
        except Exception:
            pass

    measured = first_window_ms if first_window_ms is not None else first_cpu_ms
    measured_label = "first_window" if first_window_ms is not None else ("first_cpu" if first_cpu_ms is not None else "none")
    pass_fail = "PASS"
    note = ""
    if measured is None:
        pass_fail = "FAIL"
        note = f"no CPU or window activity detected within {params.max_wait_ms} ms (exe likely hung or crashed)"
    elif measured > params.budget_ms:
        pass_fail = "FAIL"
        note = f"{measured_label}={measured:.0f} ms exceeds budget {params.budget_ms} ms"
    else:
        note = f"{measured_label}={measured:.0f} ms within budget {params.budget_ms} ms"

    lines = [
        "=== qt_perf_budget ===",
        f"Executable: {exe}",
        f"Budget: {params.budget_ms} ms",
        f"Max wait: {params.max_wait_ms} ms",
        f"Result: {pass_fail}",
        f"First CPU activity: {f'{first_cpu_ms:.0f} ms' if first_cpu_ms is not None else '(not detected)'}",
        f"First top-level window: {f'{first_window_ms:.0f} ms' if first_window_ms is not None else '(not detected)'}",
        f"Process alive at 400 ms: {alive_at_400ms}",
        f"Note: {note}",
        f"(Process killed after measurement)",
    ]
    return "\n".join(lines) + _json_footer({
        "ok": True,
        "data": {
            "executable": str(exe),
            "budget_ms": params.budget_ms,
            "first_cpu_ms": first_cpu_ms,
            "first_window_ms": first_window_ms,
            "alive_at_400ms": alive_at_400ms,
            "result": pass_fail,
            "note": note,
        },
    })


# === v0.3.2: qt_format_check ==============================================

# Built-in .clang-format templates per style. Used when init_clang_format=True
# and no .clang-format file exists in the target. These are minimal but
# representative — users will likely want to tweak them.
_CLANG_FORMAT_TEMPLATES: dict[str, str] = {
    "llvm": (
        "BasedOnStyle: LLVM\n"
        "IndentWidth: 4\n"
        "ColumnLimit: 80\n"
        "UseTab: Never\n"
        "AllowShortFunctionsOnASingleLine: Inline\n"
    ),
    "google": (
        "BasedOnStyle: Google\n"
        "IndentWidth: 4\n"
        "ColumnLimit: 80\n"
        "AllowShortFunctionsOnASingleLine: Inline\n"
    ),
    "chromium": (
        "BasedOnStyle: Chromium\n"
        "IndentWidth: 4\n"
        "ColumnLimit: 80\n"
    ),
    "mozilla": (
        "BasedOnStyle: Mozilla\n"
        "IndentWidth: 4\n"
        "ColumnLimit: 80\n"
    ),
    "webkit": (
        "BasedOnStyle: WebKit\n"
        "IndentWidth: 4\n"
        "ColumnLimit: 0  # no limit in WebKit\n"
    ),
    "qt": (
        "# Qt Company style — derived from Qt 6 qt.git/.clang-format\n"
        "BasedOnStyle: LLVM\n"
        "IndentWidth: 4\n"
        "TabWidth: 4\n"
        "UseTab: Never\n"
        "ColumnLimit: 100\n"
        "AlignAfterOpenBracket: Align\n"
        "AlignConsecutiveAssignments: false\n"
        "AlignConsecutiveDeclarations: false\n"
        "AllowShortFunctionsOnASingleLine: All\n"
        "AllowShortLambdasOnASingleLine: All\n"
        "BreakBeforeBraces: Attach\n"
        "FixNamespaceComments: false\n"
        "PointerAlignment: Left\n"
        "SortIncludes: true\n"
        "IncludeBlocks: Preserve\n"
    ),
}


class QtFormatCheckInput(BaseModel):
    target: str = Field(description="Absolute path to a .h/.cpp file OR a directory to scan (recurses into subdirs).")
    style: str = Field(default="file", description="clang-format style: 'file' (use .clang-format if present), 'llvm', 'google', 'chromium', 'mozilla', 'webkit', 'qt', or a YAML string. Default: 'file'.")
    init_clang_format: bool = Field(default=False, description="If True and no .clang-format exists in the target's parent directory, write a template .clang-format based on the chosen style. Idempotent (won't overwrite an existing file).")
    output_format: str = Field(default="text", description="'text' (human-readable) or 'json' (machine-readable).")
    clang_format_exe: str = Field(default="", description="Optional explicit path to clang-format.exe. Empty = use QT_FORMAT_EXE env var or 'clang-format' on PATH.")


def _format_check_resolve_exe(explicit: str) -> str | None:
    """Resolve clang-format binary (explicit → env → PATH). Returns path or None."""
    if explicit:
        p = Path(explicit)
        return str(p) if p.exists() else None
    env_path = os.environ.get("QT_FORMAT_EXE", "")
    if env_path and Path(env_path).exists():
        return env_path
    # Try PATH via shutil.which
    found = shutil.which("clang-format")
    return found


@mcp.tool(name="qt_format_check", annotations={"title": "CI-friendly clang-format audit: aggregate per-file pass/fail + optional .clang-format init", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_format_check(params: QtFormatCheckInput) -> str:
    """Audit a directory of C++ sources for clang-format compliance and
    aggregate the result into a single CI-friendly report.

    The companion to ``qt_format`` (which *fixes* formatting in place or
    shows a diff per file). This tool focuses on the audit:

      - Walk ``target`` for ``.h/.cpp/.cc/.cxx`` files.
      - Run ``clang-format --output-replacements-xml <file>`` for each.
      - Aggregate: total / clean / dirty file counts + total replacements.
      - With ``init_clang_format=True`` and no existing ``.clang-format`` in
        the target's parent, write a template ``.clang-format`` based on the
        chosen style (one of: llvm, google, chromium, mozilla, webkit, qt).
        Existing ``.clang-format`` is never overwritten.

    Output is suitable for CI gating: if any file is dirty, the report
    includes a non-zero "dirty_files" count; pipe that to a check.

    Args:
        params.target: absolute path to a file or directory.
        params.style: clang-format style or 'file' (use existing .clang-format).
        params.init_clang_format: if True, generate .clang-format if missing.
        params.output_format: 'text' or 'json'.
        params.clang_format_exe: explicit clang-format path (empty = auto).

    Returns:
        str: report. Starts with 'Error: ' on bad input or missing clang-format.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.output_format not in ("text", "json"):
        msg = f"Error: invalid output_format: {params.output_format} (must be text or json)"
        return msg + _json_footer({"ok": False, "error": msg})

    target = Path(params.target).resolve()
    sandbox_err = _require_sandbox(target, "target")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not target.exists():
        msg = f"Error: target not found: {target}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Optionally write a .clang-format template if missing
    written_clang_format = ""
    if params.init_clang_format:
        parent = target if target.is_dir() else target.parent
        cf = parent / ".clang-format"
        if not cf.exists():
            style_key = params.style if params.style in _CLANG_FORMAT_TEMPLATES else "llvm"
            try:
                cf.write_text(_CLANG_FORMAT_TEMPLATES[style_key], encoding="utf-8")
                written_clang_format = str(cf)
            except OSError as e:
                msg = f"Error: failed to write {cf}: {e}"
                return msg + _json_footer({"ok": False, "error": msg})

    # Resolve clang-format
    exe = _format_check_resolve_exe(params.clang_format_exe)
    if exe is None:
        msg = "Error: clang-format not found. Set QT_FORMAT_EXE env var or add clang-format.exe to PATH."
        return msg + _json_footer({"ok": False, "error": msg})

    # Collect files. .tmp is intentionally NOT skipped (SANDBOX_TMP lives under .tmp).
    _FORMAT_EXTS = (".h", ".cpp", ".cc", ".cxx")
    _FORMAT_SKIP_DIRS = (".git", "build-debug", "build-release", "node_modules")
    _FORMAT_SKIP_PREFIXES = ("moc_", "ui_", "qrc_")
    if target.is_file():
        files = [target]
    else:
        files = []
        for p in target.rglob("*"):
            if not p.is_file() or p.suffix.lower() not in _FORMAT_EXTS:
                continue
            if any(part in _FORMAT_SKIP_DIRS for part in p.parts):
                continue
            if any(part.startswith(_FORMAT_SKIP_PREFIXES) for part in p.parts):
                continue
            files.append(p)

    # Per-file audit
    file_results: list[dict] = []
    total_replacements = 0
    dirty_files = 0
    clean_files = 0
    error_files = 0

    def _audit_one(fp: Path) -> tuple[int, str]:
        """Return (replacement_count, status: 'clean'|'dirty'|'error')."""
        try:
            r = subprocess.run(
                [exe, f"--style={params.style}", "--output-replacements-xml", str(fp)],
                capture_output=True, text=True, timeout=10,
            )
            if r.returncode != 0:
                return (-1, "error")
            xml = r.stdout
            # Count <replacement ...>...</replacement> occurrences
            count = xml.count("<replacement ")
            return (count, "clean" if count == 0 else "dirty")
        except subprocess.TimeoutExpired:
            return (-1, "error")
        except FileNotFoundError:
            return (-1, "error")

    for fp in files:
        rel = str(fp)
        n, status = await asyncio.to_thread(_audit_one, fp)
        if status == "error":
            error_files += 1
            file_results.append({"file": rel, "replacements": -1, "status": "error"})
        elif status == "clean":
            clean_files += 1
            file_results.append({"file": rel, "replacements": 0, "status": "clean"})
        else:
            dirty_files += 1
            total_replacements += n
            file_results.append({"file": rel, "replacements": n, "status": "dirty"})

    summary = {
        "total_files": len(files),
        "clean_files": clean_files,
        "dirty_files": dirty_files,
        "error_files": error_files,
        "total_replacements": total_replacements,
        "written_clang_format": written_clang_format,
        "style": params.style,
    }

    if params.output_format == "json":
        return json.dumps({"summary": summary, "files": file_results}, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": summary})

    lines = [
        "=== qt_format_check ===",
        f"Target: {target}",
        f"Style: {params.style}",
        f"Total files: {summary['total_files']}",
        f"  clean: {summary['clean_files']}",
        f"  dirty: {summary['dirty_files']}",
        f"  error: {summary['error_files']}",
        f"Total replacements needed: {summary['total_replacements']}",
    ]
    if written_clang_format:
        lines.append(f"Wrote .clang-format template: {written_clang_format}")
    if dirty_files:
        lines.append("\n--- Dirty files (top 20 by replacements) ---")
        sorted_dirty = sorted([f for f in file_results if f["status"] == "dirty"], key=lambda x: -x["replacements"])
        for f in sorted_dirty[:20]:
            lines.append(f"  [{f['replacements']:>5} replacements]  {f['file']}")
        if len(sorted_dirty) > 20:
            lines.append(f"  ... +{len(sorted_dirty) - 20} more dirty files")
    if error_files:
        lines.append("\n--- Error files ---")
        for f in [x for x in file_results if x["status"] == "error"]:
            lines.append(f"  ? {f['file']}")
    if not dirty_files and not error_files:
        lines.append("\n(all files conform to the selected clang-format style)")
    return "\n".join(lines) + _json_footer({"ok": True, "data": summary})


# === v0.3.3: qt_widget_introspect ============================================

def _widget_introspect_resolve_pywinauto() -> tuple[bool, str]:
    """Check if pywinauto is importable. Returns (available, error_message)."""
    try:
        import pywinauto  # type: ignore  # noqa: F401
        return True, ""
    except ImportError as e:
        return False, f"pywinauto not installed: {e}. Run: pip install pywinauto"


def _widget_introspect_count_nodes(node) -> int:
    """Count total nodes in a widget tree (recursive)."""
    if not isinstance(node, dict):
        return 0
    children = node.get("children", [])
    if not isinstance(children, list):
        return 1
    return 1 + sum(_widget_introspect_count_nodes(c) for c in children)


def _widget_introspect_walk(elem, depth: int, max_depth: int) -> dict:
    """Walk a pywinauto element recursively into a JSON tree."""
    info: dict = {
        "name": "",
        "type": str(type(elem).__name__),
        "auto_id": "",
        "rect": "",
        "enabled": True,
        "visible": True,
    }
    try:
        info["name"] = (getattr(elem, "window_text", lambda: "")() or "")
    except Exception:
        pass
    try:
        ei = elem.element_info
        info["auto_id"] = getattr(ei, "automation_id", "") or ""
        if not info["name"]:
            info["name"] = getattr(ei, "name", "") or ""
        info["rect"] = str(getattr(ei, "rectangle", "") or "")
        info["enabled"] = bool(getattr(ei, "enabled", True))
        info["visible"] = bool(getattr(ei, "visible", True))
    except Exception:
        pass
    if depth >= max_depth:
        info["children"] = []
        return info
    children: list = []
    try:
        for c in elem.children():
            children.append(_widget_introspect_walk(c, depth + 1, max_depth))
    except Exception:
        pass
    info["children"] = children
    return info


def _widget_introspect_find(elem, name_contains: str, type_contains: str, text_contains: str, out: list) -> None:
    """Find widgets in tree matching conditions (AND if multiple)."""
    name = ""
    type_name = str(type(elem).__name__)
    try:
        name = (getattr(elem, "window_text", lambda: "")() or "")
    except Exception:
        pass
    try:
        ei = elem.element_info
        if not name:
            name = getattr(ei, "name", "") or ""
    except Exception:
        pass
    if name_contains and name_contains.lower() not in name.lower():
        pass
    elif type_contains and type_contains.lower() not in type_name.lower():
        pass
    elif text_contains and text_contains.lower() not in name.lower():
        pass
    else:
        info = {"name": name, "type": type_name, "rect": ""}
        try:
            ei = elem.element_info
            info["rect"] = str(getattr(ei, "rectangle", "") or "")
        except Exception:
            pass
        out.append(info)
    try:
        for c in elem.children():
            _widget_introspect_find(c, name_contains, type_contains, text_contains, out)
    except Exception:
        pass


def _widget_introspect_details(elem) -> dict:
    """Get detailed properties of a single widget element."""
    details: dict = {"type": str(type(elem).__name__)}
    try:
        details["name"] = getattr(elem, "window_text", lambda: "")() or ""
    except Exception:
        pass
    try:
        ei = elem.element_info
        details["auto_id"] = getattr(ei, "automation_id", "") or ""
        details["rect"] = str(getattr(ei, "rectangle", "") or "")
        details["control_type"] = str(getattr(ei, "control_type", "") or "")
        details["framework_id"] = str(getattr(ei, "framework_id", "") or "")
        details["process_id"] = int(getattr(ei, "process_id", 0) or 0)
        details["enabled"] = bool(getattr(ei, "enabled", True))
        details["visible"] = bool(getattr(ei, "visible", True))
        details["focused"] = bool(getattr(ei, "focused", False))
    except Exception:
        pass
    try:
        details["class_name"] = elem.friendlyclassname()
    except Exception:
        pass
    try:
        details["children_count"] = len(list(elem.children()))
    except Exception:
        details["children_count"] = 0
    return details


class QtWidgetIntrospectInput(BaseModel):
    action: str = Field(description="One of: 'snapshot' (whole widget tree as JSON), 'find' (search by name_contains / type_contains / text_contains), 'details' (single widget by auto_id).")
    process_id: int = Field(default=0, description="Process ID of the running Qt app. If 0, executable is launched.")
    executable: str = Field(default="", description="Absolute path of .exe to launch (only used when process_id=0). Detached, killed after operation.")
    window_title: str = Field(default="", description="Substring to locate window. If empty, the first top-level window of process_id/executable is used.")
    auto_id: str = Field(default="", description="For action='details': automation_id (the Qt setObjectName value exposed via UI Automation) of the target widget.")
    name_contains: str = Field(default="", description="For action='find': case-insensitive substring match on widget name/text.")
    type_contains: str = Field(default="", description="For action='find': case-insensitive substring match on widget class (e.g. 'QPushButton', 'QLineEdit').")
    text_contains: str = Field(default="", description="For action='find': case-insensitive substring match on widget visible text.")
    max_depth: int = Field(default=4, description="For action='snapshot': max recursion depth. Default 4 keeps output readable for complex apps.")
    timeout_seconds: int = Field(default=15, description="Seconds to wait for the window to appear after launch / connect.")


@mcp.tool(name="qt_widget_introspect", annotations={"title": "Inspect the running Qt app's widget tree (snapshot / find / details) via pywinauto + UI Automation", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_widget_introspect(params: QtWidgetIntrospectInput) -> str:
    """Inspect a running Qt application's widget tree through pywinauto + UI Automation.

    Inspired by ``0xCarbon/qt-mcp``'s ``qt_find_widget`` / ``qt_snapshot`` /
    ``qt_widget_details`` trio. This tool merges those operations behind a
    single ``action`` parameter so the LLM can issue one round-trip.

    Actions:
      - ``snapshot`` — return the entire widget tree of the first top-level
        window as nested JSON. Each node has: name / type / auto_id / rect /
        enabled / visible / children. For complex apps, prefer
        ``max_depth=4`` to keep the JSON readable.
      - ``find`` — search the tree by ``name_contains`` (button label,
        user-visible text), ``type_contains`` (e.g. ``QPushButton``,
        ``QLineEdit``), or ``text_contains``. AND-combined if multiple
        given. Returns a flat list of matches with rect.
      - ``details`` — return full properties (auto_id, class_name,
        control_type, framework_id, focused / visible / enabled,
        children_count) for the widget identified by ``auto_id`` (the Qt
        ``setObjectName`` value exposed via UI Automation's
        ``AutomationId``).

    If ``process_id`` is given, attach to the running app. Otherwise, launch
    ``executable`` (detached), wait up to ``timeout_seconds`` for a window,
    run the action, then always kill the spawned process.

    Requires ``pywinauto`` (``pip install pywinauto``). The companion to
    ``qt_ui_action`` (which drives actions) — this tool *observes* state.

    Args:
        params.action: 'snapshot' | 'find' | 'details'.
        params.process_id: PID of the running Qt app (0 = launch executable).
        params.executable: absolute path of .exe (only when process_id=0).
        params.window_title: substring to locate window (optional).
        params.auto_id: for 'details', the Qt objectName to inspect.
        params.name_contains: for 'find', substring of widget name.
        params.type_contains: for 'find', substring of widget class.
        params.text_contains: for 'find', substring of widget text.
        params.max_depth: for 'snapshot', max recursion depth (default 4).
        params.timeout_seconds: seconds to wait for window (default 15).

    Returns:
        str: human-readable summary + JSON tree / matches / details.
        Starts with 'Error: ' on bad input or missing pywinauto.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.action not in ("snapshot", "find", "details"):
        msg = f"Error: invalid action: {params.action} (must be snapshot/find/details)"
        return msg + _json_footer({"ok": False, "error": msg})
    available, err_msg = _widget_introspect_resolve_pywinauto()
    if not available:
        msg = f"Error: {err_msg}"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.process_id == 0 and not params.executable:
        msg = "Error: process_id=0 requires executable"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.action == "details" and not params.auto_id:
        msg = "Error: action='details' requires auto_id"
        return msg + _json_footer({"ok": False, "error": msg})

    proc = None
    launched = False
    try:
        from pywinauto import Application  # type: ignore

        if params.process_id:
            try:
                app = Application(backend="win32").connect(process=params.process_id, timeout=params.timeout_seconds)
            except Exception as e:
                msg = f"Error: failed to attach to process {params.process_id}: {e}"
                return msg + _json_footer({"ok": False, "error": msg})
        else:
            exe = Path(params.executable)
            sandbox_err = _require_sandbox(exe, "executable")
            if sandbox_err:
                return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
            if not exe.exists() or not exe.is_file():
                msg = f"Error: executable not found: {exe}"
                return msg + _json_footer({"ok": False, "error": msg})
            proc = await asyncio.create_subprocess_exec(
                str(exe),
                stdout=asyncio.subprocess.DEVNULL,
                stderr=asyncio.subprocess.DEVNULL,
                cwd=str(exe.parent),
            )
            launched = True
            try:
                app = Application(backend="win32").connect(process=proc.pid, timeout=params.timeout_seconds)
            except Exception as e:
                msg = f"Error: failed to attach to launched process {proc.pid}: {e}"
                return msg + _json_footer({"ok": False, "error": msg})

        try:
            if params.window_title:
                win = app.window(title_re=f".*{re.escape(params.window_title)}.*")
            else:
                win = app.window(process=app.process)
        except Exception as e:
            msg = f"Error: failed to locate window: {e}"
            return msg + _json_footer({"ok": False, "error": msg})

        if params.action == "snapshot":
            tree = _widget_introspect_walk(win, 0, params.max_depth)
            n_nodes = _widget_introspect_count_nodes(tree)
            payload = {"action": "snapshot", "process": app.process, "nodes": n_nodes, "tree": tree}
            return json.dumps(payload, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": {"process": app.process, "nodes": n_nodes}})
        if params.action == "find":
            matches: list = []
            _widget_introspect_find(win, params.name_contains, params.type_contains, params.text_contains, matches)
            payload = {"action": "find", "process": app.process, "count": len(matches), "matches": matches}
            return json.dumps(payload, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": {"count": len(matches)}})
        # details
        try:
            target = win.child_window(auto_id=params.auto_id)
            details = _widget_introspect_details(target)
            payload = {"action": "details", "process": app.process, "auto_id": params.auto_id, "details": details}
            return json.dumps(payload, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": details})
        except Exception as e:
            msg = f"Error: widget with auto_id='{params.auto_id}' not found: {e}"
            return msg + _json_footer({"ok": False, "error": msg})
    except Exception as e:
        msg = f"Error: {e}"
        return msg + _json_footer({"ok": False, "error": msg})
    finally:
        if launched and proc and proc.returncode is None:
            try:
                proc.terminate()
                await asyncio.wait_for(proc.wait(), timeout=3)
            except (asyncio.TimeoutError, ProcessLookupError):
                try:
                    proc.kill()
                except Exception:
                    pass


# === v0.3.3: qt_layout_check ================================================

# Rules for qt_layout_check. Each rule: id, severity, description.
# Detection happens at two levels:
#   - .ui file (XML parsed via ElementTree) — static analysis of the layout tree
#   - live widget tree via pywinauto (optional, with process_id)
# Severity: 'warning' (likely bug) or 'info' (style).
_LAYOUT_CHECK_RULES: list[dict] = [
    {"id": "layout_no_stretch", "severity": "info", "description": "QBoxLayout has stretch sum of 0 — all children keep their sizeHint; intentional if all children are fixed-size, but usually a missing policy."},
    {"id": "deep_nesting", "severity": "warning", "description": "Layout nested > 5 levels deep — reduces performance and confuses dynamic layouts."},
    {"id": "widget_no_layout_parent", "severity": "warning", "description": "Widget placed directly under a QWidget (not inside any QLayout) — likely an oversight."},
    {"id": "duplicated_object_name", "severity": "warning", "description": "Two widgets share the same objectName — UI Automation / findChild / qDebug lookup is ambiguous."},
    {"id": "fixed_size_in_expanding_layout", "severity": "info", "description": "Widget has fixed sizePolicy inside an Expanding parent layout — child will not grow/shrink with window resize."},
]


def _layout_check_no_stretch(layout_elem) -> bool:
    """Return True if a QBoxLayout has stretch sum of 0 (heuristic for missing policy)."""
    # We use <item><widget>...</widget></item> count as a proxy: if > 1 item and no <stretch>, warn.
    items = layout_elem.findall("item")
    if not items:
        return False
    stretches = layout_elem.findall("item/stretch")
    if stretches:
        return False
    # If only 1 child, stretch=0 is fine
    widget_children = sum(1 for it in items if it.find("widget") is not None)
    return widget_children >= 2


def _layout_check_nesting_depth(root, max_depth: int = 5) -> int:
    """Compute the deepest layout nesting under the root <widget>."""
    def _walk_depth(elem, depth: int) -> int:
        layouts = elem.findall("layout")
        if not layouts:
            return depth
        deepest = depth
        for lay in layouts:
            for child_widget in lay.findall("item/widget"):
                deepest = max(deepest, _walk_depth(child_widget, depth + 1))
        return deepest
    return _walk_depth(root, 0)


def _layout_check_widget_without_layout(root) -> int:
    """Count top-level <widget> children of a QWidget that are NOT inside a <layout>."""
    # A QWidget parent can have: <layout> OR direct <widget> children. Direct
    # <widget> children are warnings — they should be inside a layout.
    direct_widgets = [c for c in root if c.tag == "widget"]
    return len(direct_widgets)


def _layout_check_dupe_object_names(root) -> list[str]:
    """Find objectName values that appear more than once."""
    seen: dict[str, int] = {}
    for w in root.iter("widget"):
        on = w.get("name", "").strip()
        if on:
            seen[on] = seen.get(on, 0) + 1
    return [name for name, n in seen.items() if n > 1]


class QtLayoutCheckInput(BaseModel):
    source: str = Field(description="Absolute path to a .ui file OR a directory to scan recursively for .ui files.")
    output_format: str = Field(default="text", description="'text' (human-readable) or 'json' (machine-readable).")
    min_severity: str = Field(default="info", description="Lowest severity to report: 'info' < 'warning'.")


@mcp.tool(name="qt_layout_check", annotations={"title": "Static check of .ui files for layout anti-patterns (no stretch, deep nesting, duplicate objectName)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_layout_check(params: QtLayoutCheckInput) -> str:
    """Scan Qt ``.ui`` files for layout anti-patterns via ElementTree.

    Inspired by ``0xCarbon/qt-mcp``'s ``qt_layout_check`` (which runs at
    runtime). This tool runs **statically** on the .ui XML, so it works
    without launching the app. Rules detected (see ``_LAYOUT_CHECK_RULES``):

      - ``layout_no_stretch`` — QBoxLayout with >=2 widgets but no stretch
        hint. info-level: usually intentional for fixed-size windows, but
        often indicates a missing sizePolicy on a child.
      - ``deep_nesting`` — layout nested > 5 levels deep. warning.
      - ``widget_no_layout_parent`` — direct <widget> child of a <widget>
        with no enclosing <layout>. warning.
      - ``duplicated_object_name`` — two widgets share the same name.
        warning (breaks UI Automation / findChild).
      - ``fixed_size_in_expanding_layout`` — child has sizePolicy
        Fixed/Preferred while parent is Expanding. info.

    Args:
        params.source: absolute path to a .ui file or a directory to scan.
        params.output_format: 'text' or 'json'.
        params.min_severity: 'info' or 'warning'.

    Returns:
        str: per-file report grouped by rule id. Starts with 'Error: '
        on bad input.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.output_format not in ("text", "json"):
        msg = f"Error: invalid output_format: {params.output_format} (must be text or json)"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.min_severity not in ("info", "warning"):
        msg = f"Error: invalid min_severity: {params.min_severity}"
        return msg + _json_footer({"ok": False, "error": msg})
    src = Path(params.source)
    sandbox_err = _require_sandbox(src, "source")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not src.exists():
        msg = f"Error: source not found: {src}"
        return msg + _json_footer({"ok": False, "error": msg})

    sev_rank = {"info": 0, "warning": 1}
    min_rank = sev_rank[params.min_severity]

    # Collect .ui files
    if src.is_file():
        if src.suffix.lower() != ".ui":
            msg = f"Error: not a .ui file: {src}"
            return msg + _json_footer({"ok": False, "error": msg})
        ui_files = [src]
    else:
        ui_files = [p for p in src.rglob("*.ui") if p.is_file()]

    all_findings: list = []
    files_scanned = 0
    files_with_issues = 0
    _LAYOUT_SKIP_DIRS = (".git", "build-debug", "build-release", "node_modules")

    for ui in ui_files:
        if any(part in _LAYOUT_SKIP_DIRS for part in ui.parts):
            continue
        try:
            tree = ElementTree.parse(str(ui))
        except ElementTree.ParseError as e:
            all_findings.append({"file": str(ui), "rule": "xml_parse_error", "severity": "warning", "line": 0, "snippet": str(e), "description": "XML parse error"})
            continue
        root = tree.getroot()
        if root.tag != "ui":
            continue
        files_scanned += 1
        file_findings: list = []

        # Find the top-level widget
        top_widgets = root.findall("widget")
        for tw in top_widgets:
            # Rule: widget_no_layout_parent — direct <widget> children
            n = _layout_check_widget_without_layout(tw)
            if n > 0 and sev_rank["warning"] >= min_rank:
                file_findings.append({"rule": "widget_no_layout_parent", "severity": "warning", "line": 0, "snippet": f"{n} direct widget child(ren) of <widget name='{tw.get('name','')}'>"})

            # Rule: deep_nesting
            depth = _layout_check_nesting_depth(tw)
            if depth > 5 and sev_rank["warning"] >= min_rank:
                file_findings.append({"rule": "deep_nesting", "severity": "warning", "line": 0, "snippet": f"layout nesting depth = {depth} (> 5)"})

            # Rule: duplicated_object_name
            dupes = _layout_check_dupe_object_names(tw)
            for d in dupes:
                if sev_rank["warning"] >= min_rank:
                    file_findings.append({"rule": "duplicated_object_name", "severity": "warning", "line": 0, "snippet": f"objectName '{d}' appears multiple times"})

            # Rule: layout_no_stretch — QBoxLayout heuristic
            for lay in tw.iter("layout"):
                if _layout_check_no_stretch(lay) and sev_rank["info"] >= min_rank:
                    file_findings.append({"rule": "layout_no_stretch", "severity": "info", "line": 0, "snippet": f"layout with >=2 widgets but no <stretch>"})

        if file_findings:
            files_with_issues += 1
        all_findings.extend({"file": str(ui), **f} for f in file_findings)

    summary = {
        "files_scanned": files_scanned,
        "files_with_issues": files_with_issues,
        "total_findings": len(all_findings),
        "by_severity": {
            "info": sum(1 for f in all_findings if f["severity"] == "info"),
            "warning": sum(1 for f in all_findings if f["severity"] == "warning"),
        },
    }
    if params.output_format == "json":
        return json.dumps({"summary": summary, "findings": all_findings}, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": summary})

    lines = [
        "=== qt_layout_check ===",
        f"Files scanned: {summary['files_scanned']}",
        f"Files with issues: {summary['files_with_issues']}",
        f"Total findings: {summary['total_findings']}",
        f"  info:    {summary['by_severity']['info']}",
        f"  warning: {summary['by_severity']['warning']}",
    ]
    if all_findings:
        lines.append("\n--- Findings ---")
        by_file: dict = {}
        for f in all_findings:
            by_file.setdefault(f["file"], []).append(f)
        for fp, items in by_file.items():
            lines.append(f"\n  {fp}:")
            for it in items:
                lines.append(f"    [{it['severity']:>7}] {it['rule']}: {it['snippet']}")
    return "\n".join(lines) + _json_footer({"ok": True, "data": summary})


# === v0.3.3: qt_cppcheck ===================================================

# cppcheck's JSON schema (per `cppcheck --json` docs):
#   {"diagnostics": [{"file": "...", "line": N, "severity": "warning|error|style|performance|portability|information|debug",
#                     "id": "unusedFunction", "message": "..."}, ...],
#    "statistics": {"warning": N, "error": N, "style": N, ...}}
# We parse defensively (cppcheck sometimes omits "statistics").

_CPPCHECK_DEFAULT_ENABLES = "warning,style,performance,portability"
_CPPCHECK_KNOWN_SEVERITIES = ("error", "warning", "style", "performance", "portability", "information", "debug")


def _cppcheck_resolve_exe(explicit: str) -> str | None:
    """Resolve cppcheck binary (explicit -> env -> PATH). Returns path or None."""
    if explicit:
        p = Path(explicit)
        return str(p) if p.exists() else None
    env_path = os.environ.get("QT_CPPCHECK_EXE", "")
    if env_path and Path(env_path).exists():
        return env_path
    return shutil.which("cppcheck")


def _cppcheck_parse_json_objects(text: str) -> list[dict]:
    """Parse cppcheck --json output. cppcheck emits one JSON object per file
    on success; some versions emit a single object with a 'diagnostics' array.
    This parser tries both shapes and returns a flat list of findings."""
    findings: list[dict] = []
    # Strategy: find each top-level {...} object on its own line.
    decoder = json.JSONDecoder()
    idx = 0
    n = len(text)
    while idx < n:
        # Skip whitespace
        while idx < n and text[idx] in " \t\r\n,":
            idx += 1
        if idx >= n:
            break
        if text[idx] != "{":
            # Unknown token — skip one char
            idx += 1
            continue
        try:
            obj, end = decoder.raw_decode(text[idx:])
        except json.JSONDecodeError:
            idx += 1
            continue
        idx += end
        if isinstance(obj, dict):
            diags = obj.get("diagnostics") or []
            if isinstance(diags, list):
                findings.extend(d for d in diags if isinstance(d, dict))
            # Some versions also emit "statistics" — collect severity counts.
            stats = obj.get("statistics")
            if isinstance(stats, dict):
                # Stored as a special pseudo-finding so the caller can see totals
                findings.append({"_statistics": True, "counts": stats})
    return findings


class QtCppcheckInput(BaseModel):
    source_dir: str = Field(description="Absolute path to a directory (or single .cpp/.h file) to scan with cppcheck.")
    enable: str = Field(default=_CPPCHECK_DEFAULT_ENABLES, description="Comma-separated cppcheck --enable list. Default 'warning,style,performance,portability'.")
    library: str = Field(default="qt", description="cppcheck --library name. Default 'qt' (covers QObject/QString/QList). Pass '' to skip --library.")
    severity_filter: str = Field(default="", description="Optional comma-separated list of severities to include (e.g. 'error,warning'). Empty = report all.")
    output_format: str = Field(default="text", description="'text' (human-readable) or 'json' (machine-readable).")
    cppcheck_exe: str = Field(default="", description="Optional explicit path to cppcheck.exe. Empty = auto-resolve via QT_CPPCHECK_EXE env var or PATH.")
    timeout_seconds: int = Field(default=120, description="cppcheck subprocess timeout in seconds. Default 120 (large projects may need more).")


@mcp.tool(name="qt_cppcheck", annotations={"title": "Run cppcheck with --json + Qt library, parse output, aggregate per-severity counts", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_cppcheck(params: QtCppcheckInput) -> str:
    """Run cppcheck with JSON output and aggregate findings.

    The companion to ``qt_clazy_check`` (regex-only) and ``qt_lint`` (cpplint +
    qmllint + clang-tidy). Where those tools are zero-dependency,
    ``qt_cppcheck`` shells out to a real ``cppcheck`` binary for deeper
    analysis. CI-friendly: outputs aggregate counts by severity so a single
    line ``Total findings: 12`` can drive a build gate.

    Configuration:
      - ``source_dir`` — directory (recursive) or single file
      - ``enable`` — passes ``--enable=<list>`` (default: warning,style,
        performance,portability)
      - ``library`` — passes ``--library=<name>`` (default: ``qt``, which
        silences false positives on QObject / QString / QList). Pass empty
        string to skip.
      - ``severity_filter`` — keep only these severities (error, warning,
        style, performance, portability, information)
      - ``cppcheck_exe`` — explicit path; empty auto-resolves via
        ``QT_CPPCHECK_EXE`` env var or ``PATH``
      - ``timeout_seconds`` — kills the subprocess after N seconds (default 120)

    Args:
        params.source_dir: directory or .cpp/.h file to scan.
        params.enable: cppcheck --enable list.
        params.library: cppcheck --library (default 'qt'; '' to skip).
        params.severity_filter: optional severity filter (comma-sep).
        params.output_format: 'text' or 'json'.
        params.cppcheck_exe: explicit cppcheck path (empty = auto).
        params.timeout_seconds: subprocess timeout.

    Returns:
        str: aggregate report grouped by severity. Starts with 'Error: ' if
        cppcheck is not installed or input is invalid.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.output_format not in ("text", "json"):
        msg = f"Error: invalid output_format: {params.output_format} (must be text or json)"
        return msg + _json_footer({"ok": False, "error": msg})
    src = Path(params.source_dir)
    sandbox_err = _require_sandbox(src, "source_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not src.exists():
        msg = f"Error: source_dir not found: {src}"
        return msg + _json_footer({"ok": False, "error": msg})

    exe = _cppcheck_resolve_exe(params.cppcheck_exe)
    if exe is None:
        msg = "Error: cppcheck not found. Set QT_CPPCHECK_EXE env var or add cppcheck.exe to PATH. Install via MSYS2: pacman -S mingw-w64-x86_64-cppcheck, or choco install cppcheck."
        return msg + _json_footer({"ok": False, "error": msg})

    cmd = [exe, f"--enable={params.enable}", "--quiet", "--inline-suppr", "--json", "--std=c++14"]
    if params.library:
        cmd.append(f"--library={params.library}")
    cmd.append(str(src))

    try:
        proc = await asyncio.create_subprocess_exec(*cmd, stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE)
        try:
            stdout_b, stderr_b = await asyncio.wait_for(proc.communicate(), timeout=params.timeout_seconds)
        except asyncio.TimeoutError:
            proc.kill()
            try:
                await proc.wait()
            except Exception:
                pass
            msg = f"Error: cppcheck timed out after {params.timeout_seconds}s"
            return msg + _json_footer({"ok": False, "error": msg})
    except FileNotFoundError:
        msg = f"Error: cppcheck executable disappeared mid-run: {exe}"
        return msg + _json_footer({"ok": False, "error": msg})

    stdout = stdout_b.decode("utf-8", errors="replace") if stdout_b else ""
    stderr = stderr_b.decode("utf-8", errors="replace") if stderr_b else ""

    if not stdout.strip():
        # cppcheck may emit findings on stderr only in some error modes
        msg = f"Error: cppcheck produced no JSON output (exit {proc.returncode}). stderr: {stderr[:300]}"
        return msg + _json_footer({"ok": False, "error": msg, "stderr": stderr[:300]})

    raw = _cppcheck_parse_json_objects(stdout)
    severity_counts: dict[str, int] = {s: 0 for s in _CPPCHECK_KNOWN_SEVERITIES}
    findings: list[dict] = []
    for item in raw:
        if item.get("_statistics"):
            stats = item.get("counts", {})
            if isinstance(stats, dict):
                for k, v in stats.items():
                    if isinstance(v, int) and k in severity_counts:
                        severity_counts[k] += v
            continue
        sev = item.get("severity", "information")
        if sev not in severity_counts:
            sev = "information"
        severity_counts[sev] += 1
        findings.append({
            "file": item.get("file", ""),
            "line": int(item.get("line", 0) or 0),
            "severity": sev,
            "id": item.get("id", ""),
            "message": item.get("message", ""),
        })

    if params.severity_filter:
        keep = {s.strip() for s in params.severity_filter.split(",") if s.strip()}
        findings = [f for f in findings if f["severity"] in keep]

    summary = {
        "exit_code": proc.returncode,
        "total_findings": len(findings),
        "by_severity": {k: v for k, v in severity_counts.items() if v > 0},
        "files_scanned": len({f["file"] for f in findings if f["file"]}),
        "library": params.library or "(none)",
        "enable": params.enable,
    }

    if params.output_format == "json":
        return json.dumps({"summary": summary, "findings": findings[:500]}, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": summary})

    lines = [
        "=== qt_cppcheck ===",
        f"Source: {src}",
        f"cppcheck: {exe} (exit {proc.returncode})",
        f"--enable: {params.enable}",
        f"--library: {params.library or '(none)'}",
        f"Total findings: {summary['total_findings']}",
        f"  by severity: {summary['by_severity']}",
        f"  files with findings: {summary['files_scanned']}",
    ]
    if findings:
        lines.append("\n--- Findings (top 20 by severity) ---")
        sev_rank = {"error": 0, "warning": 1, "performance": 2, "portability": 3, "style": 4, "information": 5, "debug": 6}
        findings_sorted = sorted(findings, key=lambda x: (sev_rank.get(x["severity"], 9), x["file"], x["line"]))
        for f in findings_sorted[:20]:
            lines.append(f"  [{f['severity']:>11}] {f['file']}:{f['line']} [{f['id']}] {f['message'][:100]}")
        if len(findings_sorted) > 20:
            lines.append(f"  ... and {len(findings_sorted) - 20} more")
    return "\n".join(lines) + _json_footer({"ok": True, "data": summary})


# === v0.3.3: qt_thread_affinity_check =======================================

# Thread-affinity rules for Qt. These are *static* heuristics — they don't run
# the app. They catch the most common cross-thread signal bugs that
# qt_async_await_lint (also v0.3.x) does not: DirectConnection across threads,
# emit called from a non-QObject thread, missing QueuedConnection.
_AFFINITY_RULES: list[dict] = [
    {
        "id": "direct_connection_cross_thread",
        "severity": "warning",
        # connect(sender, SIGNAL(...), receiver, SLOT(...), Qt::DirectConnection)
        # where sender or receiver is the result of moveToThread(...).
        # Heuristic: flag any connect() with Qt::DirectConnection when the file
        # ALSO contains moveToThread(...).
        "pattern": r"connect\s*\([^;]*?Qt::DirectConnection",
        "requires": "movetothread",
        "description": "Qt::DirectConnection with moveToThread() in the same file — slots run on the emitter's thread, not the receiver's. Use Qt::QueuedConnection instead.",
    },
    {
        "id": "emit_without_queued_connection",
        "severity": "info",
        # emit() called from inside a non-slot context — flag if file contains
        # moveToThread AND a custom worker thread pattern (QThread::run override).
        "pattern": r"\bemit\s+\w+\s*\(",
        "requires": "movetothread",
        "description": "emit() in a file that uses moveToThread() — verify the emitting code runs on the correct thread, otherwise use Qt::QueuedConnection.",
    },
    {
        "id": "qthread_run_without_exec",
        "severity": "warning",
        # class X : public QThread { void run() override { /* no exec() */ } }
        # Heuristic: QThread subclass without exec() in run().
        "pattern": r"class\s+\w+\s*:\s*public\s+QThread\b",
        "requires": "no_exec",
        "description": "QThread subclass — verify run() override calls exec(). Without exec(), no event loop means signals/slots won't dispatch.",
    },
    {
        "id": "qobject_constructed_in_worker_thread",
        "severity": "info",
        # new QObject(...) inside QThread::run() override or QRunnable::run().
        "pattern": r"\bnew\s+QObject\s*\(",
        "requires": "qthread_run_or_qrunnable",
        "description": "new QObject() inside QThread::run() / QRunnable::run() — the object's thread() is the worker thread at construction. Call moveToThread() explicitly if you need signals dispatched on a different thread.",
    },
]


def _affinity_text_satisfies(text: str, condition: str) -> bool:
    """Return True if the text satisfies the rule's `requires` precondition.

    Used to suppress false positives: e.g. DirectConnection is only bad if
    the file uses moveToThread() at all.
    """
    if condition == "movetothread":
        return bool(re.search(r"\bmoveToThread\s*\(", text))
    if condition == "no_exec":
        # True if QThread subclass exists AND there's no exec() call in
        # non-comment code. Strip comments first so that `// no exec()` in
        # a comment doesn't satisfy the precondition.
        clean = _sst_strip_comments(text)
        if not re.search(r"class\s+\w+\s*:\s*public\s+QThread\b", clean):
            return False
        return not bool(re.search(r"\bexec\s*\(\s*\)", clean))
    if condition == "qthread_run_or_qrunnable":
        if not re.search(r"\bnew\s+QObject\s*\(", text):
            return False
        return bool(re.search(r"::run\s*\(\s*\)\s*(?:override)?\s*\{", text) and re.search(r"(?:QThread|QRunnable)", text))
    return True


class QtThreadAffinityCheckInput(BaseModel):
    source_files: list[str] = Field(description="Absolute paths to .cpp / .h files to scan for thread affinity issues.")
    output_format: str = Field(default="text", description="'text' (human-readable) or 'json' (machine-readable).")
    min_severity: str = Field(default="info", description="Lowest severity to report: 'info' < 'warning'.")


@mcp.tool(name="qt_thread_affinity_check", annotations={"title": "Static check of QObject signal/slot thread affinity (DirectConnection across threads, emit-without-queued, run() without exec)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_thread_affinity_check(params: QtThreadAffinityCheckInput) -> str:
    """Static check of QObject signal/slot thread affinity issues.

    Companion to ``qt_async_await_lint`` (v0.3.2, async-pattern regexes) and
    ``qt_signal_slot_trace`` (v0.2.7, connection graph). This tool focuses
    on **cross-thread signal/slot mistakes** that the others miss.

    Rules detected (see ``_AFFINITY_RULES``):
      - ``direct_connection_cross_thread`` — ``Qt::DirectConnection`` used in
        a file that also calls ``moveToThread()``. DirectConnection makes
        the slot run on the emitter's thread; if the receiver lives on a
        different thread, signals cross thread boundaries unsafely. Use
        ``Qt::QueuedConnection``. (warning)
      - ``emit_without_queued_connection`` — ``emit()`` in a file with
        ``moveToThread()``. Verify the emitter runs on the right thread.
        (info)
      - ``qthread_run_without_exec`` — ``class X : public QThread`` whose
        ``run()`` override does not call ``exec()``. Without ``exec()``,
        no event loop means no signal/slot dispatch. (warning)
      - ``qobject_constructed_in_worker_thread`` — ``new QObject(...)``
        inside ``QThread::run()`` / ``QRunnable::run()``. The object's
        ``thread()`` is the worker thread; call ``moveToThread()``
        explicitly if you need a different dispatch thread. (info)

    Each rule has a ``requires`` precondition — findings are suppressed when
    the precondition is absent (avoids flagging files that don't use
    threading at all).

    Args:
        params.source_files: absolute paths to .cpp / .h files.
        params.output_format: 'text' or 'json'.
        params.min_severity: 'info' or 'warning'.

    Returns:
        str: per-file report grouped by rule id. Starts with 'Error: ' on
        bad input.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if not params.source_files:
        msg = "Error: source_files is empty"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.output_format not in ("text", "json"):
        msg = f"Error: invalid output_format: {params.output_format} (must be text or json)"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.min_severity not in ("info", "warning"):
        msg = f"Error: invalid min_severity: {params.min_severity}"
        return msg + _json_footer({"ok": False, "error": msg})

    sev_rank = {"info": 0, "warning": 1}
    min_rank = sev_rank[params.min_severity]

    all_findings: list = []
    files_scanned = 0
    files_with_issues = 0

    for path_str in params.source_files:
        p = Path(path_str)
        sandbox_err = _require_sandbox(p, "source_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        if not p.exists() or not p.is_file():
            msg = f"Error: file not found: {p}"
            return msg + _json_footer({"ok": False, "error": msg})
        try:
            text = p.read_text(encoding="utf-8", errors="replace")
        except OSError as e:
            msg = f"Error: failed to read {p}: {e}"
            return msg + _json_footer({"ok": False, "error": msg})
        files_scanned += 1
        file_findings: list = []

        for rule in _AFFINITY_RULES:
            if sev_rank[rule["severity"]] < min_rank:
                continue
            requires = rule.get("requires", "")
            if requires and not _affinity_text_satisfies(text, requires):
                continue
            pat = re.compile(rule["pattern"], re.MULTILINE)
            for m in pat.finditer(text):
                line_no = text.count("\n", 0, m.start()) + 1
                file_findings.append({
                    "rule": rule["id"],
                    "severity": rule["severity"],
                    "line": line_no,
                    "snippet": m.group(0).strip()[:120],
                    "description": rule["description"],
                })

        if file_findings:
            files_with_issues += 1
        all_findings.extend({"file": str(p), **f} for f in file_findings)

    summary = {
        "files_scanned": files_scanned,
        "files_with_issues": files_with_issues,
        "total_findings": len(all_findings),
        "by_severity": {
            "info": sum(1 for f in all_findings if f["severity"] == "info"),
            "warning": sum(1 for f in all_findings if f["severity"] == "warning"),
        },
    }
    if params.output_format == "json":
        return json.dumps({"summary": summary, "findings": all_findings}, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": summary})

    lines = [
        "=== qt_thread_affinity_check ===",
        f"Files scanned: {summary['files_scanned']}",
        f"Files with issues: {summary['files_with_issues']}",
        f"Total findings: {summary['total_findings']}",
        f"  info:    {summary['by_severity']['info']}",
        f"  warning: {summary['by_severity']['warning']}",
    ]
    if all_findings:
        lines.append("\n--- Findings ---")
        by_file: dict = {}
        for f in all_findings:
            by_file.setdefault(f["file"], []).append(f)
        for fp, items in by_file.items():
            lines.append(f"\n  {fp}:")
            for it in items:
                lines.append(f"    [{it['severity']:>7}] {it['rule']}:{it['line']}  {it['snippet'][:80]}")
    return "\n".join(lines) + _json_footer({"ok": True, "data": summary})


# === v0.3.3: qt_sanitizer_run ===============================================

# Sanitizer flag map. Keys: sanitizer_type enum. Values: tuple of (compile_flag, link_flag, runtime_env_var).
# AddressSanitizer:  -fsanitize=address
# UndefinedBehaviorSanitizer: -fsanitize=undefined
# ThreadSanitizer:  -fsanitize=thread
# LeakSanitizer is bundled with AddressSanitizer (LSan runs at exit if --leak-check is on)
# Note: ASan + TSan cannot be combined (mutually exclusive at link time).
_SANITIZER_FLAG_MAP: dict[str, dict[str, str]] = {
    "address": {"flag": "-fsanitize=address", "env": "ASAN_OPTIONS", "note": "ASan + LSan. Detects buffer overflow, use-after-free, leaks at exit."},
    "undefined": {"flag": "-fsanitize=undefined", "env": "UBSAN_OPTIONS", "note": "UBSan. Detects signed-overflow, shift-out-of-range, invalid casts, alignment, etc."},
    "thread": {"flag": "-fsanitize=thread", "env": "TSAN_OPTIONS", "note": "TSan. Detects data races. Mutually exclusive with ASan."},
    "address,undefined": {"flag": "-fsanitize=address,undefined", "env": "ASAN_OPTIONS", "note": "ASan + UBSan (common combo)."},
}


class QtSanitizerRunInput(BaseModel):
    project_dir: str = Field(description="Absolute path to the Qt project directory (containing .pro file) to build with sanitizer flags.")
    sanitizer_type: str = Field(default="address", description="One of: 'address' (ASan+LSan), 'undefined' (UBSan), 'thread' (TSan), 'address,undefined' (ASan+UBSan combo).")
    build_type: str = Field(default="debug", description="'debug' (default) or 'release'. Debug is required for sane sanitizer diagnostics (line numbers).")
    run_seconds: int = Field(default=5, description="If > 0, run the built .exe detached for N seconds and capture sanitizer log output. 0 = build-only (don't run).")
    timeout_seconds: int = Field(default=300, description="Build timeout in seconds (qmake + mingw32-make). Default 300.")
    keep_sanitizer_build: bool = Field(default=False, description="If True, do NOT clean the sanitizer build artifacts after the run. Useful for debugging. Default False = always distclean.")


def _sanitizer_run_resolve_exe(proj_dir: Path) -> tuple[Path | None, str]:
    """Locate the built .exe inside the project_dir's sanitizer build tree.

    Convention: project_dir/sanitizer-<type>-<buildtype>/<projectname>.exe.
    """
    # Look for any directory named 'sanitizer-*' inside project_dir
    candidates = sorted(proj_dir.glob("sanitizer-*"))
    if not candidates:
        return None, "no sanitizer-* build directory found"
    build_root = candidates[-1]
    # Try debug/<name>.exe and release/<name>.exe
    for sub in ("debug", "release"):
        for exe in build_root.glob(f"{sub}/*.exe"):
            if exe.is_file():
                return exe, str(exe)
    return None, f"no .exe found under {build_root}"


@mcp.tool(name="qt_sanitizer_run", annotations={"title": "Build a Qt project with -fsanitize=address|undefined|thread, then run it briefly to capture sanitizer log", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_sanitizer_run(params: QtSanitizerRunInput) -> str:
    """Build a Qt project with a sanitizer flag, then run it briefly to
    capture sanitizer diagnostics.

    The companion to ``qt_smoke_test`` (smoke = does it run) and
    ``qt_perf_budget`` (perf = how fast does it run). This tool checks
    **does it crash on common memory / UB errors** by injecting
    ``-fsanitize=address`` (default), ``-fsanitize=undefined``,
    ``-fsanitize=thread``, or ``-fsanitize=address,undefined`` (common combo).

    Workflow:
      1. Detect the sanitizer flag from ``sanitizer_type``.
      2. Copy the project to ``<proj>/sanitizer-<type>-<buildtype>/``
         (preserves the original; sandbox-safe).
      3. Patch ``.pro`` to add ``QMAKE_CXXFLAGS += <flag>`` and
         ``QMAKE_LFLAGS += <flag>``.
      4. Run ``qmake`` + ``mingw32-make``.
      5. If ``run_seconds > 0``, spawn the .exe detached for N seconds
         (with sanitizer env vars like ``ASAN_OPTIONS=halt_on_error=1``),
         kill it, capture stdout+stderr.
      6. Parse the output for known sanitizer error markers
         (``==ERROR: AddressSanitizer``, ``runtime error:``, ``WARNING:
         ThreadSanitizer``, etc.). If found, return FAIL; else PASS.
      7. Always ``distclean`` the sanitizer build dir (unless
         ``keep_sanitizer_build=True``).

    Compatibility notes:
      - MinGW / GCC supports ``-fsanitize=address`` and ``-fsanitize=undefined``
        but ``-fsanitize=thread`` requires pthreads and may not link cleanly
        on Windows. ``-fsanitize=address,undefined`` works on both MinGW and
        MSVC (MSVC supports ASan since VS 2019 v16.9).
      - The build *must* be Debug for line numbers in sanitizer output.

    Args:
        params.project_dir: absolute path to Qt project (contains .pro).
        params.sanitizer_type: 'address' | 'undefined' | 'thread' | 'address,undefined'.
        params.build_type: 'debug' (default) or 'release'.
        params.run_seconds: if > 0, run the .exe briefly. 0 = build-only.
        params.timeout_seconds: build subprocess timeout (default 300).
        params.keep_sanitizer_build: if True, skip the distclean step.

    Returns:
        str: build ok/fail + sanitizer output (truncated) + summary.
        Starts with 'Error: ' on bad input. The summary line is
        ``PASS`` or ``FAIL`` based on whether sanitizer markers were found.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    proj = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj.is_dir():
        msg = f"Error: project_dir not a directory: {proj}"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.sanitizer_type not in _SANITIZER_FLAG_MAP:
        msg = f"Error: invalid sanitizer_type: {params.sanitizer_type}. Must be one of {list(_SANITIZER_FLAG_MAP)}"
        return msg + _json_footer({"ok": False, "error": msg})
    if params.build_type not in ("debug", "release"):
        msg = f"Error: invalid build_type: {params.build_type} (must be debug or release)"
        return msg + _json_footer({"ok": False, "error": msg})

    flag_info = _SANITIZER_FLAG_MAP[params.sanitizer_type]
    flag = flag_info["flag"]
    env_var = flag_info["env"]
    note = flag_info["note"]

    # Find .pro file
    pro_files = list(proj.glob("*.pro"))
    if not pro_files:
        msg = f"Error: no .pro file found in {proj}"
        return msg + _json_footer({"ok": False, "error": msg})
    if len(pro_files) > 1:
        # Use the first; emit a note in output
        pass
    pro_file = pro_files[0]

    # Sanitizer build directory
    san_dir_name = f"sanitizer-{params.sanitizer_type.replace(',', '-')}-{params.build_type}"
    san_dir = proj / san_dir_name
    try:
        san_dir.mkdir(exist_ok=True)
    except OSError as e:
        msg = f"Error: failed to create {san_dir}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Copy source files into sanitizer build dir (sandbox-safe)
    copied = 0
    for src in proj.iterdir():
        if src.name == san_dir_name or src.name in (".git", "build-debug", "build-release", "node_modules"):
            continue
        if src.name.startswith("sanitizer-"):
            continue
        dst = san_dir / src.name
        if src.is_file():
            try:
                shutil.copy2(str(src), str(dst))
                copied += 1
            except OSError:
                pass
        elif src.is_dir() and src.name not in (san_dir_name,):
            try:
                shutil.copytree(str(src), str(dst), dirs_exist_ok=True, ignore_errors=True)
            except OSError:
                pass

    san_pro = san_dir / pro_file.name
    if not san_pro.exists():
        msg = f"Error: failed to copy .pro to sanitizer build dir"
        return msg + _json_footer({"ok": False, "error": msg})

    # Patch .pro with sanitizer flag
    try:
        text = san_pro.read_text(encoding="utf-8", errors="replace")
        flag_line = f"\n# qt_sanitizer_run ({params.sanitizer_type}):\nQMAKE_CXXFLAGS += {flag}\nQMAKE_LFLAGS += {flag}\n"
        # Idempotent: skip if marker already present
        if f"# qt_sanitizer_run ({params.sanitizer_type}):" not in text:
            san_pro.write_text(text + flag_line, encoding="utf-8")
    except OSError as e:
        msg = f"Error: failed to patch {san_pro}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Build
    qmake_exe = QT_ROOT / "bin" / "qmake.exe"
    mingw_make = Path(os.environ.get("QT_MCP_MINGW_BIN", r"E:\Download_tools\QT\Tools\mingw730_64\bin")) / "mingw32-make.exe"
    if not qmake_exe.exists():
        msg = f"Error: qmake.exe not found at {qmake_exe}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not mingw_make.exists():
        msg = f"Error: mingw32-make.exe not found at {mingw_make}"
        return msg + _json_footer({"ok": False, "error": msg})

    build_log_parts: list[str] = []
    build_ok = False
    try:
        # qmake
        proc1 = await asyncio.create_subprocess_exec(
            str(qmake_exe), str(san_pro), "-spec", "win32-g++",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE,
            cwd=str(san_dir),
        )
        try:
            so, se = await asyncio.wait_for(proc1.communicate(), timeout=params.timeout_seconds // 3)
            build_log_parts.append(f"--- qmake ---\n{(so or b'').decode('utf-8','replace')}\n{(se or b'').decode('utf-8','replace')}")
        except asyncio.TimeoutError:
            proc1.kill()
            try:
                await proc1.wait()
            except Exception:
                pass
            build_log_parts.append("--- qmake timed out ---")
        # mingw32-make
        proc2 = await asyncio.create_subprocess_exec(
            str(mingw_make), "-j4",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE,
            cwd=str(san_dir),
        )
        try:
            so, se = await asyncio.wait_for(proc2.communicate(), timeout=2 * params.timeout_seconds // 3)
            build_ok = proc2.returncode == 0
            build_log_parts.append(f"--- mingw32-make (rc={proc2.returncode}) ---\n{(so or b'').decode('utf-8','replace')[:2000]}\n{(se or b'').decode('utf-8','replace')[:2000]}")
        except asyncio.TimeoutError:
            proc2.kill()
            try:
                await proc2.wait()
            except Exception:
                pass
            build_log_parts.append("--- mingw32-make timed out ---")
    except FileNotFoundError as e:
        msg = f"Error: failed to launch build tool: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    sanitizer_output = ""
    run_pass = True
    if build_ok and params.run_seconds > 0:
        exe, exe_err = _sanitizer_run_resolve_exe(san_dir)
        if exe is None:
            build_log_parts.append(f"--- run skipped: {exe_err} ---")
        else:
            env = os.environ.copy()
            env["QT_LOGGING_TO_CONSOLE"] = "0"
            # Enable halt-on-error so ASan/UBSan exits with non-zero on first error
            if params.sanitizer_type.startswith("address"):
                env[env_var] = "halt_on_error=1:abort_on_error=1"
            elif params.sanitizer_type.startswith("undefined"):
                env[env_var] = "halt_on_error=1:print_stacktrace=1"
            elif params.sanitizer_type.startswith("thread"):
                env[env_var] = "halt_on_error=1:second_deadlock_stack=1"
            proc3 = None
            try:
                proc3 = await asyncio.create_subprocess_exec(
                    str(exe),
                    stdout=asyncio.subprocess.PIPE,
                    stderr=asyncio.subprocess.PIPE,
                    cwd=str(exe.parent),
                    env=env,
                )
                try:
                    so, se = await asyncio.wait_for(proc3.communicate(), timeout=params.run_seconds)
                    sanitizer_output = (so or b"").decode("utf-8","replace") + "\n" + (se or b"").decode("utf-8","replace")
                except asyncio.TimeoutError:
                    proc3.kill()
                    try:
                        await proc3.wait()
                    except Exception:
                        pass
                    sanitizer_output = "(killed after timeout)"
            except Exception as e:
                build_log_parts.append(f"--- run failed: {e} ---")

    # Detect sanitizer error markers
    ERROR_MARKERS = (
        "==ERROR: AddressSanitizer",
        "==ERROR: LeakSanitizer",
        "runtime error:",
        "WARNING: ThreadSanitizer",
        "SUMMARY: AddressSanitizer",
        "SUMMARY: UndefinedBehaviorSanitizer",
    )
    combined = (sanitizer_output or "") + "\n" + "\n".join(build_log_parts)
    findings = [m for m in ERROR_MARKERS if m in combined]
    if findings:
        run_pass = False

    # Cleanup (unless keep_sanitizer_build)
    if not params.keep_sanitizer_build:
        try:
            # Best-effort: use mingw32-make distclean
            dc = await asyncio.create_subprocess_exec(
                str(mingw_make), "distclean",
                stdout=asyncio.subprocess.DEVNULL,
                stderr=asyncio.subprocess.DEVNULL,
                cwd=str(san_dir),
            )
            try:
                await asyncio.wait_for(dc.wait(), timeout=10)
            except asyncio.TimeoutError:
                dc.kill()
                try:
                    await dc.wait()
                except Exception:
                    pass
        except FileNotFoundError:
            pass
        # Finally remove the directory tree
        try:
            shutil.rmtree(str(san_dir), ignore_errors=True)
        except OSError:
            pass

    summary = {
        "sanitizer_type": params.sanitizer_type,
        "flag": flag,
        "build_ok": build_ok,
        "run_pass": run_pass,
        "build_dir": str(san_dir),
        "files_copied": copied,
        "error_markers_found": findings,
        "build_type": params.build_type,
        "kept": params.keep_sanitizer_build,
    }
    overall_pass = build_ok and run_pass

    lines = [
        "=== qt_sanitizer_run ===",
        f"Project: {proj}",
        f"Sanitizer: {params.sanitizer_type} ({flag})",
        f"Note: {note}",
        f"Build: {'OK' if build_ok else 'FAIL'}",
        f"Run: {'PASS' if run_pass else 'FAIL'}",
        f"Overall: {'PASS' if overall_pass else 'FAIL'}",
        f"Error markers found: {findings if findings else '(none)'}",
    ]
    if sanitizer_output:
        lines.append("\n--- Sanitizer output (first 800 chars) ---")
        lines.append(sanitizer_output[:800])
    if not params.keep_sanitizer_build:
        lines.append(f"\n(cleaned up: {san_dir})")
    else:
        lines.append(f"\n(kept build dir for debugging: {san_dir})")
    return "\n".join(lines) + _json_footer({"ok": overall_pass, "data": summary})


# === Tool: qt_perf_compare (v0.3.4) ==========================================
#
# Companion to qt_perf_budget (v0.3.2): measures a fresh startup against a
# previously-saved baseline JSON (qt_perf_budget output or prior qt_perf_compare
# output). Detects regressions: if first_cpu_ms or first_window_ms grew by more
# than regression_ms, report FAIL. CI gate for "did this release get slower?".

class QtPerfCompareInput(BaseModel):
    executable: str = Field(description="Absolute path to the .exe to measure.")
    baseline_json: str = Field(description="Absolute path to baseline JSON file (from qt_perf_budget or previous qt_perf_compare). Must contain 'first_cpu_ms' field.")
    regression_ms: int = Field(default=200, description="If (current_ms - baseline_ms) > this, report FAIL (default 200ms).")
    max_wait_ms: int = Field(default=10000, description="Hard upper bound on how long to wait for the window to appear (default 10000).")
    run_seconds: int = Field(default=0, description="If > 0, keep exe running this many seconds after measurement (default 0 = kill immediately).")


@mcp.tool(name="qt_perf_compare", annotations={"title": "Measure .exe startup latency against a baseline JSON; FAIL if regression > regression_ms", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_perf_compare(params: QtPerfCompareInput) -> str:
    """Compare a fresh startup measurement against a previously-saved baseline JSON.

    The companion to ``qt_perf_budget`` (v0.3.2): that tool checks "does it
    run FAST enough against a budget"; this tool checks "is it AS FAST as last
    time?". Useful as a CI gate to catch accidental startup-time regressions.

    Reuses the ``_perf_first_cpu_active`` (psutil) and ``_perf_find_window_for_pid``
    (pywinauto) helpers from ``qt_perf_budget``. The baseline JSON must be either
    a ``qt_perf_budget`` output (``{"first_cpu_ms": float, "first_window_ms": float,
    ...}``) or a previous ``qt_perf_compare`` output (same fields plus "deltas").

        Args:
            params.executable: absolute path to the .exe to time.
            params.baseline_json: absolute path to baseline JSON. Must contain
                ``first_cpu_ms`` (float or null).
            params.regression_ms: max allowed delta in ms (default 200).
            params.max_wait_ms: hard upper bound on first-window wait (default 10000).
            params.run_seconds: optional seconds to keep the exe running after
                measurement (0 = kill immediately).

        Returns:
            str: text report + JSON trailer. JSON trailer has ``result`` ("PASS"
            or "FAIL"), ``baseline``, ``current``, ``deltas``, ``regression_ms``.

        Raises:
            No exceptions; errors are returned as formatted strings.
    """
    err = _check_paths()
    if err:
        return f"Error: {err}" + _json_footer({"ok": False, "error": err})

    exe = Path(params.executable).resolve()
    sandbox_err = _require_sandbox(exe, "executable")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not exe.exists() or not exe.is_file():
        msg = f"Error: executable not found: {exe}"
        return msg + _json_footer({"ok": False, "error": msg})

    baseline_path = Path(params.baseline_json).resolve()
    sandbox_err2 = _require_sandbox(baseline_path, "baseline_json")
    if sandbox_err2:
        return sandbox_err2 + _json_footer({"ok": False, "error": sandbox_err2})
    if not baseline_path.is_file():
        msg = f"Error: baseline_json not found: {baseline_path}"
        return msg + _json_footer({"ok": False, "error": msg})

    if params.regression_ms < 0 or params.max_wait_ms <= 0:
        msg = "Error: regression_ms must be >= 0 and max_wait_ms must be > 0"
        return msg + _json_footer({"ok": False, "error": msg})

    # Parse baseline JSON
    import json as _json
    try:
        baseline_data = _json.loads(baseline_path.read_text(encoding="utf-8"))
    except (_json.JSONDecodeError, OSError) as e:
        msg = f"Error: failed to parse baseline_json: {e}"
        return msg + _json_footer({"ok": False, "error": msg})
    if "first_cpu_ms" not in baseline_data:
        msg = f"Error: baseline_json missing 'first_cpu_ms' field: {baseline_path}"
        return msg + _json_footer({"ok": False, "error": msg})
    baseline_cpu = baseline_data.get("first_cpu_ms")
    baseline_window = baseline_data.get("first_window_ms")

    # Spawn the .exe (mirror qt_perf_budget)
    cmd = [str(exe)]
    run_env = _qt_env()
    import time as _t
    import subprocess as _sp
    t0 = _t.monotonic()
    try:
        proc = _sp.Popen(cmd, cwd=str(exe.parent), env=run_env, stdin=_sp.DEVNULL, stdout=_sp.DEVNULL, stderr=_sp.DEVNULL, close_fds=True)
    except OSError as e:
        msg = f"Error: failed to spawn {exe}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})
    pid = proc.pid

    first_cpu_ms: float | None = None
    first_window_ms: float | None = None
    poll_interval = 0.05
    elapsed_ms = 0.0
    try:
        while elapsed_ms < params.max_wait_ms:
            await asyncio.sleep(poll_interval)
            elapsed_ms = (_t.monotonic() - t0) * 1000.0
            if first_cpu_ms is None:
                saw, _ = await asyncio.to_thread(_perf_first_cpu_active, pid)
                if saw:
                    first_cpu_ms = elapsed_ms
            if first_window_ms is None:
                found, _ = await asyncio.to_thread(_perf_find_window_for_pid, pid)
                if found:
                    first_window_ms = elapsed_ms
                    break
        # Optionally keep running for run_seconds
        if params.run_seconds > 0 and proc.poll() is None:
            await asyncio.sleep(params.run_seconds)
    finally:
        try:
            proc.kill()
            try:
                proc.wait(timeout=2)
            except _sp.TimeoutExpired:
                pass
        except Exception:
            pass

    def _delta(baseline_val: float | None, current_val: float | None) -> float | None:
        if baseline_val is None or current_val is None:
            return None
        return current_val - baseline_val

    cpu_delta = _delta(baseline_cpu, first_cpu_ms)
    window_delta = _delta(baseline_window, first_window_ms)

    # FAIL if any non-null delta exceeds threshold
    fail_reasons: list[str] = []
    if cpu_delta is not None and cpu_delta > params.regression_ms:
        fail_reasons.append(f"first_cpu regression: baseline={baseline_cpu:.0f}ms → current={first_cpu_ms:.0f}ms (+{cpu_delta:.0f}ms)")
    if window_delta is not None and window_delta > params.regression_ms:
        fail_reasons.append(f"first_window regression: baseline={baseline_window:.0f}ms → current={first_window_ms:.0f}ms (+{window_delta:.0f}ms)")
    pass_fail = "FAIL" if fail_reasons else "PASS"

    def _fmt_ms(v: float | None) -> str:
        return f"{v:.0f} ms" if v is not None else "(not detected)"

    lines = [
        "=== qt_perf_compare ===",
        f"Executable: {exe}",
        f"Baseline: {baseline_path}",
        f"Regression threshold: +{params.regression_ms} ms",
        f"Result: {pass_fail}",
        f"First CPU:        baseline={_fmt_ms(baseline_cpu)}, current={_fmt_ms(first_cpu_ms)}, delta={_fmt_ms(cpu_delta)}",
        f"First window:     baseline={_fmt_ms(baseline_window)}, current={_fmt_ms(first_window_ms)}, delta={_fmt_ms(window_delta)}",
    ]
    if fail_reasons:
        lines.append("Reasons:")
        lines += [f"  - {r}" for r in fail_reasons]
    lines.append(f"(Process killed after measurement; run_seconds={params.run_seconds})")

    return "\n".join(lines) + _json_footer({
        "ok": pass_fail == "PASS",
        "data": {
            "executable": str(exe),
            "baseline_json": str(baseline_path),
            "baseline": {"first_cpu_ms": baseline_cpu, "first_window_ms": baseline_window},
            "current": {"first_cpu_ms": first_cpu_ms, "first_window_ms": first_window_ms},
            "deltas": {"cpu_ms": cpu_delta, "window_ms": window_delta},
            "regression_ms": params.regression_ms,
            "result": pass_fail,
            "fail_reasons": fail_reasons,
        },
    })


# === Tool: qt_resource_validate (v0.3.4) ====================================
#
# Companion to qt_resources (v0.2.7). The existing qt_resources validate only
# checks "file exists on disk" + "duplicate entries". This tool goes deeper:
# naming convention, case-collision on case-insensitive FS, path-depth,
# file-size warnings, prefix-conflict detection, unusual-extension flagging.
# Designed as a CI gate to surface resource issues before runtime.

_RESOURCE_VALIDATE_RULES: list[dict] = [
    {"id": "naming_convention", "severity": "warning", "description": "Filename should be lowercase, no spaces, no special chars."},
    {"id": "case_collision",    "severity": "warning", "description": "Two file entries differ only in case — will collide on Windows / macOS."},
    {"id": "path_too_deep",     "severity": "warning", "description": "Resource path deeper than max_path_depth — Qt lookup may fail."},
    {"id": "file_too_large",    "severity": "info",    "description": "Referenced file exceeds max_file_size_kb — slow resource load."},
    {"id": "prefix_conflict",   "severity": "warning", "description": "Two <qresource> prefix blocks have overlapping sub-paths."},
    {"id": "duplicate_entry",   "severity": "warning", "description": "Same <file> appears more than once."},
    {"id": "missing_on_disk",   "severity": "error",   "description": "<file> path does not exist on disk."},
    {"id": "unusual_extension", "severity": "info",    "description": "File extension is unusual for Qt resources (e.g. .exe/.dll/.bat)."},
]

_RESOURCE_VALIDATE_NAMING_RE = re.compile(r"^[a-z0-9_\-/.]+$")
_RESOURCE_VALIDATE_UNUSUAL_EXT = {".exe", ".dll", ".so", ".bat", ".cmd", ".sh", ".ps1", ".msi"}


class QtResourceValidateInput(BaseModel):
    qrc_file: str = Field(description="Absolute path to the .qrc file to validate (must be inside sandbox).")
    max_path_depth: int = Field(default=8, description="Maximum allowed depth of resource path (default 8).")
    max_file_size_kb: int = Field(default=512, description="Warn if any referenced file exceeds this size in KB (default 512).")
    check_naming: bool = Field(default=True, description="Check file naming convention: lowercase, no spaces, no special chars.")
    check_case_collision: bool = Field(default=True, description="Detect case-collision (e.g. Icon.PNG vs icon.png on Windows FS).")
    check_prefix_conflict: bool = Field(default=True, description="Detect overlap between two <qresource> prefix blocks.")
    output_format: str = Field(default="text", description="Output format: 'text' (default) or 'json'.")


@mcp.tool(name="qt_resource_validate", annotations={"title": "Deep-validate a .qrc file: naming, case-collision, path depth, file size, prefix conflicts", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_resource_validate(params: QtResourceValidateInput) -> str:
    """Deep-validate a Qt resource (.qrc) file beyond what ``qt_resources validate`` checks.

    Runs 8 rule categories against every ``<file>`` entry:

    - ``naming_convention`` — filename should match ``^[a-z0-9_-/.]+$``
    - ``case_collision`` — duplicate ``<file>`` entries differing only in case
    - ``path_too_deep`` — path depth exceeds ``max_path_depth``
    - ``file_too_large`` — file size exceeds ``max_file_size_kb``
    - ``prefix_conflict`` — two ``<qresource>`` blocks have overlapping sub-paths
    - ``duplicate_entry`` — same ``<file>`` appears more than once
    - ``missing_on_disk`` — ``<file>`` path does not exist relative to .qrc parent
    - ``unusual_extension`` — extension is ``.exe / .dll / .so / .bat / .cmd / .sh / .ps1 / .msi``

    Designed as a CI gate: ``result`` in JSON trailer is ``PASS`` if no
    ``error``-severity findings, ``FAIL`` otherwise. Use the ``output_format``
    param to emit machine-readable JSON for CI consumption.

        Args:
            params.qrc_file: absolute path to the .qrc file (must be in sandbox).
            params.max_path_depth: max allowed path depth (default 8).
            params.max_file_size_kb: warn threshold for file size in KB (default 512).
            params.check_naming: enable naming-convention rule (default True).
            params.check_case_collision: enable case-collision rule (default True).
            params.check_prefix_conflict: enable prefix-conflict rule (default True).
            params.output_format: "text" (default) or "json".

        Returns:
            str: text report + JSON trailer. JSON has ``findings`` list,
            ``counts`` by severity, and ``result`` ("PASS" if no errors).

        Raises:
            No exceptions; errors are returned as formatted strings.
    """
    qrc = Path(params.qrc_file).resolve()
    sandbox_err = _require_sandbox(qrc, "qrc_file")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not qrc.is_file():
        msg = f"Error: qrc_file not found: {qrc}"
        return msg + _json_footer({"ok": False, "error": msg})

    root, blocks, perr = _qrc_parse(qrc)
    if perr:
        msg = f"Error: {qrc} is not a valid .qrc file ({perr})"
        return msg + _json_footer({"ok": False, "error": msg})
    qrc_parent = qrc.parent

    findings: list[dict] = []
    seen_files: set[str] = set()
    seen_lowercase: dict[str, str] = {}  # lowercase -> raw first-seen name
    total_files = sum(len(fs) for _, fs in blocks)

    def add_finding(rule_id: str, severity: str, file: str, message: str) -> None:
        findings.append({"rule_id": rule_id, "severity": severity, "file": file, "message": message})

    for prefix, files in blocks:
        for f in files:
            if not f:
                continue
            # duplicate_entry
            if f in seen_files:
                add_finding("duplicate_entry", "warning", f, f"duplicate <file> entry in prefix '{prefix}'")
            else:
                seen_files.add(f)
            # case_collision (only within same prefix to avoid cross-prefix false positives)
            if params.check_case_collision:
                lc = f.lower()
                if lc in seen_lowercase and seen_lowercase[lc] != f:
                    add_finding("case_collision", "warning", f, f"case-collision with '{seen_lowercase[lc]}' (both resolve to '{lc}')")
                else:
                    seen_lowercase[lc] = f
            # naming_convention
            if params.check_naming:
                # Take basename only — directories can have any case in path
                basename = f.rsplit("/", 1)[-1]
                if not _RESOURCE_VALIDATE_NAMING_RE.match(basename):
                    add_finding("naming_convention", "warning", f, f"filename '{basename}' violates naming convention (lowercase, no spaces, no special chars)")
            # path_too_deep
            depth = f.count("/")
            if depth > params.max_path_depth:
                add_finding("path_too_deep", "warning", f, f"path depth {depth} > max_path_depth {params.max_path_depth}")
            # file_too_large
            full = qrc_parent / f
            if full.is_file():
                try:
                    size_kb = full.stat().st_size / 1024.0
                    if size_kb > params.max_file_size_kb:
                        add_finding("file_too_large", "info", f, f"{f} is {size_kb:.0f} KB (> {params.max_file_size_kb} KB)")
                except OSError:
                    pass
                # unusual_extension
                ext = full.suffix.lower()
                if ext in _RESOURCE_VALIDATE_UNUSUAL_EXT:
                    add_finding("unusual_extension", "info", f, f"{f} has unusual extension '{ext}' for Qt resources")
            else:
                # missing_on_disk (always check — severity error)
                add_finding("missing_on_disk", "error", f, f"file does not exist on disk: {full}")

    # prefix_conflict (whole-block check)
    if params.check_prefix_conflict and len(blocks) > 1:
        # Two prefixes P1 and P2 conflict if one is a prefix of the other AND
        # both have at least one file — Qt resource lookup becomes ambiguous.
        for i, (p1, fs1) in enumerate(blocks):
            for j, (p2, fs2) in enumerate(blocks):
                if i >= j or not fs1 or not fs2:
                    continue
                p1n = p1.rstrip("/")
                p2n = p2.rstrip("/")
                if p1n and p2n and (p1n.startswith(p2n + "/") or p2n.startswith(p1n + "/")):
                    add_finding("prefix_conflict", "warning", f"{p1} vs {p2}", f"prefix '{p1}' and prefix '{p2}' overlap (one is parent of the other)")

    # Count by severity
    counts = {"warning": 0, "error": 0, "info": 0}
    for fi in findings:
        sev = fi.get("severity", "info")
        if sev in counts:
            counts[sev] += 1
    result = "PASS" if counts["error"] == 0 else "FAIL"

    if params.output_format == "json":
        import json as _json
        body = _json.dumps({"qrc_file": str(qrc), "findings": findings, "counts": counts, "result": result, "total_files": total_files}, ensure_ascii=False, indent=2)
        return body + "\n" + _json_footer({"ok": True, "data": {"qrc_file": str(qrc), "findings": findings, "counts": counts, "result": result, "total_files": total_files}})

    # text format
    lines = [
        "=== qt_resource_validate ===",
        f"File: {qrc}",
        f"Total <file> entries: {total_files}",
        f"Findings: {len(findings)} ({counts['error']} error(s), {counts['warning']} warning(s), {counts['info']} info)",
        f"Result: {result}",
    ]
    if findings:
        # Group by rule_id for readability
        by_rule: dict[str, list[dict]] = {}
        for fi in findings:
            by_rule.setdefault(fi["rule_id"], []).append(fi)
        lines.append("")
        for rule in _RESOURCE_VALIDATE_RULES:
            rid = rule["id"]
            if rid not in by_rule:
                continue
            lines.append(f"[{rule['severity']}] {rid} ({len(by_rule[rid])} finding(s)):")
            lines += [f"    - {fi['file']}: {fi['message']}" for fi in by_rule[rid][:20]]
            if len(by_rule[rid]) > 20:
                lines.append(f"    ... and {len(by_rule[rid]) - 20} more")

    return "\n".join(lines) + _json_footer({
        "ok": True,
        "data": {
            "qrc_file": str(qrc),
            "findings": findings,
            "counts": counts,
            "result": result,
            "total_files": total_files,
        },
    })


# === Tool: qt_test_coverage_diff (v0.3.4) ====================================
#
# Companion to qt_coverage (v0.2.3): that tool generates a single lcov .info
# file from a build; this tool compares TWO .info files (baseline vs current)
# to detect coverage regressions. CI gate: FAIL if any per-file coverage drops
# by more than regression_threshold, OR if the overall coverage drops.

_LCOV_SF_RE = re.compile(r"^SF:(.+)$")
_LCOV_LF_RE = re.compile(r"^LF:(\d+)$")
_LCOV_LH_RE = re.compile(r"^LH:(\d+)$")


def _lcov_parse(path: Path) -> dict[str, tuple[int, int]]:
    """Parse an lcov .info file and return {filename: (LF, LH)}.

    LCOV format: blocks of records beginning with `SF:<filename>` and ending
    with `end_of_record`. Within a block, `LF:<n>` is lines found and `LH:<n>`
    is lines hit. This parser is regex-based and tolerates Windows CRLF and
    BOM-prefixed files.
    """
    try:
        text = path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return {}
    out: dict[str, tuple[int, int]] = {}
    sf: Optional[str] = None
    lf: Optional[int] = None
    for line in text.splitlines():
        line = line.strip()
        m = _LCOV_SF_RE.match(line)
        if m:
            sf = m.group(1).strip()
            lf = None
            continue
        m = _LCOV_LF_RE.match(line)
        if m and sf is not None:
            lf = int(m.group(1))
            continue
        m = _LCOV_LH_RE.match(line)
        if m and sf is not None and lf is not None:
            lh = int(m.group(1))
            out[sf] = (lf, lh)
            sf = None
            lf = None
    return out


class QtTestCoverageDiffInput(BaseModel):
    baseline_info: str = Field(description="Absolute path to baseline lcov .info file (from previous qt_coverage run).")
    current_info: str = Field(description="Absolute path to current lcov .info file (from qt_coverage run just now).")
    regression_threshold: float = Field(default=0.02, description="Coverage drop > this fraction triggers FAIL (default 0.02 = 2 percentage points).")
    source_filter: str = Field(default="", description="Only include files matching this substring (e.g. 'src/'). Empty = include all.")
    output_format: str = Field(default="text", description="Output format: 'text' (default) or 'json'.")


@mcp.tool(name="qt_test_coverage_diff", annotations={"title": "Compare two lcov .info files to detect coverage regressions", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_test_coverage_diff(params: QtTestCoverageDiffInput) -> str:
    """Compare two lcov .info files to detect coverage regressions.

    The companion to ``qt_coverage`` (v0.2.3): that tool generates a single
    ``coverage.info`` file from a Qt project's gcov run; this tool compares
    two such files (baseline vs current) and reports per-file and overall
    coverage deltas. Useful as a CI gate to prevent coverage regressions:

    - Per-file regression: a single file's coverage drops by more than
      ``regression_threshold`` (default 2 percentage points).
    - Overall regression: aggregate coverage drops by more than threshold.

    If either condition is true, ``result`` is ``FAIL``; otherwise ``PASS``.

        Args:
            params.baseline_info: absolute path to baseline .info file.
            params.current_info: absolute path to current .info file.
            params.regression_threshold: max allowed drop fraction (default 0.02).
            params.source_filter: substring filter on source filenames (e.g. 'src/').
            params.output_format: "text" (default) or "json".

        Returns:
            str: text report + JSON trailer. JSON has ``baseline_cov``,
            ``current_cov``, ``overall_delta``, ``regressions``,
            ``improvements``, and ``result`` ("PASS"/"FAIL").

        Raises:
            No exceptions; errors are returned as formatted strings.
    """
    baseline_path = Path(params.baseline_info).resolve()
    current_path = Path(params.current_info).resolve()
    for label, p in (("baseline_info", baseline_path), ("current_info", current_path)):
        sandbox_err = _require_sandbox(p, label)
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
        if not p.is_file():
            msg = f"Error: {label} not found: {p}"
            return msg + _json_footer({"ok": False, "error": msg})

    if params.regression_threshold < 0:
        msg = "Error: regression_threshold must be >= 0"
        return msg + _json_footer({"ok": False, "error": msg})

    baseline = _lcov_parse(baseline_path)
    current = _lcov_parse(current_path)
    if not baseline:
        msg = f"Error: baseline_info has no SF/LF/LH records (empty or invalid): {baseline_path}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not current:
        msg = f"Error: current_info has no SF/LF/LH records (empty or invalid): {current_path}"
        return msg + _json_footer({"ok": False, "error": msg})

    # Apply source_filter
    if params.source_filter:
        sf = params.source_filter
        baseline = {k: v for k, v in baseline.items() if sf in k}
        current = {k: v for k, v in current.items() if sf in k}

    def _aggregate(d: dict[str, tuple[int, int]]) -> tuple[int, int]:
        total_lf = sum(lf for lf, _ in d.values())
        total_lh = sum(lh for _, lh in d.values())
        return (total_lf, total_lh)

    base_lf, base_lh = _aggregate(baseline)
    curr_lf, curr_lh = _aggregate(current)
    base_cov = base_lh / base_lf if base_lf else 1.0
    curr_cov = curr_lh / curr_lf if curr_lf else 1.0
    overall_delta = curr_cov - base_cov

    # Per-file deltas
    all_files = sorted(set(baseline.keys()) | set(current.keys()))
    per_file: list[dict] = []
    for f in all_files:
        b = baseline.get(f)
        c = current.get(f)
        b_lf, b_lh = (b if b else (0, 0))
        c_lf, c_lh = (c if c else (0, 0))
        b_cov = b_lh / b_lf if b_lf else 1.0
        c_cov = c_lh / c_lf if c_lf else 1.0
        delta = c_cov - b_cov
        per_file.append({
            "file": f,
            "baseline_cov": round(b_cov, 4),
            "current_cov": round(c_cov, 4),
            "delta": round(delta, 4),
            "baseline_lf_lh": (b_lf, b_lh),
            "current_lf_lh": (c_lf, c_lh),
        })

    regressions = [x for x in per_file if x["delta"] < -params.regression_threshold]
    improvements = [x for x in per_file if x["delta"] > params.regression_threshold]

    result = "PASS"
    fail_reasons: list[str] = []
    if regressions:
        result = "FAIL"
        fail_reasons.append(f"{len(regressions)} file(s) regressed by > {params.regression_threshold:.2%}")
    if overall_delta < -params.regression_threshold:
        result = "FAIL"
        fail_reasons.append(f"overall coverage dropped by {-overall_delta:.2%} (>{params.regression_threshold:.2%})")

    if params.output_format == "json":
        import json as _json
        body = _json.dumps({
            "baseline_cov": round(base_cov, 4),
            "current_cov": round(curr_cov, 4),
            "overall_delta": round(overall_delta, 4),
            "regressions": regressions,
            "improvements": improvements,
            "result": result,
            "fail_reasons": fail_reasons,
            "file_count": len(all_files),
        }, ensure_ascii=False, indent=2)
        return body + "\n" + _json_footer({
            "ok": result == "PASS",
            "data": {
                "baseline_cov": round(base_cov, 4),
                "current_cov": round(curr_cov, 4),
                "overall_delta": round(overall_delta, 4),
                "regressions": regressions,
                "improvements": improvements,
                "result": result,
                "fail_reasons": fail_reasons,
                "file_count": len(all_files),
            },
        })

    def _pct(x: float) -> str:
        return f"{x * 100:.1f}%"

    lines = [
        "=== qt_test_coverage_diff ===",
        f"Baseline: {baseline_path} ({len(baseline)} file(s), aggregate {_pct(base_cov)})",
        f"Current:  {current_path} ({len(current)} file(s), aggregate {_pct(curr_cov)})",
        f"Overall delta: {overall_delta:+.2%}",
        f"Threshold: {params.regression_threshold:.2%}",
        f"Regressions: {len(regressions)}    Improvements: {len(improvements)}",
        f"Result: {result}",
    ]
    if fail_reasons:
        lines.append("Fail reasons:")
        lines += [f"  - {r}" for r in fail_reasons]
    if regressions:
        lines.append("")
        lines.append("Worst regressions:")
        sorted_reg = sorted(regressions, key=lambda x: x["delta"])[:10]
        lines += [f"  {x['file']}: {_pct(x['baseline_cov'])} → {_pct(x['current_cov'])} ({x['delta']:+.2%})" for x in sorted_reg]
    if improvements:
        lines.append("")
        lines.append("Top improvements:")
        sorted_imp = sorted(improvements, key=lambda x: -x["delta"])[:5]
        lines += [f"  {x['file']}: {_pct(x['baseline_cov'])} → {_pct(x['current_cov'])} ({x['delta']:+.2%})" for x in sorted_imp]

    return "\n".join(lines) + _json_footer({
        "ok": result == "PASS",
        "data": {
            "baseline_cov": round(base_cov, 4),
            "current_cov": round(curr_cov, 4),
            "overall_delta": round(overall_delta, 4),
            "regressions": regressions,
            "improvements": improvements,
            "result": result,
            "fail_reasons": fail_reasons,
            "file_count": len(all_files),
        },
    })


# === Tool: qt_screenshot_baseline_capture (v0.3.4) ===========================
#
# Companion to qt_screenshot_diff (v0.2.7): that tool compares two PNGs; this
# tool CAPTURES the baseline PNG(s) automatically across multiple DPI scale
# factors. CI workflow: capture baseline (release tag) → change code → diff
# current vs baseline. Without this tool, users must manually launch the app
# at each scale and screenshot it.

import datetime as _dt


def _screenshot_capture_one(executable: Path, scale: float, wait_seconds: int, out_png: Path) -> tuple[bool, str]:
    """Capture a single screenshot of `executable` at QT_SCALE_FACTOR=scale.
    Returns (ok, info_or_error). Always kills the spawned process before returning.
    """
    import subprocess as _sp
    env = os.environ.copy()
    env["QT_SCALE_FACTOR"] = str(scale)
    # Ensure Qt bin dir is on PATH so exe finds Qt DLLs
    qt_bin_dir = _qt_env().get("PATH", "")
    if qt_bin_dir:
        env["PATH"] = qt_bin_dir + ";" + env.get("PATH", "")
    try:
        proc = _sp.Popen(
            [str(executable)],
            env=env,
            cwd=str(executable.parent),
            stdout=_sp.DEVNULL,
            stderr=_sp.DEVNULL,
            close_fds=True,
        )
    except OSError as e:
        return (False, f"spawn failed: {e}")
    pid = proc.pid
    try:
        import time as _t
        _t.sleep(wait_seconds)
        # Check process still alive
        if proc.poll() is not None:
            return (False, f"process exited with code {proc.returncode} before screenshot")
        try:
            from pywinauto import Application  # type: ignore
        except ImportError:
            return (False, "pywinauto not installed (pip install pywinauto)")
        try:
            app = Application(backend="win32").connect(process=pid, timeout=5)
            win = app.window(process=pid)
            img = win.capture_as_image()
            img.save(str(out_png))
        except Exception as e:
            return (False, f"pywinauto capture failed: {e}")
        if not out_png.exists() or out_png.stat().st_size == 0:
            return (False, f"screenshot file empty or missing: {out_png}")
        return (True, f"size={img.size[0]}x{img.size[1]}")
    finally:
        try:
            proc.kill()
            try:
                proc.wait(timeout=2)
            except _sp.TimeoutExpired:
                pass
        except Exception:
            pass


class QtScreenshotBaselineCaptureInput(BaseModel):
    executable: str = Field(description="Absolute path to the .exe to screenshot.")
    scale_factors: list[float] = Field(default_factory=lambda: [1.0, 1.5, 2.0], description="QT_SCALE_FACTOR values to test (e.g. [1.0, 1.5, 2.0]).")
    output_dir: str = Field(default="", description="Absolute directory to save screenshots (must be inside sandbox). Default: <SANDBOX_TMP>/baselines/<exe_name>_<timestamp>/.")
    wait_seconds: int = Field(default=3, description="Seconds to wait after launching before screenshotting (lets the UI paint).")
    label: str = Field(default="", description="Optional label stored in manifest JSON for traceability (e.g. 'v0_release_candidate').")


@mcp.tool(name="qt_screenshot_baseline_capture", annotations={"title": "Capture baseline PNG screenshots across multiple QT_SCALE_FACTOR values", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False})
async def qt_screenshot_baseline_capture(params: QtScreenshotBaselineCaptureInput) -> str:
    """Capture baseline PNG screenshots of a Qt app at multiple DPI scale factors.

    The companion to ``qt_screenshot_diff`` (v0.2.7): that tool compares two
    PNGs; this tool CAPTURES the baseline PNG(s) automatically. Typical
    workflow in a release pipeline:

    1. Tag the release → run ``qt_screenshot_baseline_capture`` (label="v0.5.0")
       → commit manifest.json + PNGs to ``baselines/v0.5.0/``.
    2. Next change → run the app, capture current → ``qt_screenshot_diff``
       (baseline_png vs current_png). CI fails on visual regression.

    Each spawned exe is killed before moving to the next scale factor.

        Args:
            params.executable: absolute path to the .exe to screenshot.
            params.scale_factors: list of QT_SCALE_FACTOR values (default [1.0, 1.5, 2.0]).
            params.output_dir: directory to save PNGs (must be in sandbox).
                Default: ``<SANDBOX_TMP>/baselines/<exe_name>_<timestamp>/``.
            params.wait_seconds: seconds to wait before screenshot (default 3).
            params.label: optional human-readable label stored in manifest.

        Returns:
            str: text report + JSON trailer. JSON has ``manifest_path``,
            ``captures`` list (per scale: png path + sha1 + size).

        Raises:
            No exceptions; errors are returned as formatted strings.
    """
    exe = Path(params.executable).resolve()
    sandbox_err = _require_sandbox(exe, "executable")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not exe.exists() or not exe.is_file():
        msg = f"Error: executable not found: {exe}"
        return msg + _json_footer({"ok": False, "error": msg})

    if not params.scale_factors:
        msg = "Error: scale_factors must be non-empty"
        return msg + _json_footer({"ok": False, "error": msg})
    for sf in params.scale_factors:
        if sf <= 0:
            msg = f"Error: scale_factors must be positive (got {sf})"
            return msg + _json_footer({"ok": False, "error": msg})

    # Resolve output_dir
    if params.output_dir:
        out_dir = Path(params.output_dir).resolve()
    else:
        ts = _dt.datetime.now().strftime("%Y%m%d_%H%M%S")
        out_dir = (SANDBOX_TMP / "baselines" / f"{exe.stem}_{ts}").resolve()
    sandbox_err2 = _require_sandbox(out_dir, "output_dir")
    if sandbox_err2:
        return sandbox_err2 + _json_footer({"ok": False, "error": sandbox_err2})
    try:
        out_dir.mkdir(parents=True, exist_ok=True)
    except OSError as e:
        msg = f"Error: cannot create output_dir {out_dir}: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    import hashlib as _hl
    captures: list[dict] = []
    failures: list[str] = []
    for scale in params.scale_factors:
        scale_str = f"{scale}".replace(".", "_")
        png_path = out_dir / f"baseline_{scale_str}x.png"
        # Run capture in thread to avoid blocking the event loop
        ok, info = await asyncio.to_thread(_screenshot_capture_one, exe, scale, params.wait_seconds, png_path)
        if ok:
            sha1 = _hl.sha1(png_path.read_bytes()).hexdigest()[:12]
            captures.append({"scale": scale, "png": str(png_path), "sha1": sha1, "info": info, "ok": True})
        else:
            captures.append({"scale": scale, "png": str(png_path), "info": info, "ok": False})
            failures.append(f"{scale}x: {info}")

    # Write manifest JSON
    manifest = {
        "label": params.label,
        "executable": str(exe),
        "captured_at": _dt.datetime.now().isoformat(timespec="seconds"),
        "scale_factors": captures,
    }
    manifest_path = out_dir / "manifest.json"
    try:
        manifest_path.write_text(_json.dumps(manifest, ensure_ascii=False, indent=2), encoding="utf-8")
    except OSError as e:
        msg = f"Error: cannot write manifest.json: {e}"
        return msg + _json_footer({"ok": False, "error": msg})

    captured_count = sum(1 for c in captures if c["ok"])
    lines = [
        "=== qt_screenshot_baseline_capture ===",
        f"Executable: {exe}",
        f"Output: {out_dir}",
        f"Label: {params.label or '(none)'}",
        f"Captured {captured_count}/{len(params.scale_factors)} scale factor(s):",
    ]
    for c in captures:
        if c["ok"]:
            lines.append(f"  {c['scale']}x → {Path(c['png']).name} (sha1={c['sha1']}, {c['info']})")
        else:
            lines.append(f"  {c['scale']}x → FAILED ({c['info']})")
    if failures:
        lines.append("Failures:")
        lines += [f"  - {f}" for f in failures]
    lines.append(f"Manifest: {manifest_path}")

    return "\n".join(lines) + _json_footer({
        "ok": captured_count == len(params.scale_factors),
        "data": {
            "executable": str(exe),
            "output_dir": str(out_dir),
            "manifest_path": str(manifest_path),
            "captures": captures,
            "captured_count": captured_count,
            "total_requested": len(params.scale_factors),
            "failures": failures,
        },
    })


# === Tool: qt_console_messages (v0.3.4) ======================================
#
# Companion to qt_log (v0.2.2, analyzes written log files) and qt_run_trace
# (v0.2.0, sets QT_LOGGING_TO_CONSOLE=1 at spawn). This tool attaches to an
# ALREADY-RUNNING Qt process (or spawns one) and reads console-like text
# widgets (QPlainTextEdit / QTextEdit / QLabel / QStatusBar) via pywinauto
# + UI Automation. Inspired by 0xCarbon/qt-mcp's qt_messages concept.

_CONSOLE_TEXT_WIDGET_CLASSES = ("QPlainTextEdit", "QTextEdit", "QLabel", "QStatusBar")


def _console_scan_text_widgets(window, auto_id_contains: str = "") -> list[str]:
    """Walk `window`'s descendant tree, return text from console-like widgets."""
    msgs: list[str] = []
    seen: set[int] = set()
    for child in window.descendants():
        try:
            handle_id = id(child)
            if handle_id in seen:
                continue
            seen.add(handle_id)
            cls = child.friendly_class_name()
            if cls not in _CONSOLE_TEXT_WIDGET_CLASSES:
                continue
            if auto_id_contains:
                try:
                    auto_id = child.automation_id()
                except Exception:
                    auto_id = ""
                if auto_id_contains not in auto_id:
                    continue
            # Prefer window_text(); fall back to legacy_properties().get('Text', '')
            text = ""
            try:
                text = child.window_text()
            except Exception:
                pass
            if not text:
                try:
                    props = child.legacy_properties() if hasattr(child, "legacy_properties") else {}
                    text = props.get("Text", "") or props.get("text", "")
                except Exception:
                    pass
            if text:
                for line in text.splitlines():
                    if line.strip():
                        msgs.append(line)
        except Exception:
            continue
    return msgs


class QtConsoleMessagesInput(BaseModel):
    process_id: int = Field(default=0, description="PID of a running Qt app to attach to. If 0, executable is launched and killed after capture.")
    executable: str = Field(default="", description="Absolute path of .exe to launch (only used when process_id=0).")
    level_filter: str = Field(default="debug|warning|critical|fatal", description="Regex filter applied to message text. Use 'warning|critical' to filter out debug spam. Empty = no filter.")
    max_messages: int = Field(default=500, description="Maximum number of messages to return (default 500).")
    wait_seconds: int = Field(default=3, description="Seconds to wait after launch before capture (only when process_id=0).")
    auto_id_contains: str = Field(default="", description="Optional: only scan widgets whose objectName (UI Automation Id) contains this substring (e.g. 'log').")


