class QtComplexityLintInput(BaseModel):
    project_dir: str = Field(description="Absolute path to a Qt project root containing C++ source to lint.")
    threshold: int = Field(default=12, description="Cyclomatic complexity threshold above which a function is flagged (default 12, rule of thumb 10±2).")
    output_format: str = Field(default="text", description="'text' (human) or 'json' (machine-readable).")
    exclude_dirs: list[str] = Field(default_factory=lambda: ["debug", "release", "build-debug", "build-release", ".git", "node_modules"], description="Directory name patterns to exclude from linting.")


