# === qt_multimedia_setup: QMediaPlayer + QSoundEffect starter (JB51 Ch 49) ===

def _mm_main_cpp() -> str:
    return r"""#include <QApplication>
#include <QMediaPlayer>
#include <QMediaPlaylist>
#include <QVideoWidget>
#include <QSoundEffect>
#include <QUrl>
#include <QFileDialog>
#include <QPushButton>
#include <QVBoxLayout>
#include <QWidget>
#include <QDebug>

int main(int argc, char *argv[]) {
    QApplication app(argc, argv);

    auto *window = new QWidget;
    window->setWindowTitle("Multimedia Demo - JB51 Ch 49");
    window->resize(640, 480);

    auto *videoWidget = new QVideoWidget;
    auto *player = new QMediaPlayer;
    auto *playlist = new QMediaPlaylist(player);
    player->setVideoOutput(videoWidget);
    player->setPlaylist(playlist);

    auto *playBtn = new QPushButton("Add Media & Play");
    QObject::connect(playBtn, &QPushButton::clicked, [&]() {
        QStringList files = QFileDialog::getOpenFileNames(window, "Select Media Files",
            "", "Media (*.mp3 *.wav *.mp4 *.avi);;All Files (*)");
        for (const QString& f : files) {
            playlist->addMedia(QUrl::fromLocalFile(f));
        }
        if (playlist->mediaCount() > 0 && player->state() != QMediaPlayer::PlayingState) {
            playlist->setCurrentIndex(0);
            player->play();
        }
    });

    auto *effect = new QSoundEffect;
    effect->setSource(QUrl::fromLocalFile(":/sounds/click.wav"));  // bundled via .qrc
    effect->setVolume(0.5f);

    auto *effectBtn = new QPushButton("Play Sound Effect");
    QObject::connect(effectBtn, &QPushButton::clicked, [effect]() {
        effect->play();
    });

    auto *layout = new QVBoxLayout(window);
    layout->addWidget(videoWidget);
    layout->addWidget(playBtn);
    layout->addWidget(effectBtn);
    window->show();

    return app.exec();
}
"""


def _mm_pro() -> str:
    return """QT       += core gui widgets multimedia
CONFIG   += c++17
TARGET   = mediademo
TEMPLATE = app
SOURCES += main.cpp
RESOURCES += sounds.qrc
"""


def _mm_qrc() -> str:
    return """<RCC>
    <qresource prefix="/">
        <file>sounds/click.wav</file>
    </qresource>
</RCC>
"""


def _mm_setup_md() -> str:
    return """# Qt 5.14.2 + QtMultimedia Setup

QtMultimedia is built on top of platform backends. On Windows + MinGW 7.3, Qt 5.14.2
ships prebuilt plugins for:

  - DirectShow (default backend) — supports most .mp4 / .mp3 / .wav files
  - Windows Media Foundation (mfPlat) — newer, requires Win 7+; better codec support

## Backend notes

The QMediaPlayer class uses DirectShow by default on Windows. If you find a file
format that doesn't play, install the right codec (e.g. K-Lite Codec Pack) and
it will work transparently.

## Audio

- QSoundEffect — for short sound effects (WAV files < 1MB recommended)
- QMediaPlayer + QAudioOutput — for longer audio (mp3, ogg, flac)
- The audio backend on Windows is WinMM / WASAPI depending on Qt build

## Video

- QMediaPlayer + QVideoWidget — basic video display
- QGraphicsVideoItem — for placing video in QGraphicsView scenes (good for board game demos)

## Common issues

- "Service not found" — codec not installed. Try a different sample file.
- "MediaPlayer error: format error" — file corrupt or unsupported codec. Re-encode.
- "QSoundEffect only plays once" — call .stop() then .play() to replay.

## Bundling assets

Use .qrc (Qt Resource) to bundle sounds into the .exe (see sounds.qrc above).
The path /sounds/click.wav then resolves at runtime via the resource system.
"""


class QtMultimediaSetupInput(BaseModel):
    """Pydantic input for qt_multimedia_setup."""
    output_dir: str = Field(description="Where to write main.cpp / mediademo.pro / sounds.qrc / MULTIMEDIA_SETUP.md.")


@mcp.tool(name="qt_multimedia_setup", annotations={"title": "Generate a QtMultimedia starter (QMediaPlayer + QSoundEffect + QVideoWidget + .qrc bundling + setup notes)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_multimedia_setup(params: QtMultimediaSetupInput) -> str:
    """Generate a QtMultimedia starter project — QMediaPlayer + QSoundEffect + QVideoWidget.

    Based on JB51 PDF Chapter 49. The generated project:
      - Has a QMediaPlayer + QMediaPlaylist + QVideoWidget for video playback
      - Has a QSoundEffect for short sound effects (WAV)
      - Bundles a sample sound via Qt Resource (.qrc)
      - Includes MULTIMEDIA_SETUP.md with backend notes (DirectShow, WMF, codec hints)

    QtMultimedia in Qt 5.14.2 uses DirectShow by default on Windows. Most common
    formats (mp3 / mp4 / wav) work out of the box; unusual codecs may need
    K-Lite Codec Pack installed.

    Args:
        params.output_dir: where to write the project files.

    Returns:
        str: report listing files written + setup notes.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    out_dir = Path(params.output_dir)
    sandbox_err = _require_sandbox(out_dir, "output_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    out_dir.mkdir(parents=True, exist_ok=True)

    sounds_dir = out_dir / "sounds"
    sounds_dir.mkdir(parents=True, exist_ok=True)
    # Write a placeholder WAV (minimal valid header for a 1-sample WAV)
    placeholder = sounds_dir / "click.wav"
    if not placeholder.exists():
        placeholder.write_bytes(b"RIFF$\x00\x00\x00WAVEfmt \x10\x00\x00\x00\x01\x00\x01\x00\x44\xac\x00\x00\x88\x01\x00\x02\x00\x10\x00data\x00\x00\x00\x00")

    main_path = out_dir / "main.cpp"
    pro_path = out_dir / "mediademo.pro"
    qrc_path = out_dir / "sounds.qrc"
    setup_path = out_dir / "MULTIMEDIA_SETUP.md"

    main_path.write_text(_mm_main_cpp(), encoding="utf-8")
    pro_path.write_text(_mm_pro(), encoding="utf-8")
    qrc_path.write_text(_mm_qrc(), encoding="utf-8")
    setup_path.write_text(_mm_setup_md(), encoding="utf-8")

    files_written = [str(main_path), str(pro_path), str(qrc_path), str(setup_path), str(placeholder)]

    lines = [
        "=== qt_multimedia_setup ===",
        f"Output dir: {out_dir}",
        "",
        "Files written:",
    ]
    for f in files_written:
        lines.append(f"  - {f}")
    lines.append("")
    lines.append("Try: add .mp3 / .mp4 / .wav files via the file dialog at runtime.")
    lines.append("Backends: DirectShow (default), WMF (Win 7+). K-Lite Codec Pack for missing codecs.")

    out = "\n".join(lines)
    return out + _json_footer({
        "ok": True,
        "data": {
            "output_dir": str(out_dir),
            "files": files_written,
        },
    })


