def _qss_for_selectors(selectors: list[str], theme: str = "light") -> str:
    """Generate a QSS file from the given list of widget selectors."""
    lines = [f"/* Generated by qt_qstyle_sheet_gen (v0.3.8) */",
             f"/* Theme: {theme} */",
             ""]
    for sel in selectors:
        if sel not in _QSS_SELECTORS:
            continue
        lines.append(f"/* {sel} */")
        lines.extend(_QSS_SELECTORS[sel])
        lines.append("")
    return "\n".join(lines)


