    """Pydantic input for qt_qstyle_sheet_gen."""
    selectors: list[str] = Field(description="List of widget selectors to include. Choose from: " + ", ".join(_QSS_SELECTORS.keys()))
    output_path: str = Field(description="Where to write the .qss file.")
    theme: str = Field(default="light", description="'light' (default, blue accents) or 'dark' (dark gray accents).")


