@mcp.tool(name="qt_qstyle_sheet_gen", annotations={"title": "Generate a QSS (Qt Style Sheet) file for any subset of 14 widget selectors (light or dark theme)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qstyle_sheet_gen(params: QtQstyleSheetGenInput) -> str:
    """Generate a QSS (Qt Style Sheet) file for any subset of 14 widget selectors.

    Based on JB51 PDF Chapter 45. 14 selector types covered:

      QPushButton / QLineEdit / QComboBox / QListView / QTableView / QHeaderView /
      QStatusBar / QMenuBar / QMenu / QToolBar / QTabWidget / QGroupBox /
      QProgressBar / QScrollBar

    Two themes: light (default, blue accents on white) and dark (blue accents on dark gray).

    Use the output via QApplication::setStyleSheet(qss.readAll()).

    Args:
        params.selectors: list of widget selector names to include.
        params.output_path: where to write the .qss file.
        params.theme: 'light' (default) or 'dark'.

    Returns:
        str: report listing the file written + the selectors included.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.theme not in ("light", "dark"):
        msg = f"Error: theme must be light|dark, got {params.theme!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    bad = [s for s in params.selectors if s not in _QSS_SELECTORS]
    if bad:
        msg = f"Error: unknown selector(s) {bad!r}. Valid: {', '.join(_QSS_SELECTORS.keys())}"
        return msg + _json_footer({"ok": False, "error": msg})
    if not params.selectors:
        msg = "Error: selectors list is empty"
        return msg + _json_footer({"ok": False, "error": msg})

    out_path = Path(params.output_path)
    sandbox_err = _require_sandbox(out_path, "output_path")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    out_path.parent.mkdir(parents=True, exist_ok=True)

    # Build QSS
    lines = [f"/* Generated by qt_qstyle_sheet_gen (v0.3.8) */",
             f"/* Theme: {params.theme} */",
             f"/* Selectors: {', '.join(params.selectors)} */",
             ""]
    for sel in params.selectors:
        rules = _QSS_SELECTORS[sel]
        if params.theme == "dark":
            overrides = _qss_dark_overrides()
            if sel in overrides:
                rules = overrides[sel]
        lines.append(f"/* {sel} */")
        lines.extend(rules)
        lines.append("")

    qss_text = "\n".join(lines)
    out_path.write_text(qss_text, encoding="utf-8")

    lines_out = [
        "=== qt_qstyle_sheet_gen ===",
        f"Output: {out_path}",
        f"Theme: {params.theme}",
        f"Selectors: {', '.join(params.selectors)}",
        f"Size: {len(qss_text)} bytes",
        "",
        "Usage in Qt:",
        "  QFile qss(\"style.qss\");",
        "  qss.open(QIODevice::ReadOnly);",
        "  app.setStyleSheet(qss.readAll());",
    ]

    out = "\n".join(lines_out)
    return out + _json_footer({
        "ok": True,
        "data": {
            "output_path": str(out_path),
            "theme": params.theme,
            "selectors": params.selectors,
            "size_bytes": len(qss_text),
        },
    })


# --- v0.3.6 sentinel (tools appended above this line) -----------------------
# === qt_concurrency_lint: QtConcurrent / QThread / QFuture anti-patterns ===
# Companion to qt_async_await_lint (v0.3.2 async-pattern regex) and
# qt_thread_affinity_check (v0.3.3 cross-thread signal/slot). This tool focuses
# specifically on QtConcurrent + QThread + QRunnable + QFutureWatcher + QSemaphore
# + QtConcurrent::run lifetime traps.
#
# 8 rules:
#   - qtconcurrent_blocking_main_thread      (warning) — QtConcurrent::blockingMapped on GUI
#   - qthreadpool_no_wait                    (warning) — QThreadPool::start() with no waitForDone
#   - qfuture_watcher_missing_setfuture      (warning) — QFutureWatcher declared but no setFuture
#   - qrunnable_no_autodelete                (warning) — QRunnable subclass missing autoDelete
#   - qthread_subclass_no_quit               (warning) — QThread subclass run() doesn't quit
#   - qmutex_lock_in_event_loop              (warning) — QMutexLocker in slot body
#   - qsemaphore_init_too_large              (info)    — QSemaphore(N>100) init suspicious
#   - qconcurrent_run_with_raw_ptr_capture   (warning) — QtConcurrent::run([] lambda with raw ptr)
#
# v0.3.9 — pure regex / brace-match, zero new dependencies.

import re
from typing import List, Dict, Tuple


_QC_RULES: List[Tuple[str, str, str, str]] = [
    # (rule_id, severity, description, regex_pattern)
    ("qtconcurrent_blocking_main_thread", "warning",
     "QtConcurrent::blockingMapped/Run/Filter on the GUI thread freezes the UI",
     r"QtConcurrent\s*::\s*blocking(Mapped|Run|Reduce|Filter)\s*\("),
    ("qthreadpool_no_wait", "warning",
     "QThreadPool::start() without any waitForDone/take() leaves task lifetime to RAII; risky under shutdown",
     r"QThreadPool\s*::\s*(globalInstance|instance)\(\)\s*->\s*start\s*\("),
    ("qfuture_watcher_missing_setfuture", "info",
     "QFutureWatcher declared — verify setFuture() is called later (otherwise `finished` never fires)",
     r"\bQFutureWatcher\s+\w+\s*;"),
    ("qrunnable_no_autodelete", "warning",
     "QRunnable subclass without explicit setAutoDelete(true|false) — defaults vary by version",
     r"class\s+\w+\s*:\s*public\s+QRunnable\b"),
    # NOTE: qthread_subclass_no_quit is NOT in this list — handled below
    # by _qc_find_run_body_without_exec (multi-line brace-match), which checks
    # whether the class's run() actually invokes exec()/quit().
    ("qmutex_lock_in_event_loop", "warning",
     "QMutexLocker / QMutex::lock() inside what looks like a slot body — may deadlock the event loop",
     r"\b(QMutexLocker|QMutex\s*::\s*lock\s*\(|QMutex\s*::\s*tryLock\s*\()"),
    ("qsemaphore_init_too_large", "info",
     "QSemaphore initialised with suspiciously large N — usually means misread concurrency limit",
     r"QSemaphore\s+(?:&|->)?\s*(\w+)\s*\(\s*(\d+)\s*\)"),
    ("qconcurrent_run_with_raw_ptr_capture", "warning",
     "QtConcurrent::run([] lambda capturing raw pointer may outlive the owner",
     r"QtConcurrent\s*::\s*run\s*\(\s*\[\s*[^\]]*\b(this|_)\b"),
]


def _qc_strip_block_comments(text: str) -> str:
    """Remove /* ... */ block comments from text (single-line aware)."""
    return re.sub(r"/\*.*?\*/", " ", text, flags=re.DOTALL)


def _qc_strip_line_comments(text: str) -> str:
    return re.sub(r"//[^\n]*", " ", text)


def _qc_strip_strings(text: str) -> str:
    """Remove string + char literals so 's = "hello"' doesn't trigger anything."""
    return re.sub(r'"(?:[^"\\]|\\.)*"', '""', text)


def _qc_strip_includes(text: str) -> str:
    """Drop `#include <...>` and `#include "..."` directives entirely so that
    QMutexLocker / QSemaphore etc. mentioned in headers don't fire false rules
    on lines like ``#include <QMutexLocker>``.
    """
    return re.sub(r"^\s*#\s*include\s+[<\"][^>\"]*[>\"]", " ", text, flags=re.MULTILINE)


def _qc_normalise(text: str) -> str:
    text = _qc_strip_block_comments(text)
    text = _qc_strip_line_comments(text)
    text = _qc_strip_strings(text)
    text = _qc_strip_includes(text)
    return text


def _qc_brace_match(text: str, start: int) -> int:
    """Return index just past the closing `}` matching the `{` at or before `start`."""
    # start points at the `{`; find matching `}` allowing nesting.
    depth = 0
    i = start
    n = len(text)
    while i < n:
        c = text[i]
        if c == "{":
            depth += 1
        elif c == "}":
            depth -= 1
            if depth == 0:
                return i + 1
        i += 1
    return -1  # unbalanced


def _qc_find_run_body_without_exec(text: str, class_pos: int, class_end: int) -> bool:
    """Detect a QThread subclass between [class_pos, class_end] whose run() body
    doesn't contain `exec()` or `quit()` (informal heuristic: a QThread without
    event loop is almost always wrong).
    """
    body = text[class_pos:class_end]
    runs = re.finditer(r"\bvoid\s+run\s*\(\s*QString\s+[^\)]*\)\s*\{", body)
    for m in runs:
        start = class_pos + m.end() - 1  # '{' position
        end = _qc_brace_match(text, start)
        if end < 0:
            continue
        run_body = text[start:end]
        has_event_loop = "exec" in run_body or "quit" in run_body
        if not has_event_loop:
            return True
    return False


def _qc_lint_file(path: Path) -> List[Dict]:
    """Run all rules on a single .cpp/.cc file. Return list of findings."""
    text = path.read_text(encoding="utf-8", errors="replace")
    out: List[Dict] = []
    # Process line by line so line numbers + snippets always align with `text`.
    lines = text.splitlines()
    for lineno_zero_based, raw_line in enumerate(lines):
        line_no = lineno_zero_based + 1
        # Skip directive lines entirely (no false positives from headers)
        if raw_line.lstrip().startswith("#"):
            continue
        # Strip comments + strings but keep line structure
        clean_line = raw_line
        clean_line = _qc_strip_block_comments(clean_line)
        clean_line = _qc_strip_line_comments(clean_line)
        clean_line = _qc_strip_strings(clean_line)
        for rule_id, severity, desc, pattern in _QC_RULES:
            m = re.search(pattern, clean_line)
            if not m:
                continue
            out.append({
                "file": str(path),
                "line": line_no,
                "rule": rule_id,
                "severity": severity,
                "description": desc,
                "snippet": raw_line.strip()[:140],
            })
    # Multi-line QThread subclass detection (whole file, brace-matched)
    clean = _qc_normalise(text)
    for m in re.finditer(r"class\s+(\w+)\s*:\s*public\s+QThread\b", clean):
        cls_name = m.group(1)
        body_start = clean.find("{", m.end())
        if body_start < 0:
            continue
        body_end = _qc_brace_match(clean, body_start)
        if body_end < 0:
            body_end = len(clean)
        if _qc_find_run_body_without_exec(clean, body_start, body_end):
            line = text.count("\n", 0, m.start()) + 1
            out.append({
                "file": str(path),
                "line": line,
                "rule": "qthread_subclass_no_quit",
                "severity": "warning",
                "description": "QThread subclass run() doesn't call exec() or quit() — no event loop = deadlocks",
                "snippet": f"class {cls_name} : public QThread {{...}}",
            })
    return out


def _qc_walk(project_dir: Path) -> List[Path]:
    out: List[Path] = []
    SKIP_DIRS = (".git", "build-debug", "build-release", "node_modules")
    SKIP_PREFIXES = ("moc_", "ui_", "qrc_")
    for root, dirs, files in __import__("os").walk(project_dir):
        # Filter SKIP_DIRS in place so os.walk doesn't descend
        dirs[:] = [d for d in dirs if d not in SKIP_DIRS]
        for f in files:
            if not f.endswith((".cpp", ".cc", ".cxx")):
                continue
            if any(f.startswith(p) for p in SKIP_PREFIXES):
                continue
            out.append(Path(root) / f)
    return out


class QtConcurrencyLintInput(BaseModel):
    """Pydantic input for qt_concurrency_lint."""
    project_dir: str = Field(description="Project root directory to scan recursively for .cpp/.cc/.cxx files.")
    min_severity: str = Field(default="info", description="Lowest severity to include: 'info' (default, all) or 'warning' (only warnings).")
    output_format: str = Field(default="text", description="'text' (human-readable) or 'json' (machine).")


@mcp.tool(name="qt_concurrency_lint", annotations={"title": "Lint Qt concurrency patterns (QtConcurrent / QThread / QFuture / QSemaphore)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_concurrency_lint(params: QtConcurrencyLintInput) -> str:
    """Detect Qt concurrency anti-patterns in a project's .cpp files — pure static regex, no .exe spawn.

    The companion to ``qt_async_await_lint`` (v0.3.2, async pattern regex) and
    ``qt_thread_affinity_check`` (v0.3.3, cross-thread signal/slot analysis).
    This tool focuses specifically on Qt's *concurrent execution primitives*:
    QtConcurrent, QThreadPool, QFutureWatcher, QRunnable, QThread subclasses,
    QMutex, QSemaphore.

    What it catches (8 rules):
      - qtconcurrent_blocking_main_thread  -- QtConcurrent::blockingMapped on the GUI thread
      - qthreadpool_no_wait                -- QThreadPool::globalInstance()->start() with no waitForDone
      - qfuture_watcher_missing_setfuture  -- QFutureWatcher created but setFuture never called
      - qrunnable_no_autodelete            -- QRunnable subclass missing setAutoDelete
      - qthread_subclass_no_quit           -- QThread subclass whose run() doesn't call exec()/quit()
      - qmutex_lock_in_event_loop          -- QMutexLocker inside what looks like a slot body
      - qsemaphore_init_too_large          -- QSemaphore(N>100) initialisation
      - qconcurrent_run_with_raw_ptr_capture -- QtConcurrent::run lambda capturing `this`

    Why this matters:
      QtConcurrent::blockingMapped on the GUI thread freezes repaints for the
      duration of the computation. QFutureWatcher without setFuture never fires
      `finished` so dependent QML never updates. QThread run() without exec()
      has no event loop so signals posted to it queue forever. Each is a
      silent-AOT production-bug class.

    Args:
        params.project_dir: directory to scan recursively for .cpp/.cc/.cxx files.
        params.min_severity: 'info' (default, all 8 rules) or 'warning' (only warning severity).
        params.output_format: 'text' (human-readable grouped by file) or 'json' (machine).

    Returns:
        str: per-file findings list + aggregate PASS/FAIL verdict.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    err = _require_sandbox(Path(params.project_dir), "concurrency_lint project_dir")
    if err:
        return err + _json_footer({"ok": False, "tool": "qt_concurrency_lint"})
    proj = Path(params.project_dir)
    if not proj.exists():
        return f"Error: project_dir does not exist: {proj}" + _json_footer({"ok": False, "tool": "qt_concurrency_lint"})

    files = _qc_walk(proj)
    findings: List[Dict] = []
    for fp in files:
        try:
            findings.extend(_qc_lint_file(fp))
        except Exception as exc:
            return f"Error: failed to read {fp}: {exc}" + _json_footer({"ok": False, "tool": "qt_concurrency_lint"})

    if params.min_severity == "warning":
        findings = [f for f in findings if f["severity"] == "warning"]

    by_rule: Dict[str, int] = {}
    by_sev: Dict[str, int] = {}
    for f in findings:
        by_rule[f["rule"]] = by_rule.get(f["rule"], 0) + 1
        by_sev[f["severity"]] = by_sev.get(f["severity"], 0) + 1

    verdict = "FAIL" if by_sev.get("warning", 0) > 0 else "PASS"
    if params.output_format == "json":
        import json
        body = json.dumps({
            "ok": True,
            "tool": "qt_concurrency_lint",
            "files_scanned": len(files),
            "findings": findings,
            "by_rule": by_rule,
            "by_severity": by_sev,
            "verdict": verdict,
        }, indent=2)
        return body + "\n"
    # text
    lines = ["=== qt_concurrency_lint ===",
             f"project       : {params.project_dir}",
             f"files_scanned : {len(files)}",
             f"findings      : {len(findings)}",
             f"by_severity   : {by_sev}",
             f"by_rule       : {by_rule}",
             f"verdict       : {verdict}",
             ""]
    if findings:
        lines.append("--- Findings ---")
        cur_file = None
        for f in findings:
            if f["file"] != cur_file:
                lines.append(f"\n  {f['file']}")
                cur_file = f["file"]
            lines.append(f"    L{f['line']:>5}  [{f['severity']:>7}] {f['rule']}: {f['snippet']}")
    lines.append("")
    return "\n".join(lines) + "\n" + _json_footer({
        "ok": True,
        "tool": "qt_concurrency_lint",
        "files_scanned": len(files),
        "finding_count": len(findings),
        "by_rule": by_rule,
        "by_severity": by_sev,
        "verdict": verdict,
    })


# === qt_viewmodel_gen: MVVM ViewModel template (companion to qt_model_gen) ==
# Companion to qt_model_gen (v0.2.8). The MVVM pattern in Qt/QML uses
#   - Model    : QAbstractListModel / QAbstractTableModel (data layer)
#   - ViewModel: QObject + Q_PROPERTY + Q_INVOKABLE  (business logic + commands)
#   - View     : QML files  (UI)
#
# This tool generates the ViewModel layer (the missing piece between model +
# QML). It scaffolds a full demo project: header + cpp + main.cpp + .pro +
# qml + qrc, so you can `qmake && mingw32-make && ./yourapp` immediately.
#
# v0.3.9 — static C++/QML template only, no runtime dependencies.

from typing import List, Dict


def _format_type_default(type_str: str, default) -> str:
    """Render a Qt-aware default literal for a property type.

    Quoted for QString/QVariant, plain for ints/booleans, None for everything else.
    """
    if default is None or default == "":
        return ""
    if type_str in ("QString", "QByteArray", "QUrl", "QColor"):
        return f" = {type_str}::{default}" if False else f' = "{default}"'
    if type_str in ("QStringList",):
        return f' = {type_str}{{{default!r}}}'
    return f" = {default}"


def _cap(s: str) -> str:
    """Capitalize first letter, leave the rest untouched."""
    return s[:1].upper() + s[1:] if s else s


def _viewmodel_header(class_name: str, properties: List[Dict],
                      commands: List[Dict], signals: List[Dict]) -> str:
    """Render the .h file with Q_OBJECT + Q_PROPERTY + Q_INVOKABLE + signals."""
    prop_decls: List[str] = []
    getters_setters: List[str] = []
    for p in properties:
        n, t, dv = p.get("name", "p"), p.get("type", "int"), p.get("default")
        prop_decls.append(
            f"    Q_PROPERTY({t} {n} READ {n} WRITE set{_cap(n)} NOTIFY {n}Changed)")
        getters_setters.append(f"    {t} {n}() const;")
        getters_setters.append(f"    void set{_cap(n)}({t} v);")
    cmd_decls = [
        f"    Q_INVOKABLE {c.get('return_type', 'void')} {c.get('name', 'cmd')}("
        f"{', '.join(c.get('args', []))});"
        for c in commands
    ]
    sig_decls = [f"    void {s.get('name', 'sig')}({', '.join(s.get('args', []))});" for s in signals]
    return f"""#ifndef {class_name.upper()}_H
#define {class_name.upper()}_H

#include <QObject>

class {class_name} : public QObject {{
    Q_OBJECT
{chr(10).join(prop_decls)}
public:
    explicit {class_name}(QObject *parent = nullptr);

{chr(10).join(getters_setters)}
{chr(10).join(cmd_decls)}

signals:
{chr(10).join(sig_decls)}

private:
{chr(10).join(_member_decls(properties))}
}};

#endif // {class_name.upper()}_H
"""


def _member_decls(properties: List[Dict]) -> List[str]:
    """Generate private member declarations from a property list (m_ + Name)."""
    out: List[str] = []
    for p in properties:
        n, t = p.get("name", "p"), p.get("type", "int")
        out.append(f"    {t} m_{n};")
    return out


def _viewmodel_ctor_init(properties: List[Dict]) -> str:
    """Generate the constructor initializer list, e.g. m_score(0)."""
    parts: List[str] = []
    for p in properties:
        n, t, dv = p.get("name", "p"), p.get("type", "int"), p.get("default")
        if dv is None or dv == "":
            continue
        if t in ("QString",):
            parts.append(f'm_{n}({dv!r})')
        else:
            parts.append(f"m_{n}({dv})")
    if not parts:
        return ""
    return f" : QObject(parent), {', '.join(parts)}"


def _viewmodel_cpp(class_name: str, properties: List[Dict],
                   commands: List[Dict], signals: List[Dict]) -> str:
    """Render the .cpp file with ctor + getters/setters + command stubs."""
    ctor_init = _viewmodel_ctor_init(properties)
    getter_setters: List[str] = []
    for p in properties:
        n, t = p.get("name", "p"), p.get("type", "int")
        getter_setters.append(f"""{t} {class_name}::{n}() const {{ return m_{n}; }}
void {class_name}::set{_cap(n)}({t} v) {{
    if (m_{n} != v) {{
        m_{n} = v;
        emit {n}Changed();
    }}
}}""")
    cmd_impls: List[str] = []
    for c in commands:
        ret = c.get("return_type", "void")
        name = c.get("name", "cmd")
        args = c.get("args", [])
        argnames = [a.split()[-1].strip() for a in args]
        ret_stmt = f"return {ret}();" if ret != "void" else "return;"
        # Provide a default implementation that emits a signal or returns {}
        sig_match = next((s for s in signals if s.get("name") == name + "Executed"), None)
        emit_stmt = f" emit {name}Executed({', '.join(argnames)});" if sig_match else ""
        cmd_impls.append(f"""{ret} {class_name}::{name}({', '.join(args)}) {{
    // TODO: implement {name}
    {emit_stmt}
    {ret_stmt}
}}""")
    return f"""#include "{class_name.lower()}.h"

{class_name}::{class_name}(QObject *parent){ctor_init} {{}}

{chr(10).join(getter_setters)}

{chr(10).join(cmd_impls)}
"""


def _viewmodel_qml(class_name: str, properties: List[Dict]) -> str:
    """Render a minimal main.qml using the viewmodel via qmlRegisterType."""
    # Build bindings for visible property labels + a few buttons for commands.
    prop_binds = "\n        ".join(
        f'Text {{ text: vm.{p.get("name", "p")}; font.pixelSize: 24 }}' for p in properties
    )
    return f"""import QtQuick 2.14
import QtQuick.Window 2.14
import QtQuick.Controls 2.14
import App 1.0

Window {{
    visible: true; width: 640; height: 480
    title: "{class_name} demo"
    {class_name} {{ id: vm }}

    Column {{
        anchors.centerIn: parent
        spacing: 12
        {prop_binds}
    }}
}}
"""


def _viewmodel_qrc() -> str:
    return """<RCC>
    <qresource prefix="/">
        <file>main.qml</file>
    </qresource>
</RCC>
"""


class QtViewModelGenInput(BaseModel):
    """Pydantic input for qt_viewmodel_gen."""
    class_name: str = Field(description="C++ class name (CamelCase). e.g. 'GameViewModel'.")
    properties: List[Dict] = Field(default_factory=list, description="List of {name, type, default?} entries. type: QString / int / bool / double / QVariant / etc.")
    commands: List[Dict] = Field(default_factory=list, description="List of {name, return_type?, args?} entries. args list of strings, e.g. ['int row', 'int col'].")
    signals: List[Dict] = Field(default_factory=list, description="List of {name, args?} entries. Optional. Auto-adds <name>Executed signal if a command has matching <name>Executed signal in this list.")
    output_dir: str = Field(description="Where to write <classname>.h / .cpp / main.cpp / main.qml / .pro / .qrc.")
    template_type: str = Field(default="demo", description="'demo' (full .pro + main.cpp + main.qml + .qrc) / 'library' (just .h + .cpp + .pro as library) / 'header_only' (.h only with inline impl).")


@mcp.tool(name="qt_viewmodel_gen", annotations={"title": "Generate Qt MVVM ViewModel skeleton (Q_PROPERTY + Q_INVOKABLE + QML demo)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_viewmodel_gen(params: QtViewModelGenInput) -> str:
    """Generate an MVVM ViewModel class — Q_PROPERTY + Q_INVOKABLE commands, ready for QML binding.

    Companion to ``qt_model_gen`` (v0.2.8, list/table model data layer). The MVVM stack in Qt + QML:

      - Model    → ``qt_model_gen`` produces QAbstractListModel / QAbstractTableModel.
      - ViewModel → ``qt_viewmodel_gen`` produces a QObject subclass with Q_PROPERTY fields
                    exposed to QML, Q_INVOKABLE commands for actions, and Qt signals for state
                    changes. This is the layer where business logic (turn switch, score update,
                    undo, save/load) lives — separate from the data binding itself.
      - View     → QML files the generated ``main.qml`` demonstrates.

    Why this matters:
      Mixing business logic into QAbstractListModel subclasses couples data shape to
      policy. Splitting into a ViewModel lets you swap the data source (SQLite, REST,
      in-memory) without touching gameplay rules, and lets QML declare binding against
      one well-named property without poking rows directly.

    What it produces (template_type='demo'):
      - ``<classname>.h`` — Q_OBJECT + Q_PROPERTY READ/WRITE/NOTIFY + Q_INVOKABLE decls
      - ``<classname>.cpp`` — constructor + getter/setter + command stubs (TODO markers)
      - ``main.cpp`` — QApplication + qmlRegisterType + QQmlApplicationEngine
      - ``main.qml`` — minimal QML showing every property bound
      - ``<classname>.pro`` — qmake (qt + qml + quick modules)
      - ``qml.qrc`` — bundles main.qml as a Qt resource

    Args:
        params.class_name: CamelCase class name, e.g. 'GameViewModel'.
        params.properties: [{name, type, default?}] Q_PROPERTY list. `default` is rendered
            into the constructor initializer (e.g. score=0, currentPlayer="Black").
        params.commands: [{name, return_type?, args?}] Q_INVOKABLE list. `args` is a list
            of `type name` strings (e.g. ['int row', 'int col']).
        params.signals: [{name, args?}] signal declarations; if a command emits an
            `<name>Executed` signal present in this list, the body wires it up.
        params.output_dir: where to write all the files.
        params.template_type: 'demo' (full project + QML demo) / 'library' (just .h+.cpp+.pro lib) / 'header_only' (.h with inline definitions).

    Returns:
        str: report listing files written + per-file size.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    err = _require_sandbox(Path(params.output_dir), "viewmodel_gen output_dir")
    if err:
        return err + _json_footer({"ok": False, "tool": "qt_viewmodel_gen"})
    try:
        out_dir = Path(params.output_dir)
        out_dir.mkdir(parents=True, exist_ok=True)
    except Exception as exc:
        return f"Error: cannot create output_dir {params.output_dir}: {exc}" + _json_footer({"ok": False, "tool": "qt_viewmodel_gen"})

    cls = params.class_name
    cls_lower = cls.lower()
    files: Dict[str, str] = {}
    files[f"{cls_lower}.h"] = _viewmodel_header(cls, params.properties, params.commands, params.signals)
    if params.template_type != "header_only":
        files[f"{cls_lower}.cpp"] = _viewmodel_cpp(cls, params.properties, params.commands, params.signals)
    if params.template_type == "demo":
        files["main.cpp"] = f"""#include <QApplication>
#include <QQmlApplicationEngine>
#include <QUrl>
#include "{cls_lower}.h"

int main(int argc, char *argv[]) {{
    QApplication app(argc, argv);
    qmlRegisterType<{cls}>("App", 1, 0, "{cls}");
    QQmlApplicationEngine engine;
    engine.load(QUrl("qrc:/main.qml"));
    return app.exec();
}}
"""
        files["main.qml"] = _viewmodel_qml(cls, params.properties)
        files["qml.qrc"] = _viewmodel_qrc()
        files[f"{cls_lower}.pro"] = f"""QT       += core gui qml quick
CONFIG   += c++17
TARGET   = {cls_lower}_demo
TEMPLATE = app
SOURCES += main.cpp {cls_lower}.cpp
HEADERS += {cls_lower}.h
RESOURCES += qml.qrc
"""
    elif params.template_type == "library":
        files[f"{cls_lower}.pro"] = f"""QT       += core
CONFIG   += c++17 staticlib
TARGET   = {cls_lower}
TEMPLATE = lib
SOURCES += {cls_lower}.cpp
HEADERS += {cls_lower}.h
"""
    # header_only: no .pro; user integrates into their own project.

    written: List[str] = []
    for name, content in files.items():
        target = out_dir / name
        try:
            target.write_bytes(content.encode("utf-8"))
            written.append(f"{name} ({len(content)} bytes)")
        except Exception as exc:
            return f"Error: cannot write {target}: {exc}" + _json_footer({"ok": False, "tool": "qt_viewmodel_gen"})

    lines = [f"=== qt_viewmodel_gen : {cls} ({params.template_type}) ===",
             f"output : {out_dir}",
             "files written:"]
    for entry in written:
        lines.append(f"  - {entry}")
    if not params.signals:
        lines.append("\nNote: no signals declared. Commands will have body that just returns.")
    if not params.properties:
        lines.append("\nNote: no properties declared. The ViewModel will be commands-only.")
    return "\n".join(lines) + "\n" + _json_footer({
        "ok": True,
        "tool": "qt_viewmodel_gen",
        "class": cls,
        "files": [{"name": n, "size_bytes": len(c)} for n, c in files.items()],
    })


# === qt_heap_snapshot: massif / heaptrack output analysis ====================
# Companion to qt_signal_slot_trace (static trace) + qt_perf_budget (time
# budget): locates *memory* hot spots. Parses two common formats:
#   - Valgrind massif text (heap=.../snapshot=N/heap_tree=detailed)
#   - heaptrack text mode (allocated N bytes ... in M times ... <backtrace>)
#
# Output: top allocations by total size + by count + snapshot delta (potential
# leak when size keeps growing across snapshots). text + json.
#
# v0.3.9 — pure text parser, zero new dependencies.

import re
from typing import List, Dict, Tuple


# Heaptrack text line: e.g. "allocated 1048576 bytes in 10 times at 0x12345"
_HT_ALLOC_RE = re.compile(
    r"^allocated\s+(\d+)\s+bytes?\s+(?:in\s+(\d+)\s+times?\s+)?at\s+(.+)$"
)
# Heaptrack "tracking <time>" header
_HT_HEADER_RE = re.compile(r"^#\s*tracking\s+([\d.]+)\s*s", re.IGNORECASE)

# Massif snapshot header lines
_MS_DESC_RE = re.compile(r"^desc:\s*(.*)$")
_MS_CMD_RE = re.compile(r"^cmd:\s*(.*)$")
_MS_TIME_RE = re.compile(r"^time:\s*(\d+)$")
_MS_SNAPSHOT_RE = re.compile(r"^snapshot\s*=\s*(\d+)$")
_MS_MEMHEAP_RE = re.compile(r"^mem_heap_B\s*=\s*(\d+)$")
_MS_MEMSTACKS_RE = re.compile(r"^mem_stacks_B\s*=\s*(\d+)$")
_MS_HEAPTREE_RE = re.compile(r"^heap_tree\s*=\s*(\w+)$")
# heap_tree=detailed indented n0:/n1: lines: " n0: 12345 0xADDR" or " n0: 12345 func_name"
_MS_TREENODE_RE = re.compile(r"^(\s+)(n\d+):\s*(\d+)\s+(.+)$")


def _detect_format(text: str) -> str:
    """Detect heap profile format by inspecting first non-blank lines.

    Returns one of: "massif" / "heaptrack" / "unknown".
    """
    for line in text.splitlines():
        line = line.strip()
        if not line:
            continue
        # massif always starts with "desc:" or "cmd:" or "time:" or "snapshot=" or "mem_"
        if any(line.startswith(p) for p in ("desc:", "cmd:", "mem_heap_B=", "snapshot=")):
            return "massif"
        if _HT_HEADER_RE.match(line) or _HT_ALLOC_RE.match(line):
            return "heaptrack"
        # Default: unknown
        return "unknown"
    return "unknown"


def _parse_heaptrack(text: str, top_n: int) -> Dict[str, object]:
    """Parse heaptrack text-mode output.

    Each allocation site becomes a row: address -> (total_bytes, count).
    Report top-N by total bytes AND top-N by count.
    """
    sites: Dict[str, Tuple[int, int]] = {}  # addr -> (bytes, count)
    total_bytes = 0
    total_count = 0
    for line in text.splitlines():
        line = line.strip()
        if not line or _HT_HEADER_RE.match(line):
            continue
        m = _HT_ALLOC_RE.match(line)
        if not m:
            continue
        bytes_str, count_str, site = m.group(1), m.group(2), m.group(3)
        b = int(bytes_str)
        c = int(count_str) if count_str else 1
        prev_b, prev_c = sites.get(site, (0, 0))
        sites[site] = (prev_b + b, prev_c + c)
        total_bytes += b
        total_count += c
    by_size = sorted(sites.items(), key=lambda kv: kv[1][0], reverse=True)[:top_n]
    by_count = sorted(sites.items(), key=lambda kv: kv[1][1], reverse=True)[:top_n]
    return {
        "format": "heaptrack",
        "total_sites": len(sites),
        "total_bytes": total_bytes,
        "total_count": total_count,
        "top_by_size": [{"site": s, "bytes": b, "count": c} for s, (b, c) in by_size],
        "top_by_count": [{"site": s, "bytes": b, "count": c} for s, (b, c) in by_count],
        "leak_candidates": _ht_detect_leaks(by_size, by_count),
    }


def _ht_detect_leaks(
    by_size: List[Tuple[str, Tuple[int, int]]],
    by_count: List[Tuple[str, Tuple[int, int]]],
) -> List[Dict[str, object]]:
    """A site with both large bytes AND high count (>5 occurrences) is a
    candidate leak: many repeated allocations of similar size at the same site
    usually means missing free()/QObject parent.
    """
    out: List[Dict[str, object]] = []
    size_index = {s: (b, c) for s, (b, c) in by_size}
    for s, (b, c) in by_count:
        if c >= 5 and b >= 4096:
            prev = size_index.get(s)
            if prev:
                out.append({"site": s, "bytes": b, "count": c,
                            "rationale": "high count + large bytes = potential leak"})
    return out


def _parse_massif(text: str, top_n: int) -> Dict[str, object]:
    """Parse Valgrind massif text output.

    Walks snapshot blocks separated by `snapshot=N` lines; collects per-snapshot
    mem_heap_B + top-level heap_tree=detailed entries (`n0: SIZE LABEL`).
    Reports peak snapshot + size growth across snapshots (leak indicator).
    """
    snapshots: List[Dict[str, object]] = []
    cur_snapshot: Dict[str, object] = {}
    cur_entries: List[Tuple[int, str]] = []
    in_tree = False

    def _flush() -> None:
        nonlocal cur_snapshot, cur_entries
        if cur_snapshot:
            cur_snapshot["top_tree"] = sorted(cur_entries, key=lambda x: -x[0])[:top_n]
            snapshots.append(cur_snapshot)
        cur_snapshot = {}
        cur_entries = []

    for line in text.splitlines():
        # snapshot= is the canonical block delimiter: any data we've seen
        # before this line belongs to the OLD block; the new block starts now.
        m = _MS_SNAPSHOT_RE.match(line)
        if m:
            # The snapshot number we just parsed belongs to the NEXT block,
            # but we want it on the just-closed block. Stash it for retroactive
            # attachment after _flush().
            new_block_snapshot = int(m.group(1))
            if cur_snapshot:
                cur_snapshot["snapshot"] = new_block_snapshot
            _flush()
            cur_snapshot["snapshot"] = new_block_snapshot
            in_tree = False
            continue
        # Track heap_tree mode
        m = _MS_HEAPTREE_RE.match(line)
        if m:
            in_tree = (m.group(1) == "detailed")
            continue
        if in_tree:
            tm = _MS_TREENODE_RE.match(line)
            if tm:
                size = int(tm.group(3))
                label = tm.group(4).strip()
                indent = len(tm.group(1))
                # top-level entries: indent <= 2 spaces (one leading space + 'n0:')
                if indent <= 2:
                    cur_entries.append((size, label))
            continue
        # Header fields: desc / cmd / time / mem_heap_B / mem_stacks_B
        for rx, key in (
            (_MS_DESC_RE, "desc"),
            (_MS_CMD_RE, "cmd"),
            (_MS_TIME_RE, "time"),
            (_MS_MEMHEAP_RE, "mem_heap_B"),
            (_MS_MEMSTACKS_RE, "mem_stacks_B"),
        ):
            mm = rx.match(line)
            if mm:
                val = mm.group(1)
                cur_snapshot[key] = int(val) if key in ("time", "mem_heap_B", "mem_stacks_B") else val
                break
    _flush()  # the last snapshot block
    return _ms_summarize(snapshots, top_n)


def _ms_summarize(snapshots: List[Dict[str, object]], top_n: int) -> Dict[str, object]:
    if not snapshots:
        return {"format": "massif", "snapshot_count": 0, "snapshots": [],
                "peak": None, "leak_candidates": [], "overall_top_tree": []}
    sizes = [s.get("mem_heap_B") for s in snapshots if isinstance(s.get("mem_heap_B"), int)]
    peak = max(snapshots, key=lambda s: s.get("mem_heap_B", 0) or 0) if sizes else None
    # Aggregate top-tree across all snapshots by sum
    agg: Dict[str, int] = {}
    for s in snapshots:
        for size, label in s.get("top_tree", []) or []:
            agg[label] = agg.get(label, 0) + size
    overall_top = sorted(agg.items(), key=lambda kv: -kv[1])[:top_n]
    # Leak candidate: monotonically increasing mem_heap_B by >=3 snapshots
    leak_candidates: List[Dict[str, object]] = []
    if len(snapshots) >= 4:
        monotonic = 0
        prev: int = 0
        for s in snapshots:
            cur = s.get("mem_heap_B")
            if isinstance(cur, int):
                if cur > prev:
                    monotonic += 1
                else:
                    monotonic = 0
                prev = cur
                if monotonic >= 3:
                    leak_candidates.append({"reason": ">=3 snapshots with monotonically increasing mem_heap_B",
                                            "last_snapshot_size": prev})
                    break
    return {
        "format": "massif",
        "snapshot_count": len(snapshots),
        "peak": {"snapshot": peak.get("snapshot"), "size": peak.get("mem_heap_B")} if peak else None,
        "leak_candidates": leak_candidates,
        "overall_top_tree": [{"label": l, "bytes": b} for l, b in overall_top],
        "snapshots": [{"snapshot": s.get("snapshot"), "mem_heap_B": s.get("mem_heap_B"),
                       "time": s.get("time"), "top_tree": s.get("top_tree")}
                      for s in snapshots],
    }


class QtHeapSnapshotInput(BaseModel):
    """Pydantic input for qt_heap_snapshot."""
    source_file: str = Field(description="Absolute path to the heap profile output text file. Detects massif vs heaptrack automatically.")
    top_n: int = Field(default=20, description="Number of top allocation sites to report (default 20).")


@mcp.tool(name="qt_heap_snapshot", annotations={"title": "Analyze heap profile output (massif / heaptrack text)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_heap_snapshot(params: QtHeapSnapshotInput) -> str:
    """Parse a Valgrind massif or heaptrack text output and report top allocation sites + leak candidates.

    The companion to ``qt_perf_budget`` (CPU-time budgets, v0.3.2) and ``qt_signal_slot_trace``
    (signal graphs, v0.2.7) — those two find *time* and *wiring* hotspots; this tool
    finds *memory* hotspots.

    Supported formats:
      - Valgrind massif text (`heap_tree=detailed`, `<snapshot N>` blocks)
      - heaptrack text mode (`allocated N bytes ... at <addr>` lines)

    Why this matters:
      A 64 MB allocation at one site means either an oversized buffer (architecture
      smell) or a missing free() / QObject parent. Repeated allocation of similar
      size at the same site (>5 times) is the canonical leak signature.

    What it does:
      1. Auto-detects format by inspecting the first non-blank lines.
      2. For massif: walks `snapshot=N` blocks, accumulates top-level heap_tree
         entries, identifies monotonic-growth snapshots (>=3 snapshots with
         `mem_heap_B` strictly increasing) as leak candidates.
      3. For heaptrack: aggregates all allocation sites by `(bytes, count)`,
         reports top-N by bytes AND top-N by count, flags sites with both
         count >= 5 AND bytes >= 4096 as potential leaks.

    Args:
        params.source_file: Absolute path to the heap profile output text file.
        params.top_n: Number of top entries to report (default 20).

    Returns:
        str: human-readable text report. JSON trailer when ``QT_MCP_JSON=1``.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    try:
        sandbox_err = _require_sandbox(Path(params.source_file), "heap_snapshot source_file")
        if sandbox_err:
            return sandbox_err + _json_footer({"ok": False, "tool": "qt_heap_snapshot"})
        src_path = Path(params.source_file)
        if not src_path.exists():
            return f"Error: source file does not exist: {src_path}" + _json_footer({"ok": False, "tool": "qt_heap_snapshot", "missing": str(src_path)})
        if not src_path.is_file():
            return f"Error: source path is not a file: {src_path}" + _json_footer({"ok": False, "tool": "qt_heap_snapshot"})
        text = src_path.read_text(encoding="utf-8", errors="replace")
    except Exception as exc:
        return f"Error: qt_heap_snapshot: cannot read {params.source_file}: {exc}" + _json_footer({"ok": False, "tool": "qt_heap_snapshot"})
    fmt = _detect_format(text)
    if fmt == "heaptrack":
        result = _parse_heaptrack(text, params.top_n)
    elif fmt == "massif":
        result = _parse_massif(text, params.top_n)
    else:
        return (f"Error: qt_heap_snapshot: unrecognized heap profile format. "
                f"First line was: {text.splitlines()[:3]!r}. "
                f"Expected massif (`desc:` / `cmd:` / `snapshot=`) or "
                    f"heaptrack (`# tracking` / `allocated N bytes at ...`).") + _json_footer({"ok": False, "tool": "qt_heap_snapshot"})
    return _format_heap_report(result, params.source_file) + _json_footer({
        "ok": True,
        "tool": "qt_heap_snapshot",
        "data": result,
    })


def _format_heap_report(result: Dict[str, object], source: str) -> str:
    """Render a human-readable heap analysis text report."""
    fmt = result.get("format", "?")
    lines = [f"=== Heap Snapshot Report ===",
             f"source : {source}",
             f"format : {fmt}"]
    if fmt == "heaptrack":
        lines.append(f"sites  : {result.get('total_sites')}")
        lines.append(f"bytes  : {result.get('total_bytes')}")
        lines.append(f"count  : {result.get('total_count')}")
        lines.append("")
        lines.append("--- Top by size ---")
        for row in result.get("top_by_size", []) or []:
            lines.append(f"  {row['bytes']:>10} B  ({row['count']:>5}x)  {row['site']}")
        lines.append("")
        lines.append("--- Top by count ---")
        for row in result.get("top_by_count", []) or []:
            lines.append(f"  {row['count']:>5}x  {row['bytes']:>10} B  {row['site']}")
        cand = result.get("leak_candidates", [])
        if cand:
            lines.append("")
            lines.append("--- Leak candidates (high count + large bytes) ---")
            for c in cand:
                lines.append(f"  {c['site']!r}  bytes={c['bytes']}  count={c['count']}  -- {c['rationale']}")
    else:
        sc = result.get("snapshot_count", 0)
        lines.append(f"snapshots : {sc}")
        peak = result.get("peak") or {}
        if peak:
            lines.append(f"peak      : snapshot {peak.get('snapshot')} = {peak.get('size')} B")
        lines.append("")
        lines.append("--- Overall top tree ---")
        for row in result.get("overall_top_tree", []) or []:
            lines.append(f"  {row['bytes']:>10} B  {row['label']}")
        cand = result.get("leak_candidates", [])
        if cand:
            lines.append("")
            lines.append("--- Leak candidates (monotonic growth) ---")
            for c in cand:
                lines.append(f"  snapshot reached {c['last_snapshot_size']} B -- {c['reason']}")
        lines.append("")
        lines.append("--- Snapshot timeline (last 10) ---")
        snaps = result.get("snapshots", []) or []
        for s in snaps[-10:]:
            sn = s.get('snapshot')
            tm = s.get('time')
            mb = s.get('mem_heap_B')
            sn_s = f"#{sn:>4}" if isinstance(sn, int) else "#  ? "
            tm_s = f" time={tm}" if isinstance(tm, int) else ""
            mb_s = f"  mem={mb} B" if isinstance(mb, int) else ""
            lines.append(f"  {sn_s}{tm_s}{mb_s}")
    return "\n".join(lines) + "\n"


# =============================================================================
# v0.4.1 tools
# =============================================================================

# --- qt_code_metrics: project health report (LOC / comment ratio / fn count
#     / cyclomatic complexity / function-length distribution) ---------------

_CM_FN_RE = re.compile(
    r'^\s*(?:[\w:<>&,\s\*\~]+?\s+)?'                    # 修饰符
    r'(?:\w+::)?'                                       # 可选命名空间 / 类
    r'(?P<name>[A-Za-z_]\w*)'                           # 函数名
    r'\s*\([^;{]*\)\s*(?:const\b)?\s*(?:noexcept\b)?\s*'  # 参数 + const + noexcept
    r'(?:->\s*[\w:<>&,\s\*]+)?'                          # 返回类型后置
    r'[\{;]',
    re.MULTILINE,
)
_CM_BRANCH_KW = re.compile(
    r'\b(if|else if|for|while|case|catch)\b|&&|\|\||\?',
    re.MULTILINE,
)


def _cm_strip_strings_chars(text: str) -> str:
    """Strip string + char literals so "if (s == \"if\")" doesn't count."""
    # 替换字符串字面量 "..." 为空
    text = re.sub(r'"(?:\\.|[^"\\])*"', '""', text)
    text = re.sub(r"'(?:\\.|[^'\\])*'", "''", text)
    # raw string R"(...)" Qt 里也常见
    text = re.sub(r'R"\([^)]*\)\s*"', '""', text)
    return text


def _cm_function_lengths(text: str) -> list[tuple[str, int]]:
    """Return [(name, line_count)] for every function/method definition in text.
    Brace-match the body; subtract comments + literals. Skip declarations ending in ';'.
    """
    clean = _cm_strip_strings_chars(text)
    clean = _sst_strip_comments(clean)
    results: list[tuple[str, int]] = []
    for m in _CM_FN_RE.finditer(clean):
        body_start = m.end() - 1  # position of '{' or ';'
        if clean[body_start] == ';':
            continue  # 纯声明 (header inline decl) 跳过
        # brace-match
        depth = 0
        i = body_start
        end = len(clean)
        while i < end:
            c = clean[i]
            if c == '{':
                depth += 1
            elif c == '}':
                depth -= 1
                if depth == 0:
                    break
            i += 1
        if depth != 0:
            continue  # unclosed brace, skip
        body = clean[body_start + 1:i]
        n_lines = body.count('\n') + 1 if body.strip() else 0
        if n_lines > 0:
            results.append((m.group('name'), n_lines))
    return results


def _cm_complexity(text: str) -> int:
    """Cyclomatic complexity for a function body (already brace-matched)."""
    return 1 + len(_CM_BRANCH_KW.findall(text))


class QtCodeMetricsInput(BaseModel):
    project_dir: str = Field(description="Absolute path to the Qt project root (must contain .cpp / .h source files).")
    top_n: int = Field(default=5, description="How many top complexity functions to show in the per-file detail (default 5).")
    threshold: int = Field(default=12, description="Cyclomatic complexity threshold; functions above this are flagged (default 12).")


@mcp.tool(name="qt_code_metrics", annotations={"title": "Generate a project health report (lines / comments / fn count / cyclomatic complexity / heatmap)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_code_metrics(params: QtCodeMetricsInput) -> str:
    """Multi-dimensional project health report: per-file LOC / comment ratio / function count /
    average + max function length, plus a project-wide cyclomatic-complexity summary
    and a text heatmap of largest source files.

    Complements ``qt_complexity_lint`` (which only reports complexity, v0.3.5) and
    ``qt_format_check`` / ``qt_clazy_check`` (style, v0.2.x). Output is text — paste
    into a code-review doc or CI summary.

    Args:
        project_dir: Qt project root to walk (.cpp / .h / .cc / .cxx; skips build/).
        top_n: How many top complexity functions to list per file (default 5).
        threshold: Cyclomatic complexity threshold; flagged functions go to warnings
            section (default 12, rule of thumb 10±2).

    Returns:
        Per-file table + project summary + complexity heatmap + JSON footer.

    Why this matters:
        A "5000-line monster function" is hard to spot from git log alone. A
        30%-comment-ratio file might be the canary of an underdocumented
        subsystem. A 3-file project averaging complexity 18 needs refactor
        before adding more. ``qt_code_metrics`` quantifies all three in one shot.
    """
    proj = Path(params.project_dir)
    if not proj.exists():
        return _json_footer({"ok": False, "error": f"project_dir not found: {proj}"})
    if not _in_sandbox(proj):
        return _json_footer({"ok": False, "error": f"project_dir outside sandbox: {proj}"})

    SKIP_DIRS = {"debug", "release", "build-debug", "build-release",
                 "node_modules", ".tmp", ".git"}
    EXTS = {".cpp", ".h", ".cc", ".cxx", ".hpp"}

    file_metrics: list[dict] = []
    project_total_lines = 0
    project_total_code = 0
    project_total_comment = 0
    project_total_blank = 0
    project_total_functions = 0
    all_fn_complexity: list[tuple[str, str, int, int]] = []  # (file, fn, complexity, loc)

    for p in sorted(proj.rglob("*")):
        if not p.is_file() or p.suffix not in EXTS:
            continue
        # 排除 moc/ui/qrc 生成产物
        if p.name.startswith("moc_") or p.name.startswith("ui_") or p.name.startswith("qrc_"):
            continue
        # 排除 build/output 目录
        if any(part in SKIP_DIRS for part in p.parts):
            continue

        try:
            text = p.read_text(encoding="utf-8", errors="replace")
        except Exception:
            continue

        # LOC categories
        lines = text.split('\n')
        total = len(lines)
        blank = sum(1 for ln in lines if not ln.strip())
        # 注释行：// 开头 或 /* */ 包裹
        comment = 0
        in_block = False
        for ln in lines:
            s = ln.strip()
            if in_block:
                comment += 1
                if '*/' in s:
                    in_block = False
                continue
            if s.startswith('//'):
                comment += 1
            elif s.startswith('/*'):
                comment += 1
                if '*/' not in s:
                    in_block = True
        code = total - blank - comment

        # Functions + complexity
        fns = _cm_function_lengths(text)
        fn_count = len(fns)
        avg_len = sum(L for _, L in fns) // fn_count if fn_count else 0
        max_len = max((L for _, L in fns), default=0)

        # Per-function complexity
        clean = _cm_strip_strings_chars(text)
        clean = _sst_strip_comments(clean)
        for m in _CM_FN_RE.finditer(clean):
            body_start = m.end() - 1
            if clean[body_start] == ';':
                continue
            depth = 0
            i = body_start
            end = len(clean)
            while i < end:
                c = clean[i]
                if c == '{':
                    depth += 1
                elif c == '}':
                    depth -= 1
                    if depth == 0:
                        break
                i += 1
            if depth != 0:
                continue
            body = clean[body_start + 1:i]
            cc = _cm_complexity(body)
            body_lines = body.count('\n') + 1 if body.strip() else 0
            all_fn_complexity.append((str(p.relative_to(proj)), m.group('name'), cc, body_lines))

        # Heatmap
        if code >= 1000:
            heat = "★★★★"
        elif code >= 500:
            heat = "★★★"
        elif code >= 200:
            heat = "★★"
        elif code >= 50:
            heat = "★"
        else:
            heat = "·"

        file_metrics.append({
            "file": str(p.relative_to(proj)),
            "total": total, "code": code, "comment": comment, "blank": blank,
            "comment_ratio": round(comment * 100 / total, 1) if total else 0,
            "fn_count": fn_count, "avg_fn_len": avg_len, "max_fn_len": max_len,
            "heat": heat,
        })
        project_total_lines += total
        project_total_code += code
        project_total_comment += comment
        project_total_blank += blank
        project_total_functions += fn_count

    # Sort by complexity
    all_fn_complexity.sort(key=lambda t: -t[2])

    # Build report
    out: list[str] = []
    out.append(f"=== Project Health Report: {proj} ===\n")
    out.append(f"Files scanned: {len(file_metrics)}")
    out.append(f"Total lines: {project_total_lines}  (code: {project_total_code} / comment: {project_total_comment} / blank: {project_total_blank})")
    if project_total_lines:
        out.append(f"Comment ratio: {round(project_total_comment * 100 / project_total_lines, 1)}%")
    out.append(f"Total functions: {project_total_functions}")
    if file_metrics:
        avg_cc = sum(c for _, _, c, _ in all_fn_complexity) / len(all_fn_complexity) if all_fn_complexity else 0
        out.append(f"Avg cyclomatic complexity: {avg_cc:.1f}  (across {len(all_fn_complexity)} functions)")
    out.append("")

    # Per-file table
    out.append("--- Per-file metrics (sorted by code lines) ---")
    out.append(f"{'Heat':<5} {'File':<40} {'LOC':>5} {'Code':>5} {'Cmt%':>5} {'#Fn':>4} {'AvgFn':>6} {'MaxFn':>6}")
    out.append("-" * 80)
    for fm in sorted(file_metrics, key=lambda x: -x['code']):
        rel = fm['file']
        if len(rel) > 38:
            rel = "…" + rel[-37:]
        out.append(
            f"{fm['heat']:<5} {rel:<40} {fm['total']:>5} {fm['code']:>5} "
            f"{fm['comment_ratio']:>5} {fm['fn_count']:>4} {fm['avg_fn_len']:>6} {fm['max_fn_len']:>6}"
        )
    out.append("")

    # Top complexity functions
    out.append(f"--- Top {params.top_n} cyclomatic-complexity functions ---")
    for fp, fn, cc, loc in all_fn_complexity[:params.top_n]:
        flag = "  ⚠" if cc > params.threshold else ""
        out.append(f"  cc={cc:>3} loc={loc:>4}  {fp}::{fn}(){flag}")
    out.append("")

    # Flagged functions
    flagged = [t for t in all_fn_complexity if t[2] > params.threshold]
    if flagged:
        out.append(f"--- {len(flagged)} functions over threshold cc>{params.threshold} ---")
        for fp, fn, cc, loc in flagged[:20]:
            out.append(f"  cc={cc:>3} loc={loc:>4}  {fp}::{fn}()")
        if len(flagged) > 20:
            out.append(f"  ... and {len(flagged) - 20} more")
    else:
        out.append(f"--- No functions over threshold cc>{params.threshold} ✓ ---")

    out.append("")
    text_out = "\n".join(out) + "\n"
    return text_out + _json_footer({
        "ok": True,
        "files_scanned": len(file_metrics),
        "total_lines": project_total_lines,
        "total_code": project_total_code,
        "total_comment": project_total_comment,
        "total_blank": project_total_blank,
        "total_functions": project_total_functions,
        "comment_ratio": round(project_total_comment * 100 / project_total_lines, 1) if project_total_lines else 0,
        "flagged_count": len(flagged),
        "max_complexity": max((c for _, _, c, _ in all_fn_complexity), default=0),
    })


