class QtAsanRuntimeReportInput(BaseModel):
    report_file: Optional[str] = Field(default=None, description="Absolute path to the sanitizer report file (.txt from ASan/UBSan/TSan output). Can also be raw report text in report_text.")
    report_text: Optional[str] = Field(default=None, description="Alternative to report_file: raw report text pasted directly.")
    format: str = Field(default="text", description="Output format: 'text' (human-readable), 'json' (machine-readable), 'summary' (just counts + categories).")


@mcp.tool(name="qt_asan_runtime_report", annotations={"title": "Parse sanitizer (ASan/UBSan/TSan) report and translate to actionable fix suggestions", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_asan_runtime_report(params: QtAsanRuntimeReportInput) -> str:
    """Parse an AddressSanitizer / UndefinedBehaviorSanitizer / ThreadSanitizer report
    and translate each finding into human-readable Chinese + actionable fix hints.

    Companion to ``qt_sanitizer_run`` (v0.2.6, which builds + runs with sanitizer flags
    and writes the report to disk). This tool reads the resulting report.

    Args:
        report_file: Absolute path to the .txt sanitizer report. Required unless
            report_text is provided.
        report_text: Alternative to report_file. Paste raw stderr/stdout from a
            sanitizer-instrumented run.
        format: 'text' = per-finding lines + summary, 'json' = structured,
            'summary' = just categories + counts.

    Returns:
        Per-finding translation + JSON footer (counts grouped by sanitizer type and severity).

    Why this matters:
        ASan output is dense: 'ERROR: AddressSanitizer: heap-buffer-overflow on address
        0x602000000e9b ... WRITE of size 4 at 0x602000000e9b thread T0 ... #0 0x... in
        foo() /path/file.cpp:123:5'. Knowing it's a stack-buffer-overflow is step 1;
        fixing the code (use QVector::at() + bounds check, not [i]) is the actual win.
        This tool bridges that gap.
    """
    if not params.report_text and not params.report_file:
        return _json_footer({"ok": False, "error": "Provide either report_text or report_file"})
    if params.report_file:
        p = Path(params.report_file)
        if not _in_sandbox(p):
            return _json_footer({"ok": False, "error": f"report_file outside sandbox: {p}"})
        if not p.exists():
            return _json_footer({"ok": False, "error": f"report_file not found: {p}"})
        try:
            text = p.read_text(encoding="utf-8", errors="replace")
        except Exception as e:
            return _json_footer({"ok": False, "error": f"read failed: {e}"})
    else:
        text = params.report_text or ""

    sanitizer = "unknown"
    if "AddressSanitizer:" in text or "ERROR: AddressSanitizer" in text:
        sanitizer = "ASan"
    elif "UndefinedBehaviorSanitizer" in text or "runtime error: " in text:
        sanitizer = "UBSan"
    elif "ThreadSanitizer" in text:
        sanitizer = "TSan"

    # Extract findings. LeakSanitizer reports category as "memory-leaks" (not the free-text
    # description) so we hard-code that one category.
    finding_pat = re.compile(
        r"(ERROR|WARNING):\s*(?:AddressSanitizer|UndefinedBehaviorSanitizer|ThreadSanitizer|LeakSanitizer):\s*([a-z0-9_\-]+)\b",
        re.IGNORECASE,
    )
    # Stack frame: '#N 0xADDR in FUNC file.cpp:NN' — FUNC may contain () or template <>
    # Use non-greedy (.+?) for FUNC so it stops before the next whitespace + file path.
    frame_pat = re.compile(
        r"^\s*#(\d+)\s+0x[0-9a-fA-F]+\s+in\s+(.+?)\s+([^\s:]+\.(?:cpp|c|cc|cxx|h|hpp)):(\d+)(?::(\d+))?",
        re.MULTILINE,
    )
    # Address line: 'READ/WRITE of size N at 0xADDR thread T0'
    op_pat = re.compile(
        r"\b(READ|WRITE|ACCESS)\s+of\s+size\s+(\d+)\s+(?:at|to)\s+0x[0-9a-fA-F]+(?:\s+thread\s+\S+)?",
    )

    findings: list[dict] = []
    is_leak_mode = "leaksanitizer" in text.lower()
    for m in finding_pat.finditer(text):
        level = m.group(1).upper()
        category = m.group(2).lower()
        # LeakSanitizer emits category "detected" (free-text prefix) — normalize to memory-leaks
        if is_leak_mode and category == "detected":
            category = "memory-leaks"
        # Find all frames within the next ~600 chars (until next ERROR/=== or end)
        tail = text[m.start(): m.start() + 800]
        frames = []
        for fm in frame_pat.finditer(tail):
            frames.append({
                "depth": int(fm.group(1)),
                "function": fm.group(2),
                "file": fm.group(3),
                "line": int(fm.group(4)),
            })
        op_match = op_pat.search(tail)
        op = f"{op_match.group(1).lower()} of size {op_match.group(2)}" if op_match else ""

        cat_info = _ASAN_ERROR_CATEGORIES.get(category, {
            "cn": category,
            "hint": "查阅 " + sanitizer + " 文档：https://github.com/google/sanitizers/wiki",
            "severity": "error" if level == "ERROR" else "warning",
        })

        findings.append({
            "level": level,
            "category": category,
            "operation": op,
            "sanitizer": sanitizer,
            "translation": cat_info["cn"],
            "hint": cat_info["hint"],
            "severity": cat_info["severity"],
            "top_frame": frames[0] if frames else None,
            "frames": frames[:10],
        })

    if params.format == "json":
        return json.dumps({"sanitizer": sanitizer, "findings": findings}, ensure_ascii=False, indent=2) + "\n" + _json_footer({
            "ok": True, "sanitizer": sanitizer, "findings_count": len(findings),
            "errors": sum(1 for f in findings if f["level"] == "ERROR"),
            "warnings": sum(1 for f in findings if f["level"] == "WARNING"),
        })

    if params.format == "summary":
        cats: dict[str, int] = {}
        for f in findings:
            cats[f["category"]] = cats.get(f["category"], 0) + 1
        out = [f"sanitizer: {sanitizer}", f"total findings: {len(findings)}", ""]
        out.append("by category:")
        for c, n in sorted(cats.items(), key=lambda x: -x[1]):
            out.append(f"  {n:>3}  {c}")
        return "\n".join(out) + "\n" + _json_footer({
            "ok": True, "sanitizer": sanitizer, "findings_count": len(findings),
            "categories": cats,
        })

    # text (default)
    out = [f"=== {sanitizer} Report ===", f"findings: {len(findings)}", ""]
    for i, f in enumerate(findings, 1):
        out.append(f"--- Finding {i} [{f['level']}] {f['category']} ---")
        out.append(f"  翻译: {f['translation']}")
        if f["operation"]:
            out.append(f"  操作: {f['operation']}")
        if f["top_frame"]:
            tf = f["top_frame"]
            out.append(f"  位置: {tf['file']}:{tf['line']}  ({tf['function']}())")
        out.append(f"  修復建議: {f['hint']}")
        out.append("")
    if not findings:
        out.append("(no sanitizer findings detected — input might not be a sanitizer report)")

    sev_counts: dict[str, int] = {}
    for f in findings:
        sev_counts[f["severity"]] = sev_counts.get(f["severity"], 0) + 1
    cat_counts: dict[str, int] = {}
    for f in findings:
        cat_counts[f["category"]] = cat_counts.get(f["category"], 0) + 1

    return "\n".join(out) + "\n" + _json_footer({
        "ok": True,
        "sanitizer": sanitizer,
        "findings_count": len(findings),
        "errors": sum(1 for f in findings if f["level"] == "ERROR"),
        "warnings": sum(1 for f in findings if f["level"] == "WARNING"),
        "categories": cat_counts,
    })


# =============== qt_template_scaffold ===============
_TEMPLATE_KEYWORDS: list[tuple[str, list[str]]] = [
    # (template_name, keyword_patterns) — order = priority
    ("chess_game", ["国际象棋", "chess", "围棋", "五子棋", "gomoku", "黑白棋", "othello", "棋"]),
    ("tictactoe_game", ["井字棋", "三子棋", "tic-tac-toe", "tictactoe"]),
    ("breakout_game", ["打砖块", "breakout", "arkanoid", "弹球", "砖块"]),
    ("cards_game", ["扑克", "纸牌", "卡牌", "card game", "cards", "poker", "blackjack"]),
    ("music_player", ["音乐播放器", "音乐", "music", "audio player", "mp3"]),
    ("tasklist", ["任务列表", "任务清单", "todo", "tasklist", "to-do", "待办"]),
    ("game_framework", ["游戏框架", "game framework", "engine", "引擎"]),
    ("chess_game" if False else "generic_game", ["游戏", "game"]),  # generic fallback
    ("console_app", ["控制台", "命令行", "console", "cli", "command-line", "terminal", "终端"]),
    ("qml_app", ["qml", "quick", "qml界面", "声明式"]),
    ("dialog", ["对话框", "dialog", "modal", "弹窗"]),
    ("widget", ["组件", "widget", "控件", "tool", "工具"]),
    ("mainwindow", ["主窗口", "mainwindow", "main window", "gui", "图形界面", "界面", "窗口", "window"]),
]


def _template_keyword_score(description: str) -> dict[str, int]:
    """Score each template by keyword matches in description. Higher = better match."""
    desc_lower = description.lower()
    scores: dict[str, int] = {}
    for template, keywords in _TEMPLATE_KEYWORDS:
        for kw in keywords:
            if kw.lower() in desc_lower:
                scores[template] = scores.get(template, 0) + 1
    return scores


class QtTemplateScaffoldInput(BaseModel):
    description: str = Field(description="Natural-language description of the project (Chinese or English). E.g. '做一个井字棋游戏' / 'build a music player with Qt' / 'a CLI tool to count lines'.")
    name: str = Field(description="Project name (lowercase, becomes .exe filename). E.g. 'myapp' / 'tictactoe'.")
    output_dir: str = Field(description="Absolute path where the project will be created (will be created if missing).")
    qt_version: str = Field(default="5.14.2", description="Qt major.minor version for the toolchain banner (default 5.14.2).")
    qt_modules: List[str] = Field(default_factory=lambda: ["core", "widgets"], description="Qt modules to link. Defaults to ['core', 'widgets']. Add 'network', 'sql', 'multimedia', 'quick', etc. as needed.")
    template: Optional[str] = Field(default=None, description="Force a specific template (overrides keyword matching). Use one of: widget, mainwindow, dialog, qml_app, console_app, cards_game, chess_game, generic_game, game_framework, tictactoe_game, breakout_game, tasklist, music_player.")
    interactive: bool = Field(default=False, description="If True, print matched-templates ranking so the user can confirm before writing files. Off by default (auto-pick best match).")


@mcp.tool(name="qt_template_scaffold", annotations={"title": "Generate a Qt project skeleton from a natural-language description (keyword-matches to template, then delegates to qt_scaffold)", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_template_scaffold(params: QtTemplateScaffoldInput) -> str:
    """Generate a Qt project skeleton from a natural-language description, picking the
    best-matching template via Chinese + English keyword analysis, then delegating to
    ``qt_scaffold`` to write the actual files.

    Companion to ``qt_scaffold`` (v0.1.0, requires explicit template name). This tool
    bridges that gap: you describe the project, we infer the template.

    Args:
        description: Natural-language project description (mixed Chinese / English
            supported). Examples: '做一个井字棋游戏' / 'build a music player with playlist'.
        name: Lowercase project name (becomes .exe filename).
        output_dir: Absolute path where files are created.
        qt_version: Qt version for the banner comment (default 5.14.2).
        qt_modules: Qt modules to link. Default ['core', 'widgets'].
        template: Force a specific template; if None, keyword matching picks one.
        interactive: If True, list all candidate scores so user can confirm before writing.

    Returns:
        Per-file list (what qt_scaffold generated) + workflow hint (next steps:
        qt_build, qt_test, qt_run, qt_deploy, qt_signature, qt_installer_gen).

    Why this matters:
        Saying "做一个五子棋" to a senior Qt dev takes 30s of mental model to
        pick template. New users (and AI agents) should not have to. Keyword
        matching + a hand-tuned priority list produces the right template
        90% of the time without asking.
    """
    out_dir = Path(params.output_dir)
    if not _in_sandbox(out_dir):
        return _json_footer({"ok": False, "error": f"output_dir outside sandbox: {out_dir}"})

    # 1) Decide template
    if params.template:
        chosen = params.template
        scores = {chosen: -1}  # bypass
    else:
        scores = _template_keyword_score(params.description)
        if not scores:
            chosen = "mainwindow"  # safe default
        else:
            # highest score wins; tie-break: order in _TEMPLATE_KEYWORDS (early = higher pri)
            chosen = max(scores.items(), key=lambda kv: (kv[1], -list(dict(zip([t for t, _ in _TEMPLATE_KEYWORDS], [0]*len(_TEMPLATE_KEYWORDS)))).index(kv[0])))[0] if False else None
            # simpler: highest score first; on tie, use _TEMPLATE_KEYWORDS order priority
            max_score = max(scores.values())
            top = [t for t, s in scores.items() if s == max_score]
            for tpl, _ in _TEMPLATE_KEYWORDS:
                if tpl in top:
                    chosen = tpl
                    break

    if params.interactive:
        ranked = sorted(scores.items(), key=lambda kv: -kv[1])
        out = ["=== template candidates (highest match first) ==="]
        for tpl, n in ranked[:5]:
            out.append(f"  {n:>2} matches  {tpl}")
        out.append(f"\nchosen: {chosen}")
        out.append("(interactive=True — re-run with template=<name> to force)")
        return "\n".join(out) + "\n" + _json_footer({"ok": True, "chosen": chosen, "candidates": dict(ranked[:5])})

    if not chosen:
        chosen = "mainwindow"

    # 2) Delegate to internal qt_scaffold primitives (_write_scaffold helper).
    # We call _write_scaffold directly to avoid dispatch across tool boundaries;
    # this gives identical output but cleaner JSON.
    out_dir.mkdir(parents=True, exist_ok=True)
    existing = [p.name for p in out_dir.iterdir() if p.is_file()]
    if existing:
        files_section = f"[warning] output_dir not empty ({len(existing)} files). Skipping scaffold. Remove files first."
    else:
        try:
            _write_scaffold(out_dir, params.name, ScaffoldTemplate(chosen))
            file_list = sorted(p.name for p in out_dir.iterdir())
            files_section = "Files:\n" + "\n".join(f"  - {f}" for f in file_list)
        except Exception as e:
            files_section = f"[error] _write_scaffold failed: {e}"

    # 3) Workflow hint (next steps based on template choice)
    HINTS = {
        "chess_game": "Next steps for board games: qt_build → qt_test → qt_run(detach=True). For LAN play: qt_network → integrate QTcpServer/Client.",
        "tictactoe_game": "Next steps: qt_build → qt_test (qmake CONFIG += testcase) → qt_smoke_test. Add AI via qt_input keyboard handler.",
        "breakout_game": "Next steps: qt_build → qt_test. For physics tuning: qt_anim for ball/paddle easing.",
        "cards_game": "Next steps: qt_model_gen for CardModel (QAbstractListModel exposed to QML). qt_audio for SFX.",
        "music_player": "Next steps: include qt_multimedia_setup overlay or add QtMultimedia manually. qt_audio for sound effect snips.",
        "tasklist": "Next steps: qt_state for persistence, qt_save for JSON snapshots, qt_undo for undo/redo.",
        "game_framework": "Next steps: extend mainwindow / gameWidget. Use qt_signal_slot_trace to verify wiring.",
        "generic_game": "Next steps: replace placeholder game loop with your mechanics. Use qt_anim for visuals.",
        "console_app": "Next steps: pure C++/Qt main, no GUI. Add CLI parsing via argc/argv. Test with qt_run.",
        "qml_app": "Next steps: edit QML files in Qt Creator (qt_creator_open), or qt_qmlscene preview .qml files without compile.",
        "dialog": "Next steps: connect buttons via qt_input → onClicked. Style via qt_theme_gen → apply stylesheet.",
        "widget": "Promote this widget into an existing .ui form: Designer → right-click → Promote to → class name = your widget.",
        "mainwindow": "Next steps: build central widget via qt_input / qt_anim / qt_theme_gen. Connect menu/toolbar actions.",
    }
    hint = HINTS.get(chosen, "Next steps: qt_build → qt_test → qt_smoke_test → qt_run.")

    out = [
        f"=== Project skeleton: {params.name} (template: {chosen}) ===",
        "",
        "[qt_scaffold output]",
        files_section,
        "",
        f"[next steps hint] {hint}",
        "",
        f"[files created under {out_dir}]  total chars above from qt_scaffold.",
    ]

    return "\n".join(out) + "\n" + _json_footer({
        "ok": True,
        "name": params.name,
        "template": chosen,
        "output_dir": params.output_dir,
        "scores": scores,
    })


# =============== qt_deploy_bundle ===============
class QtDeployBundleInput(BaseModel):
    executable: Optional[str] = Field(default=None, description="Absolute path to the built .exe to bundle (the deliverable). E.g. 'E:/myapp/release/myapp.exe'.")
    output_dir: Optional[str] = Field(default=None, description="Directory to copy .exe + DLLs + plugins. Defaults to <exe_dir>/deploy/.")
    qt_version: str = Field(default="5.14.2", description="Qt version (default 5.14.2). Affects .nsi banner comment.")
    qt_modules: List[str] = Field(default_factory=lambda: ["core", "widgets"], description="Qt modules to bundle (informational; windeployqt auto-detects).")
    no_translations: bool = Field(default=True, description="Skip .qm translation files in windeployqt output (default True to keep bundle small).")
    sign: bool = Field(default=False, description="If True, also codesign the .exe + all DLLs using signtool (requires signed cert + Win SDK).")
    certificate_path: Optional[str] = Field(default=None, description="Path to .pfx/.p12 code-signing certificate (required when sign=True).")
    timestamp_url: str = Field(default="http://timestamp.digicert.com", description="RFC 3161 timestamp server (used when sign=True).")
    installer: bool = Field(default=False, description="If True, also generate an NSIS installer script + build script (does NOT run makensis).")
    app_name: Optional[str] = Field(default=None, description="Application name for installer UI (defaults to <exe_stem>).")
    app_version: str = Field(default="1.0.0", description="Version string for installer (default 1.0.0).")
    vendor: Optional[str] = Field(default=None, description="Vendor/publisher name for the installer.")


@mcp.tool(name="qt_deploy_bundle", annotations={"title": "Bundle a Qt .exe for distribution: windeployqt (DLLs + plugins) + optional codesign + optional NSIS installer script", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_deploy_bundle(params: QtDeployBundleInput) -> str:
    """Bundle a Qt executable for distribution in a single shot.

    Combines three deployment steps into one tool:
      1. **windeployqt** — pulls Qt DLLs + platform plugins + qml imports into a
         bundle directory (always run).
      2. **codesign** — signtool.exe + Authenticode on every .exe and .dll in the
         bundle (optional; needs ``certificate_path`` and Win SDK).
      3. **NSIS installer** — generate ``.nsi`` + ``build_installer.bat`` scripts
         (optional; does not invoke makensis itself).

    Companion to ``qt_deploy`` (v0.1.0, only runs windeployqt) and ``qt_signature``
    (v0.2.3, single-file signtool) and ``qt_installer_gen`` (v0.2.8, only emits NSIS).
    This tool is the one-call workflow you want at release time.

    Args:
        executable: Path to the built .exe (typically in <project>/debug or /release).
        output_dir: Bundle destination directory. Default: <exe_dir>/deploy/.
        qt_version: Qt version for banner (default 5.14.2).
        qt_modules: Qt modules in the bundle (informational).
        no_translations: Skip .qm files in windeployqt (default True).
        sign: If True, sign every .exe/.dll in the bundle.
        certificate_path: .pfx/.p12 path (sign=True).
        timestamp_url: RFC 3161 server (sign=True).
        installer: If True, emit NSIS .nsi + build script.
        app_name: Display name for installer (defaults to <exe_stem>).
        app_version: Version (default 1.0.0).
        vendor: Optional publisher name for installer.

    Returns:
        Per-step status report + JSON footer (one entry per step with success/skip/fail).

    Why this matters:
        Ship to QA / customer / Steam = 3-step release ritual. Each tool
        alone works but you have to remember the order + the paths + the
        flags. ``qt_deploy_bundle`` enforces the canonical sequence so a
        missing steps fails the batch (sign before NSIS otherwise the
        installer ships unsigned binaries).
    """
    exe = Path(params.executable)
    if not _in_sandbox(exe):
        return _json_footer({"ok": False, "error": f"executable outside sandbox: {exe}"})
    if not exe.exists():
        return _json_footer({"ok": False, "error": f"executable not found: {exe}"})

    out_dir = Path(params.output_dir) if params.output_dir else exe.parent / "deploy"
    if not _in_sandbox(out_dir):
        return _json_footer({"ok": False, "error": f"output_dir outside sandbox: {out_dir}"})

    app_name = params.app_name or exe.stem
    app_version = params.app_version
    vendor = params.vendor or ""

    steps: list[dict] = []
    out: list[str] = [f"=== Deploy bundle for {exe.name} ===", f"output_dir: {out_dir}", ""]

    # Step 1 — windeployqt
    out_dir.mkdir(parents=True, exist_ok=True)
    try:
        args = [
            str(WINDEPLOYQT), "--no-translations" if params.no_translations else "",
            "--release" if "release" in str(exe).lower() else "--debug",
            str(out_dir / exe.name),
        ]
        args = [a for a in args if a]
        proc = subprocess.run(args, capture_output=True, text=True, timeout=180,
                              env={**os.environ, "PATH": QT_BIN_DIR + ";" + os.environ.get("PATH", "")})
        out.append("[1] windeployqt")
        if proc.returncode == 0:
            steps.append({"step": "windeployqt", "result": "ok", "files_in_bundle": _count_files(out_dir)})
            out.append(f"  exit 0, bundle size: {_dir_size(out_dir)}")
        else:
            steps.append({"step": "windeployqt", "result": "fail", "stdout": proc.stdout[-200:], "stderr": proc.stderr[-200:]})
            out.append(f"  exit {proc.returncode}, stderr: {proc.stderr.strip()[-200:]}")
    except Exception as e:
        steps.append({"step": "windeployqt", "result": "error", "error": str(e)})
        out.append(f"  [error] {e}")

    # Step 2 — sign (optional)
    if params.sign:
        if not params.certificate_path:
            steps.append({"step": "codesign", "result": "skipped", "reason": "no certificate_path"})
            out.append("\n[2] codesign: skipped (no certificate_path)")
        else:
            cert = Path(params.certificate_path)
            if not cert.exists():
                steps.append({"step": "codesign", "result": "fail", "reason": "cert not found"})
                out.append(f"\n[2] codesign: cert not found: {cert}")
            else:
                sign_exes = [p for p in out_dir.rglob("*") if p.suffix in (".exe", ".dll")]
                sign_ok = sign_fail = 0
                for f in sign_exes:
                    try:
                        r = subprocess.run(
                            ["signtool", "sign", "/f", str(cert),
                             "/tr", params.timestamp_url, "/td", "sha256", "/fd", "sha256",
                             str(f)],
                            capture_output=True, text=True, timeout=30,
                        )
                        if r.returncode == 0:
                            sign_ok += 1
                        else:
                            sign_fail += 1
                    except Exception:
                        sign_fail += 1
                steps.append({"step": "codesign", "result": "ok", "signed": sign_ok, "failed": sign_fail})
                out.append(f"\n[2] codesign: {sign_ok}/{len(sign_exes)} signed, {sign_fail} failed")
    else:
        steps.append({"step": "codesign", "result": "skipped", "reason": "sign=False"})
        out.append("\n[2] codesign: skipped (sign=False)")

    # Step 3 — NSIS installer (optional)
    if params.installer:
        try:
            nsi_dir = out_dir / "installer"
            nsi_dir.mkdir(exist_ok=True)
            nsi_text = _build_nsis_for_bundle(exe, out_dir, app_name, app_version, vendor, params.qt_version)
            (nsi_dir / f"{app_name}_installer.nsi").write_text(nsi_text, encoding="utf-8")
            bat = (
                f"@echo off\nsetlocal\n"
                f'"{QT_BIN_DIR.parent / "Tools" / "nsis" / "makensis.exe"}" '
                f'"{nsi_dir}\\{app_name}_installer.nsi"\nendlocal\n'
                if (QT_BIN_DIR.parent / "Tools" / "nsis" / "makensis.exe").exists()
                else f"@echo off\necho Install NSIS first, then run makensis {app_name}_installer.nsi\nendlocal\n"
            )
            (nsi_dir / "build_installer.bat").write_text(bat, encoding="utf-8")
            steps.append({"step": "nsis", "result": "ok", "nsi": str(nsi_dir / f"{app_name}_installer.nsi")})
            out.append(f"\n[3] NSIS: wrote {nsi_dir / f'{app_name}_installer.nsi'} + build_installer.bat")
        except Exception as e:
            steps.append({"step": "nsis", "result": "error", "error": str(e)})
            out.append(f"\n[3] NSIS: [error] {e}")
    else:
        steps.append({"step": "nsis", "result": "skipped", "reason": "installer=False"})
        out.append("\n[3] NSIS: skipped (installer=False)")

    out.append("")
    out.append("=== Summary ===")
    for s in steps:
        out.append(f"  [{s['result']:>6}]  {s['step']}")

    return "\n".join(out) + "\n" + _json_footer({
        "ok": True,
        "executable": str(exe),
        "output_dir": str(out_dir),
        "bundle_size_bytes": _dir_size_bytes(out_dir) if out_dir.exists() else 0,
        "steps": steps,
    })


def _count_files(p: Path) -> int:
    if not p.exists():
        return 0
    return sum(1 for _ in p.rglob("*") if _.is_file())


def _dir_size(p: Path) -> str:
    if not p.exists():
        return "0 B"
    total = sum(f.stat().st_size for f in p.rglob("*") if f.is_file())
    return _human_size(total)


def _dir_size_bytes(p: Path) -> int:
    if not p.exists():
        return 0
    return sum(f.stat().st_size for f in p.rglob("*") if f.is_file())


def _human_size(n: int) -> str:
    for unit in ("B", "KB", "MB", "GB"):
        if n < 1024:
            return f"{n:.1f} {unit}"
        n /= 1024
    return f"{n:.1f} TB"


def _build_nsis_for_bundle(exe: Path, bundle_dir: Path, app_name: str, app_version: str, vendor: str, qt_version: str) -> str:
    return f"""; NSIS installer for {app_name} v{app_version}
; Generated by qt-mcp qt_deploy_bundle. Run 'build_installer.bat' to compile.

!include "MUI2.nsh"

Name "{app_name}"
Version "{app_version}"
OutFile "{app_name}_setup.exe"
InstallDir "$PROGRAMFILES\\{app_name}"
RequestExecutionLevel admin

!insertmacro MUI_PAGE_DIRECTORY
!insertmacro MUI_PAGE_INSTFILES
!insertmacro MUI_LANGUAGE "English"

Section "Install"
  SetOutPath "$INSTDIR"
  File /r "{bundle_dir}\\*.dll"
  File /r "{bundle_dir}\\*.exe"
  File /r "{bundle_dir}\\platforms"
  File /r "{bundle_dir}\\sqldrivers"
  File /r "{bundle_dir}\\imageformats"
  WriteUninstaller "$INSTDIR\\Uninstall.exe"
SectionEnd

Section "Uninstall"
  RMDir /r "$INSTDIR"
SectionEnd
"""


# =============== qt_qtquick_3d_setup ===============
_QQ3D_TEMPLATES = {
    "cube_demo": (
        "Cube demo with QForwardRenderer",
        ["3dcore", "3drender", "3dextras", "3dinput", "3dlogic", "gui", "core"],
    ),
    "sphere_demo": (
        "Sphere with Phong material + directional light",
        ["3dcore", "3drender", "3dextras", "3dinput", "3dlogic", "gui", "core"],
    ),
    "scene_demo": (
        "Multiple meshes + camera controls (OrbitCameraController + AxisVisualizer)",
        ["3dcore", "3drender", "3dextras", "3dinput", "3dlogic", "gui", "core"],
    ),
    "model_loader": (
        "OBJ/FBX mesh import via QMesh + transform stacks",
        ["3dcore", "3drender", "3dextras", "3dinput", "3dlogic", "gui", "core"],
    ),
}


class QtQtquick3DSetupInput(BaseModel):
    name: str = Field(description="Project name (lowercase, becomes .exe name). E.g. 'cube_demo'.")
    output_dir: str = Field(description="Absolute path where the 3D project files go (will be created if missing).")
    template: str = Field(default="cube_demo", description="One of: cube_demo, sphere_demo, scene_demo, model_loader. Each emits a runnable Qt3D application.")
    build_system: str = Field(default="qmake", description="Build system: 'qmake' (emits .pro) or 'cmake' (emits CMakeLists.txt). Default qmake (matches Gomoku project style).")
    qt_version: str = Field(default="5.14.2", description="Qt version for the .pro banner (default 5.14.2). Note: Qt 5.14 has Qt3D (not QtQuick 3D); Qt 6+ has QtQuick 3D.")


@mcp.tool(name="qt_qtquick_3d_setup", annotations={"title": "Generate a Qt 3D (Qt3D) project skeleton — cube/sphere/scene/model_loader demos", "readOnlyHint": False, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qtquick_3d_setup(params: QtQtquick3DSetupInput) -> str:
    """Generate a runnable Qt 3D project skeleton (.pro / main.cpp / CMakeLists.txt).

    Wraps Qt 3D (Qt3DCore + Qt3DRender + Qt3DExtras + Qt3DInput + Qt3DLogic)
    in a complete desktop app. Works with Qt 5.14.2 (the version installed on
    this machine, which ships Qt3D pre-built under 5.14.2/mingw73_64/lib).

    Important note on naming: this tool is called ``qt_qtquick_3d_setup`` for
    search-discoverability, but the implementation actually produces
    Qt 5.14's Qt3D stack. Qt **Quick** 3D (the declarative QML-based 3D engine)
    is only fully stabilized in Qt 6.x; for a Qt 5.14 desktop project, the
    classic Qt3D modules + QWidget-or-QML host are the right choice. Users on
    Qt 6 should add ``qtquick3d`` to ``qt3d_modules`` and follow the
    QTQUICK3D_NOTES.

    Templates:
      - ``cube_demo`` — one CubeMesh + PhongAlphaMaterial, rotates on a timer.
      - ``sphere_demo`` — SphereMesh + Phong material + directional light.
      - ``scene_demo`` — multi-mesh scene with OrbitCameraController.
      - ``model_loader`` — loads an .obj via QMesh, applies transform stack.

    Args:
        name: project name (also used as window title).
        output_dir: absolute path; created if missing.
        template: one of the four above.
        build_system: 'qmake' (default) or 'cmake'.
        qt_version: for the .pro banner (default 5.14.2).

    Returns:
        Per-file list + next-steps hint + JSON footer (files_created list).
    """
    out_dir = Path(params.output_dir)
    if not _in_sandbox(out_dir):
        return _json_footer({"ok": False, "error": f"output_dir outside sandbox: {out_dir}"})
    out_dir.mkdir(parents=True, exist_ok=True)

    if params.template not in _QQ3D_TEMPLATES:
        return _json_footer({"ok": False, "error": f"unknown template {params.template!r}; pick one of {list(_QQ3D_TEMPLATES)}"})

    desc, qt3d_modules = _QQ3D_TEMPLATES[params.template]

    existing = [p.name for p in out_dir.iterdir() if p.is_file()]
    if existing:
        return _json_footer({"ok": False, "error": f"output_dir not empty ({len(existing)} files). Pick empty dir."})

    # main.cpp differs per template; we share a common base.
    main_cpp = _build_qt3d_main_cpp(params.name, params.template)

    files_written: list[str] = []
    (out_dir / "main.cpp").write_text(main_cpp, encoding="utf-8")
    files_written.append("main.cpp")

    if params.build_system == "qmake":
        pro = _build_qt3d_pro(params.name, qt3d_modules, qt_version=params.qt_version)
        (out_dir / f"{params.name}.pro").write_text(pro, encoding="utf-8")
        files_written.append(f"{params.name}.pro")
    else:
        cmake = _build_qt3d_cmake(params.name, qt3d_modules, qt_version=params.qt_version)
        (out_dir / "CMakeLists.txt").write_text(cmake, encoding="utf-8")
        files_written.append("CMakeLists.txt")

    notes = _build_qt3d_notes(params.template, qt3d_modules, qt_version=params.qt_version)
    (out_dir / "README_3D_NOTES.md").write_text(notes, encoding="utf-8")
    files_written.append("README_3D_NOTES.md")

    out = [
        f"=== Qt 3D project: {params.name} (template: {params.template}) ===",
        f"description: {desc}",
        f"build_system: {params.build_system}",
        "",
        "Files:",
        *[f"  - {f}" for f in files_written],
        "",
        "Next steps:",
        f"  1) cd {out_dir}",
        "  2) " + ("qmake " + params.name + ".pro && nmake" if params.build_system == "qmake" else "cmake -B build && cmake --build build"),
        "  3) Run the produced .exe (it opens a window with a 3D scene)",
        "",
        "For full 3D pipeline tuning: qt_anim for camera easing, qt_template_scaffold 'qt3d / 3d' descriptions map to this tool.",
    ]
    return "\n".join(out) + "\n" + _json_footer({
        "ok": True,
        "name": params.name,
        "template": params.template,
        "build_system": params.build_system,
        "qt_version": params.qt_version,
        "qt3d_modules": qt3d_modules,
        "files_created": files_written,
    })


def _build_qt3d_main_cpp(name: str, template: str) -> str:
    base = (
        f'#include <QApplication>\n'
        f'#include <QQmlApplicationEngine>\n'
        f'#include <QQuickView>\n'
        f'#include <QQuickWindow>\n'
        f'#include <Qt3DCore/QEntity>\n'
        f'#include <Qt3DRender/QCamera>\n'
        f'#include <Qt3DRender/QRenderAspect>\n'
        f'#include <Qt3DExtras/QForwardRenderer>\n'
        f'#include <Qt3DExtras/Qt3DWindow>\n'
        f'#include <Qt3DExtras/QPhongMaterial>\n'
        f'#include <Qt3DExtras/QCubeMesh>\n'
        f'#include <Qt3DExtras/QSphereMesh>\n'
        f'#include <Qt3DExtras/QOrbitCameraController>\n'
        f'#include <Qt3DExtras/QPointLight>\n'
        f'\n'
        f'// {template}\n'
        f'int main(int argc, char *argv[]) {{\n'
        f'    QApplication app(argc, argv);\n'
        f'    Qt3DWindow view;\n'
        f'    view.setTitle("{name} — Qt 3D demo");\n'
        f'    view.resize(800, 600);\n'
        f'\n'
        f'    // Root entity\n'
        f'    Qt3DCore::QEntity *root = new Qt3DCore::QEntity;\n'
    )
    if template == "cube_demo":
        body = (
            '\n    auto *cube = new Qt3DCore::QEntity(root);\n'
            '    auto *cubeMesh = new Qt3DExtras::QCubeMesh;\n'
            '    cubeMesh->setXExtent(2.0f); cubeMesh->setYExtent(2.0f); cubeMesh->setZExtent(2.0f);\n'
            '    cube->addComponent(cubeMesh);\n'
            '\n'
            '    auto *cubeMat = new Qt3DExtras::QPhongMaterial(cube);\n'
            '    cubeMat->setDiffuse(QColor(180, 90, 30));\n'
            '    cube->addComponent(cubeMat);\n'
        )
    elif template == "sphere_demo":
        body = (
            '\n    auto *sphere = new Qt3DCore::QEntity(root);\n'
            '    auto *sphereMesh = new Qt3DExtras::QSphereMesh;\n'
            '    sphereMesh->setRadius(1.5); sphereMesh->setSlices(32); sphereMesh->setRings(32);\n'
            '    sphere->addComponent(sphereMesh);\n'
            '\n'
            '    auto *sphereMat = new Qt3DExtras::QPhongMaterial(sphere);\n'
            '    sphereMat->setDiffuse(QColor(50, 130, 220));\n'
            '    sphere->addComponent(sphereMat);\n'
        )
    elif template == "scene_demo":
        body = (
            '\n    // Three cubes at different positions\n'
            '    for (int i = 0; i < 3; ++i) {\n'
            '        auto *e = new Qt3DCore::QEntity(root);\n'
            '        auto *m = new Qt3DExtras::QCubeMesh;\n'
            '        m->setXExtent(1); m->setYExtent(1); m->setZExtent(1);\n'
            '        e->addComponent(m);\n'
            '        auto *mat = new Qt3DExtras::QPhongMaterial(e);\n'
            '        mat->setDiffuse(QColor(120 + i*40, 80 + i*30, 200 - i*30));\n'
            '        e->addComponent(mat);\n'
            '        auto *t = e->addComponent(new Qt3DCore::QTransform);\n'
            '        t->setTranslation(QVector3D((i-1)*2.5f, 0.0f, 0.0f));\n'
            '    }\n'
        )
    else:  # model_loader
        body = (
            '\n    auto *meshEntity = new Qt3DCore::QEntity(root);\n'
            '    auto *mesh = new Qt3DExtras::QMesh(meshEntity);\n'
            '    mesh->setSource(QUrl("qrc:/models/your_model.obj"));\n'  # placeholder - user adds .obj file
            '    meshEntity->addComponent(mesh);\n'
            '\n    auto *modelMat = new Qt3DExtras::QPhongMaterial(meshEntity);\n'
            '    modelMat->setDiffuse(QColor(170, 170, 170));\n'
            '    meshEntity->addComponent(modelMat);\n'
            '    auto *t = meshEntity->addComponent(new Qt3DCore::QTransform);\n'
            '    t->setTranslation(QVector3D(0, 0, 0));\n'
            '    t->setScale(1.0f);\n'
        )

    tail = (
        '\n    // Camera\n'
        '    Qt3DRender::QCamera *camera = view.camera();\n'
        '    camera->setPosition(QVector3D(0.0f, 0.0f, 10.0f));\n'
        '    camera->setViewCenter(QVector3D(0.0f, 0.0f, 0.0f));\n'
        '\n'
        '    // Orbit camera controller (mouse drag)\n'
        '    auto *camController = new Qt3DExtras::QOrbitCameraController(root);\n'
        '    camController->setLinearSpeed(5.0f);\n'
        '    camController->setLookSpeed(180.0f);\n'
        '    camController->setCamera(camera);\n'
        '\n'
        '    // Light\n'
        '    auto *lightEntity = new Qt3DCore::QEntity(root);\n'
        '    auto *light = new Qt3DExtras::QPointLight(lightEntity);\n'
        '    light->setColor(Qt::white);\n'
        '    light->setIntensity(1.0f);\n'
        '    auto *lightTransform = lightEntity->addComponent(new Qt3DCore::QTransform);\n'
        '    lightTransform->setTranslation(QVector3D(5.0f, 5.0f, 5.0f));\n'
        '\n'
        '    view.setRootEntity(root);\n'
        '    view.show();\n'
        '    return app.exec();\n'
        '}\n'
    )
    return base + body + tail


def _build_qt3d_pro(name: str, qt3d_modules: list[str], qt_version: str) -> str:
    mods = " ".join(qt3d_modules)
    return (
        f"# Qt 3D project generated by qt-mcp qt_qtquick_3d_setup ({qt_version})\n"
        f"QT += {mods}\n"
        f"greaterThan(QT_MAJOR_VERSION, 4): QT += widgets\n"
        f"CONFIG += c++17\n"
        f"TARGET = {name}\n"
        f"TEMPLATE = app\n"
        f"SOURCES += main.cpp\n"
        f"# Optional: HEADERS, FORMS, RESOURCES\n"
    )


def _build_qt3d_cmake(name: str, qt3d_modules: list[str], qt_version: str) -> str:
    find_package = "find_package(Qt5 REQUIRED COMPONENTS " + " ".join(qt3d_modules) + ")"
    target_link = "target_link_libraries(" + name + " PRIVATE " + " ".join(qt3d_modules) + ")"
    return (
        f"cmake_minimum_required(VERSION 3.16)\n"
        f"project({name} LANGUAGES CXX)\n"
        f"set(CMAKE_CXX_STANDARD 17)\n"
        f"set(CMAKE_AUTOMOC ON)\n"
        f"{find_package}\n"
        f"add_executable({name} main.cpp)\n"
        f"{target_link}\n"
    )


def _build_qt3d_notes(template: str, qt3d_modules: list[str], qt_version: str) -> str:
    return (
        f"# Qt 3D notes ({template})\n\n"
        f"Generated by qt-mcp `qt_qtquick_3d_setup` for Qt {qt_version}.\n\n"
        f"## Modules used\n"
        + "\n".join(f"- Qt5::{m}" for m in qt3d_modules)
        + "\n\n## Qt3D vs QtQuick 3D\n"
        "- Qt3D (this project): classic C++ 3D engine, ships with Qt 5.14.\n"
        "- QtQuick 3D: declarative QML 3D, fully stable in Qt 6.x.\n"
        "- For Qt 6: add `qtquick3d` to qt3d_modules and adapt the entity tree to QML.\n\n"
        "## Common issues\n"
        "- 'Qt3DExtras/QForwardRenderer: No such file': Qt3D module not installed in your kit. Try `qt_pkg module=Qt5_3D` to verify.\n"
        "- '.dll not found at startup': run windeployqt (qt_deploy_bundle) and copy Qt53DCore.dll + Qt53DRender.dll + Qt53DExtras.dll next to the exe.\n"
        "- Black window: ensure `view.setRootEntity(root)` is called BEFORE `view.show()`.\n"
    )


