# =============== qt_qobject_invoke_metadata ===============
_QOBJECT_META_PATTERNS = {
    "signals": re.compile(r"^\s*signals\s*:\s*(.*?)(?=^\s*(public|protected|private|signals|slots|public slots|protected slots|private slots|Q_SIGNALS|}[;}]|$))",
                             re.MULTILINE | re.DOTALL),
    "public_slots": re.compile(r"^\s*public\s+slots\s*:\s*(.*?)(?=^\s*(public|protected|private|signals|slots|public slots|protected slots|private slots|Q_SIGNALS|}[;}]|$))",
                                 re.MULTILINE | re.DOTALL),
    "private_slots": re.compile(r"^\s*private\s+slots\s*:\s*(.*?)(?=^\s*(public|protected|private|signals|slots|public slots|protected slots|private slots|Q_SIGNALS|}[;}]|$))",
                                   re.MULTILINE | re.DOTALL),
    "slots": re.compile(r"^\s*slots\s*:\s*(.*?)(?=^\s*(public|protected|private|signals|slots|public slots|protected slots|private slots|Q_SIGNALS|}[;}]|$))",
                       re.MULTILINE | re.DOTALL),
    "q_signals": re.compile(r"^\s*Q_SIGNALS\s*:\s*(.*?)(?=^\s*(public|protected|private|signals|slots|public slots|protected slots|private slots|Q_SIGNALS|}[;}]|$))",
                              re.MULTILINE | re.DOTALL),
}

_QINVOKABLE_RE = re.compile(r"Q_INVOKABLE\s+(?P<ret>[\w:\<\>\s\*\&]+?)\s+(?P<name>\w+)\s*\((?P<args>[^)]*)\)", re.MULTILINE)
_QSLOT_DECL_RE = re.compile(r"^(?:\s+)?(?:virtual\s+)?(?P<ret>[\w:\<\>\s\*\&]+?)\s+(?P<name>\w+)\s*\((?P<args>[^)]*)\)\s*(?:=\s*0)?\s*[;{]",
                                  re.MULTILINE)
_QPROPERTY_RE = re.compile(
    r"Q_PROPERTY\s*\(\s*(?P<type>\w+)\s+(?P<name>\w+)"
    r"(?:\s+READ\s+(?P<read>\w+))?"
    r"(?:\s+WRITE\s+(?P<write>\w+))?"
    r"(?:\s+NOTIFY\s+(?P<notify>\w+))?"
    r"[^)]*\)",
    re.MULTILINE)


class QtQobjectInvokeMetadataInput(BaseModel):
    source_files: list[str] = Field(description="List of absolute paths to .h / .cpp / moc_*.cpp files containing Q_OBJECT-derived class declarations.")
    class_name: Optional[str] = Field(default=None, description="Optional: filter the report to only this class name (default None = first QObject class found).")
    format: str = Field(default="text", description="'text' (readable) or 'json' (machine-readable) for the introspection report.")


@mcp.tool(name="qt_qobject_invoke_metadata", annotations={"title": "Introspect Q_OBJECT metadata (signals / slots / Q_INVOKABLE / Q_PROPERTY) from .h or moc_*.cpp files (no helper.exe needed)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qobject_invoke_metadata(params: QtQobjectInvokeMetadataInput) -> str:
    """Read Q_OBJECT metadata statically from C++ headers or compiled moc_*.cpp files.

    Parses:
      - signals: section members (signal/slot declarations)
      - public slots: / private slots: / slots: members
      - Q_INVOKABLE decorated methods
      - Q_PROPERTY (READ / WRITE / NOTIFY metadata)

    Useful for:
      - Generating documentation
      - Validating that two Qt classes have a compatible interface
      - Building a property browser schema
      - Code review (find unused / undocumented signals)

    Companion to ``qt_meta_invoke`` (v0.3.7, runtime invocation via helper.exe —
    requires the app to be running) and ``qt_signal_slot_trace`` (v0.2.7, static
    connect-call graph). This tool reads the class SHAPE, not the runtime graph.

    Args:
        source_files: list of .h / .cpp / moc_*.cpp files to parse.
        class_name: optional filter; pass it when the file declares multiple
            Q_OBJECT classes (only the named class is reported).
        format: 'text' or 'json' for the report.

    Returns:
        Per-class inventory: signals / slots / Q_INVOKABLE / Q_PROPERTY.
    """
    if not params.source_files:
        return _json_footer({"ok": False, "error": "no source_files provided"})

    files: list[Path] = []
    for f in params.source_files:
        p = Path(f)
        if not _in_sandbox(p):
            return _json_footer({"ok": False, "error": f"outside sandbox: {p}"})
        if not p.exists():
            return _json_footer({"ok": False, "error": f"file not found: {p}"})
        files.append(p)

    classes: dict[str, dict] = {}
    for p in files:
        text = p.read_text(encoding="utf-8", errors="replace")
        # Find every class { ... Q_OBJECT ... } block, then walk the Q_OBJECT body.
        # We use a coarse bracket-counting parse to handle nested classes & templates.
        class_starts: list[tuple[str, int, int]] = []
        for cm in re.finditer(r"class\s+(?P<cn>\w+)\s*[^{;]*\{", text):
            cn = cm.group("cn")
            start = cm.end() - 1  # '{'
            depth = 1
            i = start + 1
            while i < len(text) and depth > 0:
                if text[i] == "{":
                    depth += 1
                elif text[i] == "}":
                    depth -= 1
                i += 1
            body = text[start + 1: i - 1]
            if "Q_OBJECT" not in body and "Q_GADGET" not in body:
                continue
            classes[cn] = {"_file": p.name, "signals": [], "public_slots": [], "slots": [], "q_invokable": [], "q_property": []}

        for cn, info in classes.items():
            # body is the class body — but classes dict lost association; recover with re-scan
            pass

    # Re-walk to associate bodies with classes
    classes = {}
    for p in files:
        text = p.read_text(encoding="utf-8", errors="replace")
        for cm in re.finditer(r"class\s+(?P<cn>\w+)\s*[^{;]*\{", text):
            cn = cm.group("cn")
            start = cm.end() - 1
            depth = 1
            i = start + 1
            while i < len(text) and depth > 0:
                if text[i] == "{":
                    depth += 1
                elif text[i] == "}":
                    depth -= 1
                i += 1
            body = text[start + 1: i - 1]
            if "Q_OBJECT" not in body and "Q_GADGET" not in body:
                continue
            if cn in classes:
                continue  # already collected
            cls = {"_file": p.name, "signals": [], "public_slots": [], "slots": [], "q_invokable": [], "q_property": []}
            for kind, pat in _QOBJECT_META_PATTERNS.items():
                m = pat.search(body)
                if m:
                    section_body = m.group(1)
                    for fm in _QSLOT_DECL_RE.finditer(section_body):
                        cls[kind].append({
                            "return": fm.group("ret").strip(),
                            "name": fm.group("name"),
                            "args": fm.group("args").strip(),
                        })
            for im in _QINVOKABLE_RE.finditer(body):
                cls["q_invokable"].append({
                    "return": im.group("ret").strip(),
                    "name": im.group("name"),
                    "args": im.group("args").strip(),
                })
            for pm in _QPROPERTY_RE.finditer(body):
                cls["q_property"].append({
                    "type": pm.group("type"),
                    "name": pm.group("name"),
                    "read": pm.group("read"),
                    "write": pm.group("write"),
                    "notify": pm.group("notify"),
                })
            classes[cn] = cls

    if params.class_name:
        if params.class_name not in classes:
            return _json_footer({"ok": False, "error": f"class {params.class_name!r} not found in provided files"})
        classes = {params.class_name: classes[params.class_name]}

    if params.format == "json":
        return json.dumps({"classes": classes}, indent=2, ensure_ascii=False) + "\n" + _json_footer({
            "ok": True,
            "files_scanned": [str(p) for p in files],
            "class_count": len(classes),
        })

    out = [f"=== Q_OBJECT metadata ({len(classes)} classes) ===", ""]
    for cn, info in classes.items():
        out.append(f"class {cn}  [{info['_file']}]")
        if info["signals"]:
            out.append("  signals:")
            for s in info["signals"]:
                out.append(f"    {s['return']} {s['name']}({s['args']})")
        if info["public_slots"]:
            out.append("  public slots:")
            for s in info["public_slots"]:
                out.append(f"    {s['return']} {s['name']}({s['args']})")
        if info["slots"]:
            out.append("  slots:")
            for s in info["slots"]:
                out.append(f"    {s['return']} {s['name']}({s['args']})")
        if info["q_invokable"]:
            out.append("  Q_INVOKABLE:")
            for s in info["q_invokable"]:
                out.append(f"    {s['return']} {s['name']}({s['args']})")
        if info["q_property"]:
            out.append("  Q_PROPERTY:")
            for p in info["q_property"]:
                bits = [f"READ={p['read']}"] if p['read'] else []
                if p["write"]:
                    bits.append(f"WRITE={p['write']}")
                if p["notify"]:
                    bits.append(f"NOTIFY={p['notify']}")
                extra = "  " + ", ".join(bits) if bits else ""
                out.append(f"    {p['type']} {p['name']}{extra}")
        out.append("")
    return "\n".join(out) + "\n" + _json_footer({
        "ok": True,
        "files_scanned": [str(p) for p in files],
        "class_count": len(classes),
        "total_signals": sum(len(c.get("signals", [])) for c in classes.values()),
        "total_invoke": sum(len(c.get("q_invokable", [])) for c in classes.values()),
        "total_props": sum(len(c.get("q_property", [])) for c in classes.values()),
    })


# =============== qt_qobject_invoke_property_diff ===============
class QtQobjectInvokePropertyDiffInput(BaseModel):
    base_files: list[str] = Field(description="First set of .h/.cpp files (the 'A' side — e.g., the public API class you want to keep).")
    head_files: list[str] = Field(description="Second set of .h/.cpp files (the 'B' side — e.g., the candidate implementation).")
    base_class: Optional[str] = Field(default=None, description="Optional: restrict base set to a single QObject class (default None = first QObject class found).")
    head_class: Optional[str] = Field(default=None, description="Optional: restrict head set to a single QObject class (default None = first QObject class found).")
    compare: str = Field(default="properties", description="'properties' (Q_PROPERTY only), 'methods' (signals + slots + Q_INVOKABLE), or 'all' (everything). Default 'properties'.")
    format: str = Field(default="text", description="'text' (default) or 'json' for the diff report.")


@mcp.tool(name="qt_qobject_invoke_property_diff", annotations={"title": "Compare Q_OBJECT metadata between two header sets (find changed properties, added/removed slots, signature drift)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qobject_invoke_property_diff(params: QtQobjectInvokePropertyDiffInput) -> str:
    """Diff QObject metadata between two header sets.

    Use to:
      - Compare a planned v2 public API against an existing v1 — find which
        properties the upgrade adds / removes / renames.
      - Detect signature drift between a real implementation and its mock.
      - Verify that a header-generator's output matches a hand-written header.

    Parsing reuses the same regex set as ``qt_qobject_invoke_metadata`` so the
    classification stays consistent across tools.

    Args:
        base_files: paths of the A-side files.
        head_files: paths of the B-side files.
        base_class: optional A filter.
        head_class: optional B filter.
        compare: 'properties' (Q_PROPERTY), 'methods' (signals + slots + Q_INVOKABLE), or 'all'.
        format: 'text' or 'json'.

    Returns:
        Per-property / per-method diff: added / removed / type_changed / signature_changed.
    """
    base_meta = await _collect_meta_for_diff(params.base_files, params.base_class, params.compare)
    head_meta = await _collect_meta_for_diff(params.head_files, params.head_class, params.compare)
    if isinstance(base_meta, str):  # error string
        return _json_footer({"ok": False, "error": f"base: {base_meta}"})
    if isinstance(head_meta, str):
        return _json_footer({"ok": False, "error": f"head: {head_meta}"})

    diffs: list[dict] = []
    base_keys = set(base_meta.keys())
    head_keys = set(head_meta.keys())
    for k in sorted(base_keys | head_keys):
        b = base_meta.get(k)
        h = head_meta.get(k)
        if b is None:
            diffs.append({"name": k, "status": "added", "new": h})
        elif h is None:
            diffs.append({"name": k, "status": "removed", "old": b})
        elif b != h:
            # Different signatures — find which field changed
            changed_fields = [f for f in b if b.get(f) != h.get(f)]
            diffs.append({
                "name": k,
                "status": "changed",
                "old": b,
                "new": h,
                "changed_fields": changed_fields,
            })
        # else identical → skip

    if params.format == "json":
        return json.dumps({"diffs": diffs, "summary": {
            "added": sum(1 for d in diffs if d["status"] == "added"),
            "removed": sum(1 for d in diffs if d["status"] == "removed"),
            "changed": sum(1 for d in diffs if d["status"] == "changed"),
        }}, indent=2, ensure_ascii=False) + "\n" + _json_footer({"ok": True, "diffs": diffs})

    out = [f"=== QObject metadata diff ({params.compare}) ===", ""]
    out.append(f"base: {sorted(base_keys)}")
    out.append(f"head: {sorted(head_keys)}")
    out.append("")
    if not diffs:
        out.append("(no differences)")
    for d in diffs:
        if d["status"] == "added":
            out.append(f"+ ADDED  {d['name']}: {d['new']}")
        elif d["status"] == "removed":
            out.append(f"- REMOVED {d['name']}: {d['old']}")
        else:
            out.append(f"~ CHANGED {d['name']}: " + ", ".join(d["changed_fields"]))
    counts = {
        "added": sum(1 for d in diffs if d["status"] == "added"),
        "removed": sum(1 for d in diffs if d["status"] == "removed"),
        "changed": sum(1 for d in diffs if d["status"] == "changed"),
    }
    out.append("")
    out.append(f"summary: +{counts['added']} added, -{counts['removed']} removed, ~{counts['changed']} changed")
    return "\n".join(out) + "\n" + _json_footer({"ok": True, **counts, "diff_count": len(diffs)})


async def _collect_meta_for_diff(files: list[str], class_filter: Optional[str], compare: str) -> dict:
    """Reuse _qt_qobject_invoke_metadata parsing to collect keyed metadata for diffing.

    Returns dict keyed on a stable identifier (e.g., 'prop::text' or 'method::connect').
    """
    if not files:
        return {}
    inp = QtQobjectInvokeMetadataInput(source_files=files, class_name=class_filter, format="json")
    raw = await qt_qobject_invoke_metadata(inp)
    try:
        # Strip trailing JSON footer if present
        body = raw.split("\n\n--- json ---", 1)[0].strip()
        data = json.loads(body)
    except Exception:
        return {}
    classes = data.get("classes") or {}
    if not classes:
        return {}
    # Pick first QObject class (or the requested filter)
    cls = next(iter(classes.values()))
    keyed: dict[str, dict] = {}
    if compare in ("properties", "all"):
        for p in cls.get("q_property", []):
            key = f"prop::{p['name']}"
            keyed[key] = {"type": p["type"], "read": p["read"], "write": p["write"], "notify": p["notify"]}
    if compare in ("methods", "all"):
        for s in cls.get("signals", []):
            key = f"signal::{s['name']}"
            keyed[key] = {"return": s["return"], "args": s["args"]}
        for s in cls.get("public_slots", []) + cls.get("slots", []):
            key = f"slot::{s['name']}"
            keyed[key] = {"return": s["return"], "args": s["args"]}
        for s in cls.get("q_invokable", []):
            key = f"invokable::{s['name']}"
            keyed[key] = {"return": s["return"], "args": s["args"]}
    return keyed


# =============== qt_qobject_invocation_count ===============
_INVOKE_METHOD_RE = re.compile(
    r"(?P<receiver>[\w\>\.\(\)\:\s\*&]+?)\.?(?P<pattern>invokeMethod|QMetaObject::invokeMethod)\s*\(",
    re.MULTILINE,
)
_INVOKE_LAMBDA_ARG_RE = re.compile(
    r"\[=*\]?\s*\(\s*(?:QObject\*\s*)?\w+\s*[,\s]\s*(?P<args>[\w\,\s\*&\(\)\":]+?)\s*\)\s*\)",
    re.MULTILINE,
)


class QtQobjectInvocationCountInput(BaseModel):
    source_files: list[str] = Field(description="List of absolute paths to .cpp files to scan for invokeMethod / QMetaObject::invokeMethod call sites.")
    method_filter: Optional[list[str]] = Field(default=None, description="Optional: only count calls to these method names (e.g. ['setText', 'update']).")
    format: str = Field(default="text", description="'text' or 'json' for the report.")


@mcp.tool(name="qt_qobject_invocation_count", annotations={"title": "Count static invokeMethod / QMetaObject::invokeMethod call sites per target method (find heavy hitters)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qobject_invocation_count(params: QtQobjectInvocationCountInput) -> str:
    """Count static invokeMethod call sites per target method (signature-free / method-name-only).

    Use to answer:
      - Which slot is hammered by QMetaObject::invokeMethod calls? (likely candidates for direct calls)
      - Which signal is most often emit-via-invokeMethod? (find banned-by-metaobject overhead)
      - Which setProperty / setX invocations cluster? (find set-then-emit anti-pattern)

    Scans .cpp files for `.invokeMethod(` and `QMetaObject::invokeMethod(`
    occurrences, extracts the method-name string when available, and aggregates
    counts. This is a static analysis — runtime invocation graphs (which
    require ``qt_invoke_helper_gen``-spawned helpers) are emitted by
    ``qt_signal_slot_trace``.

    Args:
        source_files: list of .cpp files to scan.
        method_filter: optional list of method names — only count calls to these.
            Default None = count all.
        format: 'text' or 'json'.

    Returns:
        Per-method counts + per-file breakdown (file:line nearest match).
    """
    if not params.source_files:
        return _json_footer({"ok": False, "error": "no source_files provided"})

    files: list[Path] = []
    for f in params.source_files:
        p = Path(f)
        if not _in_sandbox(p):
            return _json_footer({"ok": False, "error": f"outside sandbox: {p}"})
        if not p.exists():
            return _json_footer({"ok": False, "error": f"not found: {p}"})
        files.append(p)

    # Look for method name literal as the second/third arg to invokeMethod.
    # Pattern: receiver.invokeMethod("methodName" or QStringLiteral("methodName"))
    # Simpler approach: in each match site, take the trailing string literal.
    method_counts: dict[str, int] = {}
    site_records: list[dict] = []
    SKIP_PREFIX = "//"  # crude comment skip

    for p in files:
        text = p.read_text(encoding="utf-8", errors="replace")
        lines = text.split("\n")
        for line_no, line in enumerate(lines, 1):
            stripped = line.strip()
            if stripped.startswith(SKIP_PREFIX):
                continue
            for m in _INVOKE_METHOD_RE.finditer(line):
                # Try to find string literal on same line after `.invokeMethod(`
                tail = line[m.end():]
                lit = re.search(r'"([\w]+)"', tail)
                if lit:
                    name = lit.group(1)
                else:
                    # Sometimes the literal is on next line
                    name = ""
                if params.method_filter and name and name not in params.method_filter:
                    continue
                if name:
                    method_counts[name] = method_counts.get(name, 0) + 1
                site_records.append({
                    "file": str(p),
                    "line": line_no,
                    "pattern": m.group("pattern"),
                    "method": name,
                })

    if params.format == "json":
        return json.dumps({"method_counts": method_counts, "sites": site_records}, indent=2, ensure_ascii=False) + "\n" + _json_footer({
            "ok": True, "total_sites": len(site_records), "methods_seen": len(method_counts),
        })

    out = [f"=== invokeMethod static counts ({len(site_records)} call sites, {len(method_counts)} distinct methods) ===", ""]
    if not method_counts:
        out.append("(no invokeMethod calls with string-literal method names found)")
        out.append("(check whether your project uses direct-call syntax instead — that is the recommended path)")
    for name, n in sorted(method_counts.items(), key=lambda kv: -kv[1]):
        out.append(f"  {n:>4}  {name}")
    out.append("")
    out.append("Per-file breakdown:")
    by_file: dict[str, int] = {}
    for s in site_records:
        by_file[s["file"]] = by_file.get(s["file"], 0) + 1
    for f, n in sorted(by_file.items(), key=lambda kv: -kv[1]):
        out.append(f"  {n:>4}  {Path(f).name}")
    out.append("")
    out.append("Next: for runtime invocation graphs, use qt_signal_slot_trace (static connect calls) or qt_meta_invoke (runtime, requires helper.exe).")
    return "\n".join(out) + "\n" + _json_footer({
        "ok": True,
        "total_sites": len(site_records),
        "methods_seen": len(method_counts),
        "top_method": max(method_counts, key=method_counts.get) if method_counts else None,
    })


# =============== qt_qobject_invoke_connect_monitor ===============
class QtQobjectInvokeConnectMonitorInput(BaseModel):
    """Pydantic input for qt_qobject_invoke_connect_monitor."""
    project_dir: str = Field(description="Qt project root to scan recursively for .h/.cpp/.cc/.cxx files.")
    output_format: str = Field(default="text", description="'text' (default) | 'json'.")
    top_n: int = Field(default=10, description="How many top entries per category (default 10).")
    include_old_style: bool = Field(default=True, description="If True, also count SIGNAL(...)/SLOT(...) style connects (default True).")


# Local regexes for connect() calls (PMF style + old SIGNAL/SLOT style).
# Mirrors qt_signal_slot_trace but kept independent so name collisions cannot leak across tools.
# Sender / receiver vars may have a leading '&' (instance-pointer PMF); the optional prefix is captured.
_CM_PMF_CONNECT_RE = re.compile(
    r"(?:QObject\s*::\s*)?connect\s*\(\s*&?(\w+)\s*,\s*&(\w+)::(\w+)\s*,\s*&?(\w+)\s*,\s*&(\w+)::(\w+)\s*\)"
)
_CM_OLD_CONNECT_RE = re.compile(
    r"(?:QObject\s*::\s*)?connect\s*\(\s*&?(\w+)\s*,\s*SIGNAL\s*\(\s*(\w+)\s*\(\s*\)\s*\)\s*,\s*&?(\w+)\s*,\s*SLOT\s*\(\s*(\w+)\s*\(\s*\)\s*\)\s*\)"
)


@mcp.tool(name="qt_qobject_invoke_connect_monitor", annotations={"title": "Static connect-call topology monitor: per-sender/receiver/signal/slot hot-list heatmap (complements qt_signal_slot_trace)", "readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False})
async def qt_qobject_invoke_connect_monitor(params: QtQobjectInvokeConnectMonitorInput) -> str:
    """Static connect-call topology monitor for a Qt project.

    Walks the project for ``connect(...)`` calls (both PMF style
    ``connect(sender, &Class::signal, receiver, &Class::slot)`` and old
    ``SIGNAL/SLOT`` style), and aggregates per-entity counts:

      - **top senders** by connect count (which variable is most often wired up)
      - **top receivers** by connect count (which variable receives the most wires)
      - **top signals** by connect count (which `Class::signal` is most emitted-to)
      - **top slots** by connect count (which `Class::slot` is most connected-to)
      - **top files** by connect count

    Use cases:

      - Audit a project before a refactor — find out which objects are
        heavily wired so refactoring them has broad impact.
      - Compare two branches — count diff per category to spot
        accidental connect explosion.
      - Complement ``qt_signal_slot_trace`` (which maps every wire)
        and ``qt_qobject_invocation_count`` (which counts type-erasure
        boundary calls) — this one is the "hot entity" heatmap.

    Args:
        params.project_dir: project root (recursive).
        params.output_format: 'text' (default) | 'json'.
        params.top_n: max entries per category (default 10).
        params.include_old_style: also count SIGNAL(...)/SLOT(...) (default True).

    Returns:
        str: per-category top-N ranking. Empty project = 'no connect calls found'.

    Raises:
        No exceptions; errors are returned as formatted strings.
    """
    if params.output_format not in ("text", "json"):
        msg = f"Error: output_format must be text/json, got {params.output_format!r}"
        return msg + _json_footer({"ok": False, "error": msg})

    proj_dir = Path(params.project_dir)
    sandbox_err = _require_sandbox(proj_dir, "project_dir")
    if sandbox_err:
        return sandbox_err + _json_footer({"ok": False, "error": sandbox_err})
    if not proj_dir.exists() or not proj_dir.is_dir():
        msg = f"Error: project_dir is not a directory: {proj_dir}"
        return msg + _json_footer({"ok": False, "error": msg})

    files: list[Path] = []
    for ext in ("*.cpp", "*.cc", "*.cxx"):
        for p in proj_dir.rglob(ext):
            # NO .tmp in SKIP list — sandbox tests live under .tmp; v0.2.5/v0.3.2/v0.3.6/v0.3.7/v0.4.0/v0.4.2 lesson
            if not any(s in p.parts for s in ("debug", "release", "build-", ".git", "build")):
                files.append(p)
    for ext in ("*.h", "*.hpp"):
        for p in proj_dir.rglob(ext):
            if not any(s in p.parts for s in ("debug", "release", "build-", ".git", "build")):
                files.append(p)

    sender_counts: dict[str, int] = {}        # var -> count
    receiver_counts: dict[str, int] = {}      # var -> count
    signal_counts: dict[str, int] = {}        # "Class::signal" -> count
    slot_counts: dict[str, int] = {}          # "Class::slot" -> count
    file_counts: dict[str, int] = {}          # file -> count
    site_records: list[dict] = []

    for p in files:
        text = p.read_text(encoding="utf-8", errors="replace")
        file_short = str(p.relative_to(proj_dir) if p.is_relative_to(proj_dir) else p)
        for m in _CM_PMF_CONNECT_RE.finditer(text):
            sender_var, sclass, ssignal, recv_var, rclass, rslot = m.groups()
            sender_counts[sender_var] = sender_counts.get(sender_var, 0) + 1
            receiver_counts[recv_var] = receiver_counts.get(recv_var, 0) + 1
            sig_key = f"{sclass}::{ssignal}"
            slot_key = f"{rclass}::{rslot}"
            signal_counts[sig_key] = signal_counts.get(sig_key, 0) + 1
            slot_counts[slot_key] = slot_counts.get(slot_key, 0) + 1
            file_counts[file_short] = file_counts.get(file_short, 0) + 1
            site_records.append({
                "file": file_short,
                "line": text[:m.start()].count("\n") + 1,
                "style": "pmf",
                "sender_var": sender_var, "signal": sig_key,
                "receiver_var": recv_var, "slot": slot_key,
            })
        if params.include_old_style:
            for m in _CM_OLD_CONNECT_RE.finditer(text):
                sender_var, ssignal, recv_var, rslot = m.groups()
                sender_counts[sender_var] = sender_counts.get(sender_var, 0) + 1
                receiver_counts[recv_var] = receiver_counts.get(recv_var, 0) + 1
                sig_key = f"(?)::{ssignal}"
                slot_key = f"(?)::{rslot}"
                signal_counts[sig_key] = signal_counts.get(sig_key, 0) + 1
                slot_counts[slot_key] = slot_counts.get(slot_key, 0) + 1
                file_counts[file_short] = file_counts.get(file_short, 0) + 1
                site_records.append({
                    "file": file_short,
                    "line": text[:m.start()].count("\n") + 1,
                    "style": "signal_slot",
                    "sender_var": sender_var, "signal": sig_key,
                    "receiver_var": recv_var, "slot": slot_key,
                })

    def topn(d: dict[str, int], n: int) -> list[tuple[str, int]]:
        return sorted(d.items(), key=lambda kv: (-kv[1], kv[0]))[:n]

    top_senders = topn(sender_counts, params.top_n)
    top_receivers = topn(receiver_counts, params.top_n)
    top_signals = topn(signal_counts, params.top_n)
    top_slots = topn(slot_counts, params.top_n)
    top_files = topn(file_counts, params.top_n)
    total_connects = len(site_records)

    if params.output_format == "json":
        payload = {
            "project": str(proj_dir),
            "files_scanned": len(files),
            "total_connects": total_connects,
            "top_senders": [{"name": n, "count": c} for n, c in top_senders],
            "top_receivers": [{"name": n, "count": c} for n, c in top_receivers],
            "top_signals": [{"name": n, "count": c} for n, c in top_signals],
            "top_slots": [{"name": n, "count": c} for n, c in top_slots],
            "top_files": [{"name": n, "count": c} for n, c in top_files],
            "sender_count_distinct": len(sender_counts),
            "receiver_count_distinct": len(receiver_counts),
        }
        return json.dumps(payload, indent=2, ensure_ascii=False) + _json_footer({"ok": True, "data": payload})

    if total_connects == 0:
        return (
            f"=== qt_qobject_invoke_connect_monitor ===\n"
            f"project:   {proj_dir}\n"
            f"files:     {len(files)} scanned\n"
            f"connects:  0\n\n"
            f"No connect() calls found.\n"
        ) + _json_footer({"ok": True, "data": {"project": str(proj_dir), "total_connects": 0}})

    lines = [
        "=== qt_qobject_invoke_connect_monitor ===",
        f"project:    {proj_dir}",
        f"files:      {len(files)} scanned",
        f"connects:   {total_connects} total  ({len(sender_counts)} distinct senders, {len(receiver_counts)} distinct receivers)",
        "",
        f"--- Top {params.top_n} senders (most-wired variables) ---",
    ]
    for n, c in top_senders:
        lines.append(f"  {c:>4}  {n}")
    lines.append("")
    lines.append(f"--- Top {params.top_n} receivers (most-wired variables) ---")
    for n, c in top_receivers:
        lines.append(f"  {c:>4}  {n}")
    lines.append("")
    lines.append(f"--- Top {params.top_n} signals (Class::signal hot-list) ---")
    for n, c in top_signals:
        lines.append(f"  {c:>4}  {n}")
    lines.append("")
    lines.append(f"--- Top {params.top_n} slots (Class::slot hot-list) ---")
    for n, c in top_slots:
        lines.append(f"  {c:>4}  {n}")
    lines.append("")
    lines.append(f"--- Top {params.top_n} files (most connects in a file) ---")
    for n, c in top_files:
        lines.append(f"  {c:>4}  {n}")
    lines.append("")
    lines.append("Tip: a single sender with >5 connects is often a god-object — consider whether it should split into smaller pieces.")

    out = "\n".join(lines)
    return out + _json_footer({"ok": True, "data": {"project": str(proj_dir), "total_connects": total_connects, "files_scanned": len(files)}})


